window.IDW_ITEMS_TR=window.IDW_ITEMS_TR||{};window.IDW_ITEMS_TR["ar"]={"ICON-0001":{"nm":"أثر قدم","de":"أثرٌ ترابيُّ اللون بقي وحيدًا على أرضية الخشب. طاف صاحبه طويلًا مترددًا، ثم أخيرًا خطا خطوة أخرى إلى الأمام. ما يسجّله أثر القدم ليس الزمن الذي قضاه المرء متسكعًا، بل تلك اللحظة بعينها التي عزم فيها على الرحيل."},"ICON-0002":{"nm":"فانوس","de":"حين تلامس النار الفتيلة، يتراجع الظلام بهدوء شبرًا فشبرًا. بهذا الدفء الصغير الذي يُدفئ أطراف الأصابع، كان القدماء يكتبون أمنياتهم ويرسلونها مع التيار. فالفانوس لا يُضاء ليُنير، بل ليبقى إلى جانبك."},"ICON-0003":{"nm":"شريط زينة","de":"بعقدة واحدة، يُلَفّ القلب برفق وأناقة. سهلٌ للحلّ بالنسبة لليد المانحة، بطيء الفكّ بالنسبة لليد المتلقية. ما يربطه الشريط ليس الصندوق، بل ذلك الخفقان الذي يسبق لحظة تسليمه."},"ICON-0004":{"nm":"صندوق بريد","de":"يقف فاغرًا فمه الأحمر عند مدخل الزقاق. حتى في زمن ندرت فيه الرسائل المكتوبة بخط اليد، لا يزال هذا الصندوق الصغير ينتظر أخبار أحدهم حتى النهاية. إناء لطيف يزداد إشراقًا كلما ازداد فراغًا."},"ICON-0005":{"nm":"خريطة الجزيرة الخاصة المصغّرة","de":"ورقة واحدة: طيّها يجعلها في قبضة اليد، وفرشها يُسجّي البحر والتلال جنبًا إلى جنب. لمن يصل للمرة الأولى، كل زاوية فيها وعدٌ لم يُفتح بعد. وما إن تُفرد حتى تصير الجزيرة الصغيرة عالمًا واسعًا."},"ICON-0006":{"nm":"ميكروفون","de":"تلك النصف نبضة من التقاط الأنفاس قبيل النغمة الأولى مباشرة. معرفة أن أعين الجمهور تنتظر كلمتك الأولى تجعل أطراف الأصابع ترتجف. الميكروفون لا يُكبّر الصوت، بل يحمل تلك الرعشة حتى النهاية."},"ICON-0007":{"nm":"ساعة","de":"عقرب الثواني لا يهدأ أبدًا، لكن أحدًا لا يستعجلك. كم من ليلة حتى ظهور الفرقة، وكم من دقيقة حتى صعود المسرح—على قرص الساعة يدور الانتظار والترقّب بالسرعة ذاتها. النظر إلى الوقت هو تهدئة للقلب."},"ICON-0008":{"nm":"دفتر ملاحظات","de":"الشيء الذي يحمل أكثر الفراغات بياضًا. مسارات الرقص، وعزائم الفجر، والكلمات التي لم تُرسل قط، كلها تتراكم هنا. وفي لحظة فتحه، تتحدث ذاتُ الأمس برفق إلى ذات اليوم."},"ICON-0009":{"nm":"ختم","de":"حين يُغمس في الحبر الأحمر ويُضغط مرة واحدة بثبات، يُنقش الوعد بوضوح. أثرٌ أثقل من الكتابة وأوضح من الكلام. في نهاية كل وثيقة، كان الناس يودعون قلوبهم لهذا الختم الصغير بدلًا من أسمائهم."},"ICON-0010":{"nm":"قاعدة","de":"يخفض من شأنه إلى أقصى حد ليرفع شيئًا آخر. في القاع تمامًا، يتحمّل الثقل بصمت كي لا يهتز ما يعلوه. لا يلمع أبدًا، لكن هنا تكمن اللطف الذي يمنع الأشياء من الانهيار."},"ICON-0011":{"nm":"طابع بريد","de":"صورة صغيرة كنت تبلّل زاويتها بلعابك وتضغط عليها. الثمن الأصدق الذي يُوضع على قلبٍ أُرسل بعيدًا. مربّع واحد من المشهد يأخذ الرسالة من يدها ويحملها عبر البحر."},"ICON-0012":{"nm":"دبوس علم","de":"اغرزه في الخريطة وسيقول: \"لقد وصلتُ إلى هنا.\" ليس فتحًا بل سجلًّا، وتحية لمن سيأتي لاحقًا. علامة تدفع ظهرك بصمت قائلة: خطوة واحدة أخرى وأنت ترى هذا العلم."},"ICON-0013":{"nm":"غصن","de":"الغصن الذي انحنى مرة ينسى كيف ينكسر. في كل موضع انحنى فيه أمام الريح، تترسخ عقدة صلبة، وتُخبرك الغابة العتيقة عبر نسمة الهواء أن القوة الحقيقية تأتي من آثار الصمود."},"ICON-0014":{"nm":"زر","de":"يُفتح ثم يُغلق مرارًا وتكرارًا وهو يُحكم إغلاق الياقة. دائرة صغيرة واحدة تصدّ برفق برد الفجر وخجلًا مفاجئًا على حدٍّ سواء. ولا تدرك كم كان مكانها كبيرًا إلا حين تسقط فجأة."},"ICON-0015":{"nm":"مظروف","de":"في لحظة إغلاق فمه، يصير سرًّا أخيرًا. لا يعرف ما بداخله سوى من يتسلمه. طبقة واحدة من الورق توضع بين القلب والعالم، أرقّ باب وألطفه."},"ICON-0016":{"nm":"صندوق","de":"زواياه الأربع مستقيمة فيحتضن كل شيء بسخاء. الذكريات في موسم الانتقال، والهدايا في الأعياد، والأغراض المتفرقة في الأيام العادية. وداخل غطائه المغلق، دائمًا ما يكون مليئًا بـ\"لاحقًا\" أحدهم."},"ICON-0017":{"nm":"مقبض","de":"بين الباب والإنسان، هو أول من يمدّ يده. لا يتّصل الداخل بالخارج إلا بعد أن تُشدّ مرة واحدة. كل قرار بالدخول أو الخروج يقبض على هذه اليد الباردة مرة واحدة في طريقه."},"ICON-0018":{"nm":"ملعقة","de":"بفمه المقعّر، يرفع بهدوء المرق الدافئ. أداة تتذكّر دفء الملعقة الأولى التي نفختها الأم لتُبرّدها وقدّمتها أولًا. أكثر يد لطيفة تلامس الشفاه على المائدة، وأكثرها ملامسة."},"ICON-0019":{"nm":"شبشب","de":"في لحظة عبور العتبة، تتنفس القدمان الصعداء أولًا. صوت المساء الهادئ بعد خلع صخب النهار السريع. زوج مرتّب بعناية عند المدخل يقول لك: \"أنت في البيت الآن.\""},"ICON-0020":{"nm":"مفتاح","de":"تتعلّم كيف تفتح قبل أن تتعلّم كيف تُقفل. قطعة معدن صغيرة تدفأ في راحة اليد، ثم تتوقف يومًا بهدوء أمام باب جديد غريب. الشيء الذي يحفظ دفء من رحل أطول مما يحفظه أي شيء آخر."},"ICON-0021":{"nm":"كأس","de":"أنيق وهو فارغ، ودافئ أكثر من أي شيء وهو ممتلئ. في رنين كأسين تصطدمان وجهًا لوجه، يُحفظ وعدٌ بلا كلام. إناء وُلد ليلمع باثنين لا بواحد."},"ICON-0022":{"nm":"طبق","de":"داخل حافته المستديرة، يُسكب اهتمام يوم كامل. يُفرّغ ويُنظّف ويُملأ من جديد طوال العمر—أكثر أدوات المنزل لمعانًا وأكثرها نسيانًا في آنٍ واحد. مسرح المائدة يُقام دومًا فوقه."},"ICON-0023":{"nm":"إضاءة","de":"بمفتاح واحد تتغيّر تعابير الغرفة. ساطعة فهي الحياة اليومية، وخافتة فهي المواساة. نقطة ضوء واحدة تُترك مضاءة حتى النهاية من أجل من يعود متأخرًا تصير أدفأ ترحيب في العالم."},"ICON-0024":{"nm":"ملعقة شاي","de":"حرّكها ببطء دورة واحدة فوق الشاي، فتتشرّب الأوراق والماء أحدهما الآخر. حركة لا تستعجل، وانتظار صغير حتى تفوح الرائحة. يد فضية واحدة تُبطئ برفق إيقاع بعد الظهر."},"ICON-0025":{"nm":"فاصل كتب","de":"وعدٌ يُدسّ بهدوء في الموضع الذي توقفت عنده القراءة. النذر القائل \"توقفتُ هنا، وسأعود حتمًا\" ينام بين الصفحتين. القصة قد تُغلق، لكن القلب يُعلَّم بوضوح على ذلك السطر الواحد."},"ICON-0026":{"nm":"وسادة أريكة","de":"تستقبل بصمت الظهر والركبتين اللتين تحتاجان إلى ما تتكئان عليه. تغوص عميقًا ثم تنتفخ ببطء، ماصّة تعب اليوم. الشيء الأكثر سماحة بأكسل وضعية جلوس."},"ICON-0027":{"nm":"إطار صور","de":"حافة مربّعة تربط مشهدًا واحدًا بالأبد. للحظة التي التقطها فقط، لن يبهت الزمن مهما مرّ. اختيارٌ لطيف لا يتعلق بما يُحتفظ به بقدر ما يتعلق بما قرّر المرء الإبقاء عليه."},"ICON-0028":{"nm":"خريطة","de":"في كل ثنية منها يعبق أثر الضياع ثم العثور على الطريق من جديد. افتحها وستتمكن من السير بأطراف أصابعك أولًا حتى في أماكن لم تزرها قط. كل مغامرة تبدأ بشجاعة صغيرة، شجاعة فرد هذه الورقة الواحدة."},"ICON-0029":{"nm":"بطاقة بريدية","de":"نصف الظهر صورة، ونصفه فراغ. من ذهب بعيدًا يرسل \"أنا بخير\" في كلمات قليلة، مع منظر ذلك المكان بجانبها. أصدق ورقة، حيث الأخبار لا تحتاج مظروفًا لتشعر بالراحة."},"ICON-0030":{"nm":"بطاقة دخول","de":"في لحظة تعليقها حول عنقك، تدخل أخيرًا العالم الداخلي. اسمك على البطاقة الصغيرة يمنحك بهدوء: \"هنا، هذا مكانك.\" ليست شهادة عبور، بل دليل على أنك تنتمي إلى مكان ما."},"ICON-0031":{"nm":"حرف B","de":"الحرف الذي يُستدعى غالبًا في منتصف الكلمة. عليك أن تُطبق شفتيك مرة ثم تفتحهما فجأة كي يخرج الصوت. ليس بداية ولا نهاية، بل مكان ثانٍ موثوق يحفظ الإيقاع."},"ICON-0032":{"nm":"بطاقة عمل","de":"تُقدَّم بكلتا اليدين، وتُستقبل بتلاقي الأعين. يوم إنسان وكبرياؤه يُختزلان بهدوء في ورقة واحدة. في الهامش الضيق بين الاسم واللقب، ينغرس برفق الانطباع الأول لذلك اليوم."},"ICON-0033":{"nm":"غلاف كتاب","de":"في أقصى طرف القصة، يستقبل الريح والمطر أولًا. حماية للحروف بداخله، يهترئ من زواياه أولًا. تلك الرعشة اللحظية قبل الفتح مباشرة تبدأ دائمًا من هذه الصفحة الواحدة."},"ICON-0034":{"nm":"كتاب دراسي","de":"كفاح إنسان واحد مكتوب بكثافة بالخطوط تحت الكلمات وبالتظليل الفسفوري. مربك حين يكون جديدًا، ويصير أوثق صديق حين يُنجَز. آثار معرفة ما كان مجهولًا مطويّة بعناية في كل صفحة."},"ICON-0035":{"nm":"تصريح دخول قاعة التدريب","de":"ورقة واحدة تفتح على مصراعيها باب قاعة التدريب. غرفة مليئة بالمرايا، صوت أقدام تدق الأرض، أول ثمانية عدّات تُتعلَّم. لا بأس إن كان الرقص لا يزال متعثرًا—ورقة صغيرة تدفع برفق ظهرًا يرتجف إلى الأمام."},"ICON-0036":{"nm":"ملف مستندات","de":"أوراق متفرقة كانت تتجول، تُشبك بعناية على عمود واحد فتنال أخيرًا ترتيبًا. مع الترتيب تولد قصة، وكلما زاد سُمكها، ازداد الدليل اللطيف على أن أحدهم عاش كل تلك الأيام صفحة بعد صفحة."},"ICON-0037":{"nm":"ورقة امتحان","de":"أطراف أصابع ترتجف للحظة فوق السطور الفارغة. أخوف من الإجابة الخاطئة هو مواجهة ما لا تعرفه وجهًا لوجه. حين ينتهي التصحيح، عند كل خطأ، يبقى هامش بهدوء لنمو قادم."},"ICON-0038":{"nm":"حرف A","de":"الصوت الأول الذي لا يخرج إلا حين تفتح فمك على اتساعه. غالبًا ما يقف في مقدمة السطر، في أول اسم. حين تبدأ أي شيء، تبدأ بهذا الحرف—لذا فهو دومًا أكثر شجاعة قليلًا."},"ICON-0039":{"nm":"حرف D","de":"بظهره المنحني برفق، يسند كلمة بلطف. جانبه المستدير يتدلّى بأناقة في نهاية اسم أحدهم. ليس براقًا، لكنه يُفتقد بشدة إذا غاب—رفيق هادئ بين الحروف."},"ICON-0040":{"nm":"ورقة تدريب","de":"الورقة الوحيدة في العالم التي يجوز فيها الخطأ. تتيح لك كتابة الحركة نفسها، والجملة نفسها، عشرات المرات. بقدر ما تتكوّم صفحات مجعّدة مرمية، كان أحدهم بالتأكيد يتحسن قليلًا."},"ICON-0041":{"nm":"ورقة تلحين","de":"الساعة الثانية فجرًا، دندنة واحدة توقظك من النوم. يتردد القلم فوق الخطوط الموسيقية لأن اللحن أسرع من اليد. في كل أثر مُمحًى ومكتوب من جديد، تنمو رويدًا رويدًا أغنية لا اسم لها بعد."},"ICON-0042":{"nm":"تصريح دخول","de":"في لحظة تعليقه حول عنقك، يتحول ممرٌّ عادي إلى عالم آخر. تتسلل الكابلات عبر الظلام كالأفاعي، وخلف المسرح يبدأ عدّ تنازلي لا يُسمع. حق الدخول إلى هنا، تتحدث عنه هذه الورقة الواحدة نيابة عنك."},"ICON-0043":{"nm":"ورقة عيّنات الصور","de":"في كل مربع صغير، تعبير مختلف يقف مجمَّدًا. يضحك، يلتفت، يغمض عينيه. أشر إلى لقطة تلو الأخرى وستعود إلى أطراف أصابعك رعشة ذلك اليوم حين ضُغط الغالق. حتى اختيار لقطة واحدة هو سجلٌّ بحد ذاته."},"ICON-0044":{"nm":"جدول التصوير","de":"غدًا في أي ساعة، وأين، وماذا. ورقة واحدة ترسم مسبقًا مسار يوم كامل. بين الخانات المزدحمة دقيقة بدقيقة، يتبع أحدهم الترتيب المكتوب هنا، خطوة خطوة نحو حلمه."},"ICON-0045":{"nm":"بطاقة سعر","de":"خلف بطاقة السعر يتدلى بهدوء وقت من صنعها. بتلك الحركة الصغيرة، حركة القطع، تصير الورقة الصغيرة ملكك أخيرًا. ما يتبقى عند موضع القصّ هو رائحة الجديد وحفنة من الترقّب."},"ICON-0046":{"nm":"ملف أعمال","de":"اقلب الغلاف وينفتح دفعة واحدة الطريق الذي قطعته. بجانب صفحة تفخر بها، تجلس بخجل أول محاولة متعثرة. حين تقدّم نفسك لأحدهم لأول مرة، لا يوجد تعريف بالنفس أصدق من هذا."},"ICON-0047":{"nm":"مفكرة يومية","de":"تكتب اليوم، وترسم الأسبوع القادم، وأحيانًا تلوّن خانة بالكامل بالأسود. حتى لو لم يسر شيء وفق الخطة، لا تتوقف اليد التي تملأ الخانات. طقسٌ صغير كأنه عيشُ المستقبل مسبقًا مرة واحدة."},"ICON-0048":{"nm":"قائمة تشغيل","de":"بين الأغاني البطيئة والإيقاعات السريعة، ترتّب الموسيقى في صفٍّ واحد وفق طقس مزاج ذلك اليوم. تخيّل أن يوم أحدهم يمرّ بالضبط بهذا الترتيب، وسيصير حتى الصمت بين المقطوعات لطيفًا."},"ICON-0049":{"nm":"بطاقة طالب","de":"اسم، وصورة، وبضعة أرقام. بطاقة واحدة تشهد على أيام التنقل بين الفصل الدراسي وقاعة التدريب. في البطاقة المهترئة الزوايا من كثرة الدخول والخروج من الجيب، محفورة أيام ندية لا تعود مرة أخرى."},"ICON-0050":{"nm":"سوار","de":"أتذكر لحظة ربط لون ذلك اليوم حول معصمك؟ الهتاف الذي صرختماه معًا، وليلة الحفل التي ابتللتما فيها جنبًا إلى جنب. حتى مع اهتراء الرباط وبهتان اللون، لا تفكّه، لأنك تريد أن يظل ذلك الصيف حيًّا على معصمك."},"ICON-0051":{"nm":"شارة ذراع","de":"في لحظة لفّه حول الذراع، يُضاف بهدوء ثقل يُدعى المسؤولية. علامة من يقف في مقدمة الصف ويغادر موقعه أخيرًا. قطعة قماش واحدة تجعل أحدهم ينمو شبرًا إضافيًّا."},"ICON-0052":{"nm":"خاتم","de":"خطٌّ واحد مستدير بلا انقطاع. لأن بدايته ونهايته متلامستان، يرى الناس فيه شكل الأبد. اجمع يدين برفق وقبل أن تُقال الكلمات، يبقى الوعد على هيئة شكل."},"ICON-0053":{"nm":"وسام","de":"على القطعة المعدنية الصغيرة المثبَّتة على الصدر، محفورة الأيام التي صُمد فيها. ما يلمع ليس المعدن، بل ليالي التدريب التي لا تُحصى المختبئة خلفه. ما يفيض قبل الفخر هو، بطريقة ما، الامتنان."},"ICON-0054":{"nm":"مريلة","de":"اربط الحبل حول عنقك فتتحرر يداك. إشارة إلى أنك مستعد للانغماس في شيء ما، دقيقًا كان أم صبغة ألوان. كلما تراكمت البقع واحدة تلو الأخرى، ازداد عمق العناية التي بُذلت في ذلك اليوم."},"ICON-0055":{"nm":"غطاء أذن","de":"غلّف أذنيك برفق فتبتعد الأصوات الخارجية خطوة. في طريق المدرسة تحت ريح قارصة، ملجأ صغير للاختباء داخل دفء ناعم. دفء الشتاء أحيانًا يبدأ هكذا، من أطراف الأذنين."},"ICON-0056":{"nm":"زي مسرحي","de":"قبل رفع الستار، يعلّق زي واحد على الشمّاعة كاتمًا أنفاسه. في كل غرزة منه تنطوي حركات الرقص. في لحظة انزلاق الذراع فيه، يصير الإنسان دورًا، ويصير المسرح جلد ذلك الزي الثاني."},"ICON-0057":{"nm":"تاج","de":"في لحظة استقراره على الرأس، ينتصب الظهر المنحني من تلقاء نفسه. لمعانه الذهبي يهمس بالمسؤولية قبل السلطة. ثقله البارد على الجبين يقول كل شيء: كلما ازداد المكان بريقًا، ازداد ثقلًا."},"ICON-0058":{"nm":"عباءة","de":"ضعها على كتفيك وسترفرف الريح خلف ظهرك. ذلك الإحساس بقطعة قماش تلحق بك مع كل خطوة جري. أقرب إلى قلب طفل أراد فقط أن يبدو رائعًا، لا إلى شارة بطل."},"ICON-0059":{"nm":"قناع","de":"غطِّ الوجه وتصير، بغرابة، أكثر صدقًا. كأولئك في مسرحيات الساحات القديمة الذين ضحكوا وبكوا بحرية خلف القناع. من خلف التعبير المخفي، يتسرب الصوت الحقيقي الذي عادة ما يُكتم أعلى صوتًا."},"ICON-0060":{"nm":"أحمر شفاه","de":"أدر الغطاء وارسم خطًّا واحدًا، فيستقر عزم صغير على الشفتين. فحص أخير أمام المرآة، خط أحمر يُرسم فوق التردد. في تلك اللحظة القصيرة التي يُطلى فيها اللون، يتراجع الخوف بصمت جانبًا."},"ICON-0061":{"nm":"جاكيت","de":"حين يستقر خط الكتف تمامًا في مكانه، يصير الإنسان أكثر ثباتًا قليلًا. اطوِ الأكمام فيصير القلب مستعدًا للعمل، وارفع الياقة فيصير مستعدًا للخروج. زي واحد يحدد بهدوء وضعية اليوم بأكمله."},"ICON-0062":{"nm":"حزام تايكواندو","de":"كل مرة يتغير فيها اللون درجة، يتغيّر معه مقدار العرق المتراكم تحته. صباح القاعة حين تُشدّ العقدة بإحكام ويُنحنى في التحية. عبر أطراف الأصابع التي تربط الحزام، يتجمّع التركيز المشتّت من جديد."},"ICON-0063":{"nm":"نظارة واقية","de":"ضعها على عينيك ويزداد العالم وضوحًا بدرجة. خلف الدرع المستدير الذي يصد الريح والغبار، حتى الطريق العادي الذي تسلكه دائمًا يبدو، لسبب ما، متلألئًا كخط بداية."},"ICON-0064":{"nm":"قفاز","de":"البسها فتنبع الشجاعة على القبض بإحكام على أي شيء. الأصابع التي كانت تنكمش خوفًا من إسقاط شيء ما، تنفتح أخيرًا على اتساعها. اليد هي ما يُحمى، لكن ما يُصان حقًّا هو التحدي القادم."},"ICON-0065":{"nm":"كمامة","de":"غطِّ الجزء السفلي من الوجه فتتحدث العينان أكثر. في شارع مزدحم، حرية صغيرة من التخفي تُنعم بها خلف غطاء خفيف. لذا فإن الابتسامة المتبقية حين يُنزع كل شيء تنتشر أكثر إشراقًا."},"ICON-0066":{"nm":"قبعة","de":"أنزل الحافة قليلًا فيحيد الشمس والأنظار عنك بمقدار شبر. تحت هذا السقف الصغير المستقر على رأسك، يجوز لك اليوم على الأقل أن تسير بتعبير مرتاح. أخف تحوّل يبدأ دائمًا من هنا."},"ICON-0067":{"nm":"قميص","de":"خشخشة، ورائحة الصباح تفوح من الياقة المكوية للتوّ. بينما تُغلق الأزرار بالترتيب من الأعلى، يزداد القلب المتشعث ترتيبًا درجة درجة. صفحة بيضاء واحدة تفتح الجملة الأولى لليوم."},"ICON-0068":{"nm":"وشاح","de":"لُفّه حول العنق مرة واحدة فيُسدّ ممر الريح. بينما يتمايل طرفه على الكتف، لا يعود البرد قادرًا على الوصول إلى الداخل. قطعة واحدة موضوعة في مكانٍ ما بين الأناقة والدفء."},"ICON-0069":{"nm":"قفازات","de":"تُلَفّ حتى أطراف الأصابع فلا يعود البرد مخيفًا. رفاهية الشتاء الصغيرة، حين تصير اليدان اللتان كنت تنفخهما دفئًا هادئًا. قفاز واحد يُخلع ويُهدى قد يدفئ يد أحدهم أيضًا."},"ICON-0070":{"nm":"بطاقة تعريف عسكرية","de":"صفيحتان رقيقتان تتقابلان بهدوء. ثلاثة أحرف من اسم وبضعة أرقام، هذا ما يجعل أحدهم يُتذكَّر حتى النهاية. معدن بارد، لكنه لسبب ما يشبه أدفأ وعد."},"ICON-0071":{"nm":"حلقة إمساك","de":"أدخل إصبعك فيها ويتلاشى القلق من الإسقاط. طمأنينة صغيرة تكفي للإمساك والتلويح حتى بيد واحدة. حين تمدّ ذراعك بعيدًا لتلتقط صورة واحدة، تسند راحة يدك بصمت."},"ICON-0072":{"nm":"إكليل زهور","de":"ضعه على رأسك وسيتبعك حِضنٌ من الربيع. زهور قُطفت من الحقل ونُسجت في حلقة تحيط الجبين برفق. فوق الابتسامة المشرقة في الصورة، تبقى رائحة العشب الخفيفة طويلًا."},"ICON-0073":{"nm":"قناع نوم","de":"غطِّ العينين فيبتعد الضوء والضجيج دفعة واحدة. لعدم الرؤية، لا تسمع سوى أنفاسك. أطفئ العالم للحظة وادخل إلى السكون الداخلي، وسيُغلق باب صغير بهدوء خلف ظهرك."},"ICON-0074":{"nm":"لفاع","de":"لفة، ثم لفة أخرى—كل دورة حول العنق تُليّن الشتاء قليلًا. ربما يختلط في مكان ما بين الخيوط الصوفية قلبٌ حاكه أحدهم. ادفن نفسك فيه حتى الأنف وسيغدو العالم أكثر دفئًا."},"ICON-0075":{"nm":"قناع نصفي","de":"بتغطية نصف الوجه فقط، تبدأ ليلة الحفل التنكري. الشفاه المكشوفة تبتسم، والعينان المخفيتان تحملان سرًّا. تلك المسافة الضيقة بين المعرفة وعدمها تجعل هواء منتصف الليل يخفق."},"ICON-0076":{"nm":"قبعة بيريه","de":"ضعها بميل خفيف فيكتسب يومٌ عادي رونقًا بهدوء. قطعة قماش مستديرة مسطحة واحدة تكسو كتفيك بهواء فنان بلطف. حتى تلك اللحظة القصيرة أمام المرآة وأنت تختار الزاوية المناسبة ممتعة."},"ICON-0077":{"nm":"طوق عنق","de":"لُفّه بإحكام حول العنق فتتجمع الأنظار نحو الأعلى تلقائيًا. رباط رفيع واحد يغيّر الأجواء كلها. صغير لكنه واضح، كأنه مشبك يملأ ثقة اليوم."},"ICON-0078":{"nm":"معطف باركا","de":"أغلق السحّاب حتى النهاية وستتراجع العاصفة الثلجية خطوة. أدخل يديك عميقًا في الداخل السميك، وسيهدأ ضجيج العالم كله. بيتٌ صغير يبقى دافئًا حتى النهاية حتى وسط ريح قاسية."},"ICON-0079":{"nm":"بنطال","de":"أدخل قدميك واربط الخصر، وأخيرًا يكتمل الاستعداد للخروج. مع كل خطوة، يتحرك القماش برفق تبعًا لنسيجه. في مكانٍ ما بين الراحة والأناقة، يبدأ اليوم."},"ICON-0080":{"nm":"بيرسينغ","de":"حتى إضافة نقطة صغيرة واحدة تتطلب بعض الشجاعة. لمعة معدنية واحدة تضع نقطة واضحة عند أذن عادية. صغيرة جدًّا، لكنها ضوء يعكس ذاتًا اليوم قد تغيّرت يقينًا."},"ICON-0081":{"nm":"مخطط موجي صوتي","de":"بالنسبة للمهندس، الأغنية لا تُسمع بل تُرى. من التلال الصاعدة والهابطة على الشاشة، يقرأ أين ارتجف النفَس ذلك اليوم. صوتٌ لم يكن مرئيًا يستلقي كسلسلة جبال، كاشفًا تضاريس مقطوعة واحدة."},"ICON-0082":{"nm":"جهاز ضبط الأوتار","de":"قبيل العرض مباشرة، تلمس الأوتار الستة واحدًا تلو الآخر لتُعيد النغمات الشاردة إلى مكانها. حتى انحراف نصف درجة واحد يلتقطه الجمهور كالأشباح. ضبطها بدقة لا يلاحظها أحد—تلك هي اللطف الموجَّه للمسرح."},"ICON-0083":{"nm":"حزام يد","de":"لُفّه حول المعصم مرة واحدة فيتحلّل القلق من الإسقاط. أخوف ما على المسرح هو أن يفلت شيء من اليد، لذا يطمئن القلب أخيرًا بهذا الحزام الصغير الواحد."},"ICON-0084":{"nm":"صنج","de":"في لحظة اصطدام واحدة فقط، توضع نقطة واضحة على الجملة الأخيرة للأغنية. القرص الذهبي يعرف كيف يرنّ لأقصر مدة ويترك أطول صدى. هكذا يجب أن تُغلق النهاية، بهذا الإشراق."},"ICON-0085":{"nm":"جيتار","de":"حين تنزلق الأصابع فوق الأوتار الستة، تتحول غرفة ضيقة كليًّا إلى مسرح. أول لحن لأحدهم، وحديث النفس في فجر بلا نوم، كلاهما استمدّ نفسه الأول من داخل هذا الجسم الخشبي المستدير."},"ICON-0086":{"nm":"غيمة صوتية","de":"في طرف من السماء، تتجمع النوتات كالقطن وتطفو ببطء. يُقال إنه حين تمرّ الريح مرة واحدة، تسقط الألحان بدلًا من قطرات المطر—فيخرج أطفال الجزيرة لاستقبالها من دون مظلة."},"ICON-0087":{"nm":"خطوة رقص","de":"مسار المسرح حسابٌ يُحلّ بأطراف الأصابع. خطوة هنا، نصف نبضة هناك—لا بأس بالخطأ، فقط ببطء. الخانات التي دِيست مئات المرات ونُقشت في الجسد تجتمع لتكتمل أخيرًا خريطة مقطوعة واحدة."},"ICON-0088":{"nm":"مضخّم صوت","de":"صندوق يحوّل الهمس إلى هتاف. مع ذلك، قبل رفع الصوت درجة واحدة، تتوقف اليد دائمًا. أن الصوت الأدق، لا الأعلى، هو ما يصل إلى آخر صف في الجمهور—هذا ما يعرفه هذا الصندوق."},"ICON-0089":{"nm":"قطن النوتات","de":"حين تتجمع رؤوس النوتات المستديرة في كرة قطنية، تصير ناعمة كالوسادة. استلقِ عليها بهدوء وستسمع، بالكاد، تهويدة تتدفق—أرق شائعة في الجزيرة."},"ICON-0090":{"nm":"شريط كاسيت","de":"اضغط زر الترجيع فيصدر الشريط صريرًا ويعود ببطء إلى أول أغنية في ذلك الصيف. داخل صندوق صغير لُفّ فيه عصر بأكمله، ينام سليمًا زمنٌ لم يعد بالإمكان لمسه أبدًا."},"ICON-0091":{"nm":"شوكة رنانة","de":"اطرق الشعبتين المعدنيتين برفق فتولد نغمة مرجعية واحدة في الهواء. لهذه الرعشة الصغيرة، تنحني كل الآلات برأسها بصمت لتتوافق. بداية أي شيء تأتي من اهتزاز رقيق كهذا."},"ICON-0092":{"nm":"شريحة صوتية","de":"يُحبس جزء من صوت برفق داخل شريحة بحجم ظفر. تعليق عفوي لم يُسجَّل عمدًا، وضحكة أحدهم ظننت أنها اختفت، لا تزال تعيش وتتنفس دافئة داخل هذه الشريحة."},"ICON-0093":{"nm":"أسطوانة فينيل","de":"حين تخطو الإبرة خطوتها الأولى على طول التلم، يُسمع أولًا نفَس خافت من التشويش. بعشق ذلك الضجيج الصغير نفسه، لا يستطيع بعضهم حتى النهاية أن يتركوا هذا القرص الأسود من يدهم."},"ICON-0094":{"nm":"جيب صغير","de":"أعزّ ما تملك يبقى دائمًا في أقرب مكان إلى صدرك. كيس قماش واحد بحجم راحة اليد يصير في يوم دافئة يد، وفي يوم آخر تعويذة، وفي يوم ثالث خزانة أسرار."},"ICON-0095":{"nm":"لصقة جروح","de":"في ليالي التدريب الطويلة، يلتصق وسام صغير بكل كعب قدم. لصقة وُضعت لابتلاع كلمة \"يؤلمني\"—وعدٌ هادئ لا يعرفه أحد، بأن الرقص سيتواصل غدًا مهما كان."},"ICON-0096":{"nm":"وسادة نوم","de":"المكان الذي يُوضع فيه عبء مسرح يوم كامل هو، في النهاية، هذا المربع الناعم الواحد. أرجع رأسك عليه برفق، وسيخفت تدريجيًّا صدى التصفيق الذي بقي في أذنيك، وأخيرًا يهبط الليل على الجزيرة أيضًا."},"ICON-0097":{"nm":"جرس","de":"طنّة قصيرة واحدة، وإذا بأحدهم يدفع الباب ويدخل. إشارة إلى وصول ضيف، وتحية إلى انفتاح يوم جديد. قطعة معدن صغيرة واحدة تقضي يومها كله وهي لا تصدح إلا بالترحيب."},"ICON-0098":{"nm":"علبة حماية","de":"كلما ازداد الشيء قيمة، بُني له بيت خاص متين. اليد التي تفتحه وتغلقه تزداد حذرًا في كل مرة، لأن ما بداخله ليس مجرد غرض، بل قلبٌ لا تحتمل خسارته."},"ICON-0099":{"nm":"فرشاة تنظيف","de":"امسح على طول النسيج حتى آخر شعرة، فيتراجع الغبار الملتصق في الزوايا بهدوء. بفضل لمسة لا تتردد حتى في الأماكن غير المرئية، تستقبل الغرفة صباحًا جديدًا كل يوم."},"ICON-0100":{"nm":"رسم تخطيطي","de":"الخطوط قبل الاكتمال لا تُخفي تردّدها عناءً. في كل أثر مُمحًى ومُعاد رسمه، يبقى بلا كذب ما أراد أن يصير. البداية المتعثرة هي الأكثر صدقًا."},"ICON-0101":{"nm":"دمية","de":"ثمة كائنات تمنح العزاء لمجرد احتضانها دون كلمة تُقال. تلك الرفيقة القطنية التي ارتجفت معك بجانب الوسادة في ليالٍ ارتعشت فيها يداك خلف الكواليس، كلّ واحد منا يحمل مثلها في زاوية من قلبه."},"ICON-0102":{"nm":"جرس","de":"يقرع جرس المعبد الجبلي مرة واحدة فيعبر الوادي بأكمله. إنه قلب المعدن الذي يتوق إلى الوصول بعيدًا وأبعد، فيبكي بصوت طويل يهبط ببطء في صدر من يسمعه."},"ICON-0103":{"nm":"مظلة","de":"حين تُشارَك المظلة، لا بد أن يبتلّ أحد الكتفين. تحت المظلة المائلة قليلًا، الكتف المبلل هو أوضح دليل على اللطف. طريق قصير جُمع تحت سقف واحد يبقى طويلًا في القلب."},"ICON-0104":{"nm":"بساط تمرين","de":"افرشيه على الأرض العارية فيتحول المكان فورًا إلى غرفة تدريب. مكان يستقبلك دون كلمة كلما تدحرجت وسقطت، حركات لا تُحصى تعلّمت جسدها هنا لأول مرة."},"ICON-0105":{"nm":"جلجل","de":"هزّيه بهدوء فيتدحرج صوت صافٍ ورنّان في راحة يدك. الفرح الصغير المستدير الذي كان أطفال الزمن الغابر يعلّقونه في أطراف ثيابهم الملوّنة ويركضون به في الفناء، يستيقظ من جديد فوق راحة كفك."},"ICON-0106":{"nm":"ثعبان لعبة","de":"شكله الطويل المتدلي يُفزع الناس بخبث. خوفٌ ثم هروب ثم انفجار في الضحك أخيرًا، مزحة كهذه أيضًا فرع من فروع اللطف المتبادل."},"ICON-0107":{"nm":"لعبة","de":"لكل إنسان صندوق واحد على الأقل لا يقوى على التخلص منه حتى بعد أن يكبر. بداخله ضحكات أبهى الأيام ما تزال ملفوفة بإحكام كنابضٍ لم ينطلق بعد."},"ICON-0108":{"nm":"مائدة طعام صغيرة","de":"اِفرد رجليها المطويتين وأي مكان يصبح فورًا مكان العائلة. صوت الملاعق المتلامسة حين يجتمع الجميع حولها هو أدفأ لحن يتردد طوال اليوم."},"ICON-0109":{"nm":"صابون","de":"يصغر شيئًا فشيئًا في راحة اليد بينما يُطهّر أحدهم بصمت. أن يبلي نفسه ليغسل غيره، لا يظهر ذلك القلب الهادئ إلا بعد أن تخبو الرغوة كلها بزمن طويل."},"ICON-0110":{"nm":"مشط","de":"كما يُحلّ الشعر المتشابك خصلة خصلة، يستقيم يوم مضطرب رويدًا رويدًا أيضًا. لمسة عابرة أمام المرآة تُصلح خلسةً، إلى جانب الشعر، هندام القلب نفسه."},"ICON-0111":{"nm":"قفص طيور","de":"هناك طائر يغرّد دون أن يرحل حتى وإن كان الباب مفتوحًا على مصراعيه. قلبٌ يبقى لا لأنه محبوس بل لأنه يرغب في البقاء، هذا الفارق الدقيق يدركه هذا القفص قبل أي أحد آخر."},"ICON-0112":{"nm":"دفّاية اليد","de":"في طابور الانتظار الشتوي أمام قاعة العرض، يُدفئ دفء صغير في الجيب الأصابع المتيبسة بهدوء. لطف بحجم راحة اليد هزّه أحدهم مسبقًا ليدفئه، وهو يتخيلك ترتجف من البرد."},"ICON-0113":{"nm":"منديل","de":"قطعة قماش واحدة تستقبل الدموع والعرق دون تذمر. التطريز الصغير المنقوش في زاويتها يبقى هناك بلطف، كوداع أخير تركه من رحل أولاً، يقول له لا تنسَ."},"ICON-0114":{"nm":"بخاخ","de":"رشّة واحدة تُغيّر نسيج الهواء في لمح البصر. الضباب المنتشر فوق المسرح، والنبتة عند نافذة الصباح، داخل هذه القطرات الدقيقة يتحولان للحظة إلى عالم آخر يتلألأ."},"ICON-0115":{"nm":"شريط اختبار العطر","de":"اختيار العطر يشبه إلى حد بعيد اختيار ذكرى. خيط رائحة واحد لامسَ طرف ورقة رقيقة يجلب خلسةً إلى الأنف فصلًا كنت تظنه منسيًا."},"ICON-0116":{"nm":"طاولة طعام","de":"في كل حبة خشب باهتة محفور بهدوء عدد الوجبات التي شُوركت عليها. الأمسيات الصاخبة، والليالي المتأخرة التي قُضيت وحيدًا، هذا المربع احتضنها كلها دون كلمة واكتسب لمعانًا."},"ICON-0117":{"nm":"كبّة خيط","de":"اسحب أحد طرفيها برفق فتنفكّ بسلاسة، وبغرزة واحدة تعود لتلتحم. رتق ما انقطع يبدأ دائمًا بهدوء من خيط واحد رفيع، هكذا تمامًا."},"ICON-0118":{"nm":"معطف مطر","de":"حتى في الأيام المنهمرة، هذا الثوب الواحد هو ما يدفعك أخيرًا للخروج. من يعرف متعة الخوض في المطر مرحًا هو وحده من لا يتخذ المطر ذريعة للبقاء في البيت."},"ICON-0119":{"nm":"كيس صغير","de":"اجمع فوهته في دائرة صغيرة فيصبح ما بداخلها آمنًا أخيرًا. في كيس صغير باهت من كثرة اللمس، تتمايل معًا عملة معدنية، وذكرى يوم ما، وكلمات لم تُقل حتى النهاية."},"ICON-0120":{"nm":"رفّ كتب","de":"مرّر إصبعك ببطء على ظهور الكتب المصفوفة، فتلمس أطراف أصابعك الفصول التي مرّت بك. سبب عجزك عن التخلص من كتاب أنهيت قراءته هو أن ذاتك في ذلك الحين ما زالت تعيش هناك."},"ICON-0121":{"nm":"برج كتب","de":"الكتب المقروءة تُرقد على جنبها، والكتب غير المقروءة تُكوَّم فوقها. حتى وإن اهتز الوعد بقراءتها كلها يومًا ما قرب السقف قليلًا، فإنك تحب ذلك الاهتزاز نفسه، فتضيف اليوم كتابًا آخر."},"ICON-0122":{"nm":"عجلة الجري","de":"قد يبدو الأمر وكأنك تدور في مكانك مهما ركضت بجد، لكن القدمين الصغيرتين تتعلمان أولًا إيقاع أطراف الأصابع. الأيام السابقة التي لم تتوقف تجتمع، وذات يوم تتلألأ ساطعة على طريق حقيقي."},"ICON-0123":{"nm":"غطاء","de":"حتى لا يعلوها الغبار، وحتى لا تبهت تحت الشمس، حتى فعل التغطية يحمل عناية أطراف الأصابع. كلما ازداد اعتزازك بشيء، ازداد احتضانه برقة في الأماكن غير المرئية."},"ICON-0124":{"nm":"خيط صوف","de":"خصلة واحدة كانت تنفكّ متدحرجة فوق حجر جدتي. قد تبدو متشابكة، لكن ابحث عن طرفها واسحب برفق فتتبعك بلا فشل. هكذا طالت ليالي الشتاء غرزة غرزة."},"ICON-0125":{"nm":"حقيبة صغيرة","de":"مرهم شفاه، رباط شعر، رسالة مطوية بعناية، مهما بدت صغيرة، تحمل بداخلها قلب يوم كامل. مع صوت إغلاق السحّاب، تصبح كل الأشياء الصغيرة الثمينة آمنة دفعة واحدة."},"ICON-0126":{"nm":"مسند ذراع","de":"بعد ظهيرة غفوت فيها وأنت تقرأ، ومساء ترددت فيه جيئة وذهابًا أثناء مكالمة. في البقعة التي يتعمّق أثرها كلما طال جلوسك، تجمّعت بهدوء كل لحظات الراحة التي يتذكرها المرفق، بمقدار شبر."},"ICON-0127":{"nm":"عبوة مختومة","de":"قبل أن تُفتح، لا تنتمي لأحد بعد. كيس مختوم يفيض بترقب لم يُفتح بعد، فترتجف أطراف الأصابع الممسكة بزاويته قليلًا. هذا هو إثارة الفتح."},"ICON-0128":{"nm":"ورق تغليف","de":"قلبٌ يصل قبل الهدية بخطوة. بينما تطوي الزوايا لتتساوى وتربطها بشريط، ينفتح مسبقًا في يديك وجه المتلقي المبتسم مشرقًا."},"ICON-0129":{"nm":"ذراع تحكم الألعاب","de":"الأزرار التي يتذكرها الإبهام قبل أن يتذكرها الرأس. خسرتَ لكن جولة واحدة أخرى فقط، وتلك الجولة تنتهي بك ساهرًا الليل بطوله. الوزن الذي يلائم اليد تمامًا يرفع بهدوء مغامرة هذه الليلة."},"ICON-0130":{"nm":"إشارة مرور","de":"الأحمر يعني توقف قليلًا، والأخضر يعني يمكنك المضي الآن. بوعد بسيط واحد، تتدفق طرق لا تُحصى دون أن تتشابك. أن للانتظار أيضًا دورًا، يخبرك به الضوء الوامض بلطف."},"ICON-0131":{"nm":"سهم","de":"أرقّ شكل بالنسبة لمن ضلّ الطريق. حين يستعصي عليك معرفة أين تتجه، اتجاه واحد رسمه أحدهم من قبل يجعل خطواتك المتوقفة ثابتة من جديد."},"ICON-0132":{"nm":"إحداثيات","de":"برقمين اثنين فقط، يمكنك تحديد أي مكان في العالم بدقة. المكان الذي اتفقتم على اللقاء فيه، والشاطئ الرملي الذي دُفن فيه الكنز. حتى لا يضيع الوعد طريقه، تمسكه نقطة صغيرة واحدة حتى النهاية."},"ICON-0133":{"nm":"بلاطة","de":"وحدها، مجرد قطعة مربعة. لحظة أن تستلقي جنبًا إلى جنب كتفًا إلى كتف، تصبح أرضية وجدارًا. أشياء صغيرة تجتمع لتصنع مكانًا يطمئن فيه أحدهم لوضع قدمه."},"ICON-0134":{"nm":"ساعة رملية","de":"حين تفرغ الحجرة العلوية، تمتلئ السفلى ببطء. بمشاهدة الرمل يتسرب برفق نؤمن أن الزمن يمضي. اقلبها وتعود للبداية من جديد، هذه هي كذبة الرمل اللطيفة."},"ICON-0135":{"nm":"كرة","de":"ارمها فتعود، اركلها فتتدحرج. كونها مستديرة لا تعرف إلى أين ستقفز هو أعظم سحرها. في وسط الملعب، كانت الضحكات تبدأ دائمًا مستديرة من هذا الجسم الصغير الكروي."},"ICON-0136":{"nm":"مفتاح كهربائي","de":"طقّة، تضيء دفعة واحدة وتنطفئ دفعة واحدة. ذلك الصوت الصغير الذي يُسمع عند الدخول لغرفة مظلمة يفصل بداية اليوم المشتتة عن نهايتها بخط واحد واضح."},"ICON-0137":{"nm":"علامة استفهام","de":"عدم معرفة الجواب ليس أمرًا مخجلًا. إنه دليل مُبهج على أن الفضول ما زال حيًا. حين يطرق هذا الخطاف الصغير رأسك برفق، يخطو التعلّم أولى خطواته أخيرًا."},"ICON-0138":{"nm":"عود ثقاب","de":"عود واحد يحرق جسده ليمنح النار. يحترق لبرهة قصيرة ثم يختفي بصمت، لكن في تلك اللحظة الخاطفة تُضاء شمعة ويُدفأ موقد. عطاء صغير يصبح الزر الأول للدفء."},"ICON-0139":{"nm":"مِرقاة صغيرة","de":"اصعد عليها بقدم واحدة فقط فتصل يدك حتى إلى الرف الذي لم تكن تطاله. عمل يزيد طول أحدهم لحظة. هنا مكان لطيف ينحني منخفضًا ليرفعنا برفق."},"ICON-0140":{"nm":"ساعة يد","de":"أول شيء تُربط به رسغك في اليوم الذي عزمت فيه على الرياضة. مدرّب صغير يعدّ نبضات القلب وعدد الخطوات، يطرق برفق ليخبرك أنك مشيت اليوم أكثر قليلًا من الأمس."},"ICON-0141":{"nm":"منبّه","de":"أوفى صديق يُكره كل صباح. بفضله يخوض عنك معركة الدقائق الخمس الإضافية تحت الغطاء في كل مرة، لا تتأخر المواعيد ولا الأحلام. ذلك الصوت الذي يرن بقسوة هو في الحقيقة تشجيع."},"ICON-0142":{"nm":"نواة","de":"الجزء الأعمق الذي يبقى حتى النهاية بعد أن يُقشَّر كل ما هو خارجي. بذرة التفاحة، صدق القلب، مهما كان الأمر، يحمل مركزه الأصلب. نقطة واحدة تبقى في النهاية مهما اهتزت."},"ICON-0143":{"nm":"قلم","de":"البقعة التي تسربت خلسة على حافة اليد قبل أن يجفّ الحبر. سواء كتب بسلاسة أم لا، الخط الأول المرسوم أمام ورقة بيضاء يحتاج دائمًا شجاعة صغيرة. إنه الجسر الذي تعبر عليه الأفكار إلى أطراف الأصابع."},"ICON-0144":{"nm":"فرشاة الحبر","de":"حين تحمل الحبر وتمرّ فوق ورق الهانجي، تبقى حتى أصغر رعشة تردّد كاملة. من يستعجل بجشع سرعان ما يُفتضح أمره. الفرشاة أول من يعرف الصدق الكامن في أطراف الأصابع."},"ICON-0145":{"nm":"فقاعة كلام","de":"المكان الذي يطفو مستديرًا فوق الرأس قبل أن تخرج الكلمة من الفم بعد. هنا تُحفظ الكلمة الواحدة التي تريد قولها. حين تكون فارغة، فهي في خضم اختيار ما تملؤه به."},"ICON-0146":{"nm":"مربع اختيار","de":"ارسم خطين في المربع الفارغ فيغدو القلب أخفّ. وسام صغير تمنحه لنفسك على مهمة أنجزتها. في نهاية اليوم، وأنت تنظر إلى المربعات الممتلئة، تطمئن نفسك أنك عشت هذا اليوم أيضًا بخير."},"ICON-0147":{"nm":"لوح رقمي","de":"أينما لمست الأصابع، تنتشر الرسوم وتتدفق الحروف. ضعه بهدوء على حجرك فيضيء عالم كامل. خفيف الوزن، لكن الاحتمالات المكنونة بداخله ليست رقيقة أبدًا."},"ICON-0148":{"nm":"جهاز تحكم عن بعد","de":"يملك موهبة فطرية في الاختباء بين شقوق الأريكة. سلطة تغيير القنوات دائمًا لمن يمسكه. أصغر خلافات العائلة وأكثرها ألفة تدور فوق هذا الشبر الواحد."},"ICON-0149":{"nm":"ثقل موازن","de":"وزنٌ خفض نفسه إلى أدنى نقطة ليُثبّت ما يتمايل. مهما اهتز الأعلى، إن كان الأسفل ثقيلًا فلن يسقط في النهاية. التوازن يصمد دائمًا في مكان لا يُرى."},"ICON-0150":{"nm":"أحجية مقطوعة","de":"ليلة تحسّست فيها حتى أسفل الأريكة بحثًا عن القطعة الأخيرة الناقصة. تلك النشوة الصامتة للحظة انزلاقها في مكانها تمامًا. حين تجد الأشياء المبعثرة أماكنها، تكتمل الصورة أخيرًا."},"ICON-0151":{"nm":"مسطرة","de":"قياس الطول هو أيضًا نوع من الوفاء بالوعد. لكي يكون الشبر واحدًا للجميع، تصطف العلامات بصدق. خط مستقيم واحد قادر على تسوية حتى قلب معوجّ."},"ICON-0152":{"nm":"قماش الرسم","de":"السطح الأبيض الخالي هو الأكثر إخافة، والأكثر إثارة أيضًا. لأنه قبل وضع النقطة الأولى، يمكنه أن يصبح أي شيء. الفراغ ليس نهاية، بل اسم آخر للبداية."},"ICON-0153":{"nm":"مكعب روبيك","de":"أكثر من شخص سهر ليلته كاملة محاولًا مطابقة الأوجه الستة. إصرار أطراف الأصابع التي تُدير وتُدير من جديد. حين تجد الألوان المختلطة أماكنها، ينتظم كون صغير برشاقة."},"ICON-0154":{"nm":"جهاز ألعاب محمول","de":"شاشة صغيرة كان أبناء العم يتزاحمون حولها في العطلة. عالم مغامرة يسع براحة كف واحدة. مجرد سماع لحن واحد من نغمة التشغيل، وذلك الصيف بأكمله يعود دفعة واحدة."},"ICON-0155":{"nm":"مقبض","de":"ذلك الإحساس بأنها تلتصق باليد حين تقبض عليها بإحكام يمنح ثقة خلسة. حتى لا تنزلق، حتى لا تفلت. في أخطر لحظة، هي نقطة الوصل التي تربط اليد بالأداة في كتلة واحدة صلبة."},"ICON-0156":{"nm":"قلم حبر","de":"طوال ما تكتب بحبر مملوء، يزداد خطك أنيقًا قليلًا. تهدئ قلبك على صرير الريشة، فتشبه بهدوء تلك العناية التي كانت تبدأ ببطء السطر الأول من رسالة مكتوبة باليد."},"ICON-0157":{"nm":"لوح ألوان","de":"أزرق بجانب أحمر، أخضر فوق أصفر. فوق هذا اللوح الصغير حيث ترقد الألوان مصطفة بهدوء، تكتسب اللوحة تعبيرها أخيرًا. كل مغامرات المزج والتطبيق تخطو أولى خطواتها هنا."},"ICON-0158":{"nm":"طقم","de":"كل قطعة بمفردها قد تبدو عادية، لكن مجتمعة جنبًا إلى جنب تصبح قصة واحدة. تلك الطمأنينة حين لا تنقص قطعة واحدة وكل شيء مكتمل. جمع الأشياء المتناثرة في مكان واحد يحمل فرحة اكتمال صغيرة."},"ICON-0159":{"nm":"ريشة تنس الريشة","de":"صوت الريح الناعم الذي تصدره الريش حين تنطلق عاليًا بعد ضربة المضرب. تبدو خفيفة جدًا لدرجة أنها لن تصل بعيدًا، لكن إن ضُربت بعزم، تطير مستقيمة حتى نهاية الملعب. الخفة أيضًا نوع أصيل من القوة."},"ICON-0160":{"nm":"هوائي","de":"يقف بهدوء متجهًا نحو السماء محاولًا التقاط إشارة لا تُرى. ذلك الصبر الذي يجذب حتى الأصوات البعيدة في النهاية. في الأيام التي يضعف فيها الاستقبال، أدر الزاوية قليلًا فيصفو من جديد."},"ICON-0161":{"nm":"سماعة طبية","de":"الطرف المستدير البارد الملامس للصدر، ونَفَسٌ يتوقف للحظة. اجمع أذنك نحو دقة طبل صغيرة واحدة، فينتقل إلى أطراف أصابعك أقدم إيقاع للحياة. أداة يأتي فيها الاستماع أولًا."},"ICON-0162":{"nm":"بيدق شطرنج","de":"بيدق صغير كان يمشي ببطء مربعًا واحدًا في كل مرة. ومع ذلك، حين يبلغ الصف الأخير، يمكنه أن يصبح أي شيء. تلك الحركة الواحدة التي تقلب رقعة اللعب بأكملها بخطوة خرقاء، تراقبها رقعة الشطرنج العتيقة بصمت."},"ICON-0163":{"nm":"يد التحكم","de":"أتذكر تلك الليالي التي جُبت فيها الكون بإبهامين اثنين؟ المقبض الباهت من كثرة اللمس الذي رميته غاضبًا من الخسارة، ثم التقطته من جديد بحرج. أطول وأدفأ حوار شاركته بصمت مع أحدهم عبر الشاشة."},"ICON-0164":{"nm":"وحدة ألعاب","de":"شغّل الطاقة فيرنّ صوت تشغيل صغير كتحية. الصندوق المربع الذي كنت تشغّله وتطفئه تحت الغطاء طوال العطلة، مغامرة الطفولة الأولى كانت تبدأ دائمًا في وهج هذه الشاشة."},"ICON-0165":{"nm":"خط زمني","de":"الطرف الأيسر هو البداية، والطرف الأيمن يوم لم يأتِ بعد. اسحب نقطة واحدة إلى أي مكان بينهما، وتنفتح من جديد لحظة كنت تظنها منسية. مكان أُرقد فيه الزمن في خط واحد."},"ICON-0166":{"nm":"منشور","de":"من كان يظن أن الضوء الصافي وحسب كان يخفي سبعة ألوان طوال الوقت. السر الذي ينفتح إلى قوس قزح لحظة مروره عبر شظية زجاج. كلما بدا الشيء أكثر ترتيبًا، اختبأت بداخله ألوان أكثر."},"ICON-0167":{"nm":"وتد جولف","de":"قاعدة صغيرة واحدة توضع عليها الكرة بهدوء. كلما زادت رغبتك في إرسالها بعيدًا، احتجت أولًا إلى شيء يسندها بثبات. هذا الوتد الصغير فوق العشب يحمل الخطوة الأولى."},"ICON-0168":{"nm":"إبرة تريكو","de":"غرزة، ثم غرزة أخرى. أفلِت واحدة فقط وعليك أن تفكّ كل شيء وتعود للبداية. الوشاح الذي طال ببطء فوق حجرك طوال فصل شتاء، المكان الذي نُسج فيه صبر أطراف الأصابع دفئًا."},"ICON-0169":{"nm":"لحن مبدئي","de":"مقطع واحد كان يتسرب من شفتيك دندنة قبل أن توضع الكلمات فوقه. في ذلك اللحن الغامض الذي لم يُلبس بالحروف بعد، يكمن أصدق وجه أول للأغنية."},"ICON-0170":{"nm":"رادار","de":"يطلق إشارة نحو الظلام الذي لا يراه، وينتظر بهدوء نقطة واحدة عائدة. صبر الضوء الأخضر المستدير الذي يؤمن أن هناك شيئًا حتى حين لا يُرى شيء."},"ICON-0171":{"nm":"لوحة إيقاع","de":"طرقة طرقة، اطرق برفق فيقفز الضوء والصوت معًا في اللحظة نفسها. مكان يجعل اليدين تحفظان الإيقاع قبل الرأس. أصغر مسرح وأكثره ودًا، منتشر فوق راحة الكف."},"ICON-0172":{"nm":"طلاء","de":"الرسامون القدامى كانوا يطحنون الحجر والتراب ليحصلوا على اللون. النيلي من العشب، والأحمر من التراب. حتى في هذه القطرة الواحدة التي تُعصر الآن على أطراف الأصابع، تسري العناية العتيقة التي كانت تنقل الطبيعة برفق إلى وعاء."},"ICON-0173":{"nm":"خط","de":"الشيء الذي يولد فقط في اللحظة التي تقرر فيها وصل نقطة بنقطة. قصيرًا كان أم طويلًا، منحنيًا أم مستقيمًا، هو أبسط أثر تتركه الرغبة في الذهاب إلى مكان ما. بداية كل رسم."},"ICON-0174":{"nm":"غالق الكاميرا","de":"طقّة، تلك الظلمة الخاطفة الواحدة تمسك بمشهد إلى الأبد. حتى تعبير كنت ستفوّته في رمشة عين، تقتطع منه شذرة ضوء وتصلّبه إلى ذكرى. نصل صغير."},"ICON-0175":{"nm":"حبل أمان","de":"الحبل الذي يُربط بإحكام قبل الشخص الصاعد إلى مكان مرتفع بخطوة. يمسك عنك القلب الذي يقلق من السقوط، حارسًا جانبك دون أن يُرى، رباط وعد يبقى دائمًا خلف ظهرك."},"ICON-0176":{"nm":"قفل حديدي","de":"قفل حديدي ثقيل كان يُقفل به المخزن. لم يكن ليحبس شيئًا، بل كان رغبة في ترك ما هو ثمين مطمئنًا. حتى اليد التي تُقفله كانت تحمل عناية، صلابة البيت القديم الدافئة."},"ICON-0177":{"nm":"ميزان","de":"حين تثقل كفة، تخفّ الأخرى تلقائيًا. في تلك اللحظة من التردد بشأن ما تضعه وكم منه، يتعلم الإنسان الإنصاف. ذراعان تتمايلان لتعلّما التوازن."},"ICON-0178":{"nm":"فلّاقة صغيرة","de":"حتى ما التصق بإحكام ينشقّ في النهاية إن تتبعت خطوطه. أداة صغيرة تقسم أي شيء إلى نصفين لتنظر إلى داخله. أطراف أصابع فضولية تتوق لتفكيك ما اجتمع والنظر إليه من جديد."},"ICON-0179":{"nm":"عدّاد","de":"واحد، اثنان، ثلاثة. صديق صغير يعدّ الأرقام بصمت بدلًا من أصابعك. رفيق العدّ اللطيف الذي يحوّل القلق من نسيان عدّ شيء إلى طمأنينة، نقرة نقرة."},"ICON-0180":{"nm":"مؤشر","de":"سهم صغير يومض في مكان ما على الشاشة منتظرًا الأمر التالي. حتى وأنت مترددًا، لا يغادر مكانه، طرف الضوء الذي يشير بهدوء وكأنه يقول: لنبدأ الآن."},"ICON-0181":{"nm":"قبضة تسلق","de":"النقطة الأخيرة التي تتشبث بها قبل أن تخور قوة أطراف أصابعك تمامًا. أن هناك لحظات تصمد فيها بإرادة واحدة ألا تُفلت، تخبرك بها بهدوء تلك النتوءة الصغيرة على الجدار."},"ICON-0182":{"nm":"حصاة","de":"حجر تدحرج طويلًا في الجدول متخليًا عن كل زواياه. أن يستدير هو اسم آخر للزمن الذي تآكل. أمسكه بهدوء في راحة يدك، وستلمس صبر النهر المتدفق."},"ICON-0183":{"nm":"شعار نبالة","de":"كانت العائلات القديمة تنقش وحوشًا ونجومًا على راية واحدة لتعرّف بنفسها. صورة أوصلت القلب قبل الكلمات. علامة عتيقة تُختزل فيها كرامة إنسان بعناية في إطار صغير واحد."},"ICON-0184":{"nm":"درع","de":"الوقوف في طريق الخطر كان دائمًا من أجل من يقف خلف ظهرك. يتلقى بدلًا عنك السهام القادمة، حارسًا يومًا عاديًا لأحدهم، جدارًا ثقيلًا ولطيفًا في آنٍ واحد."},"ICON-0185":{"nm":"انبعاث","de":"هناك قلب ينطفئ ثم يضيء من جديد. لا تتعلم كيف تنهض إلا بعد أن تسقط مرة واحدة. نَفَسٌ ثانٍ يتصاعد بهدوء في المكان ذاته الذي ظننته النهاية."},"ICON-0186":{"nm":"قوس","de":"اليد التي تنوي الإرسال بعيدًا تسحب الوتر أولًا إلى أقصى مداه. لكي تُطلق شيئًا، عليك أن تحتضنه قريبًا بالقدر ذاته، يخبرك بذلك بصمت القوس المشدود المنحني."},"ICON-0187":{"nm":"قلب","de":"كلمة «أحبك» تتقلّص باستمرار إلى شكل صغير. هذا الشكل المرسوم خلسة على طرف عصا الإضاءة، وبين إصبعين متلامسين. أشيع وأصدق اختزال للقلب."},"ICON-0188":{"nm":"غيمة","de":"تنساب ببطء نحو اتجاه الريح لتصبح وجهًا مختلفًا في كل مرة. أرنبًا تارة، وقطنًا تارة أخرى، دون أن تتشبث بشيء طويلًا، تدَع كل شيء يمرّ، أخفّ قلوب السماء."},"ICON-0189":{"nm":"متاهة","de":"مكان تتعلم فيه كيف تعود أدراجك أمام جدار مسدود. حتى وأنت تتوه، تنمو خطواتك شيئًا فشيئًا نحو المخرج. عليك أن تضل الطريق مرة واحدة لتنفتح بصيرتك."},"ICON-0190":{"nm":"سنّ","de":"كانت هناك عادة رمي السنّ الساقطة فوق السطح. أمنية صغيرة أن ينبت السن الجديد مستقيمًا. وعد طفولي لطيف مفاده أنك يجب أن تفقد شيئًا مرة وأنت تكبر لتكسب شيئًا أصلب."},"ICON-0191":{"nm":"كوكب","de":"جسم مستدير يدور حول نجمه دون أن يحيد عن مساره ولو مرة. قد يبدو وحيدًا، لكن جاذبيته تُبقي دائمًا شيئًا يدور بجانبه. الاحتفاظ بمكانك بصمت يصبح عالمًا بحد ذاته."},"ICON-0192":{"nm":"نجم","de":"في الليالي التي ضلّ فيها الناس الطريق، كانوا يرفعون أعينهم نحو أسطع نقطة. ضوء بعيد المنال، لكنه يشير إلى الاتجاه بوضوح. وعد يزداد صلابة لكونه بعيدًا."},"ICON-0193":{"nm":"ظل شخصي","de":"قف وظهرك للضوء فلا يبقى من الإنسان سوى محيطه. شكل أسود واحد، مُحيَ منه الاسم والتعبير. مساحة غير مملوءة تجعلك تتخيّل أكثر لأنها فارغة."},"ICON-0194":{"nm":"أذن","de":"لتُحسن الغناء، عليك أولًا أن تُحسن الاستماع. الإيقاع والقلب كلاهما يبدآن في النهاية من الاستماع. باب صغير مستدير مفتوح، تصل إليه وتمكث فيه كل أصوات العالم أولًا."},"ICON-0195":{"nm":"ورقة خريف","de":"هناك أوراق تتلألأ بأجمل ما تكون في لحظة سقوطها بالذات. خفة إحراق أخضر فصل كامل إلى أحمر ووضعه برفق. الخريف يُرينا أن النهاية أيضًا يمكن أن تكون بهذا الجمال."},"ICON-0196":{"nm":"قمر","de":"كانت هناك ليالٍ تُضم فيها الأيدي وتُتلى الأمنيات تحت الضوء المستدير في ليلة تشوسوك. وجه لم يتشابه مرة واحدة وهو يتكرر بين الامتلاء والنقصان. مصباح يتغير لكنه يضيء المكان ذاته دومًا."},"ICON-0197":{"nm":"قلب","de":"حتى على المسرح، أصدق شيء في النهاية هو هذه الدقة. لا يتوقف رغم ارتجافه، ويخفق أشد حين يفيض. طبل صغير أحمر يخفق نيابة عنك بتشجيع لم تكمله الكلمات."},"ICON-0198":{"nm":"ظل","de":"رفيق لا يفارقك أبدًا طالما هناك ضوء. يزداد قتامة كلما ازداد الضوء سطوعًا، ويخفّ كلما خفت، أنا آخر تبعني أطول من أي شيء. شخص واحد يقف بجانبي حتى في أيام الوحدة."},"ICON-0199":{"nm":"ذيل","de":"يهتزّ من تلقاء نفسه حين يكون سعيدًا، وينكمش خلسة حين يخاف. طرف صادق لا يقوى على إخفاء القلب حتى وإن أطبق الفم بإحكام. الشعور الداخلي الذي يُسرّبه الجسد أولًا."},"ICON-0200":{"nm":"رباط ذيل","de":"شريط صغير يُربط عند الطرف لينهي الشكل، كالشريط المزركش. قلبٌ عقد العقدة مرة أخرى بإحكام كي لا تنحل. ربطة لطيفة تجمع الأشياء السهلة التشتت في مكان واحد وتُهدّئها."},"ICON-0201":{"nm":"بؤبؤ العين","de":"يمكنك انتقاء كلماتك، لكن لا يمكنك إخفاء نظرة عينيك. فهناك، داخل تلك الدائرة السوداء، يتسرب القلب المكشوف أولاً. حتى لو ابتلعتَ كلمة «أحبك»، فإن حدقتيك ترتجفان بالفعل نحوك."},"ICON-0202":{"nm":"حدوة الحصان","de":"قطعة من الحديد ازدادت صلابة كلما تآكل طرفها من طول الطرقات. يُقال إنها إذا عُلّقت مقلوبة فوق الباب، يتجمّع فيها الحظ القادم والذاهب. بصمت، تسند عودة أحدهم سالماً إلى داره."},"ICON-0203":{"nm":"حجر الشعار","de":"حتى وإن طمست الرياح والأمطار الحروف، فإن تتبعها بأطراف أصابعك يُحيي النقش الغائر بوضوح من جديد. إنه ثقل قلبٍ لم يُرد أن يُنسى. هكذا يحتضن الحجر اسماً واحداً زمناً طويلاً."},"ICON-0204":{"nm":"قدم مكفّفة","de":"بغشاء رقيق واحد يصل بين الأصابع، تتعلم كيف تدفع الماء. مجذاف صغير دسّته الطبيعة خلسة في يد سبّاح غير ماهر. تصميم رقيق يوصلك، ولو ببطء، إلى الضفة الأخرى في النهاية."},"ICON-0205":{"nm":"الترتر","de":"يتذمر الجميع من أنه يلتصق باليد ويلازمها أياماً، ومع ذلك في يوم الاحتفال يتسابقون على حبات الضوء هذه أولاً. رشّة من غبار النجوم تجعل حتى الورق العادي يتلألأ، فيصير اليوم مميزاً."},"ICON-0206":{"nm":"المخلب","de":"وحوش الغابة تخدش التراب بمخالبها لتترك دربها. ليست تهديداً بل أثراً، توقيعاً صامتاً يقول إنها مرّت من هنا. طرف حاد قد يصبح، لدى البعض، علامة طريق رقيقة."},"ICON-0207":{"nm":"البرق","de":"في اللحظة التي تفتح فيها السماء كفّها لحظياً كاشفة خطوطها، يصل الضوء قبل الرعد. كأنه يطلب منك أن تلتقط أنفاسك قبل أن يبلغك الصوت العظيم. الخوف والدهشة يولدان دوماً معاً من الومضة ذاتها."},"ICON-0208":{"nm":"التميمة","de":"سطر من الرجاء مطبوع بالحبر بإحكام على ورقة حمراء. كانوا يؤمنون أنها، إن وُضعت تحت الوسادة، تُبعد الأحلام السيئة. قلبٌ يدعو لسلامة أحدهم دافئ هكذا حتى في ورقة رقيقة واحدة."},"ICON-0209":{"nm":"جناح الفرشاة","de":"ثمة لحظات يتحول فيها طرف الفرشاة إلى جناح. تلك الخفة وهي تنزلق فوق الورق عند رسم ضربة واحدة. أن تكتب هو أن تطير في جوهره، وهذا ما أدركته يد قديمة كانت تطحن الحبر، إدراكاً مبهماً."},"ICON-0210":{"nm":"العظم","de":"ما يتبقى فقط بعد أن يتلاشى كل اللحم. الهيكل الأبيض الذي صمد حتى النهاية لأنه كان الأصلب. دليل صامت وحيد يتذكر الشكل على الأقل، وإن أخذ الزمن كل ما عداه."},"ICON-0211":{"nm":"الأنف","de":"الرائحة أقصر طريق إلى الذاكرة. رائحة الزيت في مطبخ العيد، هواء الصباح البارد بعد أول ثلج، طرف الأنف يلتقطها أولاً والقلب يلحق به بعد لحظة."},"ICON-0212":{"nm":"التوست","de":"وجبة الصباح المزدحم الأسرع تناولاً. عضّة واحدة من السطح المحمّص الذهبي تجعل شجاعة يوم كامل تتفتت بصوت مقرمش. الأشياء البسيطة غير الفخمة هي التي تنهض بالإنسان مجدداً."},"ICON-0213":{"nm":"كوكيز","de":"من ينتظر أطول أمام الفرن يظفر باللقمة الأولى. دفء الحافة المخبوزة للتو، وحلاوة عابرة. كلما خُبزت وأنت تفكر في أحد، ازدادت غرابة حلاوتها."},"ICON-0214":{"nm":"وجبة خفيفة","de":"في عصرٍ يطول فيه التمرين، كيس صغير يُخرج من أعماق الحقيبة. اقسمه إلى نصفين وستتضاعف الشبعة بعجب. حفنة من الحنان تملأ القلب قبل أن تملأ المعدة."},"ICON-0215":{"nm":"الكبسولة","de":"لا أحد يعرف ما بداخلها حتى يفتحها بالتدوير. ما يكمن داخل القشرة المستديرة هو دائماً نفس خفقان القلب. أصدق إثارة في العالم، حيث تُباع الصدفة الصغيرة وتُشترى."},"ICON-0216":{"nm":"مقبض الباب","de":"المكان الذي تلمسه أولاً أيادٍ لا تُحصى وهي تفتح الباب وتغلقه. تحية البيت الأولى، تبدأ باردة ثم تدفأ في راحة اليد. كلما تراكمت لمسات الأيدي، صارت تلك الغرفة شيئاً فشيئاً بيتاً لأحدهم."},"ICON-0217":{"nm":"نزهة","de":"حتى المشي بلا وجهة له سببه. وقتٌ تحلّ فيه الأفكار المتشابكة خيطاً خيطاً مع كل خطوة. تعود بعد دورة كاملة والجواب لم يتغير، لكن القلب وحده أصبح أخفّ بكثير."},"ICON-0218":{"nm":"السكوتر","de":"عجلتان تشقان الأزقة الضيقة. ليست سريعة، لكنها تستقبل الريح بكامل الجسد. أياماً تريد فيها فقط أن تنطلق منتعشاً اليوم، ولا بأس إن لم تصل بعيداً."},"ICON-0219":{"nm":"حاجز الأمان","de":"قبل الصعود، عارضة واحدة تنزل بإحكام أمام الصدر. وعدٌ مطمئن يرافقك حتى نهاية المرحلة المخيفة. يخبرك، بردٍ وصمت، أنه لا بأس أن تتشبث به بقوة."},"ICON-0220":{"nm":"الدرج","de":"تصعد درجة تلو أخرى وفجأة يتغير المشهد من حولك. تتعلم أخمص قدميك أولاً أنه لا ارتفاع يُبلغ بقفزة واحدة. الصعود والنزول بحد ذاته كان، لدى أحدهم، خطوات يوم كامل."},"ICON-0221":{"nm":"التيراريوم","de":"ليست حبس غابة في زجاج، بل رعاية عالمٍ كاملٍ بعناية. كون بحجم راحة اليد تنتشر فيه الطحالب وتتكوّن قطرات الماء. كلما أطلت النظر فيه، صبغ قلبك ببطء لوناً أخضر."},"ICON-0222":{"nm":"المنصة","de":"تصعد إلى مكان أعلى بشبر واحد فيتغير المشهد الذي تراه. مكانٌ يلتقي فيه الخوف والفخر عند الارتفاع نفسه. وتبعاً لمن يقف عليها، تصبح تلك الدرجة الواحدة مسرحاً مختلفاً في كل مرة."},"ICON-0223":{"nm":"الطائرة","de":"لحظة تفترش فيها الغيوم تحت قدميك، يبدأ الحنين أخيراً إلى المكان الذي غادرته. ليس ابتعاداً، بل اتساعاً للعالم. حتى حلم نشأ في جزيرة صغيرة يعبر السماء هكذا."},"ICON-0224":{"nm":"لوح التزلج","de":"شيء لا يمكنك ركوبه إلا بعد أن تتعلم كيف تسقط أولاً. في كل مرة تُخدش فيها ركبتاك، يُنقش التوازن قليلاً في جسدك. أربع عجلات صادقة تتدحرج أبعد كلما أحسنتَ السقوط."},"ICON-0225":{"nm":"جواز السفر","de":"تقلب الغلاف فتجده مليئاً بصفحات فارغة. كل ختمٍ سيُملأ يصبح دليلاً على حياة عِيشت. كتيّب صغير يحمل، لا ما بلغته من مسافة، بل إمكانية الذهاب إلى أي مكان على الإطلاق."},"ICON-0226":{"nm":"خريطة مرسومة باليد","de":"لا مسافة دقيقة فيها ولا مقياس رسم، لكنها طريق رُسم باليد فلا خوف من الضياع فيه. ورقة تتشابك فيها أسماء الأزقة والمحال بحميمية. الإرشاد الذي يحمل قلباً دائماً أدفأ من الطريق نفسه."},"ICON-0227":{"nm":"مخطط حركة المسرح","de":"ورقة تُرسم عليها كل خطوة على المسرح كخط. أين تتوقف وأين تستدير، تعدك به الأسهم مسبقاً. حتى الرقصة التي تبدو حرة تبدأ في الحقيقة من هذه الورقة الواحدة."},"ICON-0228":{"nm":"دليل المقاعد","de":"في مكان غريب، أول ما تتلمسه بحثاً هو مقعدك. تتبع الصف والرقم حتى تصل أخيراً إلى تلك الخانة الواحدة. ورقة واحدة تُجلس آلاف الخفقات بعناية، كلٌّ في مكانه."},"ICON-0229":{"nm":"بطاقة إرشاد الزقاق","de":"إرشاد كتبه أحدهم بخط يده لمن قد يضل طريقه في أزقة كالمتاهة. خط رقيق يخبرك عند أي زاوية تنعطف. دفء الحيّ كله يتجمع بوضوح في بطاقة صغيرة واحدة."},"ICON-0230":{"nm":"بطاقة التصريح الأمني","de":"فقط حين تعلّق هذه البطاقة حول رقبتك، يُفتح أخيراً باب العالم الداخلي. إذنٌ صغير يمنح الدخول، وشاهدٌ صامت على أنك تنتمي إلى هنا. من يعرف الوقت الذي استغرقه الحصول عليها وحده يعرف وزنها."},"ICON-0231":{"nm":"سوار الدخول اليومي","de":"اربطه في معصمك مرة واحدة، وستكون من أهل ذلك اليوم حتى تنزعه. شريط ورقي واحد يفصل الداخل عن الخارج، ويصير علامة على يوم قُضي معاً. حتى بعد قطعه، يبقى أثره وقتاً طويلاً."},"ICON-0232":{"nm":"بطاقة الضيف","de":"بطاقة اسم صغيرة تُلصق على الصدر تكفي ليصبح مكانٌ غريب مكانك. حين تُحمل كلمة «أهلاً بك» على ورقة واحدة، حتى القادم لأول مرة يصبح أخيراً ضيفاً."},"ICON-0233":{"nm":"أنبوب الملصق","de":"أسطوانة متينة تحفظ ملصقاً ملفوفاً دون أي تجعيد. فكلما كانت اللوحة أثمن، وجب إرسالها مستقيمة. لا يُرى ما بداخلها، لكنها تنطلق حاملة عناية أحدهم."},"ICON-0234":{"nm":"غلاف الملف","de":"الصفحة الأولى التي تلفّ حزمة سميكة من الأوراق. الوجه الذي تلمسه يدك قبل المحتوى. حين يكون الغلاف أنيقاً، تبدو حتى النية الكامنة بداخله أنيقة، بداية رقيقة لصغائر الشكليات."},"ICON-0235":{"nm":"بطاقة بريدية تذكارية","de":"تكتب سلاماً على قطعة من منظر بعيد وترسلها. وحين تصل، يكون القلب الذي أرسلته قد شاخ قليلاً هو الآخر، فيزداد عزّة. دفء الرسالة المكتوبة بخط اليد، البطيء، لا تستطيع رسالة على شاشة أن تلحق به أبداً."},"ICON-0236":{"nm":"بطاقة الهدية","de":"قصاصة ورق صغيرة تُربط فوق هدية. بكلمتي «إليك» وحدهما، يكتمل التغليف تماماً. أقصر رسالة في العالم، تكتب لا ماذا تُهدي، بل بمن فكرت."},"ICON-0237":{"nm":"بكرة ملصقات التغليف","de":"كلما مزقتَ خانة واستخدمتها، جاء التشطيب أكثر نظافة. عقدة صغيرة تمسك بإحكام الطرف الذي يوشك أن ينفلت. اللمسة الأخيرة لتغليف أُنجز بعناية تأتي دوماً من هذا الشريط الملفوف."},"ICON-0238":{"nm":"غلاف الرسالة الشفاف","de":"طبقة شفافة تلفّ رسالة مكتوبة بخط اليد كي لا تصفرّ مع السنين. تبقى الحروف ظاهرة، لكن أثر اللمس لا يصلها. غشاء غير مرئي يحرس بصمت قلب أحدهم الحريص."},"ICON-0239":{"nm":"ختم الشمع الملون","de":"النقطة الأخيرة التي تُغلق بها المغلف، كلما ازداد لونها وضوحاً قلّ تسرّب القلب منها. وعدٌ بأن يد أحد لم تلمسها حتى تُمزق. حتى السر يحتاج إلى عقدة جميلة كهذه."},"ICON-0240":{"nm":"كتيّب بطاقات الرسائل","de":"كتيّب صغير يجمع رسائل قصيرة بين دفتيه. كل صفحة فيه كلمة واحدة تُقال لأحد. اجمع، صفحة بعد صفحة، الكلمات التي لم تُقل بعد، وذات يوم تنمو الشجاعة على قولها لا محالة."},"ICON-0241":{"nm":"اللافتة القابلة للطي","de":"فُتحت فتقول: «من هنا»، وطُويت فتقول: «هذا يكفي لليوم». بأرجل مفتوحة عند مدخل الزقاق، تقف يوماً كاملاً من أجل من قد يضل طريقه. المساء الذي تُطوى فيه هو أرق راحة عندي."},"ICON-0242":{"nm":"شريط ترتيب البريد","de":"لفّ حزمة من البطاقات البريدية حول الخصر، فتتحول التحيات التي كادت تتناثر أخيراً إلى حزمة واحدة من القلب. شريط خفيف واحد يربط بعناية الكلمات المتجهة إلى أماكن بعيدة، ويودّع بهدوء الظهر الذي ينطلق في الطريق."},"ICON-0243":{"nm":"حزمة رسائل الشكر","de":"لأن كلمة «شكراً» تنزلق دوماً عن اللسان، تكتبها على ورقة بحجم راحة اليد وتربطها بهدوء. كلما ازدادت الحزمة سماكة، ازداد معها، جنباً إلى جنب، سُمك القلب الذي تدين به لأحد."},"ICON-0244":{"nm":"ورقة نموذج هتاف التشجيع","de":"ورقة نموذجية مكتوب عليها: «اهتفوا هكذا». هتافٌ لم يُلبس صوتاً بعد يحمل خفقاناً هادئاً فقط، كنوتة موسيقية فارغة تنتظر إيقاعها الأول."},"ICON-0245":{"nm":"مذكرة طلب التسجيل المسبق","de":"المذكرة التي تطلب حجز موعد التسجيل المسبق تبقى دوماً في خانة الساعة الخامسة فجراً. تدوّن الورقة الصغيرة بصمت، وكأنها تفهم كل شيء، قلباً يقتطع من نومه ليحجز مكاناً."},"ICON-0246":{"nm":"تذكرة ترتيب لقاء المعجبين","de":"ورقة واحدة تحدد أي رقم في الدور ستُلقي فيه تحيتك. الاصطفاف في الطابور ليس انتظار دورك، بل استعارة مؤقتة لترتيب، لأنك لا تستطيع أن تضع رقماً على مقدار حبك."},"ICON-0247":{"nm":"سوار رقم الانتظار","de":"رقم واحد يحدد ترتيب اصطفافك اليوم. سواء كنت في المقدمة أو المؤخرة، فمن يرتدون هذا الشريط الصغير الخفيف حول معاصمهم هم، في النهاية، رفاق قلبٍ واحد اجتمعوا ليروا المسرح ذاته."},"ICON-0248":{"nm":"جدول ترتيب بطاقات الصور","de":"نفس الوجه، ومع ذلك كلها مختلفة، فتدوّنها مقسمة خانة خانة. كلما امتلأ الجدول ازداد القلب ترتيباً، والخانة الوحيدة الفارغة تجعل صدرك يخفق بشوق ملئها اليوم."},"ICON-0249":{"nm":"قائمة تدقيق الألبوم","de":"الإصدار، البطاقة المصورة، وحتى إن كان مختوماً، قائمة حب مكتوبة بالأرقام. وأنت ترسم في مخيلتك فخر يوم اكتمالها، تخط اليوم أيضاً دائرة صغيرة أنيقة على سطر واحد."},"ICON-0250":{"nm":"ملاحظة إرشاد التشجيع","de":"شكل اليد، إيقاع الهتاف، وحتى مواضع التقاط الأنفاس. كي يندمج حتى القادم لأول مرة سريعاً في صوت واحد، تصبح الملاحظة الصغيرة دليلاً لطيفاً ينتقل من يد إلى يد."},"ICON-0251":{"nm":"دفتر الملاحظات الخاص","de":"تختار فقط الجمل التي لن تُريها لأحد وتكتبها هنا. أن الصفحة التي لم تُفتح قط هي الأصدق، هذا ما يحرسه هذا الدفتر بصمت، وغلافه مغلق دوماً."},"ICON-0252":{"nm":"ورقة أختام المناسبات","de":"تضغط، فيصير يوم آخر مميزاً. بختم صغير واحد يُطبع على تاريخ عادي، يسجل «اليوم» اسمه خلسة في قائمة الأيام التي تستحق أن تُتذكر."},"ICON-0253":{"nm":"غلاف حامل الأوراق","de":"حتى وإن هبّت الريح، وإن تسلل المطر، أحرس الورقة المثبتة حتى النهاية. أنا، الذي جعلت من نفسي درعاً للّوح، الحارس الأمين للحروف المكتوبة."},"ICON-0254":{"nm":"فهرس الملف","de":"كي لا تضل طريقك بين أوراق سميكة، يُخرج لساناً صغيراً ويشير: «هنا». علامة ملونة واحدة تحكم مئة صفحة بنظرة واحدة."},"ICON-0255":{"nm":"ملصق تبويب التصنيف","de":"هذا في هذه الخانة، وذاك في تلك الخانة. عملي أن أرتب فوضى العالم بنظام، سطراً بعد سطر. لحظة إلصاق الملصق، تجد الأشياء المبعثرة أخيراً مكانها."},"ICON-0256":{"nm":"لوحة الموافقة المصغّرة","de":"لحظة تضغط الختم بصوت خفيف، تشعر بطريقة ما أنك أصبحت راشداً حقيقياً. صغيرة الحجم لكن سلطتها حازمة، فختم موافقة واحد يُنهي بسرعة العمل المتراكم."},"ICON-0257":{"nm":"حافظة المستندات الشفافة","de":"شفافة تماماً فلا شيء تخفيه. تحتضن ورقة مهمة، وخشية أن تبتلّ بالمطر أو تتجعد، تلفّها بجسدها الشفاف وتوصلها إلى مكان اللقاء."},"ICON-0258":{"nm":"شريط تسجيل الحضور","de":"حضرت، فتُملأ خانة أخرى. حين تتراكم آثار أقدام كل يوم على طول الشريط صفاً صفاً، تصبح الجدية غير المرئية أخيراً نمطاً يُرى بلمحة."},"ICON-0259":{"nm":"دفتر تصحيح الأخطاء","de":"تدوين ما أخطأت فيه ليس جمعاً للخجل. كي لا تتعثر مرتين في المكان نفسه، إنه إعادة كتابة خطأ الأمس ليصبح دليل اليوم."},"ICON-0260":{"nm":"لوحة أختام الجدول الزمني","de":"ختمٌ واحد يُطبع على جدول فارغ فيولد «موعد». سحرُ يومٍ يُحسم بحركة رسغ واحدة، وهذا السحر في الحقيقة ليس سوى اسم آخر للحرص المسبق والاجتهاد."},"ICON-0261":{"nm":"ملصق ظهر الكتاب","de":"بطاقة اسم للكتب الواقفة وظهرها إلى الرفّ. الحروف القصيرة المكتوبة على الظهر الضيق تنادي بإشارة واحدة، من بين مئات الكتب، ذلك الكتاب الذي كنت تبحث عنه."},"ICON-0262":{"nm":"غلاف حماية الصور","de":"ممنوع لمسها بيد عارية. يطلب ألا يُترك ولو أثر بصمة واحدة، فيسجّي جسده برفق فوق لقطة ثمينة. هكذا يدوم القلب المحب طويلاً وطويلاً بلمسة حذرة كهذه."},"ICON-0263":{"nm":"ورقة فهرسة الأفلام","de":"ضع رقماً على كل شريط فيلم، فتستعيد اللحظات المتناثرة ترتيبها في القصة من جديد. دليل صغير يعتني بذكريات كُتبت بالضوء كي لا تختلط."},"ICON-0264":{"nm":"حافظة الصور الشفافة","de":"بيت شفاف يُحفظ فيه سعادة مربعة الشكل واحدة تلو الأخرى. دون قلق من انحناء الزوايا، يلمع الوجه الأعز في داخله بأناقة طوال فصول السنة الأربعة."},"ICON-0265":{"nm":"مغلف صور مصغّر","de":"قبل أن يبرد دفء صورة طُبعت للتو، يفتح مغلف صغير ذراعيه ليستقبلها. لقطة واحدة تدخل من فوهة بحجم راحة اليد تصبح، قبل أن تدري، كنزاً في حقيبة أحدهم."},"ICON-0266":{"nm":"غلاف الصورة العدسية","de":"مهمتي أن أحرس، دون خدشة واحدة، صورة معقدة تتغير ملامحها كلما أملتَها. وإذ أحمي كل وجه مختلف في كل زاوية، لا يمكنني إلا أن أكون مجتهداً بلا كلل."},"ICON-0267":{"nm":"ملصق تصنيف اللقطات","de":"أي لقطة من بين أربع هي الأفضل، يشير الملصق نيابة عنك. هذا العمل الصغير في فصل الجيدة عن المضحكة، جنباً إلى جنب، هو سرّ الاستمتاع بالذكرى مرتين."},"ICON-0268":{"nm":"شريط حفظ صور اللقطات الأربع","de":"يلتف بعناية حول ذكرى ضيقة طويلة من أربع لقطات. يحتضن بإحكام ضحكة ذلك اليوم التي كادت تتناثر في حزمة واحدة، ويحملها بأمان إلى أعماق الحقيبة."},"ICON-0269":{"nm":"ملصق زوايا الصور","de":"عندما تلصق صورة في ألبوم، يد صغيرة تمسك زواياها الأربع برفق. كي لا تسقط دون طلاء الغراء بكثافة، هكذا تبدأ الرقة من الزوايا بالضبط."},"ICON-0270":{"nm":"جدول تصحيح الطباعة","de":"أكثر دفئاً قليلاً، وأقل سطوعاً قليلاً. جدول واحد تعبث فيه بالأرقام حتى يظهر اللون الذي يرضيك، يحوّل بهدوء لقطة عادية إلى عمل فني."},"ICON-0271":{"nm":"مشبك الإيصالات","de":"يعضّ على الإيصالات المتجعدة بإحكام ولا يفلتها. بفمه الصغير يحفظ نفقات اليوم بعناية، فتأتي تسوية نهاية الشهر أخفّ بكثير."},"ICON-0272":{"nm":"إيصال تأكيد الحجز","de":"بسطر واحد يقول «تم الحجز»، يهدأ القلب رويداً رويداً. ورقة واحدة تصبح دليل وعد، تحفظ الشوق مرتباً بعناية حتى ذلك اليوم المنتظر."},"ICON-0273":{"nm":"إيصال إعادة الأمانة","de":"دليل صغير لكنه مشرّف على أنك أعدت ما استعرته إلى مكانه. لحظة تمسك هذه الورقة بيدك، يُمحى بخفة دَينٌ كان يثقل زاوية من قلبك."},"ICON-0274":{"nm":"حافظة إيصال الأمانات","de":"كي لا تفقد التذكرة التي تستعيد بها ما أودعته، سأمسكها بإحكام نيابة عنك. فمصير ورقة صغيرة واحدة قد يقرر نهاية يوم أحدهم."},"ICON-0275":{"nm":"ذيل بطاقة الاستعارة","de":"بطاقة صغيرة ترفرف على كل غرض مستعار. اتبع هذا الذيل وستكشف على الفور من أخذ ماذا، فيُحل لغز الشيء المفقود سريعاً."},"ICON-0276":{"nm":"قائمة تدقيق الفحص","de":"تتبع كل عنصر بعينيك واحداً واحداً لتتأكد ألا شيء ناقصاً. حين تمتلئ علامات الصح صفاً بعد صف، تكتسب الدقة غير المرئية أخيراً اسم الثقة."},"ICON-0277":{"nm":"مغلف مذكرة التسوية المالية","de":"دوّن ما دخل من مال وما خرج على المغلف، فتصطف الأرقام المشوشة بهدوء في صف. نهاية التسوية دائماً هذه المذكرة الصغيرة التي تضع النقطة الأخيرة بثبات."},"ICON-0278":{"nm":"ملصق الشحن","de":"ينطلق في الطريق وقد كتب على جسده إلى أين يذهب ولمن سيصل. لحظة إلصاق هذا الملصق، يصبح الصندوق مسافراً له وجهة وينطلق بشوق."},"ICON-0279":{"nm":"شريط تأكيد الاستلام","de":"يربط كلمة «وصلت بسلام» في شريط واحد ويعيدها. ارتياح من استلم وطمأنينة من أرسل يتصافحان بهدوء فوق هذا الخيط الصغير."},"ICON-0280":{"nm":"حلقة بطاقات الكلمات","de":"الكلمات التي كانت ستُفقد لو تناثرت أوراقاً منفصلة، تجمعها حلقة صغيرة واحدة وتمسك بها بإحكام. تقلّبها مرة بعد مرة، فتصبح الكلمات الغريبة، قبل أن تدري، أصدقاء ألفهم لسانك."},"ICON-0281":{"nm":"شريط مذكرة النطق","de":"تعلّق علامة صغيرة عند الموضع الذي يزلّ فيه طرف لسانك دوماً. حتى الصوت الغريب الذي كان يضل طريقه في فمك يجد نطقه الصحيح، قبل أن تدري، باتباع هذه المذكرة. صفحة أولى لترويض صوت أخرق، قليلاً قليلاً."},"ICON-0282":{"nm":"صندوق قصاصات الترجمة","de":"جسور صغيرة تعبر بين كلمة وكلمة، مطوية بعناية واحدة في كل خانة. تكتب عبارة اخترتها بصعوبة وتمررها خلسة، فيقترب حتى القلب الذي لم يكن يتفاهم بواسطة قصاصة واحدة بينهما."},"ICON-0283":{"nm":"قصاصة اقتباس","de":"الجملة التي تلامس القلب مباشرة لا تدوم إلا إن نسختها بيدك. ألصق سطراً قصصته من زاوية كتاب أمام مكتبك، فتسند تلك الحروف بهدوء يوماً كان يغرق."},"ICON-0284":{"nm":"فهرس ملاحظات","de":"أعلامٌ صغيرة ملونة تُدسّ كي لا تضل طريقك داخل كتاب سميك. تخبرك الألسنة البارزة بهدوء، من بين الصفحات، أنك تستطيع أن تتوه أبعد فقط حين تعرف الموضع الذي تعود إليه."},"ICON-0285":{"nm":"رقاقة تدقيق الحفظ","de":"علامة واحدة تُطبع بجانب ما حفظته. مرساة صغيرة تمسك بالأشياء التي تمرّ برأسك للحظة وتحاول أن تتلاشى، فكل خانة سوداء مملوءة تحمل بصمت جهد الليلة الماضية."},"ICON-0286":{"nm":"حزمة مغلفات الأسئلة","de":"قبل أن تمزق المغلف، لا أحد يعرف ماذا سيخرج منه. تلك الثواني القليلة وأنت تعبث بأطراف أصابعك عند موضع الختم، حزمة شوق طُويت فيها سؤال واحد بعناية، والخفقان مختوم معه."},"ICON-0287":{"nm":"دفتر تبويب القواعد","de":"القاعدة لا تُحفظ بالرأس بل تُتقن باليد. من التبويب الملون للصفحة التي تُفتح كثيراً إلى الدفتر الذي يلين ويتآكل رويداً، تصبح تلك الحافة المتآكلة حلقة عمر الزمن الذي صمدت فيه."},"ICON-0288":{"nm":"جدول تمرين المحادثة","de":"جدول واحد لمن يجد فتح فمه أصعب شيء في العالم. تتبع الخانات بإصبعك خانة بعد خانة، حتى تجد الكلمة الأولى التي ارتجفت في حلقك، قبل أن تدري، صوتها الخاص. فحتى الشجاعة لها دورها."},"ICON-0289":{"nm":"ورقة مسودة الألوان","de":"ألوان قبل اكتمالها تستلقي بخشونة تلتقط أنفاسها. حالة ليست إجابة نهائية بل إمكانية بعد، وعلى هذه الورقة غير المصقولة تماماً، تتمايل غدٌ أكثر من أي شيء آخر."},"ICON-0290":{"nm":"قطعة لوحة الإلهام","de":"تجمع الانطباعات المتناثرة قطعة قطعة وتلصقها في مكان واحد، فيكشف مزاج لم يكن يمسكه أحد بسهولة عن ملامحه بغموض. إحساس ما لا اسم له بعد، تشير إليه القطع بهدوء وهي تتكئ على بعضها."},"ICON-0291":{"nm":"كتيّب عينات الأنماط","de":"شبكة قماش البوجاغي ونسيج المشربية مرتبان بعناية صفحة بعد صفحة في مجلد واحد. حيث يتكرر النمط ذاته حتى النهاية، لا يسكن الكسل بل الوعد، القلب الثابت الذي يحافظ على نسق واحد."},"ICON-0292":{"nm":"ورقة عينات الأزياء","de":"رغم أنه الضوء نفسه، يختلف الملمس والظل على كل قطعة قماش. قبل اختيار زي المسرح، تلك الليلة التي قضيتها متردداً وأنت تمرر أصابعك عليه عشرات المرات، محفوظة كاملة في عينة صغيرة واحدة."},"ICON-0293":{"nm":"ورقة إرشاد ممنوعات الشعار","de":"ورقة تدوّن أولاً، بوضوح، ما لا يجوز فعله. داخل الإطار المشطوب بعلامة حمراء، تزداد الحرية وضوحاً على العكس، فيُفتح طريق جديد بالضبط حيث ظننته طريقاً مسدوداً."},"ICON-0294":{"nm":"رقاقة مرجع اللون","de":"عينة صُنعت خصيصاً لأن اللون لا يمكن شرحه بالكلمات إطلاقاً. تحبس في راحة يد صغيرة لحظة كانت فيها الغروب في أشد احمراره، لتتمكن من أن تسلّم للشخص التالي، بدقة، قائلاً: «هذا هو اللون بالضبط»."},"ICON-0295":{"nm":"بطاقة مسودة التخطيط","de":"رسمة أولى خُطت بخفة لما سيوضع أين. تحديد المكان هو في جوهره تحديد القلب، فبين الخطوط المتناثرة بتعثر، يفتح توازن الكل عينيه ببطء."},"ICON-0296":{"nm":"لوحة مذكرة الخامات","de":"الخشب، التراب، الحجر، أسماء الأشياء الملموسة مدونة بكثافة. سرٌّ لا يعرفه إلا من يبدأ بقراءة الملمس بيده أولاً، فما تبني به يحدد نصف ما سيصبح عليه سلفاً."},"ICON-0297":{"nm":"ورقة نسخ الرسم","de":"تضع ورقة رقيقة فوق الرسم التمهيدي وتتبع الخطوط بهدوء. وبينما تستعير طريق غيرك للحظة، تتعلم يدك ذلك الطريق، وبين الخطوط المنسوخة ينمو خط خاص بك خلسة، قبل أن تدري."},"ICON-0298":{"nm":"شريط مسار الدخول","de":"يصطف الناس ويدخلون تباعاً متتبعين الشريط الملصق طويلاً على الأرض. خط واحد يرشد بهدوء كي لا تتشابك الخطوات المتحمسة، يد رقيقة غير مرئية تسند الشوق كي لا ينهار."},"ICON-0299":{"nm":"لافتة إرشاد الفعالية","de":"لافتة تقف نيابة عن كلمة «من هنا». لطف صغير يُنصب عند كل مفترق كي لا يتوه أحد، يأخذ بيد يومٍ غريب لقادم لأول مرة ويمشي به بهدوء."},"ICON-0300":{"nm":"ملصق رقم الجناح","de":"رقم واحد مخصص لكل جناح يحدد بوضوح صاحب تلك المساحة. رقم صغير، لكنه وعد بأن «هذا مكانك»، فيصبح لديك مكان تعود إليه في فعالية غريبة."},"ICON-0301":{"nm":"استمارة موافقة الطاقم","de":"توقيعٌ واحد تُرك في المكان الذي اتفقت فيه القلوب على العمل معًا. ورقةٌ رقيقة واحدة، لكنها تحمل ثقل اختيار أن يثق كلٌّ بالآخر، ومن هنا بالتحديد تبدأ كل يدٍ معينة في الفعالية."},"ICON-0302":{"nm":"حزمة تذاكر تجريبية","de":"حزمة سميكة من تذاكر التجربة، مربوطة لتستقر بلطف في راحة يد واحدة. كلما وزّعتها أكثر، لا تتناقص بل تزيد \"المرات الأولى\" التي تمنحها للآخرين، فهي حزمة من الكرم تزداد دفئًا كلما لمستها."},"ICON-0303":{"nm":"لافتة علامة الطابور","de":"\"انتظر من هنا\"، تهمس الأرض بهدوء. حين تجتمع القلوب التي تحفظ دورها، يصبح الطابور الطويل مشهدًا بذاته، وعلامة صغيرة واحدة تحوّل التسرع إلى هدوء."},"ICON-0304":{"nm":"بطاقة الاستلام الحضوري","de":"بطاقة صغيرة تتعلق برفق في المكان الذي تستلم فيه ما طلبته مسبقًا. في اللحظة التي تُمسك فيها بيدك، ينزلق ذلك الارتياح الخفيف عن كتفيك، عقدة تتخذ فيها قلبٌ طال انتظاره شكله أخيرًا."},"ICON-0305":{"nm":"تذكرة الصندوق العشوائي","de":"متعة اختيار واحد من دون معرفة ما بداخله. هزّه فيرتجّ القلب أولًا عند صوت الخشخشة بالداخل، وتلك اللحظة القصيرة قبيل الفتح تصبح أكثر لحظات اليوم انتفاخًا بالأمل."},"ICON-0306":{"nm":"ملصق اكتمال المبادلة","de":"ختمٌ صغير مستدير يُعلن أن المقايضة تمّت بسلام. إنه النقطة الملساء التي تبقى بين اليدين اللتين أعطتا وأخذتا، وحين يُلصق بلمسة خفيفة، تكتمل الصفقة أخيرًا بدفء واستدارة."},"ICON-0307":{"nm":"شريط ختم السجل","de":"صندوقٌ ثمين يُلفّ مرةً واحدة بشريط ويُختم بهدوء. إنه رجاءٌ بألا يُفتح باستخفاف، وأهدأ لباقةٍ لتقدير ما بالداخل، كلها محفوظة في شريط واحد."},"ICON-0308":{"nm":"كبسولة المذكرة السرية","de":"كلمةٌ واحدة كانت تريد أن تُقال، تُحفظ بعناية داخل علبة صغيرة. أغلقها بإحكام كما لو كنت تدفن شعورًا لم تستطع إرساله، وخزنة صغيرة في راحة يدك تحرس الزمن حتى ذلك اليوم الذي تفتحها فيه من جديد."},"ICON-0309":{"nm":"بطاقة قصاصات صغيرة","de":"قصاصةٌ مقصوصة وملصقة تحمل عبق ذلك اليوم بخفة. أخفّ من مذكرات وأكثر لمسة يدوية من صورة، ورقة بحجم راحة اليد تُمسك بإحكام يومًا كان سينفلت بين الأصابع."},"ICON-0310":{"nm":"ورقة تسجيل الزيارة الأولى","de":"ارتجاف يوم وضعت فيه قدمك على هذه الجزيرة لأول مرة، يبقى في سطرٍ قصير. قبيل أن تتحوّل الغرابة إلى إلفة، تحتضن الورقة نيابةً عنك أصفى قلبٍ أول، وتحفظه طويلًا."},"ICON-0311":{"nm":"مخطط تصنيف الذكريات","de":"جدولٌ تُدوَّن فيه الذكريات مرتّبةً حسب نوعها وفرعها، واحدةً تلو الأخرى. إن كدّست كل الذكريات في درجٍ واحد، ضاع حتى أعزّ يوم بينها، فكلما كان الشيء أثمن، خُصّص له مكانه بعناية أكبر."},"ICON-0312":{"nm":"رقاقة مذكرة فقاعة الكلام","de":"كلماتٌ أرادت أن تُقال تنتفخ مستديرة كبالون وتطفو على الورق. حتى الكلمة التي لم يستطع الفم نطقها تجد شجاعتها الخفية داخل ذلك الإطار المستدير، ممرٌّ صغير ودافئ يخرج منه القلب."},"ICON-0313":{"nm":"حامل التاريخ","de":"قاعدة صغيرة تُنصّب تاريخ اليوم منتصبًا في مواجهتك. اختر يومًا واحدًا من بين تلك الأيام المتدفقة وأجلسه في الصدارة، فيكتسب حتى التاريخ العادي دفئًا يستحق الاحتفال."},"ICON-0314":{"nm":"بطاقة رقم المقتنيات","de":"رقمٌ فريد يُمنح لكل شيء تعتزّ به. أن تقتني شيئًا هو أن تعد بأن تنادي ذلك الشيء الوحيد من نوعه في العالم، فالرقم على البطاقة الصغيرة يحمل وزن القلب بوضوح."},"ICON-0315":{"nm":"غلاف الأرشفة","de":"غلافٌ رقيق داخلي تُدخل فيه كل شيء تحتفظ به طويلًا، واحدًا تلو الآخر. أن تُبعد شيئًا طبقةً واحدة عن الضوء والزمن، هو في النهاية أن تحب شيئًا يعني أن تحسن حفظه."},"ICON-0316":{"nm":"حزام حافظة بطاقة الصور","de":"حزامٌ نحيل يتيح تعليق الحافظة الصلبة حول الرقبة. إنها طريقة في عالم المشجعين، السير طوال اليوم وأنت تحمل المفضّل لديك قرب صدرك، وعلى هذا الخيط الرفيع الواحد تتعلق رفقةٌ حانية طوال اليوم."},"ICON-0317":{"nm":"دبوس حامل بطاقة الصور","de":"بدبوس صغير واحد، تقف بطاقة الصور منتصبةً على المكتب. مسطّحةً هي مجرد ورقة، لكن منتصبةً تصبح وجهًا يلتقي بعينيك، فتصنع بهدوء مكانًا يطول فيه مقام النظر."},"ICON-0318":{"nm":"رقاقة بطاقة صور هولوغرافية","de":"طبقةٌ رقيقة واحدة تتدفق عليها ألوان قوس قزح مع كل زاوية. غشاءٌ يحبس شيئًا من الضوء يكسو بطاقة عادية بضوء النجوم، سحرٌ صغير تستيقظ فيه تعبيرات مختلفة لامعةً كلما رفرفت بمعصمك."},"ICON-0319":{"nm":"غطاء حماية بطاقة الصور","de":"ضغطةٌ واحدة على الزاوية تجعلك تشعر وكأن القلب الذي تعتزّ به قد انطوى معها. درعٌ شفاف يحتضن بإحكام ورقة ثمينة واحدة، فهذا النوع من الحرص يرافق دومًا تقدير الشيء بصدق."},"ICON-0320":{"nm":"صينية ترتيب بطاقات الصور","de":"صينية ضحلة تُرقد عشرات بطاقات الصور مصطفةً حسب نسيجها. مبعثرةً هي مجرد كومة، لكن مصفوفةً في صفوف تصبح مجموعة، ونظام المودّة يُنقش في كل يد ترتّب."},"ICON-0321":{"nm":"مظروف تبادل بطاقات الصور","de":"حين تضع بطاقة صورة في مظروف لتسليمها، تتردد أطراف أصابعك للحظة. ليست وداعًا، بل رجاءٌ بأن تصبح مفضّلة أحدهم. لحظة طيّ فتحة المظروف، تتبادل رابطة صغيرة الأيدي بهدوء."},"ICON-0322":{"nm":"قلم تزيين بطاقات الصور","de":"ما يملأ الفراغ ليس الكتابة بل الشعور. أينما مرّ سنّ القلم تنبت قلوب ونجوم صغيرة، وتستيقظ ورقة عادية كتشجيعٍ لا مثيل له في العالم. التزيين ليس سوى اسم آخر للاعتراف."},"ICON-0323":{"nm":"حلقة مشبك بطاقات الصور","de":"طقّة، صوت انغلاق المشبك. بذلك القفل الصغير الواحد، تجتمع بطاقات كادت تتبعثر في صفٍّ واحد. حتى وهي تهتز طوال اليوم داخل الحقيبة، لا تُصاب زاوية واحدة بأذى. هكذا تكون المتانة هادئة."},"ICON-0324":{"nm":"حقيبة نقل بطاقات الصور","de":"عادةٌ استقرّت دون أن تشعر في اليد التي تفتح السحاب وتغلقه. مهما هطل المطر فجأة أو دفعك الزحام، يبقى الداخل وحده جافًّا. أن تضع أعز ما لديك في أعمق مكان، هذا هو عمل النقل الحنون."},"ICON-0325":{"nm":"حزام سوار لقاء المعجبين","de":"تذكّرت إحدى المعجبات طويلًا كم كانت يد الموظف دافئة وهي تربط الحزام حول معصمها. عقدةٌ واحدة تشير إلى الانتماء لهذا المكان اليوم. ذلك الحزام الملفوف مرتين لئلا ينحل، يُبقي حماس يومٍ كامل في مكانه."},"ICON-0326":{"nm":"سوار الدخول","de":"في اللحظة ذاتها التي تعبر فيها المدخل، ينفصل الداخل عن الخارج أخيرًا بوضوح. مرتديًا إياه طوال اليوم، يألف الجلد وجوده سريعًا، وحين تخلعه يبقى أثرٌ رفيع، كدليل على المكان الذي مكثت فيه."},"ICON-0327":{"nm":"رقاقة ركن الحوار","de":"حين تُفتح زاوية الحوار، تتدحرج رقاقة برشاقة. من سيتكلم أولًا، وأي سؤال سيُسحب؟ تلك الصدفة الصغيرة تغيّر الأجواء بأكملها. نزوة رقاقة واحدة أكثر محبّبةً من أي نصّ مكتوب مسبقًا."},"ICON-0328":{"nm":"تذكرة انتظار حفل التوقيع","de":"تقف في الطابور ممسكًا بورقة مرقّمة. الرقم ١٤٢. بينما تُحصي المئة والواحد وأربعين الذين سبقوك، يعدّ القلب دوره أولًا. الانتظار طويل، لكن بفضل هذه الورقة الواحدة يصبح حتى ذلك الوقت جزءًا من الحماس."},"ICON-0329":{"nm":"قفاز المصافحة السريعة","de":"في لحظة التقاء الكفّين، يستقبل القفاز نيابةً عنك ذلك الدفء العابر. يدٌ سُخّنت طوال اليوم من أجل لمسة نصف ثانية. حتى ارتداء القماش لا يمنع تلك الرعشة، وهذا ما يدركه الجميع في تلك اللحظة فقط."},"ICON-0330":{"nm":"دبوس صورة تذكارية","de":"طقّة واحدة، وهذا اليوم يُحفظ كما هو. داخل الإطار الذي يثبّته الدبوس، حتى الابتسامة المرتبكة تصبح يومًا ما أكثر المشاهد افتقادًا. التوثيق هو أرقّ طمعٍ في الإمساك باللحظة."},"ICON-0331":{"nm":"بطاقة شريط المقعد","de":"شريطٌ صغير معلّق على ظهر مقعد يتمايل دون أن تهبّ ريح. علامةٌ ربطها أحدهم، أثرٌ يشهد أن شخصًا كان هنا. حتى في المقعد الخالي بعد انتهاء العرض، يبدو الشريط وحده متذكّرًا الإيقاع بعد."},"ICON-0332":{"nm":"ملصق فحص الهدايا","de":"يُلصق ملصقٌ على كل هدية. هل أُرسلت، هل تم التحقق منها، هل ينقصها شيء؟ حتى تلقّي قلبٍ ما يحتاج إلى تدبير، فهذا الملصق الصغير يربط بين عناية وعناية من دون أي ثغرة."},"ICON-0333":{"nm":"ورقة تذكارية","de":"ورقةٌ كُتبت لتُحفظ وتُراجَع طويلًا. طقس ذلك اليوم، رقم المقعد، وحتى عنوان الأغنية الأخيرة. تتلاشى الذاكرة، لكن هذه الورقة وحدها لا تتلاشى. حتى حفظ ذكرى يحتاج إلى شكل صغير."},"ICON-0334":{"nm":"حلقة منشفة التشجيع","de":"علّق حلقةً في طرف المنشفة فلا تنزلق عن كتفك. بين مسح العرق ولفّها فوق الرأس وإعادة تعليقها على الرقبة، تحافظ رابطة صغيرة واحدة على استمرار حركات التشجيع دون انقطاع."},"ICON-0335":{"nm":"مشبك اللافتة","de":"يمسك المشبك بإحكام طرفي اللافتة. حتى لو رُفعت الذراعان عاليًا، لا تنطوي الحروف ولا ترفرف بعيدًا. هنا يقف أثبت ممثل مساند، يُقوّم الرسالة بعيدًا عن الأنظار."},"ICON-0336":{"nm":"حقيبة كتم الصوت","de":"ينزلق السحاب ببطء، دون صوت. صمتٌ صُمّم كي لا تتسرب ضجة واحدة في مكانٍ وُعد فيه بالهدوء. المراعاة أحيانًا هي أن تجعل نفسك غير مسموع، هذا ما تقوله هذه الحقيبة بهدوء."},"ICON-0337":{"nm":"رقاقة إيقاع التصفيق","de":"كلما التقت الكفّان، تعدّ الرقاقة الإيقاع. تصفيقة، تصفيقة، تصفيقة، وتصفيقات متناثرة تجتمع فجأةً في إيقاعٍ واحد. سحر آلاف التصفيقات وهي تتحول إلى نفَسٍ واحد، تسهم فيه رقاقة صغيرة بهدوء."},"ICON-0338":{"nm":"مجلد دليل التشجيع","de":"افتحه فتجد طريقة التشجيع مكتوبة خطوة بخطوة. أي لون يُرفع عند أي مقطع، ومتى يُطلق الهتاف. حتى القادم لأول مرة يصبح فردًا من العائلة بمجرد هذا المجلد الواحد. دليلٌ صغير لمشاركة وعد."},"ICON-0339":{"nm":"حزام مروحة المقعد","de":"اربط حزامًا بمقبض المروحة فلا تسقط حتى لو أفلتت من يدك. في يومٍ حار، حين تتحرر اليدان للهتاف بعد التلويح، تتدلى المروحة من المعصم. حزامٌ واحد يبرّد الحرارة والحماس معًا."},"ICON-0340":{"nm":"قطعة رقاقة لامعة","de":"عند سقوط الضوء عليها، تتكسر كل قطعة بزاوية مختلفة. ضعها في راحة يدك فيرتجف قوس قزح صغير، وتنبض الألوان حية مع كل هزّة. ربما اللمعان ليس سوى تقاسم الضوء المجزّأ إلى قطع صغيرة."},"ICON-0341":{"nm":"عمود لافتة صغير","de":"افرد العمود الصغير فيشد القماش مع الريح. ارفعه عاليًا بكلتا يديك فتصل الحروف إلى ما وراء المدرجات، واطوه فيدخل في زاوية من حقيبتك. حجم القلب لا يُقاس بطول العمود."},"ICON-0342":{"nm":"علبة ملصقات التشجيع","de":"كل ملصق منقوش بعبارة تشجيع. على المفكرة، على الهاتف، على زاوية الحاسوب المحمول، أينما لصقتها تصطبغ الحياة اليومية بالتشجيع. هكذا يترك القلب المحب أثره في كل مكان."},"ICON-0343":{"nm":"غلاف حماية الألبوم","de":"اليد التي تغلّف الألبوم بغطاء حذرة. كي لا تتآكل الزوايا، كي لا يبهت تحت الشمس. تُسمع الموسيقى بالأذن، لكن هذه الورقة الواحدة تتذكرها اليد. درعٌ من القلب يبقي ما تعتزّ به قريبًا طويلًا."},"ICON-0344":{"nm":"حلقة أغلفة الأقراص","de":"ضع الأقراص في أغلفتها واربطها بحلقة، فتصبح دفتر أسطوانات. صوت الحفيف عند قلب كل صفحة جميل. أن تجمع موسيقى متناثرة مرتّبةً في يدك، تلك سعادة الجامع الهادئة."},"ICON-0345":{"nm":"فاصل تخزين المنتجات","de":"بفاصل واحد، تجد المنتجات التي كادت تختلط مكانها. هنا بطاقات الصور، وهناك سلاسل المفاتيح، وبجانبها أعواد التشجيع. الترتيب هو بناء بيت لكل شيء. لحظة انقسام الخانات، تتحوّل الفوضى إلى نظام."},"ICON-0346":{"nm":"خيط ختم الحزمة العشوائية","de":"اربط فتحة الحزمة العشوائية بخيط، فيبقى مصير الجميع غير محدد بعد. حتى تُفكّه، الجميع بطل آمال نفسه. رعشة أطراف الأصابع وهي تفكّ الختم هي بالضبط الفرح الذي حرسه هذا الخيط."},"ICON-0347":{"nm":"صندوق ترتيب الهدايا الخاصة","de":"تصطف الهدايا الخاصة حسب نوعها داخل صندوق. البطاقات البريدية مع البطاقات البريدية، والفواصل مع الفواصل. انظر إلى الخانات وهي تمتلئ أكثر مع النمو، فيتراءى أمامك كل الزمن الذي جمعته بلمحة. الترتيب هو قائمة الذكريات بعينها."},"ICON-0348":{"nm":"ملصق تمييز الإصدار","de":"هناك أشياء تبدو متشابهة لكنها ليست كذلك. ملصقٌ واحد يفصل النسخة أ عن النسخة ب، والطبعة الأولى عن المعادة. بفضل علامة صغيرة، يزول الالتباس، وتُثبَّت بطاقة اسم واحدة واضحة على عالم الاقتناء."},"ICON-0349":{"nm":"مذكرة تتبع مبيعات الأسبوع الأول","de":"أسبوع الإصدار، ورقمٌ واحد يُرجّح القلب. علامات تدقيق مكتوبة بعناية على مفكرة. تجمّع سجلات أيام قليلة فتصبح كشف درجات صغيرًا للدعم. عادةٌ حريصة تترجم القلب المحب إلى أرقام."},"ICON-0350":{"nm":"غطاء تثبيت الملصق","de":"ركّب غطاءً في طرف ملصق ملفوف فيبقى منبسطًا بهدوء. كي لا يتجعّد وأنت تتردد بين تعليقه على الحائط أو تأطيره. غطاءٌ صغير يحفظ أعز مشهد لديك مستقيمًا تمامًا."},"ICON-0351":{"nm":"حامل الصورة الواقفة","de":"تقف الصورة مائلةً فوق الحامل. في زاوية من المكتب، بزاوية مناسبة تمامًا لمستوى العين. اختراعٌ يجعل عينيك تلتقيان بها كلما مررت. أبسط طريقة لإدخال وجهٍ محبوب إلى منظر يومك."},"ICON-0352":{"nm":"لفافة شريط البروفة","de":"يُلصق شريطٌ على الأرض ليُعلّم المكان الذي يجب الوقوف فيه. خطوة، خطوتان، هنا بالضبط. بوطء الأثر ذاته عشرات المرات، تُنقش الحركة في الجسد. تحت المسرح المتألق، يرقد هذا الأثر الصادق للشريط."},"ICON-0353":{"nm":"دبوس حركة المسرح","de":"دبوسٌ واحد مثبّت في أرضية المسرح يُخبر بالخطوة التالية. حتى في الظلام، تجد أطراف الأصابع ذلك المكان أولًا. طريقٌ دقيق وإن لم يُرَ، خريطة خفية رسمتها بروفات لا تُحصى."},"ICON-0354":{"nm":"سدادة أذن الطاقم","de":"ضع السدادة فيخفت صخب الجمهور طبقةً واحدة، ويبقى الصوت الذي ينقل الإشارات واضحًا وحده. آذان طاقم خلف الكواليس تسمع دائمًا عالمين في آن واحد. أداةٌ صغيرة لانتقاء الإشارة وسط الضجيج."},"ICON-0355":{"nm":"بطاقة شمّاعة غرفة الانتظار","de":"بطاقة اسم معلّقة على كل شمّاعة. الزي الأول، الزي الثاني، زي الإعادة. انظر إلى ذلك الجدول المدوَّن فيه ترتيب التبديل، فيتراءى مسرح اليوم مرسومًا مسبقًا بترتيب الملابس. نظامٌ هادئ يروّض الانشغال."},"ICON-0356":{"nm":"بطاقة فحص الأدوات","de":"قبل الصعود إلى المسرح، تُثبَّت بطاقة على كل أداة. هل ينقص شيء، هل كل شيء سليم؟ لا يعرف الجمهور، لكن هذا الفحص الصغير يمنع الحوادث. خلف مسرح يبدو مثاليًا، توجد دائمًا يدٌ دقيقة."},"ICON-0357":{"nm":"رقاقة إشارة الدخول","de":"تنتقل رقاقة الإشارة من يد إلى يد. الآن، ادخل. لحظة تُنقل فيها التوقيت دون كلمة واحدة. في الظلام بجانب المسرح، تُبقي هذه الإشارة الصغيرة الجميع على الإيقاع دون تفويت."},"ICON-0358":{"nm":"رقعة كواليس المسرح","de":"هناك باب لا يعبره سوى من يرتدي هذه الرقعة. خلف المسرح، حيث تصل الهتافات عبر الجدار. قطعة قماش صغيرة واحدة تفصل الأمام المتألق عن الخلف المزدحم. علامة الأشخاص الذين يسندون المسرح."},"ICON-0359":{"nm":"لوح حجب موجّه الكلام","de":"لوحُ حجب يمنع ضوء موجّه الكلام من التسرب إلى المدرجات. لا يراه إلا من على المسرح، ومن يشاهد لا يدري. حارسٌ مهذّب لسرّ المسرح، يُخفي بهدوء مساعدةً يجب ألا تُكتشف."},"ICON-0360":{"nm":"غطاء مرآة غرفة الانتظار","de":"في غرفة الانتظار بعد انتهاء العرض، تُغطّى المرآة بقماش. الزجاج الذي عكس تعبيرات لا تُحصى طوال اليوم يغمض عينيه لبرهة. آخر ما يواجهه وجهٌ عارٍ من المكياج ليس المرآة، بل ظلامٌ هادئ."},"ICON-0361":{"nm":"سوار دخول التسجيل المسبق","de":"شريطٌ صغير، إن أُغلق مرة، لا ينفكّ إلا بقطعه. من أجل التأهل الوحيد للدخول إلى مقاعد التسجيل المسبق، ركب أحدهم أول قطار في فجرٍ حالك. وزن المعصم يصبح حماس يومٍ كامل."},"ICON-0362":{"nm":"ملصق انتظار التسجيل","de":"قبيل إضاءة الضوء الأحمر مباشرةً، عملي هو ربط أنفاس الجميع في صفٍّ واحد. في سكون انتظار إشارة الدخول، أصمد بهدوء حتى اللحظة الأخيرة. لحظة انتزاعي، يرتفع أخيرًا ستار البث المباشر."},"ICON-0363":{"nm":"رقاقة موضع الكاميرا","de":"علامةٌ صغيرة واحدة مطبوعة على الأرض تُحدّد بإتقان مسارات ست كاميرات. أين يجب أن تُلتقط لتبدو أكثر إشراقًا، يعرفه المخرج حتى قبل البروفة. يدٌ ترسم داخل الإطار من خارجه مسبقًا."},"ICON-0364":{"nm":"بطاقة فحص الصوت","de":"تنقر، تنقر بالمكروفون تجاه المدرجات الخالية. إن طال الصدى، طبقة إضافية من عازل الصوت على السقف. عناية ضبط نسيج الصوت دون أن يدري الجمهور تبدأ بهدوء من هذه البطاقة الصغيرة."},"ICON-0365":{"nm":"دفتر أختام الموقع","de":"كلما مررت بموقعٍ ما، تجمع خانةً واحدة من الأختام. في كل أثر حبر منتشر، طُبع طقس ذلك اليوم ونبض القلب معًا. صفحةٌ اكتملت تصبح خريطة آثار قدم لا يستطيع أحد تقليدها، خاصتي وحدي."},"ICON-0366":{"nm":"حزام بطاقة زيارة محطة البث","de":"من دون هذا الحزام، لا تُفتح بوابة الردهة. وأنت تمشي في الممر خطوة بخطوة معلّقًا إياه حول رقبتك، يقترب ببطء العالمُ الذي رأيته على الشاشة فقط حتى الأمس، حتى يصبح قريبًا بما يكفي لتلمسه."},"ICON-0367":{"nm":"علبة أغطية أقدام الاستوديو","de":"أرضية الاستوديو دائمًا باردة وزلقة. اخلع حذاءك، ارتدِ غطاء قدم رقيقًا، فتختفي وقع الخطى بهدوء. الكاميرا تلتقط الرقص لا الخطى، لذا محو الصوت أيضًا مراعاة تجاه المسرح."},"ICON-0368":{"nm":"بطاقة وجبة غرفة الانتظار الخفيفة","de":"بين البروفة والبث المباشر، يأتي الجوع بأصدق ما يكون. بطاقة اسم صغيرة على كل وجبة خفيفة في غرفة الانتظار تقول لمن هي. تلك اللطافة في التجهيز المسبق هي ما يحمّلك حتى نهاية يوم طويل طويل."},"ICON-0369":{"nm":"شريط مذكرة المراجعة","de":"تشاهد التسجيل وتكتب. هنا النظرة، وهناك نصف إيقاع. الكتابة الكثيفة رسالة سرية إلى نفسك في الغد. الشريط الملصق في النهاية وعدٌ هادئ بأن تصبح شبرًا أفضل من الأمس."},"ICON-0370":{"nm":"بطاقة دعوة العرض التقديمي","de":"ورقة واحدة قد تكون لأحدهم انتظارًا لعام كامل. جملة قصيرة تدعوك إلى العرض، وُلدت أصغر دعوة في العالم، تحمل حتى رعشة أطراف الأصابع وهي تفتح المظروف."},"ICON-0371":{"nm":"حزام بطاقة الصحافة","de":"معلّقٌ حول رقبة الصحفي، يشقّ طريقه وسط صخب الغالق. خطواتٌ مسرعة بحثًا عن أفضل زاوية، وتلك السرعة بعينها تصبح الممر الذي ينقل حرارة المسرح إلى العالم الخارجي."},"ICON-0372":{"nm":"جدول ترتيب تحية الوداع","de":"حتى في لحظة انهمار التصفيق، لئلا يضطرب أحد، يُكتب من يتقدّم أولًا ومن يليه في سطر واحد. تنظيم التحية الأخيرة يُصاغ بعناية لا تقل عن الظهور الأول."},"ICON-0373":{"nm":"علامة أرضية جدار الصور","de":"أمام جدار الصور، يُنقش مسبقًا مكان وضع أطراف القدمين. خطوة واحدة خارج المكان تقطع شعار الخلفية. سرّ الموضع الذي يُلتقط فيه أكثر إشراقًا، معلّم بهدوء تحت القدمين."},"ICON-0374":{"nm":"سوار العرض الأول","de":"شريطٌ صغير يُثبَّت على المعصم قبيل انطفاء أضواء المسرح مباشرةً. حين يرتفع الستار، يلتقي الجميع بالمشهد ذاته لأول مرة في العمر، في الظلام ذاته. علامة صغيرة على أنك كنت حاضرًا في تلك اللحظة الأولى."},"ICON-0375":{"nm":"قطعة ستارة تذكارية","de":"في يوم العرض الأخير، هبط الستار ببطء بعد التحية الأخيرة. قطعةٌ قُصّت من ذلك الجزء ووُضعت في إطار. لا يزال حرارة الأضواء واهتزاز التصفيق فاترين في القماش، لم يبردا بعد."},"ICON-0376":{"nm":"ختم الظهور الأول","de":"في يوم الظهور للعالم لأول مرة، نُقش هذا الختم لتلك المرة الواحدة. لا وجود لظهورٍ أول ثانٍ، فحتى اللحظة القصيرة لجفاف الحبر زمنٌ لن يعود أبدًا."},"ICON-0377":{"nm":"بطاقة لقطة المسرح","de":"أكثر لقطة تألقًا في مسرح ما، قُصّت ووُضعت في بطاقة. توقفت الموسيقى والأضواء، لكن في اللحظة التي تمسكها فيها بيدك، تنتفخ هتافات ذلك اليوم من جديد قرب أذنك. سحرٌ صغير يُحيي مشهدًا متوقفًا."},"ICON-0378":{"nm":"مذكرة وضعية الختام","de":"في اللحظة التي تنتهي فيها النغمة الأخيرة، مذكرة ترسم زاوية أطراف الأصابع والنظرة التي يجب أن تتجمّد. من يعرف وحده أن لقطة الختام قد تحدد مصير أيام، يطوي هذه الرسمة الصغيرة بعناية."},"ICON-0379":{"nm":"دبوس مدينة الجولة","de":"على الخريطة، دبوس واحد يُغرس في كل مدينة زرتها. نسيم بوسان البحري وظهيرة غوانغجو كلاهما مغروسان في أطراف هذه المسامير الصغيرة. صل النقاط بهدوء فترى خط رحلة طويلة عبرت فصلًا كاملًا."},"ICON-0380":{"nm":"مشبك قسم المقاعد","de":"يقسّم عشرات الآلاف من المقاعد إلى أقسام ويدلّ على الطريق. كي لا تتوه، كي لا تصطدم بأحد. اتبعني، وسيصل الجميع إلى مكانه. النظام في النهاية لطفٌ صغير من أجل الجميع."},"ICON-0381":{"nm":"بطاقة بوابة الدخول","de":"أمام البوابة، يمرّ كل شخص بالتحقق واحدًا تلو الآخر. البوابة الأخيرة التي تُدخل يدًا تمسك بتذكرة وقلبًا ينبض. لحظة تعبرني، ينتهي الانتظار الطويل ويبدأ مسرح اليوم."},"ICON-0382":{"nm":"كبسولة حفظ السوار","de":"مهما بهت اللون، يبقى هتاف ذلك اليوم محفوظًا كما هو. غير قادر على التخلص من شريط المعصم، تلفّه بعناية داخل كبسولة صغيرة. لأنك تريد أن تمنح حتى الذكرى العزيزة خانةً صغيرة ترقد فيها."},"ICON-0383":{"nm":"عمود التبادل الميداني","de":"بين المعجب والمسرح، يعبر شيءٌ من يد إلى يد. قد يكون رسالة، وقد يكون هدية صغيرة. أنا أفتح الطريق كي يصل ذلك القلب بسلام، أكثر جسر ازدحامًا في الموقع."},"ICON-0384":{"nm":"ختم تاريخ العرض","de":"تاريخ ذلك اليوم يُطبع داخل ختم مستدير ويتوقف إلى الأبد. تتقلب صفحات التقويم، لكن هذه الدائرة الصغيرة وحدها تبقى في ذلك اليوم كما هو. حين يكون يومًا لا يريدون نسيانه، يختم الناس دومًا شيئًا ما."},"ICON-0385":{"nm":"رقعة حقيبة الجولة","de":"حقيبةٌ جالت معك تزداد رقعةً واحدة لكل مدينة. أسماء الأماكن المخيطة على القماش تصبح سيرةً ذاتية دون أن تشعر. حتى الزوايا المهترئة والبالية تبقى دليلًا على أنكما ذهبتما معًا إلى كل مكان."},"ICON-0386":{"nm":"خيط لوحة التذاكر","de":"لوحٌ يتمايل في نهاية طابور الدخول، وخيطٌ واحد يربط طرفه بإحكام. وسط مشهد الأيدي التي ترفع التذاكر عاليًا وتمتد طويلًا، أُعلّم بهدوء رأس موكبٍ يصطف فيه الحماس."},"ICON-0387":{"nm":"قطعة شريط الإعادة","de":"في الليلة التي كانت فيها الأصوات المنادية بالإعادة أعلى ما يكون، سقطت قطعة من الشريط الذي زيّن المسرح. مثل أغنية غُنّيت أطول لأن انتهاءها كان مؤسفًا، تحمل هذه القطعة أيضًا عقدة من التردد في المغادرة."},"ICON-0388":{"nm":"زجاجة كبسولة الرسالة","de":"كلمةٌ واحدة مطوية بعناية داخل زجاجة. مثل قارب صغير أُرسل على أمل أن يصل يومًا ما، أحمل قلبًا وأطفو ببطء فوق الزمن. حتى يوم فتحها، يغفو الوعد بهدوء بالداخل."},"ICON-0389":{"nm":"بطاقة اعتراف صغيرة","de":"كلماتٌ لم تستطع نطقها بفمك، كُتبت على بطاقة صغيرة ودُسّت بخفاء. ارتجفت الكتابة، لكن الصدق وحده كان واضحًا. أحيانًا تحمل أصغر ورقة أعظم شجاعة."},"ICON-0390":{"nm":"صندوق رسائل التشجيع المجهولة","de":"حتى دون كتابة اسم، يصل القلب. مع كل رسالة تدخل الصندوق، يتراكم تشجيع أحدهم مجهول الهوية، ورقة تلو الأخرى. مجموعةٌ من الحنان بلا وجه، لا تعرف من كتبها لكن دفأها وحده واضح."},"ICON-0391":{"nm":"ورقة طيّ الأمنيات","de":"ورقةٌ مربعة تصبح كركيًا ثم نجمة، متتبّعةً أطراف أصابعك. مع كل طيّة، تنطوي الأمنية طبقةً أخرى أيضًا. في الشكل المطويّ بعناية، يسكن صدقٌ يبقى أطول من الكلام."},"ICON-0392":{"nm":"شمع ختم الشريط","de":"أسقط الشمع واضغط الختم بقوة، فتُختم الرسالة أخيرًا. بالطريقة القديمة ذاتها لتثبيت قلبٍ ما. فوق الشمع الأحمر البارد، ينغلق سرٌّ واحد بهدوء."},"ICON-0393":{"nm":"ورق حشو الهدايا","de":"خوفًا من أن تتأذى الهدية، يلتف برفق حول محيطها. في كل طيّة متجعّدة يتسرّب رجاءٌ بألا تنكسر. طبقة من قلبٍ حذر في مكان لا يُرى، سيمر عليها المتلقي دون أن يلاحظها."},"ICON-0394":{"nm":"خيط رسالة ملوّن","de":"حتى الخيط الذي يربط رسالةً له لون. الأصفر للتشجيع، والأزرق للشوق. مشاعر لم تستطع الكلمات قولها كاملة تُختار بلون وتُعقد. قبل أن تفكّه حتى، تصلك حرارة القلب أولًا عبر أطراف أصابعك."},"ICON-0395":{"nm":"شريط إخفاء الخط اليدوي","de":"شريطٌ واحد يخفي الكتابة حتى لحظة التسليم مباشرةً. يحرس اعترافًا قلقًا من الافتضاح حتى الثانية الأخيرة. الصدق الذي ينكشف حين ترفعه قليلًا، وزن تلك الرعشة أعرفه عن قرب أكثر من أي أحد."},"ICON-0396":{"nm":"رقاقة عبارة التشجيع","de":"في ليلة تتموّج فيها أعواد التشجيع، جملة واحدة تُصاح بصوت واحد منقوشة داخل الرقاقة. كلمات وعد تجمع قلوبًا متناثرة في سطر واحد. حين تُنشد معًا، تلمع تلك الجملة أكثر ما تكون."},"ICON-0397":{"nm":"سلسلة مفاتيح غرفة التدريب القديمة","de":"سلسلة مفاتيح فتحت وأغلقت باب غرفة التدريب مئات المرات. تقشّر الطلاء وارتخت الحلقة، لكن فيها بقي عرق أخرق الأيام كأثر لمسٍ قديم. أن يكون الشيء باليًا، يعني أنه بقي طويلًا بذلك القدر."},"ICON-0398":{"nm":"قطعة مساحيق مسرحية","de":"لا يكتمل مكياج المسرح إلا تحت الأضواء. قطعة من ذلك اللون الغامق. في الأثر الذي وُضع بإحكام كي لا يمتزج بالعرق، تتشرّب عناية إيصال التعبير حتى أبعد مقعد."},"ICON-0399":{"nm":"علبة سدادات الأذن","de":"سدادات صغيرة كانت تتيح لك سماع صوتك على المسرح. حين ينتهي العرض، تُرقدها بعناية داخل العلبة. كلما كان الشيء أقرب في نقل الموسيقى إليك، ازددت رغبةً في حفظه بعناية أكبر."},"ICON-0400":{"nm":"ملصق الخزانة الشخصية","de":"في نهاية ممر السكن، بطاقة اسم على كل خزانة. كتابةٌ صغيرة تخبر بمن هي، تحوّل مكانًا غريبًا إلى بيت. أن يكون لك خانتك الخاصة، إذنٌ حنون بأن تبقى هنا."},"ICON-0401":{"nm":"زجاجة العناية بالحنجرة المحمولة","de":"بين البروفة والأخرى، تجرع رشفة من ماء فاتر ببطء. الحنجرة آلة يستعيرها المغني، فهذه القارورة الصغيرة التي تُملأ قبل أن يبرد الماء تحمي نغمة الغد الأولى مسبقًا. القلب الحريص هادئ دومًا على هذا النحو."},"ICON-0402":{"nm":"دبوس تذكير الجدول","de":"فوق يوم مزدحم دقيقة بدقيقة، يشير دبوس واحد إلى الخانة التالية. وبين هذه الصفوف الكثيفة، أرحب شيء هو خانة فارغة واحدة. هناك، صغيرة ومختبئة، يكمن الوقت الذي يمكن فيه إلقاء نظرة عابرة من النافذة."},"ICON-0403":{"nm":"مشبك بطانية غرفة الانتظار","de":"في عصر غفا فيه أحدهم على الكرسي بعد أن أنهى المكياج، سحب أحدهم ببطء بطانية ليضعها فوق كتفيه. هذا المشبك الذي يعضّ عليها كي لا تنزلق، يمسك بهدوء بدفء تلك اللمسة حتى موعد الصعود إلى المسرح."},"ICON-0404":{"nm":"عينة عطر صغيرة","de":"إن نقرتها برفق على باطن المعصم، تتفتح الرائحة في نطاق شبر واحد فقط. لا بأس إن لم تنتشر بعيدًا. فهي أثر لا يلحظه إلا من اقترب، وهذا ما يجعلها أكثر سرية، وبالتالي أكثر شبهًا بي."},"ICON-0405":{"nm":"بطاقة غسيل ملابس التمرين","de":"مهما غسلتَها مرات ومرات، رائحة العرق المتغلغلة في عمق القماش لا تزول تمامًا أبدًا. وأنت تطوي ملابس التمرين المنشورة تحت الشمس حتى جفّت وطراوتها، تفكر: ذلك الأثر الذي لا يمحى هو في الحقيقة أصدق علامة."},"ICON-0406":{"nm":"فيلم جيلاتيني للإضاءة","de":"بمجرد إدخال طبقة رقيقة ملونة، يذوب الضوء الأبيض في لون الغسق، وإذا أضيفت طبقة أخرى فوقها ينزل الفجر. خلف الستار، هناك يد تحبس أنفاسها وهي تكسو الضوء نفسه بثوب، تقرر أي فصل سيصبغ المسرح."},"ICON-0407":{"nm":"غطاء عدسة الإضاءة الموجهة","de":"حتى وقد أُطفئت الكاميرا، يفتح أحدهم هذا الغطاء الصغير لتنظيف العدسة. من أجل المشهد التالي الذي لم يُصوَّر بعد. فوق زمن لا تلتقطه الشاشة، أكثر الأيدي انشغالًا تضبط التركيز مسبقًا."},"ICON-0408":{"nm":"لوح عاكس المسرح","de":"حتى وإن لم يضئ من ذاته، ثمة لوح يعيد الضوء الذي تلقّاه إلى وجه ظليل. مركز المسرح مشرق إلى هذا الحد لأن هناك، عند الحافة، ذراع أحدهم تضبط بصمت الزاوية وتعكس الضوء إليه."},"ICON-0409":{"nm":"كُم فلتر الألوان","de":"أدخل ضوءًا أزرق في الكُم الشفاف فيصير الجمهور بأسره بحرًا، وبدّله إلى أحمر فينسدل الغسق في مكانه. سحر أن يتحول المسرح ذاته إلى فصل مختلف بلون واحد يبدأ من هذه الطبقة الرقيقة الواحدة."},"ICON-0410":{"nm":"دبوس رقم الإضاءة","de":"لكل ضوء من الأضواء الكثيرة رقم صغير. أيّها يُضاء وأيّها ينام، تدفق عرض الليلة مرتب مسبقًا وفق تسلسل هذه الأرقام. خلف الستار الباهر، هناك دائمًا قائمة دقيقة مفتوحة."},"ICON-0411":{"nm":"شريط علامات الإضاءة","de":"على أرضية المسرح المعتمة، يضيء شريط فسفوري بصمت المكان الذي ستتوقف عنده القدم. غير مرئي من المقاعد، لكن أطراف أصابع قدم المؤدي تتحسس هذا الضوء الخافت لتجد موضعها. حتى في الظلام يوجد دليل رقيق."},"ICON-0412":{"nm":"لوح حجب الظل","de":"لوح يمنع تسرب الضوء ليُسقط ظلًا واضحًا حادًا. التعامل مع الظلام هو في النهاية تعامل مع الضوء، فما سيُعرض يتحدد أولًا بما سيُخفى بهدوء."},"ICON-0413":{"nm":"رقاقة قياس الإضاءة","de":"رقاقة صغيرة تقيس سطوع المكان تقرأ الأرقام فوق راحة اليد. فالإضاءة الشديدة تؤذي العين مثل الظلام الشديد. وهذه الرقاقة تحرس بصمت ذلك الخط الفاصل غير المرئي حيث يشعر الإنسان بأكبر قدر من الراحة."},"ICON-0414":{"nm":"واقي الضوء الموجَّه","de":"واقٍ يُركَّب كي لا يتسرب ضوء موجَّه إلى مكان خاطئ. تجميع الضوء على شخص واحد فقط هو تركيز مفعم بالحنان. وفي اللحظة التي تطأ فيها قدماك تلك الدائرة الضوئية، ينظر العالم كله إلى شخص واحد فقط للحظة."},"ICON-0415":{"nm":"طقم أطراف سماعة الأذن","de":"زوج من أطراف السماعات يلتصق تمامًا بالأذن. إن اختلف الحجم قليلًا يتسرب الصوت، وفي لحظة التسرب يضيع الإيقاع. الأغنية التي لا يهتز عليها المسرح قيد شعرة تبدأ أحيانًا من هذه القطعة الصغيرة من المطاط."},"ICON-0416":{"nm":"شريط فيلكرو للكابلات","de":"شريط فيلكرو يجمع الأسلاك المتشابكة في خيط واحد مرتب. كلما قلّ من يرى خلف المسرح، ازداد بريق الترتيب هناك. أناقة حزمة واحدة من الكابلات تسند بهدوء الصوت المتدفق دون اهتزاز أمام الجمهور."},"ICON-0417":{"nm":"ملصق فحص الخطوط","de":"بطاقات أسماء مكتوبة بخط اليد على عشرات الأسلاك، تخبر أي آلة تخص. لا يجتمع الصوت المتفرق في أغنية واحدة إلا حين يحافظ كل حرف معوجّ من تلك الكتابة على موضعه."},"ICON-0418":{"nm":"وسادة العزل الصوتي","de":"وسادة صمت واحدة تبتلع بهدوء خطى الأقدام والارتجاف على حد سواء. تُفرش حيث تكون السكينة ضرورية حقًا. أنقى الأصوات يولد أحيانًا فوق هذه الأرضية الهادئة التي لا يتسرب منها أي ضجيج."},"ICON-0419":{"nm":"عملة فحص الصوت","de":"عملة تدفأ في راحة اليد أثناء ضبط الصوت قبل العرض. مع كل ميكروفون وكل سماعة تُفحص، تنتقل إلى قبضة جديدة. كمال المسرح الرئيسي يتشكل خطوة خطوة داخل هذه البروفة الهادئة."},"ICON-0420":{"nm":"غطاء رأس الميكروفون","de":"لأنه المكان الذي لامسته أصوات لا تحصى، يُنظَّف هذا الغطاء الذي يلف طرف الميكروفون بعناية أكبر. إنه وعاء يحمل الأغنية، فهو للمغني بمثابة يد أخرى. وأثناء تنظيفه، يُرسم مقطع الغد الأول مسبقًا في الخيال."},"ICON-0421":{"nm":"مشبك مرشّح البوب","de":"طبقة شبكية رقيقة مُعلّقة بين الشفتين والميكروفون. بفضل المشبك الصغير الذي يثبت تلك الحاجزة، يتهذب النَّفَس الذي كان يتسرب خشنًا ليخرج صوتًا مستديرًا ناعمًا."},"ICON-0422":{"nm":"بطاقة رف الصوت","de":"بطاقة صغيرة معلّقة كي لا يضل الطريق بين رفوف المعدات المتراكمة في عتمة خلف المسرح. مصدر الصوت الباهر الذي يملأ المقاعد مرتّب دومًا بعناية في مثل هذه الأماكن الخافتة."},"ICON-0423":{"nm":"دبوس شبكة السماعة","de":"دبوس يثبّت شبكة السماعة بإحكام. النافذة التي يخرج منها الصوت هي أول ما يواجه الغبار، فطبقة شبكية رقيقة تحمي النغمة. كل ما يصل إلى الأذن يرتدي طبقة حماية غير مرئية."},"ICON-0424":{"nm":"ملصق علامة الخطوات","de":"ملصقات مواقع مثبتة نقطة نقطة على الأرض. سر تطابق الرقصة الجماعية كحدّ السيف يكمن تحت الأقدام في الحقيقة. فوق آثار لا تُحصى من الوعود، حيث يطأ العشرات النقطة ذاتها ثم يتفرقون ليجتمعوا مجددًا."},"ICON-0425":{"nm":"قرص تمرين الدوران","de":"قرص تدريب يدور في مكانه مرارًا. للتغلب على الدوار، يتعلم المرء أولًا تثبيت نظره على نقطة واحدة. مهما دار بسرعة، يظل متمسكًا بتلك النقطة، وهو توازن يُنقش ببطء في الجسد."},"ICON-0426":{"nm":"لفافة شريط الركبة","de":"لفة شريط تلف الركبة بإحكام. المفاصل التي قفزت وهبطت آلاف المرات تظل صامتة في النهاية، لكن هذه الطبقة الواحدة تسند بهدوء ذلك الصمت. خلف كل جسد يصمد حتى النهاية، توجد دائمًا رعاية من شخص ما."},"ICON-0427":{"nm":"لوح محاذاة أطراف القدم","de":"لوح يضبط زاوية أطراف الأقدام بترتيب. يقال إن الرقص يكتمل عند أطراف القدمين أكثر من أطراف الأصابع. عشرات الأقدام الممدودة في اتجاه واحد تجتمع لتنسج سحر أن يبدو الكثيرون كشخص واحد."},"ICON-0428":{"nm":"وسادة مانعة للانزلاق لصالة التمرين","de":"وسادة مضادة للانزلاق تُفرش على أرضية صالة التمرين. للقفز بحرية تامة يجب أولًا أن تكون آمنًا. فقط فوق أرضية يمكن التدحرج عليها براحة بال دون خوف السقوط، تزهر أخيرًا الحركات الأكثر جرأة وشجاعة."},"ICON-0429":{"nm":"بطاقة تفكيك الحركة","de":"بطاقة ترسم الرقصة مقسّمة إلى قطع صغيرة، إيقاعًا إيقاعًا. مهما كانت الحركة صعبة، إن قُسّمت خانة خانة سرعان ما تجد نفسك تتبعها. التدفق السلس كجريان الماء على المسرح صُنع من هذه الرسوم المحفوظة قطعة قطعة مجتمعة."},"ICON-0430":{"nm":"دبوس ستارة تغطية المرآة","de":"دبوس يثبّت الستارة التي تحجب مرآة صالة التمرين للحظة. هناك حاجة أيضًا لوقت يُرقَص فيه بإحساس الجسد وحده، دون انعكاس. في لحظة تغطية المرآة، يعرف المرء أن الموسيقى تتسرب أخيرًا حتى إلى البشرة."},"ICON-0431":{"nm":"خرزة عد الإيقاع","de":"طقطقة خفيفة، تدفع خرزة واحدة بطرف إصبعك مع كل إيقاع، تعدّ معه. ملموسة كطريقة عدّ قديمة. الإيقاع، عمود الموسيقى الفقري، لا يستقر بثبات في الجسد إلا حين يُتعلّم عبر شيء يمكن لمسه هكذا."},"ICON-0432":{"nm":"شريط فحص الإحماء","de":"شريط فحص يشير إلى ما إذا كان الجسد قد ارتاح تمامًا. قبل التمرين الحقيقي يأتي دومًا استعداد هادئ أولًا. فبدلًا من الندم بعد الإصابة، ربط شريط واحد وإيقاظ الجسد ببطء يجعل الرقص أطول عمرًا في النهاية."},"ICON-0433":{"nm":"مشبك رقم الزي","de":"مشبك يُثبّت رقمًا على كل زي كي لا تختلط الأزياء الكثيرة. في تبديل الملابس اللاهث، اختلاط زي واحد فقط كارثة، لذا تُدوَّن دورة كل قطعة بوضوح. حتى الانشغال يصبح أنيقًا حين يسنده النظام."},"ICON-0434":{"nm":"وسادة دبابيس غرفة الترميم","de":"وسادة دبابيس موضوعة في زاوية غرفة الترميم. هنا تمكث اليد التي رتقت بصمت الخياطة الممزقة والأزرار الساقطة. خلف هندام المسرح الخالي من أي خلل، تختبئ عناية غرزات لم تر المسرح قط."},"ICON-0435":{"nm":"حلقة قطع القماش الاحتياطية","de":"حلقة تجمع قطع قماش احتياطية في واحدة. القماش ذاته يُحفظ جانبًا مسبقًا احتياطًا ليوم يتلف فيه الزي الأساسي. هذا الاستعداد الصغير، المحفوظ على أمل ألا يحدث شيء، ينقذ زي المسرح في لحظة وقوع أمر جلل بالفعل."},"ICON-0436":{"nm":"عبوة أزرار سريعة التركيب","de":"عبوة أزرار يمكن تثبيتها فورًا عند الحاجة الملحّة. حين يسقط زر واحد فجأة قبل العرض مباشرة، تهتز غرفة التبديل كلها للحظة. صندوق إسعافات أولية صغير لكنه موثوق تمامًا، يهدئ في لمح البصر ذلك الطارئ القصير المرتبك."},"ICON-0437":{"nm":"حامل حزام المسرح","de":"حامل يمسك بإحكام حزام زي المسرح. كي لا يضطرب الزي مهما قفزت ودُرت بعنف. الحرية التي تُستمتَع بها على المسرح بلا قيد تأتي، في النهاية، من إحكام إغلاق أماكن لا يراها أحد."},"ICON-0438":{"nm":"منفضة ريش","de":"لأن حتى وبرة صغيرة تبرز تحت الأضواء، تُمسَح ملابس الأداء برفق بمنفضة الريش. قبيل خطوة على المسرح مباشرة، تلك اللمسة الحانية لتسوية الملابس للمرة الأخيرة تخص دائمًا هذا الريش الناعم."},"ICON-0439":{"nm":"بطاقة نعل غرفة الانتظار","de":"بطاقة اسم على كل شبشب في غرفة الانتظار. في بطاقة صغيرة تخبر لمن هذا الشبشب، تكمن بصمت طمأنينة أننا فريق واحد. تلك الغرفة التي تخلع فيها حذاءك وتمدّ قدميك تصبح أدفأ منزل خلف المسرح."},"ICON-0440":{"nm":"لوح مشابك تصفيف الشعر","de":"لوح مشابك يثبت خصلات الشعر أثناء التصفيف. بين تسوية خصلة تلو أخرى، تودع الأصابع الشعر الذي يريد التبعثر لهذه المشابك للحظة. الأناقة، في النهاية، مصنوعة من مثل هذه التوقفات الصغيرة مجتمعة."},"ICON-0441":{"nm":"كبسولة تنظيم دبابيس الأمان","de":"في فجر انفتقت فيه خياطة، افتح غطاء الكبسولة فترقد فضة صغيرة باردة بترتيب. يد تمسك الزي بأشد إحكام من الداخل غير المرئي، دبوس الأمان يعمل دومًا بصمت خلف المسرح."},"ICON-0442":{"nm":"قماشة تنظيف العدسات","de":"نفخة هواء واحدة، ومسح دائري، فيتضح العالم الضبابي. تلك اللحظة القصيرة جميلة لدرجة أنك تعاود تنظيف العدسة مرارًا. قطعة صغيرة من شمس الربيع تصفّي رؤية شخص آخر بدلًا عنه."},"ICON-0443":{"nm":"أقدام مطاطية للحامل الثلاثي","de":"بمجرد تركيب المطاط على الأطراف الثلاثة، يكف الأرضية عن الصرير. وبينما تبتلع النقاط الصغيرة الاهتزاز، يهدأ المشهد على الشاشة كأنه أمر مستحيل. الاستقرار يبدأ دومًا بهدوء تحت القدمين."},"ICON-0444":{"nm":"غطاء المطر للكاميرا","de":"حتى وقطرات المطر تنساب، تلتقط العدسة العالم وهي جافة. في عصر غائم من تصوير خارجي، يُكسى معطف واق شفاف فوق الكاميرا برفق. لأن الأشياء الثمينة تُحاط أولًا قبل أن تبتل."},"ICON-0445":{"nm":"شريط علامات التصوير","de":"قف هنا، استدر هناك، آثار قصيرة ملونة تشير بوضوح إلى الطريق دون كلمة واحدة. وحتى حين تُنزع بلا أسف بعد انتهاء العرض، تظل أطراف الأقدام التي اعتادتها تتذكر ذلك الموضع طويلًا."},"ICON-0446":{"nm":"مشبك فصل اللقطات","de":"مشبك صغير يعضّ الأوراق المتناثرة بلقمة واحدة. بصوت طقة واحدة رنانة، يُربط الأمس واليوم بترتيب. الترتيب هو عادة حانية للإمساك بهدوء بما كاد يُفقد."},"ICON-0447":{"nm":"لوح توازن اللون الأبيض","de":"ارفع لوحًا أبيض أمام الشاشة فتجد الألوان تعثر بهدوء على مكانها. الغروب الأصفر، الفجر الأزرق، دون كذب. لوح واحد يعرف البياض الحقيقي يجعل بقية الألوان تتحدث بصدق."},"ICON-0448":{"nm":"علبة حفظ الذاكرة","de":"داخل علبة صفيح صغيرة، تغفو رقائق الذكريات في سلام. افتح الغطاء بصوت طقطقة، فتنسكب مشاهد الفصل الماضي في راحة يدك. الذكرى تبقى محفوظة برعاية داخل علبة واحدة متينة كهذه."},"ICON-0449":{"nm":"غطاء ظل الشاشة","de":"لُفّ حاجبًا أسود حول الشاشة فيتوقف انعكاس الضوء فورًا. حتى قرب نافذة تغمرها الشمس، لا تفقد الشاشة لونها. لكي ترى جيدًا عليك أولًا أن تحجب الضوء الطائش، هكذا يخبرك الغطاء بهدوء."},"ICON-0450":{"nm":"دبوس عزل صوت الموقع","de":"دبوس صغير مثبت في فجوة الباب يقطع بهدوء الضجيج الخارجي. خطى الممر، ضحكات الغرفة المجاورة، لا شيء منها يصل إلى هنا. لأن التقاط صوت نقي يستلزم أولًا بناء الصمت."},"ICON-0451":{"nm":"عبوة إسفنج المكياج","de":"حزمة من الإسفنج الناعم مرصوصة بعناية. انقر بودرة خفيفة بطرف الإصبع فتشرق ملامح الوجه درجة أكثر. خلف كل ابتسامة مشرقة على المسرح تختبئ دومًا هذه اللمسات الرقيقة."},"ICON-0452":{"nm":"علبة دبابيس الشعر","de":"بيت مرتب للدبابيس الصغيرة سهلة الضياع. افتح الغطاء فتصطف الفضة صفوفًا لتستقبلك. متناثرة تختفي، ومجتمعة تطمئن. حتى أصغر الأشياء تحتاج إلى بيت خاص بها."},"ICON-0453":{"nm":"علبة تعقيم الفرش","de":"فرش حملت الألوان طوال اليوم تأخذ حمام أشعة فوق بنفسجية داخل العلبة. بينما يغسل الضوء غير المرئي القديم، تخرج شعيرات الغد ناعمة كأول مرة. النظافة أيضًا خيط من خيوط العناية."},"ICON-0454":{"nm":"شبكة إسفنجات البودرة","de":"إسفنجات مستديرة تلتقط أنفاسها بهدوء داخل كيس الشبكة. حين يتخلل الهواء عبر الشبكة، تدوم نعومتها أطول. إسفنجة جافة جيدًا تحمل مسبقًا إشراق صباح الغد."},"ICON-0455":{"nm":"غطاء رذاذ تثبيت التسريحة","de":"رشة واحدة سريعة، ولا خصلة تضطرب مع الريح. غطاء صغير يثبت تسريحة عُني بها طوال الليل. فوق الشعر المثبت بإحكام، تنهمر الأضواء الساطعة وتتشظى."},"ICON-0456":{"nm":"غطاء فرشاة الشفاه","de":"غطاء صغير يلف برفق طرف الشعيرات النحيلة. حتى وهو يتقلب داخل الحقيبة، تبقى الفرشاة مستقيمة ونظيفة. الاعتناء بفرشاة صغيرة واحدة يكمل ضربة لون واحدة على الشفاه."},"ICON-0457":{"nm":"مرآة رقم الانتظار","de":"مرآة صغيرة ملتصقة بهدوء بجانب الرقم الذي ينادي دورك. قبيل الصعود إلى المسرح مباشرة، إنه المكان لتسوية خصلة شعر شاردة أخيرة. حتى التوتر يخف قليلًا حين تُلقي نظرة على انعكاسك."},"ICON-0458":{"nm":"منشفة رباط المعصم","de":"شريط ناعم يمسح عرق الجبين بلمسة واحدة من المعصم. كلما اشتدت الرقصة، امتدت اليد إليه أكثر. عزاء صغير على المعصم، يبقى قريبًا في كل لحظة ينقطع فيها النفس."},"ICON-0459":{"nm":"ملصق حقيبة الأدوات","de":"حتى وعشر حقائب متطابقة تصطف في غرفة التبديل، لا يحدث خلط أبدًا. فبطاقة الاسم على كل حقيبة تخبر بوضوح لمن هي. كتابة \"لي\" على شيء ما علامة صغيرة لكنها حانية."},"ICON-0460":{"nm":"دبوس حجز صالة التمرين","de":"من سيستخدم صالة التمرين هذه اليوم؟ دبوس صغير مغروز في اللوحة قرب الباب يقسّم الوقت بصمت. القلوب المنتظرة دورها التالي تصطف بهدوء خلف هذا الدبوس الواحد."},"ICON-0461":{"nm":"حلقة غطاء ساعة الحائط","de":"يستقر غطاء شفاف برفق فوق ساعة الحائط ليمنع الغبار. عقارب الساعة النقّارة لا تغيم، والزمن يتدفق صافيًا. الأشياء الثمينة تحتاج دومًا إلى طبقة حماية غير مرئية."},"ICON-0462":{"nm":"وسادة حماية الأرضية","de":"وسادة رقيقة ملصقة أسفل رِجل الكرسي تمنع مسبقًا خدش الأرضية الخشبية. سحبه لا يُخدش شيئًا، ونقله لا يترك أثرًا. رعاية الأرضية بصمت، هذا سر استخدامها لعمر طويل."},"ICON-0463":{"nm":"رقاقة تحذير منع المشروبات","de":"لنضع المشروبات جانبًا هنا للحظة، تطلب رقاقة صغيرة بلطف. فالنوتة الموسيقية والمعدات في ورطة إن ابتلّت. حتى كلمة \"ممنوع\" تصبح اهتمامًا دافئًا حين تُقدَّم هكذا."},"ICON-0464":{"nm":"ملصق زر التهوية","de":"حين ترغب في تغيير الهواء الخانق، اضغط هنا، يرشد ملصق صغير بجانب الزر إلى الطريق. التقاط الأنفاس يبدأ بهدوء، على نحو غير متوقع، من علامة صغيرة كهذه."},"ICON-0465":{"nm":"قاعدة مطاطية للسماعة","de":"قاعدة مطاطية تحت السماعة تبتلع برفق الاهتزاز الخافت. حين لا ينتشر الصوت الجهير عبر الأرضية، يصبح الصوت أكثر وضوحًا. الرنين الجميل لا يصفو إلا فوق قاعدة متينة."},"ICON-0466":{"nm":"مغناطيس رقم الخزانة","de":"مغناطيس رقم صغير يلتصق بباب الخزانة. في أي خانة سينام غرضي اليوم؟ حتى وإن تغيّر المكان يوميًا، مغناطيس واحد يصنع خزانتي في لحظة. الانتماء يأتي من علامة خفيفة كهذه."},"ICON-0467":{"nm":"ممسحة المرآة","de":"مسحة واحدة سريعة فوق المرآة يزول معها البخار تمامًا. لحظة يبرز فيها وجهي الغائم بوضوح. لكي أرى نفسي حقًا، عليّ أولًا أن أمسح بهدوء ما يشوّش الرؤية."},"ICON-0468":{"nm":"وسادة تخميد الباب","de":"حشوة ناعمة موضوعة في فجوة باب يُغلق بعنف. تمتص برفق صوت الطرق وانحشار اليد على حد سواء. أمان صغير يدسّ طبقة من الرقة بين اصطدامات خشنة."},"ICON-0469":{"nm":"كتلة غطاء الكابلات","de":"غطاء متين يمد جسرًا محكمًا فوق كابلات تعبر الأرضية. لا قدم تتعثر، ولا سلك يُداس. هدوء كتلة واحدة تحرس الطريق دون أن تسده."},"ICON-0470":{"nm":"مخروط تحذير الأرضية الزلقة","de":"مخروط أصفر يقف وحيدًا فوق أرضية مبللة يحذّر بصمت. خطوة حذرة، بطيئة، من فضلك. خلف المسرح المضيء يقف مثل هذا الحارس الصغير، يصون كل خطوة بهدوء."},"ICON-0471":{"nm":"عصا إضاءة الطوارئ","de":"شعاع واحد يومض في ممر مظلم بسبب انقطاع الكهرباء. كي لا تضل الطريق حتى في الظلام، يوضع ضوء الطوارئ في يدك. توجد بالتأكيد أشياء في هذا العالم تسطع أكثر ما تسطع في أحلك اللحظات."},"ICON-0472":{"nm":"غطاء حماية الدرابزين","de":"غطاء مستدير مركّب على طرف درابزين الدرج يلف بنعومة الحافة الحادة. حتى لو لامسته اليد بلا انتباه، لن يحدث أذى. تغطية الحدّة بهدوء هي أيضًا نوع من الاهتمام بشخص آخر."},"ICON-0473":{"nm":"وسادة حافة المسرح","de":"وسادة ناعمة تلتف حول حافة المسرح. كي لا تُكدَم طرف قدم تلامسها أثناء رقصة عنيفة. خلف كل حركة باهرة، حماية غير مرئية ترقص معها."},"ICON-0474":{"nm":"قرص علامة الأرضية","de":"قرص مستدير موضوع على الأرض يقول بهدوء \"قف هنا\". من يقف في الطابور ومن يبحث عن مكانه، كلاهما يتوقف بهدوء عند هذه النقطة الواحدة. النظام ينمو من علامة صغيرة."},"ICON-0475":{"nm":"سير المصباح اليدوي","de":"لُفّ الحبل المعلّق بطرف المصباح دورة واحدة حول معصمك، فلا تفقد الضوء حتى في الظلام. لفة واحدة صغيرة لكنها موثوقة، تحرّر اليدين دون قلق من سقوطه."},"ICON-0476":{"nm":"حبل تحديد المسار","de":"من فضلك لا تتجاوز هذا الحد، يرسم حبل واحد الخط برفق. حدّ لطيف يفصل بهدوء بين المكان الخطر والمكان الآمن. المنع أيضًا طريقة من طرق حماية شخص ما."},"ICON-0477":{"nm":"دبوس فحص السلامة","de":"عند كل موضع اكتمل فحصه، يترك دبوس صغير كلمة \"تم التأكد\". نقطة واحدة أشبه بختم عقل تفقّد كل شيء دون أن يفوته موضع. السلامة ليست أمرًا عظيمًا، بل مجموع علامات وُضعت واحدة تلو أخرى بعناية."},"ICON-0478":{"nm":"لوح المشاهد المصغّر","de":"عند الصوت الحاد الذي يقطع الإيقاع الأول بطقة واحدة، تتوافق أنفاس الجميع في الموقع دفعة واحدة. وإن كان صغير الحجم، فخط انطلاق كل مشهد هو دومًا هذا الإيقاع الواحد. بداية التصوير المثيرة تُفتح من هنا."},"ICON-0479":{"nm":"غطاء ميكروفون المكتب","de":"غطاء ناعم يُلبَّس برفق فوق ميكروفون المكتب. حتى نفس حاد يتنفس فجأة يمر نقيًا خاليًا من الضجيج. أدفأ ما يلف الصوت هو هذه الطبقة الصغيرة الرقيقة."},"ICON-0480":{"nm":"قطعة لوح ماص للصوت","de":"قطعة من لوح ماص للصوت مثبتة في الجدار تجمع بصمت الصدى المتناثر. حين لا يرتد الصوت ويتبعثر، تتجمع الأغنية أكثر صفاءً. الرنين الجميل يبدأ بتشذيب الصمت بعناية."},"ICON-0481":{"nm":"خطاف تعليق السماعات","de":"تعليق السماعات هنا وعد صغير. فك السلك ورتّبه بترتيب كي يلتقطه الشخص التالي مباشرة. خطاف واحد يُدخل نظامًا هادئًا إلى كابينة مزدحمة."},"ICON-0482":{"nm":"مصباح \"التسجيل جارٍ\"","de":"في اللحظة التي يضيء فيها الضوء الأحمر، يتوقف كل نفس داخل الكابينة. إشارة توقف حتى خطى الأقدام خلف الباب. التقاط الصوت يبدأ بالحفاظ على هذا الصمت العميق."},"ICON-0483":{"nm":"علبة تنظيم أصابع العزف","de":"أصابع عزف مرتبة في خانات حسب اللون. السماكة والوزن يشكّلان عادة أطراف الأصابع. قبيل المسرح مباشرة، تلك الدقة في التقاط الصحيح دون النظر تنمو من هنا."},"ICON-0484":{"nm":"أداة ترقيم الكابلات","de":"كي لا تضل الطريق بين عشرات الخيوط المتشابكة على الأرض، يجب كتابة اسم على كل طرف. فقط من كتب من أين يأتي وإلى أين يذهب لا تتعثر يده حتى في الظلام."},"ICON-0485":{"nm":"مقبض خلاط الصوت المصغّر","de":"أدره بمقدار عقدة إصبع واحدة فيتغيّر نسيج الصوت. ارفعه فيخشن، اخفضه فيغرق، والبحث عن تلك النقطة الواحدة بينهما. أرق لمسة تصنع أكبر تغيير."},"ICON-0486":{"nm":"حلقة تثبيت الحامل","de":"ما يسند المسرح ليس الأضواء الباهرة بل هذه الحلقة الصغيرة. تُمسك الاهتزاز بإحكام، وتصمد بصمت في موضعها، غير مرئية لأي عين."},"ICON-0487":{"nm":"ملصق تفكيك الديكور","de":"حتى إعادة كل ما بُني إلى وضعه بحذر له ترتيب واضح. ورقة واحدة تدوّن أين يُفك وإلى أين يُنقل. الأيدي التي تفكك ماهرة بقدر الأيدي التي تبني."},"ICON-0488":{"nm":"رقاقة مظروف المفقودات","de":"كل غرض يسقط من أحدهم يحمل قصته الخاصة. وضعه في مظروف صغير في انتظار اسم صاحبه هو حنان يحفظ للحظة حتى قلب من فقده."},"ICON-0489":{"nm":"علامة مسار التنظيف","de":"اتبع الأسهم المرسومة على الأرض فتُنظَّف كل زاوية دون فراغ. حتى المكنسة تحتاج طريقًا كي لا تدور عبثًا. ألمع بقعة توجد عند نهاية أفضل خطى رُسمت."},"ICON-0490":{"nm":"عصا توجيه الخروج","de":"حين يخفت آخر تصفيق، تفتح هذه العصا الطريق. يد ترافق ببطء القلوب التي لا تزال متحمسة دون أن تجرحها. حتى توجيه النهاية يحمل اهتمامًا دافئًا."},"ICON-0491":{"nm":"كرة بقايا الشريط اللاصق","de":"لُف البقايا المتبقية في كرة مستديرة فيولد لها استخدام مرة أخرى. تمامًا كما تجتمع الأطراف التي كادت تُرمى لتصبح كرة متماسكة، ينمو قلب التوفير من طرف إصبع صغير."},"ICON-0492":{"nm":"غطاء رقم المقعد","de":"يجب أن يحمل كل كرسي في الصالة رقمًا كي لا يضل أحد طريقه. غطاء صغير واحد يحدد المكان يحوّل ارتباك القادم الجديد إلى ارتياح هادئ."},"ICON-0493":{"nm":"دبوس فرز النفايات","de":"دبوس صغير يفصل الورق عن البلاستيك ويثبّته في مكانه. مختلطًا، إنه مجرد قمامة، لكن مفصولًا يصبح موردًا يُستخدم مجددًا. الفرز عمل حانٍ يعيد للأشياء حياة ثانية."},"ICON-0494":{"nm":"بطاقة إرجاع المعدات","de":"ما استُعير يجب أن يعود دومًا إلى مكانه. مع كل طرف إصبع يُعيده موسومًا بالبطاقة، تتراكم الثقة طبقة بعد طبقة. من يعيد بإحسان يستعير المرة القادمة بقلب مطمئن أيضًا."},"ICON-0495":{"nm":"مفتاح تسجيل خروج غرفة الانتظار","de":"بعد خلع مكياج اليوم وزيه بالكامل، يُعاد هذا المفتاح أخيرًا. إعادة ما استُلم عند الدخول لحظة الخروج. بداية اليوم ونهايته محفوظتان في اليد ذاتها."},"ICON-0496":{"nm":"علبة إسفنجة الكوشن","de":"الإسفنجة الناعمة تفقد نسيجها إذا ضُغطت. لهذا السبب تُوضع برفق لترقد في بيت مستدير واحد. للحفاظ على النعومة طويلًا، يجب أولًا التعامل معها بنعومة."},"ICON-0497":{"nm":"رقاقة ظل العيون","de":"نقطة لون واحدة توضع على الجفن تغيّر التعبير بأكمله. اللون النائم في رقاقة صغيرة لا يستيقظ إلا تحت الأضواء، مضيفًا عمقًا إلى النظرة المتجهة نحو المسرح."},"ICON-0498":{"nm":"غطاء فرشاة أحمر الخدود","de":"إذا تلف طرف الشعيرات، ينهار اللون معه. تغطيتها للحفاظ على نسيجها عادة هادئة لمن يريد إبقاء أداة جيدة قريبة منه لأطول فترة."},"ICON-0499":{"nm":"باليت شفاه رفيع","de":"الباليت السميك يشغل الحقيبة كلها. يد تعرف أن خطًا واحدًا رفيعًا كافٍ. اللحظة التي يصبح فيها التقليل هو التحضير الجيد بعينه."},"ICON-0500":{"nm":"واقي الماسكارا","de":"كي لا تتلطخ الرموش المرفوعة خصلة خصلة، يحمي واقٍ صغير برفق انحناءها. ما رُفع بعناية يجب أن يُصان بعناية، هكذا يخبرنا الوقت أمام المرآة."},"ICON-0501":{"nm":"علبة أعواد القطن","de":"بيت صغير يحفظ أعواد القطن البيضاء من التبعثر في كل اتجاه. لمسة تُبقى قريبة دومًا من أجل آخر تعديل أخير. تحضيرات صغيرة تسدّ فجوات مسرح عظيم."},"ICON-0502":{"nm":"عبوة مطاط ملقط الرموش","de":"حين يتصلّب المطاط، يؤلم قرص الرموش ويلسع. الاحتفاظ بقطع احتياطية جاهزة للاستبدال ينبع من رقة تراعي حتى أصغر الآلام."},"ICON-0503":{"nm":"فرشاة الكونسيلر","de":"بطرف شعيرات رفيع، تُمحى الظلال برفق. عمل يجلب النور إلى بقعة لم يصلها الضوء يومًا. يد تضيف نورًا بدل أن تخفي عيبًا تُتمّ العمل بأناقة أكبر."},"ICON-0504":{"nm":"منخل البودرة","de":"إذا نُخل المسحوق الناعم مرة واحدة، يستقر رقيقًا دون تكتّل. ذلك التعب الإضافي من غربلته مرة أخرى. الإخلاص، في النهاية، يظهر في أنامل تخطو خطوة زائدة."},"ICON-0505":{"nm":"مشبك لفّ الغرة","de":"مشبك يلفّ الغرة بشكل دائري ويثبّتها للحظة. وبينما تنتظرين، يستقر الشكل بهدوء في مكانه. الأناقة تزهر حيث تعرفين كيف تنتظرين دون استعجال."},"ICON-0506":{"nm":"ملعقة شمع الشعر","de":"تُغرف كمية الشمع بهذه الملعقة الصغيرة قبل أن تلمس يديك. ضبط النفس في أخذ القدر اللازم بالضبط لا أكثر. يد تعرف كيف تستخدم دون إفراط تصنع أطبع ملمس."},"ICON-0507":{"nm":"حصيرة سند مكواة الشعر","de":"لا يمكن وضع مكواة شعر ملتهبة في أي مكان بلا مبالاة. حصيرة سند واحدة تحمي المكتب واليد معًا. مكان يتعامل مع الحرارة يحتاج دومًا ملاذًا آمنًا."},"ICON-0508":{"nm":"عيّنة زيت الشعر","de":"قطرة واحدة كافية للمعان، فتُحفظ بعناية في زجاجة عيّنة صغيرة تنزلق في ركن الحقيبة. زجاجة صغيرة، لا كبيرة، هي التي تصل إلى اليد أكثر بكثير."},"ICON-0509":{"nm":"مشط تنظيف الفرشاة","de":"يمشّط المشط ببطء الشعر المتشابك بين شعيرات الفرشاة. العناية بالأدوات طقس هادئ بعد انتهاء العمل. فرشاة معتنى بها جيدًا تصوغ ملمس الغد بجمال."},"ICON-0510":{"nm":"بكرة أربطة الشعر","de":"مجرد لفّها حول بكرة يجعلها كلها مرئية بلمحة واحدة. هذه الحزمة الصغيرة الملفوفة بعناية راحة رقيقة تُهدى للصباحات المزدحمة حين كانت الأربطة المطاطية تتدحرج في كل اتجاه."},"ICON-0511":{"nm":"عبوة قفازات الصبغة","de":"قفازات رقيقة تُلبس كي لا تتلطخ اليد التي تضع اللون. رغبة في استقبال ما يلي بيدين نظيفتين حتى بعد انتهاء العمل. الحماية ليست سوى اسم آخر لذلك الاستعداد."},"ICON-0512":{"nm":"كيس شبكة الشعر","de":"كيس صغير يطوي بعناية ويحفظ الشبكة التي تُبقي تسريحة الشعر في مكانها. كلما قلّ حجم الشيء سهُل ضياعه، فلمسة تمنحه بيتًا خاصًا به هي لمسة تستحق الامتنان."},"ICON-0513":{"nm":"قلم تثبيت الشعيرات الطائشة","de":"قلم يضغط برفق على الشعيرات الطائشة ويعيدها إلى نظامها. آخر لمسة بعد انتهاء التصفيف الكبير. الإتمام هو دومًا عمل مداعبة أصغر بقعة."},"ICON-0514":{"nm":"غطاء اختبار العطر","de":"عند اختيار عطر، لا تقرّبيه من أنفك مباشرة. بل ضعي نقطة منه على غطاء صغير ودعيها تنتشر في الهواء ليظهر نسيجها الحقيقي. حتى العطر لا يصدق إلا حين يُشمّ من مسافة."},"ICON-0515":{"nm":"زجاجة العطر بكرة دحرجة","de":"خرزة مستديرة تتدحرج برفق راسمة العطر على المعصم. خلافًا لزجاجات العطر القديمة التي تُنقر وتُدهن، خط واحد ينساب وينتشر. للعطر قصة مختلفة مع كل طريقة يلامس بها الجلد."},"ICON-0516":{"nm":"غطاء رذاذ الجسم","de":"غطاء صغير يحبس عطرًا ينتشر كالضباب. إغلاق وحفظ ما يتبدد ما إن يُفتح. قلب صغير يدّخر قليلًا يجعل ذلك العطر يبقى بجانبك مدة أطول."},"ICON-0517":{"nm":"حلقة مفاتيح كريم اليدين","de":"علّقي حلقة بكريم صغير يُدهن على اليدين وسيرافقك أينما ذهبت. رفيق يتأرجح معلّقًا خارج الحقيبة يصبح تحية رقيقة لأنامل جافة."},"ICON-0518":{"nm":"خطاف كرة الاستحمام","de":"بعد أن تصنع رغوة فوّارة، لا بدّ من تجفيفها جيدًا. الكرة الشبكية المعلّقة على خطاف في زاوية الحمام تنفض قطرات الماء منتظرة صباحًا منعشًا آخر."},"ICON-0519":{"nm":"كيس كرة التدليك","de":"كيس صغير يحفظ الكرة الصلبة التي تُرخي الكتفين المتصلّبين. استراحة قصيرة خلف الكواليس، وقت لمداعبة جسد متيبّس بهدوء. العناية تبدأ دومًا من الذات."},"ICON-0520":{"nm":"علبة لصقات التبريد","de":"علبة تجمع لصقات تبرّد الجسم فور لصقها. في ليلة انتهاء مسرح ملتهب، تغفو داخلها راحة صغيرة تُهدّئ رويدًا رويدًا جسدًا وقلبًا احتدما."},"ICON-0521":{"nm":"قلم زيت الأظافر","de":"اضغطي، افركي، تألّقي. قطرة واحدة تكفي للأنامل الجافة. لا حاجة لأي علاج فخم؛ بريق ناعم ينتشر من طرف قلم صغير يلتفّ بأناقة فوق الأظافر. العناية تبدأ من قطرة صغيرة كهذه."},"ICON-0522":{"nm":"مشبك كيس العطر","de":"عقدة صغيرة تربط العطر على ورقة. في كل مرة تفتحين الدرج، تستقبلك حفنة خافتة قبل أن تلمسه يدك. رقة تبقى قريبة رغم أنها غير مرئية—مشبك واحد يحتضن بهدوء عزاء يوم كامل."},"ICON-0523":{"nm":"صينية عينات الأظافر","de":"مسرح صغير يعرض مسبقًا ألوان الأصابع العشرة. أي درجة تناسب اليوم؟ تجربة أداء هادئة تُقام على الصينية. تلك اللحظة القصيرة من الاختيار مثيرة نوعًا ما، ويوم الأنامل يبدأ من هنا."},"ICON-0524":{"nm":"غطاء مدفع الجلدة","de":"حتى في الدفع رقة. جلدة صغيرة واحدة، بالطرف المستدير، برفق، دون استعجال. اليد المتسرعة تفوّت شيئًا دائمًا، فالترتيب أقرب إلى قلب ينظر ببطء."},"ICON-0525":{"nm":"مبرد الأظافر المصغّر","de":"وجه خشن ووجه ناعم، وجهان في يد واحدة. برد الحواف الخشنة برفق حتى تنعم أمر بسيط، لكن الإتمام يأتي دومًا من لمسات صغيرة كهذه. الكلمة الأخيرة، في النهاية، للنعومة."},"ICON-0526":{"nm":"لوحة ملصقات الأظافر","de":"نجمة، زهرة، قلب—يكفي اختيار الورقة التي تناسب مزاج اليوم ولصقها. على لوحة مصفوفة برسوم صغيرة بحجم الأظافر، يلمع ملصق واحد كتوقيع رقيق يُترك على طرف الإصبع."},"ICON-0527":{"nm":"لوحة تظليل مصباح الجل","de":"غشاء رقيق يحبس الضوء لبرهة. أثناء التصلّب، ترتاح العينان بينما تتصلّب الأنامل وحدها بهدوء. حتى الانتظار يحتاج شريط ظل، وفي وقت غير متعجّل، تكتمل أنامل اليوم."},"ICON-0528":{"nm":"علبة قطع زينة الأظافر","de":"قطع لامعة تغفو في تجويف تلو آخر. أحجار كريمة، لآلئ، غبار نجوم—ترفعين الغطاء بحماسة فتح صندوق مجوهرات بلا بطاقة. أي بريق يوضع على الأظافر؟ تلك اللحظة من الاختيار هي الألمع."},"ICON-0529":{"nm":"عبوة قفازات العناية باليدين","de":"إجازة قصيرة تحظى بها اليدان أثناء نومك. داخل القفازين، تترطّب البشرة الجافة رويدًا طوال الليل. العناية، في النهاية، شيء يحدث في الخفاء، وبحلول الصباح تكون الأنامل أول من يعرف تلك الرقة."},"ICON-0530":{"nm":"زجاجة مزيل الطلاء بمضخة","de":"ضغطة واحدة، بالقدر اللازم بالضبط. رائحة باردة تتشرّبها القطنة وتمحو أمس عن الأظافر بنظافة. حتى للإفراغ إيقاع، فضغطة مضخة واحدة تُخلي بهدوء مكانًا لطلاء جديد."},"ICON-0531":{"nm":"ملقط الأحجار اللامعة","de":"لالتقاط جوهرة أدق من طرف الإصبع، تحتاجين يدًا أدق. طرف الملقط ينقل نقطة واحدة دون ارتعاش؛ الدقة نصيب الأداة بقدر ما هي نصيب القلب. ضوء صغير واحد يجد مكانه."},"ICON-0532":{"nm":"لوحة تخزين الأقراط","de":"كي لا يضيع قرط وحيد في الدرج بعد الآن. أدخلي كل زوج في مكانه، وتصبح لحظة الاختيار في صباح مزدحم أخفّ بكثير. الترتيب لطف صغير يُهدى لذاتك المستقبلية."},"ICON-0533":{"nm":"حلقات قياس الخاتم","de":"حزمة صغيرة من الحلقات تحوّل محيط الإصبع إلى رقم. تجربة كل مقاس تباعًا أشبه بالتعرّف رويدًا على شيء يناسبك تمامًا. مثل ذلك الارتياح حين يكون المقاس مضبوطًا تمامًا."},"ICON-0534":{"nm":"مسمار سوار الساعة","de":"حين يرتخي سوار الساعة، هذا المسمار الصغير الوحيد يشدّ الزمن مجددًا حول المعصم. أن أعمق جزء مخفيّ هو الأطول صمودًا—ساعة طال ارتداؤها تعرف ذلك بصمت."},"ICON-0535":{"nm":"لوحة منع تشابك القلادات","de":"تجاويف مقسّمة كي لا تتشابك السلاسل الرفيعة مع بعضها. صباح خالٍ من التشابك يبدأ من الفواصل الصغيرة التي رُتّبت مسبقًا الليلة الماضية. الراحة، في النهاية، قلب رُتّب قبل أن تصله اليد."},"ICON-0536":{"nm":"مشبك خلفية البروش","de":"كلما كانت الواجهة أبهى، كانت الخلفية أكثر صمتًا. مشبك صغير يسند بثبات البروش المثبّت على طرف الثوب؛ خلف كل بريق ظاهر توجد دومًا يد مجهولة تصمد. مكان أوثق لكونه غير مرئي."},"ICON-0537":{"nm":"كيس النظارة الشمسية","de":"قماش ناعم يلفّ برفق العدسات التي حجبت ضوء الصيف. كيس صغير يحمي رؤية زوج واحد من اصطدامات الحقيبة. القلب الذي يعتزّ بشيء يأتي دومًا كطبقة ناعمة كهذه."},"ICON-0538":{"nm":"مثقب ثقوب الحزام","de":"لخصر ضاق درجة، أو لفصل اتّسع درجة. ثقب واحد إضافي فقط، ويعود الحزام مناسبًا للجسد. أنا الذي يتغيّر دومًا، وضبط ذلك بصمت هو عمل هذه الأداة الصغيرة."},"ICON-0539":{"nm":"مشبك حلقة الوشاح","de":"مشبك يجمع وشاحًا منسدلًا في نقطة واحدة ويثبّته. أناقة كانت تنفلت في الريح تستقر أخيرًا في مكانها. حتى الأناقة تتّكئ أحيانًا على هذا المشبك الصغير، منظّمة يومًا كاد أن يفلت."},"ICON-0540":{"nm":"طقم حلقات التمائم","de":"مجموعة من الحلقات الصغيرة لتعليقها على جانب الحقيبة وصلت كطقم واحد. قلب الاحتفاظ بما تحبينه قريبًا؛ تعليق مزاج اليوم على تميمة واحدة طقس صغير لا تعرفه سواك، ولسبب ما فيه بهجة."},"ICON-0541":{"nm":"علبة مزيل الوبر","de":"حين تظهر كرات الوبر على سترة كأنها شاخت بين ليلة وضحاها، مرّري هذه العلبة عليها بهدوء فتستعيد ملامح جديدة. الطنين الخفيف الذي يزيل البلى مطمئن نوعًا ما. الثوب المحبوب يحيا مرة أخرى بهذه الطريقة."},"ICON-0542":{"nm":"بطاقة عطر الأقمشة","de":"ضعيها في عمق الخزانة وستملأ الأيام بهدوء بالعطر. رسالة مكتوبة بالعطر بدل الحروف—ورقة تُقرأ دون أن تُفتح. في كل صباح تُخرجين فيه ثوبًا، تفوح أولًا رقة كُتبت بالأمس."},"ICON-0543":{"nm":"دبوس مضاد الكهرباء الساكنة","de":"في صباح شتوي يلتصق فيه طرف التنورة بالساقين، دبوس واحد يفكّ ذلك الالتصاق برفق. سلام صغير يهدّئ حتى الاحتكاك غير المرئي—حين يزول انزعاج تافه واحد، يمضي اليوم أكثر سلاسة."},"ICON-0544":{"nm":"فرشاة الملابس المحمولة","de":"قبيل الخروج من الباب، خيط من الغبار استقرّ برفق على الكتف. افتحي الفرشاة المطوية، مرة واحدة، وينظّم الانطباع الأول مجددًا. الإتمام يحدث دومًا عند الباب، والأناقة تكتمل بتلك اللمسة الواحدة."},"ICON-0545":{"nm":"بطاقة كيس الغسيل","de":"احبسي ما لا يجوز أن يختلط في شبكة، وتكتب بطاقة بهدوء أسماءها. حتى الغسيل له مكانه، والمكان يأتي معه علامة صغيرة. نظام يوم سهل التشابك ينمو من هذه البطاقة الصغيرة."},"ICON-0546":{"nm":"قلم مزيل البقع","de":"حتى الأثر الذي تركته قطرة قهوة على قميص ينسحب بهدوء حين تُنقر عليه. قلم لا يخفي الخطأ بل يمحوه بلطف. كل شخص يحتاج فرصة واحدة ليبدأ يومه نظيفًا من جديد."},"ICON-0547":{"nm":"قماش تلميع الأحذية","de":"مسحة واحدة بالقماش ويستعيد الجلد بريقه. كلما طال ارتداء الحذاء، تعمّق اللمعان أكثر. البريق مكافأة الزمن الذي سار معًا—الحذاء ينقش تلك السنوات بصمت على ظهر القدم."},"ICON-0548":{"nm":"غطاء طرف رباط الحذاء الرياضي","de":"غطاء صغير ثُبّت على طرف رباط منفكّ. كي لا تلتفتي بعيدًا قبل خط النهاية، يُختم الطرف بإحكام. رباط مربوط جيدًا يرسل خطوة أبعد—احتراس صغير يصبح شجاعة الركض حتى النهاية."},"ICON-0549":{"nm":"شريحة اسم الشمّاعة","de":"بين شمّاعات متشابهة، هذه الشريحة الصغيرة الوحيدة تُخبرك بهدوء \"مكاني\". دليل صامت يخفّف ارتباك صباح مزدحم؛ حين يقلّ عناء البحث، تصبح بداية اليوم أخفّ أيضًا."},"ICON-0550":{"nm":"علبة ملقط العدسات","de":"أحيانًا تحتاجين طرفًا أدقّ من طرف الإصبع. ملقط يرفع عدسة صغيرة دون ارتعاش ينتظر دوره داخل العلبة. الدقة تكمن دومًا جاهزة بهدوء، نائمة حتى تُستدعى، ثم تستيقظ فورًا."},"ICON-0551":{"nm":"عبوة أقراص القطن المصغّرة","de":"حزمة صغيرة تحمل بالضبط ما يكفي لاستخدام واحد. تقلّص حجم الحقيبة بينما تبقى النعومة كما هي. التقليل من الأخذ لطف أيضًا—يوم خفيف يحلّ في المكان الذي أُفرغ."},"ICON-0552":{"nm":"علبة أوراق امتصاص الزيت","de":"امسحي بهدوء اللمعان المنتشر على الأنف في منتصف النهار بورقة رقيقة واحدة. الأوراق النائمة بصفوف مرتبة داخل العلبة—للحظة سحب واحدة منها، يتوقف أي شخص برهة لينظر بحنان إلى نفسه أمام المرآة."},"ICON-0553":{"nm":"مرآة ومشط قابلان للطي","de":"مطوية تصبح راحة يد، ومفتوحة تصبح مرآة ومشطًا. أداة صغيرة شاملة تتولى إصلاحًا سريعًا من ركن الحقيبة. الأناقة ليست شيئًا فخمًا، بل أقرب إلى قلب يمكنه أن ينفتح في أي مكان للمسة سريعة واحدة."},"ICON-0554":{"nm":"غطاء ماكينة الحلاقة للسفر","de":"يُنيم بأمان النصل الحاد داخل حقيبة السفر. بفضل هذا الغطاء الكليل الشكل لكن المتين، حتى الأصابع المتلمسة في صباح مزدحم لا تُجرح. الاهتمام هو دومًا تغطية خطر بخطوة سابقة."},"ICON-0555":{"nm":"حلقة بلسم الشفاه","de":"درع صغير يتأرجح من حزام الحقيبة. بلا قلق من التدحرج في الجيب وربما الكسر، تبقى الشفاه الجافة دومًا في متناول اليد. الاحتفاظ بشيء قريبًا هو، في النهاية، قلب يضع ما يلزم في أقرب مسافة."},"ICON-0556":{"nm":"حامل معقّم اليدين","de":"اضغطيه بيد واحدة وتسقط حفنة من النظافة. علّقيه عند الباب، على المكتب، في أي مكان، وتقترب عادة تنظيف اليدين بقدر ذلك. العادة الجيدة ليست فخمة، بل تبدأ في متناول اليد."},"ICON-0557":{"nm":"كيس المناديل النحيل","de":"هيكل رشيق يحمل حفنة من المناديل. دون أن ينفخ الجيب، يبقى دومًا جاهزًا بهدوء لزكام مفاجئ أو دموع. ورقة تُمنح لأحدهم بخفة—كلما كان الاستعداد أنحف كان أرقى."},"ICON-0558":{"nm":"زجاجة غسول الفم المصغّرة","de":"في يوم تحتاجين فيه لقاء أحدهم بعد تناول رامن حار، هذه الزجاجة الصغيرة تتولى بهدوء منعشًا سريعًا للفم. رشفة واحدة من الانتعاش تصبح أحيانًا ثقة كبيرة، تجعل تحية متردّدة أخفّ بكثير."},"ICON-0559":{"nm":"شريحة بودرة اللمعان","de":"المسي طرف الإصبع بها وضعيها على الخد، فتنتشر كغبار نجوم يتبعثر تحت الأضواء. أن يلمع خد عادي في لحظة واحدة هو سحر هذه الشريحة الصغيرة الوحيدة. النور يأتي دومًا هكذا، بغبار يعلق على طرف الإصبع."},"ICON-0560":{"nm":"ملصق تخفيف البريق","de":"في مكان يلمع بإفراط حتى يصبح مزعجًا، يخفّض هذا الملصق النور برفق. نزع طبقة واحدة من البهرجة جزء من الزينة أيضًا—الرقة المتبقية في تلك المساحة المُنقّصة تصبح أحيانًا حسًّا آخر بذاته."},"ICON-0561":{"nm":"قلم التقاط الحجارة","de":"حجر صغير علق تحت القدم أثناء السير في الطريق. قلم ينحني عمدًا ليلتقطه. القلب الذي يجمع برفق بطرف الإصبع ما كان يمكن أن يمرّ به مرورًا عابرًا—الرقة تبدأ دومًا بالتوقف."},"ICON-0562":{"nm":"لوحة تخزين الرموش الصناعية","de":"لوحة صغيرة تُرقد الرموش الصناعية بنظام، شعرة تلو شعرة. حتى بعد نزعها، لا يتشوّه انحناؤها الجميل. عزاء التخزين الهادئ المرتّب الذي يقول إن حتى ما يُوضع جانبًا لبرهة يتذكّر مكانه."},"ICON-0563":{"nm":"غطاء قاطع شريط الجفن المزدوج","de":"نصلان يلتقيان ليقطعا عقدة بضربة واحدة. كلما كان القطع أنظف، صارت العقدة التالية أرتّب. من طرف إصبع يُحسن الربط والقطع، تنطلق البداية الجديدة أيضًا بخفة أكبر."},"ICON-0564":{"nm":"شريط خط الوجه","de":"خط واحد على طول الفك، يُلصق بحذر وأنفاس محبوسة. النحت ليس رسم خط لم يكن موجودًا، بل الإشارة إلى مكان جميل أصلًا. لمسة تتبّع بحنان النسيج الذي كان هناك دومًا."},"ICON-0565":{"nm":"بودرة عاكسة للضوء","de":"مسحوق يمتصّ النور بامتلاء ثم يردّه بأناقة. رغم أنه لا يضيء من ذاته، يبعث السطوع بتبعثر الضوء المستلَم إلى شظايا دقيقة. كأنه ينقل رقة استُعيرت إلى شخص آخر، يكبر البريق كلما شُورك أكثر."},"ICON-0566":{"nm":"مروحة تثبيت المكياج","de":"نسمة مروحة تُبقي إطلالة متأنّية متماسكة حتى نهاية اليوم. كي لا تنهار، كي لا تسيل، تُبرّد وتُصلّب بهدوء. كي يبقى وجه عُني به بعناية واضحًا حتى يسدل ستار المسرح."},"ICON-0567":{"nm":"شريحة باليت تصحيح اللون","de":"قطع صغيرة تُهدّئ وتصحّح لونًا مختلًّا، تجويفًا تلو آخر. حتى اللون الذي كان يطفو وحيدًا يتألق أخيرًا حين يوضع بجانبه لون يكمّله. فقط حين يتصافح لون مع لون تصبح لوحة واحدة صافية."},"ICON-0568":{"nm":"عبوة وشاح الرقبة","de":"لفّيه حول رقبتك فيلطف الهواء البارد لغرفة تمرين الفجر كثيرًا. دافئ كلمسة يد جدّة تلفّ رقبة حفيدها. البرد يأتي دومًا أولًا إلى أرقّ الأماكن، فيحتضن مؤخرة العنق أولًا."},"ICON-0569":{"nm":"مغلّف كمّامة العين الساخنة","de":"مغلّف صغير يحفظ كمّامة عين مُسخّنة. لحظة فتح الطية، يتسرّب دفء نعسان ببطء فوق الجفنين. طقس رقيق قبل النوم، يختم يومًا متعبًا لبرهة ثم يطلقه."},"ICON-0570":{"nm":"فلتر الترطيب المحمول","de":"غشاء ترشيح صغير يعيد الرطوبة إلى غرفة جافة تمامًا. من الداخل غير المرئي، يرشّح بصمت ما يعكّر. الرطوبة الملأى في الغرفة صفاء حفظه جهد شخص غير مرئي."},"ICON-0571":{"nm":"علبة تنظيم الفيتامينات","de":"علبة تقسّم حبوب اليوم تجويفًا تجويفًا. تناولها بانتظام هو عهد بالوقوف على المسرح غدًا أيضًا. في كل تجويف صغير، قلب يعتزّ بنفسه مرتّب بدقة."},"ICON-0572":{"nm":"علبة سدادات الأذن للنوم","de":"بيت لسدادات الأذن التي تغلق أصوات العالم لبرهة. حتى السكون يحتاج عناية، فترقد بأناقة داخل العلبة. ليلة نوم عميق هي ما يجعل صوت الغد يستيقظ صافيًا، الراحة تعرف ذلك جيدًا."},"ICON-0573":{"nm":"مشبك المنشفة الباردة","de":"مشبك يعضّ بثبات على الكتف كي لا تنزلق منشفة مبرّدة. في يوم حارّ، خيط واحد من البرودة على مؤخرة العنق يعينك على تحمّل بعد ظهر طويل. حتى البرودة الصغيرة، حين تُمسك في مكانها، تدوم طويلًا."},"ICON-0574":{"nm":"كيس كرة التمدّد","de":"كيس لإعادة الكرة التي أرخت الجسد. أن تُمدَّد إلى أقصاها ثم تُجمع صغيرة مجددًا يشبه الشهيق والزفير. بين الانفراد والجمع، يزداد الجسد والقلب صلابة رويدًا."},"ICON-0575":{"nm":"لفافة رباط الضغط","de":"شريط يلفّ كاحلًا ملتويًا دورة بعد دورة. ليس شدًّا، بل دعمًا هادئًا. كلما كان المكان أكثر إجهادًا، احتاج يدًا تصمد بصمت بجانبه، هكذا تهمس اللفافة وهي تُلَفّ."},"ICON-0576":{"nm":"بطاقة فحص الحالة","de":"بطاقة تُكتب فيها حالتك اليوم بسطر واحد وتُعلَّق. تعليق الجيد والسيئ بصدق شجاعة صغيرة. بدل التظاهر بأنك بخير، اكتبي ذاتك اليوم، وسيقرأ أحدهم ذلك السطر ويعتني بك بهدوء."},"ICON-0577":{"nm":"كبسولة معطّر الأحذية","de":"كبسولة عطر تُوضع داخل الحذاء. عزاء صغير خافت يُهدى لقدمين جابتا المسرح طوال اليوم. أفضل عطر للمكان الذي بذل أكبر جهد—الرقة تصل حتى أطراف الأصابع دون أن تفوت شيئًا."},"ICON-0578":{"nm":"جدول مقاسات النعل الداخلي","de":"جدول يحفر مقاس القدم بوضوح حتى على نعل داخلي. زوج واحد مناسب تمامًا يجعل خطى المسرح خفيفة. مراعاة كل خطوة مختلفة—الملاءمة الجيدة هي، في النهاية، قلب ينظر بعمق إلى الآخر."},"ICON-0579":{"nm":"حلقة مفاتيح ملعقة الحذاء","de":"حلقة مفاتيح بملعقة حذاء صُغّرت إلى حجم راحة اليد. اعتبار صغير يسهّل تلك اللحظة القصيرة من ارتداء الحذاء. القدمان المنطلقتان في الطريق تحملان دومًا، معلّقة برفق بجانبهما، يد أحدهم الرقيقة المساعدة."},"ICON-0580":{"nm":"غطاء غبار الحقيبة","de":"قماش يغطي برفق حقيبة محبوبة من الغبار. حتى أثناء عدم استخدامها، يُنيمها بلطف ويحمي نسيجها. الأشياء التي يبقى القلب متعلقًا بها، رغم قلة لمسها، تحمل عناية هادئة كهذه."},"ICON-0581":{"nm":"دبوس ضبط الحزام","de":"دبوس يشدّ حزامًا مرتخيًا ليناسب الجسد تمامًا. إن ارتخى انزلق عن الكتف، وإن شُدّ ضاق النفَس. في ذلك الضبط الصغير للتوازن المناسب، يجد زي المسرح والقلب راحتهما أخيرًا."},"ICON-0582":{"nm":"قلم تزييت السحّاب","de":"مرّريه مرة واحدة على سحّاب متيبّس فينزلق بسلاسة مجددًا. كم هو منعش صوت شيء محشور ينفكّ فجأة. ما يجعل مكانًا متوقفًا يتدفّق مجددًا هو خيط واحد من الانسيابية."},"ICON-0583":{"nm":"طرف تنظيف الحذاء الرياضي","de":"طرف فرشاة يمسح حذاءً رياضيًا مغبرًّا نقطة بنقطة. خارج المسرح، يمحو بعناية آثار التمرين غير المرئية. النظر إلى مقدمة الحذاء وقد ابيضّت مجددًا يشعرك أنك قد تركض غدًا بقلب جديد."},"ICON-0584":{"nm":"غطاء بخاخ العزل المائي","de":"غطاء عازل للماء يدحرج قطرات المطر إلى كرات صغيرة ويسقطها. طلاء طبقة مسبقًا كي لا يبتلّ شيء رقة تنظر بعيدًا. لأنك تعرفين أن أيام المطر آتية، تسدلين طبقة رقيقة على يوم صافٍ اليوم."},"ICON-0585":{"nm":"قماش حماية الجلد","de":"قماش يُوضع بهدوء فوق الجلد ليمنع التجعّد. يحمي النسيج مثل يد قديمة كانت تلفّ ستارًا مطويًا بورق الهانجي. كلما احتفظت بشيء قريبًا لمدة أطول، ابطئي أكثر—الترويض ليس سوى اسم آخر للوقت المُنفق في العناية."},"ICON-0586":{"nm":"حزام اسم حقيبة السفر","de":"حزام اسم يجعلك تميّزين حقيبتك بلمحة بين حقائب لا تُحصى. بين الأمتعة التي تدور على الحزام الناقل، ترفع يدها بحرف واحد. مهما ابتعد السفر، اسم واحد هو ضمان اللقاء مجددًا."},"ICON-0587":{"nm":"مشبك كيس الضغط","de":"مشبك يضغط أمتعة منتفخة مسطّحة ويُغلقها. ليست مُفرَّغة بقدر ما هي مطوية بعناية. من طرف إصبع يُنظّم شؤون المنزل بترتيب، يصغر الطمع أيضًا، هكذا تخبر الأمتعة المضغوطة بإحكام بصمت."},"ICON-0588":{"nm":"ورقة منظّف السفر","de":"ورقة منظّف تغسل الملابس في حوض الحمام بقطعة واحدة فقط. تشبه حكمة المسافر البعيد الذي كان يغسل ثيابه بيده في أرض غريبة. السفر بخفة مع الحرص على الأناقة، عقلية مسافر عريقة على الطريق."},"ICON-0589":{"nm":"غطاء وسادة الرقبة","de":"غطاء نظيف يُستبدل جديدًا على الوسادة التي أسندت الرقبة. المكان الذي يُتّكأ عليه يجب أن يكون نظيفًا دومًا كي يطمئن القلب. ترك مكان ناعم وصافٍ كي يتّكئ أحدهم بارتياح—الضيافة تبدأ من هناك."},"ICON-0590":{"nm":"حزام ميزان الأمتعة","de":"حزام يرفع الحقيبة عاليًا لتقدير وزنها. قبل الرحيل، تحتضنين وزن الأمتعة مسبقًا بيدك. بين ما تأخذينه وما تتركينه، لحظة توزنين فيها بهدوء حتى ثقل القلب."},"ICON-0591":{"nm":"زوج أكياس الأحذية","de":"زوج من الأكياس يحمل حذاءين جنبًا إلى جنب، يسارًا ويمينًا. ما يسهل ضياعه منفردًا يصبح مطمئنًا حين يقترن. الأشياء التي ترافق بعضها دومًا تملك قوة على أن تحمي بعضها بهدوء."},"ICON-0592":{"nm":"حلقة الحقيبة الإضافية","de":"في يوم تعجز فيه يد واحدة، حلقة صغيرة لتعليق حقيبة للحظة. متّسع احتياطي لأيام فيها أمتعة أكثر مما يمكن حمله. مجرد وجود مكان لتعليقها قليلًا يجعل الكتفين أخفّ كثيرًا."},"ICON-0593":{"nm":"شريحة جدول رحلة السفر","de":"احفري مسار اليوم بوضوح على شريحة واحدة. أين تلتقين وإلى أين تسيرين، خط إرشاد مرسوم مسبقًا لخطى ضعيفة في تحسّس الطريق. طريق يُقطع معًا، إن دُوّن تجويفًا تجويفًا، نادرًا ما يضلّ."},"ICON-0594":{"nm":"غطاء المحوّل متعدد المقابس","de":"غطاء يتلاءم بإحكام حتى مع مقابس بلد غريب. مختلف الشكل، لكنه يتّصل في النهاية كوحدة واحدة. ربط أشياء أتت من أماكن مختلفة—الانسجام يبدأ بهدوء من تحويل صغير واحد."},"ICON-0595":{"nm":"غلاف بطاقة النقل","de":"ورقة شفافة تحمي البطاقة في كل مرة تمسّ فيها البوابة. التنقل اليومي، حتى أثر اللمسات المتكررة حتى البلى، تُغلّف بأناقة. حتى الطريق العادي يصبح ذكرى حين يُعتزّ به، وهذه الطبقة الرقيقة تثبت ذلك."},"ICON-0596":{"nm":"مشبك تذكرة الركوب","de":"مشبك يمسك بأناقة تذكرة سريعة التجعّد. فقدان تذكرة على الطريق يهزّ حتى القلب. كلما كانت الورقة أصغر، أُمسكت بإحكام أكثر—طمأنينة الرحلة تأتي من ذلك التجويف الواحد."},"ICON-0597":{"nm":"شريحة مذكّرة التبديل","de":"شريحة صغيرة كُتب عليها أين تبدّلين وسيلة النقل بسطر واحد. عند كل مفترق مربك، كلمة واحدة دُوّنت مسبقًا تفتح الطريق بوضوح. المذكّرة تلميح رقيق يُهدى بهدوء لذاتك المستقبلية التي قد تضلّ الطريق."},"ICON-0598":{"nm":"بطاقة عبور البوابة","de":"بطاقة عبور تُتعرَّف عليها بهدوء أثناء مرورك من البوابة. حتى الطريق الذي بدا مسدودًا ينفتح رويدًا حين تحملين مؤهّلك الخاص. أن تعبري بثقة يعني التقدّم بخفة إلى التجويف التالي دون تردّد."},"ICON-0599":{"nm":"حافظة إيصالات التاكسي","de":"كل ورقة صغيرة تحمل أثرًا واضحًا لطريق قُطع ذلك اليوم. اجمعي الإيصالات التي كانت تتدحرج في كل اتجاه ورتّبيها معًا بعناية، ويتراكم حتى يوم عادي، ورقة بعد ورقة، ليصبح رحلة حقيقية."},"ICON-0600":{"nm":"شريط عاكس للدراجة","de":"شريط يلتقط الأضواء العابرة على طريق معتم ويلمع بهدوء. رغم أنه لا يضيء من ذاته، يسطع بضوء أحدهم. أن تجعل نفسك مرئيًا هو رجاء رقيق لطريق ليلي بأن تعودي سالمة."},"ICON-0601":{"nm":"غطاء عجلة الحقيبة","de":"السبب في أن حواف حقيبتك تبقى سليمة بعد آلاف الدورات على أحزمة المطار هو هذا الغطاء الصغير الملتف حول العجلات. إنه أول ما يلامس أوعر الطرق - فالعناية الصامتة بأحدهم تكمن دومًا في مكان لا يلحظه أحد."},"ICON-0602":{"nm":"غطاء مسند الرأس","de":"في رحلة حافلة طويلة، تسحب غطاءً فوق مسند الرأس وتتكئ نحو النافذة. عبق الراكب الأخير وتعب الأمس لا يصلان إلى هذا الحد. مكان نظيف تسند إليه رأسك عزاء كبير بشكل مفاجئ على طريق غريب."},"ICON-0603":{"nm":"دبوس موقع السيارة","de":"\"في أي طابق، وأي مكان كانت؟\" من تاه يومًا في موقف سيارات خالٍ يعرف مدى اطمئنان هذا الدبوس. علامة واحدة تُغرَس مكان الذاكرة المتلاشية، تُهيئ طريق العودة سلفًا."},"ICON-0604":{"nm":"حبل حامل مفتاح الغرفة","de":"كيف يختفي مفتاح الغرفة بهذه السهولة؟ اربطه بحبل وعلّقه في معصمك، فلن تنسى أبدًا الغرفة الوحيدة التي تنتظرك الليلة. حتى في مدينة غريبة، طمأنينة صغيرة بأن لك مكانًا معلومًا تتدلى من معصمك."},"ICON-0605":{"nm":"شريحة لافتة الباب","de":"حين تبدأ البروفة، تُعلَّق شريحة على الباب. ممنوع الإزعاج - يعني أن هذا وقت التركيز الخالص. ذلك السكون العميق خلف الكواليس تحرسه بصمت إشارات صغيرة كهذه."},"ICON-0606":{"nm":"حقيبة أدوات الاستحمام","de":"فرشاة أسنان، غسول للوجه، منشفة بحجم الكف. أينما ذهبت، احمل هذه الحقيبة وحدها فتنتظم نهاية يومك وبدايته بأيدٍ مألوفة دائمًا. حفنة صغيرة من العناية المنزلية تجعل فراشًا غريبًا يبدو مألوفًا في لمح البصر."},"ICON-0607":{"nm":"مشبك المنشفة الاحتياطية","de":"بجانب المغسلة، كانت تلك المنشفة الاحتياطية تبقى رطبة دومًا بلا مكان تُعلَّق فيه. أمسكها المشبك وعلّقها، فتجد أخيرًا مكانها. أن تمنح شيئًا مكانًا ليجف فيه - هذا هو حجم اللطف غالبًا."},"ICON-0608":{"nm":"حقيبة موزع الكهرباء","de":"في كل مرة تفتح فيها حقيبتك، كانت الشواحن متشابكة في كتلة واحدة. لُفَّ الموزع كله وضعه بالداخل، فتستقر الأمور في نظام. حين يُحلّ سلك متشابك، تُحلّ معه زاوية صغيرة من القلب قبل الرحيل."},"ICON-0609":{"nm":"ملصق رقم السرير","de":"بطاقة رقم على كل سرير علوي في السكن المشترك. بملصق واحد يخبرك أي مكان لك، تصبح غرفة غريبة جديدة بيتًا بحلول الليل. البداية تكون دائمًا بهذا الصغر."},"ICON-0610":{"nm":"حبل غسيل صغير","de":"علّق طرفيه بين إطاري النافذة فيصبح حبل غسيل. في يوم مشمس، تتمايل بضع جوارب مغسولة باليد، ناعمة وجافة في النسيم. حتى بعيدًا عن الوطن، تجف الحياة اليومية على حبل كهذا."},"ICON-0611":{"nm":"بطاقة تمييز النعال","de":"حين تتكدس النعال عند المدخل، لا يمكن معرفة صاحب كل نعل. علّق بطاقة صغيرة وحتى الحذاء يتعرف على صاحبه. العيش المزدحم بكثرة يحتاج إلى علامات ودودة كهذه."},"ICON-0612":{"nm":"حافظة قسيمة الفطور","de":"حافظة تُدس فيها قسيمة فطورك. في صباح باكر يعتصر جوعًا، تعِد هذه الورقة الواحدة بوعاء حساء يتصاعد منه البخار. يوم السفر يبدأ دومًا ببطء من وجبة دافئة واحدة."},"ICON-0613":{"nm":"شريط عاكس للكاحل","de":"لفّه حول كاحلك فيعكس الضوء في الظلام. في نزهة ليلية، يلوّح بصمت لسيارة قادمة من بعيد قائلًا \"ثمة إنسان هنا\". هكذا يلمع الأمان بتواضع."},"ICON-0614":{"nm":"غطاء المناديل المبللة","de":"غطاء يُثبَّت بإحكام على فوهة عبوة المناديل المبللة. تخرج كل منديلة بسلاسة، ويبقى الباقي رطبًا لا يجف. مهما بدا الأمر تافهًا، فإن ما تمتد إليه يدك كل يوم له دائمًا سبب يستحق."},"ICON-0615":{"nm":"رباط حصيرة النزهة","de":"تُلَفّ الحصيرة دائريًا وتُربط بحبل. ضفة النهر، ظل أزهار الكرز - أينما فُرشت، تصبح تلك البقعة بقعتنا. رباط يحمل معه أرضًا بحجم راحة اليد أينما ذهبت."},"ICON-0616":{"nm":"علبة لاصقات البعوض","de":"علبة تحفظ لاصقات البعوض، ذلك الضروري في ليالي الصيف. الحرص على التحضير قبل أن تبدأ الحكة يكمن كله في هذه الحجيرة الصغيرة. صفوف المسارح الخارجية الخلفية تزداد أمانًا بهذه الاحتياطات الصغيرة دائمًا."},"ICON-0617":{"nm":"خطاف زجاجة نزهة المشي","de":"خطاف يُعلّق زجاجة الماء على حقيبتك حين تخرج للمشي. أن يكون الماء في متناول يدك عند الظمأ يعني أنك تستطيع السير مسافة أبعد. رابط صغير يمنع من يمشي من التوقف."},"ICON-0618":{"nm":"سلة تسوق قابلة للطي","de":"افردها فتصير سلة تسوق، اطوها فتناسب راحة كفك. مناسبة تمامًا لحزمة خضار أحببتها وأنت تتجول في أزقة السوق. حكمة إدارة المنزل نمت دومًا نحو أقل حجم، ونحو حمل أخف."},"ICON-0619":{"nm":"مشبك واقي الرياح","de":"في يوم عاصف، يمسك طرف الخيمة المتطاير ويثبته بإحكام. مشبك واحد يضغط على ما ظل يهتز فوق مكانه. أكثر ما يمكن الاعتماد عليه في الهواء الطلق هو، على غير توقع، شيء بحجم إصبع."},"ICON-0620":{"nm":"دبوس تظليل الشمس","de":"دبوس يُغرَس في النافذة ليحجب أشعة الشمس بميل. حين يشتد ضوء الظهيرة، يُسدل حفنة من الظل بهدوء. تخفيف الوهج قد يكون، لأحدهم، أرق لمسة على الإطلاق."},"ICON-0621":{"nm":"غطاء صافرة الطوارئ","de":"غطاء يغطي فوهة صافرة الطوارئ. يمنع الغبار كي تصدح دفعة واحدة عند الحاجة الحقيقية. بعض الأشياء تمنح راحة البال لمجرد وجودها قريبًا، حتى وأنت تأمل ألا تحتاج إليها أبدًا."},"ICON-0622":{"nm":"غطاء رأس المظلة","de":"غطاء صغير يُلبَس على طرف المظلة. حين تُطمَس حدته الحادة، لا يتأذى من بجانبك ولا حقيبتك. آداب أيام المطر تبدأ بصمت من تغليف طرف حاد ليصبح ناعمًا ودائريًا."},"ICON-0623":{"nm":"كيس حفظ معطف المطر","de":"كيس يُلَفّ فيه معطف المطر المطوي ويُحفظ بعيدًا. ينتظر بهدوء في زاوية الحقيبة حتى الزخة القادمة. الاستعداد هو، في النهاية، شذرة من القلب تُعِدّ ما قد لا تحتاج إليه أبدًا."},"ICON-0624":{"nm":"أغطية أحذية مضادة للماء","de":"البسها فوق حذائك ولن يتسرب المطر بعد الآن. حتى في طريق المدرسة وسط أمطار الموسم، تبقى الجوارب جافة. يوم لا تبتل فيه أطراف أصابعك يغيّر مزاجك أكثر بكثير مما تتوقع."},"ICON-0625":{"nm":"وسادة مانعة للانزلاق على الثلج","de":"ألصقها بنعل حذائك فتصبح الطرق المتجمدة أقل رعبًا بكثير. في ذلك الشتاء الذي عبرت فيه الأزقة المغطاة بالثلج بخطى مسرعة، كانت هذه الوسادة تمسك بك بثبات كي لا تنزلق. قوة موثوقة تختبئ تحت خطوات حذرة."},"ICON-0626":{"nm":"طوق تبريد الرقبة","de":"لفّه حول رقبتك فيسري برد هادئ. حكمة الصيف في أن تحمل خيطًا من البرودة على قفا رقبتك حتى في أشد أيام الحر لهيبًا. حتى طريقة تحمل الحرارة تزداد رقة قليلًا كل عام."},"ICON-0627":{"nm":"حامل المروحة المحمولة","de":"حامل يُقيم عليه المروحة اليدوية. حين تتحرر يداك، تستطيع تقليب الصفحات والكتابة بدلًا من التهوية. نسمة صغيرة تجعل صيفًا طويلًا أمام المكتب محتملًا بالكاد."},"ICON-0628":{"nm":"حقيبة كمادة التدفئة","de":"حقيبة تُحمَل فيها كمادة التدفئة. حين تدسّ أصابعك المتجمدة في جيبك لتدفئتها، تجد دفئًا صغيرًا ينتظرك هناك أولًا. تُحتمَل خرجات الشتاء بهذه الحفنة الواحدة من الدفء."},"ICON-0629":{"nm":"علبة واقيات الأذن الشتوية","de":"علبة تُحفظ فيها واقيات الأذن. مكان تُصان فيه بعناية حتى يحل البرد القادم. الأشياء التي لا نستطيع التخلي عنها مع تغير الفصول تحمل إيمانًا هادئًا بشتاء سنلتقي به مجددًا."},"ICON-0630":{"nm":"شريحة قياس الأشعة فوق البنفسجية","de":"تُقرَّب برفق من الضوء فتخبرك بلون شدة الأشعة فوق البنفسجية اليوم. تجعل شدة ضوء الشمس، غير المرئية، مرئية أخيرًا. كأنك تُثبِّت عينًا صغيرة لقراءة السماء على معصمك بهدوء."},"ICON-0631":{"nm":"لوحة أختام الحارة","de":"لوحة تملؤها بأختام تجمعها من كل متجر عند مدخل الحارة. مع كل خانة تُختم، تُرسَم خريطة الحي بوضوح في القلب. ذكريات جُمعت بالمشي على قدمين تبقى كآثار حبر كهذه."},"ICON-0632":{"nm":"لوحة دبابيس الأماكن المزارة","de":"لوحة صغيرة تغرس فيها دبوسًا لكل مكان زرته. مع تزايد النقاط واحدة تلو أخرى، يتسع محيط عالمك معها. كل دبوس أثر يهمس بهدوء \"كنتُ هنا\"."},"ICON-0633":{"nm":"حبل بوصلة صغيرة","de":"مهما طال تيهك، يبقى الشمال وحده ثابتًا في مكانه دومًا. البوصلة الصغيرة المعلقة عند صدرك، حين لا تعرف إلى أين تتجه، تهدّئ أولًا قلبك المتردد بلطف."},"ICON-0634":{"nm":"حلقة مذكرات الاتجاهات","de":"أوراق دوّنتها وأنت تبحث عن الطريق، مثقوبة في حلقة. \"انعطف يسارًا عند صندوق البريد الأحمر.\" خط يد أحدهم المتعثر يرشد بهدوء زقاقًا غريبًا. الطريق المتروك على الورق نادرًا ما يبهت."},"ICON-0635":{"nm":"دفتر ملصقات المعالم","de":"دفتر تملؤه بملصق واحد تشتريه من كل وجهة. الأبراج والجسور والأسوار القديمة تتراكم صفحة بعد صفحة. جمع الأماكن التي زرتها يشبه لمس الزمن الذي مررت به بأطراف أصابعك مجددًا."},"ICON-0636":{"nm":"شريحة تبديل المترو","de":"شريحة تقبض عليها بإحكام في محطة التبديل حيث تتفرع الخطوط. تلك اللحظة القصيرة لاختيار أين تبدّل قد تغيّر أحيانًا اتجاه اليوم كله. بخيار صغير واحد، تُظهِر المدينة وجهًا مختلفًا."},"ICON-0637":{"nm":"بطاقة استكشاف الحي","de":"\"اليوم، حتى مخبز هذا الحي.\" اسحب بطاقة واحدة فتتحدد وجهة اليوم. حتى الزقاق المألوف الذي تعبره دائمًا يصبح طريقًا جديدًا بمجرد ظهور مهمة. بطاقة تذكّرك بأن المغامرة ليست بعيدة."},"ICON-0638":{"nm":"حافظة بطاقات المتاجر","de":"حافظة تُدَسّ فيها بطاقات الأعمال التي حصلت عليها من متاجرك المفضلة. المكان اللذيذ، صاحب المحل اللطيف - تتجمع خانة تلو أخرى. الألفة مع مدينة تبدأ من أوراق صغيرة كهذه."},"ICON-0639":{"nm":"لوحة شارات إتمام المسار","de":"لوحة يُملأ فيها شارة واحدة عند إنهاء مسار المشي كاملًا. جزاء إكمال الشوط يبقى في يدك كقطعة معدنية دائرية. ذلك الفخر الذي لا يعرفه إلا من مشى حتى النهاية يُنقَش هنا بوضوح."},"ICON-0640":{"nm":"قفل حقيبة مع سلسلة مفاتيح","de":"قفل صغير مزدوج مع سلسلة مفاتيح يُثبَّت على سحاب الحقيبة. يحرس الأشياء الثمينة بإحكام بينما يتمايل رنانًا عند طرف الحقيبة. رفيق ذكي للمسافر، يجمع بين الأمان والزينة في جسد واحد."},"ICON-0641":{"nm":"بطاقة منع الفقدان","de":"يتقوقع في أعمق ظلام الحقيبة، وفي اللحظة التي يستسلم فيها الجميع، يومض بخفوت. \"أنا هنا.\" صوت شيء ظننته ضائعًا يعود إلى طرف إصبعك. مهما صغر، يبقى إلى جانب صاحبه حتى النهاية."},"ICON-0642":{"nm":"حلقة قفل السحاب","de":"طقة، وبمجرد إغلاقه، لا تستطيع يد عادية فتحه. عزيمة تصدّ الظفر المتعجل والإصبع الماكرة المتسللة على حد سواء. الأمان يذكّرك، بثقله الصلب، أنه لا بأس أن يكون قاسيًا قليلًا أحيانًا."},"ICON-0643":{"nm":"شريط جرس مانع السرقة","de":"حارس غير مرئي يمنع البضائع فوق الرف من الخروج قبل الدفع. حين تلامسها يد أمينة، يظل صامتًا حتى النهاية. الجرس الذي لا يرن هو أهدأ الأجراس على الإطلاق."},"ICON-0644":{"nm":"ملصق إخفاء بيانات التواصل","de":"يُلقي بهدوء طبقة فوق الاسم والرقم المكتوبين على صندوق الطرد. من يعيش هنا وإلى أين يذهب أمر يخص المستلم وحده. أن تُخفي بعناية نوع من اللطف أيضًا، هكذا يحرس مكانه بصمت."},"ICON-0645":{"nm":"شريط غلاف جواز السفر","de":"مطار غريب، عشرات الأغلفة المتطابقة تدور على السير عند الفجر. من بينها يلوّح بلون لا يعرفه سواك قائلًا \"من هنا\". معطف صغير يُلبَس للوثيقة المنطلقة في رحلة بعيدة. حتى وإن اهترأ الغلاف، تبقى الرحلة مشرقة."},"ICON-0646":{"nm":"حقيبة تصنيف النقود","de":"الأوراق النقدية يسارًا، المعدنية يمينًا، ومال الطوارئ في خانة لا يعرفها أحد. أول مكان تتلمسه اليد العائدة من السوق. حتى يوم متشابك يجد داخلها نظامه، مرتبًا ورنانًا."},"ICON-0647":{"nm":"ملصق ختم الأمان","de":"انزعه مرة واحدة ويبقى الأثر. ضمير صغير أمين لا يستطيع أبدًا إخفاء \"لقد فتحه أحدهم\". تحت كل صندوق وصل مختومًا وسليمًا يكمن صمت هذا الصديق الثابت."},"ICON-0648":{"nm":"شريحة اتصال الطوارئ","de":"جيب طفل تائه، داخل حقيبة الحاسوب المحمول، طرف طوق كلب. حتى حين لا تستطيع اللحظة الكلام، تنادي بالرقم بوضوح نيابة عنها. شريحة صغيرة واحدة تحمل بالكامل \"أعيدوني إلى البيت\"."},"ICON-0649":{"nm":"غطاء ريموت عصا السيلفي","de":"صور جماعية كان أحدهم دومًا يُقطَع منها لقصر الذراع. الآن، بلمسة زر واحدة عند الطرف، تدخل العائلة كلها في إطار واحد. في تلك اللحظة التي يبتسم فيها الجميع، أضغط الغالق بهدوء وأقفز إلى الداخل."},"ICON-0650":{"nm":"رباط حقيبة العدسات","de":"رباط يحتضن العدسات الاحتياطية كي لا تصطدم داخل الحقيبة. لأن قطعة زجاج واحدة هي منظر طبيعي بأكمله، لا تهزّ ذلك الثقل بإهمال. حرص المصوّر مربوط في كل عقدة."},"ICON-0651":{"nm":"حلقة علبة الفلاتر","de":"ورقة رقيقة واحدة تحوّل السماء ذاتها إلى ضوء مختلف. مكان يُحفَظ فيه ذلك السحر الصغير مرتبًا في عش دائري. في كل مرة تُفتح فيها العلبة، ترتجف أطراف أصابعك للحظة - أي غروب سألتقط اليوم؟"},"ICON-0652":{"nm":"حقيبة الحامل الثلاثي","de":"مطوي بحجم شبر، ومفرود بثلاث أرجل ثابتة لا تهتز. تلفّ برفق ذلك الرفيق الذي سيمسك المشهد بدلًا من يديك المرتجفتين. كلما ثقل العتاد، استحق أن يستلقي على قماش أنعم."},"ICON-0653":{"nm":"رقعة حزام الكاميرا","de":"تمشي طوال اليوم فتأتي اللحظة التي تثقل فيها الكاميرا كتفك. عندها تتقاسم رقعة واحدة ذلك الثقل بهدوء. عزاء صغير وطري يُوضَع على كتف تمشي بعيدًا من أجل لقطة واحدة جيدة."},"ICON-0654":{"nm":"بطاقة تصنيف بطاقات الذاكرة","de":"ليال تختلط فيها مئات الذكريات على أي بطاقة نامت. علامات ملونة ترسم الطريق. رحلة الربيع بالأزرق، أول عرض بالأصفر. أمينة مكتبة صغيرة ولطيفة تمنح حتى الذكريات رفوفها الخاصة."},"ICON-0655":{"nm":"بكرة كابل الشحن","de":"قبل أن تقيم الكابلات عرض عُقَد داخل الحقيبة، تُلَفّ دائريًا وتُنام بترتيب. رتّب سلكًا واحدًا، وينحلّ معه بشكل ما خيط من القلب. المنظر الملفوف يبعث السكينة لمجرد النظر إليه."},"ICON-0656":{"nm":"ملصق نسخ احتياطي للصور","de":"\"هذه الصور، هل نسختها احتياطيًا؟\" مذكرة صغيرة تجيب سلفًا على ذلك القلق الذي يعتصرك في وقت متأخر من الليل. كلما كانت اللحظة أثمن، وجب أن تعيش في مكانين أو أكثر، هكذا يكتب الملصق بوضوح."},"ICON-0657":{"nm":"لوحة إطار التكوين","de":"انظر إلى العالم عبر نافذة مربعة فترى فورًا ما تُدرجه وما تتركه خارجًا. الصورة الجيدة ليست في الإضافة بل في الحذف الجيد - الإطار الفارغ يُعلّم ذلك أولًا."},"ICON-0658":{"nm":"دلاية محفظة العملات","de":"تتدلى عند طرف الحقيبة حاملة بضع عملات. الخزانة الصغيرة التي تُفتح أولًا أمام آلة البيع، أو كشك الأسماك المشوية المتصاعد بخاره. رنين قعقعتها هو المؤثر الصوتي للسعادة الصغيرة."},"ICON-0659":{"nm":"عمود جمع الإيصالات","de":"أوراق كدت ترميها تُغرَز واحدة تلو أخرى. ما أكلته وما اشتريته اليوم - الإيصال يومية أكثر صدقًا من أي دفتر حسابات. اجمع إيصالات شهر كامل فتصبح سجلًا حياتيًا سميكًا نوعًا ما."},"ICON-0660":{"nm":"بطاقة سلة السوق","de":"تتعلق بمعصم يتجه للتسوق وتجول معه أزقة السوق. قالب توفو واحد، حزمة بصل أخضر، وحتى اللطف الذي يُضاف مجانًا. تحمل كل ذلك الثقل دون تذمر. رفيق يفرح بالامتلاء أكثر من الإفراغ."},"ICON-0661":{"nm":"لوحة مغناطيس تذكارية","de":"اختر واحدة من كل وجهة وألصقها على الثلاجة، فيصبح المطبخ خريطة عالم صغيرة. المدن التي زرتها تتدلى جنبًا إلى جنب، هامسة \"لنذهب مجددًا\". حتى الصفيحة العادية تملك قوة الاحتفاظ بالذكريات."},"ICON-0662":{"nm":"دفتر أختام المناطق","de":"ختم واحد لكل صفحة، والأزقة التي مشيتها تحيا من جديد بالحبر. الآثار الحمراء المجموعة من التجوال في كل أنحاء البلاد هي خريطة خطواتك. كلما قلّت الخانات الفارغة، لوّحت الرحلة القادمة بهدوء."},"ICON-0663":{"nm":"بكرة رباط التغليف","de":"صبر طويل طويل ينحلّ بلا نهاية لربط صندوق هدية واحد. لا يمنح عقدة أنيقة إلا لليد التي تعرف متى تقصّ. ملفوفًا، ينتظر بهدوء دوره القادم."},"ICON-0664":{"nm":"كيس توسيد الهدايا","de":"يحتضن قلبًا قابلًا للكسر في عناق طري. حتى داخل شاحنة توصيل تهتز، يصمد وثيرًا قائلًا \"لا بأس، أنا أسندك\". يحرس سلفًا حتى ابتسامة من سيفتح الصندوق المشرقة."},"ICON-0665":{"nm":"ملصق إخفاء بطاقة السعر","de":"كذبة بيضاء لطيفة تغطي بهدوء سعر هدية ما. \"لست بحاجة لمعرفة الثمن، خذ فقط القلب\" تقول، وهي تستقر برفق فوق البطاقة. ليست إخفاءً، بل هي جعل ذلك القلب يتألق أكثر."},"ICON-0666":{"nm":"شريحة عربة تسوق صغيرة","de":"لا يمكنك دفع عربة حقيقية، لكن هذا الرفيق الصغير المتدلي من طرف إصبعك يحمل كل حماس نزهة إلى المتجر. مهما صغر، فإن خفقان \"ماذا أشتري اليوم؟\" لا يقلّ وزنًا عن الحقيقي."},"ICON-0667":{"nm":"مشبك حذاء متوهج","de":"بريق عند طرف حذاء رياضي خرج في نزهة ليلية، يرسل لسيارة عابرة إشارة \"ثمة إنسان هنا\". أول ضوء صغير يستقبلك في زقاق مظلم. الأمان يبدأ دائمًا بهدوء من أطراف الأصابع."},"ICON-0668":{"nm":"غطاء مصباح يدوي صغير","de":"البسه فوق رأس المصباح اليدوي فينتشر الضوء أبعد وأنعم. ساحر صغير يرسم حشدًا من النجوم على سقف خيمة مظلم. في الليالي التي يكون فيها الظلام مخيفًا قليلًا، لا رفيق أفضل منه."},"ICON-0669":{"nm":"زر إشعار العودة الآمنة","de":"اضغط عليه فتطير جملة \"وصلت بسلام\" إلى عائلة بعيدة. بدلًا من صوت باب المدخل في وقت متأخر، يوصل زر صغير واحد الأخبار. يخلد أحدهم إلى النوم منتظرًا هذه الإشارة."},"ICON-0670":{"nm":"بكرة ملصقات عاكسة","de":"اقصص مربعًا وألصقه على حقيبة، أو دراجة، أو مظلة، فيصبح الطريق الليلي أقل خطورة بكثير. نوّام يستيقظ متألقًا في اللحظة التي يلتقي فيها بضوء مصباح أمامي. ملفوفًا، ينتظر الظلام القادم."},"ICON-0671":{"nm":"بطاقة تاكسي الطوارئ","de":"ضعها في خانة المحفظة فتصبح حتى المحطة الخالية في وقت متأخر من الليل أقل إرباكًا. رقم واحد، وسطر عنوان، مكتوبان كوعد: \"سأوصلك إلى البيت\". من كان يظن أن كلمة \"طوارئ\" يمكن أن تكون بهذا الاطمئنان."},"ICON-0672":{"nm":"شريط خريطة الطريق الليلي","de":"تمشي الطرق شحيحة الإنارة وهو ملفوف حول معصمك. أي زقاق مضيء وأين يحلّ الظلام - يهمس لك بالطريق المختصر الذي لا يعرفه إلا الليل. شريط يربط نفسه إلى جانبك كي لا تفقد الاتجاه في الظلام."},"ICON-0673":{"nm":"حقيبة جرس الأمان","de":"اسحبه في حالة طارئة فيصرخ بصوت عالٍ يفاجئ الزقاق كله. في بقية الأوقات يختبئ بهدوء داخل الحقيبة، مدّخرًا صوته للحظة واحدة فقط. أعلى صرخة، محفوظة في أصغر حقيبة."},"ICON-0674":{"nm":"سلسلة مفاتيح إضاءة الباب","de":"وداعًا لليالي التلمس بحثًا عن ثقب المفتاح في نهاية ممر مظلم. معلقة عند الباب، تستقبل اليد العائدة بضوء دائري. \"أحسنت، لقد وصلت\" تقول سلسلة المفاتيح مرحبةً أولًا."},"ICON-0675":{"nm":"مذكرة العودة إلى السكن","de":"\"خذ مظلتك، أطفئ الأنوار قبل الخروج.\" تنبيه قصير على الثلاجة يحرس الغرفة الخالية. ورقة صغيرة لمن سيعود. اللطف الكامن في ورقة واحدة يرافقك بهدوء حتى الباب."},"ICON-0676":{"nm":"مشط ترتيب الكابلات","de":"يمشّط الأسلاك المتشابكة برفق مرتبة كما تُمشَّط الشعر. غابة الكابلات خلف المكتب تصبح أنيقة ببضع تسريحات. ليس الشعر وحده ما يتشابك، هكذا يذكّرك المشط بهدوء."},"ICON-0677":{"nm":"فاصل حامل الأقلام","de":"القلم الرصاص هنا، القلم الفسفوري هناك، المقص في الخانة الأخيرة. يقسّم قرية صغيرة داخل كوب واحد ويمنح كل قلم مكانه. حين توجد الخانات، لا تتيه اليد بعد الآن. بداية نظام صغير فوق المكتب."},"ICON-0678":{"nm":"مشبك مذكرات الشاشة","de":"يتعلق بجانب الشاشة ويدفع \"مهام اليوم\" مباشرة إلى مستوى النظر. لوحة تنبيه صغيرة تُرى مواجهة، بلا فرصة للنسيان. مشبك واحد يمسك بهدوء بقلب يحاول دائمًا التسويف."},"ICON-0679":{"nm":"صينية تصنيف الأدراج","de":"مشابك ومطاطات، دبابيس ومماحٍ. يمنح كل قبيلة صغيرة داخل الدرج غرفتها الخاصة. حين تمتد اليد إلى خانات مقسمة، يتقلص وقت البحث وتخف زاوية من القلب."},"ICON-0680":{"nm":"أنبوب فرشاة الغبار","de":"ذرة غبار واحدة فوق العدسة تصبح بقعة عملاقة داخل الصورة. لذا تنتظر الفرشاة دائمًا داخل أنبوبها، جاهزة ونقية. طرف إصبع مجتهد يحافظ على نظافة لا يلحظها أحد."},"ICON-0681":{"nm":"زاوية سجادة المكتب","de":"شبر من النعومة يُفرَش في زاوية المكتب. لا ينزلق القلم، وبدلًا من الزجاج البارد، تسند نسجة دافئة معصمك. أرضية ودودة تمنح مكانها أولًا كي لا يرتجف خط الليل الطويل."},"ICON-0682":{"nm":"حامل سلك الفأرة","de":"حين يتشابك السلك، يتشابك القلب في مكان ما أيضًا. لمسة تمسك خيطًا نشازًا سلفًا وتُرقده مرتبًا. بالكاد تُلحَظ، لكنها ترتب بهدوء نسجة المكتب - أناقة صغيرة مجتهدة."},"ICON-0683":{"nm":"حامل قاعدة الشحن","de":"انصب جهازًا كان مستلقيًا بميل، فتلتقي الشاشة عينيك أخيرًا. حتى وقت الانتظار أثناء الشحن يصبح وقتًا مرتبًا. أن تسند شيئًا يعني أن تمنح حتى شيئًا مستريحًا مؤقتًا وضعيته اللائقة."},"ICON-0684":{"nm":"ملصق سلة نفايات صغيرة","de":"حتى أصغر سلة تحمل اسمها. سطر واحد \"ارمِ هنا\" يستدعي نظامًا هادئًا فوق مكتب فوضوي. الملصق هو، في النهاية، تحية صغيرة تخبر الشيء: نفعك هنا."},"ICON-0685":{"nm":"دبوس لوحة الفواصل","de":"يضغط ورقة واحدة بثبات فوق اللوحة. إيداع شعور لا تريد نسيانه إلى الجدار مؤقتًا. عزم اليوم المتدلي عند طرف الدبوس يتمايل قليلًا مع النسيم، يمسك بك في كل مرة تمر فيها."},"ICON-0686":{"nm":"شريحة إطار الملصق","de":"حد مربع واحد يحوّل كتابة عادية إلى جملة واحدة واضحة. شريحة تلفّ وقارًا أنيقًا حول مذكرات سهلة التبعثر. ليست حبسًا، بل احتضان الكلمات المهمة كي لا تضيع."},"ICON-0687":{"nm":"مقبض درج شفاف","de":"ضع مقبضًا على درج شفاف فتستطيع رؤية ما بداخله دون فتحه بإهمال. مسافة بحجم شبر - مرئية لكن غير مُقتربة منها. حتى الشفافية تحتاج إلى أدب، هكذا يهمس الدرج."},"ICON-0688":{"nm":"مشبك قفل الغطاء","de":"اتركه مفتوحًا فتهرب الرائحة واللون بهدوء. بملقط صغير واحد يعضّ الغطاء بإحكام، يبقى لون الأمس كاملًا حتى الغد. الإغلاق هو، في الواقع، عمل حماية ما تعتزّ به."},"ICON-0689":{"nm":"حامل مادة مانعة للرطوبة","de":"حارس صغير يكره الرطوبة ويحرس موقعه بصمت. أن يبقى الهواء الجاف قريبًا هو الشرط الأول للحفظ الطويل، هكذا تذكّرك هذه الحافظة الأنيقة بهدوء. هكذا يُصان الجفاف."},"ICON-0690":{"nm":"بطاقة سلة التنظيم","de":"بطاقة اسم صغيرة على كل سلة. حدد أي خانة تعيش فيها ماذا، فيتحول وقت البحث مباشرة إلى وقت راحة. الترتيب مذكرة لطيفة تُسلَّم سلفًا لذاتك المستقبلية."},"ICON-0691":{"nm":"لوحة فاصل صغيرة","de":"فاصل صغير يقيم بسرعة غرفة وثيرة صغيرة فوق المكتب. بهذه اللوحة الواحدة، تظهر زاوية هادئة تدير ظهرها قليلًا للعالم. مكان دافئ خاص بك تمامًا، مهيأ ليحلّ فيه التركيز."},"ICON-0692":{"nm":"حامل أكياس التخزين","de":"حامل يسند بهدوء ظهور الأكياس التي كانت تتساقط باستمرار. مجرد وقوفها مصفوفة يجعل الاختيار أسهل بكثير. أن تُقيم الأشياء منتصبة هو اعتناء مسبق باللمسة القادمة."},"ICON-0693":{"nm":"شريحة تحديد الخانة الفارغة","de":"شريحة تشير عمدًا إلى الفراغ. ترك مكان لِيُملَأ هو أيضًا خطة قائمة بذاتها. الخانة الفارغة ليست كسلًا، بل هامش بحجم شبر تُرك مفتوحًا بأدب لشيء سيصل قريبًا."},"ICON-0694":{"nm":"غطاء فرشاة الأسنان","de":"تصبح أكثر حرصًا تجاه الفرشاة التي تلامس فمك. قبعة صغيرة تصدّ حتى ذرة غبار واحدة. الاعتناء بنظافة غير مرئية هو بالضبط ذلك الحرص الصغير الذي يفتح كل صباح منعشًا."},"ICON-0695":{"nm":"شبكة حامل الصابون","de":"شبكة ترفع الصابون برفق كي لا يذوب وهو غارق في الماء. المبدأ القائل بأن تصريف الماء يبقيه أطول - تثبته بصمت كل يوم من أخفض وأصغر زاوية في الحمّام."},"ICON-0696":{"nm":"مشبك مضخة الشامبو","de":"يمسك برفق رأس المضخة كي تخرج بضغطة واحدة الكمية المناسبة تمامًا فقط. عادة الاستخدام المقتصد أساس إدارة منزل تدوم طويلًا. مشبك صغير واحد يُقيّد الإسراف بلطف."},"ICON-0697":{"nm":"غطاء تعليق الحلاقة","de":"للأشياء الحادة بيت صغير خاص بها. أدخل الحلاقة في الغطاء وعلّقها، فتنساب الرطوبة والخطر معًا. أن تتعامل مع الحدة بحذر هو أيضًا، في النهاية، طريقة للاعتناء بنفسك."},"ICON-0698":{"nm":"حلقة منشفة الاستحمام","de":"منشفة ممدودة تشكّل حلقة تصل إلى الظهر الذي لا تطاله يدك. على طول تلك النسجة الواحدة التي تنزلق عليها الرغوة، ينتشر دفء ودود يدلّك ظهرك بنفسك في أرجاء الحمّام كله."},"ICON-0699":{"nm":"عبوة مصفاة البالوعة","de":"شبكة صغيرة واحدة تدع الماء يمرّ وتمسك الفتات. في مكان لا يراه أحد، تمنع الانسداد بصمت. الأشياء العاملة في أخفض مكان تحافظ على تدفق البيت، هكذا تخبرنا البالوعة بلا كلمة."},"ICON-0700":{"nm":"لوحة خطاف ماص","de":"يصنع مكانًا جديدًا على الجدار دون دقّ مسمار واحد. اضغط لتلصقه، وانزعه، ولن يبقى أثر البتة. فن البقاء لفترة والمغادرة دون ترك أثر - القرص الماص يعرف جيدًا هذا الأدب الخفيف."},"ICON-0701":{"nm":"وسادة شبشب الحمام","de":"زوج مرتّب بعناية أمام العتبة، حيث تمتد رعاية البيت الذي تُخلع فيه الأحذية بلطفٍ حتى باب الحمام. ترحيبٌ صغير يُدفئ أطراف الأصابع الباردة، وبطاقة الاسم تُحدّد مكانه بهدوء."},"ICON-0702":{"nm":"كوب مضمضة صغير","de":"كوبٌ صغيرٌ مستديرٌ يحمل جرعة تنظيف الأسنان. في لحظة المضمضة القصيرة يستقبل بهدوء بداية اليوم ونهايته. ليس فاخراً، لكنه رفيقٌ يوميٌّ دائم - فالبساطة هي أطول أدوات المنزل عمراً."},"ICON-0703":{"nm":"غلاف منفضة الغبار","de":"غلافٌ يُكسى به ريش فرشاةٍ تجمع الغبار كأنها تُلاطفه بلمسةٍ رقيقة. كطائرٍ يطوي جناحيه بعنايةٍ حين لا يحلّق، فالأداة التي تعرف أين ترتاح تبقى إلى جانبك طويلاً."},"ICON-0704":{"nm":"عبوة تعبئة رول إزالة الوبر","de":"تُقشّر طبقةً واحدة فيظهر تحتها وجهٌ جديدٌ نقيّ. صفحاتٌ لزجة من الداخل تجمع الوبر والشعر. وفي هذه العبوة المستديرة التي تُملأ من جديد كلما فرغت، تلتفّ فضيلة التكرار الدؤوب."},"ICON-0705":{"nm":"مشبك الممسحة","de":"مشبكٌ يُمسك الممسحة بإحكامٍ بدلاً من يدك. يضع شبراً من المسافة بين الأرض الباردة وأصابعك. مقبضٌ واحدٌ يتحمّل العمل الشاق نيابةً عنك، فيجعل التنظيف الشاقّ أخفّ بكثير."},"ICON-0706":{"nm":"غطاء فرشاة الزوايا","de":"فرشاةٌ رفيعةٌ تتسلّل إلى أضيق الشقوق، وقبعةٌ صغيرة تحمي طرفها الرقيق. قلبٌ واحدٌ يعتني حتى بالزوايا التي لا تبلغها اليد. من ينظّف ما لا يُرى، يوسّع حضن البيت شبراً إضافياً."},"ICON-0707":{"nm":"حلقة وسم زجاجة الرش","de":"بطاقة اسمٍ صغيرة تستقرّ برفقٍ على كتف زجاجة الرش. تُخبرك بسطرٍ واحدٍ واضح إن كان ما بداخلها ماءً صافياً أو منظّفاً. ملصقٌ يمحو الالتباس مقدّماً، عادةٌ عريقة لمن تُدير البيت بحزم."},"ICON-0708":{"nm":"شريط تعبئة رول المناديل","de":"شريطٌ يُثبّت لفافةً جديدة في المكان الفارغ ويربطها بإحكام. إنه أبسط لمسةٍ تُعيد وصل ما انقطع. قلب أحدهم الذي يملأ المكان قبل أن يفرغ، يلتفّ مستديراً حول هذه الحلقة الصغيرة."},"ICON-0709":{"nm":"خطاف قفاز التنظيف","de":"خطافٌ يُعلّق القفازات المبللة لتجفّ بعد انتهاء العمل بالماء توّاً. يمنح اليدين المتعبتين مكاناً يرتحن فيه قليلاً. وبينما تجفّ الرطوبة ببطء، تلتقط استراحةٌ قصيرة أنفاسها استعداداً للمهمة التالية."},"ICON-0710":{"nm":"دبوس تعليق المكنسة","de":"علّق المكنسة مقلوبةً فيبقى شعرها مستقيماً دون انحناء. وضعيةٌ منتصبة تنتظر الفناء التالي. مكانٌ صغيرٌ لكنه متين، يساعدها على حفظ شكلها حتى بعد انتهاء عملها."},"ICON-0711":{"nm":"مشبك كيس القمامة","de":"يُطبق بإحكامٍ على فوّهة الكيس فيُغلقه بشدةٍ دون أن يتسرّب شيء. لمسةٌ واحدةٌ تُحكم إغلاق الطرف تجعل التنظيف النهائي أكثر نظافة. فالخاتمة، في النهاية، تبدأ من إحكام الإغلاق."},"ICON-0712":{"nm":"وعاء مشابك الغسيل","de":"وعاءٌ تعيش فيه مشابك الغسيل معاً، تلك التي يسهل ضياعها إن تفرّقت. يمنح الصغائر بيتاً مشتركاً تُقيم فيه. حين تجمع جنودك الصغار في مكانٍ واحد، تجدهم بلمحة عينٍ عند الحاجة."},"ICON-0713":{"nm":"حلقة تزويج الجوارب","de":"الجورب الوحيد يختفي دوماً في مكانٍ ما خلسة. اربط كل زوجٍ بحلقةٍ قبل الغسيل، وحتى بعد أن يجفّا ناعمين، لن يفترقا. التصنيف وعدٌ صغير يُقطع مسبقاً ضد الضياع."},"ICON-0714":{"nm":"كيس كرة الغسيل","de":"تتدحرج داخل الغسالة فتُوقظ بطرقاتٍ خفيفة الأوساخ المتغلغلة في الثياب. إيقاعٌ يُلاطف الغسيل بجسدها المستدير. وسط اندفاع الماء، تحمل في كيسها غريزة الغسيل العريقة - الطرق."},"ICON-0715":{"nm":"غطاء قياس منظف الصوف","de":"للثياب الرقيقة كميةٌ رقيقةٌ بقدرها. غطاء قياسٍ يُقدّر منظّف الصوف بدقّةٍ غطاءً واحداً لا أكثر. في علامةٍ صغيرة تكمن لمسة الحذر في التعامل مع الصوف. فتقليل الإفراط أيضاً ضربٌ من العناية."},"ICON-0716":{"nm":"رقعة ترقيع القماش","de":"رقعةٌ صغيرة تُلصق برفقٍ فوق موضعٍ باهت. لمسة أصابعَ تعتني بالمكان المهترئ بدل أن تُلقيه بلا مبالاة. في كل أثر ترقيعٍ يبقى، بجمال، نقش السنين التي مرّت مع ذلك الثوب."},"ICON-0717":{"nm":"دبوس تثبيت منشر الغسيل","de":"دبوسٌ يُمسك المنشر بثباتٍ كي لا تطير الثياب مع الريح. حتى في الأيام التي يتمايل فيها الغسيل تحت الشمس، يساعده على حفظ مكانه وسط الاهتزاز. دورٌ صغيرٌ لكنه ثقلٌ موثوق."},"ICON-0718":{"nm":"وسم كيس غسيل الملابس الداخلية","de":"تُغسل الملابس الداخلية الرقيقة منفردةً داخل شبكة. شبكةٌ تحتضن الأشياء الناعمة بعيداً عن اندفاع الماء العنيف. كيسٌ صغيرٌ يحمل بطاقةً يُذكّرنا أن حماية الهشّ بعنايةٍ هو أيضاً ضربٌ من إدارة البيت."},"ICON-0719":{"nm":"خطاف ملعقة المسحوق","de":"علّق ملعقة المسحوق مرتّبةً على الحائط. دون عناء إسقاطها في الوعاء وتبليل يدك. عادة ترتيبٍ تضع الأداة نفسها في المكان نفسه دائماً، تسكن بإحكامٍ في هذا الخطاف الصغير."},"ICON-0720":{"nm":"موقف حبل الغسيل","de":"يُطبق على طرف حبل الغسيل بإحكامٍ، فلا ينفلت حتى وإن حُمّل بغسيلٍ ثقيل. عقدةٌ أخيرة تصمد حتى النهاية كي لا يترهّل الخط المشدود. عليها يتوقّف الإغلاق المُحكم."},"ICON-0721":{"nm":"بطاقة كيس الوسادة","de":"المكان الذي تلمسه الوجنة أولاً كل ليلة، وفي داخله بطاقةٌ بحجم الظفر مخيّطة بعناية. من يقرأ الحروف الدقيقة التي تذكر درجة حرارة الغسيل؟ ومع ذلك تبقى أقرب دليلٍ يحرس وجهاً نائماً."},"ICON-0722":{"nm":"مشبك اللحاف","de":"في ليلةٍ تُترك فيها النافذة مفتوحة، لا يهرب اللحاف مهما دخلت النسمات. لأن مشبكاً أطبق فمه بإحكامٍ على الطرف. يدٌ صامتة تُمسك الحافة نيابةً عن النائم."},"ICON-0723":{"nm":"ستارة مصباح النوم","de":"\"إن لامس الضوء عينيك، ابتعد النوم.\" بستارةٍ واحدة نصبها أحدهم خلسة، يتراجع الضوء ولا يبلّل سوى قدمي السرير بخفوت. حاجزٌ صغيرٌ يُعير شبراً من الظلام."},"ICON-0724":{"nm":"جيب فجوة السرير","de":"تخيّل تلك الفجوة بين المرتبة والحائط، حيث لا تبلغها اليد. جهاز التحكّم الذي تدحرج بعيداً، والنظارة أيضاً، يجتمعان الآن هنا. جيبٌ يفتحه السرير خلسةً ليلتقط ما كاد يضيع."},"ICON-0725":{"nm":"صينية حفظ النظارة","de":"انزع العدستين فيتموّه العالم برفق، وطبقٌ ضحل يستقبل تلك اللحظة القصيرة من العزلة. وفي الصباح، حتى دون أن تتلمّس الأصابع، تنتظر النظارة دوماً في المكان نفسه."},"ICON-0726":{"nm":"قاعدة منبه الساعة","de":"عند السادسة فجراً، فوق قاعدةٍ متينة يدوّي أكره الأصوات. يحمل الساعة بثبات دون اهتزاز، ليفتح في النهاية يوم أحدهم. يحمل، بصمت، وعد الاستيقاظ الجاف."},"ICON-0727":{"nm":"حامل كابل السرير","de":"كابل الشحن الذي كان ينزلق نحو رأس السرير لم يعد يسقط على الأرض. لأن حاملاً صغيراً يُمسك طرف السلك برفق. على مرمى يدٍ، لمسةٌ رتّبت مسار الليل."},"ICON-0728":{"nm":"شريط طي البيجامة","de":"شريطٌ يلفّ مرةً واحدة حول بيجامةٍ مطويّةٍ بعناية ويربطها. حتى الليونة السريعة التغضّن تحتاج إلى ترتيب. من أجل \"أنا\" الليلة القادمة، يطوي \"أنا\" اليوم بأناقةٍ - استعدادٌ صغير."},"ICON-0729":{"nm":"حامل بطاقة العطر","de":"انصب بطاقةً معطّرةً مائلة، وكأنك تُقلّب صفحة، تُقلّب الفصل بأنفك. من اللافندر إلى الحمضيات - تصير مذكّرات ذلك اليوم مكتوبةً برائحة."},"ICON-0730":{"nm":"وسادة طبق المفاتيح","de":"ركنٌ في المدخل، حيث كانت المفاتيح تسقط بصليل. طبقٌ مبطّنٌ بوسادةٍ ناعمة يبتلع ذلك الصوت الحاد. حركة العائد الأولى يستقبلها بهدوءٍ مسند صغير."},"ICON-0731":{"nm":"غطاء تجفيف المظلة","de":"يتقاطر ماء المطر من طرف المظلة التي حملتها معك. غطاءٌ واحد يلتقط ذلك التنقيط بإحكام، فمن سبق وتوقّع تلك البركة الصغيرة التي كانت ستتسلّل خلسةً على الأرضية، وأوقفها مسبقاً."},"ICON-0732":{"nm":"شريحة تعليق الكمامة","de":"شريحةٌ بحجم الظفر ملتصقة بالحائط قرب الباب. كأنه الطقس الأخير قبل الخروج، تُعلّق الكمامة هنا. جهاز ذاكرةٍ صغير يحفظ مستوى النظر عند الباب كي لا تنسى ما يجب أن تحمله."},"ICON-0733":{"nm":"غطاء غمد سكين الطرود","de":"غطاءٌ واقٍ يُلبس نصل السكين الذي يشقّ صناديق الطرود. يُغطّي بهدوءٍ خطر الجرح الكامن خلف نشوة فتح الطرد. عنايةٌ لا تُلاحظ تفتح نهاية الانتظار بأمان."},"ICON-0734":{"nm":"قاعدة فرشاة الأحذية","de":"المكان الذي تستقرّ فيه فرشاة الأحذية رطبةً بعد انتهاء التنظيف. حتى وهي تحمل الرطوبة، تبقى الأرض جافةً ناعمة. حتى الأداة التي تصنع النظافة تحتاج مكاناً لترتاح، تُذكّرنا القاعدة الصغيرة."},"ICON-0735":{"nm":"لوحة ملاحظات الزوار","de":"\"مررت للحظةٍ ثم ذهبت.\" سطرٌ قصيرٌ من الكتابة بقي على لوحة ملاحظات المدخل. ساحةٌ صغيرة يتبادل فيها من فاتهم اللقاء أخباراً عبر الزمن. على مربّعٍ واحدٍ من الورق، تتراكم متداخلةً تحيةٌ وطلبٌ وقلبٌ واحد."},"ICON-0736":{"nm":"لفافة سد فجوة الباب","de":"تيار هواءٍ كان يتسلّل من فجوةٍ بحجم إصبعٍ تحت الباب. لفافةٌ ملفوفة تسدّ ذلك الممر بهدوء. تحتفظ بطبقةٍ إضافيةٍ من الدفء داخل الغرفة كانت تتسرّب دون أن يُرى."},"ICON-0737":{"nm":"تعويذة موقف الباب","de":"تعويذةٌ صغيرة تسند قاعدة بابٍ مفتوحٍ على مصراعيه كي لا ينغلق من جديد. تصمد بثقلها من أجل النسيم وخطى الأقدام العابرة. عنادٌ لطيف يُبقي الانفتاح مستمراً."},"ICON-0738":{"nm":"غطاء مفتاح إضاءة المدخل","de":"مفتاح المدخل الذي كنت تتلمّسه في ظلام الليل المتأخر. غطاءٌ متوهّجٌ يُشير بهدوءٍ إلى مكانه في العتمة. كي لا تتوه يدك، دليلٌ صغير يُضيء قبل أن يُضاء الضوء نفسه."},"ICON-0739":{"nm":"وسادة حامل الكوب","de":"في اللحظة التي بدأ فيها الكوب الموضوع على الطاولة ينزلق، وسادةٌ واحدة تُمسك قدمه برفق. حاملٌ يحفظ مكانه بهدوء، دون أن يترك أثراً حتى وإن تكوّنت قطرات الماء."},"ICON-0740":{"nm":"مشبك عطر السيارة","de":"مشبك عطرٍ صغيرٌ معلّقٌ داخل السيارة. يمتطي نسيم فتحة التهوية، فتملأ رائحةٌ خفيفة المكان الضيّق ببطء. عزاءٌ لطيفٌ في مقعد القيادة، يُدفئ حتى ملل الانتظار عند الإشارة برائحته."},"ICON-0741":{"nm":"غطاء حزام الأمان","de":"غطاءٌ ناعم يُلبس فوق الحزام العابر للكتف. خشونة تلامس الرقبة تختفي بسلاسة. حتى الشريط المخصّص للأمان يمكن أن تُضاف إليه اللطافة، تقول هذه القطعة القماشية الصغيرة."},"ICON-0742":{"nm":"لوحة إخفاء رقم الموقف","de":"لوحةٌ تُخفي بهدوءٍ اللوحة التي كانت تُشير إلى موقفك في المرأب تحت الأرض، قبل التقاط الصورة. لدى كلّ إنسانٍ معلوماتٌ لا يرغب في تركها. طبقةٌ واحدة تُمحى بحذرٍ من مشهدٍ من الحياة اليومية."},"ICON-0743":{"nm":"غطاء جرس الدراجة","de":"رنّة! تحيةٌ صافية تُهديها الدرّاجة عند زاوية الزقاق. غطاءٌ فوق الجرس يحمي ذلك الصوت حتى تحت المطر. عند رنّةٍ صغيرة واحدة، يبتسم الناس ويتنحّون خطوةً جانباً."},"ICON-0744":{"nm":"حلقة مقبض المقود","de":"حلقةٌ تلفّ بنعومةٍ ملمس المقود بين راحة يدك. حتى بعد قبضٍ طويل وقيادة، لا تخدر اليد. كلما طال الطريق، زادت راحة القبضة من تقصير تلك المسافة."},"ICON-0745":{"nm":"ملصق اسم الخوذة","de":"ملصق اسمٍ لُصق داخل الخوذة. بين خوذات أمانٍ متطابقة الشكل، يصرخ بخفوتٍ \"هذه لي\". أخصّ علامةٍ، منقوشةٌ فوق الصلابة التي تحمي الرأس."},"ICON-0746":{"nm":"غطاء عاكس العجلة","de":"غطاءٌ لا يبدأ عمله إلا بعد غروب الشمس. يلتقط الضوء العابر ويعكس العجلة بوضوح. في الظلام، يُرسل بالضوء إشارةً صغيرة: \"هنا إنسان\"."},"ICON-0747":{"nm":"جراب حماية مفتاح السيارة","de":"مفتاح السيارة الذي كان يُخدش باصطدامه بمفاتيح أخرى في الجيب. جرابٌ ناعمٌ يحتضن سطحه بإحكام. القلق على شيءٍ تقبضه كل يوم أن يبقى بلا خدوشٍ طويلاً، مُتضمَّنٌ هنا."},"ICON-0748":{"nm":"دبوس رف الشفط","de":"دبوس رفٍّ يلتصق بالحائط بلمسةٍ خفيفة دون دقّ مسمارٍ واحد. حتى الحائط الذي لا تريد ترك أثرٍ عليه يحظى بخانة تخزينٍ واحدة. مهارةٌ لا تترك أثراً، تُعلّق أدوات المنزل في غرفةٍ مستعارة مؤقتاً."},"ICON-0749":{"nm":"لوحة خطاف بلا تثقيب","de":"تخيّل أن بإمكانك تعليق شيءٍ دون ثقب الحائط. لوحة خطافٍ بلا تثقيب تتحمّل خلسةً حملاً خفيفاً. رغبةٌ في عدم إلحاق الضرر بمساحةٍ مستعارة، محمولةٌ بجمالٍ في خطافٍ صغير واحد."},"ICON-0750":{"nm":"قضيب تنظيم مغناطيسي","de":"صوت معدنٍ يلتصق بمكانه بطقّة. اجمع الأدوات الصغيرة المبعثرة في كل اتجاهٍ بالمغناطيس، فيتبعها ذلك الشعور اللطيف حين تصطفّ طاولة العمل الفوضوية في صفٍّ واحدٍ مرتّب."},"ICON-0751":{"nm":"قضيب تخزين الفجوة","de":"تخيّل تلك الفجوة الضيقة المنسية بين الثلاجة والحائط. قضيبٌ رفيع يملأ تلك المساحة بالفائدة. فكرةٌ مقتصدة تستخرج التخزين من مساحةٍ ظُنّت عديمة الجدوى."},"ICON-0752":{"nm":"ورقة وسادة لاصقة","de":"ورقة وسادةٍ لاصقة تحمل بثباتٍ حتى الأشياء الثقيلة بمجرد إلصاقها مرة. وإذا نُزعت، لا يبقى أثرٌ، بعجب. قوةٌ هادئة وعنيدة تتحمّل الوزن من مكانٍ لا يُرى."},"ICON-0753":{"nm":"خطاف تعليق على الباب","de":"خطافٌ يكفي أن يُعلّق فوق حافة الباب بخفّة. تتدلّى الحقائب والمناشف على مرمى يدٍ. معلاقٌ وُلد دون دقّ مسمارٍ واحد، يضيف شبراً إضافياً من السعة إلى غرفةٍ ضيقة."},"ICON-0754":{"nm":"مشبك كابل الحائط","de":"مشبكٌ يجمع الأسلاك المتدلّية على الحائط في خطٍّ واحدٍ مرتّب. كتلة الخيوط المتشابكة خلف المكتب تستقيم في مسارٍ نظيف. ترتيبٌ لا يُرى، يجعل هواء الغرفة نفسه أخفّ."},"ICON-0755":{"nm":"وسادة قاعدة المصباح","de":"وسادةٌ تُوضع برفقٍ تحت قدم مصباحٍ واقف. لا تترك خدشاً على المكتب، بل تُهدّئ حتى أدقّ الاهتزازات. حتى إقامة الضوء تبدأ من أرضيةٍ لا تهتزّ."},"ICON-0756":{"nm":"لوح لاصق مانع للانزلاق","de":"السجادة التي كانت تنزلق خلسةً من تحت القدمين تتوقّف أخيراً في مكانها. لأن اللوح اللاصق يُطبق على الأرض بإحكام. شبكة أمانٍ لا تُلاحظ، تُبعد لحظة السقوط المحتملة قبل أن تقع."},"ICON-0757":{"nm":"غطاء مفك الدقة","de":"\"هذا البرغي الصغير وحده لا ينفكّ.\" غطاءٌ يُلبس طرف مفك الدقة ويحمي نصله. أدقّ أدوات الأصابع، يفتح عالماً بحجم راحة اليد داخل آلة."},"ICON-0758":{"nm":"حلقة مفاتيح آلن","de":"حلقةٌ تنظم عدة مفاتيح آلن على خطّافٍ واحد. تنفتح المعادن المصطفّة بحسب الحجم كأنها مروحة. إيقاع يدٍ مرتّبة، تنتقي في حركةٍ واحدة القطعة التي تحتاجها بالضبط."},"ICON-0759":{"nm":"تعويذة شريط القياس المصغر","de":"تعويذةٌ متدلّية من شريط قياسٍ مصغّر يملأ راحة اليد. تتدلّى من سلسلة المفاتيح وترافقك أينما ذهبت. صديقٌ صغير يقيس ويجيب في مكانه عن أي طولٍ يُثير فضولك فجأة."},"ICON-0760":{"nm":"علبة تصنيف البراغي","de":"علبة تصنيفٍ تجد فيها البراغي المتفرّقة كلٌّ خانتها الخاصة. حتى القطع الصغيرة التي كانت تتدحرج مختلطة تكتسب نظاماً. يدٌ تتعلّم الترتيب أولاً، قبل أن تُصلح أي شيء."},"ICON-0761":{"nm":"غطاء فوهة الغراء","de":"إن أُغلقت لا أتصلّب، وإن تُركت مفتوحة أجفّ - أعيش بين الحالتين. مع كل قطرةٍ تسقط، ينضمّ في مكانٍ ما شيءٌ مكسورٌ من جديد. غطاءٌ صغير يحرس بهدوءٍ الحدّ الفاصل بين السكون والتدفّق."},"ICON-0762":{"nm":"ميزان تسوية لسلسلة المفاتيح","de":"صدقٌ بحجم راحة اليد يتدلّى في طرف حزمة المفاتيح. هذه الفقاعة الصغيرة هي دوماً أول من يلاحظ رفّاً مائلاً. أحمل في جيبي صديقاً يُخبرني بهدوءٍ أن العالم انحرف قليلاً."},"ICON-0763":{"nm":"غطاء طرف الملقط","de":"كلما كان الشيء أكثر حدّة، احتاج إلى رداءٍ يُهدّئه. غطِّ الطرف برفقٍ فلا تُصاب اليد ولا القطع بأذى. أولى آداب التعامل مع الحدّة هي تغطية طرفها بهدوء - وهذا الغطاء الصغير يتولّى تلك اللطافة."},"ICON-0764":{"nm":"لوح قطع صغير","de":"لوحٌ تلتئم ندوبه من تلقاء نفسها حتى بعد آلاف مرّات مرور النصل. تُوضع فوق الجرح مهمّةٌ جديدة، فيلتئم من جديد. يومٌ صامتٌ لأرضيةٍ تمنح جسدها كي يُقطع غيرها بنعومة."},"ICON-0765":{"nm":"كيس قطع الإصلاح","de":"كيسٌ يُطبق فمه كي لا يضيع برغيٌ واحد أو نابضٌ واحد إلى الأبد. القطع الصغيرة المتبقّية بعد انتهاء الإصلاح تنتظر هنا بهدوءٍ دورها القادم. ما يمنع الضياع دوماً هو مثل هذه الخانات المتواضعة."},"ICON-0766":{"nm":"مشبك كيس الوجبات الخفيفة","de":"حفظ قرمشة كيسٍ مفتوح يعود، في النهاية، إلى قبضةٍ واحدةٍ حاسمة. وعدٌ صغير بألّا تُترك فرصةٌ للرطوبة. عادة إحكام إغلاق الطرف تُنقذ وجبة الغد الخفيفة."},"ICON-0767":{"nm":"كوب تقسيم الجيلي","de":"لتقاسم كيسٍ واحد بين عدة أشخاص، لا بدّ أولاً من تقسيمه بإنصاف. قلبٌ يغرف نصيباً متساوياً في كل كوبٍ صغير. أؤمن أن المشاركة تبدأ دوماً من كميةٍ متساوية تماماً، كي لا يشعر أحدٌ بالغبن."},"ICON-0768":{"nm":"قصاصة ورق قصدير الشوكولاتة","de":"الفضة التي غلّفت الحلاوة تتجعّد بسهولةٍ بين الأصابع. افردها فتلمع للحظة، اطوها فتصير ذكرى. قصاصة ضوءٍ لا تزداد جمالاً إلا بعد أن يُؤكل كل شيء - انظر إليها مرةً أخرى قبل أن ترميها."},"ICON-0769":{"nm":"شريط وسم الوجبات الخفيفة","de":"ماذا يحتوي، وحتى متى يبقى صالحاً - أتحدّث نيابةً عن الكيس الصامت. في لحظة إلصاق شريطٍ واحد، يكتسب حتى الوجبة الخفيفة اسماً ووعداً. التصنيف، في الحقيقة، أرقّ طرق التذكّر."},"ICON-0770":{"nm":"علبة تصنيف الحلوى","de":"لا تضع الحامض والحلو في الخانة نفسها. عملٌ يفصل مسبقاً كي لا تتردّد اليد. حين تصطفّ العلب الصغيرة في صفٍّ، تتضاعف خلسةً متعة الاختيار."},"ICON-0771":{"nm":"ورق توسيد الكوكيز","de":"ورقٌ رقيقٌ يُدسّ بين الكوكيز كي لا يُكدَم في طريقه. كلما كان الشيء أكثر هشاشةً، احتاج إلى رفقةٍ أكثر رقّة. أحياناً تحمي النعومة أفضل من الصلابة."},"ICON-0772":{"nm":"خيط علبة الدونات","de":"عقدةٌ واحدة متقاطعة تتولّى مسؤولية سلامة الكعكة داخل الصندوق. تصير مقبضاً، وختماً، وعلامةً على انتظارٍ مشوّق. لحظة انحلال هذا الخيط هي عيد ميلاد أحدهم."},"ICON-0773":{"nm":"مشبك كيس الخبز","de":"التوِ ثم اطوِ ثم أدخلني، فتُختم نعومة الخبز حتى صباح الغد. إصرارٌ صغيرٌ عنيدٌ يمنع الهواء. الحفاظ على شيءٍ ناعم طويلاً هو دوماً مهمّة شيءٍ متين."},"ICON-0774":{"nm":"بطاقة تبادل الوجبات الخفيفة","de":"نصيبك لي، ونصيبي لك. أتذكر ذلك الحماس يوم كتبنا أسماءنا على بطاقاتٍ صغيرة وتبادلنا الوجبات الخفيفة؟ الورقة الملتصقة بقلبٍ يشارك تحمل دوماً اسم صديقٍ مكتوباً بخطٍّ واضح."},"ICON-0775":{"nm":"غطاء سدادة الشفاطة","de":"حين تتوقّف للحظةٍ بين رشفةٍ وأخرى، تُغلقني. كي لا يُسكب شيء، وكي لا يبرد، وكي ينتظر بهدوءٍ في مكانه. عمل سدادةٍ صغيرة تحرس الفوهة إلى أن تعود الشفتان."},"ICON-0776":{"nm":"حلقة اسم كوب الترمس","de":"حلقةٌ صغيرة تقول \"هذا لي\" وسط صفٍّ من أكواب الترمس المصطفّة جنباً إلى جنب. لونٌ واحد، فيذوب الالتباس برفق. علامة \"هذا ملكي\" تصير واضحةً تماماً بحلقةٍ واحدة فقط."},"ICON-0777":{"nm":"غلاف حامل الكوب","de":"طبقةٌ واحدة من الورق المضلّع تتسلّل بين الكوب الساخن وراحة يدك. لفتة عنايةٍ تُدسّ كي لا تحترق ولا تنزلق قبضتك. حراسة المسافة بينهما هي ما يُتمّم كوباً سليماً بلا أذى."},"ICON-0778":{"nm":"ملصق قالب الثلج","de":"هناك من يكتب تاريخ صنع كل دفعةٍ من الثلج. بإيمانٍ أن حتى البرودة لها ترتيب. ملصقٌ صغيرٌ واحد يجعل زمن الثلاجة يتدفّق بصدقٍ، دورةً تلو أخرى."},"ICON-0779":{"nm":"ملقط كيس الشاي","de":"تراقب وقت النقع، ثم تنتزعه في اللحظة المناسبة تماماً. لمسة يدٍ ماهرة تعرف متى تتوقّف قبل أن يشتدّ الطعم. عمق الشاي لا يحدّده وقت النقع بقدر ما تحدّده لحظة الانتزاع."},"ICON-0780":{"nm":"حامل مرشح التنقيط","de":"يحمل المرشح ويقف صامتاً كي ينزل الماء الساخن ببطء. يعرف جيداً أن الاستعجال يُضعف العبق. حتى دعم الانتظار يحتاج إلى وقفةٍ ثابتة لا تهتزّ."},"ICON-0781":{"nm":"حزام الزجاجة","de":"حزامٌ يُعلّق زجاجة الماء على معصمك أو كتفك ليسير معك. طريقة رفقةٍ تُبقيها قريبةً دائماً دون أن تتعمّد حملها. أحياناً يكون ربطها برفقٍ كي لا تُنسى، أرقّ طريقة."},"ICON-0782":{"nm":"غطاء علبة المشروب","de":"يُغطّي فوّهة علبةٍ لم تُشرب بعد كاملةً، فيمنع الغبار وفقدان الفوران. قبعةٌ صغيرة تتولّى مسؤولية النضارة حتى الرشفة القادمة. حتى تغطية ما فُتح للحظةٍ برفقٍ تحمل نصيبها من العناية."},"ICON-0783":{"nm":"حامل كوبونات المشروبات","de":"الكوب العاشر المجاني - يحتضن بطاقة الأختام كي لا يضيع ذلك الوعد. كي لا تتجعّد الأيام التي مُلئت خانةً خانة. داخل هذا الحامل، تتراكم خطى زبونٍ دؤوبٍ مرّ من هنا مراراً."},"ICON-0784":{"nm":"شريط صندوق الغداء","de":"شريطٌ يعانق صندوق الغداء دورةً واحدة كي لا ينفتح الغطاء. طمأنينةٌ صغيرة أن المرق لن يتسرّب داخل الحقيبة. عبور الأمان حتى وقت الغداء يتحمّله هذا الطوق المُحكم الواحد."},"ICON-0785":{"nm":"طقم أكواب الأطباق الجانبية","de":"امنح كل طبقٍ جانبيٍّ مكانه فلا تختلط النكهات. الكيمتشي على حاله، والخضار على حالها، كلٌّ واضحٌ متميّز. الفصل الذي تصنعه الأكواب الصغيرة هو نظام صندوق الغداء، ولطافةٌ فوق لمسة الطاهي."},"ICON-0786":{"nm":"علبة عيدان الأكل","de":"بيتٌ صغير يحمل بنظافةٍ عيدان الأكل التي شاركت وجبات اليوم الثلاث. رفيقٌ هادئ يحافظ على أناقته حتى داخل حقيبة المدرسة. تلك العناية بحملها معك، هي ما يصنع في النهاية وجبةً مرتّبة."},"ICON-0787":{"nm":"ملصق زجاجة الصلصة","de":"صلصة صويا أم خلّ؟ يمنح الوضوح للزجاجة التي كانت تُثير الالتباس. في لحظة إلصاق سطرٍ واحد، يختفي تردّد الأصابع. سرعة المطبخ المزدحم تصنعها بهدوءٍ علاماتٌ صغيرة كهذه."},"ICON-0788":{"nm":"ورق لف الكيمباب","de":"ورقة نوري رقيقة تلفّ الأرزّ والحشوة في جسدٍ واحد. لا بدّ من لفّها بإحكامٍ كي لا تتفكّك عند التقطيع. حماس صباح النزهة يخرج ملفوفاً مستديراً من هذه الطبقة الواحدة."},"ICON-0789":{"nm":"كوب حامل الأعواد","de":"أوقف الأسياخ وأعواد الأسنان جميعها في مكانٍ واحد، فلا تتردّد اليد عند الحاجة. عملٌ يمنح حتى الأشياء الحادّة بيتاً مخصّصاً لها. الترتيب، في النهاية، لطفٌ صغير من أجل اللمسة القادمة."},"ICON-0790":{"nm":"غطاء كيس التبريد","de":"غلّف كيس التبريد بطبقةٍ إضافية لتحتفظ بالبرودة أطول قليلاً. مع منع تكاثف الرطوبة من تبليل الحقيبة أيضاً. الحفاظ على الانتعاش حتى النهاية هو دوماً عمل هذه الطبقة السميكة الواحدة."},"ICON-0791":{"nm":"فاصل صندوق الغداء","de":"جدارٌ صغير أُقيم كي لا يتعدّى الأرزّ والأطباق الجانبية على مكان بعضهما. سلام خانةٍ واحدة لا يتسرّب فيها المرق. صندوق غداءٍ مقسّم خانةً خانة يحمل بأمانةٍ قلب من صنعه الدقيق."},"ICON-0792":{"nm":"بطاقة ترتيب الوجبة","de":"الحساء أولاً أم الأرزّ أولاً؟ بطاقةٌ تقترح برفقٍ ترتيب وجبة اليوم. إرشادٌ لطيف يقول إن الطعم يزداد حين يُؤكل بترتيب. تُخبرك بهدوءٍ أن للوجبة أيضاً تدفّقاً كالقصة."},"ICON-0793":{"nm":"ملصق كوب القياس","de":"ملصقٌ صغيرٌ بجانب العلامات يُشير بدقّةٍ إلى \"حتى هنا\". علامةٌ تضبط بضربةٍ واحدة الكمية التي كانت تُربكك دوماً. الدقّة تنبع من خطّ إرشادٍ صغيرٍ كهذا."},"ICON-0794":{"nm":"مقبض غطاء سيليكون","de":"مقبضٌ صغيرٌ يتيح رفع غطاءٍ ساخنٍ دون أن تحترق أصابعك. يُعير خلسةً شجاعة فتح قدرٍ يتصاعد منه البخار. الأمان يأتي دوماً من تجهيز مكانٍ للقبض عليه مسبقاً."},"ICON-0795":{"nm":"معلاق مشبك صغير","de":"مشبكٌ صغيرٌ يمنح مكاناً لفوطةٍ أو كيسٍ لم يكن له مكانٌ يُعلّق فيه. يحوّل ركناً فوضوياً من الحائط إلى مشهدٍ مرتّب. عادة تعليقٍ واحدة تجعل المطبخ أخفّ بكثير."},"ICON-0796":{"nm":"غطاء فرشاة الزيت","de":"غطِّ طرف فرشاة دهن الزيت فيتجنّبها الغبار والتصلّب. قبعةٌ تحفظ تلك النعومة حتى الطبخة القادمة. عنايةٌ صغيرة بالأدوات تحفظ، في النهاية، الطعم طويلاً."},"ICON-0797":{"nm":"وعاء ملعقة الملح","de":"ملعقةٌ صغيرة تعيش مغروسةً داخل وعاء الملح. تغرف دقّة قبضةٍ واحدة بعنايةٍ في كل مرة. لمسة التتبيل الماهرة هي بقدر ما تتذكّره هذه الملعقة الصغيرة من قلب."},"ICON-0798":{"nm":"لوحة مؤقت مغناطيسية","de":"تلتصق بباب الثلاجة فتعدّ ثلاث دقائق النودلز، وتقيس ثلاثين ثانية للتمرين. بقطعة مغناطيسٍ واحدة، يبقى الزمن العابر أمام عينيك. دائرةٌ صغيرة دؤوبة تُثبّت العابر على الحائط للحظة."},"ICON-0799":{"nm":"غطاء مقبض القدر","de":"طبقةٌ تلتفّ حول المقبض المحمّى كي لا تُمسكه بيدٍ عارية. درعٌ صغير يقف بين الحرارة وراحة يدك. نقل القدر بأمانٍ يبدأ دوماً من هذا الالتفاف الناعم."},"ICON-0800":{"nm":"مطاط تثبيت لوح التقطيع","de":"حين أُفرش تحته، لا ينزلق لوح التقطيع بعد الآن. قطعة مطاطٍ تصمد من الأسفل كلما اهتزّ قطع السكين. الثبات هو أن تُطبق بإحكامٍ في مكانٍ لا يُرى."},"ICON-0801":{"nm":"مشبك قفاز المطبخ","de":"هنا تستريح اليد التي لم تهدأ أمام النار للحظة. حين يُثبَّت قفازٌ خافق على الجدار، تبدأ استراحة قصيرة حتى الوجبة التالية. فالترتيب، في نهاية الأمر، اسمٌ آخر للحنان."},"ICON-0802":{"nm":"حامل أعواد تحريك القهوة","de":"بجانب المنضدة، ركنٌ تتكئ فيه العيدان النحيلة كتفًا إلى كتف، مصفوفة بعناية. تقف مستعدة لرسم دائرة في فنجان أحدهم صباحًا، مصطفة في صفوف كأنها جوقة إنشاد على وشك أن ترفع صوتها معًا."},"ICON-0803":{"nm":"شريط طقم حوامل الأكواب","de":"شريطٌ يستقبل برفق تلك الطقطقة الصغيرة حين يلامس الكوب سطح المائدة. اجمع الحوامل الدائرية معًا، وتكون استعدادات استقبال الضيوف قد اكتملت. فالضيافة تبدأ دائمًا، هكذا، من أصغر الأماكن أولًا."},"ICON-0804":{"nm":"رقعة ملصق شراب السكر","de":"اسمٌ واحد ملصقٌ على الزجاجة. حلو، غامق - كلمة واحدة قصيرة تُهدّئ صباحًا مزدحمًا وتجعله أكثر تناسقًا. فالملصق ورقة تُدوَّن عليها وعدٌ صغير مسبقًا."},"ICON-0805":{"nm":"وعاء أعواد تزيين الحلوى","de":"وعاءٌ تعيش فيه معًا العيدان المدبَّبة التي تنغرز في قطعة فاكهة. قبل أن تُغرَس كأعلامٍ فوق طبق الحلوى، تنتظر هنا بهدوء دورها. فحتى الحلاوة لها نظامها الخاص."},"ICON-0806":{"nm":"غلاف عصا التحريك","de":"معطفٌ ورقي يحتضن حفنة من عيدان التحريك. يمتص الرطوبة التي يسكبها مشروبٌ بارد، فيحافظ على جفاف أطراف الأصابع الممسكة بالكوب. فالعناية غير المرئية تأتي دائمًا من الأطراف."},"ICON-0807":{"nm":"بطاقة حامل أكواب التيك أواي","de":"حين لا تكفي يدان، مقبضٌ صغير يحمل الأكواب بدلًا عنك. يُمسك بالدفء المُغلَّف كي لا تسقط منه قطرة واحدة، فيودّع ذلك الدفء حتى مدخل زقاق أحدهم."},"ICON-0808":{"nm":"غطاء جرس الاهتزاز في المقهى","de":"غلافٌ يحتضن بهدوء الانتظار حتى يرن الجرس. يحرس بطاقة الدور المتلألئة في ركن المقهى، ويحمل معها أيضًا ذلك الترقب بأن رقمك سيُنادى قريبًا."},"ICON-0809":{"nm":"حلقة بطاقات الأختام","de":"ورقةٌ إذا امتلأت خاناتها العشر، منحتك كوبًا مجانًا. مع كل ختمٍ يُضاف، ينمو قليلًا اسم \"الزبون الدائم\". متعة بسيطة للغاية، معلَّقة في حلقة صغيرة."},"ICON-0810":{"nm":"كيس عينة حبوب القهوة","de":"كيسٌ يحمل حفنة من الحبوب ويقدّم رائحتها أولًا. الحموضة والحلاوة تمرّان قرب الأنف، وذلك الانطباع الأول يقرر مصير فنجانٍ كامل. فالعطر يصل أسرع من أي شرح."},"ICON-0811":{"nm":"مغناطيس ملصق الثلاجة","de":"بطاقة اسم مغناطيسية صغيرة تلتصق بباب الثلاجة. دوّن ما دخل ومتى، وحتى الطبق الجانبي الذي كاد يُنسى يستعيد دوره. فتدبير المنزل هو تثبيت الذاكرة المتدفقة."},"ICON-0812":{"nm":"رقعة تاريخ التخزين","de":"قصاصة تنقش بوضوح يوم التعبئة. شاهدٌ صغير يهمس بهدوء، حتى بعد أيام، بأن هذا لا يزال صالحًا. فالطزاجة تُصان بأطراف أصابع تتذكر التاريخ."},"ICON-0813":{"nm":"شريط علبة التقسيم","de":"شريطٌ يلتف حول خصر علبةٍ مقسَّمة. يشدّ الغطاء المتذبذب بإحكام، حافظًا نظامًا صغيرًا داخل الثلاجة. فربط شيء ما يشبه ترتيب القلب."},"ICON-0814":{"nm":"شريط مشابك سد الأكياس الملونة","de":"مشابك ملونة تعضّ بإحكام فم الكيس. الأحمر للحار، والأصفر للحلو - تعرف اليد من اللون وحده. فإشارات المرور في المطبخ تُرشد الطريق هكذا دون كلمة."},"ICON-0815":{"nm":"بطاقة اسم كيس التجميد","de":"بطاقة اسم توضع برفق فوق شيءٍ مجمَّد. تطمئن الكيس المغطى بالصقيع كي لا ينسى ما كان عليه. تحية صغيرة تُرسَل إلى مكونات غفت في سباتها الشتوي."},"ICON-0816":{"nm":"شبكة تخزين الخضار","de":"شبكة فضفاضة تحتضن بسخاء خضارًا ملطخة بالتراب. مطبخ الجدة عرف منذ زمن أن منحها متسعًا للتنفس يطيل عمرها. فالتهوية هامشٌ حنون يُمنح للخضار."},"ICON-0817":{"nm":"غطاء تصنيف أغطية الزجاجات","de":"غطاء تصنيف يُزاوج الأغطية واحدًا واحدًا بحسب الحجم. العثور على الشريك المفقود مجددًا أكثر حنانًا مما تتصور. وزوّج زوجًا مناسبًا فيغدو المطبخ أكثر تناسقًا."},"ICON-0818":{"nm":"ملصق صينية البيض","de":"علامة توضع بعناية على كل عشّ من الأعشاش العشرة الصغيرة. حكمة منزلية تقول: استخدم البيضة الأقدم أولًا. حتى بيضة مقلية واحدة في الصباح تحمل قلب من يهتم بالترتيب."},"ICON-0819":{"nm":"ملصق بقايا الطعام","de":"اكتب \"هذا لي!\" والصقه، وحتى الثلاجة تنعم بلحظة سلام. إعلان حربٍ ظريف يحدد سلفًا صاحب وجبة منتصف الليل. وهكذا تمضي العائلة يومها بمثل هذه المعاهدات الصغيرة التافهة."},"ICON-0820":{"nm":"قطعة مسند أدوات المائدة","de":"قطعة صغيرة تسند برفق الملعقة وعيدان الطعام كي لا تلامس المائدة مباشرة. هذا النظام الصغير يرفع خفية من رقيّ الوجبة. فآداب المائدة تنمو بهدوء في مثل هذه الأماكن."},"ICON-0821":{"nm":"حلقة تثبيت المناديل","de":"حلقة تنزلق بهدوء وتُمسك بمنديل كان سيتطاير مع الريح. تجمع الورق الأبيض المنتظر دوره لينفرد، ناقشة بعناية نظامًا صغيرًا على المائدة."},"ICON-0822":{"nm":"زاوية مفرش الطاولة","de":"قطعة تضغط برفق وتُهدّئ زاوية مفرش مرتفعة. تعلّم المائدة كل يوم أن الكل لا يستقيم إلا حين يُمسَك أحد طرفيه. حتى الزاوية لها نصيبها من المسؤولية."},"ICON-0823":{"nm":"صينية التوابل الصغيرة","de":"صينية صغيرة تحمل جنبًا إلى جنب طبق صويا صغيرًا ورشة ملح. احتضان المائدة الواسع الذي يمنح حتى الطبق المرافق مكانه الخاص. فالمطبخ الكوري يزداد عمقًا في القلب الذي يعتني بالتفاصيل الجانبية."},"ICON-0824":{"nm":"رقعة رقم الطاولة","de":"الرقم الذي يُنادى \"الزبون رقم كذا!\" في مطعمٍ صاخب. يمنح الانتظار نظامًا ويحفظ العدل للجميع. وما تحمله هذه الرقعة الواحدة هو وعدٌ صغير، ووجبة دافئة ستصل قريبًا."},"ICON-0825":{"nm":"شريط تمييز كوب الماء","de":"شريطٌ يُلَفّ حول كوب الماء ليخبر بهدوء لمن هو. علمٌ صغير يحدد مكانك بين أكواب متشابهة. وفي مائدة يجتمع حولها الجميع، مثل هذه العناية تمنع سوء فهمٍ لا داعي له."},"ICON-0826":{"nm":"دبوس تصنيف الأطباق الجانبية","de":"دبوسٌ يفرز بالألوان الأطباق الجانبية التي يُقدَّم فيها الطعام. يرسم بلطف حدًا بين ما لي وما لك، فيجعل متعة المشاركة أنظف. فالمودة تُشارَك، والنظافة تُصان بدقة."},"ICON-0827":{"nm":"لوحة حجب قائمة الطعام","de":"وقت التفكير المختبئ خلف قائمة طعام مفتوحة. حتى ذلك التردد القصير في اختيار الطعام هو، في الحقيقة، جزءٌ من الوجبة. ماذا سنأكل اليوم - تحجب بهدوء ذلك الترقب الصغير."},"ICON-0828":{"nm":"حامل بطاقة المقعد","de":"حامل صغير يُبقي بطاقة الاسم منتصبة. سواء في حفل أو وليمة، يعلن بوضوح أن هنا مكانك. فالضيافة لا تكتمل إلا في لحظة نداء الاسم."},"ICON-0829":{"nm":"غلاف كوب المافن","de":"معطفٌ ورقي يحتضن بإحكام خصر المافن الطازج الممتلئ. يسند الجسم الدافئ كي لا ينزلق من يدك، حافظًا الدفء حتى لحظة القضمة الأولى. فحتى الحلوى تحتاج معطفًا."},"ICON-0830":{"nm":"غطاء كيس تزيين الكريمة","de":"سدادة تُبقي فوهة كيس تزيين الكريمة مغلقة بإحكام. تسدّ الفم بعناية كي لا تتسرب قطرة أثناء الراحة. وتلك الزهرة الصغيرة فوق الكعكة تتفتح من هذا الانضباط."},"ICON-0831":{"nm":"حلقة قوالب قطع البسكويت","de":"مجموعة دائرية من القوالب تقطع العجين على هيئة نجوم ودببة. الدقيق نفسه يستيقظ من خلال أطراف الأصابع بعشرات التعابير. مهما خبزتَ، فأول ما يلامس العجين هو دومًا الحرص."},"ICON-0832":{"nm":"تعليقة كاشطة العجين","de":"يدٌ مسطحة تجمع العجين باقتصاد وتقسمه بدقة. ذلك الاجتهاد في الاعتناء حتى بالحفنة الملتصقة بالوعاء هو ما يقرر حجم رغيف الخبز. فالخَبز عملُ يدٍ مقتصدة."},"ICON-0833":{"nm":"لوحة ملاعق القياس","de":"لوحة تُصفّ ملاعق القياس بثبات دون اهتزاز - ملعقة صغيرة، نصف ملعقة كبيرة. ملعقة واحدة دقيقة تُقيم توازن النكهة باستقامة. وخلف عبارة \"لمسة اليد\" يختبئ في الحقيقة قياسٌ دقيق للغاية."},"ICON-0834":{"nm":"خطاف قفاز الفرن","de":"خطافٌ تُعلَّق عليه القفازات التي حرست الفرن الساخن. اليد السميكة التي دفعت عنك الحروق، تبقى حتى أثناء راحتها في متناول اليد. فالسلامة تبدأ دائمًا مما يبقى في مكانه."},"ICON-0835":{"nm":"مشبك شبكة التبريد","de":"ملقطٌ يعضّ بعناية شبكة تبريد الحلويات الطازجة. يمسكها كي لا تتحرك أثناء تصاعد البخار، منتظرًا معها اكتمال القرمشة. فحتى التبريد يحتاج حفنة من الصبر."},"ICON-0836":{"nm":"عود تزيين الكعكة","de":"عودٌ ينصب فوق الكعكة كلمات \"عيد ميلاد سعيد\". قُبيل انطفاء الشموع، يضيء هذا العلَم الصغير يوم شخصٍ ما بأسطع ما يكون. فالاحتفال يظهر جليًا حين يُرفَع عاليًا."},"ICON-0837":{"nm":"علبة رشّ سكر البودرة","de":"علبة تحمل رشّة خفيفة أخيرة. تستقر كالثلج الأبيض فوق حلوى طازجة، فتحوّل قطعة عادية إلى هدية صغيرة. فاللمسة الأخيرة تأتي من أخف الأيدي."},"ICON-0838":{"nm":"ملصق كيمباب المثلث","de":"قشّر الغلاف بالترتيب ١، ٢، ٣ وتعود أوراق البحر مقرمشة على ذلك المثلث. سطرٌ واحد يجعلك تتعرف من نظرة على صديقٍ متين من متجر مفتوح على مدار الساعة عند الفجر. وليالي الجوع بعد المذاكرة المتأخرة تلتصق هنا تمامًا."},"ICON-0839":{"nm":"حامل غطاء كوب النودلز","de":"مسندٌ يضغط بهدوء كي لا يرتفع الغطاء طوال دقائق الانتظار الثلاث. يحلّ محل عيدان الطعام التي كانت توضع فوقه سابقًا كي لا يتسرب البخار. وتلك اللحظة القصيرة من نضج النودلز هي أكثر لحظة إثارة في وجبة منتصف الليل."},"ICON-0840":{"nm":"غطاء عود سيخ الأطعمة","de":"غطاءٌ صغير يقبض بإحكام على طرف السيخ. يحرسه كي يسهل قضمه، دون أن تلطخ قطرة صلصة يدك. ومتعة الوجبات الخفيفة أمام محل الوجبات السريعة تكتمل دومًا بمثل هذه التفاصيل الصغيرة."},"ICON-0841":{"nm":"مقبض كيس البلاستيك","de":"علّقه على أصابعك يصدر البلاستيك صريرًا خافتًا. وزن المشتريات يميل إلى جهة واحدة، والطريق إلى المنزل يترك أثرًا أحمر في راحة اليد. وفي ذلك الصوت الخفيف، تتأرجح ثقيلة كل أعباء تدبير يومٍ كامل."},"ICON-0842":{"nm":"مشبك طيّ الإيصالات","de":"اطوِ الإيصال الطويل المنسدل إلى نصفين واقرصه بإحكام، فتصبح نفقات اليوم رزمة مرتّبة. وبينما تتراكم الأوراق المعطّرة برائحة الحبر، تُرتَّب أيضًا ذكريات تدبير المنزل الصغيرة شيئًا فشيئًا."},"ICON-0843":{"nm":"بطاقة الميكروويف","de":"قبل أن يصدر صوت \"طنّ\"، تحسب البطاقة بهدوء الوقت اللازم للتسخين. لوحة إرشاد صغيرة تدوّن الدقائق والثواني، واسم ما سيُسخَّن. وحتى القلب المنتظر دوره ليدفأ له علاماتٌ مثل هذه."},"ICON-0844":{"nm":"لفافة ملصقات الخصم","de":"كلما قشّرتَ خانة، صريرٌ لزج خفيف يداعب أطراف أصابعك. حين تتوالى الأرقام الحمراء منسدلة، تصبح سلة تسوق أحدهم أخف قليلًا. لفافة كرم صغير، ملفوفة دائريًا وتنتظر."},"ICON-0845":{"nm":"حلقة كيس الصلصة","de":"شيءٌ حامض ينفجر عند طرف الفم فيغدو يوم عادي أحلى قليلًا. حين يتأرجح الكيس المعلَّق بحلقة دائرية مع كل خطوة، تتبعني حلاوة صغيرة طوال اليوم في جيبي."},"ICON-0846":{"nm":"رقعة سلة المتجر","de":"أمسكها فيثني البلاستيك بخفة. متجرٌ مضاء بنور ساطع في ليلة متأخرة، عمقٌ يكفي لحفنة من الكيمباب المثلث ومشروب واحد. وعاءٌ حنون بمقدار وجبة واحدة فقط، حيث لا يشعر المرء بالوحدة حتى وهو وحيد."},"ICON-0847":{"nm":"شريط علبة الماكرون","de":"شريطٌ واحد يحتضن العلبة بهدوء كي لا يتبعثر الماكرون الملون. من تلقّى هدية يعرف بأطراف أصابعه أن الترقب قبيل حلّ الشريطة هو، في الحقيقة، الأحلى."},"ICON-0848":{"nm":"مشبك شبكة الفاكهة","de":"اجمع فوهة الشبكة واقرصها، فتتسرب رائحة التفاح برفق عبر الشبكة. يدٌ صغيرة واحدة تمسك بها كي لا تتدحرج. نداءٌ حنون صامت أن تُؤكل قريبًا قبل أن تلين."},"ICON-0849":{"nm":"قماش غطاء برطمان المربى","de":"يستحضر مطبخ جدتي الصيفي، حين كانت تغطي أغطية البرطمانات بقماشٍ دائري وتربطها برباط مطاطي. قطعة قماش واحدة مخططة تختم معًا وقت نضج المربى الحلو وكل ذلك الحرص. فلمسة اليد تُحفظ مغطاة هكذا."},"ICON-0850":{"nm":"شريط ربط كعك الكوكيز","de":"ضع البسكويت الطازج في السيلوفان واربط الرباط بلفّة، فتتسرب رائحة الزبدة حتى طرفي الشريط. اليد التي تقدّم شيئًا صنعته بنفسها لأحدهم ترتجف دومًا قليلًا. عقدةٌ تربط القلب معها."},"ICON-0851":{"nm":"لوحة تقسيم الشوكولاتة","de":"خانةً خانة، تحدد مكانًا كي لا تتلامس قطع الشوكولاتة. كي لا تذوب، وكي لا تتكسر. وما تحرسه هذه اللوحة الصغيرة حتى النهاية هو، في النهاية، قلبٌ كاملٌ يُقدَّم لأحدهم."},"ICON-0852":{"nm":"بطاقة هدية الشاي","de":"فوق الملصق الملفوف حول كيس الشاي، اسمٌ مكتوب بخط اليد بعناية. تلمّح الورقة الصغيرة سلفًا أن نقعه يُطلق رائحة العشب مع البخار. فنجانٌ يُدفئ اليدين حتى قبل أن تشرب منه."},"ICON-0853":{"nm":"قلادة زجاجة الحلوى","de":"قلادة صُنعت بلفّ خيط حول عنق زجاجة مليئة بحلوى ملونة. مع كل خطوة، صوتٌ كأنه خرزات صغيرة يتدحرج بالداخل. كنزٌ فخورٌ من أيام الطفولة، يُحمَل فيه الحلو حول العنق."},"ICON-0854":{"nm":"تعليقة ملعقة الهدية","de":"بتعليقةٍ صغيرة واحدة متدلية عند طرف المقبض، تصبح ملعقة عادية هديةً دون أن تدري. رنينٌ خفيف صافٍ مع كل غرفة. زخرفةٌ صغيرة تضيف لمسة أناقة إلى قلبٍ يُقدَّم."},"ICON-0855":{"nm":"بطاقة شكر الوجبة الخفيفة","de":"رغبة في ردّ ولو جزء بسيط مما تلقّيته. بطاقة شكر معلَّقة برفق على كيس وجبة خفيفة. بدلًا من \"شكرًا\" لم تكتمل قولها، تحية صغيرة تمرّ بهدوء من يدٍ إلى يد."},"ICON-0856":{"nm":"حلقة عينات شريط الماسكينغ","de":"أنماطٌ قُصّت ولُصقت بمقدار شبر تصطف في شريط صغير. وبينما تختار ببطء اللون الذي يعجبك بأطراف أصابعك، تصبغ فكرة التزيين وحدها يومك بألوانٍ زاهية. صفّ عينات حيث حتى التردد متعة."},"ICON-0857":{"nm":"غطاء ملقط الملصقات","de":"غطِّ طرف الملقط المدبب، وحتى ملصقٌ بحجم الظفر يبقى سليمًا. يدٌ دقيقة ترفع برفق زوايا لا تستطيع الأصابع الوصول إليها. فالتعامل مع ما نحبه يستلزم دومًا شيئًا من الحذر."},"ICON-0858":{"nm":"ملصق زاوية المفكرة","de":"الصق أختامًا في زوايا المفكرة الأربع، وتهدأ الصفحات الخفّاقة كأن سحرًا حلّ بها. ملمس الورق حين يُضغَط برفق، طقسٌ صغير يختم اليوم بعناية. فالتدوين يترسخ من زواياه أولًا."},"ICON-0859":{"nm":"لوحة إرشاد الثقب","de":"لوحة تخبرك سلفًا أين تصنع الثقب. حاذها بهدوء وفق الخط المنقّط، ولن تحيد. القلب الذي يقيس مرة أخرى دون تسرّع، فالدقة تأتي دومًا بهدوء من تلك الوقفة الصغيرة."},"ICON-0860":{"nm":"صينية بقايا الورق","de":"تتجمع فتات الورق المتبقية من القص بهدوء داخل الصينية. مأوى قصير لتلك القصاصات الصغيرة، كي لا يتشوش المكتب. فما يتبقى من الحرفة اليدوية يُرتَّب هكذا دون صوت."},"ICON-0861":{"nm":"وسادة الحبر الملون","de":"اضغط الوسادة برفق ثم ارفعها، وينتشر اللون رطبًا على أطراف أصابعك. أحمر وأصفر وأزرق، قوس قزح صغير يعلق بختمٍ واحد. مساحة صغيرة طرية لغرس اللون، نقطةً نقطة، فوق الورق الأبيض."},"ICON-0862":{"nm":"لفافة شريط الزينة","de":"نمطٌ ينسدل دائريًا دون نهاية. قشّر خانة والصقها فتتفتح زهرة في مكانٍ كان باهتًا. لفافة سحرٍ صغير، ملفوفة وتنتظر، تزداد جمالًا كلما تحركت يدك."},"ICON-0863":{"nm":"غطاء ختم الموضوع","de":"قبعة صغيرة تُغلّف رأس الختم بإحكام كي لا يجفّ الحبر. تحرس بهدوء كي يبقى النقش التالي واضحًا. فاللون المحفوظ جيدًا يتفتح بنفس الوضوح على الورقة التالية."},"ICON-0864":{"nm":"قصاصات مثقاب الزينة","de":"قطعٌ صغيرة أسقطها المثقاب بنقرة خفيفة. فتات ورقٍ ملون قُصّ على هيئة نجوم وقلوب وبتلات يتجمع كومة رقيقة في راحة اليد. جواهر صغيرة أجمل من أن تُرمى، فتنتهي بلصقها في مكانٍ آخر."},"ICON-0865":{"nm":"حلقة ملصقات بكرات الخيط","de":"ملصقٌ صغير يحمل اسم الخيط الملون مكتوبًا على كل بكرة. علامة حنونة تُشير إلى مكانها قبل أن تتشابك. فالخيط المتشابك، والقلب أيضًا، يسهل حلّهما كثيرًا ببطاقة اسم واحدة."},"ICON-0866":{"nm":"غلاف كتيّب الإبر","de":"غلافٌ ناعم لكتيّب من اللباد المغروسة فيه الإبر بكثافة. افتحه وتستقبلك أدوات الخياطة مصطفة بعناية. مجلد صغير يُنيم برفق الأشياء المدببة، كي لا تُجرَح أطراف الأصابع."},"ICON-0867":{"nm":"حلقة عينات الأقمشة","de":"خشنٌ أو ناعم، وقتٌ بطيء تتلمّس فيه نسيج القماش قطعة قطعة بأطراف أصابعك لتختار. بين قصاصات مصفوفة بعناية حسب اللون، وقبل أن تصبح ثوبًا، ينتظر القماش بهدوء أن يُلمَس أولًا."},"ICON-0868":{"nm":"حلقة إطار التطريز","de":"ضع القماش في الإطار الدائري وشدّه، فيصبح مشدودًا كوجه طبل. إشارة صغيرة بأن الاستعداد للتطريز غرزة بغرزة قد اكتمل. وما تُمسكه الحلقة بإحكام ليس القماش، بل القلب المُركِّز."},"ICON-0869":{"nm":"كبسولة تصنيف الأزرار","de":"أزرارٌ كانت تتدحرج هنا وهناك تستقر بهدوء بحسب اللون في كل خانة كبسولة. حكمة منزلية تقسّمها إلى أجزاء صغيرة كي لا يُفقد شيء. فحتى جمع المتناثر يستلزم هذا القدر من الحرص."},"ICON-0870":{"nm":"حامل طبشور الخياطة","de":"حاملٌ يُمسك بطبشور الخياطة الذي يرسم خطوطًا على القماش بشكل مريح في اليد. يسند بإحكام شيئًا سهل الانكسار. فالعزم الهادئ قبل حمل المقص يقول إن الخط الأول المستقيم يجعل الثوب مستقيمًا أيضًا."},"ICON-0871":{"nm":"برطمان دبابيس التثبيت","de":"داخل البرطمان الشفاف، تصطدم دبابيس التثبيت وتُصدر صريرًا خفيفًا. ارفعه أمام الضوء ويستقر بريقٌ صغير عند طرف كل إبرة. وعاءٌ متين يجمع في مكانٍ واحد ما يشكّل خطرًا حين يتناثر، وينيمه برفق."},"ICON-0872":{"nm":"لفافة شريط الترقيع","de":"شريطٌ سحري يلتصق بهدوء حين تُمرَّر عليه المكواة فوق مكان ممزق. دون غرزة إبرة واحدة، يلتئم ثوبٌ بالٍ برفق. والقلب الذي رقّع بدل أن يرمي، ملفوفٌ طبقة فوق طبقة داخل اللفافة الدائرية."},"ICON-0873":{"nm":"ورقة قالب الرقعة","de":"ورقة قالب رُسم عليها شكل الرقعة مسبقًا. خطٌ منقّط يرشد بحنان الطريق الذي سيسلكه المقص. رسم مخطط ما تريد صنعه أولًا، فالترقب يبدأ دومًا من هذا الرسم الأولي الباهت."},"ICON-0874":{"nm":"غطاء برطمان الألوان المائية","de":"غطِّه فوق فوهة البرطمان ولن تتسرب قطرة، مهما تلاطم الماء الملون بداخله. يغطي حتى القلق من انتشار ماء الشطف العكِر على المكتب. سدادةٌ هادئة تحرس بصمت مكان الرسم."},"ICON-0875":{"nm":"شريط حماية أقلام الباستيل","de":"لُفّ شريطًا حول قلم الباستيل الذي يترك مسحوقًا باهتًا، وتقلّ اتساخ أصابعك. ورقة تحتضن برفق اللون الرقيق كي لا يتفتت. فكلما كان أطرى، وجب مسكه بلطف أكبر كي يُلوَّن برقة على الورقة أيضًا."},"ICON-0876":{"nm":"غطاء تطويل قلم التلوين","de":"ركّب غطاءً في طرف قلم تلوين قصير متآكل، وتعود قطعة منه تطول من جديد. قلبٌ لا يرمي شيئًا بسهولة لمجرد أنه قصر. ومن أطراف أصابع تستخدمه حتى النهاية، يكتمل لون الرسمة أشدّ عمقًا حتى آخر مربع."},"ICON-0877":{"nm":"خطاف كوب غسل الفرشاة","de":"علّق كوب الشطف على خطاف، وتنساب قطرات الماء المتساقطة من الفرشاة رويدًا. قبل تلوين اللون التالي، سكونٌ قصير صافٍ لشطف الفرشاة. وحتى في صوت النظافة يتدفق إيقاعٌ هادئ."},"ICON-0878":{"nm":"غطاء سكين الباليتة","de":"غطاءٌ صغير يُغلّف بإحكام نصل السكين الذي يفرد الألوان ويكشطها. يحرس بهدوء الطرف الحاد كي لا يبهت. وقوام اللون المطليّ بسمك يولد من هذه الحافة المُعتنى بها جيدًا."},"ICON-0879":{"nm":"مشبك القماش الكانفاس","de":"مشبكٌ متين يشدّ قماش الكانفاس بقوة على الإطار ويثبّته. اعضضه بإحكام ويتمدد سطح الرسم مشدودًا كالطبل. وبوجود أرضية لا تهتز، تصبح ضربات الفرشاة الجارية فوقها حرة بكل ما تحمله من معنى."},"ICON-0880":{"nm":"حزام لوحة الرسم","de":"علّق الحزام على كتفك ويتبعك اللوح خلف ظهرك. استقر أينما شئت، وذلك المكان يغدو استوديوك الخاص. استوديو صغير يُحمَل على الظهر، ينطلق بخفة بحثًا عن منظرٍ يستحق الرسم."},"ICON-0881":{"nm":"أنبوب ألوان الأكريليك","de":"قطرة ماء إضافية تصنع الفجر، وقطرة أقل تصنع منتصف الليل. نفس الأزرق يفتح في كل مرة سماءً مختلفة عند أطراف الأصابع. ولحظة عصر أنبوب واحد، ينتشر لون قلب اليوم فوق الورقة."},"ICON-0882":{"nm":"ورقة عينة التدرج اللوني","de":"هذه الورقة عرفت أولًا أن الغروب لا يحمرّ دفعة واحدة. درجات صغيرة تعبر من الباهت إلى الغامق. والعين تمشي ببطء بينها، متتبّعة بهدوء وقت نضج اللون."},"ICON-0883":{"nm":"غطاء إبرة الكروشيه","de":"درعٌ صغير بحجم كُشتبان تُركّبه قبل أن يغرز الخيط في إصبعك. تعرف اليد الممارسة للحياكة طويلًا أن عدم التأذي وحده يتيح إيصالها بحنان حتى الغرزة الأخيرة."},"ICON-0884":{"nm":"علامة حلقة الحياكة","de":"علامة واحدة تعيد الوضوح إلى أين وصلتَ. راحة عدم عدّ الغرزة نفسها مرتين. وهكذا القلب أيضًا، لا يضل طريقه إلا حين يُشير برفق إلى المكان الذي أتى منه."},"ICON-0885":{"nm":"تعليقة عداد الصفوف","de":"دليلٌ هادئ على إتمام صفٍّ واحد يتراكم خانةً خانة. حتى العمل الذي بدا بلا نهاية، إذا عُدّ واحدًا واحدًا، يتجاوز فجأة نصفه. وحسابٌ صغير يُبقي قلب اليوم صامدًا حتى النهاية."},"ICON-0886":{"nm":"دبوس ترتيب طرف الخيط","de":"اترك طرف الخيط المنفلت كما هو، ولن تعرف أين ستتشابك العقدة التالية. لمسة تُرتّب سلفًا مكانًا لن يُرى. فالحنان، غالبًا، يتحرك أولًا في الأماكن غير الظاهرة، هكذا تمامًا."},"ICON-0887":{"nm":"حبل تدريب العقد","de":"عقدة بسيطة، وعقدة فراشة، وعقدة حلقية. تربط الحبل نفسه وتحلّه مرارًا حتى تحفظ اليد الشكل. وحين تصبح الأصابع الخرقاء سلسة فجأة ذات ليلة، يكون ذلك الخيط الواحد أول من يعلم."},"ICON-0888":{"nm":"شريط ملصق خيوط الصوف","de":"شريطٌ صغير يدوّن على كل كبّة سماكتها ولونها. عادة نشأت من ليالٍ قضيتها تبحث عبثًا عن نفس الخيط بعد نفاده. فالتدوين مذكرة حنونة موجهة إلى نفسك في المستقبل."},"ICON-0889":{"nm":"قطعة مسطرة القياس","de":"كم غرزة تدخل في عشرة سنتيمترات - هذا الرقم الصغير يحدد مقاس ثوبٍ كامل. وأن قطعة بحجم راحة اليد تحمل مقاس الكل، أمرٌ ثقيل الوزن حقًا حين تحمله."},"ICON-0890":{"nm":"علامة ثقب الزر","de":"قبل خياطة الزر، تضع نقطة واحدة أولًا حيث ستُصنع الفتحة. بفضل تلك العلامة التي ستختفي قريبًا، لن يعوجّ جيب الثوب. فالحرص يبقى غالبًا هادئًا في مكانٍ لا يُرى في النهاية."},"ICON-0891":{"nm":"حلقة الشرابة الصغيرة","de":"كالشرابة عند طرف النوريغيه، تصنع حلقة صغيرة تأرجحًا. وما يتدلى ويتمايل بهدوء يبقى دومًا محطّ نظر الإنسان. نسيجٌ يحيا بصمتٍ حركةً كلما مرّت نسمة ريح."},"ICON-0892":{"nm":"زجاجة الطلاء الصغيرة","de":"ليس التوفير، بل الاستخدام الدقيق هو طريقة التعامل السليم مع الطلاء. لونٌ تكفيه قطرة واحدة، تُقاس بيدٍ توضع بجانب الزجاجة الصغيرة. فالاعتدال يأتي من التخلي عن الجشع، ولو مرة واحدة."},"ICON-0893":{"nm":"عود صنفرة صغير","de":"تبدأ من السطح الخشن وتنتقل تدريجيًا إلى الأنعم. لا يوجد سطح في أي مكان يصبح أملسًا بمرورٍ واحد. من أطراف أصابع تخفض الخشونة درجة بعد درجة، يلين المكان الخشن ببطء."},"ICON-0894":{"nm":"حامل ملقط النماذج","de":"أمسك قطعة مغراة بيدك وستترك بصمة إصبعك. اقرصها برفق بالملقط وتتحرر يداك، ويكتمل الجفاف بهدوء وحده. حتى الانتظار يخفّ حين يسنده أحدهم عنك."},"ICON-0895":{"nm":"لوحة عمل الغراء","de":"تسقط قطرة غراء واحدة على المكتب فيبقى أثرها طويلًا. عادة وضع لوحة واحدة أولًا. ونصف العمل، ربما، يبدأ من تلك الرغبة بالذات في عدم تلويث المكان."},"ICON-0896":{"nm":"خانة تصنيف القطع","de":"اخلط عشرات القطع المتشابهة الشكل وسيتحول التجميع سريعًا إلى متاهة. لمسة تقسيمها في كل خانة تختصر سلفًا وقت التيه القادم. فالترتيب لطفٌ يُقدَّم إلى نفسك في المستقبل."},"ICON-0897":{"nm":"رقعة ترتيب التجميع","de":"رقعة صغيرة تدوّن أي قطعة برقمها تُركَّب أولًا. التزم بالترتيب ولن ينهار بسهولة. والنموذج، وأي يوم يُبنى خطوة بخطوة بتأنٍ، يزداد صلابة فوق ذلك الوعد الهادئ."},"ICON-0898":{"nm":"خطاف الفرشاة الصغير","de":"ضع فرشاة مستخدمة مستلقية وينضغط شعرها وينحني. مكانٌ يُعلَّق فيه رأسًا على عقب لتصريف الرطوبة. من يبقي أدواته قريبة منه طويلًا، يكون بعد انتهاء العمل أكثر انشغالًا وحنانًا لا العكس."},"ICON-0899":{"nm":"وعاء قصاصات البلاستيك","de":"وعاءٌ تتجمع فيه بهدوء الفضلات المقصوصة من الإطار. تبدو مهملة، لكنها يومًا ما تعود تفصيلًا صغيرًا. يعرف الوعاء، منتظرًا بصمت، أن حتى المتبقي له دوره."},"ICON-0900":{"nm":"غطاء بخاخ الطلاء النهائي","de":"الطبقة الأخيرة، إن رُشّت من قربٍ شديد، تنساب مباشرة إلى الأسفل. من مسافة شبر، بخفة، بخفة. وإضفاء اللمعان هو، ربما، أيضًا تمرين على التخلي عن جشع القلب ولو لمرة واحدة."},"ICON-0901":{"nm":"علبة رصاص القلم","de":"الرصاص الرفيع سريع الانكسار في الجيب، لكنه حين يُرقَّد بهدوء وترتيب داخل علبة صغيرة لا يضيع منه عود واحد سدى. الترتيب، في نهاية الأمر، هو ذلك الصمت الرقيق الذي يدّخر به المرء غده مسبقًا."},"ICON-0902":{"nm":"غلاف الممحاة","de":"معطف ورقي صغير يُلبَس للممحاة. وكلما اسودّ من كثرة اللمس، تراكمت فيه آثار التصحيحات أكثر فأكثر. والمحو في جوهره إذنٌ رقيق بأن نعود إلى البداية من جديد ولا بأس في ذلك."},"ICON-0903":{"nm":"أنبوب حفظ ريشة القلم","de":"ريشة القلم تتشقق إذا جفّت، وتنحني إذا اصطدمت بشيء. أنبوب صغير يُرقدها منفردة يحفظ نسيج الكتابة سليمًا لزمن طويل. فالأداة التي تُعامَل برفق تنزلق برفق أيضًا حين تردّ الجميل."},"ICON-0904":{"nm":"عيّنات حبر القلم","de":"أحبار تُختبر قطرة قطرة. اللون الذي بدا فيروزيًا يتحول على الورق إلى بحر عميق داكن. فاللون لا يُعرف إلا باللقاء المباشر؛ إذ كثيرًا ما يخطئ اللون الذي نتخيله في القلب هدفه."},"ICON-0905":{"nm":"علبة أسهم الفواصل","de":"علم صغير يُدسّ برفق في الموضع الذي توقفت عنده القراءة. حين تفتح الكتاب في المرة القادمة، تجد أمس نفسه يلوّح لك منتظرًا. حتى المكان الذي توقفنا عنده يصبح وعدًا، بفضل عمل تلك العلامة الصغيرة الرقيق."},"ICON-0906":{"nm":"علبة أعلام الملاحظات اللاصقة","de":"انزع ورقة واحدة والصقها، فتبدأ القصة من هناك مجددًا على الفور. وحين تصطف الأعلام الصغيرة على حافة الكتاب، تجتمع الأفكار المتناثرة بعناية في خريطة واحدة."},"ICON-0907":{"nm":"مغناطيس تجميع المشابك","de":"مغناطيس صغير يجمع المشابك المتناثرة دفعة واحدة. فكلما صغُر الشيء سهُل ضياعه، وهذه القوة الجامعة الواحدة تُنقذ المكتب الفوضوي بهدوء. فحتى في الجذب رقّة."},"ICON-0908":{"nm":"طاقم أغطية أقلام الرصاص","de":"قبعات صغيرة تغلّف أطراف الأقلام وتحمي داخل الحقيبة. فكل شيء حاد لا بد أن يوخز شيئًا، لذا يحتاج إلى يد تغطيه برفق. كي يبقى حادًا دون أن يُحدث أذى."},"ICON-0909":{"nm":"ملصق لوحة اسم المكتب","de":"لحظة تكتب اسمك وتلصقه على المكتب، يصبح ذلك المكان أخيرًا ملكًا لأحد. فحين يجد حيّز بمساحة شبر واحد صاحبًا له، تتغير من فورها الطريقة التي يستقر بها القلب هناك."},"ICON-0910":{"nm":"غطاء مقبض حبل القفز","de":"غطاء يُلبَس قبل أن يتشقق طرف المقبض ويتآكل. إيقاع الحبل الذي دار أكثر من ألف مرة، تتذكره راحة اليد قبل أن يتذكره العقل. فالنغمة المحفورة في الجسد لا تُنسى بسهولة."},"ICON-0911":{"nm":"حزام حلقة اليوغا","de":"أمسك الحلقة وافتح جسدك ببطء. وكلما شدّ الحزام أكثر، انفكت الكتفان المتيبستان طبقة بعد طبقة. فالتمدد ليس شدًا بالقوة، بل هو أقرب إلى الانتظار الهادئ حتى ينفتح الجسد من تلقاء نفسه."},"ICON-0912":{"nm":"علبة كرة تنس الطاولة","de":"كرة بيضاء خفيفة تتدحرج بعيدًا، وتتحطم فور أن تدوسها قدم. علبة صغيرة واحدة تحمي تلك الكرة الهشة حتى المباراة القادمة. فالمتانة كثيرًا ما تأتي من الاحتواء اللطيف."},"ICON-0913":{"nm":"شريط مقبض مضرب الريشة","de":"طبقة واحدة أنيقة تُلفّ حول مقبض ينزلق بفعل العرق. وفوق مقبض ملفوف بإحكام، تصبح المضرب جزءًا من اليد. وسرّ اللعب بالإحساس لا بالقوة يكمن في هذه الطبقة الرقيقة الواحدة."},"ICON-0914":{"nm":"رقاقة النقاط الصغيرة","de":"نقطة، ثم نقطة أخرى. بتحريك الرقاقات الصغيرة، تتراكم النقاط شيئًا فشيئًا. وحين تكون الحصيلة مرئية، تزداد المباراة وضوحًا، وتنبثق بهدوء شجاعة اللحاق بفارق نقطة واحدة."},"ICON-0915":{"nm":"مشبك اتجاه الحذاء الرياضي","de":"مقدّمتا الحذاء الموضوعتان بعناية تنظران دائمًا في الاتجاه نفسه. لمسة يد بسيطة تديرهما قليلًا عند خلعهما. ترتيب صغير كهذا يجعل خطوات صباح الغد أكثر خفة."},"ICON-0916":{"nm":"سلسلة صافرة الحكم","de":"حين تُعلَّق الصافرة حول العنق، يُمنَح صاحبها حق قول قف. منظر ملعب بأكمله يتوقف دفعة واحدة عند نفخة قصيرة واحدة. والقلوب التي تثق بذلك الصوت الصغير تجتمع فتصبح وعدًا."},"ICON-0917":{"nm":"أنبوب إبرة منفاخ الكرة","de":"حتى الكرة الفارغة من الهواء تعود مشدودة بإبرة رفيعة واحدة. تلك الإبرة المصانة بعناية في أنبوب صغير، تجعل المنفاخ كله عديم الجدوى في لحظة ضياعها. فأصغر شيء قد يكون أهم شيء."},"ICON-0918":{"nm":"مخروط علامة صغير","de":"من هنا إلى هناك، يرسم مخروط صغير حدًا لم يكن مرئيًا من قبل. ودون أي خط، يصطف الناس بشكل طبيعي متبعين تلك العلامة. فالنظام ينمو بهدوء من إشارات صغيرة كهذه."},"ICON-0919":{"nm":"كيس القطع النقدية","de":"كيس يجمع القطع الرنّانة في مكان واحد. اربط فوهته فلا يتناثر منها شيء. حتى الأشياء الصغيرة التافهة تحتاج مكانًا تُحفظ فيه لتؤدي دورها أخيرًا، وهذا ما يُظهره الكيس دون كلمة."},"ICON-0920":{"nm":"سجادة خلط الأوراق","de":"على مكتب أملس، لا تستقر الأوراق جيدًا في اليد. سجادة واحدة تجعل الخلط والالتقاط أكثر سلاسة. فحتى في اللعب الجيد، ثمة تحضير رقيق يبدأ باختيار السطح أولًا."},"ICON-0921":{"nm":"واقي زوايا لوح اللعبة","de":"حين تنتهي ليلة الألعاب اللوحية، يهتم أحدهم بصمت بزوايا اللوح الأربع أولًا. لأنه يعرف أن الثنية العميقة تُعوّج الجولة القادمة. وفي أطراف الأصابع التي تُسوّي الحواف، يكمن الرغبة في اللعب معًا مجددًا غدًا."},"ICON-0922":{"nm":"غطاء كوب النرد","de":"تلك اللحظة القصيرة حين يهزّ الجميع الكوب، ويُدحرجونه، ويحبسون أنفاسهم معًا. إنه سقف صغير يمنع النرد من الهروب. وتحت الغطاء، يلتقط حظ اليوم أنفاسه للحظة، ثم يخرج متدحرجًا بصوت خشخشة."},"ICON-0923":{"nm":"لوح تسوية القطع","de":"كلما ازداد حماس اللاعب، اعوجّ صفّه أكثر. مهمة دفع القطع المائلة برفق لتصطف من جديد. فالتسوية هي يد تستقبل بلطف تسرّع أحدهم المتحمس."},"ICON-0924":{"nm":"علبة رقائق النقاط","de":"كلما امتلأت العلبة برقائق النقاط، سخنت اللعبة معها. وحين تتصادم النقاط المستديرة بصوت خشخشة داخل راحة اليد، تصبح تلك الجلبة مصدر متعة قبل الفوز أو الخسارة."},"ICON-0925":{"nm":"خاتم علامة الدور","de":"خاتم صغير يخبرك أن دورك قد حان الآن. وللحظة واحدة حين تحرّكه إلى فتحة جديدة، تجتمع أنظار الجميع عليّ بهدوء. حلقة تدور ببطء بين الانتظار والترقب."},"ICON-0926":{"nm":"قاعدة قطعة اللعبة","de":"كلما كانت القطعة أسهل سقوطًا، وجب أن تكون قدمها أرسخ. قاعدة واحدة تحفظ مكانها حتى فوق لوح مهتزّ قليلًا. فالشيء الصغير يجب أن يصمد كي يقف الشيء الكبير فوقه شامخًا."},"ICON-0927":{"nm":"مشبك كتيب التعليمات","de":"كتيب التعليمات يترك صفحاته تنقلب خلسة دائمًا وهو مفتوح. قبل أن تهرب الصفحات مع النسيم، يعضّ هذا المشبك صفحة واحدة بهدوء. فالقواعد يجب أن تُثبَّت كي تستمر اللعبة حتى النهاية."},"ICON-0928":{"nm":"رباط علبة ريشة الغيتار","de":"ريشة الغيتار تفلت من الأصابع دائمًا في أكثر اللحظات إثارة. رباط واحد معلّق بالعلبة يمنع ذلك الهروب الصغير. ولا يقدّر هذا الرباط إلا من عاش ليلة توقفت فيها الموسيقى."},"ICON-0929":{"nm":"أنبوب حفظ الريشة الموسيقية","de":"الريشة تفقد صوتها في اللحظة التي تجفّ فيها. داخل أنبوب رطب، تنتظر شظية رفيعة من القصب عزفها القادم. إنه مكان يُهدأ فيه النَفَس أولًا، قبل أن يُنفَخ فيه من جديد."},"ICON-0930":{"nm":"مفتاح تغيير أوتار الآلة","de":"حين يرتخي الوتر، تنخفض النغمة معه خلسة. إدارة المقبض ببطء لاستعادة الشدّ، فالعناية تأتي دائمًا من طرف المعصم. والصوت المتقن يبدأ من هذا الترتيب الصغير."},"ICON-0931":{"nm":"قماش تنظيف الآلة الموسيقية","de":"حين ينتهي العزف، يبقى على الآلة أثر عرق خفيف أيضًا. مسحة واحدة بقماش ناعم تعيد اللمعان وتُرسي نغمات اليوم بهدوء. فالقلب المُحبّ يظهر دائمًا في اللمسة الأخيرة."},"ICON-0932":{"nm":"غطاء مسمار الضبط","de":"تصدأ مسامير الضبط دون أن نشعر إن تُركت عارية. غطاء صغير واحد يؤخر فصول الصدأ على المعدن خطوة واحدة. ومن يعتني بالزوايا غير المرئية أولًا، هو من يعزف طويلًا."},"ICON-0933":{"nm":"مصباح مشبك حامل النوتة","de":"خلف الكواليس المظلمة، ثمة لحظات يجب أن يضيء فيها النوتة وحدها. مصباح صغير يُثبَّت بحامل النوتة، يرسل ضوءه برفق إلى الأسفل. حفنة من الضوء تنير الطريق كي لا تضيع النغمات."},"ICON-0934":{"nm":"غطاء كتم صوت التدريب","de":"تدريب الفجر يتشاجر دومًا بهدوء مع نوم الجيران. أدخل غطاءً واحدًا فيتحول الصوت الجهير إلى همس. فثمة موسيقى تنمو وهي تحرس نوم أحدهم الهانئ."},"ICON-0935":{"nm":"ملصقات لوحة الطبل","de":"علامات صغيرة ملصقة فوق لوحة الطبل. أين تضرب لتحصل على أي صوت، تتعلمه العين قبل أن تحفظه اليد. هكذا يُنقش الإيقاع في الجسد ببطء."},"ICON-0936":{"nm":"رقاقة تدوين اللحن","de":"اللحن الذي كنت تدندنه يتلاشى سريعًا إن لم تمسك به. بضع نغمات مدوّنة على عجل فوق رقاقة، قد تنمو يومًا لتصبح أغنية كاملة. فالإلهام يعود دائمًا إلى اليد التي تدوّن بجدّ."},"ICON-0937":{"nm":"رباط غلاف الكتاب","de":"مزعج أن ينفتح كتاب نصف مقروء من تلقاء نفسه داخل الحقيبة. رباط واحد يربط الصفحات بهدوء فتصبح مطواعة. إنه وعد بطيّ الأمور بترتيب من أجل الصفحة القادمة."},"ICON-0938":{"nm":"خاتم ماسك الصفحات","de":"يوم تريد فيه أن تُمسك الكتاب مفتوحًا بيد واحدة وتحتسي قهوة دافئة. خاتم يُلبَس في الإصبع يمسك الصفحات نيابة عنك. فالراحة الصغيرة تبدأ من اختراعات بسيطة كهذه."},"ICON-0939":{"nm":"رقاقة مؤقت القراءة","de":"تجلس لتقرأ فصلًا واحدًا فقط، وإذا بالليل يتعمّق فجأة. اضغط الرقاقة لتحدد وقتًا، فتنال القراءة أيضًا فاصلة راحة. فكلما أحببنا شيئًا أكثر، احتجنا شجاعة رقيقة لنعرف متى نتوقف."},"ICON-0940":{"nm":"غطاء واقي زوايا الكتاب","de":"الكتاب المحبوب أكثر، يبلى من زواياه خلسة أولًا. غطاء واحد يُلبَس فتبقى أطراف الغلاف مستديرة ومحمية. إنه درع صغير يُلبَس لصون رغبتنا في الاحتفاظ بشيء طويلًا طويلًا إلى جوارنا."},"ICON-0941":{"nm":"شريط ملاحظات القراءة","de":"ثمة لحظات يهبط فيها سطر واحد كالثقل في الصدر. انطباع مدوّن على شريط يبقى في تلك الصفحة كإشارة مرجعية. إنها الحرارة الدافئة للخط الذي رُسم تحت الكلمات، لا يعرفها إلا من قرأ."},"ICON-0942":{"nm":"بطاقة إرجاع المكتبة","de":"يأتي موعد الإرجاع دائمًا وكأنه أبكر بيوم. حين يدفع التاريخ المكتوب على البطاقة ظهرك بهدوء، يكتسب الكتاب المستعار أدب النهاية أيضًا. من أجل يدَي القارئ القادم، تنتظر المكتبة على هذا النحو."},"ICON-0943":{"nm":"مشبك إضاءة الكتاب","de":"ليلة تسهر فيها وحدك تقرأ بجانب عائلتك النائمة. يكفي ضوء صغير واحد مثبّت بمشبك على حافة الكتاب. لا حاجة لدفع الظلام كله بعيدًا؛ صفحة واحدة تكفي لوقتٍ هادئ."},"ICON-0944":{"nm":"بطاقة رائحة الكتاب","de":"تفوح من الكتب القديمة رائحة يمتزج فيها ضوء الشمس بالورق. بطاقة يُقال إنها تحمل تلك الرائحة في ورقة واحدة، تفتحها فتبعث زقاق مكتبة الكتب المستعملة لحظة إلى طرف أنفك. فالذاكرة تضع إشارتها أيضًا برائحة."},"ICON-0945":{"nm":"دبوس علامة الصفحة المقروءة","de":"إلى أين وصلت بالقراءة؟ دبوس صغير يمحو ذلك السؤال الحائر. ثبّته في الجملة الأخيرة فلا يتوه غدك أكثر. علامة رقيقة تتذكر مكانك الذي توقفت عنده نيابة عنك."},"ICON-0946":{"nm":"تعليقة سلسلة الهاتف","de":"تعليقة واحدة معلّقة بسلسلة الهاتف تجعل صاحبها يبدو مختلفًا قليلًا. لون مفضّل، شكل مفضّل. ذوق صغير في قبضة اليد يهزّ مزاج ذلك اليوم برفق."},"ICON-0947":{"nm":"غطاء واقي عدسة الكاميرا","de":"مصير صور السفر معلّق على عدسة واحدة. لحظة رفع الغطاء الواقي هي بالضبط استعداد القلب لضغط الغالق. طقس صغير هو أول من يفتح عينيه قبل التقاط المشهد."},"ICON-0948":{"nm":"سدادة منفذ الشحن","de":"الغبار داخل الحقيبة يستهدف دائمًا فتحة الشحن أولًا. سدّ تلك الفتحة الصغيرة بسدادة واحدة يبقي الطرف نظيفًا لزمن طويل. هنا اجتهاد يعتني حتى بالثغرات غير المرئية."},"ICON-0949":{"nm":"حلقة حامل الهاتف المنبثقة","de":"إمالة الهاتف قليلًا لمشاهدة مقطع بارتياح. افتح الحلقة الملتصقة خلفه فتشعر اليد والشاشة براحة أكبر. حامل صغير مرتفع يمدّ ساعة مسائية هادئة قليلًا."},"ICON-0950":{"nm":"رقعة تنظيف الشاشة","de":"شاشة مليئة بالبصمات تجعل القلب أيضًا يبدو ضبابيًا نوعًا ما. مسحة واحدة برقعة، فيعود العالم واضحًا من جديد. فالنظافة أحيانًا مهمة قصيرة بلمسة إصبع واحدة."},"ICON-0951":{"nm":"علبة دبوس شريحة الاتصال","de":"دبوس إخراج شريحة الاتصال جنّية لا تختفي إلا في اللحظة التي تحتاجها فيها فعلًا. احفظه في فتحة واحدة من علبة، فلا تعود تفتّش المنزل كله بحثًا عن دبوس شعر. ترتيب صغير ينقذ بهدوء لحظة طارئة."},"ICON-0952":{"nm":"ملصق لوحة الشحن اللاسلكي","de":"ليلة يمتلئ فيها الهاتف من تلقاء نفسه بمجرد أن تضعه بهدوء على اللوحة. ملصق لاصق يحدد برفق المكان الذي يجب أن يرقد فيه الهاتف. تيار غير مرئي يملأ بصمت طاقة يوم كامل."},"ICON-0953":{"nm":"ملصق حجب الإشعارات","de":"الإشعارات التي لا نرغب في رؤيتها، تكون أريح للقلب مغطاة. ملصق واحد يُخمد ذلك الوهج الصغير عند الفجر. فأحيانًا عدم النظر أيضًا طريقة رقيقة لحماية النفس."},"ICON-0954":{"nm":"حلقة حماية العدسة","de":"في تلك اللحظة التي تلامس فيها عدسة الكاميرا الأرض، يهوي القلب فجأة. حلقة واحدة ملتفة حولها تصدّ بهدوء تلك السقطة الصغيرة. إطار يحمي أولًا العين التي تلتقط الذكريات."},"ICON-0955":{"nm":"بطاقة اسم الكابل","de":"تمييز كابلك من بين كومة متشابكة من الأسلاك المتشابهة. بطاقة واحدة تمنح سلك الشحن أخيرًا اسمه الخاص. علم صغير يدلّ على الطريق وسط أسلاك فوضوية."},"ICON-0956":{"nm":"حقيبة الشواحن","de":"الشواحن داخل حقيبة السفر تتشابك وتتشاجر دائمًا فيما بينها. تجميعها بترتيب في جيب واحد من الحقيبة يجعلها تتصالح أخيرًا. وفن التعبئة يكمن في جمع المتناثر برفق في مكان واحد."},"ICON-0957":{"nm":"ملصق منافذ لوحة الكهرباء","de":"فتحات لوحة الكهرباء المتعددة تتشابه جميعها فتُربك في كل مرة. الصق عليها ملصقات لتحدد مكان كل جهاز، فيصبح الصباح المزدحم أكثر سهولة. بطاقة اسم صغيرة تقلّل من المشاحنات اليومية التافهة."},"ICON-0958":{"nm":"بكرة لفّ الأسلاك","de":"يوم منظم للسلك، يُفكّ للاستخدام ثم يُلفّ من جديد. لفّه بترتيب حول بكرة واحدة يجعل التشابك يختفي تمامًا. واليد التي تعيد الأشياء إلى مكانها بعد استخدامها تجعل الغد أخف."},"ICON-0959":{"nm":"غطاء موصل مغناطيسي","de":"الموصل المغناطيسي يجذب دون أن ندري غبار المعادن الدقيق. غطّه بغطاء فلا يعلق به الغبار اللزج. والجهاز الذي تلمسه يد حريصة مرة إضافية، يعيش بقربنا وقتًا أطول."},"ICON-0960":{"nm":"رباط البطارية المحمولة","de":"إذا تُركت البطارية المحمولة وكابلها منفصلين، يختفي أحدهما لا محالة. ربطهما معًا بشريط يجعلهما أخيرًا زوجًا واحدًا. عقدة صغيرة تُربط برفق قبيل الخروج، تقول لهما: سافرا معًا."},"ICON-0961":{"nm":"غطاء غبار المقبس","de":"فتحة المقبس الفارغة يستقر فيها الغبار خلسة بعد أيام قليلة فقط. حين يحرس هذا الغطاء الصغير مكانه نيابة عنها، يستطيع الشاحن القادم أن يستنشق نفَسه الأول نظيفًا. حارس بوابة يحفظ الفراغ نقيًا طوال غيابه."},"ICON-0962":{"nm":"حلقة تلوين الكابل","de":"في ليلة قضيتها تتلمس سلكك بين الأسلاك المتشابكة، من الذي اقترح أن نلوّنها؟ الأزرق لك، والأصفر لي. بحلقة صغيرة واحدة، لم نعد نخلط بين أسلاكنا بعد الآن. أثر باقٍ في زاوية غرفة التدريب، لوعد رقيق قُطع بيننا."},"ICON-0963":{"nm":"رقاقة تصنيف المحوّلات","de":"أرجل مستديرة وأرجل مسطحة، مئة وعشرة أو مئتان وعشرون. رقاقة حفظت بهدوء وجوه المقابس المختلفة من بلد إلى آخر. وفي زاوية حقيبة السفر الأولى عبر البحر نحو المسرح، كانت هذه البطاقة الصغيرة للتصنيف تُدسّ دائمًا."},"ICON-0964":{"nm":"لوحة تصنيف رؤوس السماعات","de":"يُقال إن قناة الأذن تختلف عمقًا واتساعًا من شخص لآخر. وضع الأحجام الكبيرة والمتوسطة والصغيرة جنبًا إلى جنب، واختيار الزوج الذي يلائم أذنك تمامًا. إجراء رقيق يضبط الجسد أولًا، قبل الاستماع إلى الصوت."},"ICON-0965":{"nm":"حلقة سيليكون واقية للغلاف","de":"يُعتنى بأزياء المسرح حتى آخر غرزة فيها، بينما تصطدم زوايا الغلاف دائمًا عارية. حين يلفّ هذا الشريط السيليكوني الرفيع الحافة برفق، تستقبل الشاشة الصباح سليمة حتى بعد فجر انزلقت فيه من اليد."},"ICON-0966":{"nm":"ملصق إلغاء الضوضاء","de":"ثمة أيام نرغب فيها بإطفاء أصوات العالم قليلًا. هذا الملصق الصغير على أذن السماعة علامة تُشغّل السكون. تعويذة تأخذ صخب الجمهور وضجيج المترو إلى مسافة بعيدة، حتى انتهاء أغنية واحدة فقط."},"ICON-0967":{"nm":"طقم خطاطيف الأذن","de":"أثناء الرقص، تفلت إحدى سماعتي الأذن دائمًا أولًا. علّق هذه الخطاطيف التي تحتضن صيوان الأذن برفق، فتبقى الموسيقى وحدها في أذنك حتى النهاية وسط أعنف حركات الرقص. اكتشاف صغير تناقله أهل غرفة التدريب فيما بينهم."},"ICON-0968":{"nm":"غطاء فرشاة التنظيف","de":"قبعة صغيرة تُلبَس كي لا يتطاير الغبار العالق بأطراف الشعيرات من جديد. واليد التي كانت منذ زمن بعيد تنصب المكنسة مقلوبة بعد الكنس، كانت تعرف مسبقًا أن أدوات التنظيف تحتاج هي أيضًا إلى تنظيف."},"ICON-0969":{"nm":"وسادة قاعدة محطة الشحن","de":"كانت محطة الشحن تنزلق دائمًا فوق المكتب لأنها بلا أقدام. وحين حلّت هذه الوسادة الرقيقة الملصقة أسفلها محل الأقدام، استقر الجهاز في مكانه وامتلأ بهدوء بالطاقة طوال الليل."},"ICON-0970":{"nm":"علامة تمييز اليمين واليسار","de":"حرف L لليسار، وحرف R لليمين. تُوضع نقطة إضافية لتُميَّز باللمس حتى في الظلام. والرغبة في ألا تُخطئ القدم اليسرى واليمنى على المسرح ولو مرة واحدة، محفورة كاملة على هذه العلامة الصغيرة."},"ICON-0971":{"nm":"غطاء مقبس موزّع الصوت","de":"ذلك المقبس الذي شارك فيه كثيرون صوتًا واحدًا، يجب سدّ طرفه أثناء الراحة. كي لا يتسرب الغبار إلى الدائرة. لمسة يد صغيرة حذرة، ترغب في إرسال الأغنية التي استمعنا إليها معًا صافية في المرة القادمة أيضًا."},"ICON-0972":{"nm":"بكرة لفّ سلك السماعة","de":"كحركة اليد القديمة في لفّ خيط الغزل، يصبح سلك السماعة أنيقًا حين يُلفّ هنا في دائرة. لحظة تنتظم فيها الموسيقى التي كانت تتقلب متشابكة داخل الحقيبة. وسيصبح فكّها في الغد أخف بكثير."},"ICON-0973":{"nm":"رباط حامل غطاء العدسة","de":"في كل مرة تفتح فيها العدسة، كان الغطاء يفقد وجهته دائمًا. اربطه بحزام موصول بجانب الكاميرا، فلا تعود تتلمس الجيب عبثًا. أن نربط الشيء إلى جوارنا كي لا نفقده، أمر تعلمته اليد أولًا."},"ICON-0974":{"nm":"تعليقة غطاء منفذ الفلاش","de":"في منفذ الفلاش الفارغ أعلى الكاميرا، تُدسّ زخرفة صغيرة برفق. تلك التعليقة الوحيدة التي لا وظيفة لها على الإطلاق، تجعل المعدّات الثقيلة الجافة تبدو فجأة عزيزة كأنها ملكك الخاص. إنه فعل التعلّق بأداة."},"ICON-0975":{"nm":"إبزيم ضبط الحزام","de":"كلما غاص حزام الحقيبة في الكتف، تُرخي هذا الإبزيم أو تشدّه قليلًا. لمسة إصبع واحدة لاختيار طول يلائم جسدك. حتى حمل الأثقال، في نهاية المطاف، هو اعتناء بالنفس، هذا ما يخبرك به الإبزيم بهدوء."},"ICON-0976":{"nm":"علبة تكديس المرشحات","de":"بيت صغير تُرقَّد فيه قطع الزجاج التي تشقّ الضوء طبقة فوق طبقة. ضباب وصفاء، غروب وليل. وكأنها درج يُختار فيه الطقس ويُحفظ مسبقًا، يفتح المصور هذه العلبة دائمًا أولًا قبل أن ينطلق في طريقه."},"ICON-0977":{"nm":"غطاء منفاخ الغبار","de":"الكرة المطاطية التي تنفث الهواء لطرد الغبار، فوهتها أيضًا ضعيفة أمام الغبار بالقدر نفسه. أثناء الراحة، تُغطّى بهذا الغطاء. وهناك شيء رقيق في أداة تمسح غيرها لكنها تغطي فمها أولًا بهدوء."},"ICON-0978":{"nm":"غطاء زر الغالق","de":"أن يُضغط الغالق من تلقاء نفسه داخل الحقيبة، فيلتقط مئة صورة لسماء فارغة، أمر يمرّ به الجميع مرة على الأقل. هذا الغطاء الصغير فوق الزر يمنع ذلك الجهد الضائع. قفل صغير، كي لا يُحفظ سوى اللحظات التي نرغب فعلًا في الاحتفاظ بها."},"ICON-0979":{"nm":"ملصق تصنيف البطاريات","de":"من الفوضى دائمًا أن تختلط البطارية الفارغة بالمشحونة في جيب واحد. ملصق ملوّن على كل بطارية يرتّب ذلك الالتباس بهدوء. الأحمر يعني فارغة، والأخضر يعني موثوقة. إشارة مرور صامتة تُترك مضاءة في موقع التصوير."},"ICON-0980":{"nm":"فاصل حقيبة الكاميرا","de":"تقسيم الحقيبة إلى أجزاء كي لا تصطدم العدسة والجسم والبطارية الاحتياطية ببعضها. فعل بناء غرف صغيرة عديدة داخل حمل واحد. لكل مكان صاحبه، فلا يفقد شيء موضعه مهما اهتزّت الحقيبة."},"ICON-0981":{"nm":"وسادة قفاز التصوير","de":"تصوير شتوي في العراء، حيث لا يجوز أن يبرد طرف الإصبع الذي يضغط الغالق وحده. وسادة سميكة في الراحة، وقفاز يترك الإحساس في أطراف الأصابع. حل وسط رقيق من الميدان، يمسك بيد واحدة الدفء والدقة معًا."},"ICON-0982":{"nm":"أنبوب رؤوس قلم اللوح الرقمي","de":"أن يبلى رأس القلم كسنّ الرصاص، أمر يعرفه من أمسك اللوح الرقمي طويلًا. هذا الأنبوب الصغير الذي جُمعت فيه الرؤوس الاحتياطية متدحرجة، أشبه بمدّخرات طارئة لطرف الإصبع، تعوّض الخطوط التي لا يجوز أن تنقطع."},"ICON-0983":{"nm":"صينية أغطية مفاتيح لوحة المفاتيح","de":"في اليوم الذي نزعت فيه كل مفتاح على حدة لتغسله وتعيده، صارت هذه الصينية سهلًا صغيرًا. منظر الحروف الساكنة والمتحركة راقدة خانة خانة تجفّف رطوبتها. فثمة عناية لا تُرى إلا حين نفكّك الشيء مرة واحدة."},"ICON-0984":{"nm":"طقم أقدام الفأرة","de":"سرّ انزلاق الفأرة بسلاسة فوق المكتب يكمن في هذه الأقدام الصغيرة الملصقة أسفلها. حزمة تُستبدل حين تبلى. عناء أشياء تسند بصمت النعومة من مكان غير مرئي."},"ICON-0985":{"nm":"وسادة حامل الحاسوب المحمول","de":"تشبه دفترًا، لكنها في الحقيقة وسادة مطاطية تسند الحاسوب المحمول. رفع الشاشة قليلًا إلى مستوى العين لفكّ عنق منحنٍ. عناية تُقوّم الوضعية، من أجل من يكتب ويحدّق طويلًا وطويلًا."},"ICON-0986":{"nm":"منزلق تغطية كاميرا الويب","de":"ادفع بإصبعك لتغطية العدسة، وادفع من جديد لفتحها. رغبة في أن تُرى فقط حين تريد أن تُرى. في هذا المنزلق الصغير الواحد يسكن الاطمئنان الكبير المسمى الخصوصية. وصوت الإغلاق يبعث نوعًا ما بالطمأنينة."},"ICON-0987":{"nm":"ملصق تصنيف وحدات USB","de":"خمس عصي سوداء متشابهة، ولا سبيل إطلاقًا لمعرفة ما تحمله كل واحدة. الصق عليها ملصقًا صغيرًا وامنحها اسمًا، عندئذ فقط تصبح واحدة من أفرادك. فلا بد للشيء من اسم يُنادى به كي يسهل إيجاده."},"ICON-0988":{"nm":"زوايا حصيرة المكتب","de":"حين تستمر زوايا حصيرة المكتب في الالتفاف للأعلى، يتعوج معها حتى الخط اليدوي. هذه القطع الصغيرة التي تضغط الزوايا الأربع برفق، تحرس السلام المستوي فوق المكتب. فلا بد أن يهدأ السطح كي تهدأ أطراف الأصابع أيضًا."},"ICON-0989":{"nm":"مشبك حامل الموزّع","de":"مشبك ينصب الموزّع، حيث تجتمع أسلاك كثيرة، مائلًا على حافة المكتب. منظر الأسلاك الفوضوية تجتمع وتترتب في نقطة واحدة. وحسّ ربط المتشابك في خصلة واحدة حيّ هنا أيضًا."},"ICON-0990":{"nm":"غطاء بخاخ تنظيف الشاشة","de":"سدادة صغيرة لفوهة بخاخ يمسح آثار الأصابع عن الشاشة. تُغلق دائمًا بإحكام كي لا يتسرب السائل أو يجفّ. فالنظر الواضح يستلزم أولًا أن نصون وسيلة التنظيف نفسها، هذا هو الترتيب المتواضع لشؤون البيت."},"ICON-0991":{"nm":"محفظة بطاقة الذاكرة","de":"أيام من لقطات المسرح تغفو بهدوء داخل بطاقة لا تكبر ظفرًا. فإذا ضاعت، اختفى يوم بأكمله دفعة واحدة، لذا تُجمع بعناية داخل محفظة صغيرة. بيت يحتضن أصغر الذكريات وأعظمها معًا."},"ICON-0992":{"nm":"حلقة ملصقات القرص الصلب الخارجي","de":"خمسة أقراص صلبة خارجية سوداء تغفو داخل الدرج بوجوه متطابقة. فعل إلصاق بطاقة وتسميتها «ذلك الصيف»، «مقاطع غير منشورة». عمل يُثبّت فهرسًا واضحًا فوق ذاكرة ضبابية."},"ICON-0993":{"nm":"رقاقة تحقق النسخ الاحتياطي","de":"هل اكتمل النسخ الاحتياطي أم لا، على ذلك الفارق الدقيق يتوتر القلب. هذه الرقاقة الصغيرة المدسوسة عند نقطة الانتهاء تخبرك: «إلى هنا، الأمر آمن». والطمأنينة تأتي من ترك علامة خلفنا."},"ICON-0994":{"nm":"رمز مذكرة السحابة","de":"رمز يُطلق سطر ملاحظة واحدًا نحو مخزن معلّق في مكان ما بالسماء. سحر صغير حيث تخرج تلك الكتابة لتستقبلك أينما شغّلت جهازك. سماء الليل التي كنا نطلق فيها طائرة ورقية ونكتب عليها أمنية، وكأنها استقرت الآن برفق فوق راحة اليد."},"ICON-0995":{"nm":"طقم أغطية حماية USB","de":"تُترك أطراف التوصيل مكشوفة تتقلب داخل الحقيبة، فلا بد أن تتلف نقاط التماس. غطّ كل طرف بقبعة صغيرة واحفظها كطقم واحد. فعل يُهدئ فترة عدم الاستخدام برفق. أهدأ تحضير للاتصال القادم."},"ICON-0996":{"nm":"رباط علبة البيانات","de":"رباط يلفّ ويُحكم إغلاقه حول جهاز يحمل بيانات ثمينة. لفّة واحدة تشدّه بإحكام كي لا يصطدم بشيء داخل حقيبة مهتزة. اليد التي كانت تعقد حزمة بعناية ذات يوم، ما زالت حيّة في العالم الرقمي أيضًا."},"ICON-0997":{"nm":"بطاقة تصنيف الملفات","de":"حين تتكدس مئات الملفات دون أسماء، يصبح البحث عنها تيهًا بحد ذاته. في اللحظة التي تُلصق فيها بطاقات ملونة وتفتح فروعًا، يظهر طريق وسط الكومة الفوضوية. فالترتيب، في النهاية، هو فعل شقّ طريق."},"ICON-0998":{"nm":"بطاقة تلميح كلمة المرور","de":"كتابة كلمة المرور كاملة خطر، وعدم كتابتها إطلاقًا يعني نسيانها. لذا نترك دليلًا وحيدًا لا يفهمه سوانا. مثل «تلك المدينة في أول حفل». طريقة ذكية ورقيقة للتذكر، تدوّن الطريق لا الجواب."},"ICON-0999":{"nm":"ملصق تاريخ التخزين","de":"إن لم تدوّن يوم الحفظ، يتحول التخزين قريبًا إلى نسيان. ملصق التاريخ على كل صندوق ينقش بوضوح منذ متى بدأ الأمر. قلب المخزن القديم الذي كان يدوّن يوم تخمير المعجون، يستمر على هذه الورقة الصغيرة."},"ICON-1000":{"nm":"غطاء مصباح الحلقة الصغير","de":"غطاء يُغطّي فتحة الضوء لمصباح صغير يبعث توهجًا دائريًا. أرقد الضوء قليلًا كي لا تُخدش العدسة داخل الحقيبة. والحفاظ على الظلام برقة قبل إشعاله، هو أيضًا إحدى طرق الاعتزاز بالسطوع."},"ICON-1001":{"nm":"مسمار تثبيت الحامل","de":"لفة واحدة أخيرة. تختفي الفجوة المرتخية، ويستقر اطمئنان ثقيل تحت راحة اليد. خلف كل مسرح لا يهتز يكمن دومًا معصم أحدهم وقد لواه بإتقان. ما يسنده هذا المسمار الصغير هو صلابة لا تُرى."},"ICON-1002":{"nm":"شريحة إشارة البث المباشر","de":"في اللحظة التي تضيء فيها الإشارة الحمراء، تتحول خطوات الممر خلسةً إلى نقر خفيف على أطراف الأصابع. أمام كلمة \"على الهواء\"، يحبس الجميع أنفاسهم. حتى الصمت خلف الباب هو قلب متجه نحو شخص ما، وهذه الشريحة الصغيرة تعلن ذلك بهدوء."},"ICON-1003":{"nm":"مفكرة ملاحظات الدردشة","de":"تُمسك بأطراف أصابعك التشجيع الذي كان سيمر عابرًا على الشاشة. لحظة تبقى فيها كل كلمة كانت ستذوب، مرتبة وواضحة، على الورق. التدوين هو المكان الذي تستقر فيه الرقة التي تريد أن تصل، ولو متأخرة."},"ICON-1004":{"nm":"غطاء لوحة مفاتيح صامت","de":"الساعة الثانية فجرًا، ويختفي صوت الطرق على المفاتيح وكأنه كذبة. غشاء رقيق كي لا يوقظ أنفاس زميل الغرفة النائم بعمق. أهدأ مراعاة تبدأ دائمًا في مكان بلا صوت."},"ICON-1005":{"nm":"مشبك ذراع الميكروفون","de":"بين الشفتين والميكروفون، تلك المسافة بالضبط التي لا تهتز عندها الأغنية. هذا المشبك الصغير يمسك بذلك الوعد. خلف الكواليس، تسبق دائمًا يد تمسك الأمور بثبات."},"ICON-1006":{"nm":"مشبك الستارة الخلفية","de":"حتى لو هبت الريح، لا تتحرك الستارة الخلفية. لأن فكًا صغيرًا يعض الزاوية بإحكام يمسك بالمشهد كله. خلف منظر لا يهتز، يوجد دائمًا من يكزّ على أسنانه في مكان لا يُرى."},"ICON-1007":{"nm":"ملصق أزرار لوحة البث","de":"فوق عشرات الأزرار، بفضل بطاقة اسم صغيرة لا تضل اليد طريقها. سطر واحد من الملصق يمحو مسبقًا خطأً واحدًا في البث المباشر. الهدوء يأتي من الحروف المكتوبة قبل أن يبدأ الارتجاف."},"ICON-1008":{"nm":"زر ختم الوقت","de":"اضغط عليه، ويُغرَز علمٌ صغير في الزمن الجاري. فعل ختم اللحظة الحاضرة التي لن تعود أبدًا. حين تنظر إلى الوراء بعد حين، تصبح تلك العلامة بابًا يفضي إلى الذكرى."},"ICON-1009":{"nm":"حلقة مفاتيح قارئ البطاقات","de":"قرّبها فقط، وبصوت \"تيك\" تستيقظ المعلومات. رفيق صغير معلق بحلقة المفاتيح، يصدر صوتًا خفيفًا في الجيب. يوم عادي يمضي بسلام بفضل مثل هذه الإشارات الصغيرة."},"ICON-1010":{"nm":"ملصق مقبس ذكي","de":"إذا وضعت اسمًا لكل مقبس، لن تتوه بعد الآن في معرفة أي سلك لأي جهاز. قلب يمنح اسمًا حتى للكهرباء غير المرئية. الترتيب هو وجه آخر تستعيره الرقة لبرهة."},"ICON-1011":{"nm":"حامل مستشعر الحرارة والرطوبة","de":"حارس بحجم راحة اليد يراقب بصمت حرارة الغرفة ورطوبتها. الراحة لا تفتح فمها أبدًا، لكن هذا الحامل يعتني بحالتك بهدوء في كل لحظة. هكذا تُصان السلامة، بصمت."},"ICON-1012":{"nm":"غطاء مستشعر فتح الباب","de":"عين صغيرة لا تفوّت تلك اللحظة التي ينفتح فيها الباب برفق. تنقل بصمت إشارة عودة أحدهم إلى البيت. ما يحرس بيتًا خاليًا هو دائمًا، مثل هذا، أشياء صامتة لا تتكلم."},"ICON-1013":{"nm":"حامل جهاز التحكم عن بعد","de":"أجهزة التحكم التي كانت تتدحرج هنا وهناك تجد أخيرًا مكانها الخاص. زاوية صغيرة تمسك بهدوء بما كان على وشك الضياع، يد تنقش مسبقًا وعدًا باللقاء مجددًا."},"ICON-1014":{"nm":"رمز تطبيق النوم","de":"في كل ليلة تنام فيها جيدًا، تتراكم مكافأة مستديرة صغيرة. النوم أيضًا يتجمع شيئًا فشيئًا كالتمرين، هكذا يخبرك التطبيق بحنان. أصغر جائزة في العالم، تُمنح لك أنت الذي ارتحت جيدًا."},"ICON-1015":{"nm":"قاعدة مكعب المؤقت","de":"بينما تمر ثلاث دقائق بثبات، يعد المكعب وقته دون أن يهتز. زاوية بحجم راحة اليد تسنده برفق من الأسفل. حتى الانتظار يحتاج إلى أرضية يقف عليها بطمأنينة."},"ICON-1016":{"nm":"غطاء ضوء الإشعارات","de":"كي لا يكون ساطعًا جدًا، يلف الضوء برفق بطبقة ناعمة. قد يكون الإشعار عاجلاً، لكن دع العينين وحدهما ترتاحان. المراعاة هي قلب يقيس بهدوء حتى شدة الضوء."},"ICON-1017":{"nm":"بطاقة تغيير البطارية","de":"حين تظهر هذه البطاقة، فهذا يعني أن الوقت قد حان لتبديل القلب الصغير داخل الجهاز. تلميح لطيف بالاهتمام قبل أن يتوقف. سر الرفقة الطويلة يكمن دائمًا في يقظة تسبق الحدث بخطوة."},"ICON-1018":{"nm":"طقم أغطية عصا التحكم","de":"قبعات صغيرة تُلبَس كي لا ينزلق الإبهام. يزداد وضوح إحساس أطراف الأصابع. هذا الغطاء الصغير قد يحسم أحيانًا فوز جولة لُعبت بيد مبللة بالعرق."},"ICON-1019":{"nm":"غطاء قاعدة شحن السويتش","de":"يغطي برفق مكان راحة الجهاز من الغبار. لأن حتى جهازًا نائمًا لبرهة يحتاج بطانية واحدة. القلب المهتم يظهر بوضوح أكبر حين لا يُستخدم الشيء فعليًا."},"ICON-1020":{"nm":"حقيبة جهاز الألعاب المحمول","de":"عند التنقل، لا بد أن يكون بداخل هذه الحقيبة. جيب يحتضن جهاز الألعاب المحمول برفق. كي يبقى سليمًا رغم الاصطدامات هنا وهناك داخل الحقيبة، من الأفضل أن تُغلَّف الأشياء الثمينة مرة إضافية."},"ICON-1021":{"nm":"طقم ملصقات الأزرار","de":"مجرد رسمة صغيرة واحدة فوق زر عادي، وفي تلك اللحظة يصبح ملكك تمامًا. فعل ترك بصمتك الخاصة على جهاز مطابق لغيره. الطابع الشخصي يتفتح دائمًا بهدوء من مثل هذه الزوايا التافهة."},"ICON-1022":{"nm":"علبة خرطوشة الألعاب","de":"جولة لعبة غرقت فيها طوال الليل تنام بعمق داخل هذه العلبة الصغيرة. افتح الغطاء مجددًا، وتستيقظ تلك الليلة كاملة دون نقصان. الذكريات، على غير المتوقع، كثيرًا ما تُحفظ في صندوق لا يتجاوز حجم راحة اليد."},"ICON-1023":{"nm":"قاعدة مروحة التبريد","de":"بينما يبرّد الهواء الحرارة، زاوية تسند الجهاز بميل خفيف. تفسح مجالًا لجسم محتقن بالحرارة كي يلتقط أنفاسه. كي تركض بعيدًا، عليك أيضًا أن تعرف كيف تتوقف لحظة لتبرد."},"ICON-1024":{"nm":"دبوس حزام المعصم","de":"لفّه حول معصمك وثبّت الدبوس، ومهما اشتدت الحركة لن يفارق جهاز التحكم جانبك. هذا الحزام الذي يبدو مزعجًا هو في الحقيقة الاطمئنان الذي يتيح لك اللعب بقلب مرتاح."},"ICON-1025":{"nm":"غطاء مقبض العصا التناظرية","de":"يُلبس ثوبًا جديدًا فوق مقبض صقلته السنوات حتى لمع. اترك الإحساس الذي اعتادته يدك كما هو، ودع السطح وحده يبدو جديدًا. لحظة تستقر فيها الألفة والإثارة جنبًا إلى جنب في يد واحدة."},"ICON-1026":{"nm":"ملصق فتحة الحفظ","de":"على كل خانة حفظ، تُكتب بوضوح مغامرة صاحبها. سطر واحد من الملصق يحرس بصمت رحلة الأيام الماضية. الذكريات الثمينة يُستحسن أن تُنقش عليها أسماء كي لا تُمحى بالكتابة فوقها."},"ICON-1027":{"nm":"حقيبة جهاز التسجيل","de":"الآلة التي تحفظ الصوت تزداد ثمنًا بسبب ما بداخلها. تُحمل ملفوفة برفق في جيب ناعم يحميها من الصدمات. فربما ينام فيها صوت أحدهم، فتزداد الحيطة حذرًا."},"ICON-1028":{"nm":"غطاء واقي من الريح","de":"يزيح صوت الريح ويترك الصوت وحده. غطاء ناعم يُلبس برفق فوق الميكروفون أثناء التسجيل في الهواء الطلق. مصفاة صغيرة تنتقي الصدق وحده من بين الضوضاء المشوشة."},"ICON-1029":{"nm":"ملصق مذكرة صوتية","de":"هذه كلمات خطرت لي، وهذه لحن دندنته. تُلصق بطاقة اسم ملونة على كل مذكرة صوتية. شظايا الإلهام المتناثرة في كل اتجاه تجد أخيرًا مكانها وتصطف في نظام."},"ICON-1030":{"nm":"شريحة زر العينات الصوتية","de":"اضغط عليها، وتقفز قطعة من صوت محفوظ مسبقًا. قطرة مطر، تصفيق، ضحكة أحدهم؛ شظايا من العالم تستيقظ عند طرف إصبعك. الموسيقى هي جوقة حانية من مثل هذه الشرائح الصغيرة."},"ICON-1031":{"nm":"مظروف جمع الأصوات","de":"تجمع برفق في هذا المظروف الأصوات التي التقطتها مصادفة أثناء المشي. نسيج الريح، بل وصمت زقاق الفجر أيضًا. المواد التي ستصبح يومًا ما أغنية تتجمع دائمًا هكذا بتواضع."},"ICON-1032":{"nm":"أرجل حامل ثلاثي مصغر","de":"ثلاث أرجل تفرش مسرحًا صغيرًا فوق المكتب. بدلًا من يد مرتجفة، تقف بثبات وتمسك بالمشهد. لقطة واضحة تولد أخيرًا من ثلاث أرجل واقفة بصمت وثبات."},"ICON-1033":{"nm":"بطاقة ملف تسجيل","de":"على مئات ملفات التسجيل، تُلصق بطاقة قصيرة واحدة تلو الأخرى. كي تعرف بلمحة أي مقطع أول خرج في أي يوم. لافتة صغيرة تساعدك على إيجاد الأصوات المتناثرة من جديد."},"ICON-1034":{"nm":"شريط ملصق موجة صوتية","de":"شريط متموج مصبوب على هيئة الصوت نفسه. لُفّه حول دفتر أو علبة، وكأن الموسيقى أصبحت مرئية أمام عينيك. خداع بصري لطيف يحول المسموع إلى مرئي."},"ICON-1035":{"nm":"دبوس تعليق سماعة الرأس","de":"حين ينتهي التمرين، يُعِدّ بهدوء مكان راحة للسماعة المتعبة. خطاف صغير مغروز في حافة المكتب. مكتب مرتب هو مكان تُعلَّق فيه حماسة الغد مسبقًا."},"ICON-1036":{"nm":"شريط علبة هدايا صغير","de":"اللفة الأخيرة حول خصر علبة الهدية. بهذا الشريط الواحد يكتمل القلب أخيرًا. الإخلاص كثيرًا ما يصل أولًا من اليد التي تُمسِّد الخارج، أكثر مما يصل مما بالداخل."},"ICON-1037":{"nm":"غطاء طرف الشريط","de":"يلف طرف الشريط برفق ويُنهيه كي لا ينفك. تفصيل صغير بالكاد يلفت الانتباه، لكنه يغير بهدوء الانطباع الأول عن الهدية. حين يكون الختام أنيقًا، يصل القلب أيضًا بأناقة."},"ICON-1038":{"nm":"شمع ختم الطرود","de":"قطرة واحدة ساخنة تسقط لتختم المظروف. كرسالة قديمة، وعد ثقيل بألا يُفتح باستخفاف. الرسميات أحيانًا تحمل مثل هذا الثقل الدافئ."},"ICON-1039":{"nm":"حامل بطاقة شكر","de":"يسند بطاقة تحمل كلمات شكر كي لا تتجعد، مستقيمة تمامًا. كي يصل القلب واقفًا باستقامة. الامتنان يبقى في القلب أطول حين تكون هيئته أيضًا مرتبة."},"ICON-1040":{"nm":"ورق حشو على شكل نجوم","de":"أوراق مقصوصة على هيئة نجوم تملأ برفق فراغات الصندوق. قطن من قلب يتمنى ألا يتأذى شيء حتى لو اهتز. حتى في ظلام التغليف، ثمة نجمة صغيرة معلقة هناك."},"ICON-1041":{"nm":"بطاقة قائمة الهدايا","de":"أمام خانة المستلم، يتوقف القلم طويلًا. الوجه الذي يخطر ببالك بينما تكتب الاسم، والفصول التي قضيتماها معًا. في لحظة الربط، تصبح هذه الورقة الصغيرة سرًا لا يقرؤه أحد حتى يُفك."},"ICON-1042":{"nm":"خاتم ختم التهنئة","de":"اضغط عليه، وتُطبع تهنئة مستديرة واضحة. بينما تنتظر اللحظة القصيرة ليجف الحبر، القلب الذي يتخيل لمن سيقدمها هو الأدفأ. إن كان ثمة عيب، فهو أنك تريد ختمها مرة أخرى."},"ICON-1043":{"nm":"بكرة خيط التغليف","de":"ملفوفة بعناية، ثم تُفَكّ بمرح بين أطراف أصابع أحدهم المتشوقة. في تلك اللحظة القصيرة بين اللف والفك، يصبح قلب كان مربوطًا بالخيط، أخيرًا، هدية."},"ICON-1044":{"nm":"تعليقة عقدة (ليست زهرة)","de":"ليست تقليدًا لزهرة، بل هيئة خيط واحد يعانق جسده مرارًا وتكرارًا حتى يتفتح من تلقاء نفسه. صبر أطراف الأصابع التي اختارت العُقد طوال الليل بقي على هيئة برعم صغير كهذا."},"ICON-1045":{"nm":"كيس عملة الحظ","de":"قلب من كان يدسّ خلسة بضع عملات في جيب مسافر إلى طريق بعيد. فعل يملأ الجيب لا بالوزن بل بالحنان. رنين العملات مع كل خطوة يحل محل تحية \"عد سالمًا\"."},"ICON-1046":{"nm":"تعليقة كبسولة الأمنيات","de":"داخل قوقعة مستديرة، تنام أمنية واحدة مطوية بهدوء عميق. أن فتحها يحققها كذبة، لكن أن تحتفظ بها مغلقة يبقي تلك الأمنية حية إلى الأبد، هذا حقيقي."},"ICON-1047":{"nm":"حبل عقدة الحماية","de":"حبل منسوج بإحكام من خيوط الألوان الخمسة، يرد الطاقة السيئة إلى الخلف. كلمسة يد الجدة التي كانت تعقد عقدة حول المعصم في الطفولة، في كل موضع مربوط تكمن صلاة أحدهم منقوشة بعناية."},"ICON-1048":{"nm":"علبة كركي ورقي صغير","de":"بيت صغير يحفظ سالمة كركيًا ورقيًا واحدًا فقط، من الألف طية اللازمة لتصبح أمنية. لأنه لو تجعد جناح واحد فقط، فإن الإخلاص المبذول في تلك الليلة نفسه ينفك ببطء."},"ICON-1049":{"nm":"كيس أحجار متلألئة","de":"شظايا ضوء صغيرة تساقطت من زي المسرح، مكان لجمع ما لا تستطيع رمي. حتى البريق الذي كان يلتصق ويلاحقك أسبوعًا كاملًا، ينام هنا بهدوء وطاعة كما لو كان فوق راحة يدك."},"ICON-1050":{"nm":"شريحة ختم الفأل الحسن","de":"قطعة صغيرة تُضاف خلسة عند اختيار يوم جيد. ليس على عتبة بيت العرافة بل فوق مكتبي، شذرة من خرافة عزيزة تُختم بهدوء، متمنية ألا يحدث اليوم سوى الخير."},"ICON-1051":{"nm":"بطاقة سوار الأمنيات","de":"ورقة واحدة مطبوعة على هيئة سوار، تحمل أمنية هادئة من أحدهم. حتى لو تعذر ربطها حول المعصم، ضعها في عمق المحفظة، وذلك القلب وحده يبقى مربوطًا بجانبك، يسير معك دومًا."},"ICON-1052":{"nm":"جرة ملح عتبة الباب","de":"ملح خشن يوضع في جرة صغيرة، تُترك بهدوء أمام الباب. حساب قديم يرد الطاقة السيئة ولا يستقبل سوى الضيوف الطيبين. كل حبة ملح مالحة هي حارس بوابة صغير يسهر على بيتنا."},"ICON-1053":{"nm":"بطاقة تغطية رقم الحظ","de":"قبيل الخدش مباشرة، يكون الجميع فائزًا للحظة. هذه البطاقة التي تغطي الرقم المحظوظ برفق تحرس تلك الثانية الأخيرة حين يتضخم الأمل أكثر ما يكون. حتى لو ارتجفت أطراف أصابعك وأنت تخدش، تتظاهر بعدم الملاحظة وتغمض عينيها."},"ICON-1054":{"nm":"غطاء حفظ شمعة عيد الميلاد","de":"قلب صغير مرتب يحفظ حتى شمعة أُشعلت مرة، بعناية حتى عيد الميلاد التالي. إن كانت أمنية العام الماضي لم تتحقق بعد، فبإمكانك هذا العام أن تكمل من حيث توقفت وتتمنى مجددًا، حساب حانٍ."},"ICON-1055":{"nm":"خاتم عد تنازلي للمناسبة","de":"شيء وقح يُلبس العد التنازلي على إصبعك. كلما تراجع رقم الأيام المتبقية درجة، يُسحب القلب أيضًا خطوة أقرب. يصر وحده أنه سيتوهج حين يصل إلى الصفر."},"ICON-1056":{"nm":"حزام قبعة الحفلة","de":"حزام رفيع يثبت قبعة المخروط على الرأس بهدوء. صاحب المناسبة نفسه سرعان ما يشتكي من الضيق وينزعها، لكنها تبقى في الصورة إلى الأبد في تلك اللقطة. تلك مهمة كافية."},"ICON-1057":{"nm":"علامة كعكة صغيرة","de":"علامة صغيرة مغروزة في كعكة بحجم مفصلي إصبع. حتى فوق حلاوة تختفي في قضمة واحدة، يقف الاحتفال منتصبًا شامخًا. مهما صغرت، يبقى عيد الميلاد عيد ميلاد، والبطل اليوم هو أنت."},"ICON-1058":{"nm":"ملصق مفرقعة الاحتفال","de":"لا صوت انفجار لها لكنها الأبهى منظرًا، مفرقعة ورقية. في لحظة إلصاقها، يتحول طرد بريدي عادي إلى رسالة قادمة من حفلة. كثيرون يتركونها كما هي، لا يطاوعهم قلبهم على نزعها."},"ICON-1059":{"nm":"مشبك تعليق الصور","de":"خوفًا من إسقاط الذكريات المعلقة على الخيط، أُبقي فمي مطبقًا بإحكام دومًا. طالما صورة واحدة ممسوكة بين فكيّ، لا تستطيع حتى نسمة تتسلل من الشباك أن تُسقط تلك الأيام."},"ICON-1060":{"nm":"رقعة بالون التاريخ","de":"رقعة على هيئة بالون مكتوب عليها رقم. ألصقها بملابسك، ويعرف الحي كله أي يوم مميز هو اليوم كم. انزعها ويبقى أثر، وحتى ذلك الأثر الباهت يصبح تذكارًا آخر."},"ICON-1061":{"nm":"علامة تبادل الهدايا","de":"علامة مشاغبة تخلط برفق بين اليد المستلمة واليد المانحة. قاعدة صغيرة حانية لطاولة تبادل الهدايا، تطلب منك أن تتذكر ما جرى تبادله أكثر مما تتذكر من أعطاه."},"ICON-1062":{"nm":"رقم طاولة المناسبة","de":"رقم صغير منتصب على كل طاولة في المأدبة. تحديد من يجلس أين مسبقًا كي لا يشعر أحد بالحرج، يحمل حكمة حانية ممن استضافوا احتفالات كثيرة."},"ICON-1063":{"nm":"كيس هدية مقبض الباب","de":"طريقة لإيصال القلب دون قرع الجرس. علّقها خلسة على مقبض الباب واختفِ وكأنك تهرب، ووجه من يجدها المندهش يصبح أعظم هدية تعود للمُهدي."},"ICON-1064":{"nm":"ملصق توصيل سري","de":"لا يُكتب شيء على وجهه. إخفاء هوية المُرسل حتى النهاية هو كبرياء هذا الملصق الصغير. كلما طال حيرة المستلم وابتسامته، ازدادت المهمة السرية كمالًا."},"ICON-1065":{"nm":"شريحة مذكرة الجرس","de":"ورقة صغيرة تُترك بدلاً من الشجاعة التي تنقصك لقرع الباب. سطر قصير مثل \"مررت للحظة\" يبقى أطول من صوت الجرس. لأن الخط المتعرج المكتوب باليد له تعبير خاص به."},"ICON-1066":{"nm":"غطاء أمان سكين الطرود","de":"حين تستهدف شفرة سكين الطرود إصبعك عن غير قصد، بطل صغير يقف خلسة أمامها. يحمي أطراف أصابعك المتعجلة بحماسة الشيء الجديد، سالمة حتى القطعة الأخيرة."},"ICON-1067":{"nm":"قطعة فقاعات التغليف","de":"وُلدت لأُضغَط. مع ذلك الصوت \"توك\" الذي ينفجر، ينفك توتر اليوم ببطء بشكل ما. أحيانًا أُحَب أنا أطول من الشيء الذي كنت أحيط به."},"ICON-1068":{"nm":"دبوس وقت الاستلام","de":"دبوس يحدد بدقة الساعة التي سيصل فيها. حتى انتظار غامض يصبح أسهل احتمالًا حين تُمنح له إحداثية واحدة. كم مرة ستطل من الباب حتى تلك الساعة، ذلك يعود إليك وحدك."},"ICON-1069":{"nm":"حلقة مفاتيح خزانة الطرود","de":"رفيق صغير لمن ينسى دائمًا رمز خزانة الطرود. يتدلى من حلقة المفاتيح مترنحًا، وموهبته الخفية هي انتزاع كلمة \"آه صحيح\" في اللحظة الحاسمة."},"ICON-1070":{"nm":"بطاقة سلة المدخل","de":"بطاقة اسم ملصقة على سلة في زاوية المدخل. عليها وعد صامت مكتوب: \"اتركه هنا\". حتى وهي فارغة، الزاوية التي تنتظر قلب أحدهم لا تشعر بالوحدة أبدًا."},"ICON-1071":{"nm":"ملصق إخفاء العنوان","de":"فوق صندوق تتخلص منه، تترك الاسم وتمحو العنوان فقط. الاسم لا بأس أن يعرفه الجميع، أما مكان سكنك فيبقى سرك وحدك. في لحظة لصق طبقة واحدة، يولد اطمئنان صغير."},"ICON-1072":{"nm":"ملصق علبة الوجبات الخفيفة","de":"ملصق يخبرك بلمحة واحدة بما بداخل العلبة. لكن الفخ أن كتابة \"وجبة خفيفة\" تمنحك شعورًا بالاطمئنان حتى دون فتح الغطاء فعليًا. الملصق لا يتحمل مسؤولية شهيتك بالطبع."},"ICON-1073":{"nm":"قلادة صغيرة","de":"حبة صغيرة تشارك بهدوء حرارة جسدك تحت الثياب. تلامس دومًا مكانًا لا تراه عين أحد، ما يجعلها أعز من ذلك. أقرب صديق يسير معك عند صدرك."},"ICON-1074":{"nm":"سجادة ختم آثار الأقدام","de":"اضغطها على الكف، وتُترك آثار أقدام صغيرة متتالية. مذكرة نزهة يومية، تدوّن بوضوح على الورق من مشى إلى أين. أول خطوة ملطخة بالحبر هي دومًا الأوضح."},"ICON-1075":{"nm":"غطاء فرشاة تنظيف الفرو","de":"غطاء صغير يتولى بإتقان تنظيف الفرو المتشابك في الفرشاة. في موسم تساقط الفرو، حين تجمع فرشة واحدة قبضة كاملة، لولا هذا الغطاء لتحول البيت كله إلى حقل ثلج ناعم. عامل نظافة مجتهد لا يترك أثرًا."},"ICON-1076":{"nm":"علبة أكياس النزهة","de":"بيت صغير يحمل بترتيب الأكياس اللازمة لنزهة المشي. أن من يجهز نفسه مسبقًا وحده يتمشى براحة، تثبته هذه العلبة بهدوء كل يوم. تلك القطعة الواحدة التي تسبب الحرج إن نُسيت."},"ICON-1077":{"nm":"بطاقة إخفاء الاسم","de":"بطاقة تخفي الاسم الحقيقي خلسة وتترك اللقب وحده. في هذا العالم توجد رقة لا تريد أن تُظهرها لأي كان. ذلك النداء الذي يعرفه فقط من يعرف، يختبئ هنا برفق."},"ICON-1078":{"nm":"سجادة قاعدة وعاء الماء","de":"أنا الملقاة تحت وعاء الماء، رطبة دومًا. أستقبل بدلًا عنك قطرات الماء المتناثرة في كل اتجاه، وأحرس أرضية الخشب كي تبقى جافة. لا أحد يمدحني، لكني لا أشتكي أيضًا."},"ICON-1079":{"nm":"خيط ترميم الدمى","de":"الدمية التي انفكت خيوطها لا تُرمى بل تُخاط من جديد. مع كل غرزة تُملأ بها، يزداد صلابة الوقت الذي قُضي مع ذلك الصغير. الترميم في النهاية هو تأجيل الوداع بهدوء."},"ICON-1080":{"nm":"قلادة صورة تذكارية","de":"قلب من يعلق حول رقبته لقطة ابتسامته الأكثر إشراقًا. ذلك اليوم في الصورة، بدلًا من أن يُحنَّط ساكنًا، يتأرجح مع كل خطوة ويصل حتى اليوم. تلك اللحظة الجميلة لا تتوقف أبدًا."},"ICON-1081":{"nm":"شريحة لون المزاج","de":"لو كان للقلب أيضًا لون، فما لونك اليوم؟ في لحظة اختيار شريحة ووضعها على المكتب، ينتشر بهدوء شعور لم تستطع الكلمات وصفه كاملًا. ضوء الغروب أو ضوء الفجر، كلاهما جميل؛ فهي مرآة صغيرة تعكس بهدوء أنت هذا اليوم."},"ICON-1082":{"nm":"كرة تسجيل اليوم","de":"حين ينحسر النهار، يتجمع اليوم مستديرًا داخل الكرة. الأشياء التي أحسنت فيها والتي تعثرت فيها تُلَملَم وتتدحرج معًا. ضعها على راحة يدك ويصبح أمس دافئًا قليلًا، يربت على ظهرك قائلًا إنك عشت اليوم جيدًا أيضًا."},"ICON-1083":{"nm":"جرة ملاحظات الثناء","de":"الكلمات الطيبة تتبعثر بسهولة أكثر مما ينبغي، فتُطوى واحدة تلو الأخرى وتُحفظ في هذه الجرة. حين يتجمع الثناء كالعطر، تُفتح الجرة في ليالٍ يشعر فيها القلب بالفراغ. أخرج قطعة من الحنان قدمها أحدهم واقرأها مجددًا، فتعود دفء ذلك اليوم إلى الحياة."},"ICON-1084":{"nm":"حبل شريط المصالحة","de":"القلب المتشابك يشبه العقدة؛ حتى فكه يتطلب عناية. حين يمسك شخصان بطرفي الحبل ويسحبانه ببطء، يتشكل فجأة شريط جميل. المصالحة ليست قطعًا بل ربطًا من جديد، هذا ما يخبرك به هذا الحبل بهدوء."},"ICON-1085":{"nm":"رمز الامتنان","de":"في الأيام التي لا تُطاوع فيها كلمة \"شكرًا\" لسانك، تقدم بدلًا منها رمزًا خلسة. اليد المستقبلة تقرأ القلب كله من ذلك الثقل الصغير. صدق يصل قبل الكلمات، مودة تُنقل عبر حبة مستديرة واحدة."},"ICON-1086":{"nm":"علامة وقت الاستراحة","de":"حتى غرفة تمرين ركضت طوال اليوم تحتاج نبضة واحدة لالتقاط الأنفاس. علّق هذه العلامة على الباب ويتباطأ الزمن لبرهة. من عاش يومًا لاهثًا يعرف أن الأغنية تحتاج فاصلة صمت كي تتنفس."},"ICON-1087":{"nm":"درج المشاعر السرية","de":"هناك أيام لا تستطيع فيها إظهار كل ما بداخلك. في تلك الأيام تضع الحزن والخفقان معًا في درج صغير من العقل وتغلقه. لا بأس أن تتركها الآن، لأن يومًا سيأتي تفتحه فيه ببطء وترتب كل شيء."},"ICON-1088":{"nm":"بكرة ملصقات الابتسامة","de":"انزع مربعًا واحدًا، وتلتصق علامة ابتسامة بطرف إصبعك. مرح صغير يُلصق برفق في زاوية دفتر أو خزانة صديق. حين تشرق شمس صغيرة على الورق، يزداد يوم من يجدها إشراقًا قليلًا."},"ICON-1089":{"nm":"تعليقة جرس السؤال عن الأحوال","de":"الرغبة في الوصول إليك أنت البعيد تجمعت في جرس واحد. هزّه ويحمل صوت صافٍ التحية بدلًا منك. في الأيام التي لم تستطع فيها أن تسأل \"هل أنت بخير\"، هذا الرنين الصغير يركب الريح ويصل إليك أولاً."},"ICON-1090":{"nm":"دبوس غطاء مطر الربيع","de":"في أيام مطر الربيع، الأشياء التي تعتز بها هي أسرع ما يبتل. أغلق الغلاف بهذا الدبوس وتنزلق قطرات المطر بعيدًا. قلب احتضان كتاب ثمين واحد، دبوس صغير واحد يقوم مقام تلك الرقة."},"ICON-1091":{"nm":"ملصق تبريد صيفي","de":"لمسة سريعة واحدة على ظهر يد أنهكها حر منتصف الصيف. يفوح إحساس بارد كالنعناع ويخف العرق قليلاً. تلك البرودة عند الاستلقاء على الشرفة الخشبية والتهوية بمروحة يدوية، تحاكيها بأمانة ورقة بحجم راحة اليد."},"ICON-1092":{"nm":"قطعة قماش مربعات خريفية","de":"قطعة قماش مربعة تشبه حقل الخريف. إنها أثر رقعة وضعها أحدهم بعناية على مكان بالٍ. القلب الذي يرقع بدلًا من أن يرمي، قطع قماش صغيرة تجتمع لتحيي بدفء ما تآكل."},"ICON-1093":{"nm":"مشبك قفازات الشتاء","de":"قفازات الشتاء تهرب دائمًا واحدة تلو الأخرى بطريقة ما. اربط الزوج بهذا المشبك ولن تتوه يداك المتجمدتان. الرغبة في ألا يُفقَدا تسكن في قطعة معدنية صغيرة، تحرس الزوجين جنبًا إلى جنب."},"ICON-1094":{"nm":"بطاقة موسم الأمطار المقاومة للماء","de":"في موسم الأمطار، حتى بطاقة الاسم تتلطخ بالمطر. هذه البطاقة المطلية بمادة مضادة للماء تحمي كتابتها حتى تحت مطر غزير. سطر يبقى واضحًا حتى بعد أن يصفو الجو، كي لا يُنسى أبدًا لمن هذا."},"ICON-1095":{"nm":"جرة حفظ الثلج الأول","de":"الثلج الأول يختفي في اللحظة التي يلمس فيها يدك، فحفظت في جرة على الأقل ذلك الخفقان. ما هو محبوس في الزجاج ليس ثلجًا بل القلب الذي كان يخفق في ذلك اليوم. هزّها ويدور شتاء كامل مجددًا، يأخذك إلى ذلك الصباح."},"ICON-1096":{"nm":"شريط مظروف العيد","de":"شريط أحمر واحد يلف مظروف العيد. الجميع يعرف أن مودة اليد المانحة أكبر مما بداخله. القلب الذي يلف البركات مع أمنيات الصحة الجيدة مربوط بعناية داخل هذا الشريط الرفيع."},"ICON-1097":{"nm":"شريط أواني النزهة","de":"افرش البساط وافتح صندوق الغداء، وتستمر الريح في رفع الأغطية. اربط الأواني بإحكام بهذا الشريط ولن تتبعثر النزهة. القلب الذي يريد حماية وجبة معدة إلى النهاية محفوظ في شريط صغير واحد."},"ICON-1098":{"nm":"بطاقة عينة عطر الموسم","de":"كي تعرف الفصل دون أن تفتحها حتى، حُملت رائحة ذلك الوقت من السنة في بطاقة واحدة. زهور في الربيع، رائحة أوراق جافة في الخريف. في لحظة ملامستها لأنفك، يعود الفصل كاملاً: \"هذا هواء أبريل\"."},"ICON-1099":{"nm":"لوح مشبك بطاقة السعر","de":"هذا اللوح الواحد أراح صداع البسطة من بطاقات الأسعار التي كانت تطير باستمرار. يمسك الأرقام بإحكام ويقدمها مستقيمة أمام الزبون. تحية التجارة الأولى تبدأ من سطر صادق واحد لا ينحرف أبدًا."},"ICON-1100":{"nm":"لوحة قلب فتح المحل","de":"اقلب هذه اللوحة وعلقها عند الباب، ويستيقظ المتجر أخيرًا. من \"قيد التحضير\" إلى \"أهلاً بك\". إشارة صغيرة تعلن بداية اليوم، الزاوية التي تلمسها يد صاحب المتجر أولاً كل صباح."},"ICON-1101":{"nm":"بطاقة أختام الولاء","de":"حين تمتلئ الخانات العشر كلّها، يحدث خيرٌ ما على نحوٍ غامض. كلّ ختم هو خطوة زبون دائم، ومحبّة تراكمت مع الأيام. وفي كل أثرٍ يُطبع حتى يجفّ الحبر، يعيش وعدٌ صغير بالعودة، ينبض بالحياة."},"ICON-1102":{"nm":"غطاء مقبض كيس الورق","de":"مقبض الكيس الورقي هشٌّ دائمًا أمام الثقل. حين يُثبَّت هذا الغطاء، يشتدّ الخيط الذي كان على وشك الانقطاع. رغبةٌ في إيصال ما بداخله سالمًا إلى البيت، قطعة صغيرة تسند هذا الطريق حتى النهاية."},"ICON-1103":{"nm":"طبق عملات الصندوق","de":"هذا الطبق يخفّف بهدوء تردّد تمرير الفكة من يدٍ إلى يد. صوت العملات وهي ترنّ لتستقرّ في مكانها. العطاء والأخذ يصيران أكثر دفئًا بفضل هذه اللطافة المستديرة الصغيرة."},"ICON-1104":{"nm":"رقاقة تجميع النقاط","de":"خطوات اليوم تتراكم بهدوء في رقاقة واحدة. حسابٌ عجيب، كلما تجمّع أكثر خفّ القلب أكثر. متعة الامتلاء شيئًا فشيئًا تشبه بهجة مراقبة جرّة فارغة تمتلئ دون أن تشعر."},"ICON-1105":{"nm":"دبوس رقم الرفّ","de":"على كل رفّ يُغرَز رقم صغير بمودّة. دليلٌ هادئ يخبرك أين يوجد كل شيء. قلبٌ يحدّد المكان مسبقًا كي لا تتوه، حتى النظام يحمل مثل هذا الدفء."},"ICON-1106":{"nm":"كوب أسياخ التذوّق","de":"كوبٌ صغير يقدّم لقمة تذوّق واحدة. حتى الزبون المتردّد يفتح قلبه برفق أمام هذه اللقمة. كرم «جرّب واحدة» يتدلّى من طرف السيخ، ويمسك بخطى القادم لأول مرة."},"ICON-1107":{"nm":"حامل قائمة الحجوزات","de":"أسماء ضيوف اليوم تقف مرتّبة في هذا الحامل. وعدٌ رقيق بأنّ للانتظار أيضًا دورًا. تثبيت ورقة واحدة منتصبة يصبح أول تحضيرٍ عنايةً لاستقبال يوم أحدهم."},"ICON-1108":{"nm":"مشبك خيط الصور الجداري","de":"يُشدّ خيطٌ على الجدار وتُعلَّق الصور بالمشابك واحدة تلو الأخرى. لحظات الابتسام تتدلّى جنبًا إلى جنب لتجفّ كالغسيل. عندما تُعلَّق الذكريات في مكان تسقط عليه الشمس، كلما مررت من هناك يرفرف ضحك ذلك اليوم من جديد."},"ICON-1109":{"nm":"زاوية السجادة الصغيرة","de":"سجادة صغيرة تُفرش عند طرف الغرفة. بقعة تنشر الدفء أولًا على الأرضية الباردة. أول شبرٍ تلمسه القدم الحافية، عند أطراف أصابع من عاد إلى البيت، هنا أخيرًا يطمئنّ ويسترخي."},"ICON-1110":{"nm":"قماش ستر اللوحة الاسمية","de":"قطعة قماش تستر لوحة الاسم برفق. إخفاء الاسم للحظة هو أيضًا أناقة خاصة بالمنزل. طرفٌ يُسدَل بلطف على الحدّ الفاصل بين الداخل والخارج، رغبةٌ في الراحة الهادئة اليوم تتعلّق برفق."},"ICON-1111":{"nm":"مشبك سلك الإضاءة","de":"هذا المشبك يمسك سلك الإضاءة المتدلّي بترتيب. يدٌ تُقوّم الطريق كي لا يتبعثر الضوء. حين يحلّ المساء وتُصلَح خصلة سلك مشوّشة، يهدأ الضوء في الغرفة والقلب معًا أكثر فأكثر."},"ICON-1112":{"nm":"غطاء مغناطيس الملصق","de":"غطاء مغناطيسي صغير لتعليق الملصق على الجدار. تحافظ الورقة على مكانها دون أن تُحدث ولو ثقب دبّوس واحد. اليد التي تتعامل مع ما تعتزّ به تكون دائمًا رقيقة، وهذا القلب الحريص على عدم الإتلاف مصونٌ هنا."},"ICON-1113":{"nm":"حبل شرابة الستارة","de":"حبل بشرابة يربط طرف الستارة إلى جانب. يفتح طريقًا جميلًا لدخول ضوء الصباح. اسحب الحبل المزيَّن بالشرابة مرة واحدة، فيندفع نهارٌ مشرق إلى الغرفة ويبقى."},"ICON-1114":{"nm":"ملصق حامل الشمعة العطرية","de":"ملصقٌ صغير يُلصَق على حامل الشمعة العطرية. يدوّن بدقّة أيّ عطر يحترق ومتى أُشعل لأول مرة. أن تمنح اسمًا لرائحة تحبّها، هذه العناية تجعل هواء الغرفة أكثر حنانًا."},"ICON-1115":{"nm":"أرجل مطاطية للرفّ الزخرفي","de":"أربع أرجل مطاطية تسند الرفّ كي لا يهتزّ. من مكانٍ لا يُرى، تتحمّل الثقل في صمت. صغيرة ومنخفضة فلا تلفت الأنظار، لكنّ ما يصمد في الأسفل هو ما يدوم أطول في النهاية."},"ICON-1116":{"nm":"تعليقة سهم الاتجاهات","de":"من أجل من يتردّد إلى أين يذهب، يشير سهمٌ واحد بهدوء إلى الاتجاه. إيماءة رقيقة تقول: لا تفقد طريقك. بفضل قلبٍ وضعه أحدهم مسبقًا عند كل مفترق، نمضي اليوم أيضًا دون أن نتوه."},"ICON-1117":{"nm":"حبل مفتاح دعوة الجزيرة","de":"حبل مفتاح يُوضَع في يد من يدعوك إلى الجزيرة. خذه، وستصبح من الآن فردًا من هذه العائلة. ضيافة استقبال ضيفٍ غريب في دفء الداخل تكمن بثبات في الوعد الصغير المتدلّي من طرف الحبل."},"ICON-1118":{"nm":"رقاقة درجة حرارة العلاقة","de":"رقاقة واحدة تخبرك خلسةً بدرجة الحرارة بين شخصين. أزرقٌ لا يزال متكلّفًا، أم قرمزيّ دافئ صار عليه الحال دون أن يُشعَر؟ سرعة تعمّق المودّة يصعب قياسها، لكنّ راحة اليد تدرك ذلك الدفء أولًا."},"ICON-1119":{"nm":"صندوق عيّنات الأذواق","de":"حين لا تعرف بعد ما يحبّه أحدهم، تجمع عيّنات صغيرة في صندوق وتقدّمه. وسط متعة الاختيار، ينمو الذوق ببطء. أيّها سيصير ملكك؟ الصندوق مليء بإمكانيات مثيرة."},"ICON-1120":{"nm":"دبوس حجز الرعاية","de":"وعدٌ برعاية أحدهم يُغرَز بوضوح في هذا الدبّوس الواحد. اكتب الاسم والوقت فلا يضلّ القلب طريقه. ذلك التعاون الرقيق في مناوبة رعاية أطفال بعضهم البعض ينبض هنا بالحياة."},"ICON-1121":{"nm":"كبسولة سجلّ النموّ","de":"كما تتراكم علامات قياس الطول سطرًا سطرًا على إطار الباب، هذه الكبسولة تختم بهدوء صورتك من الأمس. حين تفتح غطاءها بعد زمن بعيد ستعرف كم مشت تلك الخطوات الصغيرة بعيدًا."},"ICON-1122":{"nm":"سوار تذكار اللقاء الأول","de":"تلك الرعشة عند مصافحة اليدين أول مرة، تُربَط برفق في شريط واحد. العقدة ليست هناك لتُحلّ، بل لتُبقي دفء ذلك اليوم حيًّا عند المعصم."},"ICON-1123":{"nm":"ملصق ديكور غرفتي","de":"«هنا مكاني.» في اللحظة التي يُلصَق فيها ملصقٌ صغير واحد على زاوية المكتب، تتنفّس الغرفة الغريبة أخيرًا وتصبح غرفتي. بطاقة الاسم هي المكان الأول الذي يستقرّ فيه القلب."},"ICON-1124":{"nm":"جرّة كرات الألفة","de":"هزّها فتتدحرج بصوت «طرّ»، صوت اقتراب الاثنين خطوة أقرب. بحلول امتلاء الجرّة حتى حافّتها، مجرّد مناداة اسمك سيجعل الضحك يخرج لاستقبالك أولًا."},"ICON-1125":{"nm":"ختم تحضير الظهور","de":"الورقة الأخيرة التي تغلق المظروف. حتى هنا هو التحضير، واقلب الصفحة التالية فإذا هي المسرح. يضغط المتدرّب عليها بطرف إصبعه ويهدّئ أنفاسه. أخيرًا، ها هي البداية."},"ICON-1126":{"nm":"ماء","de":"الأكثر شيوعًا فهو الأثمن. في استوديو تدريبٍ عند الفجر والأنوار مطفأة، رشفة واحدة تنهض بمن انهار واقفًا من جديد. لطفٌ بلا شكل خاص به، يتسلّل إلى أيّ إناء."},"ICON-1127":{"nm":"ماء صافٍ","de":"شفافيّة تعكس حتى الحصى في القاع بوضوح. النبع الجبلي لا يتباهى قط بصفائه. القلب الذي لا يخفي شيئًا يُرى دائمًا هكذا، حتى القاع."},"ICON-1128":{"nm":"ماء البحر","de":"بمجرّد أن يلامس طرف اللسان، تتدفّق أمواج بعيدة. في رشفة مالحة واحدة يذوب الأفق والنوارس والميناء الذي غادرته بالكامل. البحر يبقى دائمًا في الذاكرة بطعمٍ مالح."},"ICON-1129":{"nm":"ثلج","de":"يصغر رويدًا رويدًا فوق راحة اليد، يختفي بقدر ما تقبض عليه. رغم صلابته الظاهرة، يعرف أنه سيعود إلى الماء في النهاية. الثلج نهرٌ أوقف أنفاسه للحظة."},"ICON-1130":{"nm":"كرة ثلج","de":"كتلة مضغوطة بإحكام تطير بيضاء شاقّة طريقها عبر الزقاق. ضحكٌ متقطّع وخدود احمرّت من البرد. أبيض ألعاب الشتاء التي يدسّها خلسة في أيدي الأطفال."},"ICON-1131":{"nm":"تراب","de":"يحتضن البذور، يشرب مياه المطر، ويتقبّل بصمت الخطى العابرة. جلدٌ أسود يعانق كل شيء. في أول مكانٍ لكل ما ينمو، توجد هذه القبضة الواحدة."},"ICON-1132":{"nm":"تربة خصبة","de":"أدخل أصابعك فيها فيلتفّ حولها دهنٌ أسود ناعم. سرّ بستان الجدّة الذي كان يخضرّ كل عام كان هنا بالضبط. التربة الناضجة جيدًا تهمس ببشرى الحصاد الوفير برائحة السماد."},"ICON-1133":{"nm":"طين","de":"في لحظة امتصاصه الرطوبة، يقبل أيّ شكل بطواعية. لحمٌ رقيقٌ يغدو طائرًا أو وعاءً تبعًا للمس اليد. بينما تدور العجلة، تبدأ قبضة تراب أخيرًا بالحلم."},"ICON-1134":{"nm":"رمل","de":"حبيبات دقيقة تنسلّ بهدوء بين الأصابع. كلما أمسكت بها أكثر، تدفّقت أسرع، تشبه الزمن دائمًا. في قبضة واحدة من الشاطئ ترقد أعدادٌ لا تُحصى من الأمس."},"ICON-1135":{"nm":"حصى","de":"حجارة استدارت عند حافّة الجدول. هي أثر مداعبة الماء الطويلة الطويلة حتى تلاشت الزوايا الحادّة. كلما تدحرجت بعيدًا أكثر، استقرّت في راحة اليد أرقّ."},"ICON-1136":{"nm":"حجر","de":"كتلة موضوعة بلا اكتراث على جانب الطريق. أحدهم يركلها ويمضي، وآخر يلتقطها بهدوء ليبني برجًا. الحجر نفسه يصير عبئًا أو أمنية، تبعًا للقلب."},"ICON-1137":{"nm":"بلاطة حجرية","de":"حجرٌ مسطّح عريض يعبر ساحة قصر قديم. مئات السنين من الأحذية داست عليه فحفرت انخفاضًا في وسطه. كل من يطأه خطوة بخطوة، يضيف إليه طبقة أخرى من الزمن."},"ICON-1138":{"nm":"حجر جيري","de":"أصداف من زمن كانت فيه بحرًا تصلّبت طبقة فوق طبقة لتصير حجرًا أبيض. ضعه في الفرن فيتحلّل إلى جير يطلي الجدران بياضًا ناصعًا. رغم هدوئه الظاهر، هو حجرٌ يحمل عصرًا بأكمله بداخله."},"ICON-1139":{"nm":"فحم حجري","de":"غابة قديمة غفت في سوادها. سراخس من مئات ملايين السنين تصلّبت وتكتّلت عميقًا تحت الأرض. أشعل فيه النار، فيصحو ضوء الشمس المدفون طويلًا مشتعلًا من جديد."},"ICON-1140":{"nm":"فحم الخشب","de":"يحتضن النار لكنه يبتلع الدخان بصمت. خشبٌ ضُغط أسود داخل الفرن يتفتّح أحمر دون كلمة فوق الموقد. كلما كان الشيء أكثر صمتًا، بقي دافئًا لوقتٍ أطول."},"ICON-1141":{"nm":"غصن","de":"غصنٌ انحنى بصمت بدلًا من أن ينكسر يعرف سبيل الليونة. في كل مكانٍ صمد أمام ريحٍ قاسية تنشأ عقدة، والصلابة الحقيقية هي في النهاية أثر انحناء أُحسن."},"ICON-1142":{"nm":"جذع شجرة","de":"داخل حلقاته المقطوعة تتراكم مئة ربيع وشتاء، دائرة فوق دائرة. سنون شجرة واحدة عاشتها كاملة ترقد الآن ممدّدة، تنتظر بهدوء دوره ليصبح عمود بيت."},"ICON-1143":{"nm":"خشب منشور","de":"كل مرة يمرّ المسحاج، تنكشف تعرّجات عطرة طبقة فطبقة. بينما يصير الخشب الخشن أملسًا، يتراكم نشارة الخشب على الأرض كثلج أصفر. اليد التي تصقل توقظ الفائدة."},"ICON-1144":{"nm":"لوح خشبي","de":"يفرش أرضية، يصنع مصطبة، يحيط سياجًا. حين تجتمع الألواح المنشورة باستقامة، واحدًا تلو الآخر، ينهض أخيرًا مكانٌ لعيش الناس. الأشياء العادية تتراكم لتصبح مأوى."},"ICON-1145":{"nm":"خيزران","de":"جوفٌ من الداخل، لكنه منتصب أمام الريح. عزيمته التي تنقطع عند كل عقدة لتنبت من جديد، تمنّى العلماء القدامى أن يشبهوها. هنا شيءٌ يزداد استقامة لأنه فارغ."},"ICON-1146":{"nm":"فلّين","de":"اضغطه ثم أفلته فيعود منتفخًا إلى سماكته الأصلية. حين ترى هذا النسيج الخفيف والعنيد معًا، تدرك أنّ الليونة ليست ضعفًا أبدًا. من سدادات الزجاجات إلى لوحات الإعلانات، يسند الأشياء بهدوء."},"ICON-1147":{"nm":"عشب","de":"يُداس ثم ينهض مجدّدًا مع المطر التالي. مثابرة خضراء تغطّي حقلًا بأكمله دون اسم واحد. لا تستهن بصغره، فما يبشّر بالربيع أوّلًا هو دائمًا هذا المكان الوضيع."},"ICON-1148":{"nm":"قش","de":"ما تبقّى أصفر في الحقل بعد انتهاء حصاد الخريف. إن حِيك صار سقفًا، وإن فُرش صار فراشًا دافئًا. قلبٌ أعطى كل حبّة وما زال حتى النهاية يغطّي الناس."},"ICON-1149":{"nm":"قصب","de":"حين تمرّ الريح خفيفة، حفيفٌ حفيف، يغنّي ضفّة النهر بأكملها. ساقٌ جوفاء من الداخل تبكي أبعد فأبعد. الاهتزاز نفسه هو أغنيتها، ولا يخجل القصب من ذلك أبدًا."},"ICON-1150":{"nm":"قطن","de":"حين تنفتح الكبسولة الناضجة بصوت طقّة، تتفتّح غيمة صغيرة. هذا الوبر الخفيف الناعم يصير خيطًا ثم ثوبًا، يدفّئ برفق كتفَي أحدهم في ليلة شتاء باردة."},"ICON-1151":{"nm":"صوف","de":"مرّره على يديك فيدور فيها دهنٌ ويبقى دفؤه بهدوء. معطفٌ لفّه الخروف حول جسده ليصمد أمام الجبال الباردة. ذلك الدفء المقصوص ينتقل الآن إلى شتاء الإنسان."},"ICON-1152":{"nm":"خيط","de":"رفيعٌ يكاد لا يُرى، ومع ذلك هو دائمًا من يعيد وصل طرفين منفصلين. ضعيفٌ كخصلة واحدة، لكن حين يُنسَج يصبح قماشًا كاملًا. في عمل الوصل، لا تهمّ السماكة."},"ICON-1153":{"nm":"قماش","de":"اللحمة والسدى يتقاطعان مرارًا لا تُحصى ليكوّنا نسيجًا واحدًا. إنه نتيجة خيوط كانت ستنفكّ وحدها لكنها تمسّكت ببعضها بإحكام. أنّ النسيج كلما تقارب صار أدفأ، ينطبق على الناس تمامًا."},"ICON-1154":{"nm":"جلد","de":"كلما استُخدم أكثر، تتشرّبه آثار اللمس شيئًا فشيئًا حتى يشبه صاحبه. بينما تليّن الصلابة الأولى، يتعمّق اللون ويرقّ النسيج. ذلك البريق الذي نقشه الزمن، لا شيء يستطيع تقليده."},"ICON-1155":{"nm":"ريشة","de":"خفيفة إلى حدّ أنك لا تشعر بوزنها حتى وهي على راحة يدك. خصلة واحدة تحمل ذكرى التحليق في السماء كما كانت. لا تنسَ أبدًا أنّ الأخفّ هو من ارتفع أعلى."},"ICON-1156":{"nm":"صدفة بحرية","de":"تخطر ببالك فجأة كلمات الجدّة: «ضعها على أذنك». على لمعانها القوسي الداخلي منقوش البحر الذي غادرته بالكامل، حتى إن الصدفة الفارغة تحمل صدى تموّج زمنٍ مضى."},"ICON-1157":{"nm":"مرجان","de":"تصلّب كالحجر، لكنه كان مرّة مستعمرة تتنفّس بيقين. في عمق البحر البطيء يقضي مئات السنين يمدّ أغصانه. أقوى الأغصان لا تنمو إلا بعد أطول انتظار."},"ICON-1158":{"nm":"لؤلؤة","de":"عاجزةً عن تحمّل إزعاج حبّة رمل واحدة، لفّتها المحارة بهدوء في الضوء. احتضن الألم واجعله مستديرًا فيصبح بهذا التألق، عزاءٌ صغير يقدّمه البحر."},"ICON-1159":{"nm":"عشب بحري","de":"شريط أخضر متدلٍّ زلق على صخور الشاطئ عند الجزر. أمسكه فتندفع رائحة بحرية نفّاذة. بلا جذور، مستسلمًا للتيار، يعتني البحر بحديقته بهدوء."},"ICON-1160":{"nm":"نوري","de":"قرّب ورقة سوداء واحدة من النار قليلًا فتخضرّ وتفوح رائحة شهيّة. ذلك الصباح الذي كانت تُلفّ فيه حول أرزّ طازج. رقيقة جدًا لكنها تحتضن بسهولة سعادة وجبة كاملة."},"ICON-1161":{"nm":"ملح","de":"أنا البلّورة البيضاء التي تركها البحر تحت الشمس. قبضة واحدة تعمّق شوربة بلا طعم، لكن انزلاق اليد يطمس كل نكهة. طرف الإصبع وحده الذي يعرف القدر المناسب هو من يجيد استعمالي حقًّا."},"ICON-1162":{"nm":"شظية زجاج","de":"في مكان انكسارها فقط، تعكس الضوء أخيرًا فيتفتّح قوس قزح. موهبةٌ لم تكن تعرفها وهي سليمة. حتى الشيء المكسور له حصّة من ضوء الشمس يمنحها، كما تخبرك بهدوء الشظية الراقدة عند النافذة."},"ICON-1163":{"nm":"زجاج","de":"أن تكون شفافًا لا يعني فقط أنه لا شيء لتخفيه. بل أنه محا شكله الخاص كي يدع الضوء يعبر بالكامل. حتى في البقاء مخفيًّا غير مرئي، هناك أناقة باردة حين تلمسه اليد."},"ICON-1164":{"nm":"زجاجة","de":"يجب أن يكون داخلها فارغًا كي تحتوي شيئًا. مربّى، أو حفنة زهور برّية، أو رسالة مطويّة، يتغيّر اسمها بحسب ما يدخلها. الإناء الذي لا يخشى الفراغ هو الأكثر سخاءً."},"ICON-1165":{"nm":"زجاجة فارغة","de":"أحبّ الهدوء الذي يأتي بعد شرب آخر قطرة. أحدهم يرميني، وآخر يشطفني ويضعني على حافّة النافذة ليملأني بضوء الشمس. أن تجد نفعًا جديدًا حيث انتهى كل شيء، تلك هي الحياة الثانية لما أُفرِغ."},"ICON-1166":{"nm":"ورق","de":"أرقد مفروشًا أبيض، جاهزًا لتدوين أي شيء. أنا دائمًا من يحدّق أطول في قلب المتردّد أمام السطر الأول. صبر الصفحة البيضاء أعمق من الحبر بشبر."},"ICON-1167":{"nm":"ورق قديم","de":"الاصفرار ليس شيخوخة بل صمود. في كل ثنية تشرّب دفء الأيدي التي فتحته وقرأته. الورق العتيق، كي لا يُنسى، يدوّن بلونه الخاص الزمن الذي مضى."},"ICON-1168":{"nm":"حبر","de":"يبدأ نقطة واحدة، يصير جملة، وحين يجفّ يبقى كوعد. إن انتشر، بقي أثر ذلك اليوم كما انتشر. لأنّ مهمّتي أن أجعل الأمور لا رجعة فيها، يضغطني الناس مرّة أخرى بحذر أشدّ."},"ICON-1169":{"nm":"خام حديد","de":"حجرٌ نام نومًا أحمر تحت الأرض. لا يسلّم ما بداخله من حديد إلا بعد أن يمرّ عبر النار مرّة. الصلابة ليست صلبة منذ البداية، بل اسمٌ يُمنح بعد اجتياز الحرارة."},"ICON-1170":{"nm":"سبيكة حديد","de":"لم تبرد في كتلة واحدة إلا بعد أن احتمل الخام النار. هذا الشكل البارد الثقيل يصبح جسرًا وسيفًا ومعوّلًا. لأنّ استخدامي لم يُحدَّد بعد، يمكنني أن أصير أيّ شيء."},"ICON-1171":{"nm":"خام نحاس","de":"خرجتُ من التراب مرتديًا صدأً بلون التفّاح الأخضر. اصهرني فيرنّ جرس، ويقف تمثال، ويسري سلك. حتى وأنا نائم في الأرض الحالكة، كنت دائمًا أنتظر دوري لأُدعى إلى شيء ما."},"ICON-1172":{"nm":"سبيكة نحاس","de":"أبقِها إلى جانبك طويلًا فتخيط لنفسها ثوبًا أزرق بيدها. البعض يسمّي ذلك اللون عيبًا، والبعض يداعبه بوصفه نقشًا للسنين. المعدن الذي لا يخجل من لونه المتغيّر هو الأكثر حبًّا على مرّ الزمن."},"ICON-1173":{"nm":"خام ذهب","de":"نقطة واحدة يظفرون بها بعد غربلة رمل النهر مرارًا وتكرارًا. ليست ثمينة لندرتها بل لأنها لا تتغيّر أبدًا. كان القدامى يضعونها في الأيدي عربون وفاء، تمنّيًا أن يشبه القلب صفاءها الذي لا يصدأ."},"ICON-1174":{"nm":"سبيكة ذهب","de":"ترقد كتلة واحدة، لا تخفت ولا تصدأ. سمعت أكثر من طمع الناس، لكنّني بذاتي لا أطمع في شيء. مجرّد صمتٍ ثقيل مخلص فقط لعمل التألّق."},"ICON-1175":{"nm":"خردة معدنية","de":"لم أنتهِ من النفع، بل أنتظر نفعًا قادمًا. مسامير مكسورة وعلب مسحوقة تجتمع معًا لتلتقي النار الحارّة من جديد. كلمة «مهمَل» تعني بالنسبة لي أنني أستريح قليلًا."},"ICON-1176":{"nm":"برغي","de":"وحدي لا أستطيع فعل شيء. فقط حين أُلوى داخل لوحين لأربطهما بإحكام، ألعب دوري أخيرًا. موهبة جسدٍ صغير يمسك شيئًا كبيرًا، وحتى في قوة الشدّ تلك عناية."},"ICON-1177":{"nm":"مسمار","de":"بمجرّد أن أُغرَز، نادرًا ما أتراجع. مع كل ضربة مطرقة، ما يتعمّق ليس جرحًا بل وعدًا. إن كان الأمر يتعلّق بربط شيء بإحكام، أهب رأسي طيّبة خاطر."},"ICON-1178":{"nm":"ترس","de":"أدفع أسنان جاري لندور معًا. لا أحاول أن أتسابق منفردًا، بل أعرف كيف أوائم سرعة من بجانبي. كالساعة التي لا يجري الزمن فيها إلا حين تتشابك الأسنان، أومن أنّ التناغم بحدّ ذاته هو الحركة."},"ICON-1179":{"nm":"نابض","de":"كلما ضُغط أكثر، جمع في داخله قوّة العودة أكثر. الانحناء ليس استسلامًا بل استعدادًا للانبساط من جديد. حلزونٌ صغير يرتدّ بقدر ما امتصّ من صدمة، حيث المرونة نفسها هي الصلابة."},"ICON-1180":{"nm":"سلك كهربائي","de":"من الخارج غلافٌ هادئ، ومن الداخل طريقٌ يتدفّق بلا توقف. من أماكن غير مرئية ينقل الضوء والصوت. كلمسة يد تربط بصمت خلف الكواليس، ممرٌّ يزداد ثقة لأنه لا يظهر."},"ICON-1181":{"nm":"بطارية","de":"تخزّن ضوء نهار كامل شيئًا فشيئًا داخل جسمها الصغير. حين تنفد، فقط أعد ملأها، تقول، ولا تعدّ الفراغ نهاية أبدًا. تحمل مساءً صغيرًا لتضيء ليل أحدهم الطويل."},"ICON-1182":{"nm":"مصباح كهربائي","de":"خصلة رفيعة واحدة تتوهّج حمراء وتدفع الظلام بعيدًا. تحرق جسدها لا لتُدفّئ الغرفة بل لتضيئها. أكثر سخونة عند لحظة الإشعال، ولذا أكثر سطوعًا، شمسٌ صغيرة للحظة واحدة."},"ICON-1183":{"nm":"عدسة","de":"تجمع الضوء المتناثر وتُثبته بوضوح في نقطة واحدة. تستدعي بهدوء النجم البعيد والحرف الصغير فوق راحة اليد على حدّ سواء. لتساعد فعل الرؤية، تخفي شكلها الخاص، وسيطة صافية مستديرة."},"ICON-1184":{"nm":"مطاط","de":"اضغط عليّ أو مدّني، فأعود إلى مكاني في النهاية. حتى من عابوا ليونتي يختارونني في يوم ممطر. أتلقّى الصدمة القاسية برفق، ومثابرة تعيش حتى في هذه الليونة."},"ICON-1185":{"nm":"قطعة بلاستيك","de":"قطعة صغيرة انفصلت عن الجسم الأصلي. كادت تُرمى، لكن إن اجتمع الكثير منها تصبح جديدة مجدّدًا. ليست خفيفة لأنها صغيرة، بل قادرة على السفر بعيدًا لأنها خفيفة، جزءٌ من شيء ما."},"ICON-1186":{"nm":"حبل","de":"لا يصبح خيطًا واحدًا إلا حين تُفتل خصلات عديدة. وحدها تنفكّ بسهولة، لكن حين تُنسج تجرّ سفينة وتربط حملًا. عقدة تعاون قديمة، خشنة على راحة اليد، تزداد متانة بقدر ما تُلوى معًا."},"ICON-1187":{"nm":"قماش شراع","de":"لا يكره الريح بل يحتضنها ملء صدره. لا يرسل السفينة بعيدًا إلا حين ينتفخ مشدودًا، فحتى الريح المعاكسة تصير لي قوّة. طريقة التقدّم باحتضان العاتي بدلًا من مقاومته، تعلّمتها في البحر."},"ICON-1188":{"nm":"شظية مرساة","de":"مجرّد زاوية من مرساة، لكنها تتذكّر ذلك الثقل كاملًا. أيام الإمساك بالقاع العميق وإيقاف سفينة عن الحركة. حتى وقد انفصلت الآن، هي شظية ثقيلة تعرف وزن البقاء."},"ICON-1189":{"nm":"مسمار سفينة","de":"مسمارٌ ثبّت سطحًا يتمايل مع الأمواج، نقطة بعد نقطة. حتى وقد صدئ أحمر من الملح، لم يتخلّ عن مكانه حتى النهاية. حتى في تثبيت شيء عائم بإحكام، يكمن عزم صلب."},"ICON-1190":{"nm":"قماش مقاوم للماء","de":"لا يشتكي من عمل صدّ المطر. يتلقّى بصمت ما ينهمر من الأعلى، ويحفظ ما تحته جافًّا. رغم بساطته، طبقة واحدة موثوقة تحمي حمل أحدهم من البلل."},"ICON-1191":{"nm":"صبغة","de":"حين تتسلّل بهدوء إلى قماش قطني، تصبح أخيرًا لونًا. نيليّة كانت أم فوّة الصبّاغين، الأمّهات القديمات كنّ يصبغن أطراف أصابعهنّ وهنّ يكسين القماش لونًا. حتى في فعل الرسوب والتشرّب، هناك عمق نادرًا ما يزول."},"ICON-1192":{"nm":"زيت عطري","de":"قطرة واحدة تكفي ليتفتّح حقلٌ واسع دفعة واحدة، يملأ الغرفة. ضيفٌ يصل أولًا رغم أنه لا يُرى بالعين. مشهد يلمس طرف الأنف أولًا، يشدّ خلسة طرف ثوب الذكريات النائمة."},"ICON-1193":{"nm":"شمع","de":"يسيل حين يتلقّى الحرارة ويتصلّب حين يبرد، حافظًا على شكله. متنقّلًا بين الليونة والصلابة، يشكّل بهدوء أيّ شيء. يغلق ويختم ويلمّع، مادّة رقيقة تبدّل تعابيرها بحسب الحرارة."},"ICON-1194":{"nm":"شمعة","de":"تذيب جسدها ببطء لتضيء زاوية واحدة من الظلام. حين تحترق بالكامل، لا يبقى سوى قامتها المتقلّصة، لكنّ الوقت الذي دفّأت فيه ليل أحدهم لا يختفي أبدًا. الفتيل المستقيم يعرف طريقة التألّق وهو يصغر."},"ICON-1195":{"nm":"سماد عضوي","de":"أشياء متعفّنة تجتمع معًا لتصبح أخصب تراب. قشور مرمية وأوراق يابسة تصير طعام براعم الربيع الجديدة. في المكان الذي ظننته انتهى، تهدّئ الحياة القادمة أنفاسها الأولى بهدوء."},"ICON-1196":{"nm":"أرزّ","de":"تحتاج اليد إلى ثمانٍ وثمانين لمسة قبل أن تحمل حبّة واحدة في راحتها. من زراعة الشتلات إلى الدراسة، تنطوي سنة الفلّاح كاملة في هذه الحبّة الصغيرة. طبقٌ من أرزّ يتصاعد منه البخار هو بذاته فصول أحدهم الأربعة."},"ICON-1197":{"nm":"أرزّ بنّي","de":"قشرته الخارجية فقط قُشرت قليلًا، وحافظ على لونه الأصلي كما هو. أنّه يزداد شهيّة كلما مضغته أكثر هو طعم صدق لم يستعجل. عناد الحبّة الصلب، يرفض أن يُصقَل ناعمًا ويُبقي على نسيجه الخشن."},"ICON-1198":{"nm":"قمح","de":"يتذكّر الحقل الذهبي الذي كان ينحني برأسه دفعة واحدة مع الريح. يصبح خبزًا ونودلز وعجينة حساء، يدفّئ موائد كل بقاع العالم. حبّة، لأنها شائعة، تسلّلت أعمق في حياة الناس."},"ICON-1199":{"nm":"دقيق","de":"لا يتهيأ ليصبح أيّ شيء إلا بعد أن يصير مسحوقًا أبيض ناعمًا جدًّا. يلتقي الماء فينتفخ، ويلتقي النار فينضج. لأنه بلا شكل محدّد، هو قاعدة وديعة تأخذ أيّ شكل تعجنه اليدان."},"ICON-1200":{"nm":"عجين","de":"يمتزج المسحوق والماء في كتلة واحدة تحت راحة اليد. كلما عُجن أكثر ازداد مطاطية، وكلما انتُظر أكثر انتفخ مستديرًا. إن استُعجل تصلّب، فوقت التخمّر وحده لا يمكن استعجاله، يقول المخبز العتيق."},"ICON-1201":{"nm":"فتات الخبز","de":"حين تنفض الغبار الأبيض العالق بأطراف أصابعك، تجد كُمّيك قد ابيضّا دون أن تدري. يصبح قرمشاً حين يُستعمل غطاءً للقلي، ويتكوّم ناعماً كأول ثلوج الشتاء. إنه أخف أثر يتركه رغيف خبزٍ بعد خَبزه، لكن حتى الأشياء الصغيرة تنمو فائدتها."},"ICON-1202":{"nm":"معكرونة الباستا","de":"في اللحظة التي تنشر فيها حفنة منها كالمروحة فوق الماء المغلي، تعبر أشعة شمس بعيدة إلى المطبخ. الخيوط الطويلة عملٌ يخص المعصم، ونضج \"أل دنتي\" هو قلبٌ يجيد الانتظار وهو لمّا ينضج تماماً بعد. انظر إلى ذلك البريق وهو يلتف حول الشوكة مرة تلو الأخرى."},"ICON-1203":{"nm":"راميون سريع التحضير","de":"كيسٌ يُهرَّب إلى الموقد عند الفجر، بعدما مُسِح كل مكياج المسرح. الدقائق الثلاث التي يحتاجها الشعيرية لتلين هي أخص لحظات اليوم كله خصوصية. يبرد التوتر مع أنفاسك وأنت تنفخ عليها، وخلف نظارة غشّاها البخار ينتهي اليوم بهدوء."},"ICON-1204":{"nm":"توك (كعك الأرز)","de":"لا يصير الأرز \"توك\" إلا بعد أن يتحمّل ضربات الهاون. سادةً، أو إنجولمي، أو سونغپيون - فالحَبّة نفسها تنال مئة اسم بحسب مهارة اليدين التي تشكّلها. حين توضع على مائدة الاحتفال، تستدعي المحبة قبل الفم؛ طعامٌ لا يكتمل طعمه إلا بالمشاركة."},"ICON-1205":{"nm":"توك حساء رأس السنة","de":"إذا قُطِّعت أسطوانة التوك بشكل مائل، خرجت أقراصاً مستديرة كقطع نقود صغيرة. أهو كعك أرز يطفو في المرق الأبيض، أم أمنية صغيرة مستديرة؟ إفراغ وعاء في صباح العام الجديد يضيف سنة إلى العمر - طريقة رقيقة، هي طريقة هذا البلد في العدّ."},"ICON-1206":{"nm":"بطاطا","de":"انفض عنها التراب يظهر وجه مستدير. جذر تضخّم بصمت وسط رياح المنحدرات، هشّ إذا طُهي بالبخار، ولذيذ إذا قُلي. جذرٌ أمين أشبع بطون العائلة حتى في الأيام التي خفّت فيها الجيوب."},"ICON-1207":{"nm":"بطاطا حلوة","de":"حين تُنصب برميل البطاطا الحلوة المشوية عند مدخل الزقاق، كان ذلك إيذاناً ببداية الشتاء. تُقشّر ورقة القصدير فيدفئ البخار الأصفر الأصابع أولاً، وتلك الحلاوة مكافأة الجذر الذي صمد أمام البرد. دفءٌ يليق بأن يُنفَخ عليه ويُقسَم نصفين ليُتقاسم."},"ICON-1208":{"nm":"جزر","de":"عمودٌ برتقالي واحد يغوص مستقيماً في التراب. كنتَ تظن أن الأرانب وحدها تحبه، لكن القلي يوقظ حلاوته الكامنة، وفي الحساء يضيف حتى لونه. كان الكبار على حق حين قالوا إنه مفيد للعينين."},"ICON-1209":{"nm":"فجل","de":"جذرٌ واحد أبيض ثقيل يكفي ليجعل مائدة الشتاء وافرة. حادّاً بارداً في \"دونغتشيمي\"، منعشاً في حساء الفجل، مقرمشاً في \"كاكدوغي\". لا شيء منه يُهدر، حتى أوراقه الخضراء تُجفَّف تحت الأفاريز لتصبح \"سيريغي\" - خضارٌ مقتصد."},"ICON-1210":{"nm":"بصل","de":"تقشّره فتنزل دمعة تتدحرج. لحمه الحاد اللاذع يتحول حلواً كأنه كذبة حين يلامس الزيت الساخن. اسمه يُكتب في أول سطر لكل طبق كوري تقريباً - بطلٌ صامت يمهّد أساس النكهة دون ضجيج."},"ICON-1211":{"nm":"بصل أخضر","de":"حين تُرشّ الساقُ البيضاء المقطعة ناعماً والأوراق الخضراء فوق المرق، عندها فقط يشعر الطبق بأنه اكتمل حقاً. اغرس الجذر المتبقي في كوب ماء وسينمو من جديد بسرعة - حديقة نافذة صغيرة لأهل البيت المدبّرين."},"ICON-1212":{"nm":"ثوم","de":"ست فصوص تجتمع مستديرة لتكوّن رأساً واحداً. الجذر اللاذع الذي يُقال إنه حوّل دبّة إلى امرأة. اسحقه بظهر السكين فتتفجّر رائحته فوراً؛ فبدون حفنة منه لا يستقيم لا كيمتشي ولا يخنة."},"ICON-1213":{"nm":"زنجبيل","de":"جذرٌ صغير معقّد كعقدة وعرة. شريحة واحدة تكفي لتهدئة رائحة السمك وتدفئة الجسم البارد من الداخل. في ليالي الزكام التي كنتَ تئنّ فيها، بدأ ذلك الكوب الدافئ المنقوع بالعسل من هذه اللسعة الحادة."},"ICON-1214":{"nm":"كرنب صيني (نابا)","de":"مِلّح الأوراق المكتنزة، وعندها فقط يُفتح الفصل الأول من الكيمتشي. في أواخر الخريف كانت تتكوّم كالجبال في كل فناء. أن تجتمع العائلة كلها لتُخلّل دفعة واحدة كان وعداً بعبور الشتاء الطويل معاً."},"ICON-1215":{"nm":"كرنب","de":"تقشّر أوراقه المطوية المستديرة طبقة بعد طبقة فلا تجد نهاية، حتى يهدأ قلبك دون أن تشعر. مسلوقاً يصير ليّناً، ومقلياً حلواً. خضارٌ يخفي وراء مظهره الخشن رقّة غير متوقعة."},"ICON-1216":{"nm":"خس (آيسبرغ)","de":"تضع قطعة لحم في الورقة المقعّرة، وتعلوها لمسة من صلصة السامجانغ، ثم تحشو فمك بلقمة كاملة. في جلسة يلفّ فيها الجميع طعامهم ويأكلون، يترك كل واحد رسمياته جانباً بهدوء - وهذه، لا أقل، ضيافة اللون الأخضر."},"ICON-1217":{"nm":"خس ورقي","de":"أول ورقة تطلع في زاوية من الحديقة المنزلية. تُقطف فتعود لتنبت، فتملأ المائدة طوال الصيف. تلك النكهة الخضراء الطازجة - مغسولة بماء بارد وملفوفة باليد - هي، لدى البعض، كل طعم الوطن."},"ICON-1218":{"nm":"سبانخ","de":"ذلك الأخضر الكرتوني الذي كان يمنح قوة دافقة حين تُفرَّغ العلبة. مسلوقة تتقلص إلى حفنة، لكن رائحتها وحيويتها تبقى كاملة. جيدة متبّلة باليد أو مذابة في حساء فول الصويا - خضارٌ لا يجوز الاستهانة به لمجرد شيوعه."},"ICON-1219":{"nm":"سرخس (كوساري)","de":"تُقطف البراعم الغضّة التي يهبها جبل الربيع، ثم تُسلق وتُجفَّف. لا تصل إلى مائدة الأجداد ولا إلى طبق البيبيمباب إلا بعد ذلك التعب الطويل. عشبٌ ثمين، بقدر ما يتطلب من عناية اليدين، بقدر ما تتشرّبه من اهتمام، ربّاه الجبل موسماً كاملاً."},"ICON-1220":{"nm":"أعشاب برية جبلية","de":"هدية الربيع، تبدو بلا اسم لكن كل واحدة منها تحمل رائحتها الخاصة. يد الجدة تعرف من نظرة واحدة أي ورقة على درب الجبل صالحة للأكل. في سلة واحدة من الأعشاب، يأتي فصل كامل برائحته."},"ICON-1221":{"nm":"شيح (أرطماسيا)","de":"العشب المرّ العطري الذي يخترق الأرض المتجمدة أولاً. إذا صُنع منه كعك أرز، دخل ضوء الربيع إلى الفم مباشرة. في الشهر الأول كانوا يعتقدون أن غليه في حساء يدرأ نحس السنة، فكان الربيع دائماً يأتي من هذه الرائحة."},"ICON-1222":{"nm":"ورق البريلا","de":"ورقة واحدة تكفي لتصبغ الفم كله برائحتها العميقة. رافقها لحم صدر خنزير مشوي ذهبي، أو خلّلها طبقات في صلصة الصويا، فيختفي وعاء الأرز في لمح البصر. هذه الرائحة الفريدة لا تألف القلب إلا على مائدة هذه الأرض."},"ICON-1223":{"nm":"فلفل أخضر حلو","de":"ثمرة خضراء جوفاء تتكسّر بقرمشة. مرارتها الخفيفة توقظ شهية خامدة، وإذا قُليت بالزيت ازداد لونها وضوحاً. مجرد تقطيعها ورشّها فوق أي طبق يمنحه انتعاشاً فورياً."},"ICON-1224":{"nm":"فلفل رومي ملون","de":"أحمر وأصفر وبرتقالي، ألوان كإشارات المرور تملأ سلة كاملة. عضّة نيئة تسيل منها عصارة حلوة، ومجرد ألوانها تضيء المائدة. المقولة القائلة إن الخضار الجميل يفتح الشهية تنطبق هنا تماماً."},"ICON-1225":{"nm":"طماطم","de":"الحمراء المستديرة التي لم يُحسم الجدال حولها بعد: أفاكهة هي أم خضار؟ إذا طُهيت طويلاً عمُق طعمها، وإذا أُكلت نيئة كانت في غاية الانتعاش. إنها الثمرة التي تجمع شمس منتصف الصيف بأمانة، فعضّة واحدة منها تُفجّر نهاراً كاملاً."},"ICON-1226":{"nm":"خيار","de":"الأخضر الأكثر تبريداً لحرّ الصيف. أطفه في حساء بارد فيبرد الفم، أو خلّله \"سوباغي\" فتعود له قرمشته. في الأيام الحارقة يمكن تقطيعه رقيقاً ووضعه فوق العينين - خضارٌ منعش من الداخل والخارج."},"ICON-1227":{"nm":"يقطين","de":"يتدلّى مستديراً في طرف الكرمة، يملأ نفسه بالحلاوة ببطء حتى أواخر الخريف. مطهواً طويلاً يصير عصيدة صفراء تهدئ المعدة، ومقلياً يصبح فطيرة ذهبية. معلّقاً تحت الإفريز، يكون مخزناً موثوقاً طوال الشتاء."},"ICON-1228":{"nm":"يقطين أخضر صغير","de":"الأخضر الفاتح الذي يتضخّم يوماً بعد يوم في حديقة الصيف. مقطّعاً في يخنة فول الصويا، أو مقلياً ذهبياً في فطيرة - طريّ لدرجة تلين حتى في فم طفل صغير. شائعٌ، وشيوعه بالذات يزيده امتناناً، ضيفٌ دائم على مائدة منتصف الصيف."},"ICON-1229":{"nm":"باذنجان","de":"ثمرة طويلة يلمع سطحها البنفسجي كالحرير. تمتصّ الزيت فتصير طرية بلا حدود، وإذا طُهيت بالبخار جيداً، صار نسيجها ناعماً كالحرير. تبدو عادية لكنها تتناسب مع كل شيء تقريباً - ممثل مساعد رقيق على المائدة."},"ICON-1230":{"nm":"ذرة","de":"حبّات صفراء تصطف بانتظام، حبة إثر حبة. وجبة صيفية خفيفة تُطهى بالبخار وتُنفَخ ثم تُقضم، وهي أيضاً إشارة سارّة بنضج الحقول. وفي حزمة من الشعر الناعم، تكمن الحلاوة بكامل وفرتها."},"ICON-1231":{"nm":"فول الصويا","de":"حبات صغيرة صلبة تشرب الماء طوال الليل وتنتفخ. مطحونة ناعماً تصير حليب صويا، ومخمّرة جيداً تصير معجوناً - أغلب بروتين مائدة هذه الأرض بدأ من هنا. ادفن حبة واحدة في التراب وستعود نبتة كاملة من جديد."},"ICON-1232":{"nm":"توفو","de":"حين يشرب فول الصويا الماء ويُطحن ويتجمّد، يصبح كتلة بيضاء بزوايا مستقيمة. طريّ ومسالم، لا يفرض لونه على أي حساء يدخله. ينهار برفق حتى بلمسة ملعقة - طعامٌ فضيلته هي البساطة ذاتها."},"ICON-1233":{"nm":"فول أحمر","de":"اسلق الحبات الصغيرة الحمراء طويلاً فتنبثق حلاوة داكنة محمرّة عميقة. في أطول ليلة، كانت وعاء دافئ من عصيدة الفول الأحمر تطرد البرد والأرواح الشريرة معاً - وهذا القلب لا يزال ساكناً فيه. في طبقات كعك \"سيروتوك\"، كان ذلك الأحمر عناءً وإخلاصاً."},"ICON-1234":{"nm":"معجون الفول الأحمر","de":"فول أحمر مسلوق يُهرَس ناعماً ثم يُغلى ويُغلى مرة أخرى ليصير حشوة طرية. ملعقة بين قطعتي خبز، أو داخل كعك أرز، أو فوق ثلج مبشور - خيط واحد من الحلاوة يُدفئ حتى الذكريات القديمة. كل ذلك الوقت الطويل من التصفية والغلي يتحول بذاته إلى حلاوة."},"ICON-1235":{"nm":"فطر","de":"بعد توقف المطر، يطلّ برأسه بلا صوت في ظل الغابة الخافت. مهارة التراب التي تنمّي رائحتها الخاصة دون ذرة شمس واحدة. حفنة منه فقط في الحساء تمنح مذاقاً عميقاً غنياً بلا لحم - سرٌّ تخبئه الغابة."},"ICON-1236":{"nm":"فطر شيتاكي","de":"مظلّة بنية تفتح قبعتها على اتساعها. مجفّفاً تحت الشمس تماماً، تتعمّق رائحته أضعافاً، فقبعة واحدة مجففة تكفي وحدها لتُغني قدراً كاملاً من المرق. ركيزة راسخة لمائدة النباتيين، ورفيق قديم لمن يعرف عمق النكهة."},"ICON-1237":{"nm":"فطر الصنوبر","de":"في أعماق غابة صنوبر خريفية، لا يطلّ برأسه إلا بجوار أشجار الصنوبر. لا يمكن زراعته ولا بد من العثور عليه سيراً على الأقدام، ما يجعل رائحته أكثر ثمناً. مشوياً قليلاً مع رشّة ملح فقط، تدخل قطعة من الغابة إلى الفم."},"ICON-1238":{"nm":"فطر الملك","de":"مزّق الساق السميكة على طول ألياها فتصل مطاطيتها إلى يدك مباشرة. ينمو بثبات في كل فصل، فلا يبتعد أبداً عن المائدة. مشوياً أو مقلياً - داخل لحمه الوفير يكمن شبع سهل بلا عبء."},"ICON-1239":{"nm":"فراولة","de":"في طرف البيت البلاستيكي الذي صمد أمام الشتاء، تنضج حمراء أولاً. عضّة واحدة حامضة حلوة، تماماً كأول تحية لأوائل الربيع. ضع حبة واحدة مستديرة فوق كعكة، وسيتحول يوم عادي إلى ذكرى سنوية."},"ICON-1240":{"nm":"توت أزرق","de":"تنفجر بصوت خفيف فتنتشر حموضة زاهية في الفم كله. تلتقط الحبات البنفسجية الصغيرة واحدة تلو أخرى حتى يفرغ العلبة دون أن تشعر، وإذا رُشّت فوق حليب أبيض، انفتحت سماء ليلية صغيرة أمام عينيك."},"ICON-1241":{"nm":"تفاح","de":"عضّة واحدة، وقرمشة خفيفة، فيتناثر الخريف. ذلك الأحمر الذي كانت جدة البستان تمسحه بمريلتها وتناوله لك، لون لا يأتي إلا من احتضان طويل لأشعة الشمس. كلما كان أصلب، عرف كيف يبقى حلواً حتى النهاية."},"ICON-1242":{"nm":"كمثرى","de":"تقشّر قشرته فتبرد أطراف أصابعك أولاً. في الصف الأول من مائدة طقوس تشوسوك، حين تفيض عصارته الباردة الحلوة في الفم، تأتي نسمة من ريح الخريف الليلية لتجلس بهدوء بجانبك."},"ICON-1243":{"nm":"خوخ","de":"في كل مكان سقطت فيه زهرة الخوخ، يتشكّل صيفٌ ناعم الزغب. اضغط عليه قليلاً فتفوح رائحته أولاً، وفي لحظة العضّة يتبعك الفصل كله إلى داخل فمك."},"ICON-1244":{"nm":"عنب","de":"حبات بنفسجية تتدلى في عنقود واحد، يستند بعضها إلى بعض. تنفجر إحداها فتسبق الحموضة، وتتأخر الحلاوة نصف نبضة - كأنها جوقة أنيقة تنشدها آخر أيام الصيف."},"ICON-1245":{"nm":"عنب أخضر","de":"يترك اللون الأخضر الفاتح ضوء الشمس يعبر مباشرة، فيضيء مصباح في كل حبة. انتعاشٌ نظيف بلا بذور، حلاوة بلا زيادة، كأول عبارة تُنطق لتوّها بلا شوائب."},"ICON-1246":{"nm":"ليمون","de":"احكّ القشرة الصفراء بظفرك فتنبثق رائحة تُوقظ طرف أنفك فجأة. قطرة واحدة تجعل شفتيك تنقبضان تلقائياً، لكن في نهاية تلك الحموضة زاوية غريبة يضيء فيها اليوم كله."},"ICON-1247":{"nm":"ليم","de":"أصغر من الليمون وأشد اخضراراً، تحييك هذه الثمرة أولاً برائحتها الحادة اللاذعة. شريحة واحدة تكفي لإيقاظ حتى الماء الفاتر فوراً - حفنة صغيرة من الانتعاش، صغيرة لكن قوية."},"ICON-1248":{"nm":"برتقال","de":"لحظة تقشيره تعلق برائحة الشمس أصابعك. ضع فصاً فصاً في فمك فتنفجر بالونات صغيرة من العصارة الحلوة - وشيء مستدير يجعل حتى مزاجك يتدحرج مستديراً."},"ICON-1249":{"nm":"يوسفي","de":"أتذكر ذلك الطعم؟ تقشيره وقدماك مدسوسة تحت اللحاف على الأرضية الدافئة في الشتاء. الرائحة التي كانت تنتشر من بين أظافرك تصبغ الغرفة كلها بالأصفر. كيس واحد كان يكفي حجّة لتجتمع العائلة حوله."},"ICON-1250":{"nm":"موز","de":"كانت هناك أيام في فجور جائعة في زاوية غرفة التدريب، اكتفيتُ بوجبة من ثمرة صفراء واحدة تدحرجت من الحقيبة. طريّة، حلوة، ومشبعة - أرقّ حلٍّ مؤقت على الإطلاق."},"ICON-1251":{"nm":"أناناس","de":"لا بد أن تعبر طبقة من القشرة الشائكة قبل أن يظهر اللحم الأصفر. لقمة واحدة في الفم، وتلسع الحموضة الحلوة اللسان، وتظل رائحة بحر الجنوب عالقة عند الشفتين دون أن تشعر."},"ICON-1252":{"nm":"مانجو","de":"افصل اللحم الناضج بيدك فتبلّل رائحته الدبقة الحلوة أصابعك. حين يذوب اللون الأصفر العميق ويختفي في الفم، يمرّ حلمٌ حلو كقيلولة صيفية قصيرة."},"ICON-1253":{"nm":"جوز الهند","de":"هزّ القشرة الصلبة فتسمع رشرشة الماء بداخلها. اكسرها فيظهر اللحم الأبيض والعصير المنعش - جرة صغيرة يتماوج بداخلها بحرٌ بعيد كاملاً."},"ICON-1254":{"nm":"فاكهة التنين","de":"مظهرها بحراشف وردية يجعلك تتردد للحظة، لكن إذا شققتها وجدت داخلها الأبيض منقّطاً ببذور سوداء صغيرة. طعمها بسيط ومظهرها فاره - محتالة ظريفة، ظاهرها عكس باطنها تماماً."},"ICON-1255":{"nm":"كيوي","de":"اشقّ البني المكسوّ بالزغب نصفين فتظهر جوهرة خضراء. اغرف ملعقة من مقطع مرصّع ببذور سوداء كالنجوم، وقضمة حامضة واحدة تهزّك من النوم."},"ICON-1256":{"nm":"دجاج","de":"ضَعه في مقلاة مزيّتة فيطبخ صوت القلي الذهبي أولاً. لطيف وطري، يجلس بسهولة على أي مائدة - رفيق دائم لوجبة سهلة هادئة."},"ICON-1257":{"nm":"لحم خنزير","de":"يتشوّى على الشواية بصوت الطقطقة، والدهن يتطاير متناثراً وهو يحمرّ. في ليالي العشاء الجماعي حين كنت تحشو فمك بلقمة ملفوفة بورقة خس مع لمسة من صلصة السامجانغ، كانت النكهة الغنية تُدفئ المكان كله."},"ICON-1258":{"nm":"لحم بقري","de":"في كل خيط أحمر، يتخلل الدهن بدقة ويلمع. ضعه على صفيحة حجرية ساخنة فتملأ رائحته المكان أولاً، وفي اللحظة التي تدخل فيها قطعة إلى فمك، ينحلّ تعب اليوم بهدوء."},"ICON-1259":{"nm":"لحم مقدد","de":"على مقلاة الصباح يتحمّر بقرمشة، والدهن يرقص متطايراً. رائحته المالحة وحدها تكفي لتجذب حتى أفراد العائلة النائمين متأخرين، فرك أعينهم، إلى المطبخ - وجبة تناديها الرائحة أولاً."},"ICON-1260":{"nm":"سجق","de":"يتفتّح موضع الشقوق على اتساعه فتنفجر العصارة. شكل الأخطبوط الأحمر الذي كان يشغل ركناً من صندوق الغداء، كان ترفاً صغيراً استمتعت به أوقات الغداء في الطفولة."},"ICON-1261":{"nm":"بيبروني","de":"قطعة مستديرة حارة تتقلّص من أطرافها فوق الجبن الساخن. حين يتجمّع قليل من الزيت، تلك هي ذروة الفطيرة كلها - صغيرة، لكن حضورها مستدير وغني."},"ICON-1262":{"nm":"قطعة لحم مشوية","de":"شكّلها سميكة وضعها على الشواية فتحمرّ من الأطراف نحو الداخل. احشُ الخضار بين قطعة مضغوطة مشوية، ويكتمل شبعٌ يملأ يداً واحدة."},"ICON-1263":{"nm":"بيضة","de":"اكسرها فينزلق الصفار كشمس صغيرة مستديرة. رائع ممزوجاً بالأرز الطازج، ورائع كخط أصفر داخل الكيمباب - أكثر البروتينات شيوعاً، ولذلك أكثرها دفئاً."},"ICON-1264":{"nm":"حليب","de":"زجاجة باردة تُترك عند الباب فجراً، وكان اليوم غالباً يبدأ ببرودتها على راحة اليد. يتصاعد منه البخار إذا سُخّن، ويصير لذيذاً إذا بُرّد - أبيض يرافقك في أي وقت."},"ICON-1265":{"nm":"جبن","de":"شريحة صفراء تنهار ببطء فوق خبز دافئ. القلب ينتظر تلك اللحظة التي تتمدد فيها بخيوط طويلة - كلما ذابت أكثر، ازدادت لذّتها عمقاً وغنى."},"ICON-1266":{"nm":"جبن شيدر","de":"برتقاليّته الداكنة تُنبئ من النظرة الأولى بمذاق مالح. شريحة رقيقة داخل توست تنشر نكهة غنية في الفم كله - بقدر وضوح لونها، بقدر وضوح نكهتها."},"ICON-1267":{"nm":"زبدة","de":"أسقط قطعة في مقلاة ساخنة فتذوب برفق ويتصاعد بخار عطر. تُدهن على الخبز، تُمزج بالأرز - سحر أصفر يجعل كل ما يلمسه أكثر ليونة."},"ICON-1268":{"nm":"كريمة مخفوقة","de":"كلما دار المخفق، تحوّل الأبيض السائل شيئاً فشيئاً إلى غيوم متماسكة. في اللحظة التي تضع فيها ملعقة فوق كعكة، يضيء بعد ظهر عادي كعيد ميلاد صغير."},"ICON-1269":{"nm":"زبادي","de":"أدخل الملعقة فيرتفع الأبيض الحامض بسلاسة. اخلط قطعة فاكهة فيخفّ الصباح، وكوب واحد يرتّب المعدة بهدوء - طعم البداية اللطيفة."},"ICON-1270":{"nm":"إسقمري","de":"ضَعه على الشواية فيتطاير الزيت متناثراً ويملأ المطبخ دخان بين الرائحة السمكية واللذيذة. تلك اليد التي كانت تنزع العظم وتضعه فوق الأرز - أعمق إخلاص يسكن مائدة عادية."},"ICON-1271":{"nm":"سلمون","de":"طبقات وردية تتراص فوق بعضها بهدوء. باردةً تنحلّ بنعومة في الفم، ومشوية يتخلّلها الزيت فتصير لذيذة - طعمٌ متماسك عاد عبر بحر بعيد."},"ICON-1272":{"nm":"تونة","de":"افتح غطاء العلبة فتندفع رائحة مالحة فجأة. في ليالي غرفة مستأجرة صغيرة، حين كانت تُمزج بالأرز أو تُلفّ بورق البحر، كانت علبة واحدة تكفي لتصير وجبة شبعة."},"ICON-1273":{"nm":"سمك القد","de":"لحمه الصافي معتدل النكهة لدرجة أن غليه يستخرج مرقاً منعشاً منذ اللحظة الأولى. سمكٌ أبيض صمد أمام ريح الميناء الشتوية القارصة، ووعاء ساخن واحد من حسائه يُذيب حتى اليدين المتجمدتين ببطء."},"ICON-1274":{"nm":"جمبري","de":"يلتفّ ظهره مستديراً وحين ينضج يتورّد رماديه احمراراً خفيفاً. طقطقة مطاطية ورائحة لذيذة - قشّرها وكلها واحدة تلو أخرى، وسيجد الطبق نفسه فارغاً دون أن تشعر."},"ICON-1275":{"nm":"سلطعون","de":"انتزاع اللحم الأبيض من داخل القشرة الصلبة وقت صغير من الصبر. القطعة التي تضعها في فمك في نهاية ذلك العناء حلوة، وكأن بحر الخريف كله يدخل فمك دفعة واحدة."},"ICON-1276":{"nm":"حبار","de":"يتقلص مستديراً فوق الشواية، فاتحاً رائحة لذيذة. قضمة مطاطية واحدة، مغموسة بصلصة تشو-جانغ الحارة، يتبعها بحر مالح إلى الفم."},"ICON-1277":{"nm":"محار","de":"يفتح فمه في المرق الصافي مانحاً رائحته بهدوء. مع فقاقيع الغليان تنتشر رائحة البحر، ورشفة واحدة تُدفئ معدة باردة وتفكّها."},"ICON-1278":{"nm":"كعك السمك","de":"اغمسه على السيخ في مرق ساخن فيتصاعد البخار في لفائف. أمام عربة طعام في ليلة باردة، اليدان تحتضنان كوباً ورقياً من المرق وتنفخان عليه - عزاء صغير يقدّمه الزقاق."},"ICON-1279":{"nm":"كيمتشي","de":"ينضج ببطء داخل الجرة، فينمّي رائحة حامضة عميقة. مزّقه بيدك ووضعه فوق أرز طازج يكفي، والطعم الذي يختلف من بيت لبيت هو تاريخ ذلك البيت نفسه."},"ICON-1280":{"nm":"فجل مخلل أصفر","de":"قطعة صفراء تتكسّر بقرمشة نشطة في الفم. الرفيق الثابت بجانب لفافة كيمباب أو طبق وجبات خفيفة - حلاوتها الحامضة تشطف الفم الدسم فتنعشه."},"ICON-1281":{"nm":"مخلل","de":"يحبس الخيار أنفاسه للحظة في الملح، ثم يفتح عينيه في الخل. حتى لا تفوته لحظة عودة القرمشة، لا تغادر الجرة الزجاجية النافذة المشمسة أبداً. الزمن الذي يتخلّل ببطء هو من يجلب النكهة."},"ICON-1282":{"nm":"معجون الفلفل الأحمر الحار","de":"احمرار صمد سنة كاملة داخل الجرة. خلف حدّة الحرارة تختبئ برفق حلاوة فول الصويا، فملعقة واحدة تجعل اليخنة أخيراً وجه بيتنا. عمقٌ ربّته مصاطب الجرار الفخارية في الفناء بأشعة الشمس."},"ICON-1283":{"nm":"معجون فول الصويا المخمر","de":"احتضنت كتلة \"ميجو\" العفن وعاشت شتاءً كاملاً. النكهة العميقة مشيٌ على حبل رفيع بين النضج المثالي والنضج الزائد - وكانت الجدة تعرف تلك الحدود من مجرد رائحة عند أطراف أصابعها. طعمٌ يزداد عمقاً بقدر ما تنتظر."},"ICON-1284":{"nm":"صلصة الصويا","de":"كلما اسودّت حبات الصويا، ازداد عمقها الداخلي. قطرة واحدة تُحيي طبق خضار وتمنح لمعاناً لطبق مطهو ببطء، فكل لون في المطبخ يبدأ في النهاية من هذا البني الدافئ. لذّة تتجاوز الملوحة."},"ICON-1285":{"nm":"معجون الفول الأسود","de":"حتى السواد نفسه له نسيج مختلف. مذاق حلو مالح ختامي، مقلي مرة أخرى بالكراميل - اخلطه بالمعكرونة فيهزّ ذلك اللمعان الأسود شهيتك من نومها. الزرّ الأول لنكهة الوك الصينية."},"ICON-1286":{"nm":"مسحوق الكاري","de":"مسحوق أصفر تتآلف فيه توابل عديدة بسلام داخل ملعقة واحدة. أذبه في الماء فيغلي فقاعاً يُدفئ البيت كله - يصبح مقدمة عرض لأشبع وعاء في أمسية ماطرة."},"ICON-1287":{"nm":"فلفل أسود","de":"لا تحيا رائحته إلا مطحونة كاملة، وإذا طُحن مسبقاً هربت رائحته خلسة. الدورة الأخيرة تُضاف دوماً قبل إطفاء النار مباشرة - نقطة نهاية صغيرة تضعها اليد الطاهية بحرص."},"ICON-1288":{"nm":"مسحوق الفلفل الأحمر","de":"الفلفل المجفف تحت شمس الخريف يكمّل احمراره أخيراً. طحنه ناعماً أو خشناً يحدد طبع الكيمتشي، فمهارة اليد تأتي في النهاية من اختيار حبيبات هذا المسحوق."},"ICON-1289":{"nm":"ملح","de":"ضبط النكهة هو الاقتراب خطوة خطوة من الجانب الناقص. الملوحة التي تُضاف مرة لا يمكن التراجع عنها، فاليد الماهرة تضع دوماً أقل قليلاً في النهاية وتتذوق. ما تحتفظ به هو مساحتك للتنفّس."},"ICON-1290":{"nm":"سكر","de":"يهدّئ المرارة ويلطّف حواف الحموضة. لكن الحلاوة يجب ألا يُكشف وجودها، فكلما كانت التتبيلة أفضل، انسحب السكر بهدوء من المشهد في النهاية. حلاوةٌ تعرف كيف تختبئ."},"ICON-1291":{"nm":"عسل","de":"جرة جمعها النحل بعد آلاف الرحلات بين الحقول المزهرة. إذا تصلّب، يُحيا في حمّام ماء دافئ، وإذا خُلط بالشاي، لفّ الحلق برفق. ملعقة ذهبية لفصل كامل تكثّف بذاته."},"ICON-1292":{"nm":"زيت طهي","de":"لُفّ دورة واحدة في مقلاة ساخنة، فتنسى المكوّنات أن تلتصق. صبّه مبكراً يحترق، ومتأخراً يلتصق، فتلك النبضة الواحدة حين يبدأ الدخان بالتصاعد هي قاعدة القلي الذهبية. تُقاس اللحظة بالصوت."},"ICON-1293":{"nm":"زيت زيتون","de":"في اخضرار العصرة الأولى تعيش رائحة عشبية مع لسعة خفيفة من الحرارة. يُسكب في النهاية بدل أن يُوضع على النار، فتنجو رائحته حتى آخر لحظة - وترك عدم طهيه هو استخدامه الأصدق."},"ICON-1294":{"nm":"زيت سمسم","de":"أسقط قطرة واحدة في النهاية، فتُعلن الخضار المتبّلة اكتمالها أخيراً. لذّته تهرب بسهولة فوق النار، لذا يظل دوماً النقطة الأخيرة التي تُضاف بهدوء بعد انتهاء الطهي كله."},"ICON-1295":{"nm":"قرن الفانيلا","de":"اشقّ قرناً واحداً واكشط بذوره السوداء، فيرتدي الحلوى ثوب رائحة جديدة. عدم رمي القشرة المستهلكة بل دفنها في السكر - اقتصاد قديم توارثه صانع الحلويات."},"ICON-1296":{"nm":"كاكاو","de":"لبٌّ أبيض وبذور مرة داخل الثمرة. لا تُترجَم إلى الحلاوة التي نعرفها إلا بعد التخمير والتجفيف بالشمس. قبل أن تصير شوكولاتة، تحمل أول وجه لها، الأقرب إلى البرية."},"ICON-1297":{"nm":"شوكولاتة","de":"طبع رقيق يذوب لمجرد دفء راحة اليد. يجب تصليبها عند حوالي ثماني وعشرين درجة كي يحيا فيها ذلك اللمعان الذي يُكسر بقرمشة، فخلف الحلاوة تختبئ، على غير المتوقع، قاعدة حرارة دقيقة الشروط."},"ICON-1298":{"nm":"حبوب قهوة","de":"قبل الطحن، تكون الحبة الواحدة أقرب إلى صمت متماسك. لكنها إذا لاقت الماء الساخن، انتفخت وأفرغت رائحتها - فالإشارة الأولى التي توقظ الصباح تبدأ دائماً من هذه الحبة الصغيرة."},"ICON-1299":{"nm":"أوراق الشاي","de":"إذا بقيت طويلاً في الماء الساخن صارت قابضة، وإذا قصُر الوقت كانت باهتة. تأمّل الوقت الذي تتفتّح فيه الأوراق ببطء بهدوء - نقع الشاي هو قياس الانتظار بأطراف الأصابع."},"ICON-1300":{"nm":"نعناع","de":"إذا سُحق سالت مرارته، فهو ورقة رقيقة يجب التعامل معها برفق دائماً. اطرق عليها بخفة لتوقظ رائحتها النائمة، وأطفها في كوب زجاجي يوماً خانقاً، فيهدأ منتصف الصيف درجة كاملة من البرودة."},"ICON-1301":{"nm":"أعشاب عطرية","de":"إن وضعتها مع سيقانها كان العبق عميقاً، وإن اكتفيت بالأوراق وحدها صفا وخفّ. تزداد قوة إذا جُفّفت، وتزهو نضارة إذا استُعملت طازجة، وبقدر ما تحمله الحزمة الواحدة من مدى العبق، تتّسع ملامح المطبخ معها."},"ICON-1302":{"nm":"كستناء","de":"تحت قشرة شائكة يختبئ لبّ لامع البريق. اشرطه واشوه فينفتح بصوت خفيف فائحاً برائحة حلوة، حتى ليكاد دفء كيس الكستناء المشوي في زقاق تعصف فيه ريح باردة يُلمس باليد."},"ICON-1303":{"nm":"فول سوداني","de":"تكتمل نكهته الشهية على نار التحميص. حبّة صغيرة تقشّرها واحدة تلو الأخرى فينسلّ منك الوقت من دون أن تشعر، وحين تُقتسم جالسين حلقةً على الأرض، تُقشَّر معها الحكايات أيضاً، شيئاً فشيئاً."},"ICON-1304":{"nm":"لوز","de":"إن سلقته قليلاً وأزلت قشرته ازداد لبّه بياضاً ونعومة. مطحوناً يشبه الحليب، ومحمَّصاً كاملاً يصبح مقرمشاً، وبقدر ما تحمله الحبّة الواحدة من إمكانات التحوّل، يتّسع خيال صانع الحلوى."},"ICON-1305":{"nm":"سمسم","de":"هزّها برفق على نار هادئة، وفي لحظة ما تبدأ بالقفز والتفرقع. واللحظة التي تسبق توقف ذلك الصوت مباشرة هي الأشهى، فتحميص السمسم يغدو في النهاية أمراً يُدرَك بالأذن لا بالعين."},"ICON-1306":{"nm":"قصب السكر","de":"تمضغ عقدة واحدة فيسيل منها ماء حلو مع رائحة عشبية. ساق لا بدّ أن تُغلى وتُغلى مراراً كي تصير الحلاوة التي نعرفها، فبداية السكر، على غير المتوقع، خضراء طويلة القامة هكذا."},"ICON-1307":{"nm":"سكر خام","de":"حلاوة خشنة تحتفظ بلونها الأصلي، لكونها لم تمرّ بتكرير كامل. يبقى فيها عمق يشبه رائحة التراب باهتاً عطراً، فتلاحقها عمداً أياد تحبّ صدق الأشياء قبل أن تُصقل وتُلمَّع."},"ICON-1308":{"nm":"حبوب الكاكاو","de":"البذور المنتزعة للتوّ من القرن مرّة وقابضة. لا بدّ أن تصبر بصمت أياماً من التخمير حتى تتفتّح رائحتها، فالحلاوة ليست إلا جائزة صغيرة تنالها هذه الحبّة بعد صبر طويل."},"ICON-1309":{"nm":"رقائق الكاكاو","de":"لا حبّة سكر واحدة في قطع الحبوب المحمّصة المطحونة خشناً. ضعها في فمك فتأتيك المرارة أولاً ثم تلحقها الشهيّة متأخّرة، فتلتقي بالكاكاو قبل الحلاوة، بأصدق ما يكون."},"ICON-1310":{"nm":"بنّ أخضر","de":"حبيبات خضراء لا تزال تحمل رائحة نيّئة. هكذا كما هي، ينام العبق نوماً عميقاً فيها، فتبقى بهدوء إمكانيةً لا تعرف بعد ما ستصير إليه، حتى تنال معمودية النار."},"ICON-1311":{"nm":"بنّ محمّص","de":"على السطح البنّي الذي رشح منه القليل من الزيت، تجمّع العبق كاملاً. لا بدّ أن تُطحن قبل أن تبرد كي تبقى الرائحة تامّة، فمصير الفنجان الواحد يُحسم بهدوء في غضون أيام قليلة من التحميص."},"ICON-1312":{"nm":"قرن الفانيليا","de":"عبقٌ واحد يصبغ إناء حليب بأكمله. ثبّت حتى القرن المستهلَك في وعاء السكر، وبعد أيام يصير السكر كله عطراً، فهذه رفاهية لا يُلقى منها شيء البتة."},"ICON-1313":{"nm":"فلفل أسود","de":"عبق حبّة فلفل واحدة يتضاءل منذ لحظة طحنها. لذا تُبقيها كاملة على المائدة وتسحقها كلّما احتجت، فالنضارة تتفتّح من قلبٍ لا يؤجّل."},"ICON-1314":{"nm":"فلفل أبيض","de":"الحبّة، أنعم بعد أن أُزيلت قشرتها، خفيفة لا حادّة. وُلدت من حرص على ألا تبقى نقطة سوداء واحدة في صلصة بيضاء، رقّةَ مكانٍ لا يُرى."},"ICON-1315":{"nm":"قرفة","de":"انقع قطعة واحدة فتنتشر في الشاي حرارة دافئة رويداً رويداً. أضفها كاملة لا مطحونة كي تدوم الرائحة أطول، فعمق مشروب الشتاء يأتي من مثابرة هذا اللحاء المجفّف."},"ICON-1316":{"nm":"قرنفل","de":"في برعم زهرة صغيرة تشبه مسماراً، تتكثّف الرائحة كاملة. أضف أكثر مما ينبغي فتبتلع الطبق بأكمله، فاعتدال حبّة واحدة يحفظ بهدوء توازن النكهة."},"ICON-1317":{"nm":"جوزة الطيب","de":"أبقِ البذرة كاملة واسحق قليلاً منها كلما احتجت. فطبيعتها أن تتبدد رائحتها سريعاً إن طُحنت مسبقاً، ولمسة أخيرة من كشط سريع تجعل عبق الحليب أعمق."},"ICON-1318":{"nm":"هيل","de":"افقع القرن الأخضر فينسكب من داخله عبق منعش حادّ. مجرّد سحق حبّة أو اثنتين في الشاي يمنح الفنجان العادي فجأة عطر بلاد بعيدة."},"ICON-1319":{"nm":"زعفران","de":"خيوط حمراء، ثلاث بالكاد تُجمَع من زهرة واحدة. أذبها في ماء دافئ فينتشر النور الأصفر رويداً رويداً، فالثمين هو أيضاً وزن الوقت الذي قُطف يداً بيد."},"ICON-1320":{"nm":"كركم","de":"اطحن الجذر من التراب فيصبغ أطراف أصابعك صفرة. طبيعته أن تستيقظ رائحته فقط إذا قُلي قليلاً بالزيت، فذهبيّة الكاري لون رسمه هذا الجذر الصغير فوق النار."},"ICON-1321":{"nm":"ورق الغار","de":"الورقة التي يُقال إنها وُضعت على جبين المنتصر. ألقِ واحدة في ماء يغلي، فمن بين البخار تصعد للحظة هتافات ملعب قديم. وحتى في أيام لم تنتصر فيها، يصبح استنشاق عبقها عزاءً أخضر يحتضن بهدوء نسختك اليوم."},"ICON-1322":{"nm":"حليب جوز الهند","de":"العصير الأبيض الذي لا يسيل إلا حين تُكسَر القشرة الصلبة. في زاوية سوق بلدٍ حارّ، اغرس شفاطة وارتشف رشفة فيبرد ظمأ الظهيرة تماماً. الرائحة الحلوة المنعشة تملأ فمك وتجلب معها ظلّ المناطق الاستوائية."},"ICON-1323":{"nm":"زيت جوز الهند","de":"إذا تجمّد صار أبيض كأول ثلج، وإذا ذاب في راحة اليد انتشر عبقه بسلاسة. حكمة جدّة الجزيرة الرقيقة في تدبير المنزل، إذ كانت تناوله قائلة إن علبة واحدة تكفي من الرأس حتى القدم، محفوظة كاملة داخل العلبة المستديرة."},"ICON-1324":{"nm":"موز مجفف","de":"مدّدها تحت الشمس أياماً فيصير اللحم الأصفر لزجاً طرياً. عضّ قطعة تلو الأخرى بتأنٍّ، فتنبعث في فمك خلسة رائحة موسم الحصاد اللزجة الحلوة أيام المطر. الحلاوة التي نضجت ببطء تحتضن الفصل هكذا."},"ICON-1325":{"nm":"مانجو مجففة","de":"اللحم الطري، وقد تركّز تحت الشمس، وُلد من جديد هلاماً بلون الكهرمان. ثلاث نكهات في قطعة واحدة، حامضة وحلوة ومطاطية، فحرّكها ببطء في فمك ويطول العصر كله في كيس واحد."},"ICON-1326":{"nm":"أناناس مجفف","de":"على خلاف مظهره الشائك، اللبّ في الداخل أصفر مشرق تماماً. جفّف تحت الشمس فتتركّز الحموضة، حتى إن قضمة واحدة ترفع طرفي فمك من تلقاء نفسها. الأثر المنعش الباقي في نهاية القطعة يمكث طويلاً."},"ICON-1327":{"nm":"سلة فواكه استوائية","de":"ألوان قُطفت للتوّ تمتزج في سلة واحدة. برتقالي المانجو، أصفر الموز، ذهبي الأناناس، وقبل أن تمدّ يدك للاختيار يتدفّق الصيف أولاً عبر طرف أنفك. حفنة تُضيء القلب لمجرّد النظر إليها."},"ICON-1328":{"nm":"حزمة أعشاب بحرية","de":"شعر البحر، مجموع من الصخور التي كشف عنها الجزر. صوت الأمواج متشابك في رائحته المالحة، فإن نقعته بهدوء في ماء بارد انتشرت رائحة البحر الخفيفة السمكية حتى المطبخ رويداً رويداً. حفنة واحدة تفرش على المائدة سبخة صغيرة."},"ICON-1329":{"nm":"مأكولات بحرية مجففة","de":"حفنة من بحر جفّ متماسكاً. مزّقها بيدك على اتجاه الألياف، فيتحرّر مع الملوحة نسيم مالح لميناء قديم. صديق عتيق بجانب المائدة الدافئة، يدفعك بلا وعي لشوق كأس من المكولّي."},"ICON-1330":{"nm":"حبار مجفف","de":"عشر أرجل نُشرت مرتّبة وجُفّفت تحت الشمس. اشوها قليلاً حتى تفوح رائحة شهية، ثم مزّقها على اتجاه الألياف. بتلك المطاطية المستساغة، ترتفع رتبة طبق سهرة الليل درجة."},"ICON-1331":{"nm":"سمك مملّح","de":"مدفوناً في ملح خشن، يتعلّم السمك كيف يصمد أمام الزمن. قضمة واحدة من لحمه المالح العميق تُفرغ صحن أرزّ في لمح البصر، وصفة حبّ توارثتها بأطراف أصابعها جدّة من الساحل."},"ICON-1332":{"nm":"روبيان مملّح","de":"جمبري صغير ينضج ببطء في الملح ويُبعث من جديد نكهةً عميقة. لحظة إضافة ملعقة واحدة إلى الملفوف الصيني في موسم الكيمتشي، تنتشر تلك الرائحة المالحة في الفناء كله. تلك الملعقة الواحدة تحسم نكهة كيمتشي عام بأكمله."},"ICON-1333":{"nm":"أنشوجة","de":"جسد بحجم إصبع يتحمّل مسؤولية عمق قدر مرق بأكمله. مطبخ الطفولة الذي تبادلنا فيه الحديث ونحن ننزع الرؤوس والأحشاء، سمكة صغيرة لكنها امتنانية تقف بثبات في قلب شؤون البيت."},"ICON-1334":{"nm":"عشب الكومبو البحري","de":"شريط أسود طويل نما في قاع البحر. تضعه في ماء بارد وتنتشله برفق قبل الغليان مباشرة، وعدٌ حفظته أجيال من صانعي المرق. النكهة العميقة الشهية لا تستعجل أبداً."},"ICON-1335":{"nm":"عشب هيجيكي البحري","de":"قوام محبب متعرج يتفرقع في الفم. عشب بحري كان يصبغ صخور المدّ خضرة في الربيع، وإن تبّل وعُجن باليد انتشر في زاوية المائدة بحرٌ صغير ونديّ. إنها نكهة مضغ الربيع نفسه."},"ICON-1336":{"nm":"محار اللؤلؤ","de":"نور مستدير صيغ من احتضان طويل بين صدفتين متينتين. حتى تحويل إزعاج حبّة رمل واحدة إلى جوهرة، لم يستعجل البحر ولو للحظة. ضعها على راحة يدك فيستقرّ معها وزن ذلك الصبر الطويل."},"ICON-1337":{"nm":"زينة مرجانية","de":"غصن شجرة البحر الذي شذّبته الأمواج مئات السنين. إذا لامسه الضوء انتشر بالوردي والبرتقالي، حتى إن مجرّد وضعه بهدوء على رفّ يصبغ غرفة بأكملها جزيرة دافئة. حتى نسيجه الخشن الملموس بأطراف الأصابع يبدو أليفاً."},"ICON-1338":{"nm":"زر من الصدف","de":"في المكان الذي غادره لحم المحار، قُصّ الجانب الداخلي اللامع دائرياً. علّقه على ياقة الثوب فيلمع قوس قزح صغير عند أطراف الأصابع كلّما أُغلق. آخر هدية أليفة تركها البحر، وهو يمنح كل ما عنده ثم يمضي."},"ICON-1339":{"nm":"كرة زجاجية","de":"دحرجها في راحة يدك فيتبعها الضوء المحبوس بداخلها متدحرجاً. في تلك الأيام حين كنّا نجلس القرفصاء في الزقاق نلعب البلي غافلين عن غروب الشمس، كان جيب الطفل الذي كسب حبّة أخرى أثقل وأزهى من غيره بشكل غريب."},"ICON-1340":{"nm":"قطعة خشب عرعر منحوتة","de":"من كل خط نُحت يتسرّب عبق خفيف. أهل الزمن الماضي كانوا يحرقون هذا الخشب ليهدّئوا قلباً مشتّتاً. أمسك قطعة واحدة بهدوء وسيرتفع سكون هادئ من أطراف أصابعك رويداً رويداً."},"ICON-1341":{"nm":"بخور","de":"خيط رفيع يحترق ببطء، يشقّ طريقه إلى الأعلى. تتبع بعينيك المنحنى الذي يرسمه الدخان، وقلب كان يتسرّع طوال النهار يبطئ خطاه فجأة ويبقى بهدوء في مكانه."},"ICON-1342":{"nm":"زهرة الصباغة","de":"أطلق اللون الكامن في البتلات في قدر يغلي، فينصبغ القماش الصافي ببطء بذلك اللون. استعارة مؤقتة للون رسمته الطبيعة سلفاً، فالصباغة في جوهرها كانت تحيّة رقيقة تُقدَّم للزهرة."},"ICON-1343":{"nm":"صبغة نيلية","de":"زرقة عميقة هادئة استُخلصت من تخمير عشب النيلة مراراً وتكراراً. في كل مرة يُغمس القماش ويُرفع، ينتقل لونه ببطء من زرقة السماء إلى زرقة البحر. لون الانتظار، لا يتفتّح إلا حين يُترك التسرّع جانباً."},"ICON-1344":{"nm":"صبغة قرمزية","de":"انقع جذر الفوّة فيستيقظ في القدر غروب شمس كان نائماً في التراب. كان اللون الأكثر بهجة وإشراقاً في القرية، ذاك الذي كان يصبغ طرف تنّورة العروس الجديدة بجمال يوم الزفاف."},"ICON-1345":{"nm":"خيط ذهبي","de":"يُسحب الذهب أدقّ من شعرة، ويُغزل خيطاً خيطاً بعناية. أينما طُرّز يحتفظ بالضوء، حتى في غرفة مظلمة انطفأ فيها المصباح، ينهض ذلك النقش وحده مشرقاً بهدوء من تلقاء نفسه."},"ICON-1346":{"nm":"حرير","de":"الخيط الذي تقذفه دودة القز لا بدّ أن يُنسج ويُنسج مراراً كي يصير قطعة واحدة بالكاد. ملمس ينزلق كماء الربيع فوق ظهر اليد، قماش ناعم النسيج احتضنه أهل الزمن الماضي فصلاً كاملاً وربّوه ببطء."},"ICON-1347":{"nm":"زر لؤلؤي","de":"اختير فقط النور الداخلي للؤلؤة وصُقل دائرياً. كلما أغلقته على ياقة الجيوجوري، تصير أطراف أصابعك أنيقة للحظة. حبّة صغيرة لكنها ترفع بهدوء رتبة اللباس كله."},"ICON-1348":{"nm":"قطعة خريطة بحرية","de":"خلف الحافة الممزّقة، ينقطع فجأة ساحل مجهول. يُقال إن من يجمع القطع الباقية وحده يصل إلى الكنز، لكن ربما كانت الرحلة نفسها، رحلة البحث عنه تتبع الريح، هي الكنز أصلاً."},"ICON-1349":{"nm":"خارطة بحرية قديمة","de":"مسارات بحرية طمسها ماء البحر، ورسم بوصلة باهت. تتبّع بطرف إصبعك الخط الذي رسمه بحّار في ليل حالك مستعيناً بالنجوم وحدها، فتنهض من جديد ببطء على الورق العتيق جزيرة اندثرت منذ زمن بعيد."},"ICON-1350":{"nm":"رسالة في زجاجة","de":"داخل زجاجة دفعتها الأمواج إلى الشاطئ، ورقة واحدة ملفوفة. سلام لا يُعرف من أرسله ولا متى، وصل أخيراً إلى يد أحدهم. البحر أيضاً، إن توفّرت له نيّة، يصير ساعي بريد بطيئاً هكذا."},"ICON-1351":{"nm":"صندوق طافٍ","de":"المغامرة تستمرّ حتى لحظة فتح الغطاء الذي تصلّب من الماء المالح. سواء كان ما بداخله كنزاً أم رملاً فارغاً، فإن الصندوق الذي طفا من بعيد يحمل معه دوماً حكاية شخص مجهول الوجه."},"ICON-1352":{"nm":"مفتاح صغير","de":"قطعة معدنية بالية تحتلّ راحة اليد تماماً. حتى وإن نُسي تماماً أيّ باب تفتحه، يبقى في أطراف الأصابع وزن دافئ ثقيل، من النوع الذي يجعلك تفكّر في الفتح قبل الإغلاق."},"ICON-1353":{"nm":"عملة فضية","de":"قطعة فضية مستديرة، تلاشى نقشها من كثرة اللمس. عملة كانت يوماً أجرة سفينة أو مبيت ليلة متعبة، امسح سطحها البارد فيعود دفء صفقة قديمة يهتزّ خفيفاً في أطراف الأصابع."},"ICON-1354":{"nm":"عملة ذهبية","de":"ضعها على راحة يدك فيهزّ القلب أولاً وزنها الثقيل. قطعة تلمع صفراء تحت الشمس، تبدو وكأنها تعد بالثراء إن امتلكتها، لكن الأكثر لمعاناً حقاً هو الخفقان الذي يسبق استقرارها في يدك."},"ICON-1355":{"nm":"ختم القبطان","de":"وعد القبطان، مطبوعاً بإحكام فوق شمع أحمر. نقش واحد يقيم أمراً ويرسم مساراً وعراً. السلطة، في النهاية، لم تكن سوى ختم صغير متين اتفق جميع من على متن السفينة أن يؤمنوا به معاً."},"ICON-1356":{"nm":"ميكروفون يدوي","de":"لحظة إمساكه، يملأ راحة اليد وزن مطمئن غريب. سواء كنت تلقي تحية أولى مرتجفة أو تطلق أخيراً نغمة عالية، فإن هذا القضيب الصغير يمنح صوتك جناحين برفق."},"ICON-1357":{"nm":"ميكروفون لاسلكي","de":"باختفاء السلك، اتّسع المسرح كله دفعة واحدة. اركض حتى آخر الصفوف ولن ينقطع صوتك ولو مرة، وكأنّ أحداً يدفع ظهرك برفق قائلاً اركض وغنِّ كما يحلو لك."},"ICON-1358":{"nm":"ميكروفون حامل","de":"يقف بثبات عند قدميك منتظراً المغنّي بصمت. حين تتحرّر اليدان، ينتشر الغناء بالجسد كله بدل أطراف الأصابع. في البقاء في مكان واحد حتى النهاية أناقة واضحة، هذا ما يقوله هذا القضيب بهدوء."},"ICON-1359":{"nm":"مرشّح صوت","de":"طبقة قماش مستديرة واحدة تعترض أمام الميكروفون. تصفّي بلطف الأنفاس الحادّة وتترك الصوت الصافي وحده يمرّ. أن تُسمَع بوضوح يعني أن يحجب عنك شيء بصمت من مكان لا يُرى حتى النهاية."},"ICON-1360":{"nm":"سماعة أذن مسرحية","de":"أدخلها في أذنك بإحكام فتعود أغنيتك واضحة رغم هدير عشرات الآلاف. أصغر رفيق وأكثره سرّية، يحفظك من إضاعة الإيقاع على مسرح تنهمر فيه الأضواء والأصوات."},"ICON-1361":{"nm":"سماعات رأس","de":"لحظة تغطيتها للأذنين، يصغر العالم شبراً ولا يتبقّى إلا الأغنية كبيرة. غرفة مستديرة صغيرة لا يقتحمها أحد. وبغرابة، داخل سماعات ارتديتها وحدك، لست وحيداً."},"ICON-1362":{"nm":"نوتة موسيقية","de":"حين تستقرّ النقاط السوداء بهدوء على الخطوط، تبدأ الورقة الصامتة بحمل الصوت. كتابة تُسمَع لا تُقرأ. لحظة فتحها، تتنفّس من جديد أغنية كانت واقفة ساكنة."},"ICON-1363":{"nm":"نوتة غنائية","de":"عند كل موضع للتنفّس، تُرسم دائرة صغيرة. استنشق هنا، وأطلق بهدوء هناك. خريطة رقيقة تفتح الطريق كي لا يُصاب الصوت بأذى."},"ICON-1364":{"nm":"نوتة بيانو","de":"صفحة تسأل فيها عشرة أصابع عن الطريق في آن واحد. اليسرى تمسك بالجذور، واليمنى ترسم الأغنية. يدان كانتا تحكيان قصتين مختلفتين، تنطويان أخيراً في المقطع الأخير على واحدة."},"ICON-1365":{"nm":"مخطط أوتار الغيتار","de":"اللغة الأجنبية الأولى التي تتعلّمها الأصابع، كلمتها الأولى مكتوبة هنا. حين تجتمع ست نقاط في دوائر، عندها فقط ترنّ نغمة واحدة. في كل ليلة ضغط وضغط متكرر، تنمو الأنسجة الصلبة عند الأطراف."},"ICON-1366":{"nm":"مترونوم","de":"تِك، تِك، خطوة ثابتة لا تتأرجح تُقرَع بجانبك. حين يتسرّع القلب راكضاً، يمسك بك من الخلف ببطء، ببطء. فالإيقاع، في النهاية، ليس إلا وعداً بأن نمشي معاً."},"ICON-1367":{"nm":"جهاز ضبط النغمة","de":"حين تنزلق الإبرة إلى المنتصف تماماً، تجد النغمة أخيراً مكانها. تلك النقطة الواحدة، لا عالية ولا منخفضة. أن تكون مضبوطاً يعني، كما يتّضح، أن تتوقف عن الارتجاف وتسكن بهدوء."},"ICON-1368":{"nm":"بطاقة مفاتيح البيانو","de":"اقلب صفحة تلو الأخرى وتمشي المفاتيح إلى داخل راحة يدك. كون صغير من سبع خانات، من دو إلى سي. وحتى في ليالٍ بلا بيانو حقيقي، تنمو الأغنية هنا بهدوء."},"ICON-1369":{"nm":"ريشة غيتار","de":"شريحة صغيرة متينة تُثبَّت بين الإبهام والسبّابة. أسقطها فتختفي إلى الأبد تحت الكرسي، لكن لحظة إمساكها ترنّ الأوتار الستة كلها دفعة واحدة."},"ICON-1370":{"nm":"عصا الطبل","de":"حين تلتقي عصوان في الهواء، تسقط الإشارة في تلك اللحظة. واحد، اثنان، ثلاثة، أربعة. تبدأ قلوب الجميع المتفرّقة بالخفقان بالسرعة نفسها، متزامنة مع تلك النبضات الأربع."},"ICON-1371":{"nm":"دفّ صغير","de":"هزّة واحدة وينتشر صوت صافٍ في كل الاتجاهات، كأن ضوء الشمس تشظّى قطعاً صغيرة. تبدو خفيفة، لكنها أول ما تمتدّ إليه اليد حين يخفت الحماس. صغيرة، لكن لا أحد يستطيع تجاهلها."},"ICON-1372":{"nm":"حذاء رياضي للرقص","de":"للقدمين اللتين تدوران منزلقتين على الأرض، يصير الاحتكاك سلاحاً. في كل نعل بالٍ نُقشت دورة ودورة تلو الأخرى. أروع حركة تبدأ دائماً من زوج متين واحد."},"ICON-1373":{"nm":"واقي الركبة","de":"من ركع مرات لا تُحصى ثم نهض من جديد وحده يعرف امتنان هذه الطبقة الرقيقة الواحدة من القماش. شيء يمنع الأرض من أن تصير مخيفة، فالشجاعة أحياناً تُلفّ حول الركبتين هكذا."},"ICON-1374":{"nm":"واقي المعصم","de":"لفّ مسبقاً الموضع الذي ينثني فتصير الحركة المفرطة أكثر تسامحاً. المعصم صامت، يتحمّل وحده حتى يؤلم. ذلك الصمت الطويل، تعوّضه طبقة واحدة بدلاً منه."},"ICON-1375":{"nm":"واقي الكاحل","de":"في نهاية القفزة العالية يكون الهبوط، وفي نهاية ذلك الهبوط يكون الكاحل. المكان الأدنى الذي يتحمّل وزن الجسد كله. هذا الشريط الصغير يحرس بهدوء تمرين الغد."},"ICON-1376":{"nm":"شريط تمدد رياضي","de":"اسحبه فيقاوم بقدر ما شددته، محاولاً العودة إلى مكانه. وبينما تتحمّل تلك المقاومة، يطول الجسد قليلاً من دون أن يشعر. الإطالة، في النهاية، هي الأثر الذي يتركه الوقت الذي تحمّلته."},"ICON-1377":{"nm":"سجادة يوغا","de":"لحظة فرشها، تظهر على الأرض قطعة أرض تخصّك وحدك. أرض صغيرة للانحناء والاستلقاء وضبط الأنفاس. بداية اليوم ونهايته تُطويان بهدوء فوق هذه القطعة الواحدة."},"ICON-1378":{"nm":"أسطوانة إسفنجية","de":"اضغط برفق على موضع متيبّس فيؤلم في البداية، ثم سرعان ما تشعر بالراحة. في تحرير ما تصلّب دوماً قدر من الألم. فالجسد والقلب كلاهما يحتاجان إلى ضغطة واحدة قبل أن يتحرّرا."},"ICON-1379":{"nm":"دمبل","de":"ترفع الوزن نفسه وترفعه من جديد. مرة واحدة زيادة عن الأمس، هذا كل شيء. في تكرار لا شيء فيه من البهرجة، تغلظ الذراع بصمت. قطعة حديد صادقة وحسب."},"ICON-1380":{"nm":"كيتل بل","de":"بمقبض واحد يتأرجح الجسد كله. حين يدور الوزن المستدير راسماً قوساً، يُختبر توازن من يمسك به. لتبقى ثابتاً، عليك أولاً أن تعرف مركزك."},"ICON-1381":{"nm":"حبل قفز","de":"تقفز فوق حبل يمرّ سريعاً تحت قدميك، وتقفز مرة أخرى. مثل تلك اللعبة التي كنّا نعدّ فيها مع الرفاق في الفناء، كلّما تراكمت الأرقام، ضاق النفس وازداد الضحك."},"ICON-1382":{"nm":"حذاء جري","de":"زوج لا تعرف قيمته الحقيقية إلا بعد أن تخطو به على الطريق. اشقّ هواء الفجر راكضاً الطريق نفسه من جديد، فالزاوية التي كانت بعيدة بالأمس تصير اليوم على مقربة. المسافة يتذكّرها القدمان."},"ICON-1383":{"nm":"منشفة رياضية","de":"تمسح عرق جبينك فيبقى فيها خطّ واحد من جهد اليوم. اغسلها فيختفي الأثر، لكن كل ما سال يتراكم في مكان ما بترتيب. أصدق تشجيع يجفّ دوماً بجانبك."},"ICON-1384":{"nm":"زجاجة ماء","de":"تُفرَغ فتُملأ، وتجفّ فتُرتشف. تلك الرحلة البسيطة ذهاباً وإياباً تسند اليوم بصمت. مثل دلو يصعد وينزل عند البئر، من فعل الملء يبدأ اليوم من جديد."},"ICON-1385":{"nm":"مشروب بروتين","de":"هزّه جيداً وابلع رشفة، فالعضلات التي تمزّقت اليوم تمتلئ غداً من جديد. ليس مذاقاً فاخراً، لكن الجسد يعرف أن هذه لغة التعافي. النموّ دوماً يُرتشف بهدوء."},"ICON-1386":{"nm":"وجبة طاقة","de":"قطعة مسطّحة في الجيب. مؤونة طارئة تملأ الساعات الفارغة بين وجبة وأخرى. لا شيء فخم فيها، لكن هذه القضمة الصغيرة تجعلك تصمد لحركة أخرى في العصر."},"ICON-1387":{"nm":"حلوى للحلق","de":"دحرجها في فمك فيداعب النعناع الحادّ حلقاً خشناً برفق. في يوم كثرت فيه الكلام، وليلة كثر فيها الغناء، حبّة صغيرة واحدة تربّت على طريق خشن. حتى للحلاوة فائدة واضحة."},"ICON-1388":{"nm":"شاي للصوت","de":"بخار دافئ يسخّن الحلق، ومع رشفة واحدة يذوب توتر الكتفين. وصفة قديمة، كشاي الزنجبيل الذي كانت الجدّة تُعدّه. تحية رقيقة تُقدَّم للصوت قبل الغناء."},"ICON-1389":{"nm":"ماء بالعسل","de":"يُذاب ملء ملعقة من العسل ببطء في ماء فاتر. الكأس نفسها التي كان الكبار يعدّونها كلما شعرت الحلق بالخشونة. ليست دواء ولا مشروباً، بل حلاوة تداعب الجسد بهدوء من الداخل فقط."},"ICON-1390":{"nm":"خزان مرطّب الهواء","de":"وعاء يطلق ضبابةً صغيرة في الغرفة. في ليالي الشتاء حين يخدش الهواء الجاف الحلق، يهب رطوبة من دون أن يُرى. الاعتناء بشخص ما، غالباً ما يجري بصمت هكذا."},"ICON-1391":{"nm":"قسيمة راحة","de":"ورقة واحدة مكتوب عليها أنه يجوز لك أن ترتاح. لحظة تأخذها بيدك، يخفّ عبء القلب درجة. أن التوقّف أيضاً تمرين، هذه البطاقة الصغيرة تمنحك الإذن بدلاً عنك."},"ICON-1392":{"nm":"جدول تمارين","de":"فوق الوقت المكتوب خانة خانة، يستقرّ اليوم رويداً رويداً. غناء في الصباح، رقص في الظهيرة، راحة في المساء. حتى الغد الغامض، إن قُسّم بخطوط، يصير طريقاً يستحق أن يُمشى."},"ICON-1393":{"nm":"ختم الحضور","de":"يُطبع ختماً واحداً يشير إلى أنك حضرت اليوم أيضاً. وكلّما تزايدت الدوائر التي طبعها الحبر باهتة قليلاً خانة خانة، تصير المثابرة التي بدت تافهة طريقاً من دون أن تشعر. برهان صغير لكل يوم."},"ICON-1394":{"nm":"ملصق تشجيع","de":"بدلاً من قول أحسنت، تُلصَق نجمة واحدة بهدوء. بريق بحجم الظفر، لكن لحظة استقراره في زاوية الدفتر، يضيء اليوم كله. المديح صغير، لكنه بغرابة يلمع طويلاً."},"ICON-1395":{"nm":"دفتر خواطر","de":"صفحة يُفرَّغ فيها القلب الذي ارتجف خلف الكواليس في كلمات. اكتب بصدق حتى عن الأيام التي لم تسر على ما يرام، فيخفّ شيء ما في مكان ما. القلب يزداد صلابة بقدر ما تنظر في داخله."},"ICON-1396":{"nm":"بطاقة تدريب ذهني","de":"أغمض عينيك وأمسكها فينفتح المسرح بهدوء في ذهنك. أن تمشي مسبقاً دورة كاملة حول مكان لم تقف عليه بعد. المسار المرسوم بالخيال يصل قبل أطراف الأصابع الحقيقية بخطوة."},"ICON-1397":{"nm":"مرآة تدريب التعابير","de":"أمام المرآة تبتسم ثم تتجمّد، تصنع الوجه نفسه أكثر من مئة مرة. هنا تتعلّم أن الفرح والحزن كليهما يحتاجان إلى تمرين. فالتعبير هو نسخ القلب إلى الخارج."},"ICON-1398":{"nm":"دفتر تدوين الرقصات","de":"صفحة نُقل إليها كرسوم الطريق الذي ستمرّ به القدمان والذراعان. عند كل ثمانية عدّات، تشير الأسهم بهدوء إلى أين يجب أن يذهب الجسد. حتى الحركة التي أبت أن تُحفَظ تُروَّض ببطء فوق هذه الصفحة."},"ICON-1399":{"nm":"شريحة فيديو تدريب الرقص","de":"مئات الحركات محفوظة كاملة في شريحة صغيرة واحدة. شغّلها مرة أخرى قبل النوم، فتتحرّك أطراف أصابعك من تلقاء نفسها متتبّعة ذلك المسار. التكرار سجلّ آخر، يُنسخ عبر الجسد."},"ICON-1400":{"nm":"مخطط حركة المسرح","de":"خريطة واحدة للمسرح، رُئيت من الأعلى. من يلتقي أين ويتفرّق إلى أين، كله موعود مسبقاً بخطوط ونقاط. لرسم صورة واحدة معاً، لا بدّ أولاً من توزيع الطرقات."},"ICON-1401":{"nm":"تصريح البروفة","de":"المقاعد خالية والأضواء ما زالت نائمة. تصريح واحد يسمح لك بالدخول إلى هذا الهدوء. المسرح حين لا يراقبه أحد، هنا يبدأ الوقت الذي تلتقي فيه بأصدق نسخة منك."},"ICON-1402":{"nm":"دفتر الأناقة","de":"بأي مزاج سأرتدي اليوم؟ حتى القميص الواحد له شعور يليق به، هذا ما يهمس به هذا الدفتر بهدوء. كلما قلّبت صفحة أخرى، تراكمت في أطراف أصابعك التي كانت تتردد أمام المرآة لمسة ذوق صغيرة."},"ICON-1403":{"nm":"مثبت الشعر","de":"رشّة واحدة، ولن تجرؤ الريح على تشويشه بلا مبالاة. طمعٌ صغير في تثبيت تلك الدقائق القليلة على المسرح دون أي خلل. فاللحظة الكاملة تكتمل دائمًا فوق مثل هذا الإصرار البسيط."},"ICON-1404":{"nm":"باليت المكياج","de":"اثنتا عشرة خانة من الألوان هي اثنتا عشرة حالة مزاجية مختلفة. بأي تعبير ستغني اليوم؟ تختار أطراف الأصابع أولًا، ثم يتبعها القلب. وفي كل خانة تفرغ، تبقى آثار الأيام التي تُركت على المسرح عالقة بصمت."},"ICON-1405":{"nm":"دبوس الزي","de":"في أبرز اللحظات تألقًا، ثمة دبوس صغير يمسك القماش من مكان لا يُرى. كي لا ينزلق، وكي لا يضطرب. فبريق المسرح يقف دائمًا على صلابة شخص آخر."},"ICON-1406":{"nm":"لوحة الاسم","de":"في اللحظة التي يُملأ فيها الاسم في اللوحة الفارغة، يتضح وعد كان غامضًا. من سيقف في هذا المكان؟ سطر واحد من الكتابة يقرر ذلك. فالاسم هو أقصر عزيمة وأمتنها."},"ICON-1407":{"nm":"بطاقة تحية للمعجبين","de":"المتلقي شخص واحد فقط، ولكنه بالنسبة له العالم كله. عمل يضغط فيه امتنان ليالٍ عديدة في سطر تحية قصير. هكذا يفيض القلب حتى على ورقة بحجم راحة اليد."},"ICON-1408":{"nm":"ورقة تمرين التوقيع","de":"في البداية حتى اسمك يُرسم بشكل غريب. عبر فجرات من رسمه مئة مرة وصقله ألف مرة، حتى تحفظ اليد ذلك المسار قبل أن يحفظه القلب. هكذا يصبح اسم واحد أخيرًا توقيعًا."},"ICON-1409":{"nm":"ورقة أسئلة المقابلة","de":"\"بماذا أجيب على هذا السؤال؟\" ترتجف أطراف الأصابع الممسكة بالورقة قليلاً. ليس حفظ الإجابات، بل ترتيب الصدق في صفوفه، فالمقابلة، مثل الاعتراف، هي في النهاية سؤال عن ترتيب القلب."},"ICON-1410":{"nm":"دفتر المفردات الأجنبية","de":"أكثر الزوايا تآكلًا تدل على الكلمة التي حُدّق فيها أطول وقت. بقدر ما يستغرقه نطق غريب واحد ليستقر على اللسان، تقترب المسافة إلى عالم لم تزره قط شبرًا بشبر."},"ICON-1411":{"nm":"بطاقة تصحيح النطق","de":"الراء المتدحرجة، والسين المتسربة. هناك فجرات تُقضى في تقليب البطاقات واحدة تلو الأخرى، ترويضًا للسان. بقدر ما يزداد الكلام وضوحًا، يزداد وضوح وجه من تريد أن تصله بتلك الكلمات."},"ICON-1412":{"nm":"قائمة تدقيق البث المباشر","de":"الميكروفون يعمل، سماعات الأذن مؤكدة، الحركة على المسرح مراجَعة. مع كل مربع يُملأ، يفرغ القلق في الصدر خانة تلو الأخرى. قبل الصعود إلى المسرح، الدقة هي أهدأ أنواع الشجاعة."},"ICON-1413":{"nm":"لاصقة الحالة","de":"هناك بقعة تفوح دفئًا لحظة لصقها. كتف مُجهد، ربلة ساق متيبسة، عزاء بحجم راحة اليد يجيب بهدوء على الإشارات الصغيرة التي يرسلها الجسد. الراحة الجيدة أيضًا جزء من التمرين."},"ICON-1414":{"nm":"كمادة الثلج","de":"توضع بهدوء على كاحل منتفخ. وبينما يتسلل البرد ببطء، تدرك أخيرًا كم ركضت اليوم. التعافي خلف الكواليس يأتي دائمًا هكذا، بلا صوت."},"ICON-1415":{"nm":"حقيبة الإسعافات الأولية","de":"ضمادات، مسكنات، مرآة يد. تأتي لحظة تصبح فيها هذه الحقيبة الصغيرة المليئة بأشياء تافهة الأكثر طمأنة على الإطلاق. اللطف الذي أُعدّ مسبقًا يتألق أكثر ما يتألق أمام أزمة غير متوقعة."},"ICON-1416":{"nm":"بطاقة الإشارة","de":"يرفعها أحدهم خلسة من وراء الكاميرا. الجملة التي كادت تُنسى مكتوبة هناك بخط واضح. خلف عرض يسير دون عثرة، توجد دائمًا يد كهذه، لا تظهر أبدًا على الشاشة."},"ICON-1417":{"nm":"مغلف المهمة","de":"أكثر لحظة تجعل القلب ينبض هي اللحظة التي تسبق تمزيق المغلف. مهما كان بداخله، تلك الفجوة القصيرة من الترقب المجهول. سحر برامج المنوعات يعيش كاملاً داخل تلك اللحظة المختومة."},"ICON-1418":{"nm":"بطاقة الاسم","de":"اسم صغير معلق عند الصدر يحل محل التحية الأولى. بين أناس لا يعرف بعضهم بعضًا بعد، تكسر بطاقة اسم واحدة جليد الحرج. من لحظة نداء الاسم، تبدأ العلاقة."},"ICON-1419":{"nm":"ملصق العقاب","de":"ورقة واحدة تُلصق على جبين الخاسر تفجر الضحك دفعة واحدة. ودّية أكثر من أن تُسمى عقابًا، حتى الخسارة تصبح ذكرى تدوم طويلاً. علامة صغيرة ولطيفة صُنعت لنضحك معًا."},"ICON-1420":{"nm":"بطاقة عقاب عشوائي","de":"لا أحد يعرف قبل السحب. عشر دورات بخرطوم الفيل، أم لفتة دلع واحدة. في لحظة تسليم مصيرك كله لورقة واحدة، الضحك هو ما ينطلق أولًا."},"ICON-1421":{"nm":"بطاقة تلميح","de":"شيء أشبه بيد تُمد بهدوء لمكان متعثر. لا تعطي الإجابة كاملة، لكنها تدل على الطريق. التلميح الجيد ليس الإجابة الصحيحة، بل فعل تسليم شجاعة التفكير مرة أخرى بهدوء."},"ICON-1422":{"nm":"بطاقة الفرصة","de":"فرصة واحدة لقلب اللوح المائل دفعة واحدة. متى تسحب هذه البطاقة يحدد نتيجة المباراة. الحظ المُدّخر بعناية لا يثبت قيمته إلا في أحسم اللحظات."},"ICON-1423":{"nm":"بطاقة الوقت المستقطع","de":"لا بأس أن تتوقف قليلاً، هذا ما تقوله هذه البطاقة نيابة عنك. رفع يدك بثقة حين تحتاج إلى التقاط أنفاسك، فالتوقف أيضًا استراتيجية مشروعة، والراحة الجيدة أيضًا مقعد من مقاعد المهارة."},"ICON-1424":{"nm":"زر الضحك","de":"طقّة، وفي لحظة الضغط ينهمر صوت ضحك مرح مليء بالقهقهات. المشهد المضحك حقًا يحتاج حتى إلى مؤثر صوتي كهذا يساعده خلسة. دفء المكان يسخن من مزحة صغيرة كهذه."},"ICON-1425":{"nm":"ريموت المؤثرات الصوتية","de":"زر للتصفيق، وآخر للاستهجان. ساحر يشكّل الأجواء بأطراف أصابعه فقط، يجلس بهدوء في غرفة التحكم. الإخراج الذي لا تلتقطه الشاشة أبدًا هو ما يجعل ذلك المشهد ينبض بالحياة."},"ICON-1426":{"nm":"لوح المشهد","de":"طقّة، ومع ذلك الصوت الرنان تبدأ لقطة جديدة. بين عشرات اللقطات الفاشلة ولقطة موافقة واحدة، يحصي هذا اللوح الأسود كل لحظة بوضوح. إنه النبضة الأولى التي يخطوها التسجيل."},"ICON-1427":{"nm":"شريط تحديد الموقع","de":"في اللحظة التي تلامس فيها أطراف قدميك ذلك الخط، تهبط الأضواء برفق كأنها كانت تنتظر. تلك الخانة الوحيدة التي حُفظت حتى تآكلت، يكتمل المسرح أخيرًا بشريط لوني صغير مرسوم على الأرض."},"ICON-1428":{"nm":"فلتر الإضاءة","de":"نفس الوجه يتحول تمامًا بلون الضوء. في الفلتر الأزرق يسكن الفجر، وفي الأحمر يسكن الغروب. الأجواء ليست بعيدة أبدًا، إنها مطوية بهدوء داخل ورقة ملونة رقيقة واحدة."},"ICON-1429":{"nm":"بطارية الكاميرا","de":"حين يبدأ الضوء الأحمر بالوميض، يقلق القلب أولاً. لأن أجمل مشهد يأتي دائمًا عند نسبة شحن واحد بالمئة. بطارية احتياطية واحدة في الجيب تصبح راحة تلتقط أنفاسها."},"ICON-1430":{"nm":"بطاقة الذاكرة","de":"ضحكات يوم كامل وقطرات عرقه تمتلئ بكثافة داخل شريحة بحجم الظفر. صغيرة جدًا لدرجة سهولة فقدانها، وثمينة جدًا بنفس القدر. وزن الذكريات التي تحملها لا يُقاس أبدًا بالحجم."},"ICON-1431":{"nm":"فيلم بولارويد","de":"طقطقة، ثم انتظار هادئ. تلك الثواني القليلة التي يطفو فيها الوجه ببطء فوق السطح الأبيض مثيرة على نحو غريب. حتى الصورة الفورية في يدك تحتاج بالضبط ملعقة واحدة من الصبر."},"ICON-1432":{"nm":"فيلم بطاقات الصور","de":"أي تعبير سيُطبع على هذه الورقة الواحدة يبقى سرًا حتى لحظة الطباعة ذاتها. الوجه الذي سيصبح المفضل لدى أحدهم يولد هنا بالضبط. ورقة صغيرة واحدة تحمل قلبًا بهذا الاتساع."},"ICON-1433":{"nm":"غلاف بطاقة الصور","de":"بطاقة الصور لا تُلمس بيد عارية أبدًا. اضغط زاوية واحدة، وحتى ابتسامة ذلك اليوم تتألم. أن تلف مفضلك بعناية في ورقة شفافة واحدة، حتى الاعتزاز يتطلب هذا القدر من الإخلاص."},"ICON-1434":{"nm":"حافظة بطاقات صلبة","de":"أدخلها بين صفحتين صلبتين، ولن يجرؤ حتى الزمن على تجعيدها بلا مبالاة. لا تنحنِ، لا تُطوَ. الحفاظ على شيء ثمين يستعير دائمًا طبقة من الصلابة."},"ICON-1435":{"nm":"مجموعة ملصقات","de":"تُقشَّر واحدة تلو الأخرى وتُلصق على زاوية مذكرة، أو خلف حاسوب محمول. برسمة صغيرة واحدة، يصطبغ يوم عديم اللون بكل الألوان. الرغبة في تزيين ما حولك لا عمر لها."},"ICON-1436":{"nm":"قلم توقيع","de":"بصوت الحبر وهو يمرّ برفق فوق الورق، يطول الصف أكثر فأكثر. فوق ألبوم مُمَدّ بيد مرتجفة، يبقى لقاء بضع ثوانٍ طويلاً في الذاكرة. القلب يعبر عبر طرف القلم."},"ICON-1437":{"nm":"ألبوم موقّع","de":"افتح الغلاف، وتوقيع بمنحنيات مألوفة يحييك أولًا. الرابطة التي نشأت عبر الموسيقى تقترب شبرًا أكثر على الورق. أن تحتفظ به يعني أن توقف تلك اللحظة بهدوء."},"ICON-1438":{"nm":"بطارية عصا الإضاءة","de":"\"أرجوك، أضيئي.\" أيدٍ مشغولة تستبدل البطاريات قبيل الدخول مباشرة. حتى لا ينطفئ ضوءي أنا وسط عشرات الآلاف من الأضواء، بطارية صغيرة تضيء تلك الليلة العظيمة بسطوع."},"ICON-1439":{"nm":"حقيبة عصا الإضاءة","de":"مطوية بعناية دون خدش واحد، محفوظة حتى لهتافات الليلة التالية. حتى بعد أن يبرد المكان الملتهب تمامًا، تحملها إلى البيت بعناية. لأداة التشجيع مكانها الخاص، وهناك قلب يعتني بذلك المكان."},"ICON-1440":{"nm":"راية شعار","de":"جملة مكتوبة على قماش طويل تنشر نفسها عبر المدرجات. في لحظة انفتاح تشجيع يصعب قوله بالكلام، يصبح صدق شخص واحد صرخة الجميع. ذلك القماش يتحول بذاته إلى صوت."},"ICON-1441":{"nm":"راية صغيرة","de":"تشجيع صغير يسع راحة اليد بالضبط. الراية المعلقة بعيدًا ملك الجميع، لكن هذه ترفرف فقط عند حافة مكتبك أنت. تتأرجح بهدوء، مثبتة أن صغر الحجم لا يعني صغر القلب."},"ICON-1442":{"nm":"رسالة معجب","de":"صححت اسم المستلم ثلاث مرات ومحوت الجملة الأولى سبع مرات. ترتجف أطراف أصابعي قبيل إغلاق المغلف، لأن القلب صادق أكثر من اللازم. صدق أثقل من طابع بريد واحد مطوي بداخله."},"ICON-1443":{"nm":"ورق تغليف الهدايا","de":"تعرف ورقة التغليف أكثر من أي أحد أن الثانية التي تسبق الفتح هي الأكثر إثارة. رغم علمها أن مصيرها التمزق قريبًا، تلف نفسها بأنعم نسيج، مشابهة قلب من يمنحها."},"ICON-1444":{"nm":"شريطة زينة","de":"إن ربطته بإحكام شديد خنق، وإن أرخيته انحل، فإيجاد تلك المسافة بينهما هو الإخلاص بعينه. عقدة واحدة تختارها الأصابع تحمل شكل القلب. السطر الأخير في الهدية تكتبه الشريطة دائمًا نيابة عنك."},"ICON-1445":{"nm":"بطاقة شكر","de":"كلمة شكر تُقال باللسان تتبعثر مع الريح، لكن حين تُكتب بخط اليد تبقى طويلًا. فعل إعادة اللطف الذي تلقيته مع إضافة قليل فوقه. بينما تضغط كل حرف، يتعمق القلب ضعفين."},"ICON-1446":{"nm":"قسيمة صندوق غداء","de":"بورقة واحدة كهذه، ينحل قلق الغداء بهدوء. أرز طازج يتصاعد منه البخار، ووجبة تملأ خاناتها بالأطباق الجانبية موعودة. تعويذة صغيرة تحرس بعد الظهر الجائع بثبات."},"ICON-1447":{"nm":"قسيمة وجبة خفيفة","de":"صُنعت لتُستخرج في الثالثة عصرًا، حين يرسل الجوع الخفيف إشارة طفيفة. قسيمة تعرف أن حلوى صغيرة واحدة ترفع المزاج نصف شبر. ليست مكافأة كبيرة، لكنها تصل برفق في اللحظة التي تحتاجها بالضبط."},"ICON-1448":{"nm":"قسيمة مقهى","de":"كوب دافئ واحد ومقعد عند النافذة، هذا كل ما تعد به هذه القسيمة. قد تبدو كلا شيء، لكنها تصبح لأحدهم جائزة صغيرة على تحمل اليوم. دعوة لطيفة تصل رائحتها قبل خطوة."},"ICON-1449":{"nm":"تصريح تنظيف السكن","de":"افتح النوافذ على مصراعيها، انفض الأغطية، يوم لا تفلت فيه ذرة غبار واحدة. من كان يظن أن عدم القيام بذلك بنفسك سيكون رفاهية كهذه. حين تلمع الغرفة، يترتب القلب أيضًا خلسة."},"ICON-1450":{"nm":"عدة إصلاح","de":"مفك، شريط لاصق، بضع قطع مجهولة الهوية. حين تجتمع كلها يبدو أنه لا يوجد شيء لا يمكن إصلاحه، لكن حين تفتحها تجد دائمًا قطعة ناقصة. ومع ذلك، صندوق ثقة يمنحك طمأنينة غريبة بمجرد إمساكه."},"ICON-1451":{"nm":"تذكرة الحظ","de":"تذكرة فارغة بلا مقعد ولا رقم. الجوهر هو أن ما سيأتي من خير اليوم غير مكتوب عليها. ملء ذلك الفراغ من نصيب من يحملها في جيبه."},"ICON-1452":{"nm":"نرد","de":"صديق يعرف كلمة العدل أكثر من أي أحد. لا ينحاز لأحد ويحب أوجهه الستة بالتساوي. في تلك اللحظة الوحيدة التي يغادر فيها راحة يدك ويتدحرج، تتنازل المهارة والمعارف مؤقتًا عن مقعدها للحظ."},"ICON-1453":{"nm":"تذكرة انتقال","de":"وعد بأن خطوة واحدة تكفي من هنا إلى هناك. ورقة سحرية تطوي طريقًا طويلًا وتضعه في جيبك. في يوم تتردد فيه في الانطلاق، لا يوجد حاجز أعذار أفضل من هذا."},"ICON-1454":{"nm":"تذكرة إعادة المحاولة","de":"بدلًا من مد يد لمن سقط، تذكرة تدفع ظهره بهدوء وتقول له حاول مجددًا. تخبرك بأهدأ طريقة أن الفشل ليس نهاية بل فاصلة قصيرة. شجاعة المرة الإضافية تتراكم هنا."},"ICON-1455":{"nm":"تذكرة إنجاز سريع","de":"مفتاح غش لطيف يتخطى الانتظار قليلاً. من يستطيع أن يلوم قلبًا لا يحتمل حتى ثلاث دقائق؟ هنا متعة أشبه بالمخالفة قليلاً، مثل دفع رمل الساعة الرملية بإصبعك."},"ICON-1456":{"nm":"معزز الإنتاج","de":"نفس اليدين، نفس الوقت، لكن الناتج مضاعف. يدور بمرح فوق طاولة العمل كأنه يقول لا تسأل عن السر. جهاز صغير يُلبِس أجنحة بهدوء ليدين تعملان بجد."},"ICON-1457":{"nm":"سكاكر الألفة","de":"حتى الحرج الذي يصعب حله بالكلام يذوب أمام شيء حلو. رابطة تقترب شبرًا أكثر من الأمس بسبب حلوى واحدة فُتحت معًا. اكتشاف صغير لطيف، أن الحلاوة هي سرعة التقارب."},"ICON-1458":{"nm":"جيلي استعادة المزاج","de":"في يوم حزين، شيء بارد وطري يفعل فعله فورًا. عضة واحدة تكفي لينحل تعبير كان معتمًا. إصلاح القلب أمر ثمين بطبيعته، فتصنيفه بدرجة R لم يكن عبثًا."},"ICON-1459":{"nm":"مسحوق التلألؤ","de":"رشّه برفق على شيء عادي فيصبح فجأة مميزًا. حقيقته مجرد مسحوق لامع، لكن لحظة رشّه يبدو العالم أكثر حيوية بغرابة. كتوابل السعادة تُنثر على الحياة اليومية."},"ICON-1460":{"nm":"شريط المسرح","de":"قف على المسرح، وتبحث عنك أضواء لا تُحصى دفعة واحدة. علامة X صغيرة على الأرض تحدد ذلك المكان بصمت. الأدق في مكان لا يُرى هو ما يسند في النهاية أعظم مسرح."},"ICON-1461":{"nm":"رباط كابلات","de":"بطل صغير يرتب الأسلاك المتشابكة بدقة في لمحة واحدة. أن تشديده مرة واحدة لا يمكن التراجع عنه هو عيبه وسحره معًا. أداة أساسية يحتفظ بها بهدوء من يهتمون بالنظام حقًا."},"ICON-1462":{"nm":"كابل احتياطي","de":"غرض لا وجود له عندما تملكه، ويصبح مشتهىً بشدة حين يغيب. نائم في أعماق الحقيبة خلف الكواليس، يستيقظ فجأة في اللحظة الحاسمة. يثبت كلمة الاستعداد بجسده ذاته."},"ICON-1463":{"nm":"جدول تدقيق البروفة","de":"ورقة مكتظة خانة تلو خانة بالحركة والإشارات وحتى تبديل الأزياء. إن غاب تدقيق واحد هنا، يهبط قلب أحدهم فجأة. المسرح الكامل لا يرفع ستاره إلا بعد أن تُملأ هذه الورقة بالكامل."},"ICON-1464":{"nm":"لافتة موقع التصوير","de":"هنا مقهى، وهناك زقاق، اتبع الأسهم إلى عالم مختلف تمامًا. كذبة مرسومة على خشب رقائقي، لكنها أمام الكاميرا تصبح حقيقية. مرشد صادق كرّس حياته كلها للإشارة إلى الاتجاه."},"ICON-1465":{"nm":"كأس صغيرة","de":"قطعة ذهبية تجعلك تشعر غريبًا بأنك أطول شبرًا لحظة تسلمها. تلمع فوق المكتب قائلة إنه لا بأس حقًا ألا تكون الأول، وإنها تعرف كل ما بذلته اليوم. عزاء كبير تقدمه مكافأة صغيرة."},"ICON-1466":{"nm":"حقيبة ظهر","de":"لحظة ارتدائه على الظهر، تشعر وكأنك تستطيع الانطلاق إلى أي مكان. رغم أن ما بداخله قليل، إلا أن الإمكانيات تملؤه حتى الحافة. المغامرة تبدأ دائمًا بشدّ هذين الحزامين بإحكام."},"ICON-1467":{"nm":"بوصلة","de":"لا تشعر بالذعر حتى وأنت تائه، لأن طرف الإبرة يشير دائمًا إلى الشمال. طريقة اهتزازها طويلًا قبل أن تجد مكانها أخيرًا أشبه بقلب الإنسان تمامًا. تخبرك بطرفها المرتجف أن التيه لا بأس به."},"ICON-1468":{"nm":"دفتر ملاحظات","de":"الصفحة الأولى فارغة دائمًا. من يحمل القلم وحده يعرف ماذا سيكتب. أنا فقط أنتظر، أن تصبح أفكار اليوم كتابة وتستقر فوقي بهدوء. تصنيف R هو وزن الإمكانية التي ستُملأ قريبًا."},"ICON-1469":{"nm":"قلم رصاص","de":"أن يكون الخطأ مقبولًا هو أرق ما في هذه الأداة. طالما صديقه الممحاة قريب، يمكنك البدء من جديد مرات لا تُحصى. يقصر كلما بُري، لكن قصره دليل على أنه أُحبّ طويلاً."},"ICON-1470":{"nm":"فيلم تصوير","de":"في لحظة مرور الضوء، ينطبع لون ذلك اليوم كاملاً. أن اللقطة بعد مرورها لا يمكن التراجع عنها أبدًا هو التوتر والسحر معًا. اختيار من يريدون تعمّد تذكّر إيقاع أبطأ في عصر سريع."},"ICON-1471":{"nm":"كاميرا فورية","de":"طقطقة، ثم انتظار قصير. أمسكها وهزّها برفق، فتتضح اللحظة الضبابية شيئًا فشيئًا. آلة سحرية بعض الشيء تمسك هذا المكان بالذات، كما هو، على ورقة واحدة."},"ICON-1472":{"nm":"صورة قديمة","de":"بقدر ما بهت اللون، مرّ من الوقت بقدره. في كل زاوية متآكلة، بقيت لمسة يد أحدهم. أن أقدم صورة تحمل أوضح ذكرى، ربما بسبب تلك اللمسات بالذات."},"ICON-1473":{"nm":"دفتر القصاصات","de":"قصاصات يصعب التخلي عنها تتجمع وتتجمع حتى تصبح مجلدًا واحدًا. تذكرة سينما باهتة، بتلة زهرة جافة، مذكرة قصيرة واحدة. أشياء متناثرة في عين الآخرين، لكن لمن يفتحه يعود موسم كامل إلى الحياة."},"ICON-1474":{"nm":"سجل الإبحار","de":"ريح اليوم وأمواجه، وسطر واحد من القلب. تدوينها بأمانة حتى في الأيام العادية هو قانون الإبحار. دليل الوصول بسلام مكتوب دائمًا في مكان ما داخل هذا السجل السميك."},"ICON-1475":{"nm":"قطعة خريطة","de":"مجرد زاوية واحدة من الكل، لكن بدونها لن تجد الطريق أبدًا في النهاية. يا لها من نشوة حين تتلاءم حافة ممزقة مع قطعة أخرى تمامًا. تصنيف R له حضور القطعة الأخيرة من أحجية."},"ICON-1476":{"nm":"رسالة في زجاجة","de":"دون معرفة من سيقرأها، تسلّم نفسها بهدوء للأمواج. لا تتوقع ردًا، بل تتمنى فقط أن يصل هذا القلب إلى مكان ما. أبطأ طريقة لإرسال بريد وأكثرها رومانسية."},"ICON-1477":{"nm":"نرد","de":"ستة أوجه تضحك بشكل مستدير كأنها تقول أنت مجددًا. نفس الشكل، لكن إعطاء إجابة مختلفة مع كل تدحرجة هو تقلب هذا الصديق الثابت. لحظة مغادرته يدك، تسلّم الاختيار مؤقتًا للقدر."},"ICON-1478":{"nm":"طاحونة هوائية صغيرة","de":"لا تنبض بالحياة إلا حين تهب الريح. تُركت ساكنة، فهي مجرد جناحين من ورق، لكن دع أحدهم ينفخ عليها فتبدأ بالدوران بمرح. عدم الخجل من تلقي المساعدة هو حكمة هذه الزهرة الصغيرة."},"ICON-1479":{"nm":"سلة نزهة","de":"افتح الغطاء، وتحييك رائحة الكيمباب أولًا. عشب أخضر، حصيرة مفروشة، وأيدٍ تتشارك الطعام مع أيدٍ أخرى. الأيام التي امتلأت فيها هذه السلة كانت دائمًا، بغرابة، تحت سماء صافية."},"ICON-1480":{"nm":"مزهرية","de":"زهرة واحدة فقط تكفي لتغيير هواء الغرفة كله. حين تكون فارغة، الانتظار الصامت هو واجبها الحقيقي. أكثر أدوات المسرح تواضعًا في الغرفة، تخفض حضورها لتزيد بريق الزهرة."},"ICON-1481":{"nm":"بتلة زهرة","de":"حين تأخذ الريح واحدة، يصبح الربيع أخف بقدرها. الشجرة العجوز في الفناء تقدم نفس التحية كل عام، أن السقوط أيضًا جزء من عمل التفتح. التناثر ليس نهاية، بل رسالة تُرسل مسبقًا إلى الربيع القادم."},"ICON-1482":{"nm":"وردة","de":"رفع الأشواك أولًا وعد بألا تُلمس بلا مبالاة. في داخلها يختبئ أحمر القلب. ترك أحدهم زهرة واحدة بهدوء عند القدمين ورحل، كاتبًا قلبه باللون وحده بدلًا من الاسم."},"ICON-1483":{"nm":"زنبق أبيض","de":"بجانب الخزف الأبيض النقي، وُضعت هذه الزهرة البيضاء دائمًا. عطرها يذهب بعيدًا، لكن الأمل ألا تتزعزع هيئتها. من ذلك المكان الذي اختار النقاء بدلًا من البهرجة، يحافظ الزنبق بصمت على قدر من الوقار."},"ICON-1484":{"nm":"توليب","de":"الوقوف في صف برؤوس منحنية قليلاً يبدو أنيقًا بغرابة. الزهرة التي تتصدر الصف الأول من حديقة الربيع. صدقها في التفتح دفعة واحدة والذبول دفعة واحدة يصبغ الموسم القصير بأعمق الألوان."},"ICON-1485":{"nm":"السنبل","de":"على ساق واحدة تتدلى أجراس صغيرة متكاتفة. هزّها فلا صوت، لكن العطر يرن بدلاً منه في أرجاء الغرفة. عند عتبة الربيع، ترف لطيف يستبدل هواء الغرفة كله بمزهرية واحدة."},"ICON-1486":{"nm":"عينة ضفدع","de":"جسد صغير توقف فيه الزمن داخل صندوق زجاجي. مكتوب على الملصق: حقول الأرز والبرك، الأنشط في اليوم التالي للمطر. فقط بعد التوقف، تبقى حتى حرارة الضفة المائية التي عاش عندها الكائن مسجّلة."},"ICON-1487":{"nm":"عينة سحلية","de":"الذكاء الذي كان يقطع ذيله ويهرب به وحده لا يُمحى حتى بعد أن يصبح عينة. ضيف صغير كان يحب الجدران الحجرية الدافئة بالشمس. في المذكرة المجاورة، مكتوب بوضوح اتجاه البقعة المشمسة التي كان يحب تسلقها."},"ICON-1488":{"nm":"سجل الخلد","de":"مذكرات من يتنقل تحت الأرض تُكتب بحبيبات التراب. أين حفر وأين توقف، خريطة لطرق لا تُرى. الوقت الذي عاشه مدبرًا ظهره للضوء يصبح لأحدهم سجلًا في غاية الأمانة."},"ICON-1489":{"nm":"عينة صدفة","de":"نقش صلب صقلته الأمواج آلاف المرات وأرسلته. كان أهل الشواطئ الطينية يعرفون من أي بحر جاءت الصدفة بمجرد النظر إلى نسيجها. شكل بحر كان حيًا يتنفس يومًا ما، يُحفظ كاملاً في عينة بحجم راحة اليد."},"ICON-1490":{"nm":"عينة مرجانية","de":"في أعماق البحر، ينمو بالكاد شبرًا واحدًا على مدى مئات السنين. يبدو كأغصان، لكنه في الحقيقة بيت بنته معًا حيوات صغيرة لا تُحصى. أن الأبطأ يبقى أطول، يثبته المرجان بصمته."},"ICON-1491":{"nm":"دليل أيدونغ","de":"جزء من قصة متناثرة في مكان ما من الجزيرة. قصاصة ورق صغيرة تشير بهدوء إلى الخطوة التالية. كل مغامرة، في النهاية، تبدأ بالتقاط آثار تافهة كهذه، كما يقول الدليل العجوز."},"ICON-1492":{"nm":"قطعة التوقيع المميز","de":"حين يجد النقش المتناثر مكانه، تكتمل أخيرًا علامة واحدة. قطعة محفور عليها نسيج فريد لأحدهم. تخفي معناها حتى تُطابَق، وفي لحظة تطابقها، تصبح أخيرًا اسمًا."},"ICON-1493":{"nm":"شظية ذكرى المسرح","de":"حتى بعد انتهاء أغنية، تبقى حرارة متبقية بين المقاعد. انزع ذلك الدفء وصلّبه فيصبح شظية صغيرة كهذه. شظايا متناثرة من التصفيق والهتاف، إن جُمعت بهدوء، تعيد تلك الليلة إلى الحياة كاملة."},"ICON-1494":{"nm":"ختم البداية","de":"يوم نودي باسمك لأول مرة، ذلك الأثر الحبري المطبوع على ظهر يدك. حتى الحرص على تجفيفه بعناية كي لا يتلطخ كان جزءًا من خط البداية. ختم صغير واحد يجعل يومًا معينًا لا يُمحى أبدًا."},"ICON-1495":{"nm":"ميدالية أفضل آيدول","de":"ثقل لا يُسمح به إلا لمن يصل إلى أعلى مكان. لكن هذه الميدالية ثقيلة ليس بسبب المعدن. بل لأن وزن الأيدي التي لا تُحصى والتي ملأت المسرح معًا، يجتمع كاملاً في نقطة واحدة."},"ICON-1496":{"nm":"مفتاح صغير","de":"كان أول مفتاح للسكن دائمًا مفتاح الغرفة الأعمق. مكان تعلمت فيه فتح الباب قبل أن تتعلم إغلاقه. يوم الرحيل، يبقى الدفء الذي تركته راحة اليد فوق المعدن البارد طويلًا."},"ICON-1497":{"nm":"صندوق كنز","de":"لا أحد يعرف ما بداخله قبل فتحه. هذا الجهل بالذات هو الكنز الحقيقي لصندوق الكنز. في اللحظة القصيرة لرفع الغطاء، يعود الجميع للحظة إلى نبض أيام الطفولة."},"ICON-1498":{"nm":"مخطط هندسي","de":"فوق خطوط مرسومة خانة تلو خانة، يعيش مبنى لم يُشيَّد بعد. فرد المخطط هو السير عبر الغد مرة مسبقًا. خط واحد مرسوم بعناية يسند غدًا لن ينهار."},"ICON-1499":{"nm":"بطاقة وصفة","de":"على بطاقة واحدة مكسوة بآثار اللمس، مكتوبة نكهة يد الجدة كمقادير. كلمات غامضة مثل قبضة من الملح هي السر الأدق. كلما بهت الخط، ازداد وضوح ذلك المطبخ الذي كان يُطهى فيه ذلك الطعام في الذاكرة."},"ICON-1500":{"nm":"تصريح منشأة","de":"ورقة واحدة تحوّل أرضًا خالية إلى مكان يمكن استخدامه. كان المبنى الجديد يحتاج دائمًا أولًا إلى ختم القرية. الإذن، في النهاية، هو ختم دافئ يقول إنه لا بأس من بدء شيء ما هنا."},"ICON-1501":{"nm":"تصريح الميناء","de":"قبل أن ترسي السفينة مرساتها، كان لا بد من هذه الورقة الواحدة أولاً. ختم الميناء الباهت هو أول تحية تستقبل بها القادمين من بعيد. بين الرحيل والوصول، يفتح الميناء قلبه دائمًا بورقة واحدة."},"ICON-1502":{"nm":"شهادة انتماء الجزيرة","de":"شهادة صغيرة تعلن أنك أصبحت أحد أبناء هذه الجزيرة. حين يقدم جار جديد، كانت القرية القديمة تضيف اسمه إلى سجلها وتوزّع كعك الأرز الدافئ. إنها مجرد ورقة، لكن المكتوب عليها ترحيب مشرق: \"أنت الآن واحد منا\"."},"ICON-1503":{"nm":"لوحة اسم الغرفة","de":"باسم واحد معلّق بجانب الباب، تتحوّل الغرفة الخالية أخيرًا إلى بيت لأحدهم. حتى في الأجنحة القديمة، كانت أول ما يُعلَّق لوحةٌ محفور عليها اسم صاحب المكان. لوحة الاسم صغيرة، لكنها مليئة بدفء القول: \"هنا يعيش أحدهم\"."},"ICON-1504":{"nm":"طابع بريد المعجبين","de":"حتى العناية بترطيب الطابع والضغط عليه بإحكام كانت جزءًا من رسالة كاملة. فعل إلصاق مشاعر المحبة على قصاصة صغيرة وإرسالها بعيدًا. حتى في العصر الرقمي، ما زال أحدهم يرسل قلبه بيده."},"ICON-1505":{"nm":"شارة الجزيرة اللامعة","de":"علّقها على ياقتك، وسيتبعك بريق صغير أينما ذهبت. حين تلتقي بمن يرتدي الشارة نفسها في الطريق، تتفاهمان دون كلمة. البريق ليس تباهيًا، بل إشارة هادئة: \"نحب الجزيرة نفسها\"."},"ICON-1506":{"nm":"طاولة العمل","de":"السطح المليء بالخدوش يشهد على الأيدي التي صنعت أكثر الأشياء. المكان الذي أُصلح فيه شيء ووُصل وهُذّب. أكثر من مكتب نظيف، تحمل طاولة العمل الفوضوية في الحقيقة قصصًا أكثر بكثير."},"ICON-1507":{"nm":"صندوق التخزين","de":"كلما كان الشيء أثمن، كان تحديد مكانه أسبق. حتى قدماء الناس كانوا يحفظون الوثائق الثمينة في صناديق من خشب الباولونيا. أن تحفظ شيئًا جيدًا يعني، في النهاية، أن تطوي اليوم بعناية من أجل شخص في المستقبل."},"ICON-1508":{"nm":"صندوق الموارد","de":"حين يفيض المخزون تُجمع، وحين ينقص تُستعمل. هنا تكمن حكمة زمن كان فيه امتلاء المخزن يعني اطمئنان القلب. الادّخار هو وجبة رقيقة تُقدَّم مسبقًا لذاتك المستقبلية."},"ICON-1509":{"nm":"صندوق التبريد","de":"صندوق مملوء بالثلج يحفظ البرودة حتى في عزّ الصيف. وكأنّ حكمة بيت الثلج القديم انتقلت إلى حجم راحة اليد. أن تحافظ على البرودة يعني أن تُطيل بقاء أطزج لحظة قليلاً بعد."},"ICON-1510":{"nm":"مضخة الماء","de":"حرّك المقبض صعودًا وهبوطًا، وسينبع الماء العميق من باطن الأرض. آلة صادقة لا تتدفق إلا بعد أن يُسكب فيها دلو واحد من ماء التحضير. أدرك أهل البئر منذ القدم أن عليك أن تُعطي أولاً كي تنال."},"ICON-1511":{"nm":"جهاز تنقية المياه","de":"معجزة صغيرة يتصاعد فيها الماء العكر صافيًا طبقة بعد طبقة. كان القدماء يرشّحون الماء بترتيب طبقات من الرمل والفحم داخل الجرار. الصفاء لا يُنال مجانًا، بل هو عناية الترشيح البطيء."},"ICON-1512":{"nm":"حامل مرشّة الماء","de":"في اللحظة التي تجد فيها المرشّة مكانًا لترتاح فيه، يصبح يوم الحديقة مرتّبًا. تحديد مكان لتعليق الأداة عادة من يحب عمله. حين يُحدَّد مكان واحد، تصبح الساحة كلها أكثر انتظامًا."},"ICON-1513":{"nm":"حامل قصبة الصيد","de":"قد يرحل الإنسان انتظارًا لعضة السمكة، لكن قصبة الصيد تحفظ مكانها. وضعية الانتظار الصبور، انتظار صيد السنين على ضفة النهر، محفورة هنا كما هي. الحامل، في النهاية، ركيزة لوضع نفاد الصبر جانبًا قليلاً."},"ICON-1514":{"nm":"سلة الجمع","de":"حفنة من أعشاب الجبل وزهرة برية واحدة، حِمل يد الأم. من بين فجوات الخيزران المنسوج، تتسرّب رائحة التراب بهدوء. تبعًا لما تملؤه، يمكن للسلة الفارغة أن تصبح ربيعًا أو خريفًا."},"ICON-1515":{"nm":"الهاون والمدقّة","de":"دقّ، دقّ، بإيقاع ثابت يُطحن الحَبّ فيستيقظ يوم القرية. أداة كان صوت دقّها يملأ الأزقة في الأعياد. لجعل الصلب طريًا، يلزم إيقاع ثابت من يد عاملة."},"ICON-1516":{"nm":"لوح التقطيع","de":"كل أثر تتركه السكين ينقش تاريخ وجبة. لوح خشبي مليء بالخدوش وسام مطبخ لأكثر الأيدي اجتهادًا. تقطيع شيء ما يبدأ من الرغبة في تقديمه بعناية."},"ICON-1517":{"nm":"قدر الطهي","de":"صوت الغليان الفوّار ألطف من أي موسيقى. في فجر جائع، تلك الدقائق الثلاث انتظارًا لنضج المعكرونة هي أحنّ عزاء خاص. على كامل القاع المستدير، تسخن دفء رغبة إطعام أحدهم."},"ICON-1518":{"nm":"مقلاة","de":"مهارة الطهي في لحظة واحدة فوق النار تتوقف على هذا القِدر الواحد. كلما كان السطح أكثر تتبيلًا وتلطيفًا، قلّ التصاقه وزاد لمعانه. المقلاة الحديدية طويلة الاستعمال هي بذاتها شاهد على سنوات عاشها المطبخ."},"ICON-1519":{"nm":"الفرن","de":"بينما تُغلق الباب وتنتظر، يحدث سحر هادئ في الداخل. الوقت الذي ينتفخ فيه العجين ويَنضَج اللون. حتى لو لم تره، إن انتظرت بثقة، ستخرج نتيجة دافئة من الباب."},"ICON-1520":{"nm":"الخلاط","de":"حتى الأشياء الصلبة تصبح في لحظة واحدة كوبًا ناعمًا حين توضع هنا. دوامة صغيرة تمتزج فيها مكونات مختلفة فيولد منها طعم جديد. الانسجام، في النهاية، أن يتنازل كل طرف قليلاً عن حوافه."},"ICON-1521":{"nm":"خفّاقة","de":"بحركة معصم واحدة يُحبس الهواء، وبقدر سرعة الخفق يقوى ما كان رقيقًا. بينما ترتفع الفقاعات كالقمم، ليس العجين وحده ما ينتفخ. ينتفخ معه أيضًا قلبُ من يريد أن يُطعم أحدهم اليوم."},"ICON-1522":{"nm":"مطحنة البن","de":"أدر المقبض على حفنة من حبوب البن، وستتحطم الرائحة أولًا بين الأسنان. حين يتيبّس ذراعك، يصبح المسحوق ناعمًا أخيرًا، وتزداد الرشفة الأولى عمقًا بقدر ذلك الجهد. العناية تبدأ دائمًا من المعصم."},"ICON-1523":{"nm":"طاحونة الدقيق","de":"تدخل الحبّة بين الحجرين وتخرج دقيقًا أبيض. لا بأس إن لم تكن ناعمة من المرة الأولى، فكرّرها مرتين أخريين. حتى جعل الخشن ناعمًا له ترتيبه، تُخبرنا الطاحونة بصمت."},"ICON-1524":{"nm":"منضدة النشر","de":"حين تُرفَع الجذوع، يقرأ المنشار حبيبات الخشب أولًا. تجنّب العقد واقطع في الطريق المستقيم وحده كي لا يعوجّ اللوح. قطع الخشب هو، في النهاية، فرد الزمن الذي عاشته شجرة واحدة بترتيب وعناية."},"ICON-1525":{"nm":"ماكينة الخياطة","de":"طقطقة— صوت الإبرة تمسك القماش وتجري يملأ الليل المتأخر. غرزة واحدة تصل قطعتين في جسد واحد، وفي كل درزة خفيّة داخل زي المسرح، تُخاط بإحكام ساعات سهر أحدهم."},"ICON-1526":{"nm":"منضدة الصباغة","de":"اغمس القماش الأبيض وأخرجه: في البداية أخضر فاتح، ثم يزرقّ أخيرًا حين يلامس الهواء. ذلك اللون الذي لا يظهر إلا بعد نقع النيلة ثلاث مرات. أن الانتظار نفسه يصبح لونًا، تعلمته أول مرة أمام منضدة الصباغة هذه."},"ICON-1527":{"nm":"حامل الكاميرا الثلاثي","de":"في اللحظة التي تفرد فيها أرجله الثلاثة وتلامس الأرض، يهدأ العالم المهتزّ. لقطة كانت سترتجف في يدك تصبح واضحة فوق ميثاق هذه النقاط الثلاث. لتحدّق في شيء طويلًا، عليك أولًا أن تعرف كيف تقف ثابتًا."},"ICON-1528":{"nm":"حامل الإضاءة","de":"ضع نورًا فوق عمود واحد، وأي مكان في الغرفة يصبح مسرحًا صغيرًا. أدر الزاوية قليلًا فتطول الظلال وتنبض التعابير بالحياة. ليست أداة لمحو الظلام، بل لوضعه هو الآخر بلطف في مكانه."},"ICON-1529":{"nm":"حامل الميكروفون","de":"في لحظة ضبط الارتفاع، تتحدد المسافة بين الفم والأغنية. ارفع يديك، وسيبقى الصوت في مكانه. فقط على مسرح تتحرر فيه اليدان، تبدأ أغنية تُغنّى بالجسد كله."},"ICON-1530":{"nm":"حامل النوتة الموسيقية","de":"حين تتكئ الصفحة المفتوحة بميل خفيف، تصطف النغمات عند مستوى نظر العازف. حتى لو جاءت المقطوعة التالية بإيماءة واحدة، لا يهتز الحامل. خلف عزف أي شخص، يوجد دائمًا مكان صامت."},"ICON-1531":{"nm":"الحديقة المنزلية","de":"احرث التربة وارسم الأخاديد، وتظهر خطوط وعد صغيرة فوق الأرض. الأيام القليلة بعد دفن البذرة تبدو وكأن لا شيء يحدث، لكن في صباح ما تدفع فلقتان غضّتان التراب وتصعدان. مشهد لا يراه إلا من انتظر."},"ICON-1532":{"nm":"الحديقة الخصبة","de":"البذرة نفسها، لكن أوراقها في هذه الأرض تنمو ضعف الحجم. أدخل إصبعك فتتبعك تربة سوداء طرية حتى تحت الأظافر. النمو الجيد كان، في النهاية، عمل الأرض غير المرئية تحت القدمين تنجزه بصمت."},"ICON-1533":{"nm":"البيت الزجاجي","de":"تحت سقف زجاجي، تسير الفصول بإيقاع أبطأ بخطوة. حتى حين يسقط الصقيع في الخارج، يبقى الداخل رطبًا برطوبة منتصف الصيف. من أجل الأشياء الضعيفة أمام البرد، حبس أحدهم ضوء الشمس بهدوء تحت السقف."},"ICON-1534":{"nm":"حوض الأعشاب","de":"مرّر أطراف أصابعك على الأوراق، وتحيّيك الرائحة أولًا. ريحان، إكليل الجبل، نعناع— كلما نادَيت اسمًا التصقت رائحة مختلفة بأصابعك. حوض صغير واحد يحوّل المطبخ بأكمله بلطف."},"ICON-1535":{"nm":"البستان","de":"في الربيع تنحني الأغصان بظل الزهر، وفي الخريف بثقل الثمر. اصعد السلّم واقطف ثمرة واحدة وعضّها، فتنفجر في فمك حلاوة جمعتها الشمس طوال عام كامل. وكأنها رسالة ردّ تبعثها الشجرة إلى الإنسان."},"ICON-1536":{"nm":"جذع الفطر","de":"احفر ثقوبًا في جذع مقطوع وازرع فيه الجراثيم، فتربّي الشجرة الميتة شيئًا من جديد. بعد أيام قليلة، في الصباح الذي تنبت فيه القبعات عناقيدَ، تبدأ حياة جديدة بهدوء في المكان الذي ظننته النهاية."},"ICON-1537":{"nm":"خلية النحل","de":"قرّب أذنك فتسمع اهتزازًا منخفضًا ودؤوبًا في الداخل. آلاف رفرفات الأجنحة تجتمع لتصنع بالكاد ملعقة واحدة من الحلاوة. تعب يوم كامل من التنقل بين الحقول يتجمّع هنا، لزجًا وذهبيًا."},"ICON-1538":{"nm":"عشّ الدجاج","de":"قبل بزوغ الفجر، تُصدر الجالسات على العارضة حفيفًا أولًا. أدخل يدك في القش الدافئ فتمسك بيضة لا يزال دفؤها باقيًا. المكان الذي يعلن الصباح أولًا هو أول من يُعدّ مائدة الصباح."},"ICON-1539":{"nm":"المرعى","de":"سهل واسع تمتزج فيه رائحة العشب برائحة الشمس. فوق ظهور تجترّ ببطء داخل السياج، تمرّ ظلال الغيوم. في هذا المكان الذي لا شيء فيه يستعجل، حتى الزمن يسيل ببطء، كأنه يرعى."},"ICON-1540":{"nm":"مشغل الجبن","de":"الحليب الطازج يتصلّب ببطء عبر التخثّر والنضج. انتظر أشهرًا على رفّ بارد كالكهف، ويتغلغل نكهة عميقة في الكتلة البيضاء. الجبن اسم لا يُمنح إلا لحليب لم يستعجل."},"ICON-1541":{"nm":"مشغل التوفو","de":"انقع الفول واطحنه واغله، فيصبح حليب الفول ذو الرائحة النيّئة عطرًا شهيًا. قطرة واحدة من ماء الملح تجمع المتناثر إلى توفو طري، وبضغطة هادئة، تتشكّل زواياه. هنا يد تهدّئ قلبًا مشتتًا وتمنحه شكلًا."},"ICON-1542":{"nm":"مصطبة جرار المخللات","de":"في زاوية مشمسة من الفناء، تتجمّع جرار قصيرة متلاصقة تتشمّس. ارفع غطاءً فتفوح رائحة زمن عتيق. طعم الصلصة التي خمّرتها الجدّة هو، في الحقيقة، أكل السنين ملعقة تلو أخرى."},"ICON-1543":{"nm":"مطحنة القرية","de":"حين تدور الأحجار بصرير، يتحرر الحَبّ إلى دقيق. يطفو غبار أبيض في ضوء الشمس، وينتظر دورهم من يريدون عجن وعاء من كعك الأرز. كان يوم عيد القرية يبدأ دائمًا عند هذه العتبة."},"ICON-1544":{"nm":"المخبز","de":"من خلال شقّ باب الفرن تتسرّب رائحة الزبدة والسكر. حين يصفرّ العجين المنتفخ، تتباطأ الخطوات المارّة أمام المتجر دون وعي. رغيف خبز طازج واحد يحمل دفئًا لا يقاومه أحد."},"ICON-1545":{"nm":"عربة الوجبات الخفيفة","de":"تخفق المظلة البلاستيكية في الريح ويتقلّص مرق التوكبوكي فورانًا. مساء يُحتسى فيه المرق من كوب ورقي مع سيخ كيك سمك واحد، مكانٌ يذيب البرد والجوع معًا دفعة واحدة. عزاء صغير في نهاية الزقاق."},"ICON-1546":{"nm":"المطبخ الغربي","de":"تسخن المقلاة ويطقطق زيت الزيتون. بتعديل واحد للنار، قد تتماسك الصلصة أو تحترق. هنا حيث يُوزَن حتى توازن الألوان فوق الطبق، تصبح الوجبة عرضًا مُعدًّا بعناية فائقة."},"ICON-1547":{"nm":"المطبخ الصيني","de":"فوق نار حامية، يدور الووك كأنه يرقص. في اللحظة القصيرة التي تتصاعد فيها الألسنة، تُحبس رائحة المكونات كاملة. سريعًا وحارًّا، سرّ الطبخ الصيني يكمن في تلك النفَس الواحد الذي تفوّته إن ترددت."},"ICON-1548":{"nm":"المقهى","de":"ادفع الباب فتحييك رائحة حبوب البن وموسيقى هادئة أولًا. مقعد بجانب النافذة، لاتيه يبرد، ودفتر مفتوح. لتمنحك لحظة تنفّس وسط يوم صاخب، خبّأت المدينة غرفًا صغيرة كهذه هنا وهناك."},"ICON-1549":{"nm":"متجر الحلويات","de":"داخل الواجهة الزجاجية، تصطف كعكات ملونة في انتظار الزبائن. في لحظة تشقّ فيها طرف الشوكة الكريمة، ترتفع زاوية الفم أولًا. وصفة صغيرة وحلوة تجعل حتى اليوم الحزين محتملًا بقطعة واحدة."},"ICON-1550":{"nm":"محل الجزارة","de":"تحت ضوء أحمر، يستلقي اللحم مرتّبًا بحسب اتجاه الألياف. بكلمة واحدة \"هذا جيد اليوم\"، تنزلق السكين بالسماكة المضبوطة تمامًا. دفء مائدة العشاء يبدأ بهدوء من هذه اليد التي تحرس المكان نفسه كل يوم."},"ICON-1551":{"nm":"منضدة تجهيز المأكولات البحرية","de":"منضدة عمل تختلط فيها رائحة السمك الفجرية ببرودة الجليد. حتى إن تطايرت القشور وتخدّرت اليدان، لا تتوقف عين تنتقي الأطزج أبدًا. هنا تجد الأشياء التي خرجت للتوّ من البحر طريقها إلى المائدة."},"ICON-1552":{"nm":"حقل الملح","de":"احبس ماء البحر، وتتكفّل الشمس والريح بالباقي. انتظر أيامًا حتى يجف الماء، فتنبت بلورات بيضاء على القاع كالنجوم. حفنة من الملوحة هي، في الحقيقة، هدية صنعها البحر والسماء معًا ببطء."},"ICON-1553":{"nm":"حامل تجفيف الأعشاب البحرية","de":"على حبل طويل، يتدلى عشب البحر والكمبو جنبًا إلى جنب، يتمايلان مع الريح. الأشياء المشبعة بماء البحر تجفّ وتزداد اخضرارًا عميقًا. أكثر نكهات البحر تقشفًا، صنعتها الشمس ونسيم الملح معًا، تتدلى هنا."},"ICON-1554":{"nm":"الرصيف الصغير","de":"ألواح خشبية غارقة نصفيًا في الماء تتموّج بخفة تحت القدمين. مكان مثالي تمامًا لربط قارب صغير واحد. الرحيل إلى بعيد والعودة بسلام، كلاهما يبدأ وينتهي عند هذا الرصيف الواحد."},"ICON-1555":{"nm":"مستودع الميناء","de":"افتح الباب الخشبي المعتّق بريح البحر، وستجد الشِباك والبراميل والحبال مكدّسة حتى السقف. بضائع متجهة إلى رحلة بعيدة وبضائع وصلت للتوّ تستقرّ للحظة تحت سقف واحد. مكان أشبه بمحطة عبور يتقاطع فيها الرحيل والعودة بلمحة."},"ICON-1556":{"nm":"المنارة","de":"فقط حين يشتدّ ظلام البحر ليلًا، تبدأ عملها أخيرًا. الضوء الدوّار يشقّ الضباب ويقول: \"هنا طريق\". حارس طويل لا ينام أبدًا، من أجل عودة أحدهم سالمًا."},"ICON-1557":{"nm":"حوض بناء السفن","de":"أقم العارضة وثبّت الأضلاع، فيتشكّل هيكل سفينة. في ساحة يرنّ فيها صوت المطارق طوال اليوم، تحلم سفينة لم تتذوق طعم الماء بعد برحلتها الأولى. مكانٌ يتصلّب أولًا كي يرحل لاحقًا."},"ICON-1558":{"nm":"غرفة التسجيل","de":"حين يُغلق الباب، تختفي كل أصوات الخارج في لحظة واحدة. كل ما يُسمع خلف سماعات الرأس هو نَفَسك وإيقاعك فقط. في صمت هذه الغرفة الصغيرة، يولد أخيرًا صوت يمكنه أن يرتجف بحرّية."},"ICON-1559":{"nm":"غرفة الموسيقى","de":"تسرّب توافقات من شقّ الباب يملأ الممر. أحدهم يتتبّع السلّم الموسيقي وآخر يعدّ الإيقاع. مكان يُسمح فيه بامتزاج الأصوات الخام والناضجة، فصل دراسي رقيق تخطو فيه كل أغنية خطواتها الأولى."},"ICON-1560":{"nm":"غرفة البيانو","de":"افتح غطاء المفاتيح، وستجد طبقة رقيقة من الغبار على المفاتيح البيضاء. في لحظة ملامسة الأصابع لها، ينتشر رنين صافٍ في أرجاء الغرفة. إن وُجدت أمسيات لا وحدة فيها رغم العزلة، فربما بسبب هذا البيانو الواحد."},"ICON-1561":{"nm":"غرفة الرقص","de":"اضغط بأطراف أصابع قدميك، فيدفعك الأرض إلى الأعلى مجددًا. بينما تنسخ المرايا الأربعة الحركة نفسها أربع مرات، يحفظ الجسد الرقصة بنصف إيقاع سابق للموسيقى. غرفة يبقى فيها العرق والنَفَس أطول مدة، ومنها تخرج الحركات التي نمت هنا لتمشي إلى المسرح."},"ICON-1562":{"nm":"غرفة الجيم","de":"الوزن لا يكذب أبدًا. يحب الناس تلك الصدق بالذات، إذ يُضاف إلى الكتف بالضبط بقدر ما يُرفع، لذا يقصدونني كل فجر. ما يُنقَش ببطء في المرآة ليس عضلات، بل الساعات التي صمدت فيها دون استسلام."},"ICON-1563":{"nm":"غرفة اليوغا","de":"تنفّس بعمق، وستشعر وكأن أرضية الخشب تنتفخ معك. غرفة تطوي فيها ببطء يومًا جاء مسرعًا، وعلى حصيرة واحدة، يعود كل شخص إلى إيقاع نَفَسه الخاص. حتى القلب المتعجّل يضع نفسه جانبًا هنا لبرهة."},"ICON-1564":{"nm":"غرفة تبديل الأزياء والمكياج","de":"قبيل الخروج إلى المسرح مباشرة، يصبح الناس هنا لبرهة أشخاصًا آخرين. حين تدفئ المصابيح المحيطة بالمرآة الوجه بالتساوي، يلتصق الارتجاف بطرف قطعة البودرة ويختبئ خلف الياقة بهدوء. مكان تبدأ فيه لحظة التحوّل وتنتهي."},"ICON-1565":{"nm":"غرفة الأزياء","de":"حتى اكتمال زي واحد على المسرح، تُلبَس الثياب المعلقة هنا وتُخلع عشرات المرات. دمية عرض تدور ودبابيس التثبيت مغروزة فيها، خطوط الحاشية مرسومة بالطباشير. خلف البريق، تبقى دائمًا أثر إبرة خياطة أحدهم."},"ICON-1566":{"nm":"ديكور محطة البث","de":"يكفي أن يبدو الجانب الوحيد الذي تلتقطه الكاميرا حقيقيًا، تعلّمت ذلك مبكرًا. دُر خلف الخشب الرقائقي فلن تجد سوى هيكل فارغ. دعم بهاء الواجهة كان دائمًا نصيب ألواح خشبية غير مرئية."},"ICON-1567":{"nm":"استوديو التصوير","de":"أول سرّ هو إلقاء الضوء من ثلاث جهات لمحو الظلال. الضوء الرئيسي يُبرز الوجه، والضوء المساعد الظل، والضوء الخلفي أطراف الشعر. في لحظة سقوط الغالق، تحبس خلفية بيضاء واحدة أجمل ابتسامة لهذا اليوم."},"ICON-1568":{"nm":"قاعة الحفلات","de":"في الظلام عالي السقف، أحمل الوعد نفسه دائمًا: أنه حين يرتفع الستار، حتى المقاعد الفارغة ستحبس أنفاسها كإنسان واحد. من أجل تلك اللحظة الواحدة التي تسقط فيها أول نبضة، أقف فارغة بهدوء طوال العام."},"ICON-1569":{"nm":"كشك لقاء المعجبين","de":"المسافة بين يد ويد تساوي بالضبط عرض طاولة واحدة. تحية قصيرة، توقيع مرتجف، وكلمة لم تُقَل حتى النهاية، تمرّ متتالية. داخل هذا الحيّز الصغير، يلتقي وجهًا لوجه للمرة الأولى شعور محبة رُبّي طويلًا."},"ICON-1570":{"nm":"السرير","de":"كنت دائمًا أول من يستقبل نهاية اليوم. حين تهدأ أخيرًا الأرجل المتعبة من التمرين وحتى الارتجاف المتبقي خلف الكواليس، يبدأ الصباح من جديد بخطى خفيفة. أقول تصبح على خير، وأحتضنك دون كلمة."},"ICON-1571":{"nm":"السرير الطابقي","de":"بين الطابق العلوي والسفلي، تصل خمس درجات من السلّم بين شخصين. أصوات خافتة تُتبادَل بعد إطفاء النور، ونجوم مضيئة في الظلام ملصقة على السقف. تصبح الغرفة الضيقة أوسع ما تكون بفضل القصص التي تصعد وتنزل السلّم كل ليلة."},"ICON-1572":{"nm":"الرفّ","de":"ما تضعه فوقي يكشف من أنت. رسالة وصلت، أول كأس فوز، تذكرة دخول باهتة، تصطف جنبًا إلى جنب. لست أثاثًا للتباهي، بل مكان يعرض بهدوء ذكريات لم يستطع أحد التخلي عنها."},"ICON-1573":{"nm":"المكتب","de":"مع دفتر كلمات مفتوح، تُرسم أسطر جديدة فوق آثار ممحوّة. أكواب ورقية تراكمت طوال الليل ولحن واحد بالكاد أُنقذ. العمل البطيء لنقل القلب إلى كلمات يحدث دائمًا بهدوء فوق هذا السطح المستوي."},"ICON-1574":{"nm":"الكرسي","de":"عبارة \"اجلس للحظة\" رقيقة بشكل مفاجئ. مهما طال الاجتماع أو امتدّ التمرين، يتحمّل مسند الظهر ثقل الجسد بصمت. أعرف أن من وقف طويلًا هو من يرحّب بي أكثر."},"ICON-1575":{"nm":"الأريكة","de":"لتحويل السكن المتأخر ليلًا إلى غرفة معيشة، أنا وحدي أكفي. تزاحموا جالسين لمشاهدة برنامج ترفيهي، وقبل أن تشعروا، يكون أحدكم قد نام مستندًا إلى مسند الذراع. المقعد الأوسط الغائر يشهد على دفء ذلك البيت."},"ICON-1576":{"nm":"الطاولة","de":"حين يجلس الجميع حولي، لا يصبح أحد في صدر المجلس. يفوح حساء طازج وصوت اصطدام الملاعق، وأحداث اليوم تجتمع في المنتصف. حين ينبسط سطح مستدير واحد، يجلس اليوم المتناثر أيضًا مجددًا حول مكان واحد."},"ICON-1577":{"nm":"خزانة الملابس","de":"كلما تغيّر الفصل، تنسكب قصص قديمة من الداخل. أزياء المسرح والملابس اليومية كتفًا إلى كتف، تنتظر الثياب دورها التالي خلف الباب المغلق. فقط حين يُفتح الباب، يتقرر أخيرًا يوم اليوم الذي سيُرتدى."},"ICON-1578":{"nm":"المرآة","de":"المديح والعيب، أردّهما بالصدق نفسه. مكان الفحص الأخير قبل الخروج إلى المسرح، أمامي يهذّب الناس تعابيرهم ويصحّحون وقفتهم. أصدق صديق لا يقول كلمة واحدة أبدًا."},"ICON-1579":{"nm":"طاولة الزينة","de":"في كل درج صغير، وجه مختلف نائم. أنبوب للمسرح، وآخر للاستخدام اليومي، وثالث نادر مُدَّخر. اجلس أمام المرآة، وستبدأ ببطء بتحديد أي شخص ستصبح حين تخطو إلى الخارج اليوم."},"ICON-1580":{"nm":"السجادة","de":"الملمس الأول الذي تلامسه قدم حافية يحدد درجة حرارة الغرفة. آثار الجلوس معًا لتناول الوجبات الخفيفة والتمرغ تبقى وبرًا. أثاث يعمل من أدنى مكان، يدفئ الأرضية الباردة شبرًا إضافيًا."},"ICON-1581":{"nm":"الستارة","de":"أنا من يقرر كم من الصباح يُسمح له بالدخول. اسحبني قليلًا فيدخل ضوء الشمس طويلًا، أغلقني بإحكام فيصبح حتى النوم المتأخر أمرًا مغتفَرًا. الوقوف بين النافذة والغرفة وضبط كمية الضوء بهدوء، هو دائمًا نصيبي."},"ICON-1582":{"nm":"المصباح","de":"الغرفة نفسها تصبح وقتًا مختلفًا تمامًا بحسب لون الضوء. الضوء الأصفر يمدّ المساء طويلًا، والضوء الأبيض يوقظ الفجر بوضوح. ساحر بحجم راحة اليد، يغيّر مزاج اليوم خفية بمفتاح واحد."},"ICON-1583":{"nm":"الساعة الحائطية","de":"صوت عقرب الثواني لا يُسمع إلا في غرفة هادئة. كلما تعمّق التمرين نُسِيتُ، وفجأة حين تنظر إلى الأعلى، يكون خارج النافذة قد أصبح فجرًا دون أن تشعر. دون أن ألوم الزمن المنقضي، أشير بصمت فقط إلى الدقيقة التالية."},"ICON-1584":{"nm":"مزهرية","de":"حتى حين تذبل الزهور، لا أترك مكاني فارغًا. وعاء يحفظ لبرهة شعورًا مُهدى، وطالما هناك يد تبدّل الماء، تبقى المائدة مضيئة. حتى وأنا فارغة، أقف بشكل من ينتظر أحدهم."},"ICON-1585":{"nm":"إطار الملصق","de":"حتى تعليق وجه محبوب على الجدار يتطلب عناية. مكان لا تلامسه الشمس مباشرة، مسمار واحد أفقي تمامًا. ورقة واحدة مسجّاة برفق خلف الزجاج تكون أول من يحييني كل صباح حين أدخل الغرفة."},"ICON-1586":{"nm":"لوحة بطاقات الصور","de":"هل أرتّبها أبجديًا أم بترتيب الإصدار؟ تلك الحيرة السعيدة هي حيث يبدأ شغف المعجبين. خانة فارغة واحدة هي مكان المفضّل الذي لم يُقابَل بعد. كلما امتلأت بطاقة تلو أخرى، تصبح اللوحة سجلًا زمنيًا صغيرًا خاصًا بي."},"ICON-1587":{"nm":"حامل عصا التشجيع","de":"أخرج البطارية، والمقبض إلى الأعلى. حتى في زاوية الميل عند الوقوف مهارة خاصة بها. في انتظار الهتاف القادم، تطفئ العصا نورها هنا بالذات وتُسجِّي جسدها بهدوء. الراحة الجيدة تجعلها تضيء أسطع."},"ICON-1588":{"nm":"رفّ الجوائز","de":"في الصف الأمامي يوضع الأقدم. من تمثال مسابقة صغيرة إلى كأس مسرح كبير، تصطف لا بترتيب الطول بل بترتيب القلب. كلما لمّعتها، يعود ارتجاف ذلك اليوم على المسرح ليلامس أطراف أصابعي مجددًا."},"ICON-1589":{"nm":"سلة النزهة","de":"افتح الغطاء فتتسرّب رائحة شمس الربيع أولًا. كيمباب وترمس وحصيرة واحدة، مرصوصة بعناية استعدادًا للتوجه إلى الحقول. خطى من يحملني تصبح دائمًا، بطريقة ما، أخف بشبر من المعتاد."},"ICON-1590":{"nm":"أصيص زهور صغير","de":"شبر واحد من حافة النافذة يكفيني. خضرة صغيرة تتحمّل بسخاء حتى نسيانك المتكرر لسقيها. في زاوية مكتب شخص مشغول، أفتح ورقة إضافية كل يوم، ناقلًا بهدوء تحية اليوم."},"ICON-1591":{"nm":"أصيص زهور كبير","de":"بينما ينمو طولي، ينمو الإنسان معي. حين تلتقط الأوراق العريضة التي تشغل زاوية من الصالة ضوء الشمس وتلقي بظلها، يدخل الفصل خلسة إلى الغرفة أيضًا. مكافأة لا يعرفها إلا من لا ينسى السقي."},"ICON-1592":{"nm":"طقم الشموع المعطّرة","de":"في لحظة إشعال الفتيلة، يهدأ هواء الغرفة درجة. تنتشر الرائحة ببطء، مدفئة تعب الأمس وطاردته إلى الخارج. بشعلة صغيرة واحدة، يُختتم نهاية يوم مزدحم كطقس هادئ."},"ICON-1593":{"nm":"ثلاجة صغيرة","de":"افتح البابَ في ليلة متأخرة، ويرحّب بك علبة مشروب باردة. طنين اهتزاز صغير يجعل السكن الخالي أقل وحدة قليلًا. لا أستطيع إدارة بيت كامل، لكن لا شيء يضاهيني في تدبّر فجر جائع."},"ICON-1594":{"nm":"قبعة شبكة اصطياد الحشرات","de":"في لحظة وضعها على الرأس، يتبعك حقل صيفي فوق كتفيك. الشبكة المستديرة تصفّي ضوء الشمس بلطف، ومع كل خطوة تتمايل رائحة العشب برفق. قبعة تلبسك فصلًا كاملًا، حتى لو لم تصطد يعسوبًا واحدًا."},"ICON-1595":{"nm":"كيس شبكة الجمع","de":"معلّقًا على الخصر، يصبح رفيقًا في الجمع. أن تُحكم فتحته قليلًا فلا يهرب ما أُمسك، أول حيلة تُتعلَّم في الحقول. كيس قماشي خفيف واحد يحتضن بإحكام حصاد يوم كامل."},"ICON-1596":{"nm":"زجاجة مراقبة الحشرات","de":"أعرف أن ثقوب التهوية هي الأهم لضيف يمكث لبرهة فقط. ممر تنفس صغير مثقوب في الغطاء، وورقة عشب واحدة مفروشة في القاع. إعادته إلى الأدغال بعد انتهاء المراقبة جزء من هذا الزوج أيضًا."},"ICON-1597":{"nm":"علبة دبابيس العينات","de":"حتى في زاوية غرز الدبوس المائلة الواحدة تكمن مهارة. إن كانت عميقة جدًا تكسر، وإن كانت ضحلة اهتزّت، لذا يجب توزيع قوة أطراف الأصابع بدقة. علبة تحمل بهدوء عناية من يرغب في التحديق طويلًا في حياة صغيرة."},"ICON-1598":{"nm":"غطاء صندوق التربية","de":"العناية بالحدود بين الداخل والخارج هي مهمتي. أُغلَق بإحكام شديد فيختنق من بداخلي، وأُترك مفكوكًا جدًا فيضيع الطريق، لذا أترك دائمًا فجوة كخط مائل. الحماية تختلف بوضوح عن الحبس."},"ICON-1599":{"nm":"طبق تغذية الفراشات","de":"ضع قطنة مبللة بماء السكر في المنتصف، وتتجمّع الأجنحة حولها. السرّ أن يكون ضحلًا وواسعًا، بعمق لا تغرق فيه الأقدام الصغيرة. طبق واحد يجمع بهدوء ضيوفًا يتوقفون قليلًا في حديقة مشمسة."},"ICON-1600":{"nm":"مصباح استدراج الحشرات","de":"اتركه مضاءً بخفوت في الظلام، وتتجمّع الأجنحة الصغيرة تتبع الضوء. اجعل السطوع ناعمًا، والمكان بعيدًا عن الناس. مُنادٍ لطيف للغاية، يُهدّئ ليلة صيف مليئة بالطنين إلى حدّ ما."},"ICON-1601":{"nm":"ملصق الحشرة","de":"ست أرجل وزوج من قرون الاستشعار، وحياة صغيرة نائمة داخل قصاصة ورق بحجم الظفر. الصقها برفق في زاوية الدفتر، فيتفتح شبر من المرج بهدوء بين الصفحات."},"ICON-1602":{"nm":"بطاقة تصريح الاصطياد","de":"قبل أن يرفع أحدهم شبكة اليعاسيب، يسأل الكبار أولاً: كم عدداً، وإلى أين. بطاقة صغيرة واحدة ترسم خطاً لطيفاً بين الفضول المتحمس والوعد الواجب حفظه."},"ICON-1603":{"nm":"علبة الطعم","de":"عند فتح الغطاء تفوح رائحة الفجر الباردة ذات النكهة السمكية. ربما ما يستدعي السمك ليس الطعم، بل قلب يعرف كيف ينتظر بهدوء حتى يرتجف العوّامة."},"ICON-1604":{"nm":"علبة العوامات","de":"خزانة صغيرة تنام فيها عوامات ملونة، خانة تلو الأخرى. بعضها صباح بحيرة هادئة، وبعضها ظهيرة تيار عنيف. لكل تعبير من تعابير الماء، يُطوى الرفيق المناسب بعناية."},"ICON-1605":{"nm":"بكرة خيط الصنارة","de":"لا تلفّ الخيط المرتخي حول أصابعك. أعده بترتيب على هذه الأداة المستديرة، فتنحل التشابكات خلسةً. يشبه هذا لمسة تُعيد تنظيم يوم قد ترهّل."},"ICON-1606":{"nm":"أداة نزع الصنارة","de":"فقط من لسعته محاولة نزع صنارة عالقة بيده المجردة يتعرف على هذه الأداة. طريق أقل ألماً، لكائن صغير ولأطراف أصابعي معاً. المراعاة تبدأ دائماً من هذه التفاصيل الصغيرة."},"ICON-1607":{"nm":"غطاء مجرفة المحار","de":"طبقة واحدة تلف نصل المجرفة المنتشلة للتو من الشاطئ الطيني. كي لا يقرض الطين والماء المالح حدّها، تُدسّ راحة رقيقة وناعمة بين البحر والأداة."},"ICON-1608":{"nm":"بطاقة جدول المد والجزر","de":"متى يأتي الماء ومتى ينحسر، تخبرك بطاقة بحجم راحة اليد بهدوء. تقويم صغير دوّن فيه إنسان الوعد القديم الذي تبادله القمر والبحر."},"ICON-1609":{"nm":"فرشاة تنظيف حوض السمك","de":"امسح برفق الطحالب الخضراء العالقة على جدار الزجاج، فيتسلل الضوء من جديد إلى العالم الصغير تحت الماء. إسعاد يوم أحدهم عادة ما يجري بهذا الهدوء."},"ICON-1610":{"nm":"شريحة حرارة الحوض","de":"يومض رقم واحد، وحين يستقر عند الدرجة المناسبة، تطمئن الأسماك أخيراً. دفء خانة واحدة، لا باردة جداً ولا ساخنة جداً. الرعاية تصل حتى إلى ما لا يُرى."},"ICON-1611":{"nm":"أنبوب مراقبة الأحياء البحرية","de":"ضيف صغير يمكث قليلاً داخل الأنبوب الشفاف. عدّ زعنفته الظهرية بهدوء، ثم أعده إلى البحر. المراقبة ليست امتلاكاً، بل استعارة لبرهة قصيرة."},"ICON-1612":{"nm":"فرشاة الحفريات","de":"ما يوقظ نسيج الحجر النائم منذ عشرات الملايين من السنين ليس مطرقة، بل طرف فرشاة ناعم. أمام زمن قد يتفتت إن استعجلت، يصبح الحذر أرقى أشكال الاحترام."},"ICON-1613":{"nm":"غطاء فرشاة التنقيب","de":"حين يجف طرف الفرشاة تماماً، لا يسقط التراب بنعومة. غطاء صغير واحد يحافظ على رطوبة أنفاس الفرشاة. يد تعتني بأدواتها هي التي تخطو الخطوة الأولى في التنقيب."},"ICON-1614":{"nm":"لوح عينات الطبقات الأرضية","de":"في شبر من التراب تتراكم مئات السنين طبقة فوق طبقة. اغرفها بهدوء على هذا اللوح، فتنكشف أنماط الزمن الخفية شيئاً فشيئاً وترسم خطوطها ببطء."},"ICON-1615":{"nm":"صينية شظايا العظام","de":"رتّب القطع المتناثرة خانة خانة، فتتحسس حياة كانت مبعثرة في الريح طريقها ببطء نحو مكانها. الترميم هو استعادة النظام المفقود برفق وحنان."},"ICON-1616":{"nm":"شريط الترميم","de":"خيط رفيع واحد يصل الموضع المكسور. لا يخفي الندبة، بل يعانقها بحنان ويثبتها. يثبت بهدوء أن ما تحطم يمكن أن يعود كاملاً من جديد."},"ICON-1617":{"nm":"غطاء لافتة العرض","de":"صفيحة واحدة تغطي برفق البطاقة خلف الزجاج كي لا تبهت. تحمل أمنية أن تبقى تلك الجملة القصيرة، عمّن عاش وأين، واضحة للقراءة حتى بعد زمن بعيد."},"ICON-1618":{"nm":"بطاقة المستودع","de":"غرفة عميقة تنام فيها كنوز لم تخطُ يوماً إلى الضوء. كل ما بداخلها يحمل بطاقة اسم صغيرة، كي لا يُنسى حتى وإن لم يقف في مكان مضيء."},"ICON-1619":{"nm":"مظروف التبرع للمتحف","de":"يسلّم أحدهم بصمت ما جمعه طوال حياته. ما يحمله هذا المظروف ليس أشياء، بل قلباً احتضنه طويلاً. المشاركة تصبح أطول معرض يبقى، تُضيء أحداً ما."},"ICON-1620":{"nm":"شريحة رقم العينة","de":"في نفس المكان الذي جُمع فيه، يُخصص بهدوء رقم صغير. متى، وأين، التقيته للمرة الأولى. فالاكتشاف غير المدوّن سرعان ما يتبدد كضباب الصباح."},"ICON-1621":{"nm":"زجاجة شظية النيزك","de":"شظية سقطت وهي تشق سماء الليل، حُبست داخل زجاجة. شعاع ضوء واحد كان يخفت قبل أن تتمكن حتى من تمني أمنية، يتلألأ الآن من جديد بهدوء بين يديك."},"ICON-1622":{"nm":"خيط جرس الرياح الصدفي","de":"تُنظّم أصداف جُمعت واحدة تلو الأخرى على الشاطئ في خيط وتُعلّق تحت الشرفة. كلما مرّ النسيم، تصدر رنيناً خفيفاً، فيتبع بحر ذلك الصيف طريقه بهدوء إلى داخل البيت."},"ICON-1623":{"nm":"قطرة ندى قزحية","de":"قطرة واحدة تتجمع في طرف ورقة بعد توقف المطر. في ذلك الشكل المستدير، تنحصر السماء بأكملها والألوان السبعة معاً. ثمة أوقات تحتضن فيها أصغر الأشياء أوسع المشاهد."},"ICON-1624":{"nm":"زجاجة جمع الضباب","de":"أحضرت زجاجة مليئة بضباب الفجر من سفح الجبل. أمسكها فتشعر بالبرودة والبياض الضبابي. طمع صغير وحنون، أن تُبقي بجانبك للحظة ما لا يمكن الإمساك به."},"ICON-1625":{"nm":"كوب جامع الندى","de":"كوب صغير يجمع الندى الذي تراكمته أوراق العشب قطرة قطرة طوال الليل. لا يكاد يملأ رشفة واحدة، لكن أصفى وأنقى جزء من الصباح يركد فيه بسكون."},"ICON-1626":{"nm":"دبوس شريط النسيم","de":"شريط عُقد على شكل الأثر الذي تركه النسيم وهو يمر. ثبّته في شعرك، وستتبعك نسمة رقيقة مع كل خطوة. خفة يوم ربيعي، عُقدت بهدوء في دبوس واحد."},"ICON-1627":{"nm":"كبسولة صوت الأمواج","de":"قرّبها من أذنك بهدوء، فتتدفق أمواج البحر البعيد. كأن أحدهم ختم بعناية في كبسولة صغيرة ذلك الصوت الذي كنا نحتفظ به في صدفة البحر أيام الطفولة."},"ICON-1628":{"nm":"شظية نجمة الرمل","de":"أمسك حفنة من رمل الشاطئ ليلاً، وستجد فتات نجوم مختلطاً فيها يتلألأ. هل سقطت من السماء أم طحنتها الأمواج بنعومة؟ لا أحد يكلف نفسه عناء السؤال."},"ICON-1629":{"nm":"شريحة سجل طقس الجزيرة","de":"سماء الجزيرة تغير مزاجها عدة مرات في اليوم. دوّن الصفاء والضباب والزخات بعناية في شريحة صغيرة، فتستطيع أن تفتح سماء الأمس من جديد اليوم."},"ICON-1630":{"nm":"طقم درج المنحدر","de":"درجة، ثم أخرى، لصعود المنحدر الشديد ونزوله. رتّب القطع المتناثرة معاً، فيصبح حتى المنحدر ممشى هادئاً. شقّ الطريق يعني أن تضع سلفاً الخطوة التالية لشخص آخر."},"ICON-1631":{"nm":"لفافة نمط الطريق الترابي","de":"لفافة أخذت نسيج طريق ترابي ناعم كما هو. افردها بصوت خفيف، ويفترش تحت قدميك درب ريفي يجعلك ترغب في المشي حافياً."},"ICON-1632":{"nm":"شريحة نمط الطريق الحجري","de":"نقش الأحجار التي كانت تُبلّط الأزقة القديمة محفوظ كاملاً داخل شريحة صغيرة. مع كل خطوة، طقطقة خفيفة، تنبعث خطى قرية عتيقة من جديد عند أطراف قدميك."},"ICON-1633":{"nm":"قطعة سياج الشاطئ","de":"قطعة واحدة من سياج منخفض نُصب على الرمال كي لا تتخطاه الأمواج. حارس حدود صغير وصامت، يقف راسماً خطاً لطيفاً بين البحر والرمل."},"ICON-1634":{"nm":"رقعة ترميم العشب","de":"قطعة خضراء توضع برفق فوق بقعة تعرّت من الدوس. خلال أيام قليلة تتشابك الأعشاب أيدياً وتملأ الفراغ. الطبيعة تعرف دائماً كيف تشفي نفسها بنفسها."},"ICON-1635":{"nm":"وتد علامة مجرى الماء","de":"وتد يُشير مسبقاً إلى المسار الذي سيسلكه الماء. كي لا يتوه ماء المطر في طريقه، يقف علم صغير مغروس في الأرض بصمت حتى في الأيام الممطرة."},"ICON-1636":{"nm":"قطعة جسر صغير","de":"قطعة واحدة من جسر صغير يصل ضفتي الجدول. بين هذه الضفة وتلك، يبدأ الوعد بإمكانية العبور في أي وقت بهدوء من هذه القطعة الصغيرة الواحدة."},"ICON-1637":{"nm":"غطاء درابزين نقطة المشاهدة","de":"في أعلى نقطة في الجزيرة، قطعة تشطيب واحدة تلف طرف ذلك الدرابزين. تسند بهدوء وتحمي المكان الذي تلمسه أيدي المجتمعين للنظر بعيداً أكثر من غيره."},"ICON-1638":{"nm":"قاعدة موقد المخيم","de":"قبل أن يوضع الحطب، مكان يسند الجمر كي لا يتناثر. فوقه، تحترق دافئة لأزمنة طويلة ليالٍ من الحديث الهامس والنظر إلى النجوم."},"ICON-1639":{"nm":"لفافة عينة ورق الحائط","de":"مزاج الغرفة يبدأ من جدار واحد. فتح لفافة صغيرة لاختيار لون هو رسم هادئ مسبق، لنوع الأيام التي تودّ أن تعيشها من الآن فصاعداً."},"ICON-1640":{"nm":"شريحة عينة الأرضية","de":"تحسّس أولاً بأطراف أصابعك ملمس الأرضية التي ستلامسها قدماك الحافيتان. دافئة أم باردة؟ على هذه الشريحة الصغيرة الواحدة يتوقف بهدوء دفء الأيام التي ستعيشها لاحقاً."},"ICON-1641":{"nm":"طقم خطاف السقف","de":"في لحظة تعليق خطاف واحد على العارضة، يتحول السقف الفارغ إلى مكان ينتظر أحداً. جرس رياح أم أصيص زهور؟ هذا الخطاف الحديدي الصغير يتحمل الوزن، لكن قلب الساكن هو من يقرر ما سيُعلَّق."},"ICON-1642":{"nm":"طبقة تظليل النوافذ","de":"ضوء الظهيرة صريح أكثر من اللازم، فتُكسى النافذة بغشاء رقيق واحد. تدخل الشمس كما هي، لكن الحواف تلين، ويصبح كل شيء في الغرفة أليفاً بلون المشمش. ليس حجباً، بل جعل الضوء ينتشر بحنان."},"ICON-1643":{"nm":"غطاء جرس الباب","de":"قائلاً إن حتى الجرس الذي يضغطه الضيف يحتاج ملابس، ألبسه أحدهم غطاءً مستديراً. يصد المطر ويصد الغبار، وقبل كل شيء هو الفم الصغير المستدير الأول الذي يقدم التحية: \"يعيش أحد هنا.\""},"ICON-1644":{"nm":"حامل سجل الزوار","de":"حامل نُصب ليكتب كل قادم اسمه ثم يمضي. قبل أن يجف الحبر، يسيل من طرف القلم سطر من التحية. حين تتراكم خطى الزائرين سطراً سطراً، يصبح الدفتر الفارغ أثخن ألبومات هذا البيت دون أن يُشعر أحد."},"ICON-1645":{"nm":"دبوس تثبيت الأثاث","de":"مكان المكتب الذي ترددت طويلاً في تحريكه، يحسمه دبوس واحد يُغرس في الأرض. مسمار صغير يمسك بهدوء بقدمي الأثاث. تهز الأرضية الخشبية رأسها بصمت، مقرّة أن المكان إن استقر مرة، صار محبوباً."},"ICON-1646":{"nm":"إطار لصيقة التخزين","de":"ما الذي يحويه الدرج وأين، لا يستطيع الدرج قوله أبداً. لذا أُدخلت بطاقة اسم في إطار مربع لتتكلم نيابة عنه. في لحظة استقرار لصيقة واحدة، تستعيد الخانات المشوشة أسماءها وتهدأ."},"ICON-1647":{"nm":"عود معطر الغرفة","de":"العطر المبلل لطرف العود ينتشر ببطء إلى الأعلى. لافندر تارة، ومرج بعد المطر تارة أخرى. حين يبدّل خيط الرائحة الخفي هواء الغرفة، ينزلق تعب اليوم عن كتفي العائد إلى بيته."},"ICON-1648":{"nm":"مشبك كيس البذور","de":"البذور المشتراة في الربيع ولم تُزرع بعد، تُثبّت بإحكام بمشبك مع كيسها. فإن تسرّبت حبة واحدة، ينقص الموسم القادم سطراً. في هذا المشبك الصغير، تنام حديقة العام المقبل بأكملها."},"ICON-1649":{"nm":"صينية الشتلات","de":"امتلئ كل خانة بالتراب لتصنع أول غرفة لبرعم فتيّ. حياة واحدة في كل حفرة، طلاب مستجدون ينمون مصطفين في صف. انظر إليها فترى صباحاً من الخضرة يجمعها للحضور، صباح يبدأ من جديد كل يوم فوق الصينية."},"ICON-1650":{"nm":"دبوس علامة الري","de":"\"أنا عطشان.\" بما أن الأصيص لا يستطيع الكلام، تُغرس لافتة صغيرة في التراب ترسل الإشارة نيابة عنه. حين يتغير اللون، يحين وقت السقي. أصغر مترجم بين النبات والإنسان يتسع بأكمله في هذا العود بحجم شبر."},"ICON-1651":{"nm":"رباط دعامة النبات","de":"ساق تنمو قد تترنح تحت وزنها، فتُربط برفق بخيط ناعم إلى دعامة. إن شُدّ كثيراً اختنقت، وإن أُرخي كثيراً سقطت، فاليد الرابطة تحتاج دفئاً بالقدر المناسب. حتى النمو يحتاج رفيقاً بجانبه."},"ICON-1652":{"nm":"شبكة صد الحشرات","de":"الأفواه الصغيرة التي تستهدف الأوراق الغضة، تصدها بهدوء شبكة منسوجة بعناية. تسمح للريح والضوء بالمرور وتحرف فقط ما يؤذي، حارس بوابة غير مرئي. سلام الحديقة مدين لرعاية هذه العيون الشبكية الضيقة."},"ICON-1653":{"nm":"بطاقة قياس ضوء الشمس","de":"كم من الشمس يصل هنا؟ تُنصب بطاقة واحدة في الحوض وتُسأل بهدوء. بقدر ما يغمق لونها، بقدر ما نالت من الضوء اليوم. هذه الورقة الصغيرة تفرز مكاناً للنبتة التي تحب الشمس وأخرى تفضل الظل."},"ICON-1654":{"nm":"شريط اختبار حموضة التربة","de":"مسّ شريط الاختبار بالتراب، ومن الوردي إلى الأزرق، تبوح الأرض بمكنوناتها لوناً. حيث لا حموضة زائدة ولا قلوية زائدة، تتنفس الجذور بأريحية أكبر. مشاعر التراب الخفية تُقرأ خانة تلو الأخرى."},"ICON-1655":{"nm":"لصيقة سلة الحصاد","de":"هل ما قُطف اليوم خس أم طماطم كرزية؟ تُعلَّق بطاقة اسم على كل سلة. في صباح حصاد تفوح فيه رائحة التراب والخضرة، لحظة تعليق اللصيقة، تصبح تلك السلة أول علامة على الطريق إلى المائدة."},"ICON-1656":{"nm":"جرة حفظ البذور","de":"تُدسّ البذور المجموعة هذا العام في جرة زجاجية وتُرسل إلى الربيع القادم. أغلق الغطاء ويتوقف الزمن قليلاً، بينما تنتظر الحبيبات الصغيرة دورها في الظلام. إنها جرة أشبه برسالة تُرسل عبر فصل كامل."},"ICON-1657":{"nm":"شريط التطعيم","de":"ضع غصناً مقطوعاً وغصناً جديداً وجهاً لوجه، ولفهما بالشريط، فيصبحان تدريجياً جسداً واحداً. النسغ يسري من جديد في موضع القطع، والجرح يشفى ببطء. الوصل، في النهاية، هو تقبل نسيج الآخر."},"ICON-1658":{"nm":"غطاء مقص التقليم","de":"تُلبس قبعة صغيرة طرف المقص الحاد. بينما ترتاح اليد التي خفّفت الأغصان، يبقى النصل حاداً واليد سالمة. قائلة إن حتى الأداة التي أنهت عملها تحتاج بيجامة، تُنيم الحديقة أدواتها بعناية."},"ICON-1659":{"nm":"علبة فرز بذور الزهور","de":"بلسم وشقائق ندى وزهرة الرابعة عصراً، بذور تختلف اسماً ولوناً، لكل منها غرفتها في خانة منفصلة. فلو اختلطت، لن تعرف مع الربيع من هو من. الفواصل الصغيرة داخل العلبة ترسم سلفاً مخطط حديقة لم تتفتح بعد."},"ICON-1660":{"nm":"صينية عجلات الأصيص","de":"ركّب أربع عجلات، وحتى الأصيص الثقيل ينطلق ليتبع أشعة الشمس. نافذة شرقية في الصباح، ظل عند الظهيرة. الخضرة التي كانت ثابتة بحكم وزنها تتدحرج، لاهثة وراء الضوء طوال اليوم بحثاً عن أفضل مكان."},"ICON-1661":{"nm":"رباط توجيه المتسلقات","de":"محلاق يتحسس الهواء الفارغ، حائراً إلى أين يذهب، فيقوده الرباط بهدوء نحو الطريق الصحيح. إلى الأعلى، وأعلى فأعلى. امنحه مكاناً يتشبث به، وسيمسك النبات بتلك اليد بعجب. حتى النمو يحتاج دليلاً واحداً."},"ICON-1662":{"nm":"حامل بطاقة لغة الزهور","de":"البطاقة الموضوعة بجانب الزهرة تحمل الكلمات التي تقدمها تلك الزهرة. الهورتنسيا تقول الإخلاص، والأقحوان يقول البراءة. كي يصبح السير في الحوض نزهة لقراءة الرسائل، يستعير حامل صغير بهدوء صوت الزهرة الصامتة."},"ICON-1663":{"nm":"غطاء لافتة الحديقة","de":"خشية أن يمحو المطر والريح الكتابة، تُلبس لافتة الحديقة قبعة شفافة. \"طماطم هنا\"، \"ريحان هنا\". الأسماء التي كادت تتلاشى تبقى واضحة، فلا تنسى الحديقة أفراد أسرتها ولو بعد مرور عام."},"ICON-1664":{"nm":"ملعقة السماد","de":"عند إضافة الغذاء إلى التراب، يحرق الطمع الجذور بدلاً من أن يفيدها. لذا ملعقة واحدة، لا أكثر ولا أقل. الملعقة الصغيرة تغرف الكمية المناسبة وتذكّرك: القلب الذي يُحسن التربية يأتي دوماً من أطراف أصابع تعرف الاعتدال."},"ICON-1665":{"nm":"فوهة الرذاذ","de":"أدر الفوهة، فيتناثر تيار الماء كالضباب الهابط. الورقة الغضة التي كانت تُجرح بتيار عنيف، ترفع رأسها برقة تحت قطرات أشبه بالندى. الماء نفسه يصبح تحية مختلفة تماماً بحسب طريقة منحه."},"ICON-1666":{"nm":"كوب قياس العلف","de":"كوب، وكوبان. تقيس وجبة صديقك بعناية لا بالتخمين. إن زادت تركها، وإن نقصت حزن، فتحسب الكمية الملائمة تماماً. الحب أحياناً يأتي بهيئة القياس الدقيق كهذا."},"ICON-1667":{"nm":"غطاء فرشاة تساقط الشعر","de":"في موسم تساقط الشعر، يلف غطاء بعناية الزغب الناعم المتشابك في الفرشاة. غطّ الفرشاة بعد الاستخدام، وسيبدأ الغد أيضاً نظيفاً ناعماً. لمعان أفراد العائلة المشتركين في السكن ينمو بهدوء من هذا الترتيب الصغير."},"ICON-1668":{"nm":"غطاء مقص الأظافر","de":"يُركَّب غطاء صغير على طرف مقص الأظافر الحاد، كي لا يخدش هذا الأداة المنتهية من عملها الأشياء الأخرى في الدرج. بعد انتهاء وقت العناية، يكتمل دوران الرعاية بتهدئة الأداة وإنامتها."},"ICON-1669":{"nm":"زينة الطوق","de":"علّق شريحة براقة واحدة على الطوق، فيصبح درب النزهة المعتاد أكثر تميزاً قليلاً. زينة صغيرة تتلألأ في الشمس. قد لا تكون براقة، لكنها علامة كافية أن هذا الصغير فرد محبوب جداً من عائلة أحدهم."},"ICON-1670":{"nm":"بطاقة صحة الحيوان الأليف","de":"هل أكل جيداً اليوم؟ هل يؤلمه شيء؟ تدوّن سطراً في اليوم عن يوم رفيقك في السكن على البطاقة. حين تُسجَّل حالة فرد العائلة الذي لا يتكلم بالكتابة، ينمو قلب الرعاية أيضاً دقة وثباتاً."},"ICON-1671":{"nm":"غطاء وسادة النوم","de":"تُلبس وسادة النوم ثوباً جديداً ناعماً. انزع القماش الذي تآكل من التمرغ والاحتكاك، وستفوح رائحة زغب مجفف بالشمس. الاعتناء بأكثر مكان يُستلقى عليه هو عناية يومية لمن يعيش معك."},"ICON-1672":{"nm":"دبابيس السياج الصغير","de":"اغرس دبابيس صغيرة على حافة الحوض لتقيم سياجاً منخفضاً. ليس تهديداً بـ\"لا تتخط\"، بل حداً لطيفاً يقول إن هذا حتى هنا مكان الزهور. لا بد من خط يُحفظ كي تنمو الأشياء بأمان داخله."},"ICON-1673":{"nm":"علبة حلوى التقرب","de":"حتى الصغير الخجول تنتصب أذناه عند صوت اهتزاز هذه العلبة. بداخلها حفنة من الحلوى تفتح القلب. لأن الوعود الصغيرة أسرع من الكلام في التقريب، يتقدم صوت الطقطقة أولاً."},"ICON-1674":{"nm":"بطاقة سجل النزهة","de":"أي طريق اليوم وكم مسافة؟ تعقد السجل على البطاقة كعقدة. حين تتجمع الخطى تصبح خريطة، وحين تتجمع الخرائط تصبح ذكرى. كل يوم سِرتما فيه معاً يتراكم بعناية على هذه البطاقة الصغيرة."},"ICON-1675":{"nm":"طبق علف الطيور","de":"ضع الطبق على حافة النافذة وانثر حبات دخن قليلة، فيتقاطر ضيوف مجهولون تباعاً. صوت النقر الخفيف، وخفقان الأجنحة. مائدة صغيرة، تجلب حفنة واحدة مُقدَّمة حفلاً موسيقياً صغيراً كل صباح."},"ICON-1676":{"nm":"علبة مراقبة السنجاب","de":"داخل العلبة الشفافة تلتقي عيني سنجاب مستديرتين. خدّان ممتلئان بالبلوط وهو يميل رأسه، يا له من منظر. على وعد بالنظر لحظة ثم إطلاق سراحه سريعاً، تتبادل تحية عابرة مع قطعة صغيرة من البرية."},"ICON-1677":{"nm":"قالب جبسي لأثر القدم","de":"تسكب جصاً ليّناً لتصنع قالباً لأثر قدم صغير. أثناء انتظار التصلب، يتوقف زمن الفناء قليلاً أيضاً. ذلك الختم الصغير للقدم، المحكوم عليه بالزوال مع النمو، يرفعه القالب الأبيض كأنه أبدي ويضعه بهدوء بين يديك."},"ICON-1678":{"nm":"غطاء عدسة المنظار الليلي","de":"يُغلق غطاء صغير طرف العدسة التي تتأمل الليل. كي تنتظر الزجاجة التي رأت النجوم والأعشاش الليلة القادمة دون ذرة غبار واحدة. حتى العين التي ترى الظلام بوضوح تحتاج فاصلة راحة واحدة خلال النهار."},"ICON-1679":{"nm":"علامة حماية العش","de":"عند اكتشاف عش بين الأغصان، بدلاً من الاقتراب، تُنصب علامة. \"عائلة طيور تعيش هنا، بهدوء رجاءً.\" المراقبة دون التطفل، تلك الخطوة الحانية إلى الوراء هي ما يجعل العش في أمان أكبر."},"ICON-1680":{"nm":"شريحة تسجيل أصوات الحيوانات","de":"أغنية الأدغال، وزقزقة تحت الشرفة، وصوت حشرات الليل، لا تُحبس في الشريحة بل تُستعار قليلاً. صندوق صوت صغير، إذا أُعيد تشغيله، يحيي حتى هواء تلك اللحظة. كي لا يختفي كل ما سُمع."},"ICON-1681":{"nm":"غطاء منظار المراقبة","de":"قبل أن يحلّق طائر واحد بلحظة، تحبس الغابة أنفاسها للحظة. في تلك السكينة، قطعة قماش واحدة تغطي العدسة تحمي وضوح البعيد، دون أن تلمسه بصمة إصبع واحدة."},"ICON-1682":{"nm":"حزام كاميرا درب الغابة","de":"مع كل صعود لدرب الغابة الشديد الانحدار، تلمس الكاميرا صدرك بلطف متكرر. ينبض القلب وتُصدر الغالق صوتها بنفس الإيقاع، وهذا الحزام الواحد يمسك تلك اللحظات بثبات أمام صدرك."},"ICON-1683":{"nm":"بطاقة الإرشاد الطبيعي","de":"حتى نبتة عشب واحدة لها اسم، تخبرك البطاقة بهدوء. حين يُمنح ما كنت تمر به دون معرفة اسماً، يبدأ درب الجبل فجأة بالازدحام بوجوه مألوفة ودودة."},"ICON-1684":{"nm":"رقعة ترميم الشراع","de":"حتى القماش الذي يواجه الريح بكل كيانه تبقى فيه ندوب. برقعة صغيرة واحدة توضع برفق فوق الموضع الممزق، يستعيد الشراع أهليته لاحتضان البحر البعيد من جديد."},"ICON-1685":{"nm":"لوح تدريب العقد","de":"إلى الأعلى، ثم الأسفل، ولفة أخرى، الترتيب الذي حفظته اليد يصبح عقدة. في ليلة تقرع فيها العاصفة سطح السفينة، ذلك الإجراء الواحد يربط الإنسان والسفينة معاً ككيان واحد."},"ICON-1686":{"nm":"غطاء سلسلة المرساة","de":"لا تستهن بهذه القبعة الصغيرة التي تُلبس طرف السلسلة الحديدية. الصدأ ينمو خفية بالداخل، فغطاء واحد يقف في وجه ريح البحر يطيل بهدوء عمر المرساة."},"ICON-1687":{"nm":"راية علامة المسار","de":"في يوم يزداد فيه الضباب كثافة حتى يمحو ما أمامك، تنطق راية واحدة بالطريق بدلاً عنك. نقطة لون واحدة ترفرف في الريح تُرخي أخيراً كتفي ربان تائه متصلبتين."},"ICON-1688":{"nm":"حلقة مفاتيح المقصورة","de":"فوق بحر متمايل، تتدلى حلقة صغيرة واحدة على باب المقصورة الضيق. ما دام المفتاح يحفظ مكانه، فإن غرفة للعودة إليها لن تُغلق أبداً دونك."},"ICON-1689":{"nm":"علبة خريطة مقاومة للماء","de":"تحت المطر، تمحو الخريطة الورقية طريقها أولاً. بينما تصمد ورقة واحدة جافة داخل العلبة الشفافة، حتى الرحلة المبللة لا تفقد اتجاهها في النهاية."},"ICON-1690":{"nm":"فتيلة مصباح السفينة","de":"الزيت الذي امتصته الفتيلة ببطء يتفتح أخيراً لهباً. نقطة ضوء واحدة على السطح، وعند ذلك الارتعاش الصغير، تقترب المسافة الشاسعة لبحر الليل قليلاً."},"ICON-1691":{"nm":"قماش إشارة الاستغاثة","de":"على مسافة لا يبلغها الصوت، تسافر اليد التي تلوّح بقماش أحمر عالياً أبعد من الكلمات. هذا النسيج الواحد يشق الريح، صائحاً نيابة عنك أن أحداً هنا حيّ."},"ICON-1692":{"nm":"دبوس اتجاه ريح البحر","de":"من يعرف من أين تهب الريح يحدد المسار. على الاتجاه الواحد الذي يشير إليه دبوس صغير بهدوء، يتكئ قليلاً مصير إبحار هذا اليوم كله."},"ICON-1693":{"nm":"غطاء المجرفة القابلة للطي","de":"اطوِ النصل وغطّه، وحتى المجرفة الدؤوبة تلتقط أنفاسها قليلاً. آخر ما تفعله اليد التي انتهت من نبش كل التراب هو العناية بحد الغد كي لا يكل."},"ICON-1694":{"nm":"علبة البوصلة الجيبية","de":"الإبرة تشير دائماً إلى الشمال دون ارتجاف، لكن ما يحمي تلك الإبرة هو علبة متينة. من ضلّ الطريق مرة، يحتضن اتجاهه بعناية أكبر."},"ICON-1695":{"nm":"شبكة تجفيف أواني المخيم","de":"علّق الأواني المغسولة في الشبكة لتجف تحت شمس الصباح. يوم المخيم يبدأ بصوت جفاف الماء، وهذا الأمر البسيط يملأ الخيمة بطمأنينة."},"ICON-1696":{"nm":"بطاقة إذن التخييم","de":"إذن بالمكوث ليلة في هذا الجبل. في لحظة استقرار ورقة واحدة بيدك، تصبح حتى الغابة الغريبة حليفتك للحظة وتستقبل خيمتك الصغيرة بهدوء."},"ICON-1697":{"nm":"رباط راية درب الاستكشاف","de":"اربط راية عند كل مفترق طرق، ولن يتبعثر طريق العودة في الظلام. علامة صغيرة واحدة تركها من سبقك تدفع بهدوء ظهر الخطى التي تتبعه."},"ICON-1698":{"nm":"علبة عود الثقاب المقاومة للماء","de":"يغرق عود الثقاب بقطرة واحدة ليصمت إلى الأبد. داخل علبة محكمة لا تدخلها قطرة ماء، تنتظر الشرارة جافة وساكنة، من أجل أبرد ليلة فقط."},"ICON-1699":{"nm":"مرشح مياه محمول","de":"حتى الماء العكر الذي يجعلك تتردد يصفو حين يمر عبر هذا المرشح. جهاز صغير يُنزل الشك قبل العطش، فالثقة بأن بإمكانك الشرب هي نفسها رشفة من السكينة."},"ICON-1700":{"nm":"حزمة بطانية الطوارئ","de":"مطوية، لا تكاد تتجاوز راحة اليد، ومفرودة، تصبح دفء شخص واحد. كي تخفّ وطأة كلمة \"طارئ\" قليلاً، تنتظر البطانية في زاوية من الحقيبة، مستعدة دوماً لتصبح دافئة."},"ICON-1701":{"nm":"سوار العلامة الليلية","de":"على درب جبلي غرق في الظلام، يشع معصمٌ واحد بضوء هادئ. ذلك الشريط الصغير الذي يُعلن مكان كل واحد، يربط السائرين معًا بخيطٍ رقيقٍ لا يُرى، بحنان."},"ICON-1702":{"nm":"ملصق خوذة عامل المنجم","de":"الملصق الملتصق على الخوذة هو بطاقة اسم أخرى لعامل المنجم. في النفق العميق حيث حتى الضوء ثمين، يتعرّف العامل على رفيقه بحفاوة من خلال تلك الصورة الصغيرة التي يلمع عليها ضوء المصباح."},"ICON-1703":{"nm":"دبوس علامة عرق الخام","de":"في المكان الذي عُثر فيه على عرق الخام، يُغرَز الدبوس بهدوء. نقطة واحدة تلمع وحيدة في الظلام تُخبر بلطف من يأتي بعده أن يبدأ الحفر من هنا."},"ICON-1704":{"nm":"مسطرة قياس الشروخ","de":"قياس الشق المتصدع في الجدار عملٌ بطيء وصبرٌ عنيد. هل اتسع بمقدار شبر منذ الأمس؟ الرقم الصغير الذي تُخبر به المسطرة يكشف الانهيار قبل أن يقع."},"ICON-1705":{"nm":"ورق نسخ نقوش الأثر","de":"يضع المرء ورقًا فوق النقش المحفور في الحجر وينقر الحبر برفق شديد. في اللحظة التي تنهض فيها لمسة يد من ألف عام في خطوط سوداء، يُجلس النسخ الزمن الغابر لوجهك للحظة."},"ICON-1706":{"nm":"علبة العملة القديمة","de":"هذه القطعة المعدنية الصغيرة، النائمة بأمان بعيدًا عن الصدأ، تحمل آخر صوتٍ لأمةٍ اندثرت. عصرٌ كاملٌ يسكن في عملةٍ واحدة، يشيخ ببطء داخل العلبة الشفافة."},"ICON-1707":{"nm":"حامل شظية الكريستال","de":"حتى الكريستالة التي تحبس الضوء في داخلها تحتاج إلى ما تستند إليه. في اللحظة التي تستقر فيها برفق على حامل صغير، ينشر الشيء الهش أخيرًا تألقه كاملًا."},"ICON-1708":{"nm":"قطعة خريطة الكهف","de":"الخريطة الممزقة لا تكشف إلا نصف سرها بمكر. حتى يوم العثور على القطعة الباقية، تُبقي هذه الورقة الواحدة بقية الدرب مخفيةً نصفها في مكانٍ ما داخل الكهف."},"ICON-1709":{"nm":"كلابة الهبوط بالحبل","de":"لتسليم جسدك نحو أسفل الجرف، عليك أولًا أن تثق بهذه الكلابة ثقةً كاملة. أن تُعلّق وزنك على قطعة واحدة من الفولاذ البارد - هكذا هي الثقة بطبيعتها، شيءٌ بهذا الثقل."},"ICON-1710":{"nm":"تصريح التنقيب","de":"ورقة واحدة يُختم عليها بوضوح إذن حفر الأرض. لإيقاظ ما هو مدفون، اطلب الإذن أولًا - التنقيب يُعلّم بهدوء أن البداية تكون بالأدب."},"ICON-1711":{"nm":"حقيبة كاسر الرياح","de":"عندما تُفرد وظهرك إلى الريح، ينفتح متر من السكون في وسط السهل العاصف. خلف هذه الطبقة الواحدة، تُحمى جذوة صغيرة، ويجد المتعب لحظة راحة."},"ICON-1712":{"nm":"غطاء نظارة العاصفة الرملية","de":"مهما اشتدت الرمال في دورانها، يجب أن تُحفظ الرؤية حتى النهاية. غطاء رقيق فوق النظارة يصبح شجاعة إبقاء العينين مفتوحتين والمضي قدمًا، حتى في قلب العاصفة."},"ICON-1713":{"nm":"صينية استقبال يوم المطر","de":"يتساقط ماء المطر قطرة قطرة من طرف حذاء الضيف القادم. صينية موضوعة بهدوء أمام المدخل تستقبل بصمتٍ ودفء أطرافَ القدمين الباردة المبللة."},"ICON-1714":{"nm":"بطاقة التبريد لموجة الحر","de":"بطاقة صغيرة تُلطّف حرارة منتصف النهار برفق. معلّقة على الحقيبة، تحتفظ ببرودتها، ثم تمنحك قبضة من الظل خلسة حين تبدأ قطرات العرق بالتكوّن."},"ICON-1715":{"nm":"حزام دفّاية اليد لموجة البرد","de":"حزامٌ دافئ يُلَفّ مرة واحدة حول الخصر. حين تنتشر حرارة دفّاية اليد صاعدةً على أسفل الظهر، يصبح حتى سهل منتصف الشتاء القارس مكانًا يُحتمل قليلًا."},"ICON-1716":{"nm":"كيس امتصاص الرطوبة","de":"الرطوبة تنخر الأشياء دون صوت. بينما يمتص كيسٌ صغير في الصندوق الرطوبة بصمت، تحافظ الأشياء العزيزة على شكلها جافة وسليمة."},"ICON-1717":{"nm":"غطاء الحذاء من الطين","de":"أحيانًا يجب أن يبقى الحذاء وحده نظيفًا حتى وأنت تمشي في الوحل. هذا الغطاء الرقيق الذي يصد الطين يجعل الخطوات العابرة لعتبة البيت أخف وطأة."},"ICON-1718":{"nm":"غطاء فانوس ضباب البحر","de":"حين يحاول ضباب البحر ابتلاع الفانوس بأكمله، يجمع هذا الغطاء بهدوء خيوط الضوء المتناثرة. حتى في الفجر الباهت، لا ينطفئ ضوء الميناء الواحد أبدًا."},"ICON-1719":{"nm":"دبوس التحذير من الصواعق","de":"حين تتدلى الغيوم السوداء منخفضة، يُقدّم دبوسٌ واحد التحذير أولًا. كلمة الانحناء قبل أن يضرب البرق - التواضع أمام الطبيعة يُتعلّم دائمًا بشكل أفضل مسبقًا."},"ICON-1720":{"nm":"فاصل كتاب الوصفات","de":"فاصل صغير يُدَسّ بين صفحات كتاب طبخ مفتوح. حين تتلمس عائدًا إلى السطر الذي أضعته أمام النار، تستيقظ نكهة يد الأم أيضًا على تلك الصفحة."},"ICON-1721":{"nm":"عصا توزيع التوابل","de":"كانت أمي تقول دائمًا \"قبضة واحدة\" فقط. رغم أن التقدير بالعين لا يمكن أن يكون دقيقًا، إلا أن لمسة يدها لم تتزعزع قط. وأنت تقيس الملح بهذه العصا، تدرك أن ما نضج أطول من أي مقياس لم يكن تخمينًا بل حبًا."},"ICON-1722":{"nm":"رباط غطاء التخمير","de":"هل تعلم أن الجرة تتنفس أيضًا؟ حين يحتضن هذا الرباط الغطاء بإحكام، يبدأ الداخل والخارج بالتحدث ببطء. فقط بعد مرور تلك الأيام غير المستعجلة، يكتسب الانتظار أخيرًا اسم النكهة."},"ICON-1723":{"nm":"شريحة ملصق التعتيق","de":"شريحة صغيرة كُتب عليها بعناية تاريخ التحضير. يتلاشى الخط بينما يزداد ما بداخلها عمقًا. أن تدوّنه وكأنك تنساه، ثم تخرجه فجأة يومًا ما - هكذا هو التعتيق، وعدٌ يُحفظ بهذه البساطة."},"ICON-1724":{"nm":"مصفاة المرق","de":"المرق الصافي لا يأتي إلا بعد التصفية، ثم التصفية مرة أخرى. راقب الشبكة تحتجز البقايا وتترك الجوهر وحده يتدفق، وستصلك عبر أطراف أصابعك حكمة المطبخ القديمة - أن العمق يتجمّع في المكان الذي أُخذ منه شيء."},"ICON-1725":{"nm":"قماش تخمير العجين","de":"يضع المرء قطعة قماش برفق فوق العجين. بينما تنتفخ الخميرة بدأب تحت ذلك الظلام، تتعلم للمرة الأولى حنان الأشياء التي تنمو بهدوء في أماكن لا تُرى."},"ICON-1726":{"nm":"دبوس تحضير المكونات","de":"دبوسٌ صغير يشق ألياف البصل الأخضر ويثبّت الثوم بإحكام. التحضير أشبه بتحية أولى تُقدَّم للمكونات، فكلما زادت العناية في التقليم، أضاء ضوء مائدة العشاء درجةً أكثر."},"ICON-1727":{"nm":"ملقط التقديم","de":"أين تُوضع اللقمة الأخيرة على الطبق - في النهاية، هذا الملقط هو من يقرر. في تلك اللحظة القصيرة التي تتردد فيها يد ماهرة نصف نبضة في الهواء، تصبح الوجبة لوحة فنية بهدوء."},"ICON-1728":{"nm":"غطاء صندوق الغداء الحافظ للحرارة","de":"كان صندوق الغداء المُستلم أمام بوابة المدرسة يجب أن يبقى دافئًا حتى يُقرع جرس الغداء. الحرارة المحبوسة داخل هذا الغطاء لا تبرد، بقدر عمق قلب من وقف أمام الموقد منذ الفجر."},"ICON-1729":{"nm":"بطاقة دعوة لتناول الطعام","de":"\"تعال نأكل عندنا يومًا ما.\" هل هناك كلمة أكثر حنانًا من هذه؟ بلا وعدٍ عظيم، فقط الجلوس على المائدة نفسها - أقدم دعوة يمكن أن تحملها الكورية موجودة في هذه البطاقة الواحدة."},"ICON-1730":{"nm":"شريحة حجز الطاولة","de":"تكتب اسمك وتحجز المكان. بينما تربط شريحة صغيرة طاولة فارغة باسم أحدهم لبرهة، يقترب الموعد المتفق عليه ببطء، كخطوات أقدام."},"ICON-1731":{"nm":"بطاقة تقييم التذوق","de":"وجوهٌ تأخذ لقمة واحدة وتمنح النجوم بجدية بالغة. السطر الصادق المدوّن بعناية على هذه البطاقة هو أدفأ توبيخ لجعل الطبق التالي ألذّ."},"ICON-1732":{"nm":"شريط شكر صندوق الغداء","de":"تلف شريطًا حول صندوق الغداء الفارغ تمامًا وتعيده. حتى من لم يستطع قول الشكر أبدًا، يربط في هذه العقدة على الأقل، القلبَ الذي عجز عن التعبير عنه."},"ICON-1733":{"nm":"بطاقة تنبيه الحساسية","de":"هذه البطاقة الصغيرة الواحدة تحمي مائدة أحدهم بصمت. أن تُوضح بدقة ما بداخل الطعام هو اسم آخر للضيافة - عناية تصل حتى إلى ما لا يُرى."},"ICON-1734":{"nm":"ملعقة ذكرى الطعم","de":"تلك النكهة التي بقيت طويلًا على طرف اللسان كانت، في الحقيقة، مشهد ذلك اليوم. حين تحملك ملعقة واحدة في لحظة إلى مطبخ الطفولة، يبدو أن الذاكرة شيءٌ يغرفه القلب لا المعدة."},"ICON-1735":{"nm":"قطعة قائمة اليوم","de":"ماذا نأكل اليوم؟ أمام أصعب سؤال في العالم، نخسر في كل مرة. اقلب هذه القطعة واترك القائمة للقدر، وسيصبح قلبك، على غير توقع، خفيفًا وسعيدًا."},"ICON-1736":{"nm":"جرس المائدة المشتركة","de":"اقرع الجرس مرة واحدة، وتتجمع العائلة المتفرقة في غرفها في مكان واحد. ذلك الجرس فوق المائدة المستديرة هو أعذب ترجمة لكلمات \"جاهز، تعال بسرعة.\""},"ICON-1737":{"nm":"بطاقة ترتيب الحلوى","de":"الحلويات تأتي دائمًا في النهاية. هذا الوعد الذي لا أحد يعرف من وضعه، تحفظه هذه البطاقة بدلًا عنه. مضيفٌ صغير وحنون للمائدة، يدّخر ذروة الشهية للقمة واحدة من الحلوى."},"ICON-1738":{"nm":"قطعة المساومة","de":"في قلب السوق، تتصادم بحنان عبارتا \"خفّض السعر قليلًا\" و\"أنا أخسر أصلًا\". هذه القطعة هي إيصال زبونٍ قديم، حيث تنتهي المساومة، في النهاية، بالضحك."},"ICON-1739":{"nm":"دبوس فحص المخزون","de":"تمسح رفوف المستودع بهدوء، تجد الفراغات، وتغرز دبوسًا. أن تعرف ما تبقى وما نفد - عمل إدارة المنزل الكبير يبدأ دائمًا من هذا الفحص الصغير."},"ICON-1740":{"nm":"فرشاة تنظيف الرف","de":"في مساء انتهاء السوق، يعمّ المتجر صوت الفرشاة الخفيض وهي تكنس الرف الفارغ. في أطراف الأصابع التي تمسح مكانًا سيُملأ غدًا مجددًا، يعلق اجتهاد يختم اليوم بعناية."},"ICON-1741":{"nm":"بطاقة توصية اليوم","de":"\"هذا جيد اليوم.\" بطاقة يمدّها صاحب المتجر خلسة. في تلك التوصية التي تدفع بلطف كتف الزبون المتردد فيما يختار، تكمن كرامة يوم كامل بأناقة."},"ICON-1742":{"nm":"حافظة أختام الزبون الدائم","de":"املأ عشرة وواحدة مجانًا. هذه الحافظة، بمربعات أختامها التي تمتلئ شيئًا فشيئًا، هي وجهٌ آخر لكلمة \"زبون دائم\"، لأن التردد كثيرًا يعني، في النهاية، أنك تحب المكان."},"ICON-1743":{"nm":"مشبك سجل التبادل","de":"مشبك يجمع ويحفظ سجلات الأشياء المُستبدلة والمُعادة. كلما زاد التبادل، ازداد السجل سماكة، وبتلك السماكة تزداد الثقة المبنية مع الجيران سُمكًا أيضًا."},"ICON-1744":{"nm":"بطاقة نفاد البيع","de":"في اللحظة التي تُثبَّت فيها هذه البطاقة على القطعة الأخيرة، يمتلئ القلب بغرابة. إنه وداعٌ قصير، أشبه بـ\"إلى اللقاء\"، لشيءٍ راحلٍ إلى مائدة أحدهم، إلى ركن ما من غرفة."},"ICON-1745":{"nm":"سلة المنتج المحجوز","de":"سلة تحمل بطاقة اسمك تحتفظ بمكان واحد على الرف. ذلك المكان المحجوز مسبقًا يُخبرك بهدوء، وأنت داخل، \"كنت أنتظرك طوال هذا الوقت.\""},"ICON-1746":{"nm":"بساط منضدة التغليف","de":"البساط الممدود فوق منضدة التغليف مسرحٌ لأيدٍ مشغولة. في تلك اللحظة القصيرة التي تُطوى فيها الورقة ويُربط الخيط بعناية، ينزلق شيء عادي متحولًا إلى هدية لأحدهم."},"ICON-1747":{"nm":"ورقة موعد الزيارة","de":"\"سأمر غدًا.\" ورقة كُتب عليها سطرٌ ودُسّت في شق الباب. حتى حين تفوت رؤية بعضكما البعض، يركب الوعد على ورقة واحدة، ليصل قبل الشخص وينتظر بهدوء."},"ICON-1748":{"nm":"سلة هدية الجيران","de":"السلة الممرّرة فوق الجدار تأتي دائمًا مع عذر \"أعددتُ أكثر من اللازم قليلًا\". هكذا يعبر الدفء الكوري إلى هذا الجانب، متظاهرًا باللامبالاة تحت ستار الوفرة."},"ICON-1749":{"nm":"صندوق أخبار القرية","de":"أخبار القرية الكبيرة والصغيرة تتراكم بعناية داخل هذا الصندوق. من انتقل حديثًا، ومن يقيم وليمة - أوراق قليلة تجتمع لتنقل النبض الهادئ للحي."},"ICON-1750":{"nm":"ختم شكر الزيارة","de":"تضغط الامتنان لمجيء أحدهم بختمٍ واحد. تلك البقعة الواحدة من الحبر المنتشرة على الورق تبقى في مكانها أطول من كلمات \"لن أنسى.\""},"ICON-1751":{"nm":"بطاقة الثناء على اللطف","de":"بطاقة تدوّن عليها بهدوء لطفًا قدّمه أحدهم اليوم، ثم تُعيدها. في قرية تكلّف نفسها عناء تدوين الحنان الصغير بالكلمات، تستمر الأشياء الجيدة بالدوران والعودة."},"ICON-1752":{"nm":"ختم رسالة الاعتذار","de":"كتفاحةٍ نضجت حمراء، لا يمكن تقديم كلمة \"آسف\" إلا بعد أن تنضج تمامًا. هذا الختم المضغوط بإحكام على المغلف هو أثر الشجاعة التي احتضنت اعتذارًا يصعب قوله حتى النهاية."},"ICON-1753":{"nm":"لوحة العمل المشترك","de":"ورقة واحدة مقسّمة إلى خانات مكتوب فيها من يتولى ماذا. من يعمل كتفًا بكتف يعرف أن العمل الثقيل بمفرده يصبح أخف بكثير حين تُقسّم الأسماء عليه."},"ICON-1754":{"nm":"شريط أذواق الجيران","de":"تُشير بهدوء إلى ما يحبه الجار بأشرطة ملونة متعددة. أن تتذكر أذواق شخص ما هو أهدأ اعتراف بأنك تعتز به، دون أن تقول ذلك أبدًا."},"ICON-1755":{"nm":"حلقة لوحة اسم الدعوة","de":"حلقة واحدة معلّقة على لوحة الاسم تُعلن \"نستقبل ضيوفًا اليوم\". إنها علامة بحجم كف اليد، لكن يتدلى منها قلبٌ مفتوح على مصراعيه، أنهى استعداده لاستقبال أحدهم."},"ICON-1756":{"nm":"سوار دخول المهرجان","de":"شريطٌ باهت اللون، ارتُدي أيامًا، وكان أعز من أن يُنزع. فقط حين ثُبّت على المعصم بدأ المهرجان حقًا. في داخله ينام، محفوظًا كاملًا، يومٌ لم ينتهِ تمامًا حتى بعد انتهائه."},"ICON-1757":{"nm":"حافظة تذكرة الألعاب النارية","de":"قبل أن ينفجر سماء الليل مباشرة، تقبض التذكرة داخل هذه الحافظة بإحكام على القلب الخافق. إنه وعدٌ يُمسَك حتى يتصبب عرقًا في كف اليد، كله من أجل تلك اللحظة الواحدة التي تتفتح فيها أولى الألعاب النارية بفرقعة."},"ICON-1758":{"nm":"صحن مراقبة القمر","de":"كانت هناك ليالٍ يبدو فيها أنك اغترفت القمر البدر بأكمله في طبق. ضع الفواكه الطازجة وكعك السونغپيون بعناية على هذا الصحن وانحنِ للقمر، وسيصل قلبٌ مستديرٌ واحد إلى أقاصي السماء."},"ICON-1759":{"nm":"دبوس قفاز مهرجان الشتاء","de":"حتى حين تتجمد يداك في الثلج، تستمر القفازات بالانزلاق من معصميك. فقط حين يُثبّت هذا الدبوس بإحكام على الكم، يمكنك أخيرًا أن تجري في مهرجان الشتاء بكامل حريتك."},"ICON-1760":{"nm":"بطاقة بذور استقبال الربيع","de":"بذورٌ قليلة نائمة داخل البطاقة، كل واحدة تنتظر ربيعها. ادفنها في التراب وستنبت لا محالة، كوعد، ويبدو أن كل بداية تنبثق من نقطة واحدة صغيرة وصلبة."},"ICON-1761":{"nm":"ختم شاطئ الصيف","de":"تختم موجةٌ أثرها بإحكام في الرمل ثم تنسحب رويدًا. رغم علمها أنها ستُمحى قريبًا، تترك أثرًا صغيرًا يقول إن أحدهم كان هنا. الصيف دائمًا يُختم مرة واحدة بوضوح، ثم ينساب مع رائحة الملح."},"ICON-1762":{"nm":"شريط حصاد الخريف","de":"اليد التي ربطت السنابل تعقد الشريط بعناية في النهاية. عقدةٌ واحدة تجمع عرق عام كامل بحرص. حتى وهي تفرغ الحقول، يُقدّم الخريف تحية أخرى بأجمل الألوان، كالغروب."},"ICON-1763":{"nm":"فقاعة كلام الصورة التذكارية","de":"\"شكرًا لأنك أتيت إلى هذا الحد.\" تحية لم تُنطق بها الشفاه أبدًا تنتفخ مستديرة على الورق. قطعة صغيرة مستديرة من القلب، تُعير صوتًا برفق للصمت المجمّد داخل الصورة."},"ICON-1764":{"nm":"دبوس خريطة أرض المهرجان","de":"علامة غرزها أحدهم لكي لا تضيع في الساحة الواسعة. حتى حين تندفع قدماك أولًا نحو صوت الموسيقى الشعبية، يقود هذا الدبوس الواحد بهدوء تائهك إلى المكان المتفق عليه."},"ICON-1765":{"nm":"المفتاح الرئيسي للألبوم","de":"ما هو مغلق ليس الألبوم بل الزمن المختوم بداخله. رعشة التسجيل الأول، فجر آخر مزج. أدر المفتاح ببطء، وسيصرّ باب تلك الغرفة، الذي لا يعرفه إلا صانعوه، وينفتح."},"ICON-1766":{"nm":"بطاقة قائمة الأغاني","de":"ترتيب الأغاني المدوّن على ورقة واحدة هو في الحقيقة ترتيب القلب. أين سيَغُصّ الحلق، وأين سيلتقط الأنفاس - الورقة تعرف كل ذلك مسبقًا. إثارةٌ تتصاعد قبل أن تسمع حتى النغمة الأولى."},"ICON-1767":{"nm":"بطاقة فحص التسجيل الصوتي","de":"فقط من أعاد نفس المقطع مئة مرة يضع هذه البطاقة. \"مرة أخرى، مرة واحدة فقط بعد.\" بجانب ختم النجاح يختبئ ليلُ أحدهم الذي شكّ في أذنيه حتى الفجر."},"ICON-1768":{"nm":"ملصق الطلب المسبق","de":"وعدٌ بانتظار شيء لم يخرج بعد إلى العالم. في اللحظة التي يُلصق فيها الملصق، يُحجز مكان فارغ واحد بصمت باسم أحدهم. حتى الانتظار المثير له رقم تسلسلي."},"ICON-1769":{"nm":"ملصق ختم الطبعة الأولى","de":"يشبه لمسة اليد القديمة التي كانت تغطي الجرة بورق الهانجي وتختمها بالغراء. ورقة واحدة تقسم بالحفاظ على الأشياء كما كانت في البداية. لأنك تعلم أنها ستختفي لحظة نزعها، تظل تحدّق في هيئتها أطول فأطول."},"ICON-1770":{"nm":"شريحة تقويم العودة","de":"أضف دائرة واحدة إلى التقويم، وتقصر الليالي حتى ذلك اليوم بمربع واحد. تاريخ العودة واضح على الشريحة الصغيرة في يدك. بالنسبة لمن ينتظر، الزمن يُحسب هكذا، باليد."},"ICON-1771":{"nm":"غلاف صورة الكونسبت","de":"قبل أن يزيح الكونسبت التالي لون هذا الكونسبت، تحفظ ورقة شفافة نسيجه بعناية. لكي لا يُنسى حين يتغير الفصل، تحمي بلطف لون الأيام الماضية، بأركانها كاملة."},"ICON-1772":{"nm":"قطعة كشف التيزر","de":"قبل رفع الستار مباشرة، عملة صغيرة تُقبض في راحة اليد. في لحظة مدّها، ينفتح المشهد الأول المقفل شبرًا نحو العالم. الكشف، في النهاية، مسألة من يمد يده أولًا."},"ICON-1773":{"nm":"حامل عرض الألبوم","de":"في اللحظة التي يرفع فيها حامل منخفض واحد الألبوم قليلًا، يصبح قرصٌ عادي نجم العرض. ممثل مساند حنون، يسند من الخلف، بصمت، الزاوية التي يلامسها الضوء بأجمل شكل."},"ICON-1774":{"nm":"تصريح عرض الظهور الأول","de":"تصريح واحد مطبوعة عليه كلمات \"نقدّمها لكم لأول مرة\". من الممر الطويل خلف الكواليس إلى أول تصفيق من المقاعد، يحمل هذا التصريح عبر عتبة الظهور الأول المرتجفة."},"ICON-1775":{"nm":"شريحة علامة مسار المسرح الأول","de":"تتلمس بأطراف أصابع قدميك الشريحة الملتصقة بالأرض. مربعٌ واحد يعرفه الجسد أولًا، حتى دون النظر. في لحظة الهبوط بدقة على المكان المحفوظ، تتحول الرعشة في أطراف الأصابع أخيرًا إلى حركة واضحة."},"ICON-1776":{"nm":"بطاقة كلمة التحية","de":"حتى الجملة المألوفة \"كل هذا بفضلكم\" لم تعد مألوفة حين تُكتب بخط يد مرتجف. سطور قليلة دُوّنت مسبقًا خوفًا من أن يُنسيها الانفعال. الصدق أحيانًا يتكئ على بطاقة واحدة."},"ICON-1777":{"nm":"ورقة حجز تصوير البروفايل","de":"ورقة كُتب عليها بعناية التاريخ المقرر للوقوف أمام العدسة. جدول زمني للتحضير البطيء لأفضل وجه ممكن. كلما امتلأت خانة فارغة، طالت الليالي المُقضاة أمام المرآة أيضًا."},"ICON-1778":{"nm":"ورقة انتساب نادي المعجبين","de":"ورقة انتساب تُكتب عليها بخجل السطر الواحد لاسمك وقلبك. قول أنك تحب شيئًا صعبٌ دائمًا، لكن هذه الورقة الواحدة تكتب تلك الكلمات نيابةً عنك بعناية. توقيعٌ أول على اختيار البقاء معًا."},"ICON-1779":{"nm":"ورقة فحص هدية الظهور الأول","de":"لمسة تتفقد كل قطعة، متخيلةً الشخص الذي سيستلمها. هل تضررت الأركان؟ هل فُقد شيء من القلب؟ الهدية تُحَبّ مرة قبل أن تُقدَّم حتى، وتنطلق."},"ICON-1780":{"nm":"علامة نهاية المسرح","de":"قبل إسدال الستار مباشرة، علامة موضوعة حيث تستقر الوضعية الأخيرة. ليست إعلانًا عن النهاية بقدر ما هي نقطة صغيرة تعقد النهاية بعناية. المسرح المغلق جيدًا وحده يفتح المسرح التالي."},"ICON-1781":{"nm":"دبوس انتظار المقابلة","de":"دبوس يحفظ بهدوء السكون قبل أن تبدأ الأسئلة. خلال ذلك الصمت القصير لاختيار الإجابات في الذهن، تقول هذه العلامة الصغيرة بحنان نيابة عنك، \"ليس بعد، لكن قريبًا.\""},"ICON-1782":{"nm":"مغلف تذكار الظهور الأول","de":"مثل القلب القديم الذي كان يضع رسالة ثمينة، مغلفًا وكل شيء، في يد من يرحل، تحمل طبقة واحدة سجل المسرح الأول بعناية. في يوم فتحها بعيدًا في المستقبل، تنسكب رعشة ذلك اليوم أيضًا معها."},"ICON-1783":{"nm":"ماصة تدريب التنفس الغنائي","de":"تدريب على إرسال النفس طويلًا، في تيار واحد، عبر طرف الأنبوب الرفيع. الغناء، في النهاية، هو نفسٌ محسوبٌ جيدًا - هذه الماصة الصغيرة تخبرك بهذا بهدوء كل صباح. الريح قبل الصوت."},"ICON-1784":{"nm":"شريحة نقر تدريب الإيقاع","de":"تِك، تِك، تِك - أصدق صديق في العالم. يمسك بك حين تسرع ويدفع ظهرك حين تتباطأ. نقش الإيقاع في الجسد أشبه بحوار طويل مع هذه الشريحة الصلبة."},"ICON-1785":{"nm":"شريط فحص خط الرقص","de":"أين تتوقف أطراف الأصابع، وأين ينفتح الكتف - تتبّع خط الحركة بشريط واحد. خط الرقصة المرسوم جيدًا يبقى مستقيمًا ومرتبًا حتى في المكان الذي لا تراه المقاعد."},"ICON-1786":{"nm":"بطاقة ملاحظات التعابير","de":"تلك المقولة، أن حتى الابتسام يجب أن يُتعلّم. ورقة تدوّن شيئًا فشيئًا زاوية العينين وارتفاع طرفي الشفتين. التعبير الذي عجزت المرآة عن إخبارك به، تخبرك به هذه البطاقة بحنان نيابة عنها."},"ICON-1787":{"nm":"مذكرة تدفق الراب","de":"\"استرح هنا لحظة، واسكبها هناك\" - مذكرة ترسم مسبقًا مجرى الكلمات. كلما أسرع المقطع، وجب أن يكون طريق النفس أوضح. داخل الأسهم المرسومة بسرعة، يعيش إيقاع مقطع كامل ويتنفس."},"ICON-1788":{"nm":"ملصق حرارة الصوت","de":"للصوت أيضًا أيام دافئة وأيام باردة. علامة صغيرة تختارها بلون وتلصقها لنسيج اليوم. تسخينًا وتبريدًا بالتناوب، يستيقظ الصوت كل يوم بدرجة حرارة مختلفة قليلًا."},"ICON-1789":{"nm":"قطعة روتين الراحة","de":"عملة تُوضع في يدك مع كلمات أن الراحة الجيدة مهارة أيضًا. امددها وستتمكن من التوقف قليلًا دون شعور بالذنب. لمن ركض بلا توقف، التوقف هو الخيار الأكثر شجاعة."},"ICON-1790":{"nm":"دبوس هدف النمو","de":"دبوس صغير مغروز مع كلمات \"لنحاول الوصول إلى هذا الحد\". رغم أنه يبدو بعيدًا يكاد لا يُدرَك، تنمو خطوة واحدة نحوه كل يوم. الهدف أشبه بوعدٍ حنون يلوّح من بعيد."},"ICON-1791":{"nm":"مغلف التقييم الأسبوعي","de":"تجمع عرق ودموع أسبوع كامل بعناية في مغلف واحد وتسلّمه. ما أُتقن وما بقي ناقصًا يجلسان جنبًا إلى جنب بداخله. فتحه واجب صغير يُسلَّم لذاتك في الأسبوع القادم."},"ICON-1792":{"nm":"علبة قطع ديكور المسرح","de":"خلف المسرح البرّاق تعيش قطعٌ بلا أسماء. مسمار واحد، حلقة واحدة تجتمع لتُطلق النجوم على السقف. افتح العلبة، وستجدها مليئة بالعناية الصغيرة التي تسند البهاء بصمت."},"ICON-1793":{"nm":"لوحة كونسبت الأزياء","de":"بتثبيت قصاصات القماش والألوان واحدة تلو الأخرى، ترتدي مسبقًا زيًا لم يوجد بعد في العالم. زي المسرح يكتمل أولًا على اللوحة. الخيال يمشي دائمًا خطوة أمام الإبرة."},"ICON-1794":{"nm":"شريحة ملاءمة اللون","de":"نفس الزي يرتدي وجهًا مختلفًا تمامًا حسب الضوء. أي لون يبتسم بأشد سطوع مع ذلك الشخص - تكتشفه بوضع الشرائح واحدة تلو الأخرى قريبًا منه. الملاءمة اكتشافٌ في نهاية مقارنة طويلة."},"ICON-1795":{"nm":"لوحة عينات رباط الحذاء","de":"ما يسند خطوة ثابتة على المسرح هو، على غير توقع، رباطٌ صغير. حتى لا يُحل، ولكن دون أن يضيّق أيضًا. أرقّ تفكير، يُبذل في أخفض مكان، اختيارًا من أربطة موضوعة حسب نسيجها."},"ICON-1796":{"nm":"مغلف فحص الإكسسوارات","de":"كلما لمع شيء أكثر، بدت عيبة واحدة أكبر بوضوح. لمسة تحمل المجوهرات من المغلف إلى الضوء وتفحصها بعناية. القلب الذي يتفحص الأشياء الصغيرة حتى النهاية هو ما يحمي المسرح."},"ICON-1797":{"nm":"رقعة لون الشعر","de":"عينة صغيرة لتجربة فصل جديد على الشعر مسبقًا. اللون الذي يصبغ خصلة واحدة خلسة يلمّح بهدوء إلى الانطباع الأول للكونسبت التالي. التغيير يبدأ دائمًا من مكان بحجم كف اليد."},"ICON-1798":{"nm":"بطاقة كونسبت الأظافر","de":"ورقة تحدد مسبقًا الرسومات الصغيرة التي ستُرسم على أطراف الأصابع العشرة. لكي يظهر الكونسبت بخفة حتى في إيماءة واحدة، تُلبِس القصةَ بعنايةٍ حتى أدق التفاصيل."},"ICON-1799":{"nm":"تذكرة تغيير الستايل","de":"\"هل أصبح اليوم نسخة مختلفة قليلًا عن أمس؟\" - تذكرة واحدة تجعل ذلك السطر ممكنًا. سواء الشعر أو الملابس أو الأجواء، تفتح هذه التذكرة الباب المثير نحو مظهر جديد."},"ICON-1800":{"nm":"بطاقة تعديل المقاس","de":"بطاقة تدوّن بعناية أماكن التضييق والتوسيع حتى يلائم الجسد تمامًا. مثل اللمسة القديمة التي كانت تصلح ملابس الطفل غرزة غرزة، هذا التعديل الصغير يجعل المسرح أكثر راحة بشبر واحد."},"ICON-1801":{"nm":"بطاقة مسودة الصورة المصغرة","de":"ورقة واحدة لم تلمسها الألوان بعد. فوق خطوط القلم الخشنة، تحاول بهدوء أن تخمّن إلى أين سينساب المشهد التالي. الأكثر إثارة من الاكتمال هو دائمًا هذا السطر الأول الناقص، كما تُذكّرنا غرفة المونتاج الهادئة."},"ICON-1802":{"nm":"ملصق الموافقة على التصوير","de":"\"هل يجوز أن أُصوَّر هنا؟\" بدل الكلمات، تضع علامة دائرية صغيرة على صدرك. ملصق واحد صغير يقيم وعدًا لطيفًا بين الكاميرا والقلب."},"ICON-1803":{"nm":"دبوس موقع جدار الصور","de":"دبوس صغير مغروس في زاوية الجدار. يحدد مسبقًا من سيقف وأين. وحيثما غُرس الدبوس، تتوقف ابتسامة لتصبح صورة واحدة."},"ICON-1804":{"nm":"رقاقة اختيار اللقطة","de":"إصبع يشير إلى واحدة فقط من بين مئات اللقطات. حين توضع هذه الرقاقة، تصبح كل التعابير المطوية جانبًا وكأنها عاشت من أجل تلك اللقطة الواحدة. الاختيار يشبه دائمًا وداعًا هادئًا."},"ICON-1805":{"nm":"مغلّف كواليس التصوير","de":"كل ما جرى خلف الكاميرا يُحفظ هنا. اطوِ الفتحة فينام الضحك والأخطاء والتثاؤب النعسان معًا. وما يصير أعزّ من العمل الأصلي غالبًا هو ما يختبئ في الداخل."},"ICON-1806":{"nm":"مذكرة طلب المونتاج","de":"\"ثانية واحدة أطول هنا، وخفّض الموسيقى قليلًا.\" ورقة مزدحمة بالحبر الأحمر. دقّة شخص ما تُعدّل نَفَس الفيديو بنبضة واحدة. الإتقان ينمو فوق لمسات صغيرة كهذه."},"ICON-1807":{"nm":"وسم جدولة الرفع","de":"علامة صغيرة على فيديو سيخرج إلى العالم وحده في السابعة صباح الغد. حتى بينما ينام الجميع، يبقى الوعد يقظًا. الوقت المحدد مسبقًا لا يعرف كيف يتأخر."},"ICON-1808":{"nm":"غطاء إطار الصورة المصغرة","de":"غطاء يلفّ أفضل مشهد افتتاحي. يطوي الزوايا بعناية كي لا تلمسها بصمة أصابع أو غبار. وحتى يُعرض، يُصان الانطباع الأول بهذه الرقة."},"ICON-1809":{"nm":"رقاقة مدة التصوير","de":"رقاقة صغيرة تقيس كم دقيقة صُوّرت اليوم. الطول لا يعني الأفضل، ولا القصر يعني الأخف. معرفة الطول المناسب هي الزر الأول للمونتاج."},"ICON-1810":{"nm":"ورقة تدقيق شعار التشجيع","de":"ورقة تُراجَع مرة أخرى قبل الصراخ بأعلى الصوت. فحرف واحد خاطئ يبعثر آلاف الأصوات. خلف الهتاف، مرّت أولًا يد تدقيق لا تُرى."},"ICON-1811":{"nm":"غلاف حفظ رسوم المعجبين","de":"رسمة رسمها أحدهم طوال الليل. يُمنح لها بيت شفاف صغير كي لا تتجعّد. وكأن ما رُسم بالقلب يجب أن يُحتضن بالقلب ليدوم، يعانقها الغلاف بصمت."},"ICON-1812":{"nm":"خيط تصنيف رسائل المعجبين","de":"خيط يربط الرسائل المتراكمة بترتيب حسب مُرسِلها. مع كل عقدة، يُرتَّب حنينُ يومٍ كامل. هنا يد لا تدع رسالة واحدة تفلت، حتى وإن لم تستطع الرد على جميعها."},"ICON-1813":{"nm":"استمارة حجز تبادل السلع","de":"\"هل يوجد من يبدّل معي؟\" ورقة تكتب عليها قلبك المرتجف وتمدّها. لسبب واحد فقط، أنكما تحبان الشيء نفسه، يصير غريبان صديقين للحظة."},"ICON-1814":{"nm":"رقاقة مقاعد التشجيع الجماعي","de":"رقاقة تحدد المقاعد التي سيجلس فيها من يرتدون اللون نفسه جنبًا إلى جنب. حين تجتمع القلوب المتفرقة في قسم واحد، يبدأ الجمهور بالغناء كأنه شخص واحد ضخم."},"ICON-1815":{"nm":"إيصال إعلان عيد الميلاد","de":"إيصال واحد استُلم بعد رفع الحب على لوحة إعلانية. ما لا يُكتب بجانب المبلغ هو الجهد المتجمّع طوال الليل. تبقى هذه الورقة دليلًا على احتفال موجّه لشخص واحد فقط."},"ICON-1816":{"nm":"غلاف دفتر الرسائل","de":"غلاف يلفّ كتابًا جُمعت فيه خطوط أيدٍ كثيرة. افتحه فتتراكب الخطوط المختلفة في قلب واحد. المظهر أنيق، لكن الداخل مليء بضجيج دافئ."},"ICON-1817":{"nm":"دبوس عضوية نادي المعجبين","de":"دبوس صغير يُمنح فقط لمن ينادون الاسم نفسه. لحظة تثبيته على الصدر، يتحول إعجاب كان وحيدًا إلى وعد يتشاركه كثيرون. الانتماء له شكل دائري كهذا."},"ICON-1818":{"nm":"رمز التشجيع الإلكتروني","de":"نقطة ضوء تلوّح بها أيدٍ بعيدة خلف الشاشة. المسافة شاسعة، لكن الإيقاع واحد. إنه دليل على أن التشجيع يصل دون فشل، حتى من مقاعد لا تُرى."},"ICON-1819":{"nm":"شظية مفتاح بالية","de":"قطعة معدن مكسورة الأسنان. لا أحد يتذكر بعد الآن أي باب كانت تفتحه. ما يبقى أطول عمرًا من المكان المقفل هو دائمًا هذا النصف عديم الفائدة من مفتاح كهذا."},"ICON-1820":{"nm":"خريطة الممر السري","de":"ورقة قديمة ترسم طريقًا مختبئًا خلف اللبلاب. الطرق المختصرة لا يعرفها إلا من يعرفها. لحظة انفتاحها، تُبدّل الجزيرة العادية وجهها بهدوء إلى مسرح للمغامرة."},"ICON-1821":{"nm":"بطاقة فك الشيفرة","de":"بطاقة تعيد الحروف المبعثرة المشوّشة إلى مواضعها الأصلية. حين يستقيم سطر واحد، يلوّح السر التالي. حتى العقدة التي بدت مستعصية تبدأ في النهاية من الحرف الأول."},"ICON-1822":{"nm":"خيط الصندوق المختوم","de":"خيط مربوط بإحكام كأنه يقول لا تفتح. لا يعرف ما ينام داخل العقدة إلا من عقدها. رغبة الفكّ ورغبة الحماية مربوطتان جنبًا إلى جنب في هذا الخيط الواحد."},"ICON-1823":{"nm":"رقاقة أحجية الآثار","de":"شظية صغيرة سقطت من جدار حجري قديم. أعدها إلى موضعها فتحيا صنعة يد شخص من ألف عام مضت بين أطراف أصابعك. جمع المتناثر هو عمل يعيد وصل الزمن من جديد."},"ICON-1824":{"nm":"قصاصة أسطورة الجزيرة","de":"ورقة نُسخت عليها بخط اليد حكايات قديمة تجول في الجزيرة. لا يهم كثيرًا إن كانت حقيقية أم لا. الحكاية التي انتقلت من فم إلى فم تصبح، في ذاتها، حلقة نمو في عمر الجزيرة."},"ICON-1825":{"nm":"حجر العلامة الخفية","de":"حجر يبدو موضوعًا عفويًا على جانب الطريق. لا يشير إلى الاتجاه بهدوء إلا لعينٍ عارفة. كلما كان السر الذي تريد دفنه أعمق، كلما وقف بوجه أكثر عادية."},"ICON-1826":{"nm":"مغلّف اللغز","de":"لا شيء مكتوب على الخارج. هذه اللحظة القصيرة قبل كسر الختم هي الأكثر إثارة. وحتى تكون الإجابة بين يديك، تبقى كل الاحتمالات حية داخل المغلّف."},"ICON-1827":{"nm":"غطاء عدسة المحقق المكبّرة","de":"غطاء صغير يُركّب بهدوء على طرف العدسة المكبّرة. حين لا تستخدم للتحديق، يترك العدسة ترتاح بصمت. أن ترى جيدًا يعني أولًا أن تحمي جيدًا، درس يتعلمه المحقق باكرًا."},"ICON-1828":{"nm":"تذكرة حافلة الجزيرة الدائرية","de":"تذكرة واحدة لركوب الحافلة التي تدور حول الجزيرة. المحطة الأخيرة هي نقطة الانطلاق من جديد. على طريق يعود دورانًا إلى حيث بدأ، يبدو المشهد جديدًا قليلًا في كل مرة."},"ICON-1829":{"nm":"وسم استئجار الدراجة","de":"وسم يتدلى من مقود دراجة مستأجرة. حرية قصيرة تُمنح حتى موعد إعادتها. حين ينتهي وقت شق الريح، يجمع هذا الوسم ذلك الوعد بهدوء."},"ICON-1830":{"nm":"تذكرة صعود القارب الصغير","de":"تذكرة صعود لركوب قارب صغير. على السطح المتمايل، تقترب جزيرة من جزيرة. عبور الممر المائي يجلب معه دائمًا قليلًا من الإثارة وقليلًا من دوار البحر."},"ICON-1831":{"nm":"دبوس عجلة العربة","de":"دبوس يثبّت عجلة العربة بإحكام. قطعة معدن صغيرة واحدة تجعل حِملًا ثقيلًا يتدحرج. أقل الأجزاء ظهورًا غالبًا ما يتحمل بصمت أكبر وزن."},"ICON-1832":{"nm":"رمز التلفريك","de":"رمز دائري يُوضع في التلفريك الذي يشق الهواء. لحظة تترك فيها قدماك الأرض، تُحتضن الجزيرة كلها في نظرة واحدة. كلما ارتفعت أكثر، صار المشهد أكثر سخاءً."},"ICON-1833":{"nm":"شريط ركوب المنطاد","de":"شريط يُلفّ حول المعصم قبل الصعود إلى السلة. حين ينتفخ اللهب وتبتعد الأرض، يخفّ القلب أيضًا. الصعود يعني أن تضع وزنك جانبًا للحظة."},"ICON-1834":{"nm":"رقاقة استدعاء تاكسي الماء","de":"رقاقة صغيرة لاستدعاء تاكسي يجري فوق الماء. ارفع يدك فيقترب قارب شاقًّا التيار. ما يشقّ طريقًا حتى حيث لا طريق هو، في النهاية، شجاعة من يستدعي أولًا."},"ICON-1835":{"nm":"تصريح مدخل مسار الجبل","de":"تصريح يُسلَّم عند البوابة الأولى إلى الجبل. من هنا فصاعدًا، أطراف أصابع قدميك تحدد الطريق. القمة قد تكون بعيدة، لكن من يجتاز المدخل وحده يُوعد بذلك المنظر."},"ICON-1836":{"nm":"مفتاح خزانة الميناء","de":"مفتاح صغير يفتح خزانة بجانب الرصيف. بيدين خفّتا بعد ترك الحمل، تنظر إلى البحر. أن يكون لديك مكان تضع فيه الأشياء قليلًا هو أمر يمنحك شجاعة السفر بعيدًا."},"ICON-1837":{"nm":"غطاء برطمان التخليل","de":"غطاء برطمان يحبس كل ما هو حامض. أغلقه بإحكام فيحافظ خيار الصيف على قرمشته حتى الشتاء. سرّ التغلب على الزمن يبدأ، كما يتبين، بإغلاق الأشياء جيدًا."},"ICON-1838":{"nm":"بطاقة رف التجفيف","de":"بطاقة اسم تُلصق على ما يُنشر ليجف على المصفاة. سجّل ماذا وُضع ومتى، فلا ينقلب الانتظار فوضى. حتى في زمن الشمس والريح، لا بد من شيء اسمه الدور."},"ICON-1839":{"nm":"مغلّف رقائق التدخين","de":"مغلّف يحوي رقائق من خشب عطر. افتح الفوهة فتُحيّي أنفك رائحة أشبه بنار المخيم أولًا. النكهة التي عمّقها الدخان لا تنفتح إلا ببطء، ولمن يعرف كيف ينتظر وحده."},"ICON-1840":{"nm":"ملصق المؤن المحفوظة","de":"ملصق يوضع على جرة، تمنياتٍ بأن تصمد طوال العام. يوم التحضير والجهد المبذول مكتوبان عليه. الطعام الذي يُحفظ طويلًا يأتي دائمًا مع مذكرة صغيرة تحاول تذكّر مذاق ذلك اليوم بيد صانعه."},"ICON-1841":{"nm":"وسم ساعة التخمير","de":"التخمير لا يثق بالساعة. فهو يقيس الزمن بالرائحة لا بعقرب الدقائق. لحظة تصل فيها رائحة حامضة إلى أنفك، يومئ الوسم بصمت: \"حان الوقت الآن.\" حتى الانتظار له مقياسه الخاص."},"ICON-1842":{"nm":"دبوس تصنيف رفوف الثلاجة","de":"هنا يقف شرطي المرور الصغير للثلاجة. الخضروات فوق، الأطباق الجانبية تحت، وبقايا الأمس في الصف الأمامي. اغرس دبوسًا واحدًا، وسرعان ما تعرف اليد التي كانت تتخبط عند فتح الباب طريقها."},"ICON-1843":{"nm":"شريط تدفئة صندوق الغداء","de":"لفّت أمي شريطًا حول صندوق الغداء كي لا يهرب الدفء قبل الظهيرة. فكّ الشريط، وتحت الغطاء المغطى بالبخار، لا يزال دفء الصباح مستلقيًا دافئًا، ينتظرني."},"ICON-1844":{"nm":"برطمان تعتيق الصلصة","de":"التوابل الجيدة لا تستعجل أبدًا. فهي تمنح صويا الصلصة والثوم بهدوء وقتًا ليتخلل أحدهما الآخر. في ظلمة البرطمان تتعمق النكهة ببطء، وحكمة فناء الجرار البطيئة تنتقل لتسكن برطمانًا صغيرًا."},"ICON-1845":{"nm":"بطاقة مربى الفصل","de":"فراولة في الربيع، مشمش في الصيف، تين في الخريف. بطاقة واحدة تكتب الفصل بعناية على البرطمان. افتح الغطاء في عمق الشتاء، فتذوب شمس العام الماضي ببطء، ملعقة تلو أخرى."},"ICON-1846":{"nm":"لوحة شارات نسبة الجمع","de":"لا داعي لعناء عدّ ما جمعته، فلوحة الشارات تتباهى به نيابةً عنك. مع امتلاء كل خانة فارغة، ترتفع كتفاك قليلًا؛ هذا ليس رقمًا، بل أثرَ خطى طُبع على أطراف الأصابع."},"ICON-1847":{"nm":"بطاقة الخانة غير المكتشفة","de":"مكان لم يُلتقَ بعد. الظل على البطاقة يقدّم وعدًا برسم غامض فحسب. الفراغ يعني قريبًا سيمتلئ، فالترقب ينتظرك دائمًا بشكل علامة استفهام."},"ICON-1848":{"nm":"ختم إتمام الدليل","de":"ذلك الصوت حين يهبط الختم \"طرقًا\" على الخانة الأخيرة. أغلق الدليل وافتح راحة يدك، فتجد نقطة حبر أحمر عالقة كوسام إتمام. ذلك الارتياح العميق الذي لا يعرفه إلا من جمع حتى النهاية."},"ICON-1849":{"nm":"رقاقة لون الندرة","de":"حتى الشكل نفسه يروي حكاية مختلفة حين يختلف اللون. رقاقة واحدة ترسم بهدوء الخط بين العادي والنفيس. عين الجامع تتوقف دائمًا طويلًا أمام ذلك الفارق الخفي في الصبغة."},"ICON-1850":{"nm":"قسيمة تبادل المكرر","de":"ظهر مرة أخرى، مرة أخرى. في اليوم الذي التقطت فيه للمرة الثالثة شيئًا تملكه أصلًا، تمد هذه القسيمة يدها بهدوء. كأنها عزاء لطيف بأن المكرر، إن احتُضن بدل أن يُرمى، سيعود يومًا شيئًا نفيسًا."},"ICON-1851":{"nm":"لوحة رقم صندوق المجموعة","de":"رقّم كل صندوق، فيصبح المستودع مكتبة صغيرة. رقم 17 يحمل ما جُمع في الربيع، رقم 23 ما التُقط عند البحر. أنا فهرس هادئ، أرتّب الذكريات المتناثرة سطرًا سطرًا."},"ICON-1852":{"nm":"دليل ترتيب العرض","de":"العرض يُصنع نصفه بالموضع. الطويل إلى الخلف، اللامع إلى الوسط. اتبع الدليل وحرّك الأشياء بيدك، فسرعان ما يلتقط الرف المزدحم أنفاسه كصالة عرض صغيرة."},"ICON-1853":{"nm":"منفضة غبار المقتنيات","de":"كلما كان الشيء أعزّ، استقر عليه الغبار أفضل. بطرف الفرشاة الناعم، برفق، تكنس حتى الشعور بالذنب لعدم النظر إليه طويلًا. وبينما تنظّف، تلمع الذكريات النائمة من جديد للحظة."},"ICON-1854":{"nm":"قسيمة توسيع حد التخزين","de":"إن جمعت طويلًا بما فيه الكفاية، يصبح نفاد المكان قلقًا سعيدًا. ذلك الارتياح الهادئ لرؤية رف إضافي واحد؛ هذا ليس طمعًا، بل دليل على أن ما تحبه كثير إلى هذا الحد."},"ICON-1855":{"nm":"بطاقة رمز دعوة صديق","de":"تسليم هذا الرمز هو ألطف دعوة على الإطلاق، تقول \"تعال والعب معي\". القلب محفوظ في بضعة أرقام. لا تبدأ حكاية تخصكما وحدكما إلا حين يضع الصديق الذي تلقاها قدمه على الجزيرة."},"ICON-1856":{"nm":"مفتاح المستودع المشترك","de":"باب المستودع لا يُفتح وحده أبدًا. قفل لا يدور إلا حين تجتمع يدان، يدك ويدي. المساحة المشتركة تحمل دائمًا وعدًا مشتركًا، معلّقًا بشكل مفتاح."},"ICON-1857":{"nm":"وسم الإبلاغ عن مفقود","de":"الشيء المفقود عزيز على أحدهم أيضًا. كتابة سطر واحد، \"إنه هنا\"، وتعليقه؛ الوسم خيط صغير يعيد بهدوء ربط قلب ضائع مؤقتًا بصاحبه."},"ICON-1858":{"nm":"راية طلب المساعدة","de":"طلب المساعدة ليس ضعفًا بل شجاعة. حين ترتفع الراية، يهرول أحدهم من مكان ما. أسرع ما ينتشر في هذه الجزيرة ليس الإشاعة، بل الأيدي الممدودة نحو بعضها."},"ICON-1859":{"nm":"سوار الاتصال الطارئ","de":"طمأنينة صغيرة تُلبس حول المعصم. مهما حدث، الرقم المكتوب هنا يهرول أسرع من أي أحد. رفيق هادئ يُنسى في الأيام العادية، ويصبح الأكثر اعتمادًا في لحظة الحاجة."},"ICON-1860":{"nm":"رقاقة توزيع المهام","de":"من يتسوق ومن يطبخ؛ وزّعوا الرقاقات ولن يبقى ما تتشاجرون عليه. الخطوة الأولى في صنع شيء معًا تبدأ من تحديد نصيب كل شخص بلطف."},"ICON-1861":{"nm":"لوحة الإنتاج التعاوني","de":"ما لم تكن لتجرؤ على محاولته وحدك يصبح ممكنًا، كأنه سحر، حين يجتمع كثيرون. مع امتلاء الأسماء على اللوحة واحدًا تلو الآخر، تتقلص الخانات الفارغة ويكبر الضحك. التعاون ينمو بهدوء بين الخانات."},"ICON-1862":{"nm":"بطاقة آداب الزيارة","de":"عند دخول بيت أحدهم، تصير حذرًا من أطراف أصابع قدميك. ما هو مكتوب على البطاقة ليس قواعد كبرى، بل وعود صغيرة دافئة فحسب، مثل \"رتّب حذاءك، وابدأ بالتحية\"."},"ICON-1863":{"nm":"جرس نهاية الحفل","de":"حتى الفرح يحتاج نهاية كي يُنتظر التالي بشوق. حين يرنّ الجرس \"طن\"، يجمع الجميع أغراضهم بوجوه مليئة بالحسرة. الحفل الذي يعرف كيف يودّع بلطف هو الذي يبقى أطول في القلب."},"ICON-1864":{"nm":"شريط زوايا المرتبة","de":"مهما فردت الغطاء بسلاسة، تظل الزوايا ترتفع لا محالة. بفضل شريط يمسك الزوايا الأربع بإحكام، يستيقظ السرير كل صباح مرتّبًا كغرفة فندق."},"ICON-1865":{"nm":"خيط زر ياقة اللحاف","de":"أنا خيط الزر الذي يمسك ياقة اللحاف. مهما تقلّبت طوال الليل، أشدّ قبضتي كي لا تهرب الياقة. لحاف بلا تجعدة واحدة عند الاستيقاظ، هذا هو أجر مناوبتي الليلية."},"ICON-1866":{"nm":"مشبك تثبيت الطبقة العلوية","de":"تحاول الطبقة العلوية أن تنزلق خلسة عند أول فرصة. في كل مرة، يعضّ المشبك الزاوية بقوة ليحفظ مكانها. عنيد صامت واحد يحافظ على ترتيب الفراش من زاوية لا تُرى."},"ICON-1867":{"nm":"مُملّس تجاعيد الشرشف","de":"التجاعيد الدقيقة التي تتجمع على الشرشف طوال الليل تشبه بطريقة ما تجعدات القلب. كالقماش الذي يصير أملسًا بمسحة واحدة من المُملّس، أتمنى لو يُكوى يوم مضطرب برقة كهذه أيضًا."},"ICON-1868":{"nm":"قاعدة تهوية المرتبة","de":"حتى المرتبة تحتاج فسحة لتتنفس. حين تفتح القاعدة ممرًا للهواء من الأسفل، تتسرب الرطوبة وتنساب النداوة الجافة. النوم الجيد يبدأ بهدوء من ذلك الهواء الذي يسند ظهرك."},"ICON-1869":{"nm":"غطاء سحّاب كيس اللحاف","de":"تلك الفوضى الليلية حين يستمر الحشو بالخروج أثناء تبديل كيس اللحاف. غطِّ السحّاب بطبقة واحدة، ولن تستيقظ من اصطدام قدمك به. سلام كبير تجلبه طبقة صغيرة واحدة."},"ICON-1870":{"nm":"وسادة منع تكتل الحشو","de":"حشو الوسادة سرعان ما يتجمع في جانب واحد، مكوّنًا تلة صغيرة. حين تصمد الوسادة بثبات بين الفراغات، يبقى التسطيح حتى النهاية. بفضلها، تعود نعومة كأنها جديدة كل ليلة دون فشل."},"ICON-1871":{"nm":"خطاف مرونة شرشف السرير","de":"الشرشف يحاول دائمًا أن يتقشر ببطء إلى جانب واحد. علّق الخطاف في الزوايا واشدّه بشد، فلن يتزحزح مهما تقلّبت طوال الليل. الشد يصبح بهدوء أساس النوم العميق."},"ICON-1872":{"nm":"وسم تبديل غطاء الوسادة","de":"حين تتساءل فجأة إن كنت غسلت غطاء الوسادة اليوم، تجيبك وسمة واحدة بوضوح. جدولًا تنساه مرارًا من كثرة النوم، تتذكره هذه العلامة الصغيرة بدلًا عنك بأمانة."},"ICON-1873":{"nm":"فاصل كتاب مذكرات الأحلام","de":"حلمًا يتبعثر بين أصابعك لحظة استيقاظك، تحبسه إشارة المرجعية في الصفحة التي وضعتها. افتحه فيبقى بحر الليلة الماضية وسماؤها كما هما، جسر صغير موضوع برفق بين النوم والكتابة."},"ICON-1874":{"nm":"حصاة الضجيج الأبيض","de":"ليلة هادئة جدًا كثيرًا ما توقظك بدلًا من أن تُنيمك. حين تُطلق الحصاة صوتًا يشبه حفيف المطر الناعم، يهدأ القلب ببطء تبعًا لذلك النسيج. حجر صغير يهدّئ الصمت برفق."},"ICON-1875":{"nm":"رقاقة نوم استشعار الحرارة","de":"سواء كانت جبهتك دافئة أم أطراف قدميك باردة أثناء نومك، ترقب الرقاقة بهدوء إلى جانبك. بفضل حارسٍ ليلي يجد بلطف الحرارة المناسبة تمامًا لجسدك، يستمر النوم دون انقطاع حتى الفجر."},"ICON-1876":{"nm":"مشبك ستارة التعتيم","de":"شمس الصباح مجتهدة جدًا لدرجة أنها تتسلل باستمرار عبر فجوة الستارة. عضّ الطرفين بقوة بالمشبك، فتعود الغرفة سوداء كمنتصف الليل من جديد. شريك موثوق لغفوة إضافية واحدة."},"ICON-1877":{"nm":"حامل إسقاط ضوء القمر","de":"أطفئ الضوء فيرتفع قمر عبر السقف. الوهج الناعم الذي تقذفه القاعدة يحوّل الغرفة إلى سماء ليلية صغيرة. ذلك الشعور بالنوم وأنت تنظر إلى القمر، محفوظ هنا عند رأس سريرك تمامًا."},"ICON-1878":{"nm":"معلّاق كيس عطر النوم","de":"كيس يحمل رائحة اللافندر والعشب يتمايل برفق عند رأس السرير. مع تسلل العطر إلى أنفك، ترتخي كتفاك رويدًا، وكيس عطر واحد يستدعي النوم قبل الوسادة."},"ICON-1879":{"nm":"دبوس صندوق موسيقى التهويدة","de":"لفّ النابض برفق فتنساب لحن صغير. التهويدة التي تدور من طرف الدبوس تشبه تمامًا الإيقاع الذي كانت الجدة تربّت به على ظهرك. كل نغمة تُثقل الجفون ببطء."},"ICON-1880":{"nm":"كوب النبات الرطب","de":"أنا كوب يُنبت النباتات بالماء الصافي بدل التراب. وأنت تراقب الجذور الدقيقة تطفو في الماء، يصبح هواء الغرفة نفسه أكثر رطوبة قليلًا. بئر صغيرة خضراء، تتجمع فوق المكتب."},"ICON-1881":{"nm":"قارورة جمع شظايا الأحلام","de":"الأحلام المسكوبة في السبات بلا شكل، وحين تستيقظ تتسرب بين أصابعك. أن توقف شظية واحدة على وشك الاختفاء بغطاء القارورة، وتحبسها حتى الصباح؛ الرغبة في التذكر تبدأ من مكان صغير كهذا."},"ICON-1882":{"nm":"صينية نظارات جانب السرير","de":"لحظة تخلع نظارتك وتضعها جانبًا، وبغرابة، ينزل معها تعب يوم كامل. هذه البقعة الصغيرة عند رأس سريرك موجودة لتستقبل تلك الحركة الواحدة. صينية تُضبب العالم بهدوء قبل النوم."},"ICON-1883":{"nm":"حلقة سنادة كوب طاولة السرير","de":"أثر دائري واحد يتركه كوب الماء قد يبدو تافهًا، لكنه ندبة في خشب الطاولة الليلية. حلقة صغيرة تُركَّب لمنع ذلك. القلب المهتم يعمل دائمًا بصمت في هذه الأماكن غير المرئية."},"ICON-1884":{"nm":"مسطرة طيّ اللحاف المربع","de":"حتى طيّ اللحاف مربعًا ومرتبًا له نسيجه. حاذِ الزوايا باتباع هذه الأداة المحدّدة للزاوية، حتى القلب المضطرب يُملَّس مرة واحدة. المكان المرتب هو أدبّ تحية لافتتاح اليوم."},"ICON-1885":{"nm":"خطاف سلك الشحن جانب السرير","de":"خطاف عُلّق عند رأس السرير لأنني كرهت انزلاق سلك الشحن إلى الأرض طوال الليل. السلك الذي يمتلئ بالطاقة بهدوء وأنت نائم ينتظر، مشحونًا تمامًا، أطراف أصابعك في الصباح."},"ICON-1886":{"nm":"سلة وجبات خفيفة جانب السرير","de":"سلة تجمع الوجبات الخفيفة المفضلة في متناول اليد. تحضير لطيف مُعَدّ استباقًا لجوع متأخر الليل. صوت خشخشة التقاط واحدة في الظلام محبب دون سبب واضح."},"ICON-1887":{"nm":"جناح حامل كتاب وقت النوم","de":"جناح يسند بلطف الصفحة المفتوحة كي لا تفقد سطرك حتى لو غلبك النعاس. الصفحة الواحدة التي أغلقتها لحظة إغماض عينيك تنتظرك في المكان نفسه الليلة القادمة."},"ICON-1888":{"nm":"قاعدة حجرية لمنبه جانب السرير","de":"حتى منبه الصباح يحتاج مكانه الثابت الذي لا يهتز. القاعدة الحجرية المستديرة تتحمل وزنه بثقل، وتحرس مكانها كوعد لا ينزلق حتى مع مجيء الفجر."},"ICON-1889":{"nm":"مسمار تعليق قناع النوم","de":"مسمار لتعليق قناع النوم الذي حجب الضوء طوال الليل، كي يتنفس القماش خلال النهار. منح مكان جاف لقماش أدّى واجبه؛ العناية الصغيرة تتسرب بهذه النقاوة."},"ICON-1890":{"nm":"مشبك مصباح يدوي جانب السرير","de":"مشبك يمسك الضوء الصغير الذي تحتاجه في منتصف الليل موجّهًا إلى الجهة التي تريد. عضّ المصباح اليدوي على حافة السرير، فتصير اليد التي كانت تتحسس الظلام أكثر راحة. لمسة تحدد اتجاه الضوء."},"ICON-1891":{"nm":"حبل ربط ستارة الفاصل","de":"حبل ربط يمسك الستارة التي تفصل مساحة مشتركة. إنها مجرد قطعة قماش رقيقة، لكن ما وراءها ليل خاص بأحدهم. حدّ لطيف يحمي نوم كل شخص في غرفة مشتركة."},"ICON-1892":{"nm":"لوح توزيع المقبس المشترك","de":"لوح خشبي صُنع كي يتشارك كثيرون المقبس الوحيد. يوزّع الكهرباء بالتساوي كي لا يظلم ليل أحد. العيش معًا يبدأ، في النهاية، من مشاركة أشياء صغيرة كهذه."},"ICON-1893":{"nm":"حجر التنازل عن سطوع الإضاءة","de":"حين يكون الضوء ساطعًا جدًا، تُمرّر حجرًا بدل الكلمات. \"هل يمكن أن تخفّفه قليلًا؟\" هذا الشيء الصغير ينقل تلك الجملة الواحدة نيابة عنك. أرقّ طلب في غرفة مشتركة."},"ICON-1894":{"nm":"رمز التنازل عن وقت الاستيقاظ","de":"رمز صغير يُمرَّر إلى راحة يد من يستيقظ أولًا. من ينال مزيدًا من نوم الفجر ومن يستيقظ أولًا، يحدده هذا الرمز دون خلاف. القلب الذي يرتب دور التنازل بطرف الإصبع."},"ICON-1895":{"nm":"حلقة رقم علاّقة الملابس المشتركة","de":"حلقات أرقام مخصصة لعلاّقات ملابس يشترك فيها كثيرون. كي لا يختلط مكان أحد بآخر، رقم صغير واحد يصنع النظام بهدوء. خط لطيف مرسوم في حياة يومية سهلة الاختلاط."},"ICON-1896":{"nm":"غطاء درجة سلّم السرير الطابقي","de":"غطاء يُركَّب على الدرجة الصاعدة إلى الطابق العلوي. كي لا تكون باردة أو زلقة عند لمس قدم حافية لها، يعتني بسلامة درجة واحدة. هذه العناية الصغيرة عند طرف السلّم تسند بثبات أحلام الطابق الأعلى."},"ICON-1897":{"nm":"ذراع حامل المناديل المشترك","de":"حامل بشكل ذراع لتعليق مناديل الحمام المشترك. وُضع بحيث يمكن لأي شخص سحب ورقة بيد واحدة بسهولة. قد يبدو تافهًا، لكنه لمسة تجعل صباح كثيرين ينساب بسلاسة."},"ICON-1898":{"nm":"رقاقة دور معطّر الجو","de":"رقاقة تسجل من دوره ليعيد ملء معطّر الجو. حتى خيط رائحة خفيف واحد وعد بتحمل المسؤولية بالتناوب. الرائحة الجميلة لا تأتي مجانًا، بل تتفتح في دور أحدهم."},"ICON-1899":{"nm":"مقبض مصباح النوم المشترك","de":"مقبض مصباح ليلي يشعله ويطفئه كثيرون معًا. اليد التي بقيت مستيقظة آخر الجميع تجمع الضوء أخيرًا. وعد هادئ لمن يتشاركون غرفة واحدة، يتناقلون فيه وهجًا ناعمًا."},"ICON-1900":{"nm":"تجويف كوب مسند ذراع الأريكة","de":"تجويف دائري محفور في مسند ذراع الأريكة. يمكنك ترك الكأس من يدك للحظة دون قلق الانسكاب. مكان الراحة يحتاج موضعًا لكأس واحد قبل أن يستطيع القلب أن يتمدد أخيرًا بارتياح."},"ICON-1901":{"nm":"مقبض سحّاب حشوة الوسادة","de":"مقبض صغير معلّق بالسحّاب الذي يفتح ويغلق حشوة الوسادة. حلقة واحدة تُغني عن عناء تغيير الغطاء عند الغسيل. أصابع تعتني حتى بالداخل غير المرئي - فحنان تدبير المنزل يختبئ هناك دائمًا."},"ICON-1902":{"nm":"وسادة إسناد لفجوة ظهر الأريكة","de":"وسادة تملأ الفجوة في مسند الظهر وتدعم أسفل الظهر. تملأ الفراغ حتى لا يتألم ظهرك حتى بعد جلوس طويل. الراحة التي يتعرّف عليها جسدك أولًا، بتنهيدة \"آه، هذا هو\"، في لحظة الاتكاء."},"ICON-1903":{"nm":"شريط تثبيت زوايا الوسادة","de":"شريط يُمسك بزوايا الوسادة التي كانت تزحف معك كلما جلست. يثبّتها في مكان واحد كي لا تنزلق. الأناقة تبدأ من تثبيت صغير وعنيد كهذا."},"ICON-1904":{"nm":"شريط حماية درزات الوسادة","de":"أول مكان يبلى في الوسادة هو دائمًا درزة الزاوية. شريط حماية يُلفّ حول ذلك الموضع مسبقًا فيمنعه من التمزق. قلب يتمنى أن يبقيها قريبة طويلًا، متين كالغرزة نفسها."},"ICON-1905":{"nm":"جيب جهاز التحكم لفجوة الأريكة","de":"جهاز التحكم الذي كان يختفي دائمًا بين الوسائد وجد أخيرًا بيتًا خاصًا به. جيب صغير يُدسّ في فجوة الأريكة. أن تعرف أن ما ظننته ضائعًا موجود هناك دومًا، طمأنينة أكبر مما تتوقع."},"ICON-1906":{"nm":"رباط لفّ بطانية الركبتين","de":"رباط يُستخدم للفّ بطانية الركبتين وربطها. الدفء الذي يتبعثر حين تُترك مفرودة، يُرتَّب بعناية لليلة التالية. هكذا يمكن للدفء أيضًا أن يُحفظ ليُخرَج ويُسدَل من جديد غدًا."},"ICON-1907":{"nm":"زر غطاء مسند القدمين","de":"زرّ يُثبّت غطاء مسند القدمين، ذلك الجزء الذي يبلى أسرع من ملامسة الأقدام، ليسهل تبديله. تلك النقرة الواحدة تُطيل عمر القماش. القلب الذي يريد استخدام الأشياء طويلًا دقيق حتى في أصغر التفاصيل."},"ICON-1908":{"nm":"غطاء انزلاق أرجل الأريكة","de":"حتى الأريكة الثقيلة يجب ألا تخدش الأرضية. غطاء ناعم يُلبَس أطراف الأرجل الأربعة، يتمشى بحذر ليصون الأرضية الخشبية. الأثاث الحريص حتى أطراف قدميه يكسب محبة أكبر بطريقة ما."},"ICON-1909":{"nm":"حامل تجميع أجهزة التحكم","de":"حامل يُصفّ جنبًا إلى جنب أجهزة التحكم التي كانت تتدحرج وتتبعثر في كل اتجاه. حين تقف العصي الطويلة والقصيرة في صفّ مرتب، هذا وحده يُهدئ أجواء الغرفة درجة."},"ICON-1910":{"nm":"خطاف شحن يد التحكم","de":"خطاف يُعلَّق عليه يد التحكم بعد جولة لعب حماسية لتُشحَن. بينما تتدلى وتملأ طاقتها بهدوء، ترتاح يداك أيضًا للحظة. هذه الوقفة القصيرة تُهيّئ الجولة التالية بثبات."},"ICON-1911":{"nm":"كيس قطع لعبة الطاولة","de":"كيس صغير يحتضن قطعًا بألوان متعددة. القطع المنتظرة داخل الكيس للجولة القادمة تُصدر صوت طقطقة كلما هزّه أحد. عند ذلك الصوت يستيقظ أولًا شعور \"جولة أخرى؟\"."},"ICON-1912":{"nm":"صحن رمي النرد","de":"صحن مخصص لرمي النرد. الحظ الذي كان يقفز خارج الطاولة ويختفي، تحبسه الحافة بالداخل. في تلك اللحظة القصيرة حين يتدحرج ثم يتوقف، تتوقف أنفاس الجميع معًا للحظة."},"ICON-1913":{"nm":"رباط تثبيت حزمة الأوراق","de":"رباط يشدّ حزمة أوراق اللعب كي لا تتبعثر. حتى تُخلَط، يبقى ترتيبها وعدًا بحدّ ذاته. في حركة نزع الرباط لتُفتَح الأوراق، تبدأ أخيرًا حكاية الجولة."},"ICON-1914":{"nm":"مشبك ترتيب أسلاك الكونسول","de":"مشبك يُمسك الأسلاك المتشابكة خلف الكونسول ويُسرّحها بترتيب. يُصلح الفوضى بصمت في مكان بالكاد يُرى. النظام دائمًا يكتمل هكذا بهدوء من الخلف."},"ICON-1915":{"nm":"قرص تدوير النقاط","de":"قرص صغير يُدار لإظهار النقاط. طقّة، ومع كل درجة يرتفع الرقم، تتبعه الهتافات. حتى دون عدّ في الرأس، تتذكر أطراف الأصابع أولًا نتيجة ذلك اليوم."},"ICON-1916":{"nm":"قاعدة تثبيت لوحة اللعب","de":"قاعدة تُسند لوحة اللعبة بميل، تضبط الزاوية كي يرى الجميع الجالسون حولها اللوحة بنظرة واحدة. كي لا يضطر أحد لمدّ رقبته، تفرش بهدوء رؤية عادلة للجميع."},"ICON-1917":{"nm":"كأس سحب الترتيب","de":"كأس تُدسّ فيه اليد لسحب ترتيب اللعب. عود واحد يُتحسَّس ويُقبَض عليه يقرر من يبدأ أولًا. في تلك اللحظة القصيرة من الاتكاء قليلًا على الحظ، يخفق قلب الجميع معًا داخل الكأس المستدير."},"ICON-1918":{"nm":"صحن مقسّم لمشاركة الوجبات الخفيفة","de":"صحن مقسّم لتقديم الوجبات الخفيفة حسب نوعها. حين تُفصَل الأماكن، يمكن اختيار المفضّل دون تصادم الأيدي. العناية التي راعت من سيشاركون الطعام تسكن كل قسم من الصحن."},"ICON-1919":{"nm":"غطاء تدفئة إبريق الشاي","de":"غطاء يلفّ كتفي إبريق الشاي ليحفظ دفأه. يُدثّره كي لا يبرد الشاي وهو ينضج ببطء. إنها رغبة أطراف الأصابع في تقديم فنجان دافئ يبقى دافئًا حتى النهاية."},"ICON-1920":{"nm":"مسند كيس الشاي","de":"مسند يُرفع عليه كيس الشاي المنقوع ليرتاح قليلًا. يستقبل حتى آخر قطرة كي لا تسيل شيء منها. مكان يمنح حتى الورقة التي أدّت دورها ختامًا أنيقًا."},"ICON-1921":{"nm":"حلقة تمييز الأكواب المشتركة","de":"ستة أكواب متطابقة على رفّ غرفة الاستراحة. بدل السؤال عن صاحب كل كوب، ألبسناها حلقات بألوان مختلفة. علامة صغيرة واحدة تربط بهدوء ستة أشخاص، لكلٍّ ذوقه الخاص، إلى مكان واحد على نفس الطاولة."},"ICON-1922":{"nm":"سلة مشاركة الفشار","de":"بينما يمرّ من يد إلى يد، يُحيّيك بخاره الشهي أولًا. إن كان هناك ما لا ينقص غرابةً كلما اغترفت منه حفنة، فهو قلب أمسية تُقضى مشاركةً وأنتم جالسون معًا."},"ICON-1923":{"nm":"علبة ملقط مكعبات السكر","de":"تُسقط مكعب سكر بالملقط، طقّة، في فنجان الشاي. مشاهدة زواياه البيضاء تذوب ببطء وتختفي: أدبٌ غير متعجّل للحلاوة، تعلّمته أول مرة على طاولة شاي الجدّة."},"ICON-1924":{"nm":"بساط مانع انزلاق الصينية","de":"حتى لو مالت الصينية، تحافظ الأكواب على مكانها. كما تفعل دائمًا الأشياء التي تُمسك بثبات من الأسفل، يتحمّل البساط وحده لحظة الانزلاق الوشيكة، ثم يُطبق فمه في النهاية دون أن يشتكي."},"ICON-1925":{"nm":"كوب تثبيت شفاطة المشروب","de":"انتصاب الشفاطة يمنع المشروب والقلب معًا من الاضطراب. في عصر تُصبح فيه الطاولة مرتبة بفضل انتصاب بسيط واحد، يحتضن الكوب عمودًا صغيرًا ويسند بهدوء ساعات الكسل."},"ICON-1926":{"nm":"ملتقط فتات الكعك","de":"قرمشة، وفي لحظة تفتّت الكعكة تتجمّع الفتات المتساقطة هنا. أن تحتضن حتى الأثر الذي تركته أشهى قضمة: لمسة ختامية هادئة للمائدة، حانية حتى مع آخر فتات."},"ICON-1927":{"nm":"خيط تعليق الصور بالمشابك","de":"تُعلَّق صور بولارويد واحدة تلو الأخرى بمشابك على خيط ممدود كحبل الغسيل. بينما تخفق ابتسامات اليوم في النسيم وتجفّ، تصبح مساحة من الحائط معرضًا صغيرًا مضيئًا للذكريات."},"ICON-1928":{"nm":"بكرة خيوط الذكريات","de":"بكرة حُلّ خيطها المتشابك ولُفّ من جديد بترتيب. أشياء استمرت، عُقدت عند كل موضع انقطاع. إذا أُعيد لفّ الذاكرة ببطء هكذا، دورة تلو الأخرى، يطول من جديد طريق ظننته قد قصُر."},"ICON-1929":{"nm":"غطاء ثقب مسمار تعليق الحائط","de":"غطاء صغير مستدير يخفي أثر المسمار. غطِّ برفق حتى الندبة الصغيرة المتبقية بعد إزالة ما كان معلقًا هناك، ويعود الحائط إلى وجه أملس كأن شيئًا لم يكن."},"ICON-1930":{"nm":"إطار إدراج صورة جماعية","de":"صورة جماعية لستة أشخاص التُقطت بأكتاف متلاصقة. في لحظة إدخالها في الإطار، تُختم ضحكة ذلك اليوم ودفؤه معًا. الإطار هو اليد التي توقف يومًا عابرًا بأكثر الطرق هدوءًا."},"ICON-1931":{"nm":"لوحة فلين للملاحظات","de":"لوحة بنية مزدحمة بآثار الدبابيس. وعد يجب ألا يُنسى، ورقة تشجيع تركها أحدهم، مهام اليوم كلها تُثبَّت طبقة فوق طبقة. جدار موثوق بجانب المكتب يتذكّر بدلًا من رأسك."},"ICON-1932":{"nm":"عقدة تعليق إكليل الباب","de":"حتى إكليل واحد يُعلَّق على الباب يتطلّب براعة الأصابع. يجب ربط العقدة بإحكام كي لا تسقط في موسم الرياح. القلب الذي يرحّب بأحدهم يشتدّ دائمًا أولًا من مكان لا يُرى."},"ICON-1933":{"nm":"غطاء بندول ساعة الحائط","de":"غطاء قماشي يلفّ البندول المتأرجح ليصدّ عنه الغبار. حتى قياس الزمن يحظى برعاية كهذه. احمه برفق من البلى، وتبقى ساعة الحائط بجانبنا مدة أطول قليلًا."},"ICON-1934":{"nm":"لوحة تجميع الملصقات","de":"الملصقات التي كانت تتبعثر في كل درج تجتمع على لوحة واحدة وتصطفّ في صف. شخصية مفضلة، نجمة لامعة، ورقة بخط اليد. حين تُصفّ فرحة الجمع الصغيرة بترتيب، يستقيم القلب أيضًا."},"ICON-1935":{"nm":"حبل ربط الأعلام الزخرفية","de":"حبل يصل الأعلام الملوّنة في خيط واحد. عيد ميلاد أو ترحيب، في لحظة عبور الحبل السقف، تتحول غرفة عادية إلى بيت احتفال. الاحتفال هو عمل وصل قلب مقطوع من جديد."},"ICON-1936":{"nm":"مسند فلين للغلاية الكهربائية","de":"قطعة فلين واحدة تسند قاعدة الغلاية الساخنة. كي لا تحترق الطاولة، تحتضن تلك الحرارة وحدها. عناية صغيرة تسند بصمت كي لا يترك دفء أحدهم أثرًا."},"ICON-1937":{"nm":"صينية فتات المحمّصة","de":"الفتات التي يسقطها الخبز المحمّص الذهبي تتدحرج إلى الصينية. اسحبها ورجّها فحسب، وينتهي الأمر. تستقبل صباحًا مزدحمًا دون كلام، وتُهيّئ نفسها نظيفة من جديد للوجبة التالية."},"ICON-1938":{"nm":"حلقة دوران الميكروويف","de":"على الحلقة الدوّارة، يرسم الطبق ببطء دورة كاملة. ذلك الدوران، المُدار كي يتسخن كل شيء بالتساوي، يُحيي أرزّ الأمس البارد ليعود وجبة تتصاعد منها بخار ساخن من جديد."},"ICON-1939":{"nm":"غطاء موقد الحث الصغير","de":"مهما تناثر الزيت في كل الاتجاهات، يبقى الموقد نظيفًا. غطاء واحد يفصل بين الحرارة الشديدة واليدين. الأشياء التي تقف حائلًا دون أن تُرى تصون المطبخ مكانًا لا يحترق."},"ICON-1940":{"nm":"غطاء تنفيس بخار طنجرة الأرز","de":"صوت فحيح تسرّب البخار. بفضل غطاء صغير يُطلق برفق الضغط المحتبس، يفتح الأرز المطهو حديثًا غطاءه بأنعم وجه. لا استعجال في وقت النضج بالبخار."},"ICON-1941":{"nm":"حامل تثبيت المغرفة","de":"ثبّت المغرفة التي تُحرَّك بها الشوربة منتصبة. قلب صغير لا يريد أن يترك ولو بقعة واحدة على سطح المطبخ. نظافة المطبخ تبدأ دائمًا من هذه الزوايا الصغيرة غير الملحوظة."},"ICON-1942":{"nm":"غطاء سيليكون لمقبض القدر","de":"ثبّت السيليكون على مقبض قدر ملتهب ولن تحترق يدك. طبقة واحدة تتوسط بين الحرارة وراحة اليد. تحمي من يطهو وجبات دافئة من أقرب مكان ممكن."},"ICON-1943":{"nm":"مصفاة ترسبات الغلاية الكهربائية","de":"حتى الماء المغلي يوميًا يتراكم عليه أثر خفيف. شبكة دقيقة تصفّي الترسبات بهدوء، فلا يُصَبّ سوى فنجان صافٍ. يد دؤوبة تصون أول رشفة شاي من مكان لا يُرى."},"ICON-1944":{"nm":"مؤقّت طهي بأرجل مشبك","de":"ثلاث دقائق أخرى فقط، يقول المؤقّت، عاضًّا حافة الطاولة بإحكام بأرجله المشبكية. بينما ينضج المعكرونة، يقف مستندًا على أرجله الصغيرة، يعدّ تكتكةً تلو أخرى أكثر لحظة يُنتظر في اليوم."},"ICON-1945":{"nm":"كوب تصريف ماء أدوات المائدة","de":"ماء يتقاطر من الملاعق والشوك المشطوفة للتو. حين يجمع كوب التصريف بهدوء تلك الرطوبة، تجفّ المائدة سريعًا. النظافة عناية حانية تعتني حتى بقطرة ماء واحدة."},"ICON-1946":{"nm":"رفّ فواصل لتثبيت الأطباق واقفة","de":"تُثبَّت الأطباق منتصبة، مقسّمة إلى خانات. الأواني التي كانت تخدش بعضها عند تكديسها تحصل كلّ منها على مكانها الخاص. الترتيب هو، في النهاية، منح كل شيء خانته التي لا تصطدم فيها بالآخرين."},"ICON-1947":{"nm":"حلقة مطابقة العيدان الصينية","de":"مرّر العيدان التي فقدت رفيقتها ووحدها في الحلقة، وأعد جمع الاثنتين. فعود واحد سرعان ما يفقد فائدته، فهذه الحلقة الصغيرة التي تربطهما جنبًا إلى جنب تحفظ نظام الدرج."},"ICON-1948":{"nm":"شجرة تعليق الأكواب المتفرعة","de":"علّق الأكواب واحدًا تلو الآخر على حامل يتفرّع كالأغصان. بينما تجفّ الرطوبة على كل كوب مقلوب، تقف زاوية من المطبخ بهدوء كشجرة صغيرة أنيقة."},"ICON-1949":{"nm":"مقبض صينية أدوات المائدة","de":"صينية ترقد فيها الملاعق والعيدان والشوك جنبًا إلى جنب في خانات. أمسك المقبض وارفع الصينية كاملة، فيصبح تجهيز المائدة أخف بكثير. جماليات النظام تسكن الدرج أيضًا، بلا استثناء."},"ICON-1950":{"nm":"لوح تجفيف الأكواب المقلوبة","de":"اقلب الأكواب المغسولة، وتتساقط قطرات الماء، تقّ تقّ. بينما تجفّ ببطء عند نافذة مشمسة، يستعيد كأس الزجاج بهدوء شفافيته الأولى استعدادًا للرشفة التالية."},"ICON-1951":{"nm":"مشط تنظيف فراغات الشوكة","de":"أسنانه الدقيقة تكنس برفق الطعام من بين شعب الشوكة. بفضل لمسة تعتني حتى بأضيق الفراغات، تبدأ الوجبة التالية دائمًا بأول قضمة نظيفة تمامًا."},"ICON-1952":{"nm":"لبّاد مانع انزلاق تكديس الأطباق","de":"كدّس الأطباق فيصدر صوت اصطكاك حاد بين الخزف. رقاقة لبّاد واحدة موضوعة بينها تُخمد ذلك الاحتكاك. سرّ الاستخدام المشترك الطويل يكمن في أن تترك كل منها الأخرى أنعم قليلًا."},"ICON-1953":{"nm":"خيط حلقي لتعليق ملعقة الشاي","de":"علّق ملعقة الشاي الصغيرة الظريفة بالحلقة وثبّتها على الحائط. لا تُدفن في الدرج بل تلمع دائمًا في متناول اليد - أداة صغيرة تحتلّ مكانها بفخر. حتى لتدبير المنزل موضع ثابت لكل شيء."},"ICON-1954":{"nm":"صينية تقسيم رفّ الثلاجة","de":"قسّم رفّ الثلاجة إلى أقسام، ويحصل كل مكوّن على بيته الصغير. الأشياء التي كانت تختلط وتُنسى تجد مكانها، وفي كل مرة تفتح الباب ترى بوضوح ما يوجد وأين."},"ICON-1955":{"nm":"مشبك تثبيت كيس التجميد","de":"أمسك كيس التجميد نصف الفارغ بالمشبك وأوقفه منتصبًا. كي لا ينقلب فيسيل، وكي يسهل إيجاده لاحقًا. حتى في برودة الفريزر تسكن حكمة ربة منزل بارعة ومرتبة."},"ICON-1956":{"nm":"مشدّ إحكام غطاء الزجاجة","de":"زجاجة تُترك مغلقة بشكل غير محكم سرعان ما تفقد غازها. تلك اللفة الواحدة للمعصم، شدّ الغطاء بإحكام، تحبس الرائحة والفوران بالداخل سليمين حتى صباح الغد. البراعة تلمع في التفاصيل الصغيرة."},"ICON-1957":{"nm":"بساط مانع انزلاق حجيرات البيض","de":"بطانة تحتضن البيض المستدير في خانات كي لا يتدحرج وينكسر. الرغبة في معاملة أكثر الأشياء هشاشة بأكبر عناية تجلس صغيرة وحانية في زاوية من باب الثلاجة."},"ICON-1958":{"nm":"شريط توسيع جيب باب الثلاجة","de":"مدّد جيب باب الثلاجة قليلًا إلى الجانب لتصنع خانة إضافية. فحين يكبر المنزل، يجب أن تكبر مساحته أيضًا. في مهارة توسيع مكان ضيّق، ينعكس قلب ربة منزل بارعة."},"ICON-1959":{"nm":"غطاء ضغط لبقايا الطعام","de":"غطاء يُضغط برفق فوق بقايا الأطباق الجانبية. يحرسها بهدوء كي لا تجفّ أو تمتصّ روائح أخرى. يد حانية تدّخر بعناية حتى ما تبقى من وجبة واحدة."},"ICON-1960":{"nm":"ريشة توجيه اتجاه الهواء البارد","de":"إلى أي جهة سيتدفق الهواء البارد؟ ريشة صغيرة تحدّد الاتجاه بهدوء. حرّك بطرف إصبعك مسار النسيم غير المرئي، ويصل البرد حتى أعمق زاوية داخلية."},"ICON-1961":{"nm":"وسادة امتصاص رطوبة درج الخضار","de":"في أظلم زاوية بدرج خضار الثلاجة، أحتفظ بصمت بالرطوبة. المعجزة الصغيرة أن الورقة الذابلة أمس تعود منتعشة صباحًا. حتى دون أن يعرف أحد، تبقى النضارة دائمًا مسؤوليتي."},"ICON-1962":{"nm":"حاجز منع تدحرج علبة المشروب","de":"يلتصق بهدوء بحافة الطاولة، ويُمسك بقدم العلبة التي أوشكت على التدحرج. مشروب كاد ينسكب، طاولة كادت تُمسح. طمأنينة تدبير المنزل تبدأ من حاجز صغير لا يُلاحَظ كهذا."},"ICON-1963":{"nm":"قرص تدوير مهام النوبة","de":"اليوم، من يغسل الأطباق، ومن يفرز إعادة التدوير. دورة واحدة للسهم وتنحلّ كل مشاجرة بسلاسة. في بيت يتزاحم فيه خمسة، يصبح التناوب أرقّ أنواع السلام."},"ICON-1964":{"nm":"شريط سيليكون لتمييز أكواب الأفراد","de":"خمسة أكواب متشابهة، وصباح مليء بالحيرة عن صاحب كل منها. ألبس شريطًا ملونًا بحجم المعصم، ويتّضح الوعد الصغير \"هذا كوبي\"، فيسكن نظام حنون مائدة الفطور برشاقة."},"ICON-1965":{"nm":"حلقة تحديد حصص الوعاء","de":"في يوم مزدحم، تصبح العلامات داخل الوعاء صديقًا يُعتمد عليه. خانة للأرز، وخانة للأطباق الجانبية. لا قليلًا جدًا ولا كثيرًا، خطّ حنون يخبرك بهدوء بمقدار ما تأكله اليوم بالضبط."},"ICON-1966":{"nm":"وعاء ملقط لمشاركة الوجبات الخفيفة","de":"ادفع الكيس كاملًا نحو أحدهم، ويبقى أثر يدك المحرج. وزّعها واحدة تلو الأخرى بالملقط، وعندها فقط تتساوى حصة الجميع. المشاركة تليق بها الأيدي المرتبة أكثر من الحفنات."},"ICON-1967":{"nm":"حامل بطاقة اسم نوبة الغلاية","de":"كان غلي الماء دائمًا نصيب اليدين ذاتهما. منذ بدأنا تعليق بطاقات الأسماء بالتناوب على الحامل بجانب الغلاية، صار فنجان الشاي الدافئ مودّة تُنقَع بالتناوب."},"ICON-1968":{"nm":"شريحة تنبيه \"لا تترك بقايا\" على المقلبة","de":"كلمة \"لا تترك شيئًا\" معلّقة صغيرة عند طرف المقلبة. قد تبدو كنصيحة مزعجة، لكن لا شيء كريه فيها، لأن روح المائدة القديمة، حيث كانت كل وجبة تُقدَّر، تسكن هنا."},"ICON-1969":{"nm":"خطاف جيب أدوات المائدة الشخصية","de":"لم تعد أدوات المائدة تتدحرج فضفاضة في الدرج. في لحظة دخول كل طقم إلى جيبه الخاص وتعليقه على الحائط، تصطفّ أماكن أفراد الأسرة الخمسة جنبًا إلى جنب. ترتيب صغير يسند سلام كل يوم."},"ICON-1970":{"nm":"شريحة فلين لتحديد مقاعد المائدة","de":"افرش قطع الفلين على المائدة، ويتّضح من يجلس أين. المقعد الذي تجلس فيه دائمًا، الوجه الجانبي الذي تواجهه دائمًا. المكان المحدد هو أهدأ برهان على كلمة \"نعيش معًا\"."},"ICON-1971":{"nm":"خطاف لفّ مئزر النوبة","de":"المئزر الذي انتهى مع غسل الأطباق لا يُرمى في أي مكان. مطويًا ومعلّقًا على الخطاف، يصبح جاهزًا نظيفًا صباح الغد. قلب يفكر بالشخص التالي يسكن في هذه العقدة الصغيرة."},"ICON-1972":{"nm":"كيس طيّ الشباشب التي تُستخدم مرة واحدة","de":"يوم قدوم الضيوف، أُفرَش كاملًا بكيسي. النعال التي تُستخدم مرة واحدة والمرتبة بالداخل ترحّب بأقدام وصلت للتو بدفء وثير. الضيافة تبدأ دائمًا بهدوء من المدخل."},"ICON-1973":{"nm":"جيب أذيال ورق أعواد القطن","de":"حين تُستنفد أعواد القطن ولا يبقى سوى ذيولها الورقية، أجمع أطرافها بعناية. أن تُخصَّص مساحة حتى لما سيُرمى. أعرف أن سرّ المكتب المرتب يكمن في لطف كهذا بأمور صغيرة."},"ICON-1974":{"nm":"حزمة بكرات عدة الخياطة","de":"اربط الخيوط الملونة معًا كي لا تتفكك بكراتها وتتشابك. زرّ سقط، كمّ تراخى - هذه الحزمة الواحدة تُصلحهما سريعًا. خياطة يدوية تنقذ بهدوء ليلة يوم مهمّ."},"ICON-1975":{"nm":"قطعة صابون مغلّفة منفردة","de":"قطعة صابون مغلّفة بعناية بمفردها تُوضع في كل غرفة ضيوف. جسد بحجم راحة اليد يغسل غبار اليوم بحفنة رغوة واحدة. النظافة تبدأ دائمًا من أماكن صغيرة كهذه."},"ICON-1976":{"nm":"كبسولة طيّ قبعة الاستحمام المطوية","de":"اطوِ ثنياتها فتنطوي في راحة يدك، وافردها فتلفّ الشعر بإحكام. كي لا ينهار شعر مصفّف بدشّ واحد. هذه الطبقة الوحيدة تحمي أناقة صباح الغد."},"ICON-1977":{"nm":"غلاف حماية فرشاة الأسنان","de":"شعيرات الفرشاة أكثر حساسية مما تظن. غلاف واحد يغطي أطرافها فلا يصل إليها حتى غبار الحقيبة. حماية الأماكن غير المرئية - العمل الحقيقي للنظافة، يُتعلَّم في كل رحلة."},"ICON-1978":{"nm":"ملقط سحب قطن التجميل ورقة بورقة","de":"لا يخرج قطن التجميل نظيفًا إلا حين يُلتقَط ورقة واحدة في كل مرة. فإذا انسكب كله دفعة واحدة، يُهدَر أكثر. \"واحدة تلو الأخرى، بعناية\" - هذه هي القاعدة الهادئة فوق طاولة الزينة."},"ICON-1979":{"nm":"ملعقة أحذية صغيرة قابلة للطيّ","de":"مطويةً، في الجيب؛ مفرودةً، عند الكعب. أفتخر بأني أُنجز عملًا كبيرًا نوعًا ما بجسد صغير. حتى في صباح النوم المتأخر، كنت دائمًا أنا من يجعل ارتداء الحذاء ممكنًا دون أن يفسده."},"ICON-1980":{"nm":"بكرة خيط تنظيف الأسنان المفردة","de":"لُفّ خيطًا واحدًا من خيط الأسنان بعناية، واقطع منه بالضبط ما تحتاجه حين يحين الوقت. بكرة لا تكبر ظفر الإصبع، لكنها لا تغيب أبدًا عن مهمة حماية ابتسامة مشرقة. حتى للابتسامة استعداد لا يُرى."},"ICON-1981":{"nm":"مقبض غطاء الغلاية الكهربائية","de":"كي لا يحرق بخار الماء المغلي يدك، أثبّت نفسي فوق الغطاء. شبر واحد بين الحرارة وراحة اليد. تلك المسافة الصغيرة تُدفّئ بأمان صباحًا مزدحمًا لأحدهم."},"ICON-1982":{"nm":"لوح سيليكون لمسند المكواة","de":"أخطر لحظة هي حين تُبعد يدك عن المكواة قليلًا أثناء الكيّ. أوقف المكواة فوق لوح السيليكون، ولن تحترق الطاولة ولا الثياب. تسوية التجاعيد لا تكتمل إلا فوق المسند."},"ICON-1983":{"nm":"خطاف شمّاعة مضاد للسرقة","de":"كي لا ينزلق الثوب المعلّق بلا مبالاة، يُطبق الخطاف فمه بإحكام. حارس صغير يحمي القطعة العزيزة في الخزانة. الحماية عمل هادئ كهذا."},"ICON-1984":{"nm":"مصفاة ترسبات الغلاية","de":"مهمتي أن أصفّي بهدوء الترسبات العائمة في الماء المغلي. لا يصفو فنجان الشاي إلا بعد تصفية حتى الرواسب غير المرئية. العناية دائمًا تنضج في الأماكن التي لا يراها أحد."},"ICON-1985":{"nm":"شريط مانع انزلاق الشمّاعة","de":"شمّاعة ملفوفة بشريط مانع للانزلاق لا تُسقط حتى الحرير الخفيف. من رأى ذات مرة ثوبًا سقط على الأرض وتجعّد، يعرف امتنانه لهذا الخيط الرفيع الواحد."},"ICON-1986":{"nm":"مشبك ترتيب سلك المكواة","de":"سلك متروك فضفاضًا يتعثر بالأقدام ويجعل أحدهم يترنح. لمسة يد واحدة تربطه بعناية بمشبك. منع الحوادث يبدأ دائمًا من ترتيب صغير تافه كهذا."},"ICON-1987":{"nm":"فتحة قاعدة الغلاية الكهربائية","de":"أُجلس الغلاية بإحكام في فتحتي كي لا تهتزّ. أن تكون في مكانك الصحيح يعني أن تكون مطمئنًا. هناك سبب لتسخين الماء الدافئ في نفس المكان كل صباح."},"ICON-1988":{"nm":"أرجل مشبك شمّاعة البنطال","de":"حين تُمسك أرجل المشبك حاشية البنطال بإحكام، لا تتكوّن ولو غرزة واحدة. بذلة مكوية جيدًا تُعامَل بتقدير منذ لحظة تعليقها. القصّة الأنيقة تكتمل داخل الخزانة."},"ICON-1989":{"nm":"خطاف تعليق مجفف الشعر","de":"اترك المجفف في أي مكان وسيتشابك سلكه سريعًا. علّقه على الخطاف، ويتّسع المغسل، ويخفّ صباح الغد. مكان مرتب يُريح قليلًا يومًا مزدحمًا."},"ICON-1990":{"nm":"كوستر مشروبات الميني بار","de":"ضعه بهدوء تحت الكأس، ولن تنتشر القطرات على الطاولة. لطف قطعة كوستر واحدة لا يترك دائرة أثر. النظافة هي اللطف الذي لا يترك أثرًا."},"ICON-1991":{"nm":"لافتة \"عدم الإزعاج\" للباب","de":"لافتة معلّقة على مقبض الباب تهمس بهدوء \"أستريح الآن\". تحرس نفسًا واحدًا من قيلولة في نهاية يوم طويل. حتى الفاصلة يحتاج أحدهم لحراستها بعناية."},"ICON-1992":{"nm":"غطاء زر استدعاء خدمة الغرف","de":"بفضل الغطاء الذي يحيط بالزر، لا يُضغط عن طريق الخطأ حتى لو لامسه طرف كمّ. كي تنادي بوضوح فقط عند الحاجة الحقيقية. غطاء صغير واحد يجعل غرفة ضيوف مزدحمة أكثر أناقة."},"ICON-1993":{"nm":"أرجل ملقط ثلج الميني بار","de":"أمسك الثلج بيد عارية فيكون باردًا ومنزلقًا باستمرار. تتولى أرجل الملقط تلك المهمة بإحكام بدلًا منك. خلف بداية كأس مشروب بارد تختبئ يد مساعدة غير مرئية."},"ICON-1994":{"nm":"فتحة إدخال بطاقة مفتاح الغرفة","de":"أدخل البطاقة في الفتحة، وتُضاء أنوار الغرفة فجأة. أنا مجرد شقّ صغير، لكنني أول إشارة تفتح مساحة لإلقاء تعب اليوم. تُضاء الأنوار من جديد في المكان الذي تعود إليه."},"ICON-1995":{"nm":"حلقة ختم عنق زجاجة الماء","de":"إن كانت حلقة الختم المعلّقة على عنق الزجاجة سليمة، فهذا يعني أن أحدًا لم يلمسها بعد. وعد صغير يثبت أنها كما كانت في البداية. الثقة تبدأ من ختم لم يُكسَر."},"ICON-1996":{"nm":"حامل تثبيت الكتيّب الإرشادي","de":"أوقف الكتيّب الإرشادي بميل، وتتوقف عليه العيون العابرة تلقائيًا. الوضعية الرزينة لمعلومات تنتظر أن تُفتَح. مجرد إبقائه ظاهرًا يجعل طريق أحدهم أسهل."},"ICON-1997":{"nm":"شريحة مسطحة لفتح زجاجات الميني بار","de":"في زاوية من جسدها المسطح يختبئ بتكتم شقّ لفتح أغطية الزجاجات. مهما كانت صغيرة، تؤدي مهمتها بإتقان. أول رشفة باردة من زجاجة مشروب تُفتَح دائمًا بهذه الشريحة الصغيرة."},"ICON-1998":{"nm":"غطاء مقبض تعديل الإضاءة","de":"أدر المقبض المغطّى برفق، وتتغير سطوع الغرفة ببطء. ساطعًا، ثم خافتًا. اختيار الضوء عند النوم طقس يختتم اليوم بلطف."},"ICON-1999":{"nm":"إسفين إيقاف عجلة حقيبة السفر","de":"ضعه برفق تحت العجلة، ولن تتدحرج الحقيبة من تلقاء نفسها. حتى على رصيف محطة منحدر، تحافظ الأمتعة على مكانها. طمأنينة رحلة المغادرة تشتدّ من هذا الإسفين الصغير."},"ICON-2000":{"nm":"لوح طيّ حقيبة السفر","de":"افرد القميص أو البنطال فوقه، ويُطويان بترتيب أنيق. كي لا ينهار داخل الحقيبة، وكي تخرج بلا تجعيد في المدينة التي تصل إليها. الحقيبة المحزومة جيدًا تساعد الرحلة حتى قبل المغادرة."},"ICON-2001":{"nm":"مقبض قفل الخزنة","de":"عندما تدير المقبض، ينزلق مزلاج صغير إلى الداخل بهدوء. أن تودع مقتنياتك الثمينة هو وعد بأن تُريح قلبك تمامًا، ولو لليلة واحدة فقط. فالقفل هنا ليس قلقًا، بل اسمًا آخر لراحة البال."},"ICON-2002":{"nm":"غلاف مقبض حقيبة السفر","de":"في كل بقعة بهتت من لمس الأيدي، تنقش رحلة مغادرة لشخص ما. حين تقبض على هذا الغلاف المهترئ بقدر الأميال التي جُرّ خلالها، تدرك بهدوء أن الرحيل، في النهاية، كلمة تحمل العودة بداخلها."},"ICON-2003":{"nm":"مشبك تعليق حقيبة السفر الصغيرة","de":"علّق الحقيبة الصغيرة على حافة المغسلة، وستتسع الغرفة الضيقة بمقدار شبر. أن يبدأ النظام داخل الحقيبة بمشبك صغير واحد، أمرٌ تعرفه سلفًا يدُ من سافرت بعيدًا."},"ICON-2004":{"nm":"مشبك موزّع الشواحن","de":"تُجمع عدة كابلات في مقبس واحد. في ليلة انتظار اكتمال الشحن، هنا يدٌ صغيرة تمسك بحنان بالأسلاك المتناثرة وتجمعها في مكان واحد."},"ICON-2005":{"nm":"رباط بطاقة اسم حقيبة السفر","de":"خيط واحد يجعلك تميّز حقيبتك بين حقائب سوداء متطابقة. أن تعلّق اسمك هو علامة رقيقة على أن هذه الأمتعة تملك طريقًا للعودة إلى صاحبها."},"ICON-2006":{"nm":"لوحة تعليق سلك الشحن الجدارية","de":"لوحة صغيرة على الجدار قرب رأس السرير تُسند سلك الشحن بترتيب. في أول ليلة في غرفة غريبة، حين يضيء ضوء مألوف واحد، يصبح ذلك المكان بيتًا للحظة."},"ICON-2007":{"nm":"أرجل حامل الأمتعة القابلة للطي","de":"افرد الأرجل المطوية، وترتفع الحقيبة عن غبار الأرض بمقدار شبر. الحقيبة الموضوعة دون أن تُفتح بعد، تحمل بصمت رحلة لم تنتهِ، وتنتظر الصباح التالي."},"ICON-2008":{"nm":"فتحة بطاقة المفتاح","de":"يجب إدخال البطاقة كي تضيء أنوار الغرفة. ضوء لا يشرق إلا أثناء إقامتك - يوم المسافر يدفأ بمقدار السطوع الذي تسمح به هذه الفتحة الصغيرة، لا أكثر."},"ICON-2009":{"nm":"عروة رباط بطاقة المفتاح","de":"علّق البطاقة الواحدة حول عنقك، وتتحرر يداك. أن تربط قلق الضياع بحبل واحد هي حكمة صغيرة توارثها المسافرون ذوو الأمتعة الثقيلة منذ زمن طويل."},"ICON-2010":{"nm":"زر جرس نداء الاستقبال","de":"اضغط عليه، ويرن صوت صافٍ في مكان ما عند الاستقبال. كي لا يكون طلب المساعدة أمرًا محرجًا، يجلس الجرس دومًا بلطف في متناول اليد."},"ICON-2011":{"nm":"مشبك رقم الدور لتسجيل الوصول","de":"التقط ورقة الدور المستلمة في نهاية الصف وثبّتها. حتى الانتظار له نظامه الخاص - فالنظام ينمو من وعد صغير بأن يحترم كل منا وقت الآخر بهدوء."},"ICON-2012":{"nm":"شرابة مفتاح الغرفة","de":"شرابة معلقة في طرف المفتاح تتمايل برفق مع كل خطوة. القلب الذي يضيف لمسة من الأناقة إلى ما هو نفعي بحت، لا يظهر إلا لمن يعرف متعة أطراف الأصابع."},"ICON-2013":{"nm":"غطاء جرس الباب في الاستقبال","de":"ضع الغطاء فوق الجرس، ولن يُكسر سكون منتصف النهار. اهتمام صغير لحماية نوم عميق لشخص ما - حتى الصمت شيء صنعه أحدهم بعناية."},"ICON-2014":{"nm":"بطاقة رقم الغرفة المعلقة","de":"ورقة معلقة على مقبض الباب تحمل رقم الغرفة بوضوح. أرقام قليلة تحدد المكان الذي سأعود إليه الليلة، وفي ممر غريب تصبح تلك الأرقام منارة صغيرة."},"ICON-2015":{"nm":"شريط بطاقة المفتاح المغناطيسي","de":"قرّب الشريط الأسود من فتحة الباب، وينفك القفل برفق. عصرٌ تفتح فيه إشارة غير مرئية بابًا - ما كان يومًا أشبه بالسحر، استقر الآن كأمر يومي في راحة اليد."},"ICON-2016":{"nm":"وسادة ختم تسجيل الوصول","de":"في كل مرة يُطبع فيها الختم، تستقبل الوسادة الحبر بتساوٍ. كي تبقى ضربة التأكيد واضحة، توجد يدٌ تسند العمل بصمت من مكان غير مرئي."},"ICON-2017":{"nm":"قضيب تعليق عربة الأمتعة","de":"قضيب واحد معلق على عربة الأمتعة يحمل حقيبة الملابس دون أن تتجعد. للأشياء التي تحمل عنا عبء يوم ثقيل، يحلو أحيانًا أن نهمس لها بكلمة شكر."},"ICON-2018":{"nm":"بطاقة مقبض حقيبة السفر","de":"بطاقة صغيرة معلقة على مقبض الحقيبة الكبيرة. طالما بقيت خانة الاسم فارغة، تبقى الإثارة قائمة - وجهة هذه الحقيبة التالية لم تتقرر بعد."},"ICON-2019":{"nm":"إسفين تثبيت عجلة عربة الأمتعة","de":"ضع إسفينًا تحت العجلة كي لا تتدحرج العربة في المنحدر. حماية السكون هي أحيانًا الوجه الآخر الأكثر موثوقية للأمان."},"ICON-2020":{"nm":"إبزيم حزام الأمتعة","de":"شدّ الحزام بإحكام كي لا تنفجر الحقيبة المنتفخة بأغراض السفر. حتى حين تنتهي الطريق، لا يتقلص حجم الذكريات، فالإبزيم يحمل ذلك الثقل حتى النهاية."},"ICON-2021":{"nm":"غطاء خطاف عربة الأمتعة","de":"الغطاء الموضوع على خطاف العربة لا يترك أثرًا واحدًا على الملابس. قلبٌ يتوقع حتى الخدوش غير المرئية - الضيافة الجيدة تكتمل في مثل هذه التفاصيل الصغيرة."},"ICON-2022":{"nm":"جيب بطاقة اسم حقيبة السفر","de":"جيب صغير على جانب الحقيبة يحتضن بطاقة الاسم. كتابة اسم صاحبها أشبه بأن تنقش سلفًا حق اللقاء مجددًا، حتى لو ضاعت."},"ICON-2023":{"nm":"مشبك قفازات نقل الأمتعة","de":"عند حمل الأثقال، يمسك المشبك بالقفازات بإحكام كي لا تنزلق. حماية اليدين وإتقان العمل ينبعان في النهاية من قلب واحد."},"ICON-2024":{"nm":"شبكة تغطية الأمتعة","de":"غطِّ الشبكة، ولن تتناثر القطع الصغيرة من الأمتعة في كل اتجاه. كل عقدة ضيقة في الشبكة تمنع ضياع الأشياء الصغيرة وسط زحمة التنقل."},"ICON-2025":{"nm":"حامل مذكرات عربة الأمتعة","de":"مذكرة مثبتة على مقبض العربة تحمل رقم الغرفة. عادة تدوين الوجهة - كلما ازدحمت الأيدي، اتكأت أكثر بهدوء على سطر واحد من الكتابة."},"ICON-2026":{"nm":"غطاء صحن قبة فضية","de":"ارفع القبة الفضية، ويتصاعد البخار دفعة واحدة. القلب الذي يغطي الطعام كي لا يبرد هو الإخلاص بعينه، رغبة في تسليم الدفء كما هو تمامًا."},"ICON-2027":{"nm":"لوحة \"عدم الإزعاج\" لمقبض الباب","de":"علّق هذه اللوحة على مقبض الباب، وتصبح حتى خطوات الممر حذرة. عبارة واحدة \"لا توقظوني\" - الراحة أيضًا لا تكتمل إلا حين يحرسها أحد."},"ICON-2028":{"nm":"حلقة منديل ورقي لخدمة الغرف","de":"أدخل المنديل الورقي في حلقة دائرية ليأخذ شكلًا أنيقًا. تبدأ أناقة الوجبة من هذه الحلقة الصغيرة - فالعناية تظهر بأوضح صورها في أدق التفاصيل."},"ICON-2029":{"nm":"بساط مانع انزلاق الصينية","de":"ضع بساطًا فوق الصينية، ولن تنزلق الأطباق. أن تُحفظ الأشياء في مكانها حتى وسط الاهتزاز - حتى الاستقرار الهادئ يحمل تصميمًا دقيقًا من شخص ما."},"ICON-2030":{"nm":"بطاقة طلب الإفطار المعلقة على الباب","de":"علّق بطاقة طلب الإفطار على مقبض الباب، ويصبح صباح الغد وعدًا مسبقًا. أن تدوّن وجبتك الأولى الليلة هو وجه آخر من وجوه الانتظار الرقيق."},"ICON-2031":{"nm":"حامل أرجل الصينية","de":"افرد أرجل الصينية، وحتى فوق السرير تصبح مائدة حقيقية. وجبة صباحية تُقدَّم في مكان استلقائك - حامل صغير يحوّل غرفة عادية إلى مشهد فاخر."},"ICON-2032":{"nm":"غطاء تدفئة الإبريق","de":"غطِّ الإبريق بغلاف دافئ، ويبقى دفء الماء طويلًا. كما في ليالٍ قديمة كان الناس يجتمعون حول الموقد، رغبة الحفاظ على الدفء لا تعرف زمنًا."},"ICON-2033":{"nm":"ذيل طلب التنظيف لمقبض الباب","de":"علّق ذيل طلب التنظيف على مقبض الباب لترك إشارة صامتة. طلبٌ يُنقل دون أن تُفتح الشفتان - خلف الغرفة النظيفة يكمن وعد يد غير مرئية."},"ICON-2034":{"nm":"حامل زجاجات التوابل للصينية","de":"يمسك الحامل بإحكام كي لا تنقلب زجاجات التوابل. الحفاظ على توازن النكهة حتى فوق صينية مهتزة، هو الدور الصامت لهذا التثبيت الصغير."},"ICON-2035":{"nm":"حامل مذكرات الحجوزات","de":"ثبّت مذكرات الحجز واقفة، ويُقرأ الترتيب بنظرة واحدة. كي لا تتشوش حتى الأيدي المشغولة، إنه أداة نظام صغيرة تُبقي ورقة واحدة واقفة بوضوح."},"ICON-2036":{"nm":"لوحة خريطة دبابيس المعالم السياحية","de":"اغرس دبابيس في الخريطة وحدّد الأماكن التي تريد زيارتها واحدًا تلو الآخر. كل دبوس إثارة لم تُزر بعد - تبدأ الرحلة فعليًا في اللحظة التي تُفتح فيها الخريطة."},"ICON-2037":{"nm":"مشبك راية استدعاء التاكسي","de":"عند استدعاء تاكسي، يُقيم المشبك الراية الصغيرة منتصبة. إشارة تصرخ بها الراية بدلًا من يد مرفوعة - في الشارع أيضًا، يجب أن يكون النداء واضحًا كي يصل."},"ICON-2038":{"nm":"مقبض جرس الكونسيرج","de":"اضغط على المقبض، ويصل صوت صافٍ إلى مكتب الكونسيرج. إشارة ترحيب تقول اسأل عمّا شئت - في مدينة غريبة، أطمأن نداء وحيد يمكن الاعتماد عليه."},"ICON-2039":{"nm":"لوح مشبك رقم الحجز","de":"ثبّت ورقة رقم الحجز في اللوح المشبكي كي تظهر بوضوح. كي لا يختلط المقعد الموعود، إنها أمانة صغيرة تُثبّت سطرًا واحدًا من الأرقام بترتيب."},"ICON-2040":{"nm":"إطار عرض كتيبات الجولات","de":"اعرض كتيبات الجولات، وتتوقف يد المسافر تلقائيًا. في كل ورقة تُفتح واحدة تلو الأخرى، يطوي بهدوء مشهد طريق لم يُسلك بعد."},"ICON-2041":{"nm":"حامل ختم الخريطة الإرشادية","de":"من أجل الخطوات الأولى عند المدخل، يُثبّت علبة الختم فوق الخريطة دون اهتزاز. حين لا يسيل الحبر، لا تتشوش الطريق أيضًا. مكان يحمل الثقل بصمت كي تقف الإرشادات الصغيرة منتصبة."},"ICON-2042":{"nm":"بطاقة حفظ المظلة","de":"في بعد ظهيرة كانت قطرات المطر تتقاطر من الأفاريز، يُعلّق رقم واحد على كل مظلة. حين يعود من انقطع عنه المطر ليأخذ مظلته، تنادي البطاقة بوضوح على ذكرى مبللة."},"ICON-2043":{"nm":"حامل جرس نداء مكتب الاستعلامات","de":"يرن مرة واحدة، رنين خفيف، ويهرع أحدهم بابتسامة من الجهة الأخرى. الجرس الصغير المعلق في زاوية المكتب هو أرقّ مترجم، ينقل حتى الكلمات التي عجزت عن قولها."},"ICON-2044":{"nm":"فوهة موزّع الشامبو","de":"افتح راحة يدك واضغط برفق، وتتفتح الرغوة بصوت خفيف. تلك الدفعة الواحدة بينما تفوح الرائحة في الحمام. النغمة التي توقظ صباحًا نعسانًا بأرق طريقة تبدأ هنا بالضبط."},"ICON-2045":{"nm":"صينية تصريف طبق الصابون","de":"صينية تُصرّف بهدوء الماء المتجمع تحت الصابون. كي لا يلين، وكي لا يتفتت. عناية صغيرة ورقيقة للحفاظ على ما يتآكل قليلًا كل يوم بجانبك لفترة أطول."},"ICON-2046":{"nm":"ملعقة ملح الاستحمام","de":"اغرف ملعقة من المسحوق وذوّبها في الماء الدافئ، فينتشر اللون والعطر ببطء. بينما تحرّك بمعصمك، يتحول الحوض إلى بحيرة صغيرة، ويغرق فيها بهدوء تعب يوم كامل."},"ICON-2047":{"nm":"كيس شبكة الرغوة","de":"احبس قطعة صابون في الشبكة وافركها، فتمتلئ راحتاك برغوة ناعمة. ساحر صامت في ركن من الحمام، يحوّل الخشونة إلى نعومة."},"ICON-2048":{"nm":"غطاء تعقيم فرشاة الأسنان","de":"رغبة في أن يبقى كل ما يلامس الفم نظيفًا دائمًا. غطاء صغير واحد يلف أطراف الشعيرات برفق، يعتني حتى بما لا يُرى. النظافة تُصنع من تراكم مثل هذه الأشياء الصغيرة."},"ICON-2049":{"nm":"غطاء علبة أعواد القطن","de":"علبة تستلقي فيها العيدان البيضاء بترتيب، وغطاء يُقفل عليها بشكل دائري. فتح بصوت خفيف، إغلاق بنقرة. علامة نهاية رقيقة لترتيب الحمام، تُختتم بصوت صغير."},"ICON-2050":{"nm":"زجاجة قطرات زيت الاستحمام","de":"أمِلها قليلًا، وتسقط قطرة تلو أخرى من زيت عطر. البريق والرائحة الخفيفة تنتشر في الحوض. أبسط من أن تكون رفاهية، وأرق من أن تكون عادة - قطرة واحدة فقط."},"ICON-2051":{"nm":"فاصل صينية مستلزمات الحمام","de":"فوق صينية مقسّمة إلى خانات، تجد الزجاجات الصغيرة مكانها الخاص. أشياء تبدو فوضوية متناثرة وأنيقة مجتمعة. فاصل واحد يحافظ على نظام صباح مزدحم."},"ICON-2052":{"nm":"حامل الساعة الرملية للساونا","de":"وعد رقيق بأن تُدفَّأ ظهرك ولو طوال مدة سيلان الرمل فقط. بينما تتساقط الساعة الرملية المائلة على حاملها الوقت حبة حبة، يستريح الإنسان وسط البخار الكثيف قليلًا، بلا هوية سوى الراحة."},"ICON-2053":{"nm":"منشفة الحمام البخاري بأذني خروف","de":"لُف طرفي المنشفة وارفعهما منتصبين كأذني خروف، فيرتخي الوجه في المرآة برفق. وسط البخار الساخن، طقس صغير في حمام البخار يعيد الجميع للحظة إلى طفولتهم."},"ICON-2054":{"nm":"مغرفة ماء الساونا","de":"اغرف الماء بالمغرفة كاملة واسكبها على الحجارة الساخنة - فحّ - ويتصاعد البخار حتى السقف. في تلك اللحظة يغرق الجسد كله في ضباب دافئ، ويتحلل التعب القديم ببطء في قطرات العرق."},"ICON-2055":{"nm":"قضيب قياس حرارة حوض نقع القدمين","de":"اغمس القضيب في الماء، وتتحدث العلامات إليك برفق. لا حارة جدًا ولا باردة، بل تلك الدرجة بالضبط. قبل أن تغمس أطراف قدميك، هو أول إصبع يسأل عن حال الماء."},"ICON-2056":{"nm":"ملقط حجارة الحمام البخاري","de":"لا يمكن الإمساك بحجر ساخن حديثًا بيد عارية. حين يقبض الملقط عليه بإحكام ويرفعه، ينتقل الحر إلى مسافة آمنة. الحذر أيضًا مهارة، يقول حمام البخار بهدوء."},"ICON-2057":{"nm":"وسادة أرضية للساونا","de":"افرد واحدة على الأرض الساخنة، ويصبح المكان الذي يلامس ظهرك أكثر نعومة. وسادة تستقبل بصمت يومًا مغموسًا بالعرق. الراحة، في النهاية، تأتي من المسافة المناسبة عن الأرض."},"ICON-2058":{"nm":"كيس ملح لنقع القدمين","de":"أمسك حفنة من الملح الخشن، وذوّبها في ماء دافئ، فيذوب الإرهاق من أطراف الأصابع صاعدًا. بينما يلف البخار المالح ساقيك، يتوقف أخيرًا يوم كامل من المشي."},"ICON-2059":{"nm":"طبق حجر عطر الساونا","de":"أسقط بضع قطرات من العطر على الحجر الساخن، وينتشر العطر الدافئ ببطء في الساونا. أغمض عينيك، أهذه غابة أم حقل زهور؟ أقصر رحلة، تُقطع عبر طرف الأنف."},"ICON-2060":{"nm":"غطاء دافئ لكمادة التسخين","de":"قماش يلف الكمادة الساخنة بإحكام ليحبس الدفء طويلًا. تمامًا كقلب يحتضنها خشية أن تبرد، يبقى الدفء المستقر على بطنك رفيقًا طوال الليل."},"ICON-2061":{"nm":"عيدان ناشر العطر","de":"عيدان رفيعة تمتص العطر وتنشره ببطء في الغرفة. رائحة خفيفة تتسلل مع كل شهيق. هي الطريقة التي يتشرب فيها المكان الذي نقيم فيه رائحة صاحبه شيئًا فشيئًا."},"ICON-2062":{"nm":"مقبض ضبط زاوية كرسي الاستلقاء الشمسي","de":"أدر المقبض ببطء، ويميل مسند الظهر برفق. قليلًا نحو الشمس، قليلًا نحو الظل. البحث عن الزاوية الأكثر راحة هو حساب خاص بك وحدك."},"ICON-2063":{"nm":"شريط مانع الانزلاق حول حافة المسبح","de":"شريط مانع للانزلاق يحيط بحافة الماء بالكامل. كي تتوقف بأمان أقدام صغيرة تركض مرحة بعد اللعب بالماء، إنه خط نهاية أمان يفترش المكان بهدوء بعيدًا عن الأنظار."},"ICON-2064":{"nm":"عروة صمام هواء العوامة","de":"عروة معلقة بعناية في الصمام الصغير الذي يحبس الهواء. كي لا ينجرف الصمام بعيدًا في الماء بعد أن يُنزع من العوامة. حكمة تمنع سلفًا ضياعًا تافهًا في منتصف يوم صيفي."},"ICON-2065":{"nm":"غطاء درج دخول المسبح","de":"غطاء يلف بنعومة نهاية الدرج المؤدي إلى الماء. كي لا تُخدش باطن القدم الحافية، يستقبل بلين أول خطوة للدخول. لأن كل بداية يجب أن تكون حذرة دائمًا."},"ICON-2066":{"nm":"عروة رباط وسادة كرسي الاستلقاء","de":"عروة تُعلَّق فيها الرباط وتُربط كي لا تنزلق الوسادة. وعد صغير بالحفاظ على مكانها حتى مع هبوب الريح. عقدة واحدة تُثبّت كسل بعد الظهر في مكانه."},"ICON-2067":{"nm":"لوحة حامل مشروبات فيلا المسبح","de":"لوحة تُدخل فيها كوب المشروب بإحكام عند حافة المسبح. مكان واحد لا يتأثر حتى بالرش المرح. وضع البرودة في متناول اليد يُطيل بعد ظهيرة صيفية طويلًا."},"ICON-2068":{"nm":"مشبك تعليق ملابس السباحة المبللة","de":"التقط ملابس السباحة التي تقطر ماءً واتركها بهدوء لنسيم الهواء. بينما تجف تحت الشمس، يقف المشبك صامتًا ممسكًا بها. انتظار هادئ ورقيق، من أجل السباحة القادمة."},"ICON-2069":{"nm":"ثقل قاعدة عمود المظلة","de":"ثقل ثقيل يوضع عند قاعدة العمود كي لا تتمايل المظلة مع الريح. بقاء الظل في مكان واحد لفترة طويلة مدين كله لهذا الوزن. الموثوقية غالبًا ما تختبئ في أدنى مكان."},"ICON-2070":{"nm":"رقاقة عائمة لقياس حرارة المسبح","de":"رقاقة صغيرة تطفو على الماء وتُخبر بهدوء عن درجة الحرارة. تحمرّ إن كان الماء باردًا جدًا، وتلين إن كان معتدلًا. عرّافة صغيرة لطيفة تقرأ مزاج الماء بلون واحد."},"ICON-2071":{"nm":"شرابة سحب سحّاب الخيمة","de":"اسحب برفق الشرابة الصغيرة المعلقة في طرف السحّاب، وينفتح باب الخيمة برقة. مقبض تلتقطه الأصابع فورًا حتى دون أن تتلمسه. يرشد بلطف تنقلات منتصف الليل العميق."},"ICON-2072":{"nm":"دبوس فراشة لتثبيت حبل الخيمة","de":"دبوس يعضّ الحبل على شكل فراشة ويثبته بإحكام. القماش الذي كان يرفرف مع الريح يهدأ أخيرًا. ليلة التخييم تحرسها بصمت مثل هذه العقد الصغيرة الماهرة."},"ICON-2073":{"nm":"صمام هواء لمرتبة التخييم الفاخر","de":"ضع فمك عليه وانفخ، انفخ، فتتضخم المرتبة ببطء. املأها وأغلق الصمام بإحكام، تصبح الأرضية وثيرة، ويكتمل أخيرًا مكان لتمديد جسدك تحت ضوء النجوم."},"ICON-2074":{"nm":"خطاف تعليق سقف الخيمة","de":"خطاف معلق من سقف الخيمة لتعليق فانوس أو منديل. حكمة تدبير منزلي تستغل بحرص حتى المساحة الصغيرة فوق الرأس. كأنك تعلّق نجمة واحدة على السقف بدلًا من السماء."},"ICON-2075":{"nm":"شريط تثبيت كيس النوم الملفوف","de":"شريط يُلف ويُثبّت كي لا ينفك كيس النوم الملفوف. فراش يصغر مجددًا مع حلول الصباح. الاستعداد للرحيل هو طيّ دفء الليلة الماضية بترتيب."},"ICON-2076":{"nm":"لوحة حامل الأحذية عند مدخل الخيمة","de":"لوحة توضع عند مدخل الخيمة لتحمل الأحذية بترتيب. التراب في الخارج، والداخل نظيف. عتبة واحدة تفصل بلطف بين الداخل والخارج، أدب صغير من آداب التخييم."},"ICON-2077":{"nm":"خطاف تعليق فانوس التخييم الفاخر","de":"خطاف منحنٍ لتعليق الفانوس. علّقه هنا، وينتشر الضوء بشكل دائري داخل الخيمة. تلك البقعة التي تُعلَّق فيها شعلة واحدة وسط الظلام، تصبح غرفة معيشتنا الليلة."},"ICON-2078":{"nm":"مشبك لف نافذة تهوية الخيمة","de":"مشبك يلف نافذة التهوية ويمسك بها. افتح ممرًا صغيرًا للنسيم، ويصبح الهواء داخل الخيمة أكثر انتعاشًا. فجوة صغيرة واحدة تصنع بهدوء متسعًا للتنفس طوال الليل."},"ICON-2079":{"nm":"مرتبة أرضية للخيمة","de":"مرتبة تُفرش على أرض الخيمة لمنع التراب والرطوبة. طبقة واحدة تفرش فراشًا جافًا حتى فوق العشب. كي تبقى في الطبيعة دون أن تبتل بها، تمدّ يد العون بهدوء بجانبك."},"ICON-2080":{"nm":"حلقة تثبيت أقراص البار","de":"حلقة تُثبَّت في طرفي البار كي لا تنزلق الأقراص. قفل صغير يثق تمامًا بوزن من يرفع. حين يسند الأمان بثبات، عندها فقط يتجدد الحد بخطوة واحدة."},"ICON-2081":{"nm":"غطاء مقبض الكيتلبل","de":"في المجموعة الأخيرة حين كان الحديد يعضّ راحة اليد، يجعل هذا الغطاء الصغير الألم يختفي. أن تستمر بالإمساك حتى النهاية أصعب من رفع الوزن نفسه - تدرك اليد ذلك أولًا في اللحظة الأخيرة."},"ICON-2082":{"nm":"إسفين إدخال أقراص الأثقال","de":"إن اهتز القرص ولو قليلًا، تنهار وضعية جسدك حتى قبل أن ترفع. إسفين رفيع يُدسّ في الفجوة يثبّت المركز دون أي صوت. الصلابة تبدأ دائمًا بهدوء في مكان غير مرئي."},"ICON-2083":{"nm":"مشبك مزلاج البار","de":"أطراف الأصابع التي تُثبّت المزلاج يجب ألا تتردد. صوت النقرة الصغير ذاك يسند كل الحركة التالية. يتعلم الجسد أولًا كيف يضع ثقته في مشبك واحد."},"ICON-2084":{"nm":"رقاقة لون وزن القرص","de":"رقاقة بلون مختلف لكل وزن، تتعرف عليها اليد أولًا حتى لو لم تقرأ الرقم. الأحمر ثقيل والأزرق خفيف، تذكّر الوزن باللون. الجسد، بشكل مفاجئ، يقيس قوته عبر العين."},"ICON-2085":{"nm":"قاعدة أرضية للكيتلبل","de":"بفضل القاعدة التي توسّع سطح التلامس مع الأرض، لا تُحفر الأرضية الخشبية. آثار التمرين يجب أن تبقى في العرق والعضلات فقط. قلب صغير لا يريد ترك جروح حتى تحت القدمين، يتمدد هنا."},"ICON-2086":{"nm":"علامة مركز البار","de":"العلامة المحفورة في منتصف القضيب هي نقطة مرجعية لتوازن اليمين واليسار. اليد التي تقبض على المركز بدقة تقلل الاهتزاز إلى النصف. حين تعرف أين المركز، عندها فقط تستطيع الرفع بأمان."},"ICON-2087":{"nm":"رف تخزين أقراص الأثقال","de":"الأقراص المستخدمة تعود إلى مكانها. المشهد المرتب حسب الوزن على الرف هو مراعاة صامتة للشخص التالي. مساحة منظمة هي أوثق وسيلة أمان، يؤمن أحدهم بذلك."},"ICON-2088":{"nm":"حاجز إيقاف تدحرج القرص","de":"حادث القرص الموضوع على الأرض حين يتدحرج فجأة ليسحق ظهر القدم يأتي دائمًا في لحظة غفلة واحدة. حاجز التوقف يمنع بهدوء تلك اللحظة الخاطفة. المصائب الكبيرة لا تأتي من أماكن كبيرة، بل تتدحرج من فجوة صغيرة."},"ICON-2089":{"nm":"وسادة مسند ظهر المقعد","de":"إن كانت الوسادة المسندة للظهر قاسية جدًا، يصبح التنفس نفسه ضحلًا. تلك الحدود بين الصلابة الملائمة والنعومة الملائمة نقطة توازن لا يتلمسها بأطراف أصابعه سوى من جلس طويلًا."},"ICON-2090":{"nm":"دبوس ضبط ارتفاع الرف","de":"دبوس واحد يحدد الارتفاع، فيلائم القضيب كتف أي شخص. أشخاص بأطوال مختلفة يتشاركون نفس الأداة بوئام - ثقب تعديل صغير واحد يصنع تلك المساواة الرقيقة."},"ICON-2091":{"nm":"غطاء بكرة الجهاز","de":"داخل الغطاء الذي يلف البكرة، يدور الكابل مرارًا وتكرارًا دون صوت. قطعة تخفي الاحتكاك في الداخل وتمنح اليد النعومة فقط. الجهاز الجيد لا يكشف أبدًا عن الجهد الذي بذله."},"ICON-2092":{"nm":"أقدام مانعة للانزلاق لأرجل المقعد","de":"أقدام مانعة للانزلاق مثبتة في نهايات الأرجل الأربع تُثبّت المقعد بإحكام على الأرض. فقط حين لا يهتز يمكنك أن تضع كل قوتك بثقة. الاستقرار، في النهاية، يبدأ من احتكاك صغير عند القدم."},"ICON-2093":{"nm":"خطاف حامل البار في الرف","de":"الخطاف الذي يُوضع عليه القضيب يجب أن يكون دائمًا في ارتفاع تصله اليد. المكان الذي تضع فيه ذراع متعبة القضيب أخيرًا برفق - ذلك الموضع بمقدار شبر يغلق تمرين اليوم بأمان."},"ICON-2094":{"nm":"مقبض دبوس وزن الجهاز","de":"المقبض الذي يُدخل فيه الدبوس لاختيار الوزن يجب أن يكون أملسًا كي لا يؤذي الأظافر. حتى في الحركة الصغيرة العابرة لتغيير الوزن، تشعر بأن لمسة نهائية راعت أطراف أصابع الإنسان تختبئ بهدوء."},"ICON-2095":{"nm":"رافعة قفل زاوية المقعد","de":"إن كانت الرافعة التي تقفل زاوية المسند مرتخية، تنهار الوضعية بهدوء. يقين تلك اللحظة التي تُثبَّت فيها بنقرة. يتفقد المشرف هذا الصوت بالذات بهدوء أولًا كل صباح عند فتح الأبواب."},"ICON-2096":{"nm":"حامل قضيب الأمان في الرف","de":"في أسوأ لحظة حين يفلت البار من اليد، يستقبل حامل قضيب الأمان ذلك الوزن بدلًا عنك. بوجود حامل غير مرئي، ينتظر دائمًا في الأسفل، يستطيع الإنسان أخيرًا أن يدفع نفسه حتى حدوده القصوى."},"ICON-2097":{"nm":"غطاء طرف كابل الجهاز","de":"الغطاء الصغير الذي يجمع طرف الكابل هو العقدة الأخيرة ضد الانفراط. ربط الخيوط بترتيب كي لا تتناثر - رقي اللمسة الأخيرة يستقر دائمًا عند تلك النقطة الطرفية غير الملحوظة."},"ICON-2098":{"nm":"كيس مسحوق الطباشير","de":"حفنة من المسحوق الأبيض تُفرك على اليدين لمحو الانزلاق. غير مرئية كمكياج خلف الكواليس، لكن استقرار كل حركة اليوم يبدأ فعليًا من هذه الحفنة الواحدة. الاستعداد يبدأ دائمًا من أطراف الأصابع."},"ICON-2099":{"nm":"مشبك تمرين قبضة اليد","de":"مشبك صغير يكرر بصمت القبض والإفلات يبني قوة القبضة. تنمو قوة القبضة أبطأ من العضلات الكبيرة، لذا فهذا أيضًا تمرين على وضع التسرع جانبًا بهدوء."},"ICON-2100":{"nm":"شريط تباعد الأصابع","de":"شريط يُدس بين الأصابع ليُباعدها ببطء نحو الخارج. يد اعتادت استخدام عضلات القبض فقط تستعيد قوة الفرد. بقدر ما يحتاج القبض بإحكام إلى تمرين، يحتاج الإفلات بهدوء إلى تمرين أيضًا، تقول اليد."},"ICON-2101":{"nm":"غطاء أنبوب الطباشير","de":"لو ارتخى غطاء علبة المسحوق قليلاً فقط، لابيضّت الحقيبة كلها. غطاء صغير يُغلق بإحكام يمنع تلك الفوضى الصغيرة قبل وقوعها. فنجاح الاحتواء يتوقف دائماً على السدادة."},"ICON-2102":{"nm":"رباط دعم الركبة","de":"الرباط الذي يُلف حول الركبة ليسندها يجب أن يتوقف عند الضغط المناسب تماماً. فإن شُدّ كثيراً أعاق الدم، وإن ارتخى لم يُجدِ نفعاً، لذا تقيس يد خبيرة تلك المسافة الدقيقة بذاكرتها بهدوء."},"ICON-2103":{"nm":"حبل المقاومة المطاطي","de":"الحبل المطاطي الذي يتمدد ثم يعود يوقظ العضلات النائمة من دون أي ثقل حديدي. فالمقاومة لا يلزم أن تكون ثقيلة. وحتى أمام شدّ لطيف، يستجيب الجسد دائماً بصدق."},"ICON-2104":{"nm":"كيس أوزان الكاحل","de":"كيس الرمل الذي يُربط حول الكاحل يشدّ كل خطوة نحو الأسفل بثقل مُرضٍ. فبإضافة قليل من الوزن يتحول المشي العادي إلى تدريب حقيقي. إنها حكمة صغيرة تُضيف لمسة من الجهد إلى الحياة اليومية."},"ICON-2105":{"nm":"بكرة لفّ المعصم","de":"بكرة تُلف ببطء بواسطة المعصم لرفع ثقل معلّق بحبل. المعصم هو أصغر المفاصل وأكثرها نسياناً، وهذه الأداة البسيطة تُعيد بهدوء إحياء تلك القوة المنسية."},"ICON-2106":{"nm":"كرة القبضة المطاطية","de":"كرة مطاطية تُقبض وتُفتح في راحة اليد تُبقي التمرين مستمراً بهدوء حتى خلف المكتب. القوة التي تُبنى في اللحظات الضائعة تدوم أطول من قوة تُصرف دفعة واحدة. فالثبات ينمو دائماً من مثل هذه الأشياء الصغيرة."},"ICON-2107":{"nm":"إبزيم حزام نبض القلب","de":"لو انزاح إبزيم الحزام حول الصدر قليلاً فقط، قفزت الأرقام. حتى محاولة الإصغاء إلى نبض قلبك تبدأ أولاً بربطة محكمة. فكل قياس يبدأ في النهاية من التصاق محكم بلا فجوة."},"ICON-2108":{"nm":"مشبك قياس النبض","de":"مشبك يعضّ طرف الإصبع بلطف ليحصي النبض بهدوء. تُدخل إصبعك وتهدّئ أنفاسك، فيرتفع إيقاع القلب واضحاً على شاشة صغيرة. فالجسد يُخبر دائماً بحاله الحقيقية من دون كذب."},"ICON-2109":{"nm":"علبة سوار مراقب المعصم","de":"العلبة التي تحفظ جهاز قياس المعصم صغيرة لكنها تعرف أهلها. فكلما كان الجهاز الصغير سهل الضياع، احتاج إلى بيت يعود إليه أكثر. وحفظ الأشياء جيداً هو أيضاً شكل من أشكال الرقة."},"ICON-2110":{"nm":"دبوس علم الوتيرة","de":"دبوس علم صغير يُحدّد بدقة النقطة التي يستهدفها العدّاء. نقطة واحدة تُحدَّد مسبقاً - \"إلى هنا فقط\" - تحمل الأقدام المثقلة حتى النهاية. فخط النهاية في القلب يغرسه المرء بيده دائماً."},"ICON-2111":{"nm":"غطاء ضوء نبض القلب","de":"مصباح صغير يومض بهدوء تماشياً مع نبضات القلب. حين تراقب إيقاع اشتعاله وانطفائه، يتحرك قلبك من جديد أمام فكرة أن الحياة قد تكون بهذا الانتظام."},"ICON-2112":{"nm":"سلسلة خرز عدّ الأشواط","de":"تُحصى التكرارات بخرزات تُدفع واحدة تلو الأخرى بلمسة خفيفة. لا حاجة لحفظ الرقم في الذهن، فأصابعك تتذكر بدلاً عنك. حين تُسلَّم عملية العدّ لليدين، يبقى العقل حاضراً بالكامل مع الحركة."},"ICON-2113":{"nm":"وسادة مشبك قياس الأكسجين","de":"وسادة مشبك تُلبس طرف الإصبع لتقرأ بهدوء كمية الأكسجين في الدم. حين يظهر عمق النَفَس غير المرئي على شكل رقم، تُدرك من جديد أن الاعتناء بالجسد هو في النهاية مجرد نظرة فاحصة."},"ICON-2114":{"nm":"شريط ألوان مناطق نبض القلب","de":"شريط يُقسّم شدة التمرين بالألوان يُخبرك بلمحة واحدة عن مدى جهدك الآن. الأزرق راحة، والأحمر هو الحد الأقصى. إنه وعد هادئ يصبح فيه اللون نفسه لغة لطيفة وبسيطة."},"ICON-2115":{"nm":"كبسولة قياس هلامية","de":"كبسولة هلامية صغيرة تقيس حال الجسد تحمل في حبة واحدة معلومات يوم كامل. أياً كان ما بداخل قشرتها الشفافة، فإن رغبة معرفة النفس أكثر قليلاً مطويّة هناك أيضاً."},"ICON-2116":{"nm":"عروة تعليق منشفة العرق","de":"عادة صغيرة، تعليقها دوماً على عروتها الخاصة بدل رميها في أي مكان، تحافظ على ترتيب الغرفة كلها. مثل هذه العروة التي تخصص مكاناً تعود إليه المنشفة، فإن الترتيب يتألق دائماً في التفاصيل الصغيرة."},"ICON-2117":{"nm":"رباط غطاء زجاجة الماء","de":"الحبل القصير المعلّق بغطاء زجاجة الماء يمنع حادثة تدحرج الغطاء بعيداً. حكمة ربط ما يسهل ضياعه بالجسد - حبل صغير واحد يُبعد بهدوء متاعب يوم كامل."},"ICON-2118":{"nm":"ريشة المروحة اليدوية","de":"ريشة مروحة تُثير نسيماً حين تُفتح على اتساعها. كالمراوح القديمة التي كانت تُبرّد العرق في الأيام الحارة، أبسط الأدوات تمنح أبرد عزاء. فنسمة واحدة تتفتح دائماً من أطراف الأصابع."},"ICON-2119":{"nm":"كيس منشفة التبريد","de":"كيس صغير يحفظ منشفة تبرد إذا بُلّلت. قطعة قماش واحدة تُبرّد الحرارة تنام هناك بهدوء، ثم تحطّ برفق على رقبة متعبة لتحمل معها دفء منتصف النهار بهدوء."},"ICON-2120":{"nm":"صحن تنقيط","de":"صحن يُوضع مسبقاً ليستقبل مكان سقوط قطرات الماء المتجمعة. أن تُهيّئ مكاناً لاستقبال ما يتقاطر، بدل لوم انسيابه. لطف المطبخ يبقى دائماً هكذا، من دون صوت."},"ICON-2121":{"nm":"ريشة توجيه المروحة الهوائية","de":"لحظة انحراف الهواء المندفع مباشرة قليلاً على طول ريشة صغيرة، يلتقط هواء صالة التمرين الخانق أنفاسه أخيراً. تغيير التيار كان دائماً مسألة زاوية صغيرة كهذه."},"ICON-2122":{"nm":"عصابة الجبين","de":"لو ابتلّت الخصلات الأمامية أثناء غسل الوجه، لاختلّ اليوم كله. هذا الشريط الذي يرفع الشعر برفق عن الجبين يمنح من يقف أمام المرآة خمس دقائق جافة. لا تلاحظ قيمته إلا حين يغيب."},"ICON-2123":{"nm":"حامل مشبك كوب الشرب","de":"حين يتمايل الكوب بخطر عند حافة المكتب، يُمسك هذا المشبك بهدوء أحد جانبيه. يوم مرّ من دون انسكاب، ترسله رشفة ماء واحدة، يعود الفضل فيه إلى من أمسك الحافة نيابة عنك."},"ICON-2124":{"nm":"مقبض عروة نافذة التهوية","de":"النافذة المغلقة تماماً خانقة، والمفتوحة على اتساعها باردة. هذا المقبض بعروته يتذكر الفجوة المناسبة تماماً بينهما. فالتهوية في النهاية شأن قلبي - ترك الأشياء مفتوحة بالقدر الكافي."},"ICON-2125":{"nm":"غطاء زاوية مكعب الفلين","de":"الزاوية الحادة هي التي تؤذي دائماً عند الاصطدام. لذا يُنحت جزء من الفلين ليُكسى به كل ركن. المكان الملفوف برفق لن يؤلم ركبة أحد بعد الآن."},"ICON-2126":{"nm":"مقبض حزام الوسادة الطويلة","de":"حمل وسادة طويلة أكثر إزعاجاً مما يظن المرء. اربط حزاماً واحداً وستحملها بيد واحدة بسهولة. سرّ حمل الثقيل بخفة يكمن في مكان وضع المقبض."},"ICON-2127":{"nm":"مشبك إبزيم الحزام","de":"هناك أيام تشد فيها الخصر درجة أضيق، وأيام تُرخيه درجة. الذي يعرف حالك بأصدق طريقة هو هذا المشبك الصغير. قطعة معدن تُسجّل بصمت صدق الجسد."},"ICON-2128":{"nm":"قاعدة دعم ربع المكعب","de":"مكعب مقطوع إلى أرباع يسند الأرضية بثبات. لا مرتفعاً ولا منخفضاً، بل بذلك القدر بالضبط من التوازن. يُظهر بصمت أن الإسناد هو أن تخفض نفسك لترفع ما فوقك."},"ICON-2129":{"nm":"غطاء وسادة البيضة","de":"تُلبس وسادة مستديرة كالبيضة ثوباً مضبوطاً بدقة. وإن تشرّبت العرق، يكفي نزعها وغسلها. تعرف ربّة المنزل أن كل ما يلامس الجلد يومياً يحتاج إلى قطعة إضافية تتبدل بها."},"ICON-2130":{"nm":"إسفين تسوية المكعبات","de":"لو مالت الأرضية قليلاً فقط، اهتز كل ما بُني بعناية. أدخل إسفيناً رقيقاً واحداً في الفجوة، ويستعيد العالم مستواه. فتقويم الأشياء لا يحتاج إلى شيء عظيم."},"ICON-2131":{"nm":"عقدة نهاية الحزام","de":"تُعقد عقدة إحكام صلبة كي لا يتفكك طرف الحزام ويتهدل. الحبل المُنهى طرفه بعناية يدوم طويلاً. عقدة صغيرة واحدة تُعلّم أن الختام أصعب من البداية."},"ICON-2132":{"nm":"وسادة ركبة قابلة للطي","de":"ذلك الألم الحاد كلما لامست الركبة أرضية صلبة. وسادة واحدة تُطوى وتُفرد تنزلق برفق بين الركبة والأرضية. إنها رقة تسند ركبة أحدهم نيابة عنه."},"ICON-2133":{"nm":"قاعدة مانعة لانزلاق المكعب","de":"مهما كان المكعب متيناً، يصبح عديم الجدوى إن انزلق. التعرجات الدقيقة المحفورة في القاعدة تُطبق على الأرضية بإحكام. سرّ الثبات يختبئ دائماً في الجانب السفلي غير المرئي."},"ICON-2134":{"nm":"مشبك محاذاة القضبان","de":"تُصفّ القضبان في خط مستقيم وتُثبَّت بمشبك. من اعتاد ترتيب الصفوف يعرف ذلك الرضا الغريب والصغير الذي ينبع من وضع المعوجّ جنباً إلى جنب."},"ICON-2135":{"nm":"عروة حزام أوتار الركبة","de":"حين يشد خلف الفخذ حتى تنفلت صرخة، تمتد هذه العروة نحو أطراف الأصابع التي لا تصلها اليد. حيث لا يمكن الوصول وحدك، يمدّ خيط واحد جسراً لساقك."},"ICON-2136":{"nm":"وسادة فرد أصابع القدم","de":"حتى الأصابع المحبوسة داخل الحذاء طوال النهار تحتاج إلى استراحة. على وسادة تُباعد بينها، تتمطى القدم أخيراً. مساء يُرخي الجسد بدءاً من أبعد مكان فيه."},"ICON-2137":{"nm":"مقياس زاوية الوضعية","de":"بالعين وحدها، يستحيل تقدير كم درجة انحرفت وضعيتك. حين يُخبرك المقياس بهدوء عن الزاوية، يستقيم الجسد أخيراً. تدرّج يُظهر الميل الذي لم تكن تراه."},"ICON-2138":{"nm":"إسفين محاذاة الحوض","de":"بعد ظهيرة كسولة تصلّب فيها الحوض مائلاً إلى جانب واحد. تسند إسفيناً واحداً وتستعيد مركزك ببطء. ليس إجباراً على الاستقامة، بل مساعدة على إيجاد المكان الصحيح من جديد."},"ICON-2139":{"nm":"إبزيم شريط فتح الكتف","de":"شريط يُقوّم بهدوء الكتفين المنقبضتين. شدّ الإبزيم يفتح ببطء الظهر المحني. تنفّس بعمق بكتفين مفتوحتين على اتساعهما، وعندها فقط تظهر وقفة الانحناء على المسرح."},"ICON-2140":{"nm":"إسفين دعم العمود الفقري","de":"استلقِ على ظهرك ويرسم عمودك الفقري انحناءه الطبيعي. إسفين يسند ذلك الانحناء بهدوء من دون مقاومته. معرفة الراحة الحقيقية تبدأ من احترام الانحناء الذي وُلد به الجسد."},"ICON-2141":{"nm":"إسفين تمديد ظهر القدم","de":"تمديد ظهر القدم كان دائماً ينقصه شيء ما. اسند الإسفين المناسب وستتمدد بانتعاش إلى عمق لم تكن تصله. منحدر صغير يساعدك على الوصول أبعد قليلاً."},"ICON-2142":{"nm":"مسند محاذاة المعصم","de":"حين يبدأ المعصم المنحني أمام لوحة المفاتيح بالوخز، ينزلق المسند بهدوء تحته. أول من يعتني باليدين العاملتين طويلاً هي أشياء متواضعة منخفضة كهذه."},"ICON-2143":{"nm":"رباط دعم المعصم","de":"قبل رفع شيء ثقيل، تلفّ رباطاً حول المعصم مرة واحدة. طمأنينة تنمو مع كل لفة. عادة اللف مسبقاً قبل الإصابة هي السر الهادئ لمن يتمرن على المدى الطويل."},"ICON-2144":{"nm":"جيب هاتف الذراع","de":"أين تضع هاتفك أثناء الجري كان دائماً هاجساً. هذا الجيب المربوط على الساعد يأخذ ذلك الهمّ بعيداً. اركض وأغنيتك المفضلة مربوطة على ذراعك، وسيبدو الطريق أقصر بكثير."},"ICON-2145":{"nm":"غطاء نابض جهاز القبضة","de":"غطاء يُلبس طرف نابض جهاز القبضة كي لا يوخز راحة اليد. طوال القبض والإفلات المتكرر، تحفظ هذه السدادة الصغيرة السلام بين اليد والمعدن. رعاية في مكان لا يُرى."},"ICON-2146":{"nm":"كشتبان حماية أصابع القفاز","de":"كانت أصابع الجدة الماهرة في الخياطة تلبس دائماً كشتباناً. هذا الكشتبان المثبت في طرف القفاز يحمي طرف الإصبع. رغبة صون اليدين التي عملت طويلاً تتشابه بغرابة عبر الأجيال."},"ICON-2147":{"nm":"وسادة ثفنات القبضة","de":"الثفنات المتصلبة في راحة اليد هي بصمات تركها الجهد. وسادة تُلصق فوقها تجعل التكرار التالي ممكناً. بلفّ المكان المتصلّب من جديد، يتشبّث الإنسان مرة أخرى."},"ICON-2148":{"nm":"شريط مانع انزلاق راحة اليد","de":"حين تنزلق راحة اليد باستمرار، يُفلَت ما أُمسك بجهد. لفّ الشريط الخشن ويصير اليد والأداة جسداً واحداً. القوة التي لا تفلت تأتي، بغرابة، من الاحتكاك."},"ICON-2149":{"nm":"شريط امتصاص عرق الساعد","de":"قبل أن يصل العرق المنساب أثناء التمرين إلى المعصم، يمتصه هذا الشريط على الساعد أولاً. أن العرق ليس عاراً، تشهد على ذلك بصمت قطعة قماش مبللة تماماً."},"ICON-2150":{"nm":"رفّ تجفيف القفازات","de":"ارمِها بأي طريقة وسيكون الصباح التالي عذاباً، لكن علّقها بعناية وسيجففها النسيم طوال الليل من تلقاء نفسه. رائحة القفازات الجافة النظيفة تفتح الغد نقياً منعشاً."},"ICON-2151":{"nm":"مقبض سحاب ملابس الرياضة","de":"بيدين مبللتين تماماً، يستحيل الإمساك بسحاب صغير. علّق مقبضاً واحداً وستُسحب دفعة واحدة نظيفة. عروة تافهة تنقذ دقيقة كاملة من الارتباك."},"ICON-2152":{"nm":"رقعة تهوية طرد العرق","de":"تُوضع رقعة تهوية في أشد بقعة حرارة في الجسم. الحرارة المحبوسة تتسرب بهدوء عبر الرقعة. فعل فتح ثقب تنفس صغير واحد في قلب الاختناق."},"ICON-2153":{"nm":"قطعة وسادة نعل الحذاء","de":"تُقتطع القطعة البالية فقط من النعل القديم وتُستبدل بقطعة جديدة. لمسة لا ترمي الشيء كله، بل تستبدل فقط ما يؤلم. إصلاح صغير تحت القدم يجعل خطوات اليوم كلها أخف."},"ICON-2154":{"nm":"رقعة كي أرقام الرياضة","de":"يُضغط رقم الظهر بالمكواة ليُطبع على الثوب. بينما تبرد الحرارة، يستقر الرقم بثبات على القماش. ختم البداية الذي يجعل من يرتدون الرقم نفسه فريقاً واحداً."},"ICON-2155":{"nm":"غطاء تدعيم مقدمة الحذاء","de":"غطاء تدعيم على المقدمة يصدّ بهدوء مصير حذاء تصطدم مقدمته باستمرار. أول مكان يبلى يُصنع الأمتن. فكلما طال عمر الحذاء، كان أشد صلابة من طرف مقدمته."},"ICON-2156":{"nm":"عقدة حبل شدّ ملابس الرياضة","de":"لحظة شدّ حبل خصر ملابس الرياضة وعقده، يلتف الثوب الفضفاض حول الجسد بإحكام. هذه العقدة المحكمة التي لن تنفك تحافظ على الثبات طوال الحركات الشديدة."},"ICON-2157":{"nm":"شريط مانع انزلاق جورب الكاحل","de":"ذلك الإزعاج المتكرر لجورب الكاحل المنزلق داخل الحذاء. شريط واحد يُمسك ذلك الانزلاق. جورب صغير كان يُهمَل، يحافظ أخيراً على مكانه."},"ICON-2158":{"nm":"وسادة عرق إبط ملابس الرياضة","de":"وسادة تُوضع مسبقاً حيث ينبع العرق أكثر. مهما تشرّبت، لا يظهر أثر على سطح الثوب. الأشياء التي تعمل بصمت بعيداً عن الأنظار هي التي تُبقي المسرح نظيفاً."},"ICON-2159":{"nm":"عروة سحب كعب الحذاء","de":"بعد ارتداء الحذاء، اسحب عروة الكعب بلمسة خفيفة وتنزلق القدم بسهولة. تلك الراحة الوجيزة التي تعفيك من الانحناء. في صباح مزدحم، عروة كهذه تؤدي دوراً لا يُستهان به."},"ICON-2160":{"nm":"غطاء رأس مسدس التدليك","de":"يُستبدل الرأس بحسب مكان الطرق. لكل عضلة متصلبة شكل يناسبها تحديداً. مساء يختار للكتفين اللتين تحمّلتا اليوم شدة العزاء المناسبة تماماً."},"ICON-2161":{"nm":"قاعدة شحن مسدس التدليك","de":"حتى اليد التي ستُرخي الجسد طوال اليوم لا تستيقظ إلا بعد اكتمال الشحن. بينما يتحول الضوء الأحمر إلى أخضر، يمكنك الراحة قليلاً. حين يتوقف الوميض، يحين بهدوء دور تدليك الأكتاف المتيبسة من جديد."},"ICON-2162":{"nm":"قرص شدة مسدس التدليك","de":"خفيف، أكثر قليلاً، هنا يكفي. وأنت تدير القرص، تساوم أطراف أصابعك بهدوء جسدها. وعد اليوم - أن تشتد بقدر الألم فقط - مكتوب بوضوح بين التدريجات الصغيرة."},"ICON-2163":{"nm":"حلقة حامل كرة الاهتزاز","de":"حتى الكرة التي تتدحرج جيداً تحتاج مكاناً لتتوقف فيه لحظة. هذا الحامل الدائري يحتضن بهدوء القلب الراغب في التدحرج بعيداً، محافظاً على مكانها حتى يحين الدور التالي. الراحة أيضاً جزء من التمرين."},"ICON-2164":{"nm":"غطاء مقبض عصا الضغط","de":"بغطاء صغير واحد يُلبس الطرف، يتلاشى الألم في راحة اليد رويداً رويداً. بين الصلابة والجلد، يلزم دائماً طبقة لينة واحدة. لمسة رقيقة تُدوّر أولاً المكان الذي سيلامس."},"ICON-2165":{"nm":"كيس بكرة الفول السوداني","de":"كيس صغير يحفظ بكرة تدليك على شكل حبة فول سوداني. حين تتدحرج خارجة من زاوية الحقيبة، يخرج معها عزم الأمس على الاعتناء بالجسد اليوم أيضاً. كيس صغير يتذكر الوعد."},"ICON-2166":{"nm":"حامل بكرة تدليك القدم","de":"حين يهتز مكان إسناد القدم، يهتز الاسترخاء معه. هذا الحامل الذي يُثبّت البكرة يُطبق على الأرضية بإحكام، مهيئاً مكاناً تتكئ فيه قدمان متعبتان بأمان. الاطمئنان يأتي من عدم الاهتزاز."},"ICON-2167":{"nm":"سدادة قلب البكرة","de":"سدادة صغيرة تغلق قلباً مجوفاً. لا بد أن يُملأ الداخل غير المرئي كي لا يتشوّه الخارج. المكان الذي لن يراه أحد أثناء التدحرج، هذا الجزء الصامت يسنده بصبر."},"ICON-2168":{"nm":"غطاء طرف عصا التدليك","de":"غطاء مستدير يُكسى به طرف العصا. كي لا يبلى، كي لا يُخدش - حماية الطرف هي في النهاية طريقة إبقائها بجانبك طويلاً. رغبة في لفّ أول مكان يتلقى الصدمة بأنعم طريقة."},"ICON-2169":{"nm":"قاطع لفافة الشريط اللاصق","de":"بسحبة يد واحدة، يُقطع الشريط بنظافة. حتى في العقد والختام حيلة صغيرة، وهذه الشفرة تعرف إحساس النهاية المرتبة. النهاية النظيفة تجعل ما يليها أخف."},"ICON-2170":{"nm":"غطاء لاصق نهاية الشريط","de":"غطاء يضغط بهدوء على النهاية كي لا تنفك. يبدأ الجميع، لكن البقاء ملتصقاً حتى النهاية صعب دائماً. هذه اليد الصغيرة التي تمسك الشوط الأخير تتولى بصمت مسؤولية ختام اليوم."},"ICON-2171":{"nm":"كمّ ضغط المعصم","de":"لفّ طبقة واحدة حول معصم مُجهد، ويصل الألم متأخراً خطوة واحدة. كيد تُمسك بهدوء يدك، يصبح الضغط أحياناً أرق حماية. إنه ليس شداً، بل إسناداً."},"ICON-2172":{"nm":"إبزيم حماية الكاحل","de":"صوت النقرة القصير عند إغلاق الإبزيم يريح البال. لفّ الكاحل بإحكام، وتتصاعد بهدوء شجاعة تقول إنه ربما يصح أن تخطو خطوة أبعد. صوت صغير واحد يصبح بداية راسخة."},"ICON-2173":{"nm":"مشبك حزام ضغط الركبة","de":"تزداد الركبة ثباتاً بقدر ما يُشدّ الحزام. لن ينفك، لكن لن يؤلم أيضاً - وبينهما يوجد بالضبط ثقب واحد مناسب. لا ينسى المشبك ذلك المكان أبداً، في كل مرة."},"ICON-2174":{"nm":"مقص لصق الأصابع","de":"مقص صغير يقطع بدقة الشريط الملفوف حول مفصل الإصبع. طرفه مستدير كي لا يجرح الجلد. كلما كانت الأداة للعناية، شُحذت نصلها بلطف أكبر - يُظهر هذا المقص ذلك بصمت."},"ICON-2175":{"nm":"بكرة لف شريط الضغط","de":"بكرة تلف بترتيب شريط ضغط منحلاً. اليد التي تلف بعناية ما انتهت من استخدامه لن تتشابك في المرة القادمة أيضاً. في كل طبقة ملفوفة بترتيب، تتشرب أناقة اليوم."},"ICON-2176":{"nm":"رباط وسادة حماية الساق","de":"رباط يربط الوسادة التي تحمي مقدمة الساق. العقل الذي يفحص أولاً مكان الاصطدام المحتمل هو بذاته استعداد. ادخل الملعب بساقين معقودتين بإحكام، ويتضاءل الخوف في قلبك إلى النصف."},"ICON-2177":{"nm":"مشبك واقي الكوع","de":"مشبك صغير يعضّ بإحكام كي لا ينزلق الواقي. تافه كقرص ورقة، لكن إن انفكّ هذا، ترتخي كل الأشياء. تثبيت صغير واحد يمسك بإحكام طمأنينة يوم كامل."},"ICON-2178":{"nm":"مقبض حلقة التمدد","de":"أمسك الحلقة ومدّد جسدك، وسترى أطراف أصابع وصلت أبعد بشبر عن الأمس. ليس العضل وحده ما يتمدد بقدر الشد. القلب المتصلب أيضاً ينفرج قليلاً في تلك الأثناء."},"ICON-2179":{"nm":"فاصل تباعد أصابع القدم","de":"باعد بين الأصابع المحبوسة في الحذاء طوال اليوم، ويتسلل النسيم إلى المكان الضيق. ثمة أشياء في هذا العالم لا ترتاح إلا بعد الابتعاد قليلاً. حتى أطراف الأصابع تحتاج متسعاً لتتنفس."},"ICON-2180":{"nm":"لوح إسفين إرخاء الساق","de":"يُدس كالإسفين تحت الساق فتسترخي رويداً. زاوية مائلة واحدة تُسرّب بهدوء ثقل يوم كامل. الاتكاء بميل خفيف، هذا أحياناً أريح وضعية على الإطلاق."},"ICON-2181":{"nm":"مسند إرخاء الرقبة","de":"تُسند الرقبة عليه وتُغمض العينين قليلاً. أنه من المسموح وضع الرأس الثقيل جانباً للحظة، يهمس هذا المسند الصغير دائماً بهدوء للكتفين من مكانه المعتاد. حتى الاتكاء يحتاج شجاعة."},"ICON-2182":{"nm":"غطاء طرف عصا التمدد","de":"غطاء واحد يُغطي طرف عصا طويلة الامتداد. حين يكون الطرف ليناً، يطمئن أينما لامس. تدوير الزوايا أولاً مهما كانت الوجهة - هكذا يبدأ الاهتمام دائماً بصمت."},"ICON-2183":{"nm":"لوح نتوءات وسادة الضغط","de":"استلقِ فوق نتوءات متعرجة، وفي كل مكان مضغوط عليه يتسرب اليوم بعيداً. عند تلك الحدود بين الألم واللذة، تسترخي الأكتاف المتيبسة طوال اليوم ببطء وكأنها تستسلم."},"ICON-2184":{"nm":"ساعة رملية للتنفس والاسترخاء","de":"وعد هادئ بإطالة النَفَس حتى تسقط آخر حبة رمل. خيط الرمل الرفيع يُحصي بهدوء إيقاع الشهيق والزفير. والعقل المشغول أيضاً يهدأ قليلاً في تلك الأثناء."},"ICON-2185":{"nm":"مسند كرة ضغط باطن القدم","de":"أسند كرة في منتصف باطن القدم واضغط بثبات. للقدمين اللتين حملتا الجسد كله طوال اليوم، يترك هذا المسند الصغير مكانه بهدوء قائلاً إن الدور عليهما الآن ليُسنَدا. حتى ما يسند يحتاج وقتاً للراحة."},"ICON-2186":{"nm":"حبل حلقة إرخاء الكتف","de":"حبل حلقة يُعلَّق على الكتف ويُشد. مدّ الخيط نحو المكان المتصلب، وتنفك العقدة المتشابكة درجة درجة. يُظهر أن حتى التحرر يحتاج شيئاً يمسك بيدك."},"ICON-2187":{"nm":"قرص حبل الممر المائي","de":"حبة مستديرة واحدة من حبل الممر الذي يقسّم المسبح. حدّ لطيف يُرسم فوق الماء كي لا تصطدم بالسبّاح المجاور. فواصل صغيرة تحمي طريق كل واحد تدفع الجميع للتقدم جنباً إلى جنب حتى النهاية."},"ICON-2188":{"nm":"خطاف شدّ حبل الممر","de":"خطاف يشد حبل الممر ويعلّقه. إن ارتخى انحنى مع الموج، وإن شُدّ كثيراً انقطع. إيجاد الشدّ المناسب يشبه ضبط القلب، إذ تتلمس دائماً مكاناً ما بينهما."},"ICON-2189":{"nm":"غطاء لون الممر","de":"سدادة صغيرة تُلبَس لوناً مختلفاً لكل ممر. علامة مطلية كي تتعرف على طريقك بلمحة حتى من بعيد. أن يمنع لون واحد التِيه - الإرشاد أصلاً يبدأ من هذا اللطف البسيط."},"ICON-2190":{"nm":"لوح تعليق حبل الممر","de":"لوح يُعلَّق عليه حبل الممر بترتيب حين لا يُستخدم. في اليد التي ترتب الحبل بعناية للانطلاقة التالية، يكمن بهدوء عزم هادئ على إنهاء اليوم بشكل جيد."},"ICON-2191":{"nm":"مقبض بكرة لفّ حبل الممر","de":"أدر المقبض دورة تلو دورة لتجمع الحبل الطويل المنفكّ. جمع ما تناثر يتطلب دائماً صبراً. دورة، ثم أخرى - هكذا يكتمل الختام ببطء، من دون استعجال."},"ICON-2192":{"nm":"ملقط عقدة نهاية الممر","de":"ملقط يعضّ بإحكام كي لا تنفك عقدة نهاية الحبل. لا يترك حتى جزءاً ضئيلاً يفلت. لا بد من يد تراقب حتى النهاية كي يحافظ حبل طويل على شكله المرتب من دون تشابك."},"ICON-2193":{"nm":"حبة عوّامة حبل الممر","de":"حبة عوّامة حبل الممر التي تطفو على الماء. كي لا تغرق، احتضنت في داخلها هواءً وافراً. أن بعض الخفة تأتي من فراغ مُلئ بجهد، تُظهره الأمواج المتلاطمة في كل مرة."},"ICON-2194":{"nm":"علم رقم الممر","de":"علم صغير يعلن رقم الممر. قطعة قماش واحدة ترفرف في الريح تخبرك بوضوح \"هذا مكانك\". معلم صغير لكنه لا لبس فيه، يرشدك مباشرة إلى طريقك من دون تِيه."},"ICON-2195":{"nm":"خطاف وصل حبل الممر","de":"خطاف يصل حبلاً بحبل آخر. بخطاف واحد يعيد وصل طريق منقطع، يكتمل الممر المائي أخيراً. الوصل هو في النهاية عمل قطعة معدن صغيرة تمدّ يدها بهدوء بين أشياء تباعدت."},"ICON-2196":{"nm":"لوح دواسة كتلة الانطلاق","de":"الدواسة فوق خط الانطلاق تستقبل كاملاً ثقل القفزة الأولى. تلك الثانية العُشر من الركل بكل قوة - صلابة ما تدوسه أطراف الأصابع تدفع بداية سباق كامل. كل انطلاق يبدأ من مكان يُداس بثبات."},"ICON-2197":{"nm":"عارضة مقبض الانطلاق","de":"العارضة التي تُمسكها اليدان بإحكام قبيل إشارة الانطلاق. لا بد من تثبيت القلب المرتجف في مكان ما كي لا يهتز الانطلاق. مجرد وجود ما يُمسَك يجعل الحركة التالية أوضح وأثبت بكثير."},"ICON-2198":{"nm":"حبل أعلام السباحة الظهرية","de":"حبل أعلام يُخبر السابح الذي ينظر إلى السقف بأن الجدار اقترب. لطف يُنذر مسبقاً بما لا يُرى. بإشارة واحدة تعتني بظهرك، تصبح الضربة الأخيرة آمنة."},"ICON-2199":{"nm":"وسادة جدار الانعطاف","de":"وسادة لينة تُلصَق على الجدار حيث يتغير الاتجاه. كي لا تؤلم حتى مع الاصطدام القوي، تحتضن مكان الانعطاف بنعومة. في طريق العودة، يسبق دائماً لطف هادئ من أحدهم."},"ICON-2200":{"nm":"لوح لمسة الوصول","de":"لحظة ملامسة طرف الإصبع، ينتهي كل شيء. نهاية طريق طويل لاهث تنحصر في هذه الطرقة الخفيفة الواحدة. الوصول ليس شيئاً عظيماً، بل هو إصابة المكان الصحيح تماماً، يُجيب اللوح بهدوء."},"ICON-2201":{"nm":"شريط منزلق منصة الانطلاق","de":"عند حافة المنحدر، يحبس الجميع أنفاسهم للحظة واحدة على الأقل. تجاوز ذلك الخوف العابر وانزلق إلى الأسفل، وفجأة تنطلق الضحكة مع رذاذ الماء. كل بداية تبدأ دومًا خلف خطوة صغيرة من الخوف."},"ICON-2202":{"nm":"مخروط علامة مسافة الدوران","de":"عندما تتردد عند مفترق الطرق، تتحدث هذه النقطة الصغيرة أولًا. تقول لك: عد من هنا، لا تضل الطريق. يرى أحدهم هذا اللون الواحد فيجد اتجاهه من جديد ويمضي."},"ICON-2203":{"nm":"إسفين زاوية كتلة الانطلاق","de":"في تلك النبضة النصفية حين ينحني الجسد إلى أدنى وضعية، قبيل الوثبة مباشرة. هناك موطئ صغير يسند الزاوية كي لا تنزلق أطراف أصابع القدمين. كل لحظة تحليق عالٍ تولد من هذا الميل."},"ICON-2204":{"nm":"غطاء واقٍ لحافة الجدار","de":"كي لا يؤلم الاصطدام أثناء اللعب، تخلت الحافة عن حدتها ولانت. رغبة ألا تتأذى نُحتت مرارًا حتى التصقت بالجدار. أرقّ حماية غالبًا ما تكون بهذا الصمت."},"ICON-2205":{"nm":"خطاف تعليق طوق النجاة","de":"في العادة، ليس سوى مكان يُعلَّق عليه شيء ما. لكن في اللحظة التي يسقط فيها أحدهم في الماء، هذا هو أول مكان تمتد إليه يد. هناك نوع من الاعتماد في هذا العالم يكون أفضل حين لا يُستخدم أبدًا."},"ICON-2206":{"nm":"عصا خطاف الإنقاذ","de":"ذراع طويلة تقرّب في لحظة واحدة مسافة يتعذر بلوغها. حين تقصر اليد، يصير هذا الخطاف يدًا بديلة. الإنقاذ، في النهاية، هو أن تمدّ أطراف أصابعك لشخص بعيد."},"ICON-2207":{"nm":"رأس دش حافة المسبح","de":"\"لا تنسَ أن تغتسل قبل الدخول.\" كما لو كانت العبارة المعتادة لمراقب المسبح، ينهمر تيار الماء فوق الرأس. مع دفقة باردة واحدة، يتساقط غبار اليوم قطرة قطرة."},"ICON-2208":{"nm":"بلاطة أرضية مانعة للانزلاق","de":"نقوش دقيقة بارزة كي لا تنزلق القدم الحافية. من مكان لا يُرى، تمسك بثبات أخمص القدمين. أمتن أمان يختبئ دومًا في الأماكن غير اللافتة."},"ICON-2209":{"nm":"لوحة عمق المياه","de":"قبل أن تضع قدمك في الماء، يخبرك الرقم أولًا بالعمق. مكان قد يخيفك إن دخلته جاهلًا، يهدأ له القلب بمجرد أن تقرأه. كل ما تفعله هذه اللوحة هو أن تساعد في قدر صغير من الاستعداد."},"ICON-2210":{"nm":"حبل عوامات خط الأمان","de":"حبال ملونة تطفو على سطح الماء فاصلة بين المناطق. تعِد العوامات، وهي تتشابك بالأيدي، بأن هذا الحد آمن. بوجود الحدود يمكن أخيرًا أن تسبح بحرية وطمأنينة."},"ICON-2211":{"nm":"حوض تعقيم غمس القدمين","de":"حوض صغير تمكث فيه القدم الحافية لحظة قبل دخول الماء. طقس قصير من النقاء يبدأ من القدمين محفوظ فيه. النظافة تبدأ دومًا بعناية هذه الخطوة الواحدة."},"ICON-2212":{"nm":"مخروط تحذير الأرضية المبللة","de":"مخروط أصفر واحد يُبطئ الخطى برفق. \"الأرض مبللة هنا، احذر.\" رعاية تُقدَّم باللون بدل الكلمات. هذا التحذير الصغير يحرس بهدوء يوم من كاد أن ينزلق."},"ICON-2213":{"nm":"خزانة إسعافات أولية جدارية","de":"نادرًا ما تُفتح الخزانة البيضاء المعلقة على الجدار. لكن في اللحظة التي تُفتح فيها، تصبح راحة بال لشخص ما. الطوارئ تنتظر دومًا بهدوء في أقرب مكان."},"ICON-2214":{"nm":"شبكة كشط سطح الماء","de":"ترفع بهدوء الأوراق والغبار العائم على السطح. الصفاء لا يأتي من تلقاء نفسه، فلا بد ليد أحدهم أن تلتقطه مرة كل يوم. خلف الماء الساكن، توجد شبكة مجتهدة."},"ICON-2215":{"nm":"خرطوم روبوت تنظيف الأرضية","de":"حتى في ليلة ينام فيها الجميع، يتجول ببطء متحسسًا الأرض. أكثر العمال إخلاصًا في الساعات التي لا يراقبها أحد. ذلك الصفاء الصباحي هو الأثر الذي رسمه هذا الخرطوم طوال الليل."},"ICON-2216":{"nm":"علبة جرعات الكلور","de":"حتى في الحفاظ على صفاء الماء، ثمة مقدار مناسب تمامًا. إن زاد قسا، وإن نقص تعكّر - التوازن بين الاثنين. يد غير مرئية تضبط بهدوء ذلك المقياس كل يوم."},"ICON-2217":{"nm":"زجاجة فحص جودة المياه","de":"تجمع رشفة ماء في زجاجة صغيرة لتسأل عن حال اليوم. للعين تبدو كما هي دائمًا، لكن الأرقام لا تكذب. الاطمئنان هو ما يُتحقق منه مرة كل يوم على هذا النحو."},"ICON-2218":{"nm":"شوكة جمع ألواح اللعب المائي","de":"شوكة طويلة تجمع الألواح والحطام العائم على سطح الماء. يد تجمع المتناثر تشبه القلب بطريقة ما. حتى الفوضى، إذا كُنست مرة، تعود إلى الترتيب."},"ICON-2219":{"nm":"شبكة غطاء المصرف","de":"شبكة دقيقة تحرس الممر الذي يخرج منه الماء. تفرز بهدوء ما يُترك يذهب وما يُحتفظ به. حتى في توديع الأشياء يلزم مرشّح، تخبرك هذه الشبكة الصغيرة بصمت."},"ICON-2220":{"nm":"عوامة قياس حرارة الماء","de":"كشّاف صغير يطفو على الماء ليقرأ درجة الحرارة. أباردة هي أم مناسبة، لطف يخبرك قبل أن يلامس جسدك الماء. أول اطمئنان عند الدخول يبدأ دومًا من هذه العوامة."},"ICON-2221":{"nm":"قضيب لفّ غطاء المسبح","de":"مقبض يلفّ غطاءً واسعًا ويحفظه جانبًا. أداة تعرف متى تُفرد ومتى تُطوى تبدو موثوقة بطريقة ما. في وقت الراحة، كأنها تُدثِّر الماء أيضًا بلحاف."},"ICON-2222":{"nm":"سلة سكيمر المسبح","de":"السلة التي يتجمع فيها أخيرًا الحطام العائم على السطح. لأن هناك وعاءً يستقبل الشوائب في مكان لا يُرى، يبقى سطح الماء صافيًا دومًا. خلف النظافة يتراكم الجهد."},"ICON-2223":{"nm":"حامل تجفيف قبعة السباحة","de":"تُعلَّق قبعة السباحة المشبعة بالماء مقلوبة. بينما تتساقط منها القطرات واحدة تلو الأخرى، تلتقط القبعة أنفاسها ببطء. الجفاف، في النهاية، ليس سوى اسم آخر للانتظار."},"ICON-2224":{"nm":"عروة حزام كتف ملابس السباحة","de":"عروة صغيرة تمسك الحزام كي لا ينزلق عن الكتف. من مكان لا يُرى، تحافظ بهدوء على هندام مرتب. الأناقة تكتمل دومًا فوق دعامات صغيرة كهذه."},"ICON-2225":{"nm":"كيس ترتيب قبعات السباحة","de":"كيس تجد فيه قبعات السباحة المبللة أماكنها واحدة تلو الأخرى. مأوى صغير يحتضن الأشياء سهلة التبعثر في حضن واحد. الترتيب عادة رقيقة لمحاولة ألا تفقد الأشياء."},"ICON-2226":{"nm":"بطانة صدر ملابس السباحة","de":"بطانة واحدة تستقر برفق داخل الثوب. غير مرئية من الخارج، لكنها تعدّل بلطف وضعية كتفي مرتديها. بعض الطمأنينة تُملأ بهدوء من الداخل لا من الخارج."},"ICON-2227":{"nm":"مشبك بطاقة اسم قبعة السباحة","de":"مشبك صغير يُثبّت بطاقة اسم على طرف قبعة السباحة. بين أشياء متشابهة، يقول بوضوح: \"هذه لي.\" علامة واحدة تنهي الالتباس في الحال."},"ICON-2228":{"nm":"عروة سحّاب ملابس السباحة","de":"\"هل يمكنك رفع سحّاب ظهري؟\" ذلك المكان الذي لم تبلغه يدك وحدها، تسحبه هذه العروة الصغيرة بدلًا من اليد. مسافة رقيقة تساعد في الخطوة الأخيرة."},"ICON-2229":{"nm":"لوح منع التفاف قبعة السباحة","de":"تُقوَّم وتُسند قبعة سباحة اعتادت الالتفاف. دعامة تساعد بهدوء الشيء الملتوي على استعادة شكله. لا بد من يد تقوّمه كي يعود أي شيء مستقيمًا سويًّا من جديد."},"ICON-2230":{"nm":"مشبك ربط خصر ملابس السباحة","de":"مشبك يلفّ الخصر بالقدر المناسب ويثبّته كي لا ينزلق للأسفل. لا شديد الضيق ولا رخو، بل مقدار العدل ذاك. الراحة تسكن دومًا في مكان ما بين الاثنين."},"ICON-2231":{"nm":"ملقط قلب قبعة السباحة","de":"ملقط يمسك قبعة سباحة مقلوبة ويعيدها إلى وضعها الصحيح دفعة واحدة. لمسة اليد التي تعيد المقلوب إلى وضعه السليم مُرضية إلى حد ما. متعة الترتيب الصغيرة تأتي من أمور تافهة كهذه."},"ICON-2232":{"nm":"حزام مقبض لوح الركل","de":"حزام يلتف حول اليد كي لا يفلت لوح الركل. حتى وأنت تُدفع بتيار الماء، وجود شيء تتمسك به راحة كبيرة. لا يزال ارتعاش يوم تعلم الركل لأول مرة عالقًا في هذا الحزام."},"ICON-2233":{"nm":"حزام تثبيت عوامة السباحة","de":"حزام يمسك بإحكام العوامة المثبتة بين الساقين. فقط حين لا تنحلّ، يمكنك أخيرًا أن تركز على الوضعية وحدها. فوق شيء مثبَّت جيدًا، يتعمق تمرين ذلك اليوم شيئًا فشيئًا."},"ICON-2234":{"nm":"معلّق زعانف الجدار","de":"حين تُعلَّق الزعانف جنبًا إلى جنب على الجدار، تبدو تمامًا كسرب من البط يستريح قرب الماء. أقدام أنهت سباحتها تنفض الماء برفق منتظرة الغد. حتى الفاصلة تبدو مستديرة ولطيفة بطريقة ما."},"ICON-2235":{"nm":"غطاء حافة لوح الركل","de":"غطاء صغير واحد يُوضع على حافة لوح الركل. كي لا يؤلم الاصطدام، وكي لا يتلف مع الاهتراء، يلفّ الطرف. سرّ إبقائه بجانبك طويلًا يكمن في العناية بحوافه أولًا."},"ICON-2236":{"nm":"شبكة تخزين الزعانف","de":"زعانف تشبه أقدام البط المكففة تستحم بالشمس داخل الشبكة. كأنها بطات خرجت للتو من الماء تُجفف ريشها، تجف ببطء داخل الشبكة. قيلولة هانئة تحضيرًا للسباحة القادمة."},"ICON-2237":{"nm":"بطاقة ترتيب عوامة السباحة","de":"تُلصق بطاقة اسم على كل عوامة لتوضيح صاحبها بجلاء. كلما كان المكان يتشاركه كثيرون، ارتاح القلب أكثر حين يتضح \"لمن هذا\". بطاقة صغيرة واحدة تُرسي النظام."},"ICON-2238":{"nm":"حامل تصريف لوح الركل","de":"مكان يُسند بميلان كي يتساقط الماء المتجمع في لوح الركل قطرة قطرة. لا بد أن تفرّغ ما احتويته كي تخفّ، يخبرك الحامل بصمت. الخطوة الأولى للجفاف هي أن تُسند الأشياء جيدًا."},"ICON-2239":{"nm":"مشبك ربط حزام الزعانف","de":"قطعة صغيرة تشد حزام الزعنف ليلائم القدم تمامًا. إن ارتخى انزلق، وإن شُدّ آلم - تلك الدرجة الدقيقة الحساسة. لتنساب خفيفًا كبطة ذات أقدام مكففة، تحتاج هذا الهامش الرفيع."},"ICON-2240":{"nm":"رقاقة إيقاع الركل","de":"رقاقة صغيرة تخبرك بالإيقاع كلما ركلت. واحد، اثنان، ثلاثة - حين يستقر الإيقاع في جسدك، يتحول الماء إلى أغنية دون أن تشعر. تعلّمك هذه الرقاقة برفق أن للسباحة إيقاعًا أيضًا."},"ICON-2241":{"nm":"كيس ملابس السباحة المبللة","de":"داخل الحقيبة الخارجة من المسبح، أنا دومًا أول من يحجز مكانًا. فلتنظر إليّ الأمتعة الأخرى بريبة، ماذا أفعل - يجب عزل المبلل كي نبقى جميعًا جافين. غرفة الحجر الصحي للرطوبة، ذلك هو المنصب الرقيق الذي أشغله."},"ICON-2242":{"nm":"لوح عصر الماء","de":"للماء طبيعة تجعله يهرب خلسة عند أول ضغطة. ضغطة، ثم أخرى - لا يستسلم إلا حين يُوضع فوق اللوح ويُحمَّل بثقل. لمن لم يجد استخدامًا لقوة معصمه، نادرًا ما يجد مسرحًا أفضل من هذا."},"ICON-2243":{"nm":"لوح فاصل حقيبة السباحة","de":"إذا وُضع كل شيء في حجرة واحدة، يختلط المبلل بالجاف. عمل الانزلاق بهدوء بينهما ورسم خط فاصل. إن كان فاصل واحد يجلب السلام، فربما يكون التصالح أمرًا بسيطًا على نحو مفاجئ."},"ICON-2244":{"nm":"كيس أحذية مقاوم للماء","de":"يبتلع حذاء ملطخًا بالرمل بأكمله دون أن يغيّر تعبيره قيد أنملة. مهما جرى في الداخل، يبقى الخارج جافًا - تلك اللياقة التي تحرسها مقاومة الماء. كيس كتوم اللسان مرحّب به في كل مكان."},"ICON-2245":{"nm":"سدادة تصريف حقيبة السباحة","de":"أدر السدادة، فينسال اليوم المتجمع في قاع الحقيبة دفعة واحدة. ترتيب ما بعد اللهو الممتع يعتمد دومًا على هذه الفتحة الصغيرة الواحدة. حتى معرفة كيف تدع الأشياء تسيل بعيدًا تتطلب تصميمًا."},"ICON-2246":{"nm":"سجادة امتصاص الماء","de":"تستلقي بهدوء أمام المدخل، تستقبل رطوبة كل قدم داخلة. حتى لو لم يعترف بها أحد، الأرضية تعرف - لم ينزلق أحد اليوم أيضًا. في مكان صامت يسكن أجر صامت."},"ICON-2247":{"nm":"طبق حامل قبعة السباحة المبللة","de":"حين تفقد قبعة سباحة مُلقاة مكانًا تذهب إليه، أرفعها أنا. رغم أنني أُدعى طبقًا وأحمل قطرات ماء بدل الطعام، إن كان العمل هو تهيئة مكان لأحدهم، فحتى الحامل يستطيع أن يرفع رأسه بفخر."},"ICON-2248":{"nm":"مشبك تجفيف المناشف","de":"عملي أن أعضّ بإحكام على منشفة فوق حبل الغسيل. عنادي الذي لا يتخلى مهما داعبتني الريح هو فخري. حتى تجفّ في الشمس، لا تُرخي اليد التي أمسكت قبضتها أولًا."},"ICON-2249":{"nm":"خطاف تعليق الحقيبة المقاومة للماء","de":"في لحظة تعليقها على الخطاف، تحصل الحقيبة الهائمة أخيرًا على عنوان. حتى لو كانت مجرد متدلية تستعير ركنًا من الجدار، هل هناك ما هو مطمئن مثل مكان لا داعي فيه للخوف من الضياع؟"},"ICON-2250":{"nm":"سوار دخول الزحليقة","de":"الحماس الذي كان ينتظر دوره بهدوء يتكثف كله في هذا السوار الصغير الواحد. فقط بعد تثبيته على المعصم يبدأ طابور الزحليقة بالتموج، فلعل الدخول ليس سوى ربط وعد حول المعصم."},"ICON-2251":{"nm":"قطعة حصيرة الزحليقة المائية","de":"يركض الناس فوقها بمرح دون أن يلاحظوا الفجوة تحت أقدامهم. حصيرة فُرشت كي لا ينزلق أحد، لا تكشف وجودها إلا حين تفقد قطعة واحدة منها. أشياء كثيرة في هذا العالم لا تُذكر إلا بالفراغ الذي تتركه."},"ICON-2252":{"nm":"سوار مقاوم للماء لمفتاح الخزانة","de":"حراسة مفتاح الخزانة من الماء وظيفتي مدى الحياة. ملتفًّا حول المعصم أتشارك في الرذاذ، لكنني أحافظ على ذلك المفتاح جافًا تمامًا وحده. لو ضعتُ لما وجدتَ حتى ملابسك، فأنا فعلًا حارس ذو مسؤولية جسيمة."},"ICON-2253":{"nm":"لوحة إشارة انطلاق الزحليقة","de":"في تلك اللحظة العابرة حين يتحول الأحمر إلى أخضر، تقفز كل قلوب من فوق الزحليقة معًا. سلطة منح الإذن بالانطلاق - من كان يظن أن لوحة إشارة صغيرة كهذه يمكن أن تحمل كل هذا الحماس."},"ICON-2254":{"nm":"مشبك سترة النجاة لنهر الاسترخاء","de":"مشبك يمسك بإحكام جسدًا يطفو على نهر الاسترخاء. فقط بعد ذلك الصوت \"طقّ\" تسترخي أخيرًا وتستسلم للتيار. الاطمئنان أحيانًا يبدأ من مزلاج صغير كهذا."},"ICON-2255":{"nm":"راية توجيه حوض الأمواج","de":"تُخبر الجميع مسبقًا بموعد قدوم الأمواج. رفع الراية يعني الهتاف، وخفضها يعني لحظة لالتقاط الأنفاس. من الطريف أن ما يضبط الإيقاع عند حافة الحوض المتلاطم هو مجرد قطعة قماش واحدة."},"ICON-2256":{"nm":"قلادة رقم الزحليقة","de":"ارتدِ حول عنقك رقم الطابور الذي أنت فيه، ولن يحدث خلط أبدًا. بطاقة رقم واحدة تحسم من له الدور - النظام، على ما يبدو، غالبًا ما يبدأ من قلادة صغيرة كهذه."},"ICON-2257":{"nm":"عملة إعادة شحن السوار","de":"قرّبها برفق من السوار وتكتمل عملية الشحن. في عصر التجول في الماء دون نقد أو بطاقة، هذه العملة الصغيرة تؤدي دور محفظة كاملة. بقدر ما يخفّ وزن معصمك يخفّ القلب أيضًا."},"ICON-2258":{"nm":"غطاء مقبض مدفع الماء","de":"مقبض مدفع الماء يُستمتع به حين يُقبض بإحكام. افقد غطاءً واحدًا وانسَ التصويب، فهو يدور في يدك دون توقف - نتيجة معركة الماء في عز الصيف تتوقف على هذه القطعة الصغيرة الأخيرة."},"ICON-2259":{"nm":"كوب قالب برج قلعة الرمل","de":"احشُ الرمل المبلل واضغط بإحكام ثم اقلبه، فيرتفع برج صغير. لا أحد يفهم أفضل مني ذلك القلب الذي يواصل البناء رغم علمه أنه سينهار. لمعماري الرمل، القالب هو المخطط نفسه."},"ICON-2260":{"nm":"أسنان مشط الرمل","de":"اسحبه كأنك تمشط الرمل، وتبقى أخاديد مرتبة. رغم علمها بأن الأمواج ستمحو النقش قريبًا، تواصل الأسنان بجد رسم خطوطها. في صنع أشياء مآلها الزوال بعناية فائقة سحر خاص أيضًا."},"ICON-2261":{"nm":"ثقل تثبيت عمود المظلة","de":"يقف بصمت عند القاعدة كي لا تطير المظلة مع الريح. حراسة الظل ليست مهمة القماش اللافت، بل مهمة الثقل الراسخ الثقيل. الوزن غير المرئي هو الأكثر اعتمادًا دومًا."},"ICON-2262":{"nm":"مقبض منخل الرمل","de":"هزّ لتغربل الرمل، ولن يبقى في يدك سوى الأصداف والكنوز الصغيرة. أمسك المقبض وهزّ برفق - نصف البحث عن كنوز الشاطئ يُحسم بهذا المنخل الواحد."},"ICON-2263":{"nm":"قالب رمل على شكل صدفة","de":"املأه بالرمل المبلل، انقر برفق مرات، وتتفتح أصداف بحجم راحة اليد صفًا على الشاطئ. قد لا تستطيع أكل صدفة حقيقية، لكن هذا الشكل يستطيع أي شخص صنعه. سحر صيفي بسيط."},"ICON-2264":{"nm":"دبوس ضبط زاوية المظلة","de":"كلما تحركت الشمس، يجب على المظلة أن تدير رأسها لتتبعها. اسحب الدبوس وأعد تثبيته، فيتحرك الظل بهدوء إلى مكانه الجديد. جوهر فن تجنّب الضوء يكمن في هذه الزاوية الصغيرة."},"ICON-2265":{"nm":"غطاء طرف نصل مجرفة الرمل","de":"ضعه على طرف النصل الحاد ويبقى داخل الحقيبة آمنًا. اجعل شجاعة حفر الرمل جانبًا للحظة، فبغطاء واحد يصبح لعبة وديعة. معرفة كيفية إخفاء الحدة أيضًا نوع من اللطف."},"ICON-2266":{"nm":"مشبك حافة حصيرة الشاطئ","de":"حين تحاول الريح رفع حافة الحصيرة، أعضّ عليها بإحكام. الحفاظ على مكان واحد فوق الرمل يعود في النهاية إلى عناد الزوايا الأربع جميعًا. عصر بلا خفقان هو ثمرة جهد مشابك صغيرة."},"ICON-2267":{"nm":"خطاف تعليق الملابس بظل المظلة","de":"علّقها ببساطة على عمود المظلة، وتجفّ الملابس المبللة في الظل. بعيدًا عن الشمس، معرضة للنسيم، حبل غسيل مؤقت أقامه خطاف واحد. حتى على الشاطئ، تحضر حكمة تدبير المنزل."},"ICON-2268":{"nm":"حقيبة عنق للهاتف مقاومة للماء","de":"احتضن هاتفك وعلّقه حول عنقك، فتجد الشجاعة لالتقاط الصور حتى تحت الماء. حفظ تلك الرغبة في التقاط لقطة إضافية آمنة وجافة. كحارس شخصي للذكريات، إنه متين إلى حد كبير."},"ICON-2269":{"nm":"حقيبة مقاومة للماء للملابس المبللة","de":"تحتضن الملابس المبللة التي غيّرتها بأكملها دون تذمر. عدم ترك قطرة ماء واحدة تلمس بقية الأمتعة كبرياؤها، فتُطبق فمها بإحكام وتحرس ركنًا من الحقيبة. النهاية النظيفة تبدأ مني."},"ICON-2270":{"nm":"حزام رست صندل اللعب المائي","de":"يلتف برفق حول رست القدم كي لا ينزلق الصندل الحافي. اركض في الرمل كما تشاء، وحزام واحد يكفي لتطمئن. رفيق موثوق لخطواتك، لا يُلاحظ لكنه دومًا بجانبك."},"ICON-2271":{"nm":"علبة عنق مقاومة للماء للبطاقات","de":"تحمل تذاكر الدخول والبطاقات وتُعلَّق حول العنق لترافقك في اللعب المائي. انغمس في الرذاذ كما يحلو لك دون خوف من الفقدان، فهي تحمي البطاقات جاعلة جسدها درعًا. وضعية حارس شخصي موثوق."},"ICON-2272":{"nm":"كيس قماش مانع لتبخر نظارات السباحة","de":"امسح الجزء الداخلي المشوش من نظارات السباحة مرة واحدة بالقماش، فيعود العالم تحت الماء واضحًا من جديد. كيس قماش صغير واحد هو المفتاح الذي يفتح رؤية غائمة نحو الصفاء."},"ICON-2273":{"nm":"فرشاة تنظيف الرمل الرطب","de":"تنفض حتى الرمل بين الأصابع برفق ودقة. اليد الأخيرة التي ترتب آثار جولة ممتعة في البحر، عند عتبة البيت مباشرة. مرة واحدة تمر بها الفرشاة، ويودّع رمل اليوم بأكمله أخيرًا."},"ICON-2274":{"nm":"كيس سحّاب مقاوم للماء للعملات","de":"يحبس بضع عملات معدنية بإحكام خلف السحّاب. سواء ابتلّت أو لا، تبقى رنّتها كما هي، فمال الطوارئ لشراء وجبة خفيفة محروس حتى النهاية. كيس صغير لكنه مدبِّر حصيف."},"ICON-2275":{"nm":"رباط لفّ منشفة اللعب المائي","de":"لفّ منشفة واربطها برباط واحد، وتتدلى مباشرة من حزام الحقيبة. اليدان حرّتان، والمنشفة على الكتف. سرّ اللعب المائي بأمتعة خفيفة يختبئ في هذه الحزمة الصغيرة."},"ICON-2276":{"nm":"غطاء حلقة مفاتيح السوار المقاوم للماء","de":"زرّ الإتمام الأخير على السوار الذي يحرس المفتاح من الماء. فقط حين ينغلق الغطاء بصوت \"طقّ\" تقفز أخيرًا مطمئنًا إلى المسبح. نقطة نهاية صغيرة لكن بلا ثغرات، تتولى مسؤولية إحكام الإغلاق."},"ICON-2277":{"nm":"سدادة فم الأنبوب التنفسي","de":"عضّ عليها وينفتح ممر التنفس، ويقترب المشهد تحت البحر من عينيك مباشرة. سدادة صغيرة تتيح لك التنفس حتى تحت الماء. من كان يظن أن استعارة نفس يمكن أن تكون مثيرة إلى هذا الحد."},"ICON-2278":{"nm":"وسادة مانعة لتبخر قناع الغوص","de":"حين يتشوش الجزء الداخلي من القناع، تفقد المشاهدة تحت الماء بريقها أيضًا. وسادة واحدة توقف ذلك الضباب، فرؤية واضحة هي ثمرة هذه الطبقة الواحدة غير المرئية."},"ICON-2279":{"nm":"مشبك تثبيت أصابع الزعنف","de":"يشد طرف الزعنف ليلائم القدم تمامًا، فتركل الماء دون أي ارتخاء. كي لا تتسرب القوة الكامنة في ركلة واحدة، يعقد المشبك بصمت عقدة محكمة عند الطرف."},"ICON-2280":{"nm":"غطاء حزام قناع الغوص","de":"يلفّ حزام القناع برفق كي لا يشدّ الشعر. طبقة واحدة من الاهتمام تُزيل تلك اللسعة التي كانت تحدث كل مرة عند خلعه. ما يعتني به غطاء صغير هو، على نحو مفاجئ، اللطف نفسه."},"ICON-2281":{"nm":"غطاء صمام تصريف الأنبوب التنفسي","de":"حتى في فعل حبس النفس، توجد فجوة يتسرب منها الماء بهدوء. صمام صغير واحد يعيد توجيه ذلك التسرب برفق ويحرس مساحة الشهيق حتى النهاية. البحر يتذكر هذا الاجتهاد الصغير بأكبر امتنان."},"ICON-2282":{"nm":"خطاف تخزين الزعانف","de":"حين تتدلى الزعانف مرتبة على خطاف واحد مثبت في الجدار، ينزل هدوء مرتب حتى على غرفة المعدات الفوضوية. وضع الأشياء في مكانها هو أهدأ وعد نحو الغطسة القادمة."},"ICON-2283":{"nm":"وسادة مشبك الأنف لقناع الغوص","de":"وسادة واحدة تضغط الأنف برفق. بفضل هذا اللطف الصغير الذي يمنع الماء من الاندفاع، يحافظ الوجه على تعبيره حتى في البحر البارد."},"ICON-2284":{"nm":"حارس رأس الأنبوب التنفسي","de":"الحارس الملفوف حول طرف الأنبوب التنفسي يدفع الماء بهدوء حين تعبر الأمواج فوقه. كلما كان عمل القطعة غير مرئي، كلما دعمت بعمق أكبر أمان نفس واحد."},"ICON-2285":{"nm":"شريط مانع للانزلاق لنعل الزعنف","de":"شريط رفيع ملصق بنعل الزعنف. خط احتكاك واحد تتشبث به أطراف الأصابع كي لا تنزلق على سطح مبلل. الأمان يبدأ دومًا بهدوء في نُسج صغيرة كهذه."},"ICON-2286":{"nm":"غطاء صمام أسطوانة الأكسجين","de":"غطاء يغطي صمام أسطوانة ممتلئة بالهواء. كي لا يستقر الغبار، وكي لا يتلوث ممر التنفس. التغطية عناية مسبقة تصل حتى إلى النفس الأول للشخص القادم."},"ICON-2287":{"nm":"غطاء فوهة منظم التنفس","de":"المكان الذي يلامس الشفتين يجب أن يكون الأنظف دومًا. هذا الغطاء الواحد فوق الفوهة يحرس بصمت مدخل النفس من رياح الملح والرمل."},"ICON-2288":{"nm":"عروة سحب سحّاب بدلة الغوص","de":"عروة سحب قصيرة مثبتة على سحّاب بدلة الغوص. لمسة مدروسة أُضيفت كي تستطيع حتى الأيدي المتخدرة من برودة الماء سحبها لأعلى دفعة واحدة. حتى في إغلاق الثياب يتسلل تفكير أحدهم الدقيق."},"ICON-2289":{"nm":"غطاء حماية عداد الهواء","de":"غطاء الحماية الملفوف حول زجاج العداد الذي يخبرك بالهواء المتبقي. لأن تلك الأرقام يجب ألا تغيم أبدًا. كلما كان المقياس يقرأ الحياة نفسها، زادت العناية في مسحه وتغطيته."},"ICON-2290":{"nm":"مشبك حزام الأثقال","de":"أناس يلفون الثقل حول خصورهم للنزول إلى الأعماق. في تلك اللحظة العابرة التي يُفتح فيها مشبك واحد أو يُغلق، يتجمع الاختيار بين الصعود والغرق بهدوء عند أطراف الأصابع."},"ICON-2291":{"nm":"حزام معصم فانوس الغوص","de":"في الماء الحالك السواد، حزام واحد مربوط حول المعصم يمسك الفانوس بإحكام. حتى لو أفلتت اليد، يظل الضوء تابعًا. عدم فقدان وميض صغير وسط الظلام مطمئن لهذا السبب."},"ICON-2292":{"nm":"مشبك ترتيب خرطوم التنفس","de":"مشبك صغير يجمع الخراطيم المبعثرة في مكان واحد. امنع التشابك مسبقًا ولن تتخبط اليدان حتى في لحظة عاجلة. الترتيب لطف هادئ تجاه نفسك في المستقبل."},"ICON-2293":{"nm":"تقوية أصابع قفاز الغوص","de":"قماش تقوية موضوع فوق كل طرف إصبع. الأماكن التي تسحب الحبال وتتمسك بالصخور لا بد أن تهترئ أولًا، لذا وُضعت طبقة إضافية لتحتضن ذلك التآكل سلفًا."},"ICON-2294":{"nm":"حلقة قاعدة أسطوانة الأكسجين","de":"حلقة قاعدة واحدة تُبقي أسطوانة ثقيلة منتصبة. تحتضن بشكل دائري ثقلًا كان يمكن أن ينقلب، مانحة إياه التوازن. الإسناد هو أن تمنح جانبك كي لا يسقط شيء ما."},"ICON-2295":{"nm":"غطاء زعنفة لوح ركوب الأمواج","de":"غطاء يلفّ الطرف الحاد لزعنفة أسفل اللوح. كي لا تتأذى وأنت تمشي على الرمل، يُريح للحظة ذلك الطرف الذي كان يشق الأمواج. أثناء الراحة، لا بأس أن يكلّ الجميع حدّته."},"ICON-2296":{"nm":"غطاء حماية طرف نصل المجذاف","de":"غطاء حماية يحرس طرف نصل المجذاف. يمنع الخدوش الناتجة عن ارتطامه بالصخور من إخلال مسار الماء. اعتنِ بالطرف، وستحملك ضربة مجذاف واحدة أبعد."},"ICON-2297":{"nm":"مقبض مجذاف الكاياك","de":"مقبض ملفوف في المكان الذي تلتقي فيه راحة اليد بالمجذاف. يُسند برفق ذلك المكان الذي كانت تتشكل فيه النفطات، كي لا تكره اليدان المجذاف حتى وهما تصعدان النهر عكس التيار."},"ICON-2298":{"nm":"علبة صفيح لتخزين شمع ركوب الأمواج","de":"علبة صفيح صغيرة تحفظ كتلة من الشمع. ذلك السحر الذي يثبّت قدميك على اللوح يُستخرج دومًا من هذه العلبة بحجم راحة اليد. من علبة أنيقة واحدة يبدأ استعداد اليوم."},"ICON-2299":{"nm":"عروة تثبيت رباط الكاحل","de":"العروة التي تشد الرباط الواصل بين الكاحل واللوح. عقدة واحدة تعد بألا تفلتك حتى وأنت تُجرف مع موجة كبيرة. الاتصال وعد بالتمسك كي لا تنجرف بعيدًا."},"ICON-2300":{"nm":"سدادة هواء لوح التجديف الواقف","de":"لوح يتصلّب حين يمتلئ بالهواء، والسدادة التي تحبس ذلك النفس. افتحها فيطوى مسطحًا، أغلقها فيقف على الماء. سدادة صغيرة واحدة تحمل يومًا ينتفخ ثم يهبط."},"ICON-2301":{"nm":"حزام وسادة مقعد الكاياك","de":"حزام يربط الوسادة بالمقعد. من أجل الظهر والخصر اللذين يجدّفان طويلاً وهما جالسان، يُبقي النعومة في مكانها كي لا تنزلق بعيداً. فحتى الراحة تحتاج إلى عقدة محكمة."},"ICON-2302":{"nm":"واقي مقدمة لوح ركوب الأمواج","de":"واقٍ يلفّ مقدمة اللوح. إنه حشوة أُضيفت إلى الأنف الذي يتلقى الاصطدامات كثيراً، لكي يفقد حدّته هو أولاً. أن تضع النعومة في المكان الذي يتقدّم الصفوف هو عهدٌ باستخدامه طويلاً."},"ICON-2303":{"nm":"إبزيم إغلاق الحقيبة المضادة للماء","de":"إبزيم تطويه وتُحكم إغلاقه مرتين وثلاثاً كي لا تتسرّب نقطة ماء واحدة. حفظ الأشياء الثمينة جافّةً يتطلّب دائماً لمسة يد إضافية. وذلك الإحكام الأخير هو ما يمنح الطمأنينة."},"ICON-2304":{"nm":"قطعة من شبكة مرمى كرة الصالات","de":"قطعة واحدة من الشبكة التي كانت تهتزّ في المرمى ذات يوم. تتذكّر، خيطاً خيطاً، هتافات لحظة امتلأت فيها بالكرة. في كل عقدة عاش هدف، وفي كل موضع بالٍ لا تزال مباراة ذلك اليوم حيّة."},"ICON-2305":{"nm":"فوهة مضخة كرة القدم","de":"فوهة مضخّة تنفخ الهواء في كرة أُفرغت من الهواء. الجلد الذي كان يتدحرج مترهّلاً وكئيباً يقفز ويرتدّ من جديد. أن تملأها هو أن تُنهض لعبة متوقّفة على قدميها من جديد."},"ICON-2306":{"nm":"قاعدة علم الركنية","de":"قاعدة تُقيم علماً منتصباً عند ركن الملعب. إنها علامة صغيرة تشير إلى الحدود، لكن بتلك النقطة الواحدة تكتسب الأرض الترابية أخيراً شكل الملعب الحقيقي."},"ICON-2307":{"nm":"رباط واقي الساق","de":"رباط يشدّ واقي الساق إلى السمّانة. يُحكم قبضته على الموضع الذي يتلقّى الصدمات كثيراً، فتبقى كل خطوة دون خوف حتى وسط الاحتكاك الخشن."},"ICON-2308":{"nm":"دبوس استبدال مسامير الحذاء","de":"دبوس لاستبدال مسمار بالٍ بآخر جديد. الأسنان الصغيرة عند طرف الحذاء التي تتشبّث بالعشب. كي لا تنزلق، عليك أحياناً أن تعيد البناء من تحت قدميك."},"ICON-2309":{"nm":"غطاء صمّام كرة القدم","de":"غطاء صغير يسدّ فتحة تنفّس الكرة. يحرس المدخل كي لا يتسرّب الهواء الذي ملأته. أن تحافظ على شدّه يشبه ألّا تفقد حدّتك حتى المباراة القادمة."},"ICON-2310":{"nm":"مخروط رسم خطوط الملعب","de":"مخروط يرسم خطوطاً على الأرض ليقسم الطريق. من هنا فريقنا، ومن هناك الفريق الآخر. مخروط صغير واحد يحوّل أرضاً خالية فوضوية إلى ملعب له قواعد."},"ICON-2311":{"nm":"فرشاة غبار حذاء كرة الصالات","de":"فرشاة تكنس التراب والغبار العالق في تجاعيد حذاء كرة الصالات. حين تنتهي المباراة، يتراكم على الحذاء أيضاً تراب يوم كامل. ولمسة النفض هذه تحية صامتة للقدمين اللتين ركضتا بإتقان."},"ICON-2312":{"nm":"معلّاق قفّازات الحارس","de":"معلّاق يجفّف قفازات حارس المرمى ويحملها. إنه المكان الذي ترتاح فيه اليدان المبلّلتان بالعرق قليلاً، بقدر ما صدّتا من تسديدات. من أجل المباراة القادمة، يجفّ المبلّل ويرتخي القلب المتصلّب رويداً رويداً."},"ICON-2313":{"nm":"حلقات تعليق شبكة السلة","de":"الحلقات الصغيرة التي تعلّق الشبكة بالطوق. بفضلها تُصدر الكرة ذلك الصوت الناعم حين تمرّ خلالها. ذلك الصوت الرنّان للتسجيل يبدأ في الحقيقة من هذه الخطاطيف الصغيرة."},"ICON-2314":{"nm":"أداة تنفيس هواء كرة السلة","de":"أداة تُخرج قليلاً من هواء الكرة الشديدة الصلابة. فالشدّ الزائد يجعل الارتداد جامحاً. تخفيف الهواء بالقدر المناسب: كرة ذات إحساس جيد تولد دائماً من ذلك التوازن الملائم."},"ICON-2315":{"nm":"وسادة استشعار اللوحة الخلفية","de":"وسادة استشعار ملصقة خلف اللوحة الخلفية. تقرأ لحظة ملامسة الكرة بوضوح، في أرقام. حتى اللحظة التي تفوتها العين يتذكّرها هذا الحسّ الصغير، فيصبح الحكم أكثر عدلاً."},"ICON-2316":{"nm":"مخاريط عوائق المراوغة","de":"مخاريط عوائق مصفوفة على طريق تمرين المراوغة. بين التملّص هنا وهناك تنمو مهارة القدمين. أن تقف عائقاً هو أيضاً لطف يعلّم كيفية النفاذ بشكل أفضل."},"ICON-2317":{"nm":"فرشاة صمّام كرة السلة","de":"فرشاة صغيرة تنظّف فتحة صمّام الكرة. فإن سدّها الغبار لن تدخل الإبرة، لذا تنظّف من المدخل غير المرئي أولاً. قبل أن تملأ شيئاً، عليك دائماً أن تفرغه وتنظّفه."},"ICON-2318":{"nm":"لفافة شريط لصق الأصابع","de":"لفافة شريط تُلفّ حول الأصابع. تُحكم قبضتها على مفصل ملتوٍ، فتمنح الشجاعة للإمساك بالكرة من جديد. تضميد جرح هو إعلان صغير بأنك لن تتوقّف."},"ICON-2319":{"nm":"مشبك رقم القميص","de":"مشبك يثبّت الرقم على القميص. فبدلاً من اسمك، يجول رقم في الملعب. وفي تلك القرصة الواحدة المحكمة كي لا يسقط، يُكتب بوضوح من يلعب اليوم."},"ICON-2320":{"nm":"حلقة هدف تمرين التسديد","de":"حلقة هدف تُثبّت داخل الطوق لتضيّق المرمى. تُصغّر المساحة التي يجب أن تدخلها الكرة، فتدرّبك على تحمّل الإخفاق. ارمِ نحو ذلك الباب الضيّق طويلاً، وستتعلّم أطراف أصابعك الدقّة دون أن تشعر."},"ICON-2321":{"nm":"ممسحة نعل حذاء كرة السلة","de":"قبل الدخول إلى الملعب، تنحني وتمسح النعل أولاً. لأنك لا تريد أن تترك ولو زلّة واحدة على الأرضية الخشبية. اغرس تلك الخطوة الأولى بأطراف قدم نظيفة، فتصبح أنت اليوم أكثر ثباتاً قليلاً من أنت الأمس."},"ICON-2322":{"nm":"حلقة شدّ شبكة الكرة الطائرة","de":"الشدّ لا يُرى بالعين. لكن في اللحظة التي تشدّ فيها الحلقة الحبل إلى نهايته وتتوقّف، تقسم الشبكة الملعب إلى نصفين بشبر واحد من التوتّر. توازن تمسكه يد غير مرئية يوقظ المباراة."},"ICON-2323":{"nm":"مشبك تثبيت الهوائي","de":"الهوائي الذي كان يتمايل باستمرار مع الريح يقف منتصباً بمجرّد مشبك واحد. شيء صغير يكبح اهتزازاً كبيراً. واليد التي تثبّت بهدوء سلكاً واحداً خلف الكواليس تتحرّك أيضاً بهذا القدر تماماً من الحبّ."},"ICON-2324":{"nm":"معلّاق سترة الليبرو","de":"سترة اختصاصي الدفاع الملوّنة تُعلَّق على الحائط، تنتظر المباراة القادمة. اسم لا يلمع، لكنه يسند الملعب كله: الليبرو. هناك، في أكثر المواقع انخفاضاً، توجد العينان الأبعد نظراً."},"ICON-2325":{"nm":"جراب واقي الركبة","de":"كلما تدحرجت على الأرض أكثر، اصطدمت ركبتاك أكثر. هذا الجراب الصغير الذي يحفظ الواقيات بعناية يعرف: أن مَن يتعلّم أولاً كيف يسقط بشكل جيّد هو مَن يحلّق في النهاية أبعد من الجميع."},"ICON-2326":{"nm":"مقياس ضغط كرة الطائرة","de":"لا يمكن معرفة ذلك بنقرة طرف الإصبع. إبرة المقياس ترتجف بخفّة وتشير إلى علامة واحدة. قياس نَفَس كرة واحدة هو أوّل زرّ في المباراة. من ضغط صادق يولد مسار صادق."},"ICON-2327":{"nm":"شريط خطّ ملعب الدودج بول","de":"دائرة واحدة مرسومة بالشريط على تراب الملعب. داخلها وخارجها يفصلان كوناً كاملاً من لعبة المطاردة نصف اليوم. اليد التي رسمت الخطّ تعرف أنّ القاعدة هي بداية اللعب ذاتها."},"ICON-2328":{"nm":"حامل صافرة الحكم","de":"حين يخفت صوت الصافرة الحادّ، تُوضع بهدوء في مكانها على الحامل من جديد. إنه الموضع الأقرب لسماع أنفاس الحكم. والعدالة تبدأ دائماً من مهمّة صغيرة هي الحفاظ على المكان."},"ICON-2329":{"nm":"هدف حائطي لتمرين التمرير","de":"في فجر لا أحد فيه ليستقبل الكرة، ترفع أطراف أصابعك آلاف المرات نحو الهدف الملصق على الحائط. الحائط هو أكثر الزملاء تسامحاً. والكرة التي يعيدها تنهض بك من جديد وأنت منهك."},"ICON-2330":{"nm":"قضيب قياس ارتفاع الشبكة","de":"حتى لو انخفضت الشبكة بمقدار إصبع واحد، تنحرف المباراة عن مسارها. في لحظة رفع قضيب القياس، تتحوّل العدالة من رقم إلى عادة يومية. دقّة غير مرئية تحرس الملعب."},"ICON-2331":{"nm":"دبوس زاوية كتلة الانطلاق","de":"من وضعية الانحناء، الزاوية التي تلامس عندها أطراف الأصابع الكتلة، تلك الدرجة الواحدة تحدّد الانطلاقة. بدبوس واحد تثبّت الكتلة وتضبط أنفاسك. وضعية البداية ترافقك بهدوء حتى خطّ النهاية."},"ICON-2332":{"nm":"علم رقم مسار الجري","de":"علم صغير مغروس في كل مسار يهزّ رقمه مع الريح. الجميع يركضون في الاتجاه نفسه، لكن لكل واحد طريقه الخاص. يحتضن المضمار التوازي والاختلاف في آن واحد."},"ICON-2333":{"nm":"غطاء طرف عصا التتابع","de":"من أجل تلك اللحظة التي ستلامس يد العدّاء الأخير، يُدوِّر الغطاء الحواف بنعومة. أثمن ما في سباق التتابع ليس السرعة، بل اليد التي تُسلَّم إلى الشخص التالي."},"ICON-2334":{"nm":"معلّاق شريط قياس الأرقام","de":"تُعلَّق شريط القياس الذي سجّل الأرقام على الحائط كي لا يتشابك. إنه المكان الذي تتدلّى فيه مسافة الأمس ومسافة اليوم جنباً إلى جنب. التقدّم يأتي دائماً أولاً في هيئة فارق صغير في الأرقام."},"ICON-2335":{"nm":"مخروط تحديد منعطف المضمار","de":"مخروط صغير موضوع داخل المنعطف يخبرك بنيّة الطريق. لا تنعطف إلى الداخل كثيراً، ولا تتشتّت إلى الخارج. من يجيد الالتفاف هو من يتصدّر في النهاية."},"ICON-2336":{"nm":"مشبك شريط خطّ النهاية","de":"ذلك الشريط الذي سيلامس صدراً أولاً، يمسكه المشبك بشدّ ويظلّ منتظراً. خيط وُجد ليُقطع. يتحمّل الريح طوال اليوم من أجل ثانية واحدة لشخص ما."},"ICON-2337":{"nm":"غطاء مسدّس الانطلاق","de":"حتى تنطلق إشارة \"الطلقة\"، تنام فوهة المسدّس تحت غطائها. وعاء صوت يحمل البداية بداخله. كلما اشتدّ الصمت، ازداد صدى الطلقة الأولى انتشاراً بعيداً."},"ICON-2338":{"nm":"دبوس ضبط ارتفاع الحواجز","de":"كلما رفعت الارتفاع درجة، تغيّر موضع الدبوس ليتبعه. والخوف أيضاً ينمو بذلك القدر تماماً. ومع ذلك تقدّر القدمان في كل مرة موضعاً أعلى قليلاً وتواصلان الركض."},"ICON-2339":{"nm":"قرص عدّاد الأشواط","de":"حين تفقد العدّ لعدد الأشواط المتبقّية، تدير القرص درجة واحدة. طقطقة الرقم المتناقص الصغيرة تعيد القوة إلى الساقين. اليد التي تحصي المسافة المتبقّية تحافظ على وتيرتك."},"ICON-2340":{"nm":"حامل تخزين عمود القفز بالزانة","de":"العمود الطويل المرن يحتاج مكاناً خاصاً به ليستند إليه. لأنه أداة يجب أن تنحني لتقفز، تُقيمه بعناية أكبر. مرونة محفوظة جيداً تحتضن أعلى القفزات."},"ICON-2341":{"nm":"مجرفة تسوية حفرة الرمل","de":"تسوّي ببطء حتى آثار أقدام اللاعب السابق بالمجرفة. تعود حفرة الرمل مستوية من جديد، كأنها المرّة الأولى، في كل جولة. اليد التي تمحو الآثار من أجل قفزة شخص ما موجودة هناك، صامدة وصامتة."},"ICON-2342":{"nm":"شريط تحديد مسافة الاقتراب","de":"خطوة ناقصة لا تفي، وخطوة زائدة لا تفي أيضاً. شريط تحديد المسافة على الأرض يخبرك بصدق أين تضع قدمك للانطلاق. الاقتراب الجيّد ليس طمعاً أهوج، بل حساباً هادئاً."},"ICON-2343":{"nm":"مقبض قرص الرمي","de":"إن انزلقت الأصابع، تُرمى الرمية قبل أن ترميها فعلاً. ملمس المقبض الخشن الملتفّ حول القرص يكبح الدوران. توقيت الإطلاق يبدأ دائماً من إحساس القبضة."},"ICON-2344":{"nm":"حلقة حامل كرة دفع الجلة","de":"حلقة حامل تحتضن بهدوء الكرة الحديدية الثقيلة كي لا تتدحرج بعيداً. عشّ صغير يحفظ السكون قبل لحظة الرمي مباشرة. كلما كانت القوة أكثر انفجاراً، وجب أن يكون موضع استقرارها أكثر ثباتاً."},"ICON-2345":{"nm":"غطاء واقي رأس الرمح","de":"غطاء يوضع فوق رأس الرمح الحادّ يغلّفه بصمت ناعم. حين تستلقي أداة صُنعت للتحليق بعيداً بهدوء ساكنة، يُروَّض الخطر باللطف. حتى في التخزين تعيش السلامة."},"ICON-2346":{"nm":"مشبك حامل عارضة القفز العالي","de":"كي لا تسقط العارضة حتى عند لمسة خفيفة، يسندها المشبك بتوازن بديع. الموضع المسؤول عن ذلك الخطّ المرتجف بين العبور والسقوط. العدالة تسكن في التفاصيل الصغيرة."},"ICON-2347":{"nm":"مثبّت زاوية حصيرة الهبوط","de":"إن ارتفعت زاوية حصيرة الهبوط، يُصاب أحدهم. المثبّت يضغط الزوايا الأربع بإحكام. كي يهبط الجسم الذي حلّق أعلى بأمان أكبر، يسنده من الخفاء."},"ICON-2348":{"nm":"شريط حدود دائرة الرمي","de":"حدود موضع الرمي تُرسم بخطّ واحد من الشريط. وبحسب الدوس على ذلك الخطّ أو عدمه، يحيا الرقم القياسي أو يموت. خيط واحد نحيل حيث تلتقي الحرية بالقاعدة، وعد."},"ICON-2349":{"nm":"قاعدة مطّاطية لعارضة التوازن","de":"كي لا تهتزّ عارضة التوازن الضيّقة، تُطبق القاعدة المطاطية على الأرض بإحكام. ذلك التوازن الخالي من الارتجاف الذي يتكشّف فوقها هو في الحقيقة من صنع ثبات خفيّ تحتها."},"ICON-2350":{"nm":"لفافة مقبض العقلة","de":"كي لا تنزلق الكفّ، تُلفّ لفافة حول مقبض العقلة. سرّ الدوران المتلألئ لا يكمن في البهرجة بل في يد مقبوضة بإحكام. العرق المتساقط على الحصيرة يعرف ذلك."},"ICON-2351":{"nm":"مثبّت ارتفاع حبال جهاز الحلق","de":"إن اختلف ارتفاع الحبلين بمقدار عرض كفّ واحد، تنهار الحركة. المثبّت يمسك ذلك التوازن بصمت. وفوق ارتفاع مضبوط بدقّة فقط يبدأ التحليق الحرّ أخيراً."},"ICON-2352":{"nm":"غطاء مقبض حصان الحلق","de":"الغطاء الملفوف حول المقبض يقي راحة اليد من التقرّحات. تحت الحركة الدوّارة المتلاحقة توجد يد تخدّشت والتأمت مرّات لا تُحصى. الحماية عهد لطيف نحو التمرين القادم."},"ICON-2353":{"nm":"دبوس ضبط المسافة بين قضيبي المتوازي المختلف الارتفاع","de":"تُضبط المسافة بين القضيبين بدقّة بواسطة دبوس. تلك المساحة الفارغة التي سيعبرها الجسم تصبح المسرح. أطراف الأصابع تعرف أولاً: فوق مسافة دقيقة تولد أجرأ القفزات."},"ICON-2354":{"nm":"غطاء نابض لوحة القفز","de":"لحظة ركل اللوحة، يدفع النابض الجسم نحو السماء. الغطاء يلفّ قوة ذلك الارتداد بإحكام. أقصر اقتراب يصنع أطول تحليق في الهواء."},"ICON-2355":{"nm":"كيس بودرة المغنيسيوم","de":"البودرة البيضاء التي تفركها على يديك تعويذة صغيرة تمحو الانزلاق. الطقس القصير المتمثّل في إدخال اليد إلى الكيس وإخراجها يهدّئ الخوف. حتى التوتر، في النهاية، يُروَّض عند أطراف الأصابع."},"ICON-2356":{"nm":"لفافة معصم الجمباز","de":"لفّ الشريط حول المعصم يشدّ معه خيوط القلب أيضاً. إمساك مفصل كان سيهتزّ، مسبقاً. معصم واحد مربوط جيداً يسمح بهدوء بدوران أكثر جرأة."},"ICON-2357":{"nm":"حلقة أمان الأرجوحة الهوائية","de":"قبل رمي الجسم في الفراغ مباشرة، تصبح حلقة الأمان يداً غير مرئية. فقط حين يزول الخوف من السقوط يمكنك التحليق أبعد ما يكون. الثقة تُكمّل التحليق."},"ICON-2358":{"nm":"غطاء علبة كرات التنس","de":"تحت الغطاء الذي يسدّ فوهة العلبة، تنام كرات جديدة حاملة ضغطها. صوت الفرقعة الصغير عند فتح علبة يوقظ إثارة المباراة. الختم وعد يحفظ النضارة."},"ICON-2359":{"nm":"ملقط شدّ أوتار المضرب","de":"يعضّ الملقط على شدّ الوتر بإحكام ولا يتركه حتى النهاية. لأنّ توتّر وتر واحد يحدّد ارتداد الكرة. ذلك الإحساس غير المرئي باليد يبدأ من هذا الملقط الصغير."},"ICON-2360":{"nm":"مكنسة خطوط ملعب التنس","de":"حين تنتهي المباراة، تُكنس ببطء على طول الخطوط البيضاء للملعب. أزل التراب وتعود الخطوط واضحة من جديد. تمهيد الطريق للمباراة القادمة، تلك العناية الأخيرة تُحيي الملعب."},"ICON-2361":{"nm":"شريط حماية رأس المضرب","de":"لفّة واحدة حول إطار المضرب، وحتى الاصطدامات الخشنة تُستقبل بنعومة. أعرف أنّ الحافة هي الموضع الذي يبلى أولاً. ولأنّ تحمّل ذلك البلى بدلاً عنّي هو نصيبي، أقف اليوم أيضاً في أقصى الخارج."},"ICON-2362":{"nm":"شريحة استشعار حرارة الصالة الرياضية","de":"الريح الباردة التي تندفع عند فتح الباب في الفجر، تقرأها شريحة بحجم راحة اليد قبل أيّ إنسان. أن تستشعرها قبل أن يبرد الأنف حتى، إنها أهدأ تحية تفتح يوم صالة رياضية خالية."},"ICON-2363":{"nm":"لوحة قدم خطّ الأساس","de":"للاعب المتردّد في أين يضع طرف قدمه، خطّ واحد مرسوم على الأرض يكفي. الخطّ الذي يجب ألّا يتجاوزه يصبح هو ذاته خطّ انطلاق أبعد قفزة، تخبرك اللوحة بصمت."},"ICON-2364":{"nm":"معلّاق سلّة كرات التنس","de":"تحمل عشرات الكرات في فمّ واحد دون أن تُسقط ولو كرة واحدة. جمع ما تناثر في الملعب وتسليمه للتمرين القادم، يد مشغولة بصمت في الزاوية تتدلّى هنا اليوم أيضاً."},"ICON-2365":{"nm":"غطاء طرف مقبض المضرب","de":"لحظة تركيبه بنقرة في نهاية المقبض، يستقرّ المضرب أخيراً في راحة اليد. غطاء صغير يفصل بين الانزلاق والطمأنينة. سدّ الطرف بإحكام هو ما يجعل الضربة الأولى ثابتة."},"ICON-2366":{"nm":"مشبك منشفة جانب الملعب","de":"حتى لو هبّت الريح بعنف، يُطبق فمه ويصمد بجانب الملعب كي لا تطير المنشفة التي عُصرت بعناية. حتى في حماية استراحة قصيرة لالتقاط الأنفاس، تكون أطراف أصابع شخص ما ماهرة قد عملت."},"ICON-2367":{"nm":"ملقط تسوية ريش الريشة الطائرة","de":"ريشة واحدة مشوّشة تكفي لاهتزاز الطيران. قوّم الجناح المجعّد بلطف، وتستعدّ الريشة الطائرة للتحليق مستقيمة من جديد. الوصول بعيداً يبدأ دائماً من مثل هذا التزيين الصغير."},"ICON-2368":{"nm":"غطاء أنبوب الريشة الطائرة","de":"كي لا تلين الريشات المصفوفة بالداخل، تسدّ طرف الأنبوب بإحكام. رأيت طويلاً ما يكفي لأعرف أنّ لمسة رطوبة واحدة تُطرح الريشة أرضاً. الحفظ الجيّد بالفعل جزء من المباراة."},"ICON-2369":{"nm":"حامل استقرار كرة تنس الطاولة","de":"الكرة الصغيرة التي كانت تتدحرج تلتقط أنفاسها قليلاً فوقي. إسنادها بهدوء كي لا تتدحرج بعيداً، إنه اللطف الأكثر استدارة الذي يُقدَّم بجانب الطاولة."},"ICON-2370":{"nm":"أسطوانة مطّاطية لمضرب تنس الطاولة","de":"مرّر الأسطوانة بهدوء فوق وجه المطاط، فيرتفع الغبار القديم وتعود اللزوجة إلى الحياة. يجب أن يحيا الدوران كي تنحني الكرة. حالة المضرب اليوم تستيقظ من هذه اللمسة الرقيقة الواحدة من العناية."},"ICON-2371":{"nm":"عصا قياس ارتفاع الشبكة","de":"حتى لو ارتفعت الشبكة شبراً واحداً، تتغيّر طبيعة اللعبة. من يرفضون في النهاية الثقة بالعين المجرّدة يقرّبونني منها. يبدو أنّ العدالة لا تأتي إلا من ارتفاع مقيس بدقّة بالمسطرة."},"ICON-2372":{"nm":"شريحة استشعار سرعة الريشة الطائرة","de":"سرعة الريشة الطائرة وهي تشقّ الهواء، أحسبها بهدوء. حين تستقرّ السرعة غير المرئية سابقاً في رقم واضح، تصبح كلمة المدرّب التالية أكثر وضوحاً بكثير. إنه عمل تحويل الحدس إلى حقيقة."},"ICON-2373":{"nm":"كبسولة تخزين كرة تنس الطاولة","de":"ضع كرة مستديرة بلطف داخل الكبسولة، وتتراجع الخدوش والغبار بعيداً. أملاً أن تبقى سالمة حتى المباراة القادمة، إنه القلب الذي يهب غرفة صغيرة كاملة."},"ICON-2374":{"nm":"معلّاق أوتار مضرب الريشة","de":"علّق الأوتار المرتخية بترتيب، ولن تتخبّط اليد التالية في الدور. الترتيب هو في النهاية أشبه برسالة لطيفة تكتبها مسبقاً لك في الغد. اليوم يُريح الغد."},"ICON-2375":{"nm":"شريط حماية حافة مضرب تنس الطاولة","de":"الحافة التي يسهل أن يرتفع عندها المطّاط، أحتضنها بهدوء بخطّ واحد. فإن انفتحت الحافة، يضطرب حتى ملمس الكرة. حماية الزاوية تصبح، في النهاية، حماية لنقطة واحدة."},"ICON-2376":{"nm":"كيس تدفئة كرة الاسكواش","de":"الكرة الباردة نادراً ما ترتدّ. قبل المباراة، كيس يُدفئها ويحتضنها كأنه راحة يد. ذلك الدفء الصغير المنقول إلى اليد يحدّد مسبقاً نَفَس وإيقاع الجولة."},"ICON-2377":{"nm":"ملقط شبكة عصا اللاكروس","de":"حين تبدأ عقدة الشبكة بالارتخاء بهدوء، أعضّ على تلك العقدة الواحدة دون كلمة. يجب أن تكون الشبكة مشدودة كي تبقى الكرة فيها. هنا اليد التي تمسك المباراة بأكملها من موضع غير مرئي."},"ICON-2378":{"nm":"شريط حماية طرف مضرب الاسكواش","de":"كلما ضربت الحائط بقوة أكبر، بكى المضرب أولاً من طرفه. لفّ ذلك الطرف الباكي بلطف، وسيلعب معك موسماً إضافياً. من يعرف كيف يوفّر الطرف هو من يمسك المضرب طويلاً في النهاية."},"ICON-2379":{"nm":"غطاء نصل عصا الهوكي","de":"ضع الغطاء فوق النصل الحادّ، وأخيراً تطمئنّ كل من الحقيبة وأطراف الأصابع. تهدئة شيء خطير بصمت، إنها اللياقة القديمة التي تراعيها أولاً عند حزم العصا."},"ICON-2380":{"nm":"قماش تلميع كرة الكريكيت","de":"افرك الكرة الحمراء بالقماش، ويحمل أحد جانبيها الضوء كالمرآة. يعرف الرامي بحاسّة أطراف أصابعه أنّ الكرة تنحني حين يحيا اللمعان. حتى في التلميع الدؤوب تسكن استراتيجية صامتة."},"ICON-2381":{"nm":"غطاء أنبوب تخزين كرات اللاكروس","de":"كي لا تتدحرج الكرات الصلبة كما يحلو لها، تسدّ فوهة الأنبوب بإحكام. تجميع أشياء يسهل تناثرها في مكان واحد بلطف، أساسيات الإدارة تكون دائماً بهذا القدر من الصغر."},"ICON-2382":{"nm":"قطعة هدف حائط الاسكواش","de":"قطعة هدف صغيرة مثبّتة في الحائط تجمع عيني اللاعب المرتبكتين إلى نقطة واحدة. النقطة الوحيدة التي تخبرك أين تصوّب، حتى ذلك الحائط الواسع يضيق أمام هذه القطعة إلى هدف واضح."},"ICON-2383":{"nm":"كمّ مقبض عصا الهوكي","de":"انقل المقبض الذي اعتادته يدك إلى عصا جديدة غريبة، وفي تلك اللحظة تصبح الأداة ملكك فوراً. كمّ صغير يتيح لك ارتداء الألفة مباشرة، هذا هو الطريق المختصر إلى التأقلم."},"ICON-2384":{"nm":"معلّاق شبكة مرمى الملعب","de":"يجب أن تُعلَّق الشبكة بالمرمى كي يصبح الهدف هدفاً حقّاً أخيراً. كانت الشبكة دائماً هي ما يمسك حتى النهاية تلك اللحظة القصيرة التي امتلأت فيها بالكرة. في الموضع الذي يستقبل شكل الهتاف المنفجر، أنا موجودة هناك."},"ICON-2385":{"nm":"غطاء نصل التزلج","de":"بالنصل مكشوفاً، لا يمكنك أن تطمئنّ ولو لخطوة واحدة خارج الجليد. حين تغادر الجليد، رجاءً ألبسني. تهدئة الحدّة بصمت هي أيضاً أدب حافظ عليه المتزلّجون طويلاً."},"ICON-2386":{"nm":"معلّاق رباط حذاء التزلج","de":"الأربطة الطويلة للحذاء الذي خلعته، تُعلّقها بترتيب، واحداً تلو الآخر. أربطة حُلّت كي لا تتشابك تفتح الجولة التالية على الجليد بسلاسة. ختام اليوم يصبح، هكذا تماماً، استعداداً للغد."},"ICON-2387":{"nm":"منشفة نصل التزلج","de":"على نصل غادر الجليد للتو، تتجمّع قطرات صغيرة. امسح تلك الرطوبة برفق ويمرّ الصدأ مروراً دون أن يمسّه. جمع الآثار التي تركها البرد بهدوء، هذا هو يومي."},"ICON-2388":{"nm":"وسادة كاحل حذاء التزلج","de":"إن اهتزّ الكاحل مرّة واحدة، ينهار الانزلاق كله. وسادة تلفّه بإحكام وتثبّت الوطأة. ذلك التوازن الأنيق فوق الجليد يبدأ دائماً أولاً من موضع غير مرئي."},"ICON-2389":{"nm":"جراب واقي نصل التزلج","de":"جراب صغير في زاوية الحقيبة لوضع واقي النصل بعناية. عادة تجهيز كل ما يلزم دون إغفال شيء تحافظ على المعدات طويلاً. حقيبة مرتّبة هي المشهد الأول لانزلاق جيد."},"ICON-2390":{"nm":"مشبك نعل حذاء التزلج","de":"كي لا ينزلق النعل الداخلي بهدوء خارج الحذاء، يمسكه بإحكام تحت القدم. إن انحرف موضع الوطأة، تنحرف القفزة معه. اليد التي تمسك بأكثر المواضع انخفاضاً تساعد في النهاية أعلى القفزات."},"ICON-2391":{"nm":"حلقة غطاء نصل التزلج","de":"كي لا ينزلق الغطاء بسلاسة، تربطه بإحكام بحلقة. أعرف أنّ الحماية المتراخية ليست حماية في النهاية. حلقة واحدة مربوطة جيداً تحرس ذلك النصل حتى النهاية."},"ICON-2392":{"nm":"غطاء شدّ رباط حذاء التزلج","de":"اشدد الأربطة بقوة وأقفلها بالغطاء، ولن تنحلّ بعد ذلك أبداً. إحكام الربط بلا فجوة من رأس القدم، إنها أمتن عقدة تُربط قبل الخطوة الأولى على الجليد."},"ICON-2393":{"nm":"قماش تجفيف نصل التزلج","de":"من نصل أنهى للتو انزلاقاً كاملاً، تجمع الرطوبة المتجمّعة بهدوء. أعرف أنّ النصل المتروك مبلّلاً يبكي. فقط النصل المجفّف نعومة يرسم المنحنى التالي بوضوح على الجليد."},"ICON-2394":{"nm":"غطاء مقبض عصا التزلج","de":"لفّ طرف مقبض العصا برفق، وتصبح راحة اليد الممسكة أكثر راحة. القوة التي تشقّ حقل الثلج تأتي في النهاية من ذلك الموضع المُمسك بإحكام. غطاء صغير واحد يسند انحداراً طويلاً حتى النهاية."},"ICON-2395":{"nm":"دبوس رباط لوح التزلج على الثلج","de":"لحظة خروج الدبوس الصغير الذي يربط اللوح بالقدم، يتوقّف الجبل أمامك. قطعة يجب فحصها أولاً رغم صعوبة رؤيتها، هذا الاتصال الثابت يصبح الحرية فوق حقل الثلج."},"ICON-2396":{"nm":"ملقط حماية طرف حافة التزلج","de":"كي لا تخدش الحافة الحادّة داخل الحقيبة، تعضّ الطرف بلطف. تهدئة الحدّة إلى نوم، إنه الختام الرقيق الذي تقدّمه بعد نزول جيّد من الجبل."},"ICON-2397":{"nm":"واقي مقدّمة لوح التزلج على الثلج","de":"لفّ مقدّمة اللوح بإحكام، وحتى الاصطدام المباشر يتناثر بنعومة. حراسة الموضع الذي يصطدم أولاً بصمت، الشجاعة لمواجهة انحدار حادّ تبدأ من هنا بالضبط."},"ICON-2398":{"nm":"غطاء إبزيم حذاء التزلج","de":"كي لا يتضرّر الإبزيم باصطدامه بالثلج البارد، تغطّيه بهدوء. قفل آخر يحرس آلية القفل، هذا الغطاء الصغير يطيل موسم الحذاء قليلاً خلسة."},"ICON-2399":{"nm":"حلقة رباط لوح التزلج على الثلج","de":"كي لا يهرب اللوح بعيداً حتى لو غادر يدك، أربط الكاحل باللوح بخيط واحد. حتى لو أفلتّه، لن تفقده نهائياً، إنها حلقة اطمئنان هادئة معلّقة عند طرف حبل طويل."},"ICON-2400":{"nm":"طرف مكشطة قاعدة التزلج","de":"الشمع القديم المتصلّب على القاعدة، تكشطه بسلاسة. فقط بإزالة القديم تماماً يحيا الانزلاق الجديد. قاعدة عُنيت بعناية تفتح حقل الثلج التالي بسرعة أكبر بكثير."},"ICON-2401":{"nm":"مصد حافة لوح التزلج","de":"قبل أن يشقّ اللوح الثلج، يلامس طرف الأنف العالمَ أولاً. كل صدمة يتلقّاها هذا المطاط الصغير قبل غيره. في أقصى المقدمة، يتآكل دون أن يُظهر ذلك أبدًا—وانزلاق أحدهم ينساب فوق هذا الإخلاص الكليل."},"ICON-2402":{"nm":"حلقة سلة عصا التزلج","de":"في اللحظة التي توشك فيها العصا أن تغوص في الثلج العميق، تتحسّس هذه الحلقة المستديرة الأرض بدلاً منها. دائرة تسند بهدوء خطوة كادت أن تتعثر. رغم أنها لا تُرى، تبقى قريبة كيدٍ يمنعك من الانزلاق."},"ICON-2403":{"nm":"غطاء فرشاة تشميع الحافة","de":"حين ينتهي العناء، تُغلق بلطف قبل أن يجفّ المسحوق. عمل يحفظ نعومة اليوم دون أن يضطرب شعرة واحدة. حتى تنتظرك عناية الأمس كما هي حين تفتحها مجددًا."},"ICON-2404":{"nm":"معلاق واقي الأذن الشتوي","de":"أتذكر؟ واقي الأذن الذي نُسي قليلاً بجانب الحقيبة حين حلّ الربيع. ومع ذلك، في الليلة التي يُعلن فيها عن أول تساقط للثلج، يكون أول من يُنادى. هناك مكان مخصّص لتعليق الفصل، وهذا الخطاف لا ينسى ذلك الوعد أبدًا."},"ICON-2405":{"nm":"علبة حجر شحذ السكين","de":"لشحذ نصلٍ، يجب أولاً ترطيب الحجر—تسلسل متأصّل كلمسة يد الجدة. حتى الأداة التي تروّض البلادة تحتاج مكانًا لترتاح فيه، فهذا البيت الصغير يحتضن الحجر منتظرًا العناية القادمة."},"ICON-2406":{"nm":"كيس كتلة الشمع","de":"المادة التي تصنع انزلاقًا رائعًا تنام متكتّلة وصلبة في داخلها. ثقل يحتضن كتلة متجمّدة. الانزلاق دائمًا ينطلق من هذا الثقل الهادئ لينتشر فوق حقل الثلج."},"ICON-2407":{"nm":"حلقة كيس دفاية اليد","de":"في نزهة شتوية، المكان الذي تتحسّسه الأصابع أولاً داخل الجيب. يمنح بيتًا ثابتًا لتلك الدفء الصغير الذي يذيب اليدين المتجمدتين. كلما اشتدّ البرد، ازدادت هذه الحلقة الصغيرة لطفًا."},"ICON-2408":{"nm":"مسند حجر شحذ طرف النصل","de":"إن اهتزّ، اعوجّت الحافة، لذا يثبّت نفسه أولاً بإحكام. مسند لا يتحرك أبدًا، مسؤول عن دقّة غيره وحده. حافة سكين أحدهم المستقيمة تقف فوق هذا الصمود الصامت."},"ICON-2409":{"nm":"مشبك واقي الرقبة الشتوي","de":"في طريق المدرسة تحت الريح الباردة، لحظة انزلاق واقي الرقبة—طقّة على الياقة. حتى الدفء يحتاج أن يحافظ على مكانه ليصبح دفئًا حقًا. صوت صغير واحد يمسك دفء الصباح ولا يتركه يفلت."},"ICON-2410":{"nm":"غطاء مكواة التشميع","de":"بينما يبرد السطح الذي عمل بحرارة، تحميه قطعة قماش واحدة بهدوء من الغبار. أداة تعتني بأداة أخرى جهّزت الانزلاق. هكذا تستمر الرعاية بصمت."},"ICON-2411":{"nm":"غطاء قلم زيت الحافة","de":"إن فُتح مرة وجفّ، لن يمكن رسم الخط التالي. لذا فإغلاقه هو بالضبط فتح لما بعده—غطاء صغير يحبس رطوبة الطرف، واعدًا سلفًا بضربة الغد."},"ICON-2412":{"nm":"رأس شرابة التشجيع","de":"مئات الخيوط تنطلق من هذه النقطة الواحدة، تتناثر معًا على الإيقاع. بهاء التمايل يبدأ دائمًا من نقطة مربوطة بإحكام. تحت المسرح، أول عقدة تُرقّص الجمهور."},"ICON-2413":{"nm":"سير يد عصا الإضاءة","de":"بعد ساعتين من الهتاف، في اللحظة التي كادت فيها عصا الإضاءة أن تسقط، يعيدها هذا السير إلى يدك. رغبة في ألا تُفقد حتى لو سقطت. ذلك القلق الحنون صنع حلقة على معصمك."},"ICON-2414":{"nm":"مشبك طيّ وسادة المدرجات","de":"النهوض والجلوس عشرات المرات أثناء التشجيع. وبينهما، يطوي هذا المشبك الصغير الوسادة بعناية ويحافظ على مكانك. حتى في جمهور صاخب، هناك لمسة خفية تعتني بمقعد أحدهم."},"ICON-2415":{"nm":"حلقة منديل التشجيع","de":"في اليوم الذي ينتشر فيه النقش نفسه في كل مقعد، تربط قطعة قماش واحدة قلوب عشرات الآلاف في لون واحد. النقطة الأولى التي تبدأ منها تلك الموجة هي هذه الحلقة الصغيرة—المكان الذي يتحوّل فيه التشجيع الوحيد إلى تشجيعنا نحن."},"ICON-2416":{"nm":"نصف مضرب التصفيق","de":"التصفيق وحيدًا صوت صغير، وحين يجتمع في المدرجات يصبح موجة. النصف الذي يعرف بصدق أن الصوت لا يرنّ إلا حين يلتقي بآخر. في لحظة التقاء تصفيقك بتصفيقي، يكبر التشجيع."},"ICON-2417":{"nm":"غطاء زاوية لافتة التشجيع","de":"يلفّ الزاوية الحادة ليجعلها مستديرة، حتى لا يتأذى من بجانبك. حتى في القلب المتحمّس اللاهج، هناك اهتمام متبادل مطويّ بداخله. هكذا يزداد التشجيع دفئًا حين يكون مستديرًا."},"ICON-2418":{"nm":"حامل عصا شريط التشجيع","de":"حتى في اللحظة التي يتوقف فيها الخفقان، يقف العمود منتصبًا منتظرًا الهتاف التالي. مكان يستريح فيه بهدوء لحظة كي يتمايل مجددًا. بين هتاف وآخر، سكون قصير يلتقط فيه الشريط أنفاسه."},"ICON-2419":{"nm":"مروحة مكبّرة صوت التشجيع","de":"كي يصل صراخ شخص واحد إلى أقصى المسرح، يضيّق شكل المروحة مسار الصوت. فمٌ يفكّر دائمًا في كيفية الإيصال أكثر من حجم القلب نفسه. شكل صنعه شوق للوصول أبعد قليلاً."},"ICON-2420":{"nm":"علبة دبوس خلف شارة التشجيع","de":"قبل تثبيت الشارة على الصدر وبعد نزعها، تبدأ راحة الشارة هنا وتنتهي هنا. بيت صغير يُنيم الدبوس الحاد الخلفي بأمان. حتى نقطة كانت تلمع تحتاج مكانًا تستلقي فيه لتستريح قليلاً."},"ICON-2421":{"nm":"لوحة رقم لوحة النتائج","de":"تحمل عناية زمن كان فيه كل هدف يُستبدل يدويًا. قبل العصر الرقمي، كانت النتيجة تُنقش خانة خانة بأطراف أصابع البشر. لوحة كان فيها رقم واحد يحمل حماس أحدهم."},"ICON-2422":{"nm":"قطعة مغناطيس لوحة الخطط","de":"بتتبّع أطراف أصابع المدرّب، يتبادل الدفاع والهجوم أماكنهما. كل صورة في الذهن قبل المباراة تُرسم أولاً في حركة هذه النقاط الصغيرة. النتيجة تُعرض مرة مسبقًا فوق اللوحة."},"ICON-2423":{"nm":"مظلة توهج لوحة النتائج","de":"كي لا تُشوّش الأرقام الباهرة رؤية اللاعب، تقطع المظلة الضوء. حتى السطوع يحتاج أحيانًا أن يُحجب بالقدر المناسب ليؤدي دوره. في ألمع مكان، ظلّ يعمل بأهدأ ما يكون."},"ICON-2424":{"nm":"حلقة قلب صفحة النتيجة","de":"في كل مرة تُقلب فيها صفحة، يتغيّر الرقم ويرتفع الهتاف تبعًا له. أثر من زمن تناظري كانت فيه السجلات تُجدَّد بلمسة يد. زمن كان فيه القلب ينقلب مع صوت انقلاب النتيجة."},"ICON-2425":{"nm":"علبة قلم رسم خطوط الخطة","de":"كل مسار مرسوم على السبورة البيضاء في غرفة الملابس يخرج من هذا القلم. حافظة صغيرة متينة تحتضن مخطط المباراة. في صمت ما قبل المواجهة الحاسمة، المكان الذي يحمل أكثر الكلمات صمتًا."},"ICON-2426":{"nm":"نقّارة عدّاد النقاط","de":"بكل ضغطة، خانة واحدة، والعدّ يرتفع بصوت طقطقة واضح. حين تُترك الأرقام لأصابعك، يمكن للقلب أن يتوجّه كليًا للمباراة. إيقاع صغير يخفّف عبء العدّ."},"ICON-2427":{"nm":"غطاء أسلاك لوحة النتائج","de":"خلف الضوء الباهر، توجد دائمًا أسلاك متشابكة وغير مرتبة. عمل تغطية تلك الفوضى بترتيب. فقط حين تُرتّب الأماكن غير المرئية، يلمع المكان المرئي أخيرًا."},"ICON-2428":{"nm":"فرشاة ممحاة لوحة الخطط","de":"حين ينتهي شوط، يُفرغ السطح استعدادًا للصورة التالية. لا يمكن لاستراتيجية جديدة أن تبدأ إلا فوق مساحة فارغة تمامًا. الفرشاة الممحية هي في الحقيقة أول لمسة للخطة القادمة."},"ICON-2429":{"nm":"مشبك علم عرض النتيجة","de":"يمسك بعلم يوشك أن يطير مع الريح ولا يتركه. كي يحافظ القماش الخفّاق على مكانه. حتى إعلان السجلّ للعالم يحتاج أولاً يدًا تُثبّته بثبات."},"ICON-2430":{"nm":"مشبك حبل صافرة الحكم","de":"بصفارة واحدة، تتوقف المباراة ثم تتدفق من جديد. عقدة صغيرة تربط تلك السلطة بإحكام حول الرقبة. حتى قبل أن تُدوّي الصفارة، ربط الصمت بترتيب هو أيضًا من مهام هذا المشبك."},"ICON-2431":{"nm":"بكرة شريط القياس","de":"يجمع الطول المقيس ليعيده إلى داخله. القياس في النهاية تكرار للفرد والطيّ. مقبض يساعد تلك الرحلة البسيطة دون تذمّر، يدور كل مرة خلف الدقة."},"ICON-2432":{"nm":"علبة طيّ علم الحكم","de":"العلم الذي كان يفصل بحزم بين الداخل والخارج، حين تنتهي المباراة، يُطوى بعناية ويستريح. حتى تلك الإشارة الواضحة تلتقط أنفاسها قليلاً لما يأتي بعدها. حتى الحزم له راحته الهادئة."},"ICON-2433":{"nm":"حلقة تعليق ساعة التوقيت","de":"يعلّق الزمن المتدفق في مكان واحد، لا على المعصم. ساكن قبل القياس، ثم يندفع لحظة يُستدعى—محطة للزمن. بيت صغير للثواني، حابسًا أنفاسه، ينتظر إشارة الانطلاق."},"ICON-2434":{"nm":"عجلة رسم خطوط الملعب","de":"أينما دار، يبقى مسار أبيض واضح. تُنقش حدود القواعد على الأرض هكذا، دورة واحدة تلو الأخرى بدقة. قبل بدء المباراة، العجلة التي تترك أول أثر قدم على الملعب."},"ICON-2435":{"nm":"جيب بطاقة الحكم","de":"في لحظة القرار، البطاقة التي تُسحب من الصدر تنام هنا. غرفة انتظار حكمٍ يبقى صامتًا حتى النهاية قبل أن يُكشف. جيب دائم الاستعداد والانتظار، يتمنى ألا يُسحب منه أبدًا."},"ICON-2436":{"nm":"مسند ثقل الميزان","de":"عمل الوزن لا يكون صادقًا إلا فوق أرض ثابتة لا تهتز. مسند يحمل الثقل بينما يمنح جسده مسطّحًا تمامًا. الخطوة الأولى للقياس الدقيق تبدأ دائمًا من مكان هادئ."},"ICON-2437":{"nm":"نقّارة إشارة الانطلاق","de":"بصوت واحد، تدفع كل الأقدام الأرض في اللحظة نفسها. البداية قصيرة للغاية، لكن اليد التي تصنع ذلك الإيجاز أهدأ من أي أحد. يد تُطلق ارتجاف خط البداية بطقطقة واحدة فقط."},"ICON-2438":{"nm":"قاعدة مخروط الملعب","de":"اسمه غريب لكن عمله واضح—يسند بثقل مركز الملعب كأنه مسرح. في مركز يتلألأ فيه الجميع، هناك دائمًا ساق واحدة غير مرئية تصمد بصمت."},"ICON-2439":{"nm":"إبزيم حزام التنفس البطني","de":"الصوت الجميل يأتي من نفس عميق لا من الحلق، والخصر يعرف ذلك أولاً. إبزيم يجعل راحة يدك تشعر بانتفاخ البطن وهبوطه. نقطة انطلاق الأغنية تكمن دائمًا تحت هذا النفس الواحد."},"ICON-2440":{"nm":"لوح ريشة تمرين التنفس","de":"حين تتمايل الريشة برفق مع نفَسك، هذه إشارة أن تنفسك منتظم. تمنح شكلاً بلطف للنفَس غير المرئي، وتعلّم أساس الغناء. تمرين يتعلّم بالعين النفَس الذي يسبق النغمة الأولى."},"ICON-2441":{"nm":"ساعة رملية للشهيق","de":"داخل الزجاج، ينساب الرمل كالنفَس. استنشق، توقف لحظة، ثم أخرج ببطء—الحبيبات تعدّ الإيقاع بدلاً منك. راقب الرمل المتساقط بصمت لبرهة، وفجأة يستقيم نفَسك المشوّش من تلقاء نفسه."},"ICON-2442":{"nm":"قاعدة تمرين الشمعة","de":"أشعل الفتيلة، وسيرتجف صوتك مع اللهب المتراقص. مكان نحته أحدهم بعناية ليسند ذلك الارتجاف الصغير قليلاً. بقدر سماكة الشمع المتصلّب المتراكم، تتجمّع هنا الليالي التي غنّيت فيها وحدك."},"ICON-2443":{"nm":"رباط وسادة ضغط البطن","de":"بدل وضع اليد على البطن، يضغط رباط واحد ذلك المكان بهدوء. يشدّ حين يمتلئ النفَس، ويرتخي بلطف حين يفرغ كليًا. رفيق صغير صامت إلى جانبك، يساعد الجسد على تذكّر الإيقاع أولاً."},"ICON-2444":{"nm":"غطاء بالون استمرار التنفس","de":"لا تنفخ البالون دفعة واحدة. طويلًا، ببطء، ادفعه حتى النهاية. بينما تعضّ الغطاء وتُخرج الهواء، يصل الهواء إلى أعمق نقطة في رئتيك. الأغنية، في النهاية، تطير بقدر طول النفَس الذي صبرت عليه."},"ICON-2445":{"nm":"مقبض تهدئة التنفس","de":"كلما اهتزّ القلب، ازدادت رغبة اليد في الإمساك بشيء ما. أمسك هذا المقبض فتنزلق كتفاك إلى الأسفل، ويطول شهيقك بمقدار شبر. تعلّم كيفية القبض هو تعلّم كيفية تهدئة الذات، وراحة اليد تعرف ذلك أولاً."},"ICON-2446":{"nm":"حلقة رباط اهتزاز عضلات البطن","de":"علّق الرباط بالحلقة فينتشر اهتزاز هادئ إلى وسط بطنك. تتجمّع القوة بهدوء في نفس المكان الذي يرتجف حين تضحك بصوت عالٍ. المركز الثابت ينمو دائمًا هكذا، ببطء، في مكان لا يراه أحد."},"ICON-2447":{"nm":"قرص عدّ الشهيق","de":"واحد، اثنان، ثلاثة—كل مرة يتقدّم فيها القرص خانة، تُنقش عمق النفَس الذي استنشقته. تزداد الأرقام خانة، فتصمد الأغنية عبارة أخرى. على هذا القرص الصغير، تُسجَّل بصمت سعة الرئة التي بنيتها اليوم."},"ICON-2448":{"nm":"لوح ملعقة تمرين اللسان","de":"نُقشت على اللوح بدقة المواضع التي يجب أن يلمسها طرف اللسان. كيف تُدحرج، وتنقر، وتتوقف قليلًا. خلف نطق ينساب بسلاسة تختبئ فجرات لا تُحصى تعلّم فيها اللسان طريقه هكذا."},"ICON-2449":{"nm":"مشبك مرآة شكل الفم","de":"يمسك المشبك بلطف شكل الفم المنعكس في المرآة. \"آ\" مستديرة، و\"إي\" ممتدّة إلى الجانبين. درس هادئ لا يشارك فيه سواك والمرآة، يهذّب شكل الصوت بمواجهة وجهك مباشرة."},"ICON-2450":{"nm":"فقمة الفلين لتصحيح النطق","de":"فقمة صغيرة منحوتة من الفلين تجلس في زاوية المكتب تستمع إلى النطق. في ليالٍ يزلّ فيها حرف الراء مرارًا وتنهار المعنويات، تقول عينا الفقمة المستديرتان بهدوء: لا بأس، لنحاول مرة أخرى فقط."},"ICON-2451":{"nm":"دبوس علامة تنفس الكلمات","de":"أين تتنفس في كلمات الأغنية—هذا الدبوس يخبرك أولاً. اغرسه في نهاية سطر، فيصبح ذلك المكان فاصلة الأغنية الحنونة. لتغنّي بحرية، حتى الجملة تحتاج مسافة واحدة لالتقاط أنفاسها."},"ICON-2452":{"nm":"مسند ذقن تمرين اللفظ","de":"بمجرد إسناد الذقن قليلًا، يجد النطق الذي كان يتشتّت مكانه. الكلام الواضح ليس عمل الفم وحده، بل يُبنى بالذقن والحلق والنفَس معًا. مسند صغير واحد يساعد بصمت في ذلك التوازن الدقيق."},"ICON-2453":{"nm":"حامل قالب فم حروف العلة","de":"آه، إيه، إي، أوه، أوو—إطار يُقيم كما هي المسارات التي تسلكها هذه الحروف الخمسة خارج الفم. ضعه بهدوء بجانب المرآة وشكّل هيكل الصوت كل يوم. أي أغنية، هيكلها يبدأ في النهاية من هذه الحروف الخمسة."},"ICON-2454":{"nm":"بطاقة تعقيد اللسان","de":"بطاقة معقّدة لدرجة أن قراءتها تجعل اللسان يتعثّر وينفجر الضحك أخيرًا. لا بأس حقًا أن تخطئ—الخطأ نفسه هو التمرين. كل مرة تتجاوز فيها هذه الجملة المشاغبة، يستيقظ صوت واحد أكثر وضوحًا."},"ICON-2455":{"nm":"سدادة إرخاء الشفتين","de":"إحماء يرجف الشفتين لإيقاظ فمٍ متيبّس. عضّ السدادة وأخرج الهواء طويلًا، فترتخي الشفتان النائمتان برقة. أصغر وألطف تمرين إحماء لفتح العبارة الأولى بلين."},"ICON-2456":{"nm":"رباط مطاطي لمقطع الكلمات","de":"لُفّ رباطًا مطاطيًا لتحديد المقطع الذي يعثرك دائمًا. كل مرة ترى فيها ذلك المكان على معصمك، يخطر ببالك جبل اليوم الذي يجب تسلّقه. كلما صعُب المقطع الموسيقي، ازددت النظر إليه، وطالت مدة احتفاظك به في قلبك."},"ICON-2457":{"nm":"حلقة وشاح تدفئة الرقبة","de":"كي لا تبحّ الحنجرة في هواء فجر تغيّر الفصول، يُعلَّق الوشاح بإحكام على الحلقة. فقط من حنجرة ملفوفة بدفء ينطلق صوت صافٍ أخيرًا. حماية الصوت تبدأ دائمًا بالاعتناء بالحنجرة أولاً."},"ICON-2458":{"nm":"طرف بكرة اهتزاز الحبال الصوتية","de":"حين يتدحرج طرف البكرة ببطء على جانب الرقبة، تستيقظ الحبال الصوتية النائمة طوال الليل برفق. اهتزاز خفيف يُرخي التوتر المتصلّب، وتلين النغمة الأولى المتردّدة. لمسة تُدفئ الجسد قبل الغناء."},"ICON-2459":{"nm":"صحن كوب إحماء الدندنة","de":"بشفتين مطبقتين، دندن بهدوء، احتضن كوبًا دافئًا يتصاعد منه البخار بكلتا يديك فيدفأ الحلق أيضًا. دندنة منخفضة تنتشر في دوائر فوق الصحن. هكذا تبدأ الأغنية، من رشفة واحدة من دفء فاتر."},"ICON-2460":{"nm":"كبسولة حفظ حلوى الحنجرة","de":"من أجل الأيام التي يهبط فيها الحلق خشنًا وجافًا، تُجمَّع الحلوى بهدوء داخل الكبسولة. دحرج واحدة في فمك قبل الصعود إلى المسرح مباشرة، فيفتح النعناع البارد الحلق المسدود بانتعاش. قليل من العزاء لحالات الطوارئ، محفوظ في علبة صغيرة خاصة بك وحدك."},"ICON-2461":{"nm":"كيس كمادة البخار للحلق","de":"لُفّ الكيس المشبع برقة بالبخار الدافئ حول رقبتك، فتذوب المواضع التي تصلّبت من طول التمرين برفق. بنفس دفء منشفة سُخّنت للتو، يمنح بهدوء لحظة راحة للحبال الصوتية المتعبة الغارقة."},"ICON-2462":{"nm":"ساعة رملية لراحة الحبال الصوتية","de":"الوعد الهادئ بألا تتحدث اليوم، تعدّه بهدوء حبيبات رمل نحيلة. إغلاق الفم قليلًا وادّخار الصوت. ذلك الوقت الهادئ، الذي هو أيضًا أفضل عناية على الإطلاق، يتدفق ببطء هنا."},"ICON-2463":{"nm":"سدادة إحماء رفرفة الشفتين","de":"رفرفة شفاه تمتطي النغمات صعودًا وهبوطًا بينما ترتجف الشفتان برفق. عضّ السدادة قليلًا، فيستقرّ الارتجاف الجامح ليصبح أكثر انتظامًا. أداة صغيرة بحجم راحة اليد تُثبّت بلطف أول زر في التصويت."},"ICON-2464":{"nm":"غطاء رذاذ ترطيب الحلق","de":"كي لا يجفّ الحلق على مسرح جافّ، اضغط الغطاء ورشّ رذاذًا رقيقًا. خذ نفَسًا عميقًا واحدًا من الهواء المرطّب، فيستعيد الصوت الجافّ بريقه الصافي مجددًا."},"ICON-2465":{"nm":"كرة اهتزاز إرخاء الصوت","de":"أمسك الكرة المرتجفة بدقة في راحة يدك بسكون، فيصعد ذلك الاهتزاز برفق عبر الذراع حتى الرقبة. صديق إحماء مستدير وحنون يهزّ برفق ويوقظ الأعضاء الصوتية التي تصلّبت من التوتر."},"ICON-2466":{"nm":"علامة نقطة التشكيل","de":"علامة صغيرة واحدة مغروسة في أرضية المسرح. هنا مكانك، وهناك مكاني. حين يجتمع كثيرون ليرسموا صورة واحدة، يمسك بهدوء بالجميع في مكانهم—وعد غير مرئي بألا يتشتّت أحد."},"ICON-2467":{"nm":"رقاقة رأس سهم المسار","de":"رقاقة على شكل رأس سهم تشير بوضوح إلى اتجاه الخطوة التالية. أين تدور وأين تتوقف، تخبرك الأرضية أولاً كي لا تضيع الطريق. المسار هو خريطة حفظتها أطراف الأصابع بالسير عليها عددًا لا يُحصى من المرات."},"ICON-2468":{"nm":"دبوس مركز التشكيل","de":"النقطة الواحدة التي تصبح بهدوء المرجع حين يجتمع كثيرون. حول هذا الدبوس تُرسم دائرة مستديرة، وينفتح التشكيل على اتساعه. حتى الحركات المتناثرة تجد نظامها بمجرد وجود نقطة مركزية واحدة."},"ICON-2469":{"nm":"وتد نقطة التقاطع","de":"حيث يلتقي مساران في نقطة واحدة، يُغرس وتد بإحكام. كي لا يصطدما، كي لا يتقاطعا ويتشابكا. حتى في تلك اللحظة العابرة اللاهثة، لا أحد يضيع طريقه."},"ICON-2470":{"nm":"علم اتجاه الخروج","de":"حين يخفت صدى النغمة الأخيرة، تنسلّ بهدوء نحو حيث يشير العلم. فالخروج يجب ألا يكون أكثر تشوّشًا من الدخول. حتى نهاية المسرح لها اتجاه مُتّفق عليه مسبقًا."},"ICON-2471":{"nm":"مشبك شريط قياس المسافات","de":"أمسك بطرف شريط القياس بإحكام بالمشبك، فيخرج شبر بعد شبر بدقة لا تخطئ. حتى المسافة بين شخص وآخر تُضبط بترتيب كأنها قِيست بمسطرة. مشهد يبدو أنيقًا يُولد دائمًا من أطراف أصابع بهذه الدقة."},"ICON-2472":{"nm":"حلقة حبل مرجع الاصطفاف","de":"علّق الحبل بالحلقة واسحبه مشدودًا في خط واحد، فيصبح ذلك الخط النحيل معيارًا يقف الجميع بمحاذاته. مظهر الصفّ المرتّب هذا الأنيق يعود الفضل فيه لهذا الخط المستقيم غير المرئي وحده."},"ICON-2473":{"nm":"قطعة خط منقّط لمسار الحركة","de":"قطع ترسم بهدوء طريقًا على الأرض بخط منقّط. سِر على هذه الآثار الخافتة ولن تضيع حتى في الظلام. بينما تربط نقطة بنقطة، تتّحد الخطوات المتناثرة في تيار واحد."},"ICON-2474":{"nm":"دبوس أرضية الموقع","de":"دبوس مغروس في الأرض كي لا تنسى مكانك. حتى في الظلام الدامس، تتحسّس أطراف الأصابع ذلك النتوء الصغير وتجده لا محالة. فقط حين تتوقف تمامًا عند تلك النقطة الواحدة، ينسكب الضوء أخيرًا فوق رأسك."},"ICON-2475":{"nm":"رباط تركيز فصل الرقبة","de":"إن تمايل الذقن تبعًا لها، يرتجف الصوت ويتشتّت معه. لإتقان تحريك الرقبة وحدها بينما يبقى الرأس ساكنًا، تُلَفّ الرباط. خلف حركة بدت حرّة تمامًا، يكمن هذا التمرين الصامت على الفصل."},"ICON-2476":{"nm":"مشبك وسادة تثبيت الكتف","de":"كي لا ترتفع الكتفان من تلقاء نفسيهما، تُثبَّت الوسادة بمشبك بهدوء. كي يميّز الجسد بوضوح أين يجب أن يتمايل وأين يجب أن يبقى ساكنًا. الخط المضبوط يولد دائمًا من مثل هذه اللمسات الصغيرة من الثبات."},"ICON-2477":{"nm":"إبزيم حزام استشعار الأضلاع","de":"يقرأ الحزام بهدوء النسيج الدقيق للأضلاع وهي تتّسع ثم تعود لتتجمّع. أغلق الإبزيم فتنتقل حركة النفَس بوضوح إلى أطراف أصابعك. الغناء العميق الثابت ينبع من هذه الحركة غير المرئية للعظام."},"ICON-2478":{"nm":"بندول تمايل الحوض","de":"يتأرجح الثقل ببطء يمينًا ويسارًا، مخبرًا بهدوء الإيقاع الذي يرسمه الحوض. كيف ينقل مركز الجسد وزنه، يعلّمك ثقل صغير بحجم راحة اليد دون كلمات. أن للتمايل نفسه نسيجًا خاصًا."},"ICON-2479":{"nm":"حلقة دوران المعصم","de":"علّق الحلقة على معصمك وأدرها ببطء إلى الداخل ثم إلى الخارج، فترتخي المفاصل المتيبّسة طوال الليل برفق. لحركة تصل حية إلى أطراف الأصابع، يجب أن يصبح المعصم مرنًا أولاً. هذا الدوران الصغير يفتح تعبيرًا أعظم."},"ICON-2480":{"nm":"حبل حلقة مقاومة الكاحل","de":"ضع الحلقة على كاحلك واسحب الحبل، فتعلق مقاومة هادئة بأطراف أصابع قدميك مع كل خطوة تخطوها. بقدر ما تدوس بثقل، تتراكم القوة بهدوء في ساقيك. القفزة الخفيفة كالريشة تقف دائمًا فوق تمرين ثقيل كهذا."},"ICON-2481":{"nm":"كيس رمل تركيز الجذع","de":"فقط بعد لفّه حول بطنك تعرف أخيرًا أين كان مركز جسدك بالضبط. بينما يشدّ الثقل الكتفين، يجد المركز المتمايل مكانه ببطء، وحيث يُفكّ الرباط، يبقى وضع انتصاب واحد."},"ICON-2482":{"nm":"غطاء عصا محاذاة العمود الفقري","de":"حين يلمس غطاء صغير ظهرًا عاش منحنيًا طوال اليوم، يشعر وكأن أحدًا يفرد كتفيك خلسة. يمكنك أن تعيش منحنيًا، لكن الوقوف منتصبًا مهارة حنونة يجب أن تتعلّمها ببطء من جديد."},"ICON-2483":{"nm":"كرة ضغط إرخاء العضلات","de":"اضغط بقوة على مكان متكتّل، فيلسع أولًا ثم يرتاح سريعًا. كدفء ظهر جدتك وهو يفرك ظهرك في طفولتك، الإرخاء هو أن تتألم قليلًا أكثر بينما تبقى إلى جانبك."},"ICON-2484":{"nm":"برغي ضبط زاوية المرآة","de":"أدره بمقدار راحة يد فقط، وتعكس المرآة وجهًا مختلفًا تمامًا. بدورة واحدة للبرغي يميل العالم ثم يعتدل، فيبدو أن مواجهة الذات أيضًا تحتاج تصويبًا هادئًا."},"ICON-2485":{"nm":"وسادة مسح ضباب المرآة","de":"أمام مرآة غشّاها بخار ساخن، يفقد المرء وجهه للحظة. مسحة واحدة سريعة ويعود الوجه. بفضل هذه اللمسة التي تزيل الضباب، ألتقي بنفسي مجددًا كل صباح."},"ICON-2486":{"nm":"مطاط قاعدة حامل الكاميرا الثلاثي","de":"عند طرف قدم الحامل الثلاثي، نقطة مطاط بحجم الظفر تحسم مصير اللقطة. قبضتها القوية على الأرض تُسكت الاهتزاز، فالصورة الثابتة تبدأ دائمًا بهدوء من احتكاك غير مرئي."},"ICON-2487":{"nm":"فيلم شبكة مرجع الزاوية","de":"الخطوط الشبكية الرفيعة على الفيلم أشبه بعجلات تدريب للعين. كلما ألف التكوين اليد أكثر، اختفت الخطوط بهدوء تاركة الحسّ وحده. آثار التعلّم تصبح غير مرئية كلما نضجت أكثر."},"ICON-2488":{"nm":"دواسة بدء التسجيل","de":"بالنسبة لشخص يداه ممتلئتان تمامًا بالأشياء، كان الإصبع الأخير دائمًا هو إصبع القدم. اضغط عليها برفق فيبدأ التسجيل—خلف الكواليس، يُدار كل شيء بمهارة، حتى أطراف الأصابع."},"ICON-2489":{"nm":"مشبك اتجاه الإضاءة","de":"أين يسقط الضوء يعتمد على أطراف أصابع هذا المشبك بحجم الظفر. عمل تحريك ظلّ بمقدار شبر وإبراز ملمح، على ذلك الفرق الصغير يتردّد أحدهم طويلًا وبعمق."},"ICON-2490":{"nm":"ستارة مقارنة اللقطات","de":"ضع الأمس واليوم جنبًا إلى جنب، وعندها فقط يتكلّم التغيير. في لحظة انزلاق الستارة إلى الأسفل، تنكشف على الشاشة بصدق المسافة الزمنية التي عُبرت بينهما."},"ICON-2491":{"nm":"سير معصم جهاز التحكم","de":"لُفّ حبلاً واحدًا حول المعصم فيرتاح القلب الذي كان قلقًا من إسقاطه. جهاز أمان صغير يمنح اليد حرية أكبر بدلاً من ذلك—مفارقة حنونة حيث ما هو مربوط يريح البال."},"ICON-2492":{"nm":"غطاء العدسة","de":"بينما ترتاح الكاميرا، تُغمض العدسة عينها بهدوء أيضًا. في عالم تترك فيه ذرة غبار واحدة ندبة على الشاشة، تغطيتها برفق هي رغبة في الاعتزاز بها طويلًا."},"ICON-2493":{"nm":"رباط رفع زاوية الشفاه","de":"ارفع زاويتي الفم قليلًا، فيرتخي تعبير متيبّس ببطء. الابتسامة أيضًا، في النهاية، عضلة—في البداية تستعير قوة الأداة، وفي صباح ما تبتسم بإشراق بقوتك الخاصة."},"ICON-2494":{"nm":"بكرة تدليك عضلات الخد","de":"دحرج داخل الخد ببطء لإرخائه، فتنساب الكلمات بسلاسة أكبر بكثير. تحضير هادئ يوقظ الوجه برفق قبل الغناء. حين يُدفَّأ التعبير أيضًا، يزداد دفئًا."},"ICON-2495":{"nm":"مقياس زاوية الابتسامة","de":"تعرف الكاميرا أن حتى الابتسامة لها زاويتها الصحيحة. وبقياسها هنا وهناك بالمقياس، تدرك أخيرًا—أجمل ابتسامة تتفتّح من صدق لا يمكن قياسه إطلاقًا."},"ICON-2496":{"nm":"مشبك حركة الحاجب","de":"تحرّك الحاجب ولو ميليمترًا واحدًا، فيتغيّر نسيج القلب بأكمله. مشبك يمسك بهدوء أصغر جزء في التعبير—التمثيل هو عمل أطراف الأصابع في ترويض دقائق كهذه."},"ICON-2497":{"nm":"ملصق رفع عظمة الخد","de":"ارفع عظمتي الخد قليلًا والصقهما، فيظهر على الوجه مكان يستقرّ فيه الضوء. البُعد الذي تصنعه ملصقة واحدة بحجم الظفر—يخفي مكياج المسرح أسرارًا غير مرئية كهذه."},"ICON-2498":{"nm":"رقعة عين تغطية الغمزة","de":"غطِّ عينًا واحدة، فيتجمّع القلب كليًا في العين المتبقية. تمرين الغمز هو، في النهاية، تعلّم كيفية إخفاء نصف بأناقة. توجد بالتأكيد تعابير تزداد وضوحًا بقدر ما تُغطّى."},"ICON-2499":{"nm":"مشبك قالب شكل الفم","de":"غا، غيا، غو... طابق شكل فمك مع القالب فيزداد النطق المشوّش وضوحًا. أن كل حرف علة هو وضعية للوجه، تنقشه ببطء في جسدك أمام المرآة."},"ICON-2500":{"nm":"كيس إحماء تعابير الوجه","de":"قُبيل الصعود إلى المسرح مباشرة، كيس دافئ يُدفّئ الوجه برفق. كما تتصلّب الحركة حين تبرد اليدان، كذلك يفعل التعبير. حقيقة صغيرة من خلف الكواليس: حتى الابتسامة تحتاج إلى تسخين مسبق."},"ICON-2501":{"nm":"شريط تنعيم الجبين","de":"عندما يُلَفّ الشريط حول الجبين، يهدأ التجعّد العميق الذي كان محفورًا فيه بهدوء. أداة تمنح الغضون التي حفرها القلق راحةً قصيرة. وتحت الجبين الأملس يبدو الإنسان أصغر سنًّا قليلاً."},"ICON-2502":{"nm":"كُشتبان تقليب النص","de":"كُشتبان صغير يُلبس في طرف الإصبع لتقليب الصفحات. وإيقاع تقليب صفحات النص السميك صفحةً صفحة يصبح، دون أن ندري، إيقاع القصة نفسها. حتى القراءة تحمل في داخلها عادةً يدوية رقيقة."},"ICON-2503":{"nm":"علم تلوين المشاعر","de":"الفرح أصفر، والحزن أزرق. حين يُلوَّن القلب وتُرفع الراية، يتّخذ الشعور الخفيّ شكلًا وهو يرفرف في الريح. هكذا يمكن للأحاسيس أيضًا أن تُرسم باليد."},"ICON-2504":{"nm":"مشبك التشديد على الحوار","de":"«ضع الثقل على هذه الكلمة»، يهمس المشبك بهدوء. المعنى الكامل للجملة نفسها يتغيّر بتشديد واحد فقط، فهو علامة صغيرة تمسك بمركز ثقل الكلام."},"ICON-2505":{"nm":"مكعّب فاصلة القراءة","de":"مكعّب يُوضع ليقول: «ارتَحْ هنا لحظة». الفاصلة في الحوار ليست توقفًا بل نَفَسًا يُستَنشَق تحضيرًا للكلمات التالية. مَن يُحسن الاستراحة هو مَن يُحسن الكلام في النهاية."},"ICON-2506":{"nm":"شريط مشبك تحديد النفَس","de":"يرتفع الشريط وينخفض على طول المشبك، راسمًا طول النفَس أمام العينين. مراقبة إيقاع الشهيق والزفير ومحاكاته - فبداية الأغنية تبدأ دائمًا من إتقان التنفّس."},"ICON-2507":{"nm":"كيس نرد المشاعر","de":"نردٌ يتدحرج خارجًا من الكيس ليقرر شعور اليوم. إن ظهر الفرح، جرّب أن تفرح، وإن ظهر الغضب، جرّب أن تغضب. يصبح تمرين التمثيل لعبةً تُسلَّم فيها القلوب للصدفة."},"ICON-2508":{"nm":"حامل النص المائل","de":"ضع النص فوق الحامل المائل فلا تحتاج لإطراق رأسك. هذا الميل الصغير الذي يحافظ على مستوى النظر يعتني بهدوء برقبة تصلّبت من طول التمرين."},"ICON-2509":{"nm":"ستارة الهمس","de":"علامة تقول: من هنا فصاعدًا اهمس. حين يُخفَض الصوت خلف الستارة، يحبس الجمهور أنفاسه وينصت أكثر. تلك مفارقة المسرح اللطيفة: كلما همست أقل، وصل صوتك أبعد."},"ICON-2510":{"nm":"صندوق رموز تبديل الأدوار","de":"اقلب الرمز قليلًا فيتغيّر الدور الذي تؤديه. اليوم بطل الرواية، وغدًا صديق يقف بجانبه. في جزيرة ينمو فيها الجميع معًا، يأتي دور كل واحد ليقف يومًا في وسط الخشبة."},"ICON-2511":{"nm":"ملصق نقطة تثبيت النظر","de":"ثبّت عينيك بهدوء على نقطة صغيرة بجانب الكاميرا. في اللحظة التي تستقر فيها نظرة متذبذبة في مكان واحد، تنبض العينان على الشاشة بالحياة بوضوح. فالنظرة الثابتة تبدأ في النهاية من السكون."},"ICON-2512":{"nm":"مسطرة مثلثة لقياس الزاوية","de":"حين تبدو زاوية من الشاشة مائلة بطريقة غريبة، ضع المسطرة المثلثة عليها ببساطة فتظهر الإجابة. عمل تسوية ما هو معوجّ. قبل أن تثق بعينيك، جرّب أن تثق بالمسطرة للحظة."},"ICON-2513":{"nm":"حامل عدسة بمستوى النظر","de":"اضبط العدسة على مستوى عين الشخص فتكذب الشاشة أقل. لا من الأعلى ولا من الأسفل، بل حين تواجهه بعينين متساويتين فقط، تُلتَقط تعبيرات وجه حقيقية غير مزيّفة."},"ICON-2514":{"nm":"ريشة سهم توجيه النظر","de":"تنساب النظرة في الاتجاه الذي تشير إليه الريشة. سهم صغير يقود عين المشاهد برفق. اللقطة الجيدة تشير بلطف إلى أين يجب أن تنظر."},"ICON-2515":{"nm":"رقاقة أرضية لمسار التصوير","de":"طأ بهدوء نقطة من مسار حُفظ عن ظهر قلب، فتجد الموقع التالي جاهزًا في متناول يدك. الخطوات التي تجول على المسرح هي طريق خفي تتشكل بربط علامات صغيرة كهذه، مغروسة نقطة نقطة في الأرض."},"ICON-2516":{"nm":"شريط قياس مسافة الكاميرا","de":"يقيس الشريط المسافة بين الشخص المصوَّر والكاميرا. في عالم يفصل فيه شبر واحد بين البعيد والقريب، يصبح شريط القياس حارسًا صامتًا يحمي الحدّ بين الضبابية والوضوح."},"ICON-2517":{"nm":"دليل إمالة الرأس","de":"إلى أي مدى يجب أن تُميل رأسك لتبدو في أرقّ حالاتك؟ اتبع الدليل فتعرف بهدوء أن زاوية الإمالة تشبه تمامًا مقدار ما تفتحه من قلبك."},"ICON-2518":{"nm":"مشبك مرآة يدوية لتلاقي النظرات","de":"ضع مرآة يدوية بجانب الكاميرا بواسطة المشبك، فتنظر إلى عينيك بينما تلتقي بعينيك. أداة صغيرة تمدّ برفق جسرًا من النظر بين «أنا» في المرآة و«أنت» على الشاشة."},"ICON-2519":{"nm":"مصباح إشارة التصوير","de":"حين تضيء اللمبة، فتلك إشارة إلى أن التصوير جارٍ الآن. مصباح صغير يجمع توتر الموقع المتحمّس في نقطة واحدة. منذ لحظة إضاءة الضوء، تتناسق أنفاس الجميع في إيقاع واحد."},"ICON-2520":{"nm":"زر جرس ردّ الفعل","de":"اضغط الزر فيرنّ جرس صافٍ ونقيّ. مثل التصفيق الذي ينفجر بعد مشهد جميل، تحمل هذه الجرسية الصغيرة كلمة دافئة من أحدهم تقول: أحسنت."},"ICON-2521":{"nm":"أنبوب قرعة رد الفعل السريع","de":"هزّه فتُصدر العيدان الخشبية صوت طقطقة، تحرّك الأجواء أولًا. مَن يفتح المسرح يتقرر بلمسة معصم واحدة - مَن يُسحَب اسمه يبتسم بارتباك، ومَن يبقى يتنهّد ارتياحًا. حتى تقاسم الحظّ له قواعده اللطيفة."},"ICON-2522":{"nm":"جرس هزّ المؤثرات الصوتية","de":"حرّك معصمك قليلًا فتتداخل رنّة «شلنغ» كتعليق مفاجئ. هذا الجرس الصغير يملأ الفجوة قبل أن يصبح الصمت محرجًا. في عدّ إيقاع الضحك، يسبق هذا دائمًا بخطوة."},"ICON-2523":{"nm":"غطاء صندوق المفاجأة","de":"قبل أن يُفتح، لا أحد يستطيع تخمين ما بداخله. تلك هي المهمة الوحيدة لهذا الغطاء. كي تنفجر الصرخات والضحكات معًا في لحظة اهتزازه المفاجئة، يُعلَّق الترقّب على مفصلة واحدة."},"ICON-2524":{"nm":"مروحة ردّ الفعل القابلة للطي","de":"صوت الفتح المفاجئ يصبح ردًّا بحدّ ذاته. تُهدي أضلاع المروحة الإعجاب الذي عجز الكلام عن التعبير عنه. بين حركتي الطيّ والفتح يتنقّل الحماس، وشريط من المشاعر يتمايل مع النسيم."},"ICON-2525":{"nm":"عجلة روليت العقوبات","de":"لا أحد يعرف مسبقًا في أي خانة ستتوقف الإبرة. كلما تباطأت العجلة تسارع القلب في الاتجاه المعاكس - نقرة، ويُكتب مصير اليوم المضحك حيث توقفت. ثوانٍ قليلة حتى الارتجاف فيها ممتع."},"ICON-2526":{"nm":"لوحة فقاعة تعجّب","de":"ارفعها عاليًا فوق الرأس فترتفع كلمة «واو» على شكل حروف. ورقة واحدة تسبق القلب، صارخةً ما عجز الفم عن مجاراته. لأن ردود الفعل أيضًا تحتاج إلى إخراج مسرحي."},"ICON-2527":{"nm":"علم يدوي للتجميد المفاجئ","de":"في لحظة رفع العلم، يتجمّد الجميع في مكانهم تمامًا. إشارة تحبس حتى صوت الأنفاس في صورة ثابتة. وحين ينخفض من جديد، ينهمر الضحك المجمَّد دفعة واحدة."},"ICON-2528":{"nm":"وعاء مشابك الإجابات الطريفة","de":"كلما كانت الإجابة أغرب، عُلّقت بإحكام أكبر. حين تتمايل الإجابات الخاطئة المعلّقة على الحبل في الريح، يصبح المسرح مكانًا تُحَبّ فيه الأخطاء أكثر من الإجابات الصحيحة. إنه مشهد يوم يجوز فيه أن تخطئ."},"ICON-2529":{"nm":"إسفين مسند تصحيح الوضعية","de":"في لحظة إسناد الظهر، يتلمّس العمود الفقري المنحني طريقه الصحيح برفق. إسفين صغير يسند بصمت. الوضعية الصحيحة، كما يهمس من خلفك، لا تصبح مريحة إلا حين يسندك أحد."},"ICON-2530":{"nm":"مكعّب دعم محاذاة الحوض","de":"صلابة صغيرة تُوضع تحت القدمين حين يتذبذب مركز الثقل. توازن الجسد يرتفع في النهاية ببطء من الأرض. لاعب مساند بلا اسم يسند الوضعية من مكان لا يُرى."},"ICON-2531":{"nm":"كرة توازن شدّ البطن","de":"ضعها على البطن واشدّها بهدوء فيتجمع المركز المتناثر في نقطة واحدة. كلما ضبطت نفَسك بعمق، ازدادت الكرة صلابة، ويستعيد الجسد محوره المنسيّ نفَسًا بعد نفَس."},"ICON-2532":{"nm":"مسطرة فحص انحناء العمود الفقري","de":"ضع المسطرة على طول الظهر فيظهر الانحناء الخفيّ على المقياس. الوقوف مستقيمًا ليس محو الانحناء، بل قراءة ذلك الانحناء الصغير بحنان."},"ICON-2533":{"nm":"حلقة مرنة لفرد الكتفين","de":"علّقها على الكتفين واسحبها ببطء فينفتح الصدر المنقبض على اتساعه. المرونة تهمس دائمًا: عُد إلى مكانك، والظهر المنحني طوال اليوم يستقيم شيئًا فشيئًا استجابةً لذلك النداء الرقيق."},"ICON-2534":{"nm":"كيس رمل لتنشيط عضلات الجذع","de":"لُفّه حول الخصر فتوقظ حبيبات الرمل الثقيلة العضلات النائمة. حتى الحركة الخفيفة تصبح جادّة فجأة أمام هذا الثقل. كل حبة رمل تهمس بهدوء أنك تزداد صلابة بقدر ما تصمد."},"ICON-2535":{"nm":"بطاقة وسادة دعم عظم الذيل","de":"وسادة تسند برفق أسفل عظم الذيل، وبطاقة صغيرة معلّقة في طرفها. أداة أشبه بورقة رقيقة كُتب عليها وأُلصقت من أجل يوم أنهكه الجلوس الطويل: يمكنك أن تستند هنا قليلًا."},"ICON-2536":{"nm":"حامل ثلاثي لزاوية دعم أسفل الظهر","de":"يستند على ثلاث أرجل ليثبّت بهدوء الزاوية التي يتكئ عليها أسفل الظهر. دعامة تتسلل إلى وضعية على وشك الانهيار. ثلاث نقاط، على غير المتوقع، تكفي لتثبيت ما يتذبذب."},"ICON-2537":{"nm":"مشبك وضعية شدّ الذقن","de":"اسحب الذقن قليلًا واسنده فيستعيد خط الرقبة المشوّش مكانه. توبيخ مشبك بحجم الإصبع لطيف بطريقة ما. كيف ترفع رأسك باستقامة، هذه الأداة الصغيرة تعلّمك ذلك."},"ICON-2538":{"nm":"شريط سلّم خطوات القدم","de":"الشريط المفروش على الأرض يرسم بالتتابع المربعات التي تطؤها القدم. طأها مربعًا مربعًا بأمانة، ودون أن تدري تُنقَش الخطوات في الجسد. فالطريق يزداد وضوحًا كلما وُطئ أكثر."},"ICON-2539":{"nm":"مخروط توجيه تغيير الاتجاه","de":"انصبه فيصبح علامة صغيرة تقول: انعطف هنا. يُهدي زاوية لقدمين اعتادتا الركض المستقيم فقط. حتى طريق الانعطاف يخفي في داخله إيقاعًا خاصًّا به."},"ICON-2540":{"nm":"لوح توازن للوقوف على قدم واحدة","de":"في لحظة الوقوف على قدم واحدة، يميل اللوح قليلًا. تلك الثواني القليلة التي تُبذَل فيها جهود مضنية للتغلب على التذبذب هي الدرس الأصدق في التوازن. طرف القدم الذي يكافح ألّا يسقط يقول كل شيء."},"ICON-2541":{"nm":"مصباح وميض سرعة رد الفعل","de":"في لحظة إضاءة الإشارة، تتسابق اليد والعين على مَن يسبق. الضوء الوامض لا يمنح فسحة للتردد. اليد السريعة تتحرك دائمًا نصف إيقاع قبل التفكير."},"ICON-2542":{"nm":"علامات أرضية للخطوات المتعرّجة","de":"نقاط صغيرة مثبّتة بشكل مائل على الأرض تقود القدمين للرقص بتعرّج. الأصعب من الخط المستقيم هو دائمًا التداخل المتعرّج. تُهت بين النقاط فتنضج حركة القدم السريعة بمهارة."},"ICON-2543":{"nm":"عصا مسطّحة للتوازن على الحبل","de":"ضع قدميك على العصا الرفيعة فيضيق العالم كحبل واحد. كماشي حبال يسير في الهواء، تحمّل شبرًا واحدًا كامل تركيزك. التوازن كلما ضاق ازداد وضوحًا."},"ICON-2544":{"nm":"سوار كرة الارتداد لخفة الحركة","de":"ارتده في معصمك فترتد كرة صغيرة نحوك بارتداد خفيف. في لحظة الرمي والالتقاط، تُنقَش سرعة رد الفعل في أطراف الأصابع. السرعة، في النهاية، هي ألّا تفوّت ما يعود إليك."},"ICON-2545":{"nm":"حلقة هولا لخفّة القدم","de":"علّقها بقدمك ولُفّها فتستمر الحلقة في إغراء الساق بالحركة. في لحظة توقفها تسقط، فتظل القدم تتحرك دون توقف. وبين الحركة التي تشبه اللعب، تنضج خفة القدم وسرعتها."},"ICON-2546":{"nm":"خذروف خشبي لمركز طرف القدم","de":"خذروف يدور على الكفّ يتوقف فورًا في لحظة فقدانه لمركزه. كأيام الطفولة حين كنا نضرب الخذروف في الفناء، التوازن هو شيء لا يمكنه أن يقف إلا بالدوران بلا توقف."},"ICON-2547":{"nm":"رباط شدّ لحماية الكاحل","de":"لُفّ الكاحل واشدّه فتصبح الخطوة المتذبذبة أكثر ثباتًا. كلما كان المكان أسهل للإصابة، وجب الإمساك به بحنان أكبر. خيط واحد يصبح طمأنينة خطوة واحدة."},"ICON-2548":{"nm":"شريط لفّ لتدفئة الركبة","de":"لُفّه حول الركبة الباردة فيتسرّب الدفء بين المفاصل. المفصل المتصلّب لا يلين إلا بعد أن يُدفَّأ. قبل الحركة، إنها أدفأ تحية صباحية تقدّمها لجسدك."},"ICON-2549":{"nm":"كرة ضغط لإرخاء العضلات","de":"اضغط بثبات على النقطة المتصلّبة فتلاطف الحبيبات العقدة بهدوء. راحة غريبة أنها تنحلّ بقدر ما تؤلم. حتى التصلّب الذي لا تصل إليه اليد، تُربّت عليه هذه الكرة الصغيرة نيابة عنها."},"ICON-2550":{"nm":"عجلة ترتيب الإحماء","de":"أيقظ الجسد من الخانة التي تتوقف عندها العجلة. الرقبة، الكتفان، الكاحلان - اترك الترتيب للحظّ وأبقِ القلب خفيفًا. حين يتسلل اللعب إلى الإحماء، يبتسم الجسد المتصلّب أولًا برفق."},"ICON-2551":{"nm":"كمّادة حرارية لتدفئة المفاصل","de":"ضع كمّادة ساخنة على المفصل فينتشر ارتياح أشبه بدفء أرضية الشتاء. إنه الوقت الذي تلين فيه المفاصل المتصلّبة بنعاس هادئ. الجسد المدفَّأ عندها فقط يستعد للتحرّك ببطء."},"ICON-2552":{"nm":"حلقة مقبض شدّ التمدّد","de":"أمسك الحلقة واسحبها فتتمدد العضلات المتصلّبة طويلًا. حوار مشدود يدور بين اليد التي تصمد والجسد الذي ينفتح. بقدر ما تتمدّد، ستصبح حركات الغد أخفّ."},"ICON-2553":{"nm":"لوح نتوءات لتنشيط باطن القدم","de":"قف حافيًا على النتوءات فتستيقظ باطن قدميك النائمة فجأة. كذلك الوخز اللاذع لسير حافي على طريق حصوي، يرتفع شعور ملامسة الأرض من أطراف الأصابع."},"ICON-2554":{"nm":"دبوس مغناطيسي لملاحظة الإصابة","de":"اكتب: لا تُجهد نفسك، وثبّتها على اللوح المعدني. الذكريات المؤلمة تُنسى بسهولة، لذا تُعلَّق أمام العينين بمغناطيس. العناية بالجسد أيضًا تبدأ من سطر واحد مكتوب."},"ICON-2555":{"nm":"أسطوانة معقّدة لإرخاء اللفافة العضلية","de":"دحرج القضيب المعقّد ببطء فتنحلّ اللفافة الملتصقة قسمًا تلو قسم. لمسة تدفع العقد بعيدًا برفق. اليوم المتكتّل أيضًا، حين يُفرد عقدة عقدة هكذا، يصبح أخفّ بكثير."},"ICON-2556":{"nm":"شريط أرضي لخط المشي","de":"يُفرَش مستقيمًا على الأرض فيمنح القدمين خطًّا واحدًا لتتبعه. حتى المشية المشوّشة، حين توضع على هذا الخط، تستقيم قريبًا. ارسم الطريق، فلن تتوه القدم بعد الآن."},"ICON-2557":{"nm":"قضيب مستوى الكتفين","de":"ضعه عرضيًّا على الكتفين فيكشف بهدوء توازنًا مائلًا إلى جانب واحد. الاستواء يعني دائمًا خفض جانب ورفع الآخر. قضيب واحد يشير بصمت إلى عادة معوجّة."},"ICON-2558":{"nm":"ثقل توازن قمّة الرأس","de":"كي لا يسقط الثقل الموضوع على قمة الرأس، يجب أن يقف الجسد كله مستقيمًا كخط واحد. كالمشهد القديم لمن كان يمشي وجرّة ماء متوازنة على رأسه، يُضبَط المركز من أعلى نقطة نزولًا."},"ICON-2559":{"nm":"مسند زاوية الذقن","de":"اسند الذقن برفق فيستعيد الرأس الذي كان يتدلى باستمرار زاويته الصحيحة. راحة قصيرة تُتَّكأ على مسند واحد. الخط المستقيم لا يكتمل إلا حين يسنده أحد من الأسفل."},"ICON-2560":{"nm":"وتد تباعد الخطوة","de":"الوتد المغروس في الأرض يقيس مسبقًا المسافة التي يجب أن تحطّ فيها القدم. خطوة واحدة، لا واسعة ولا ضيّقة، تلك المسافة الصادقة. توازن المشي يبدأ بهدوء من هذه العلامة الصغيرة."},"ICON-2561":{"nm":"إسفين اتجاه طرف القدم","de":"الخطوة الأولى المتردّدة، أطراف الأصابع تتردّد أولًا حول إلى أين تذهب. حين يحدد هذا الإسفين الصغير الاتجاه، يميل القلب برفق نحو تلك الجهة أيضًا. تحديد الطريق ليس قرارًا عظيمًا، بل الشبر الذي تشير إليه أطراف الأصابع."},"ICON-2562":{"nm":"حزام تقويم الظهر","de":"ذلك الصوت الذي كان يقول دائمًا: استقم، استقم، يبدو أنه يعيش داخل هذا الحزام. قوّم يومًا منحنيًا بهدوء، فيغدو الثقل الجاثم على الكتفين أخفّ قليلًا بشكل غريب. وضعية واحدة صحيحة تنهض بالقلب أيضًا."},"ICON-2563":{"nm":"لوحة توزيع وزن القدم","de":"سبعة على القدم اليسرى، وثلاثة على اليمنى. أين تضع ثقلك يحدد توازنك. اللوحة تسأل بهدوء: إلى أي جهة تميل الآن؟ حتى الوقوف مستقيمًا هو في الحقيقة تعديل لا ينقطع."},"ICON-2564":{"nm":"عمود هدف لمستوى النظر","de":"العينان تسقطان دائمًا نحو أطراف القدمين. في تلك اللحظات، يرفع عمود واحد منصوب بعيدًا نظرك ببطء. النظر بعيدًا هو تمرين على الذهاب بعيدًا، فحين ترفع رأسك، حتى المكان الذي بدا بعيد المنال يقترب."},"ICON-2565":{"nm":"مشبك بطاقة زاوية الانحناء","de":"خمس عشرة درجة، ثلاثون درجة، خمس وأربعون درجة. القلب ينحني بقدر ما ينثني الخصر. الزاوية المكتوبة على البطاقة ليست مجرد رقم، بل مقياس صغير يقيس صدق الاحترام تجاه الآخر."},"ICON-2566":{"nm":"حلقة أدب ضمّ اليدين","de":"اضمم يديك معًا بترتيب فيستقرّ القلب المتلهّف بهدوء في مكان واحد. هذه الحلقة الصغيرة تمسك بحنان أطراف الأصابع المشوّشة التي لم تعرف ماذا تفعل، وتثبّت بهدوء الوضعية الأولى للتحية."},"ICON-2567":{"nm":"مغناطيس سهم المسار","de":"أول ما تبحث عنه قدم تائهة، وهي تنظر حولها، هو سهم. اتجاه واحد ملصق بمغناطيس يقطع التردد ويجذب خطواتك برفق نحو حيث يجب أن تذهب. حتى القلب الحائر يجد أخيرًا اتجاهًا واحدًا."},"ICON-2568":{"nm":"دبوس علامة اتجاه الخروج","de":"طريق الخروج أصعب دائمًا من طريق الدخول. حتى في الظلام حين تنطفئ الأضواء، هذا الدبوس المتوهج بوضوح يشير بهدوء إلى المسار الأخير. أن تغادر جيدًا هو أيضًا جزء من المسرح، وهذا ما تدركه فقط في النهاية."},"ICON-2569":{"nm":"شريط بطاقة ترتيب الانحناء الرسمي","de":"كان هناك زمن يتضح فيه من ينحني أولًا ومن ينحني بعده. اخفض جسدك بالترتيب المكتوب على الشريط، فيكتسب الاحترام نسيجًا، ويكتسب الأدب تدفّقًا. إنه الحفاظ على ترتيب القلب."},"ICON-2570":{"nm":"رقاقة مغناطيسية لمحاذاة الخطوات","de":"إن اختلّت خطوة شخص واحد، اهتزّ الصف كله. كرقاقة تلتصق بنقرة عند محاذاة أطراف الأصابع، الوقوف معًا يعني التنازل برفق عن خطوتك لمن بجانبك. أصوات الأقدام التي تخطو بإيقاع واحد هي الأكثر طمأنينة."},"ICON-2571":{"nm":"علامة حدوة لموضع الانحناء على المسرح","de":"حتى انحناءة واحدة على المسرح لها مكان تقف فيه. ضع قدميك على العلامات المنتشرة بشكل دائري كحدوة حصان، فتجد التحية الأولى التي كانت تخطئ باستمرار من التوتر شكلها أخيرًا. حين تعرف مكانك، يهدأ الارتجاف قليلًا أيضًا."},"ICON-2572":{"nm":"بطاقة إيماءات الشكر","de":"الامتنان الذي عجزت الكلمات عن حمله كاملًا يتدفق عبر أطراف الأصابع. رسم قلب، ووضع يد على الصدر - كل إيماءة مكتوبة على البطاقة تصبح ترجمة للقلب مدوَّنة بالحركة. الصدق الذي يتوق للوصول له شكل دائمًا."},"ICON-2573":{"nm":"وتد بطاقة تباعد الطابور","de":"حتى الوقوف في الطابور له أدب لطيف. كوتد يحافظ على مسافة شبر واحد بالضبط عن الشخص الذي أمامك، الانتظار يبدأ من مراعاة صغيرة لعدم دفع بعضنا بعضًا. الوقوف على مسافة قليلة هو أيضًا اهتمام بالآخر."},"ICON-2574":{"nm":"حلقة قلب بطاقات الإشارة","de":"حين تظل الجملة التالية تدور على الشفاه، يقلب إصبع صفحة بهدوء. الأوراق الصغيرة المخيّطة في الحلقة تكبح بهدوء نبض القلب المتسارع، وتفتح بثبات خانة ما يجب قوله بعد ذلك. مهما ارتجفت، لا ينقطع التدفّق."},"ICON-2575":{"nm":"ساعة رملية لترتيب البرنامج","de":"راقب حبات الرمل وهي تتساقط بهدوء، فيستقر الترتيب التالي بهدوء في القلب. حتى سقوط الحبة الأخيرة، هذه الساعة الصغيرة تعلّمك قراءة الزمن بعينيك، دون استعجال."},"ICON-2576":{"nm":"عصا تمرين إمساك الميكروفون","de":"قبل أن يصبح الأمر بديهيًّا، تكون عصا فارغة ثقيلة كألف رطل. زاوية القبضة، والمسافة من الفم، والقوة المبذولة في المعصم - التمرين الذي يُقبَض ويُترَك مرات لا تحصى يتفتّح يومًا ما فجأة إلى حركة واحدة طبيعية."},"ICON-2577":{"nm":"عصا لسان للنطق الواضح","de":"غا، نا، دا، را. أمسك العصا بفمك ودحرج الأصوات حتى يتضح طرف لسانك. كلمة تعبر واضحة نقية أشبه بزهرة تتفتح بهدوء فوق مئات الساعات من التلعثم والتداخل."},"ICON-2578":{"nm":"علم يدوي لإشارة البدء","de":"ابدأ، توقف، استرح إيقاعًا واحدًا. علم واحد بلا كلمة يقود نفَس المسرح. من مكان لا يراه الجمهور، تمسك يد تتمايل بهدوء بكل إيقاع دون أي فجوة."},"ICON-2579":{"nm":"جرس تحويل الفقرة","de":"رنّة صافية، ويتغير المشهد. كصوت الجرس الذي كان ينتشر في سوق عند الغسق، هذا الرنين الصغير يحمل قلبًا متردّدًا برفق إلى الفقرة التالية. التحوّل يبدأ دائمًا من صوت."},"ICON-2580":{"nm":"بندول إيقاع نفَس الكلام","de":"استنشق الهواء - واحد، اثنان - وازفر ببطء. اضبط نفَسك متتبعًا البندول المتمايل يمينًا ويسارًا، فتستعيد الكلمات التي كانت تندفع بسرعة إيقاعها من جديد. سرعة الكلام كانت في النهاية سرعة النفَس."},"ICON-2581":{"nm":"لوح طيّ نص الإدارة","de":"في حركة واحدة من الطيّ والفتح، يُحفَظ ترتيب اليوم كاملًا. في لحظة فتح اللوح الذي تشرّب لمسات اليد، يصطف القلق حول ما يجب طرحه أولًا في صف هادئ. فتحة واحدة تنظّم اليوم كله."},"ICON-2582":{"nm":"ساعة رملية لإيقاع النفَس","de":"شهيق ثلاثة، حبس أربعة، زفير ستة. بينما يتدفق الرمل، يتدفق نفَسك بهدوء معه. عدّ كل نفَس واحدًا تلو الآخر هو أقدم طريقة وأرقّها للعناية ببطء بذاتك المشغولة."},"ICON-2583":{"nm":"شرابة زينة وسادة التأمل","de":"تتمايل الشرابة المعلّقة في طرف الوسادة بهدوء دون أي ريح. اجلس متربعًا، فيأتي هدوء إنسان قديم كان يجلس على شرفة خشبية يضبط قلبه، ليقترب برفق ويمكث قليلًا ثم يمضي."},"ICON-2584":{"nm":"جرس ريح يدوي لضبط النفَس","de":"حين تمرّ نسمة واحدة، يبكي صوت صافٍ بهدوء. معلّق كجرس ريح عند حافة السقف، يُسقط قطرة واحدة باردة ومنعشة فوق قلب يغلي بالاضطراب. حتى الصوت له قوة تُبرّد."},"ICON-2585":{"nm":"طبق استقبال دخان البخور","de":"الدخان المتبقي من احتراق البخور يهبط ببطء على الطبق. كتلك الرائحة التي كانت تتصاعد أمام مائدة صباح عيد، يهدّئ خيط واحد من الدخان بهدوء شديد الهواء المضطرب ويملأ الغرفة بالسكينة."},"ICON-2586":{"nm":"ثقل تمايل الشهيق والزفير","de":"نفَسي يمتطي ثقلًا واحدًا يرتفع ببطء ثم ينخفض من جديد. يطفو عند الشهيق ويهبط عند الزفير - في يوم ينسى فيه الجسد كيف يتنفس، هذه الساعة الصغيرة تعلّمه من البداية مرة أخرى."},"ICON-2587":{"nm":"مطرقة رنين جرس التأمل","de":"اقرع الجرس مرة واحدة بهدوء فينتشر الصدى طويلًا. كصوت جرس الريح الذي كان يرنّ في معبد جبلي، مجرد الإصغاء بسكون حتى يختفي ذلك الرنين تمامًا في الهواء يغسل ركنًا من القلب بصفاء."},"ICON-2588":{"nm":"ريشة دليل مسار النفَس","de":"ضع الريشة بهدوء أمام أنفك فيصبح مسار النفَس غير المرئي مرئيًّا أخيرًا. تمايل خفيف يعني أنك تتنفس جيدًا، وسكون يعني أنك حبست النفَس طويلًا. أخفّ الأشياء أحيانًا يكون أصدق دليل."},"ICON-2589":{"nm":"حصاة تهدئة القلب","de":"الحصاة المقبوضة في راحة اليد باردة وناعمة. كحجر تدحرج طويلًا على ضفة نهر حتى تخلّى عن كل حوافه، استمر في لمسه بأطراف أصابعك فتتآكل الزوايا الحادة في قلب مضطرب شيئًا فشيئًا لتصبح مستديرة."},"ICON-2590":{"nm":"مشبك حرارة تنفّس الأنف","de":"درجة حرارة طرف الأنف تخبر بهدوء عمق النفَس. يقرأ المشبك بصمت الهواء الداخل باردًا والخارج دافئًا، ليريك بوضوح أمام عينيك التنفّس الذي عادة لا تشعر به حتى. للنفَس أيضًا تعبير."},"ICON-2591":{"nm":"لوحة ملصقات طقس المزاج","de":"هل قلبي اليوم صافٍ أم غائم؟ في لحظة اختيار ملصق صغير ولصقه على اللوحة، يصبح المزاج الذي كان يصعب التعبير عنه بالكلمات نوعًا من الطقس ويكتسب شكلًا واضحًا. حتى القلب يحتاج إلى نشرة جوية."},"ICON-2592":{"nm":"ختم يدوي بلون المشاعر","de":"الفرح أصفر، والحزن أزرق. اختر لونًا واطبعه بقوة على الورق، فيبقى لون القلب أثرًا. حتى المشاعر التي يصعب تسميتها، يأتي اللون إليها أولًا ليتعرّف عليها بهدوء."},"ICON-2593":{"nm":"رقاقة بتلة قلب اليوم","de":"ضع قلب اليوم كله برفق فوق بتلة واحدة. كأزهار الأزاليا المتطايرة في يوم ربيعي، رقاقة واحدة خفيفة ورقيقة تسأل بهمسة، في نهاية يوم يذوي، كيف كانت حالك."},"ICON-2594":{"nm":"مغناطيس فقاعة كلام التشجيع","de":"الكلمات التي تريد قولها تظل تدور عند الشفاه. في لحظة الضغط على مغناطيس فقاعة الكلام، تصل كلمة تشجيع لم تتمكن من نطقها بصوت عالٍ بهدوء إلى يوم شخص متعب. هكذا يُنقَل القلب."},"ICON-2595":{"nm":"ختم مظروف القلب الداخلي","de":"الكلمات التي لم تتمكن من إخراجها تُوضَع بعناية في مظروف ويُختَم عليها. كإنسان قديم يختم رسالة بالغراء بأطراف أصابعه، ختم واحد يحفظ القلب الداخلي بأمان. في انتظار هادئ ليوم يُخرج فيه ويُفتح."},"ICON-2596":{"nm":"برعم زهرة حرارة المشاعر","de":"برعم مقفل، عند لمسه الدفء، ينفتح طبقة تلو الأخرى بحذر. يتفتح مع ارتفاع حرارة القلب - كم دفئًا نلت اليوم، هذه الزهرة تعرفه قبل الكلمات. حتى القلب يأتيه الربيع."},"ICON-2597":{"nm":"حزام مرآة يدوية للثناء الذاتي","de":"ارفع المرآة والتقِ بعينيك المنعكستين فيها بهدوء. ما يعكسه الوجه الصغير المعلّق بالحزام ليس وجهك، بل أنت البارحة، الذي يستحق كلمة تقول: صمدت جيدًا. لم تكن المواساة بعيدة أبدًا."},"ICON-2598":{"nm":"طقم أختام تعابير المزاج","de":"ابتسامة مشرقة، دموع تكاد تفيض، شفاه متجهّمة عابسة. اضغط أختام التعابير بقوة لتكتب يوميات القلب. في يوم يصعب فيه الكتابة بالكلمات، وجه صغير يتحدث بهدوء نيابة عنك عن مزاج ذلك اليوم."},"ICON-2599":{"nm":"حلقة ترتيب كبّة خيوط المشاعر","de":"مهما تشابكت الكبّة، حلّها بصبر خيطًا خيطًا فتعود في النهاية إلى خيط واحد. علّق المشاعر المتشابكة والخانقة على الحلقة واحدة تلو الأخرى، فحتى قلبك الذي لم تفهمه أبدًا يجد خيطًا رفيعًا يُتبَع."},"ICON-2600":{"nm":"حبل كيس عطر النوم","de":"من الكيس العطري المعلّق عند الوسادة، تنتشر رائحة أعشاب خفيفة بهدوء. كرائحة الجدة وهي تضع العطر عميقًا في الخزانة، بينما تداعب الحبل بأصابعك، يغرق التوتر الذي كان متيقظًا طوال اليوم في نوم هادئ."},"ICON-2601":{"nm":"لوحة قلب وضعية النوم","de":"ليلة تقلّبتَ فيها حتى غفوت أخيرًا عند الفجر. اقلب وضعية الجسد الراقد برفق، فيتسلل تقلّب الأمس خلسةً إلى انتعاش صباح اليوم. الراحة أيضًا تحتاج إلى تمرين، وهذه اللوحة الصغيرة تعين عليها بصمت."},"ICON-2602":{"nm":"معلّقة ضوء القمر عند الوسادة","de":"تُعلَّق شعرة من الضوء المتسللة عبر فتحة الستارة عند رأس الوسادة. نهر خافت يجري فوق الوجه النائم، وحتى ليالي المتدربة التي كانت تخاف الظلام ازدادت رقّةً أخيرًا. كانت أول عزاء صغير عرفته."},"ICON-2603":{"nm":"رقاقة برعم الحالة","de":"حالة اليوم مُقفَلة كبرعم زهرة. اضغط الرقاقة برفق فتتفتح شيئًا فشيئًا، فالجسد يعرف قبل أي أحد إن كان النوم هنيئًا أم لا. حتى ذلك التردد قبل التفتّح الكامل محبّب بهدوء."},"ICON-2604":{"nm":"غطاء فتيل مصباح النوم","de":"\"لا تُطفئوا الضوء.\" من أجل الصغيرة التي تخاف الظلام، وضع أحدهم غطاءً برفق فوق الفتيل. لا شديد السطوع ولا شديد الخفوت، بل وعدٌ صغير وحنون يرافقها فقط حتى يغلبها النعاس."},"ICON-2605":{"nm":"دبوس عبّاد الشمس لصحوة الصباح","de":"إذا ثُبّت عند الوسادة، يُدير رأسه برفق كزهرة عبّاد الشمس نحو أول أشعة الشمس. حتى في الأيام التي لا ترغب فيها بالنهوض، لثمة سبب يدعوك إليه الضوء، فيأخذ الصباح في اتجاه واحد."},"ICON-2606":{"nm":"فرشاة الوسادة بالأعشاب المنوّمة","de":"تُغمَّس اللافندر والبابونج في طرف الفرشاة وتُمرَّر مرة واحدة على الوسادة. وبينما تتسلل الرائحة إلى كيس الوسادة، يتحلّل توتر اليوم كله ببطء عن الكتفين. النوم الجميل يبدأ من هذه الرائحة الصغيرة."},"ICON-2607":{"nm":"مشبك زاوية اللحاف","de":"عند الفجر، تتسلل أطراف القدمين خارج اللحاف مرارًا. إذا ثُبّتت الزاوية بإحكام بالمشبك، لا تستطيع الدفء الهرب طوال الليل. إنه إحكام صغير يُوضع مكان قول \"نم هنيئًا\"."},"ICON-2608":{"nm":"سلة جمع حصى الحال","de":"عمل جميل واحد كل يوم، حصاة واحدة بحجم راحة اليد. كلما ثقلت الحصى المتجمعة في السلة، اطمأن القلب أكثر خلسة. جمع اللحظات العادية في راحة اليد، هكذا كانت السعادة تُحسب دائمًا."},"ICON-2609":{"nm":"جرة جمع نجوم العزيمة","de":"كل ليلة، شكّل عزيمة اليوم على هيئة نجمة وأسقطها في الجرة. حين تمتلئ، تصبح الجرة سماء ليل صغيرة. تعرف الفوهة التي كانت فارغة أن الوعود لا تتلألأ إلا حين تُجمَع."},"ICON-2610":{"nm":"معلّقة حلوى المكافأة الصغيرة","de":"حلوى واحدة تمنحها لنفسك في نهاية يوم متعب. في لحظة إخراجها من المعلّقة ووضعها في الفم، يصبح كل شيء على ما يرام حتى لو لم يلاحظ أحد. فالمكافأة الصغيرة أصدق تشجيع."},"ICON-2611":{"nm":"قالب ختم \"أنجزتُه اليوم\"","de":"تُغمَس في الحبر وتُضغَط بقوة على الدفتر. \"أنجزته اليوم.\" اليوم الذي أُتقن فيه العمل واليوم الذي اكتُفي فيه بالصمود يملآن مربّعًا واحدًا بالتساوي. لا حاجة لأن يكون كل يوم كاملًا، فقط ألا تتوقف عن الختم."},"ICON-2612":{"nm":"قاعدة حاملة علم التشجيع","de":"إذا غُرست بإحكام في الأرض، كلما اشتدت الريح خفق العلم بقوة أكبر. حتى ما يتمايل يحتاج إلى يد تسنده. هكذا يصمد قلب من يشجّع أحدًا، من الأسفل."},"ICON-2613":{"nm":"أصيص زراعة بذرة الهدف","de":"الهدف لا يُحفَظ بالكلام بل يُدفَن في التراب. وبينما تزرع بذرة وتسقيها وتنتظر، يتحول القلق ببطء إلى جذور. ما ينمو داخل الأصيص ليس البرعم وحده."},"ICON-2614":{"nm":"لوحة ملصقات الثناء","de":"ملصق واحد لكل عمل جيد. كلما امتلأت اللوحة بالألوان، عادت الأيام التي مرّت مهملة إلى الحياة بلونها. كنا نعرف في طفولتنا أن الثناء يزداد وضوحًا كلما لُصق أكثر."},"ICON-2615":{"nm":"حلقة ربط شريط العزيمة","de":"يد تُدخل الشريط في الحلقة وتعقده. بإحكام كي لا يُفكّ، لكن دون شدّة زائدة. العزيمة تشبه هذه العقدة تمامًا، إن شُدّت كثيرًا انقطعت وإن تُركت رخوة انزلقت بهدوء."},"ICON-2616":{"nm":"رقاقة صدفة الإنجاز الصغير","de":"اكتب إنجازًا صغيرًا على صدفة التقطتها من الشاطئ. كقطعة نحتتها الأمواج وصقلتها لتصل إلى هنا، يومك أيضًا تدحرج طويلًا حتى صار لامعًا. كل ما يصمد أمام الزمن يتلألأ في النهاية."},"ICON-2617":{"nm":"خطّاف تعليق ميدالية المكافأة","de":"الميدالية التي نُلت بجهد لا تُوضع في الدرج بل تُعلَّق على مستوى العين. وزنها المعلّق على الخطّاف يشدّ الكتفين كل صباح. المكافأة لا تُخفى، بل تُعلَّق هناك لتُنظَر إليها."},"ICON-2618":{"nm":"كوب تنقيط مظلة الأمطار","de":"تنساب مياه أمطار الموسم من طرف المظلة قطرة قطرة. إذا وُضع كوب تحته، يبقى المدخل جافًا. لا يمكن منع ما ينهمر، لكن يمكن تحديد أين يسقط."},"ICON-2619":{"nm":"كمادة باردة لتبريد الحرّ","de":"خلف الكواليس في عزّ الصيف، كمادة باردة توضع برفق على مؤخرة الرقبة. الحرارة المتصاعدة تهدأ لحظة. \"خذ نفسًا.\" يدٌ تعتني بي قبل أن يفعل الحرّ ذلك تمنح طمأنينة."},"ICON-2620":{"nm":"مشبك تثبيت شفرة المروحة","de":"حتى الشفرات التي كانت تدور بعنف تقف بهدوء بمشبك واحد. كلما اشتدت الريح، احتاجت إلى ما يمسكها بإحكام. الأشياء سريعة الدوران تصبح آمنة بمن يمسكها."},"ICON-2621":{"nm":"قضيب تجفيف الحذاء المبلل","de":"الحذاء المبلل بالمطر يترك حتى القلب رطبًا بحلول الصباح. إذا أُدخل القضيب داخله، يصبح جافًا وصالحًا للّبس مجددًا في الصباح. ما يبتلّ لا يُرمى، بل يُجفَّف برفق."},"ICON-2622":{"nm":"لوحة تنظيف طين الحذاء المطاطي","de":"حذاء مطاطي غارق في طين حقول الأرز. فقط بعد فركه على اللوحة يُصعَد إلى الأرضية. ترك وحل الخارج عند الباب قبل الدخول تقليد قديم يحافظ على نظافة البيت."},"ICON-2623":{"nm":"قطعة بلاط باردة لصيف حافي القدمين","de":"القدم الحافية تعرف أولًا. إذا لامست الأخمص قطعة البلاط الموضوعة على أرضية الصيف، يتلاشى حرّ الظهيرة في قبضة من البرودة برفق. برودة صغيرة واحدة تكفي لجعل فصل طويل محتملًا."},"ICON-2624":{"nm":"شريط عتبة يمنع الأمطار","de":"مجرد شريط واحد لُفّ حول العتبة، ولم تعد مياه الأمطار تتسلل إلى الداخل. خط رفيع يفصل الداخل عن الخارج. المكان الجدير بالحماية يليق به حدّ محكم أكثر من جدار فخم."},"ICON-2625":{"nm":"طبق حامل بخور البعوض","de":"في ليلة صيفية، إذا وُضعت لولبة طارد البعوض على حاملها، يتصاعد دخان لاذع وأليف في آنٍ. كما يخفت البخور دائريًا شيئًا فشيئًا، يتعمّق الليل ببطء أيضًا. إنها رائحة تلك الأيام التي كنا نستلقي فيها على المقعد الخشبي نعدّ النجوم."},"ICON-2626":{"nm":"حلقة كم التبريد للحرّ","de":"يُغطّى الساعد الملسوع بالشمس بالكم الواقي. إذا ثُبّت بإحكام بالحلقة على كمّ الثوب، يصبح عمل منتصف النهار محتملًا. البرودة هي تلك اللطافة الصغيرة التي تُظلِّل موضع اللمس بشبر واحد."},"ICON-2627":{"nm":"مكنسة يدوية لكنس أوراق الخريف","de":"تُكنَس الأوراق الساقطة المتناثرة في الفناء وتُجمَع بالمكنسة اليدوية. فصل كامل يحفّ تحت القدمين. تنظيم شيء ما هو أيضًا وداعٌ رقيق لما يجب تركه يمضي."},"ICON-2628":{"nm":"قضيب دعم نافذة التهوية","de":"يُثبَّت قضيب في غرفة خانقة ليُبقي النافذة مفتوحة قليلًا. تتسلل نسمة الخريف برفق وتحمل الهواء الراكد بعيدًا. التهوية منفذ تنفّس صغير يبدّل بهدوء ما تجمّع في الداخل بما هو في الخارج."},"ICON-2629":{"nm":"سدادة كيس البلوط","de":"كالسنجاب، يملأ الكيس بالبلوط ثم يسدّ الفوهة بالسدادة. بإحكام، كي لا تتدحرج حبة واحدة للخارج. الرغبة في حماية ما جُمِع هي غريزة قديمة للكائنات الصغيرة التي تعبر الشتاء."},"ICON-2630":{"nm":"مضرب تنفيض غبار لحاف الخريف","de":"يُنشَر اللحاف الذي غطّى طوال الصيف في الفناء ويُنفَض بضربات متتالية بالمضرب. تنتشر رائحة الشمس بين الغبار. أن تنفض الفصل القديم لتفرش الفصل الجديد فوقك، المعصم يتذكر ذلك أولًا."},"ICON-2631":{"nm":"حبل سدّ فتحة النافذة من الريح","de":"يُسَدّ الهواء البارد المتسلل من فتحة النافذة بإحكام بحبل واحد. خيط رفيع يحمي دفء الغرفة حتى النهاية. البرد الشديد يبدأ دائمًا من فجوة صغيرة، والاستعداد للشتاء يعرف ذلك."},"ICON-2632":{"nm":"غطاء مصفاة أوراق الخريف","de":"مصفاة موضوعة فوق مجرى تصريف المياه. تصفّي الأوراق بعناية وتترك الماء وحده يجري. الخريف يقول من شرفته إنه كي يجري الماء دون انسداد، يجب أن تقرر ما تسمح بمروره وما تمسكه."},"ICON-2633":{"nm":"مشبك حزمة العشب الجاف","de":"تُربط حزمة العشب الجاف تمامًا بإحكام بالمشبك. يد تجمع الأشياء المتناثرة في حزمة واحدة. حتى في المكان الذي فرغ فيه خضار الصيف تمامًا، إذا جُمِع ما تبقّى بقيت فائدته كاملة."},"ICON-2634":{"nm":"مؤرجحة درجة حرارة ريح الخريف","de":"عندما تهبّ الريح، تتمايل المؤرجحة. من مدى تمايلها تُقاس عمق خريف اليوم. درجة الحرارة ليست رقمًا، بل تصل إلى اليد أولًا كشيء يتمايل برقة."},"ICON-2635":{"nm":"حافظة دفاية اليد في جيب المعطف","de":"\"يداك باردتان.\" حافظة دفاية اليد الموضوعة في جيب المعطف تدفئ بهدوء الأصابع المتجمدة. القلب الذي يحسب برد أحدهم أولًا يسكن دائمًا بصمت داخل الجيب."},"ICON-2636":{"nm":"حافة تجميع تكاثف النافذة","de":"تستقبل الحافة بهدوء الدموع التي أذرفتها نافذة الشتاء طوال الليل. مجرى ماء صغير خلقه فرق الحرارة بين الداخل والخارج. حيث يكبر الفرق، يتدفق الكثير، تُظهر نافذة الفجر ذلك كل يوم."},"ICON-2637":{"nm":"شبكة حماية أمام نار الموقد","de":"تُنصَب شبكة الحماية أمام الموقد المشتعل. الدفء قريب، والخطر على بُعد شبر واحد بالضبط. إبقاء النار قريبة دون أن يُصاب أحد بأذى هو أبسط مسافة في الاعتناء بشخص ما."},"ICON-2638":{"nm":"مشبك تثبيت لحاف الشتاء","de":"عندما ينزلق اللحاف الشتوي السميك مرارًا، يضغطه المشبك بهدوء ليثبّته في مكانه. الدفء الثقيل يجب أن يُمسك بإحكام ليؤدي غايته. هكذا تُحمى دفء ليلة الشتاء بإتقان."},"ICON-2639":{"nm":"ملعقة كشط الصقيع","de":"تُكشَط طبقة الصقيع البيضاء المتفتحة على زجاج السيارة عند الفجر بالملعقة. الرؤية الضبابية تتضح خطًا بعد خط. حتى المتجمد يمكن كشطه في النهاية، تُخبرك بذلك أطراف أصابع صباح الشتاء."},"ICON-2640":{"nm":"غطاء عازل لسدادة زجاجة الماء الساخن","de":"يُوضع غطاء عازل فوق الزجاجة المملوءة بالماء الساخن. كي لا تبرد طوال الليل، يلفّ الدفء بطبقة إضافية. طريقة الاحتفاظ بالدفء طويلًا هي، في النهاية، احتضانه بعناية بشيء ما."},"ICON-2641":{"nm":"قضيب ضغط ورق عزل الباب","de":"الريح القارصة التي كانت تتسلل من فتحة الباب تتردد لحظة عند لقائك. قضيب واحد يضغط طرف ورق النافذة إلى الأسفل. دفء الغرفة يحمي أخيرًا أهله، والشتاء يُدفَّأ بهذا العناد الصغير."},"ICON-2642":{"nm":"طبق حامل دفاية القدمين","de":"طبق مستدير موضوع تحت دفاية القدمين. يستقبل كل الحرارة وحده ولا يترك أثر احتراق واحدًا على الأرض. حين تدفأ أطراف أصابع قدمي أحدهم حتى النعاس، ينتهي نصيبي من اليوم بهدوء."},"ICON-2643":{"nm":"حلقة تعليق قماش امتصاص التكاثف","de":"كي لا تفقد القطعة التي مسحت قطرات الماء على نافذة الفجر مكانها، تنتظرها حلقة معلّقة على الجدار. أكثر من الابتلال حتى التشبّع، الانتظار جافة مجددًا لصباح الغد هو جوهر معنى الامتصاص الحقيقي."},"ICON-2644":{"nm":"معلّقة تجفيف قفازات الشتاء","de":"القفازات التي أنهت جولة معركة كرات الثلج تفرد أصابعها بجانب المدفأة. منظر تعليقها على المعلّقة وهي تنفث بخارًا خفيفًا. في نهاية بعد ظهيرة حمرّ فيها طرف الأنف، إنه أهدأ غسيل في الشتاء."},"ICON-2645":{"nm":"قطعة تبديل ريش منفضة الغبار","de":"عندما يبلى الريش، يُستبدَل بريش جديد. لحظة يعود فيها طرف مطاردة الغبار ناعمًا مجددًا. أن لأدوات التنظيف أيضًا فصولها المتغيّرة، هذا التبديل الصغير يخبرك به برفق في راحة يدك."},"ICON-2646":{"nm":"مقبض عصر قماشة التنظيف","de":"مقبض مثبَّت ليوفّر عليك جهد رسغك. لفّة واحدة وتُخرج القماشة الماء من تلقاء نفسها. وداعًا لأيام الكفاح أمام لوح الغسيل. في شؤون البيت، حفنة من الحيلة تصبح لطفًا بذاته."},"ICON-2647":{"nm":"رأس بديل لفرشاة الأرضية","de":"عندما تبلى فرشاة الأرضية، يُستبدَل الرأس فقط. المقبض يبقى كما هو، والوزن الذي اعتادته اليد يبقى كذلك. في الأشياء المستخدَمة طويلًا يسكن لطفٌ صغير وثابت لا يريد أن يُرمى كل شيء دفعة واحدة."},"ICON-2648":{"nm":"بكرة تعبئة رول إزالة الوبر","de":"بعد نزع آخر ورقة من رول الوبر، يشعر المرء بفراغ غريب. حينها تُركَّب بكرة جديدة. إنه وعد التعبئة العنيد والحنون بمتابعة حتى قطعة وبر واحدة عالقة على سترة صوفية حتى النهاية."},"ICON-2649":{"nm":"كاشطة غبار الزوايا","de":"حتى في الزوايا التي لا تصلها المكنسة، يقيم الغبار سكناه بهدوء. نكش الزاوية بطرف رفيع لتنظيفها. الاهتمام حتى بما لا يُرى هو بالضبط كرامة شؤون البيت."},"ICON-2650":{"nm":"مشط تنظيف المكنسة","de":"حتى المكنسة التي كنست طويلًا تحتاج إلى لمسة راحة. مشّط الشعر المتشابك بين الشعيرات بهذا المشط، فتستعد المكنسة أخيرًا، بعد أن أنهت جولة عملها، للكنسة التالية."},"ICON-2651":{"nm":"وسادة تلميع حبيبات الأرضية الخشبية","de":"إذا كُسي حبيب الخشب بطبقة من الشمع، يستعيد الخشب ببطء بريقًا نسيه منذ زمن طويل. أخمص القدم يكاد ينزلق ولا ينزلق، بعد ظهيرة يبتسم فيها البيت كله لامعًا ومرتاحًا."},"ICON-2652":{"nm":"كانسة غبار فتحة الباب","de":"أنا أتصيّد الغبار الذي يسكن فتحة الباب. كلما تسلل شيء وتراكم في كل مرة يُفتح فيها الباب ويُغلق، أجمعه بجسمي النحيل. كلما ضاقت الفجوة وعمُقت، جاء دوري لا محالة."},"ICON-2653":{"nm":"غطاء شبكي لغبار دعّاسة المدخل","de":"كي لا يتسرب الغبار الذي ابتلعته دعّاسة المدخل إلى الخارج مجددًا، يقف غطاء شبكي واحد حارسًا أخيرًا. الغبار الذي جلبه الحذاء الموحل من العالم الخارجي، يُسمح له بالدخول إلى هذا الحد فقط ولا أبعد."},"ICON-2654":{"nm":"فرشاة إزالة ترسبات الصنبور","de":"فرشاة صغيرة تدور وتُزيل الترسبات الكلسية التي استقرت بهدوء عند عنق الصنبور. المكان الذي تلمسه الأيدي كل يوم يجب أن يلمع أكثر. هذا هو أدب الحمام الذي تحفظه هذه الفرشاة الصغيرة."},"ICON-2655":{"nm":"غطاء شبكي لشعر البالوعة","de":"أُمسك بهدوء الشعر المنجرف نحو البالوعة. أدرأ كارثة الانسداد الصغيرة بغطاء واحد. يوم بطل صغير مستدير وصلب يمرّ بهدوء دائمًا تحت القدمين."},"ICON-2656":{"nm":"كاشطة فواصل البلاط","de":"الفواصل التي اسودّت بين البلاط الأبيض، اكشط تلك السنوات القديمة برفق بالطرف. حين تنظف الشقوق الضيقة، يلتقط الحمام بأكمله أنفاسه خفيفًا وكأنه جديد."},"ICON-2657":{"nm":"دبوس تنظيف رأس الدش","de":"افتح ثقوب رأس الدش المسدودة بطرف الدبوس، فيتدفق الماء الذي كان يتقاطر بالكاد بغزارة منعشة مجددًا. صوت ماء الصباح المنتصر، حين ينحلّ انسداد صغير واحد."},"ICON-2658":{"nm":"كوب حفظ فرشاة المرحاض","de":"حتى فرشاة المرحاض لا تصبح صحية إلا حين ترتاح في مكان جاف. مغروسة بترتيب في كوب صغير يستقبل القطرات، تنتظر دورها التالي. رقيّ الأداة لا يظهر في استخدامها بل في طريقة حفظها."},"ICON-2659":{"nm":"إسفنجة مسح العفن","de":"العفن الأسود المنتشر في زوايا البلاط، لذلك الضيف العنيد تقترح الإسفنجة برقة المغادرة. بعد مسحة واحدة سريعة، يعود الحمام مشرقًا إلى بياضه الأصلي."},"ICON-2660":{"nm":"ممسحة ضباب المرآة","de":"أمام مرآة غائمة بعد الاستحمام، ترسم الممسحة خطًا واحدًا فيعود وجهي واضحًا. لحظة تلتقي فيها مجددًا بتعبير اليوم الذي اختبأ قليلًا خلف الضباب."},"ICON-2661":{"nm":"معلّقة شبشب الحمام","de":"عُلِّق الشبشب المبلل مقلوبًا، فيتساقط الماء قطرة قطرة ويجف الداخل. كي لا تبرد قدما الشخص التالي. عناية المعلّقة الصغيرة تسبق دائمًا بخطوة، خارجة لاستقبالك."},"ICON-2662":{"nm":"علبة فرشاة الأظافر","de":"حتى الفرشاة الصغيرة التي تُنظّف تحت الأظافر لها بيتها الخاص. تدخل بإحكام في العلبة وتجفّ دون رطوبة، منتظرة المغسلة التالية. النظافة تبدأ دائمًا بهدوء من الترتيب."},"ICON-2663":{"nm":"غطاء كوب تعقيم فرشاة الأسنان","de":"حتى فرشاة الأسنان التي تلامس فمك مرتين يوميًا تحتاج إلى ملاذ صغير. لحظة يُغلق غطاء كوب التعقيم بصوت خفيف، تُحمى مساحة صغيرة من النظافة بهدوء من الرطوبة العالقة في الحمام."},"ICON-2664":{"nm":"كبسولة حمل أعواد القطن","de":"كي لا تنكسر أعواد القطن في حقيبة السفر أو تتناثر، تحتضنها كبسولة واحدة بدفء. كلما كان الشيء أصغر، وجب تجهيزه مسبقًا كي لا تُفاجَأ في طريق غريب."},"ICON-2665":{"nm":"لوحة صغيرة لفحص الأنفاس","de":"انفخ في راحة يدك ثم قرّبها من اللوحة الصغيرة، فيلمسها نفسك ويجعلها ضبابية بيضاء. أظرف دليل على أنني حيّ هنا في يوم بارد، تسجّله هذه اللوحة الصغيرة بصمت."},"ICON-2666":{"nm":"بيت حفظ ملقاط الأذن","de":"عندما يسافر ملقاط الأذن داخل الحقيبة، يفقد طرفه حدّته بسهولة. لذلك أُعِدّ له بيت صغير. بداخله، حيث لا يتأذى طرفه حتى وهو مُحمول، تنام الأداة الرقيقة بهدوء."},"ICON-2667":{"nm":"مشبك طيّ المنديل","de":"يعضّ المشبك برفق منديلًا مطويًا بعناية من زواياه الأربع، مانعًا إياه من الانفراط داخل الحقيبة. قطعة واحدة مطوية بأناقة تمنح رقيًا هادئًا مهما كانت اللحظة التي تُخرَج فيها."},"ICON-2668":{"nm":"علبة الضمادات","de":"في يوم يُخدَش فيه ركبتك، افتح العلبة فتصطف ضمادات متنوعة تنتظرك. اللطف الذي يعرف كيف يهتمّ حتى بجرح صغير. حقيبة الإسعافات الأولية يجب أن تُبقى دائمًا في متناول اليد."},"ICON-2669":{"nm":"ممسحة بصمات راحة اليد","de":"امسح البصمات المتبقية على الزجاج فتختفي آثار اللمسات المترددة. سحر صغير بحجم راحة اليد، حيث يعود العالم خلف النافذة، الذي كان غائمًا عند كل لمسة، شفافًا مجددًا."},"ICON-2670":{"nm":"فاصل فرز إعادة التدوير","de":"الورق من هنا، والعلب من هناك. فاصل واحد يفرّق مصيرًا كاد أن يختلط. إعادة التدوير هي في النهاية قلب يفرز بعناية، وهذا الفاصل المحكم يرسم ذلك السطر الأول بوضوح."},"ICON-2671":{"nm":"مجرفة نزع الملصقات","de":"حتى الملصق اللزج المتشبث يستسلم بهدوء أمامي. أدخل نصل المجرفة المسطّح برفق تحت الزاوية، فينزع نظيفًا دون أثر واحد، وداعٌ منتصر."},"ICON-2672":{"nm":"أسنان قطع شريط اللاصق الورقي","de":"لا حاجة للبحث عن مقص فقط لاستخدام الشريط اللاصق. ضعه على الأسنان واسحب، فينقطع بدقة على طول النسيج. أعزّ صديق صغير ورشيق لأطراف أصابع محبي التزيين."},"ICON-2673":{"nm":"قوس تثبيت زاوية الالتصاق","de":"قوس صغير يمسك بإحكام زاوية مرتفعة من الداخل. من مكان غير مرئي، يحافظ بصمت على استقامة الزاوية. خلف الأشياء المستقيمة ظاهريًا، يوجد عادة دعامة خفية كهذه."},"ICON-2674":{"nm":"أنبوب حماية أوراق الملصقات","de":"كي لا تتجعد أوراق الملصقات الثمينة أو تصبح رطبة، تنام داخل الأنبوب جنبًا إلى جنب مع الفيلم الواقي. إلى جانب فرحة الجمع، يرافقها دائمًا عناية بحمايتها برفق."},"ICON-2675":{"nm":"فرشاة تنظيف الختم الحبري","de":"تمرّ الفرشاة برفق على طول النسيج بين فتحات الختم المشبع بالحبر، مزيلةً اللون القديم. لمسة صغيرة ومجتهدة تُنظّف مسبقًا كي يخرج الانطباع التالي واضحًا."},"ICON-2676":{"nm":"جناح تثبيت الأوراق الشفافة","de":"كي لا تنزلق أوراق الملف من مكانها، تمسك الأجنحة الجانبين بإحكام. بفضل بقاء كل ورقة في مكانها، لا تضطرب أبدًا أصابع اليد وهي تقلّب الصفحات."},"ICON-2677":{"nm":"مغرفة تخزين قطع الزينة","de":"تُغرَف القطع الصغيرة المتناثرة للزينة دفعة واحدة بالمغرفة الصغيرة. حين يختفي عناء التقاطها واحدة تلو الأخرى بالأصابع، يصبح وقت صنع شيء ما بعناية أكثر متعة."},"ICON-2678":{"nm":"مشبك خيوط الفاصلة","de":"كي لا تسترخي الخيوط المتدلية من طرف الفاصلة، يربطها المشبك بإحكام. حتى الدليل الذي يعيدك إلى صفحة لم تنتهِ من قراءتها يريح البال حين يبقى مظهره أنيقًا."},"ICON-2679":{"nm":"مشبك غطاء قلم الزينة","de":"مشبك يضغط الغطاء بإحكام كي لا يجفّ طرف قلم الزينة. يمنع مأساة أن يتصلب قلم نُسي مفتوحًا، فيبقى اللون يتدفق دائمًا رطبًا كأول مرة."},"ICON-2680":{"nm":"طرف تركيب رأس المفك","de":"اترك مقبض المفك كما هو، وبدّل فقط الرأس في الطرف. صليبي أو مستقيم، بلا عناء. الذكاء في إنجاز أعمال متعددة بأداة واحدة محشور بإحكام في طرف هذا الرأس الصغير."},"ICON-2681":{"nm":"ملفّة زاوية ورق الصنفرة","de":"لفّ السطح الخشن بشكل دائري وامسكه، فتصبح راحة اليد أداة بحد ذاتها. مع كل دفعة على طول النسيج، تستدير الزاوية الخشنة، والنعومة الأخيرة تتعرّف عليها أطراف أصابع الإنسان دائمًا."},"ICON-2682":{"nm":"قمع فرز البراغي","de":"تمرّ البراغي المتناثرة عبر عنق ضيق وتتجمع متدحرجة في مكان واحد. صوت الأشياء الصغيرة التي كانت تتدحرج على المكتب وهي تجد مكانها، يمنح شعورًا وكأن حتى القلب المشوّش يُرتَّب بدوره."},"ICON-2683":{"nm":"خطّاف طرف شريط القياس","de":"الخطّاف عند طرف شريط القياس هو اليد الثانية لمن يعمل وحيدًا. علّقه على زاوية فلا يهتز الشريط، ويصبح اليد والقلب صادقين بقدر الطول الذي قِسته."},"ICON-2684":{"nm":"غطاء مقبض المفتاح الإنجليزي","de":"طبقة تُلبَس على المقبض المعدني البارد. لحظة تمسك به، يصلك دفء ناعم بدلًا من البرودة. الأداة تبقى بجانبك أطول حين تراعي أولًا من يمسك بها."},"ICON-2685":{"nm":"قلنسوة حماية طرف المخرز","de":"قلنسوة صغيرة تُلبَس على كل طرف حاد. راحة البال في تحسس الدرج دون أن تُوخَز، كلما كان الشيء أحدّ، كلما لُفّ بعناية أكبر، فلا يتأذى أحد."},"ICON-2686":{"nm":"نصل تقشير عزل الأسلاك","de":"قشّر العزل فقط برقة واترك السلك الداخلي سليمًا. في لحظة فكّ طبقة واحدة برفق وظهور خيط نحاسي لامع، تعرف النصل الجيدة أين تتوقف بالضبط."},"ICON-2687":{"nm":"ممسحة نافذة فقاعة الميزان","de":"فقط حين تتوقف الفقاعة الواحدة في المنتصف تمامًا يكون الاستواء حقيقيًا. مسح النافذة الصغيرة حتى تصفو يشبه التحضير الهادئ لتنظيم النَفَس قبل رسم خط."},"ICON-2688":{"nm":"كُمّ حماية إصبع الطرق","de":"كُمّ صغير يلفّ بإحكام حول الإصبع الممسك بالمسمار. اطرق دون خوف، يقول، فحتى لو أخطأت المطرقة سيكون كل شيء بخير، فهو جاهز بإحكام لتلقّي الضربة بدلًا من إصبعك."},"ICON-2689":{"nm":"بساط مانع انزلاق وعاء الطعام","de":"طبقة مطاطية تسند الوعاء كي لا ينزلق على الأرض. دون أن يهرب الوعاء أثناء الأكل بحماس، يبدأ هدوء الوجبة من مكان لا يتزعزع."},"ICON-2690":{"nm":"معلّقة مغرفة العلف","de":"تُعلَّق مغرفة تقديم العلف على الجدار لتجفّ برفق. نظام صغير يستقبل اليد من المكان نفسه في كل وجبة، أن يكون هناك فمٌ يجب الاعتناء به أمرٌ حنون كهذا."},"ICON-2691":{"nm":"طبق فيضان وعاء الماء","de":"يستقبل بهدوء الرشفة التي طفحت من حافة وعاء الماء. بفضل الطبق العريض الذي يحتضنها مسبقًا كي لا تبتل الأرضية، يبقى ما تحت القدمين جافًا ومريحًا دائمًا."},"ICON-2692":{"nm":"ملقط توزيع الوجبات الخفيفة","de":"ملقط يلتقط بدقة قطعة واحدة من الوجبة الخفيفة ويقدّمها. حتى أمام فم صغير ينتظر بأنفه الممدود، هناك طرف أصابع حنون لا يفقد تنظيمه في المشاركة."},"ICON-2693":{"nm":"مشبك لفّ فوهة كيس العلف","de":"مشبك صغير يلفّ فوهة كيس العلف المفتوح ويمسكه. بإغلاقة واحدة، تُمنَع الرطوبة، وتُصان حفنة الغد الصباحية المقرمشة سليمة تمامًا."},"ICON-2694":{"nm":"سدادة صنبور زجاجة الماء","de":"سدادة تنطبق تمامًا على صنبور زجاجة الماء. تقطر، ثم تتوقف القطرة المتساقطة ويجفّ المحيط. ما يُسَدّ جيدًا لا يتسرب، ويبقى صافيًا راكدًا لفترة طويلة."},"ICON-2695":{"nm":"كوب مدرّج لقياس العلف","de":"يُقاس كوب واحد بدقة وفق التدريج. لا كثير ولا قليل، في اليد التي تقدّر وجبة اليوم بإنصاف، يُحتوى يوم فرد صغير من العائلة بالمقدار المناسب."},"ICON-2696":{"nm":"حافة بساط الطعام المنسكب","de":"حافة تمنع الطعام المنسكب من تجاوز البساط. حافة واحدة مرتفعة قليلًا تجمع بإحكام الفتات الذي كاد يتناثر."},"ICON-2697":{"nm":"حلقة فصل الأوعية المتراصّة","de":"حلقة صغيرة تفصل برفق وعاءين متداخلين. اليد التي كانت تكافح وهما ملتصقان بإحكام تصبح خفيفة. الفصل الجيد أيضًا، إذا تأملت، رعاية حانية."},"ICON-2698":{"nm":"قمع تجميع كرات الفناء","de":"قمع يجمع في مكان واحد الكرات التي تدحرجت عبر الفناء. في مساء بعد جولة لعب صاخبة، تخطر ببال المرء تلقائيًا يد تجمع ما تناثر هنا وهناك."},"ICON-2699":{"nm":"قبعة عمود السياج","de":"تُلبَس قبعة مستديرة على كل عمود من أعمدة السياج. كي لا تتشقق الأطراف بفعل الريح والمطر، تسلّل في الفناء بأكمله قلبٌ يعتني ويغطّي حتى أصغر شيء."},"ICON-2700":{"nm":"خطّاف طيّ نفق اللعب","de":"خطّاف لطيّ نفق اللعب الذي استُمتِع به كثيرًا وتعليقه بعناية. إذا طُوي يوم ملطّخ بالتراب وعُلّق بإتقان، فإن اللعب المرتَّب جيدًا يَعِد دائمًا بغدٍ آخر."},"ICON-2701":{"nm":"وسادة مقبض حبل السحب","de":"وسادة تلف مقبض حبل السحب بنعومة. مهما شددته بقوة، لا تُسلَخ راحة يدك أبدًا. وكلما طال إمساكك به ارتاحت يدك أكثر، بفضل لطف صغير من أحدهم."},"ICON-2702":{"nm":"مشبك قماش الظل في الفناء","de":"مشبك يُثبّت بإحكام قماش الظل الممدود في الفناء. حتى برودة منتصف النهار تحتاج من يُمسك بها لتبقى. تحت الظل الذي يحافظ عليه المشبك مشدودًا، يمتد بعد ظهر كسول ويستريح طويلًا."},"ICON-2703":{"nm":"غطاء نصل مجرفة الحفر","de":"غطاء تُلبسه بهدوء نصل مجرفة الحفر. دعه يستريح بعد يوم عمل شاق، فيبقى غير كليل، جاهزًا ليلتقي بتربة الربيع القادم من جديد."},"ICON-2704":{"nm":"منحدر تدحرج الكرة","de":"منحدر واحد تتدحرج عليه الكرة بمرح إلى الأسفل. على طول الميل الخفيف، تندفع الكرة بسعادة. ميل صغير واحد يصنع متعة يوم كامل."},"ICON-2705":{"nm":"حلقة مزلاج بوابة السياج","de":"حلقة مزلاج تُقفل بوابة السياج. بصوتها الصغير عند الإغلاق، يطمئن القلب. بوابة واحدة مغلقة بإحكام تحمي فناءً صغيرًا كعالم قائم بذاته."},"ICON-2706":{"nm":"خيط جرس اللعب","de":"هزّ برفق الخيط المعلق به الجرس فينتشر صوت صافٍ. رنين، رنين—تستيقظ غرفة كانت هادئة، وعند رنة صغيرة واحدة يُرهف القلب كله سمعه."},"ICON-2707":{"nm":"طبق تصريف ماء أصيص الزهور","de":"طبق يلتقط بهدوء الماء المتسرب من أسفل أصيص الزهور. يحتفظ بالفائض حتى تبقى حافة النافذة جافة. حتى الرعاية حين تفيض، تحتاج مكانًا تُجمع فيه."},"ICON-2708":{"nm":"مجرفة زراعة الشتلات","de":"مجرفة صغيرة لنقل الشتلات الغضة إلى التربة وغرسها برفق. تحت أطراف أصابع تُثبّت كل برعم بعناية، يرفع ربيع أخضر رأسه حتى في حديقة بحجم راحة اليد."},"ICON-2709":{"nm":"دبوس علامة صفوف الحديقة","de":"دبوس علامة تكتب عليه وتغرسه في كل صف لتدوين ما زُرع فيه. على تربة لم يظهر فيها نبت بعد، تتذكر بطاقة اسم صغيرة بهدوء ما سينمو."},"ICON-2710":{"nm":"شبكة فوهة إبريق الري","de":"شبكة رقيقة تُركّب على فوهة إبريق الري. الماء الذي كان ينهمر في تيار واحد يتناثر إلى خيوط عديدة كرذاذ ناعم. تدفق لطيف وحده يحمي الأوراق الغضة من الأذى."},"ICON-2711":{"nm":"مشبك تثبيت الدعامة","de":"مشبك يربط برفق ساقًا مهتزة بدعامتها. مجرد سند مُستعار حتى يستطيع الشيء الغض الوقوف مستقيمًا—فالنمو يحتاج إلى سند كهذا."},"ICON-2712":{"nm":"مشبك إغلاق كيس البذور","de":"مشبك يُطبق بإحكام على كيس البذور المتبقية ليغلقه. إذا أُغلق جيدًا، لا تتسرب حبة واحدة. وعد صغير بربيع قادم يسكن في هذه القبضة الواحدة."},"ICON-2713":{"nm":"مغرفة قياس التربة والسماد","de":"مغرفة صغيرة لأخذ الكمية المناسبة من التربة والسماد. لا زيادة ولا نقصان، ملعقة واحدة مضبوطة بدقة. فوق الكمية المحسوبة تمامًا، تؤدي التربة أخيرًا عملها."},"ICON-2714":{"nm":"خطاف تعليق أصيص الزهور","de":"خطاف يُعلّق أصيص الزهور برشاقة في الهواء. الخُضرة المرفوعة تقترب شبرًا من الشمس والنسيم. حديقة صغيرة تطفو قرب النافذة."},"ICON-2715":{"nm":"شبكة غطاء حماية البراعم","de":"شبكة غطاء تحمي بلطف البراعم الغضة حديثة النمو. حتى تتحمل الأوراق ما تزال طرية أول برد وأشعة حارقة، أضعف شيء هو أول من يُرعى."},"ICON-2716":{"nm":"معلاق شعر مشط العناية","de":"مكان تنفض فيه الشعر المتساقط عن المشط وتُعلّقه مرتبًا. المشط النظيف الفارغ ينتظر اللمسة التالية. الأناقة تبدأ دائمًا من عادة صغيرة، الاعتناء بالأدوات."},"ICON-2717":{"nm":"حلقة مانعة للانزلاق لحوض غسل القدمين","de":"حلقة تُثبّت حوض غسل القدمين كي لا ينزلق. تحت أقدام صغيرة ترفس الماء، لا يتحرك الحوض، فلا تهتز اليد الغاسلة ولا القلب المغسول."},"ICON-2718":{"nm":"خطاف تعليق حبل النزهة","de":"خطاف واحد يُعلّق عليه حبل النزهة قرب الباب. في مكانه المعتاد بجانب الباب، ينتظر دائمًا الاستعداد للانطلاق. لحظة إنزال الحبل، تنطلق معه خطوة متحمسة."},"ICON-2719":{"nm":"غطاء حماية تقليم الأظافر","de":"غطاء واقٍ يحمي اللحم الغض أثناء تقليم الأظافر. فقط بوجود حد آمن يرسم إلى هنا بالضبط، تبقى اليد الممسكة بالمقص هادئة دون ارتجاف."},"ICON-2720":{"nm":"شريط قياس حرارة ماء الاستحمام","de":"شريط يطفو في ماء الاستحمام ليخبر بدرجة حرارته. العادة القديمة في غمس ظهر اليد لتقدير الدفء المناسب، تطفو الآن مترجمة بوضوح إلى شريط لون واحد."},"ICON-2721":{"nm":"بكرة لاصقة لإزالة الشعر","de":"شعرة بيضاء واحدة على ثوب أسود، تبدو الأكبر قبل الصعود إلى المسرح مباشرة. مع صوت الدحرجة، تنتقل بقايا يوم كامل بترتيب إلى الورقة اللاصقة. النظافة تكتمل هكذا، شريطًا تلو شريط، بقدر ما تُزيله."},"ICON-2722":{"nm":"ملقط كيس فضلات النزهة","de":"في نهاية النزهة، تأتي لحظة حانية من الانحناء. أمسك الكيس بطرف الملقط فتبقى اليدان نظيفتين والقلب خفيفًا. المشي معًا يحمل لباقة صغيرة في تنظيف ما بعده، وهذا الملقط يعرفها أولًا."},"ICON-2723":{"nm":"حافة سجادة مسح القدمين","de":"حافة السجادة أمام الباب هي أول ترحيب تلمسه القدم. توقف طرف قدم مبللة هنا مرة واحدة يبقي الأرضية الداخلية جافة. أدنى مكان على الإطلاق، يمسح ويستقبل كل داخل بصمت."},"ICON-2724":{"nm":"خيط عقدة جرس العناية","de":"حتى تعليق جرس واحد له ترتيبه. لُفّ الخيط مرتين ومرّره مرة واحدة، فيتبع صوت صافٍ كل خطوة. الاعتناء بالمظهر، في النهاية، هو القلب الذي لا يهمل هذه اللمسة الأخيرة الصغيرة."},"ICON-2725":{"nm":"كيس تنقيط المظلة القابلة للطي","de":"في ردهة بعد توقف المطر، تتناثر قطرات من طرف مظلة مطوية على الأرض. كيس واحد يلتقطها بهدوء فلا تنزلق قدم أحد. اللطف عادة يبقى قريبًا هكذا، دون صوت."},"ICON-2726":{"nm":"مشبك حزام الحقيبة","de":"حقيبة معلقة على كرسي تنزلق باستمرار إلى الأسفل. أمسكها مرة بمشبك الحزام فتصبح اليدان حرتين دون قلق من سقوطها. راحة الخروج تبدأ عندما يمكنك نسيان أمتعتك للحظة."},"ICON-2727":{"nm":"كيس قماشي لدفاية اليد","de":"في زقاق تهب فيه ريح باردة، يحمل كيس قماشي داخل الجيب الدفء بهدوء إلى راحة اليد. طبقة ناعمة تلف الشيء الساخن وتدفئه بالقدر المناسب. حنان الشتاء يُنقل دائمًا عبر قطعة قماش واحدة."},"ICON-2728":{"nm":"حامل مرآة الجيب القابلة للطي","de":"افتحها فتميل مرآة صغيرة لتجد زاويتها. لتتمكن من مواجهة وجهك دون حملها، يقف الحامل نيابة عنك. حتى في تلك اللحظة القصيرة من تعديل مظهرك، يرافقك ممثل مساعد يُعتمد عليه."},"ICON-2729":{"nm":"غطاء علبة المناديل المبللة للخروج","de":"الورقة الأولى من المناديل المبللة كانت دائمًا في طور الجفاف. أغلق الغطاء بنقرة فتبقى الرطوبة حتى آخر ورقة. الحفاظ عليها صالحة للاستخدام حتى النهاية، سر الحياة المنزلية الطويلة يكمن في أمور بسيطة كهذه."},"ICON-2730":{"nm":"فاصل عملات المحفظة","de":"حين تتناثر العملات بين الأوراق النقدية، تزدحم صالة الدفع دائمًا. فاصل واحد يجمع الأشياء المستديرة في جانب فلا تتوه أطراف الأصابع بعد الآن. الترتيب هو منح كل شيء مكانًا واسمًا."},"ICON-2731":{"nm":"علبة طي الكمامة للخروج","de":"مطوية بداخلها، لا تتجعد الكمامة حتى داخل الحقيبة. علبة تحتضن بنظافة قطعة خلعتها للحظة. عادة حانية واحدة، حفظها بعناية للاستخدام لاحقًا، تكمن هنا."},"ICON-2732":{"nm":"غطاء أسنان مشط الجيب","de":"أسنان المشط داخل الحقيبة كانت غالبًا تخدش الأمتعة الأخرى. ضع غطاء الأسنان فيصبح المشط آمنًا والأشياء المرافقة له سالمة أيضًا. من اعتنى بأشيائه يعرف أن طبقة حماية صغيرة واحدة تحمي الطرفين معًا."},"ICON-2733":{"nm":"مشبك تقسيم الدرج","de":"كلما فُتح الدرج، تناثرت محتوياته المختلطة كأنها تنهيدة. قسّمه إلى أقسام بمشبك واحد فتجد الأشياء الصغيرة أخيرًا منطقتها الخاصة. درج مرتب يغيّر بهدوء مزاج كل صباح."},"ICON-2734":{"nm":"حامل عرض العملات","de":"أقم عملة قديمة واحدة منتصبة فتصبح بذاتها معرضًا صغيرًا. الحامل يُسندها بزاوية ليُظهر نقش الوجه بوضوح. رفع زمن اهترأ بلمسات الأيدي إلى مستوى العين، هنا تتعمق متعة الجمع."},"ICON-2735":{"nm":"حلقة لف سلك سماعات الأذن","de":"كانت هناك صباحات ضاع نصفها في فك تشابك سلك سماعات الأذن. لُفّه بترتيب حول حلقة اللف، وفي المرة القادمة يخرج ناعمًا. ترتيب صغير يصبح هدية هادئة تُهدى إلى نفسك في الغد."},"ICON-2736":{"nm":"خطاف حائطي لسلك الشحن","de":"سلك الشحن المتدلي على الأرض كان يُداس باستمرار. ألصق خطافًا واحدًا على الحائط لتعليقه، فيصبح المكتب أكثر رحابة بكثير. ترويض الفوضى ليس أمرًا عظيمًا، بل مجرد مكان صغير بحجم مسمار واحد."},"ICON-2737":{"nm":"حامل جهاز التحكم عن بُعد","de":"جهاز التحكم الذي كان يختفي دائمًا في شق الأريكة، وجد أخيرًا بيتًا يعود إليه. أقمه في الحامل فلا داعي للبحث عنه، ولا للجلوس عليه. أن يكون لديك مكانك الخاص، يصبح راحة صغيرة حتى لشيء."},"ICON-2738":{"nm":"مشبك تعليق ذراع النظارة","de":"النظارة الموضوعة جانبًا كانت دائمًا تنزلق بهدوء إلى مكان ما. علّق ذراعها برفق على المشبك فلا تلامس العدسات الأرضية أبدًا. الرغبة في مقابلة الغد دون خدش تسكن في هذا المعلاق الصغير."},"ICON-2739":{"nm":"مشبك تصنيف حلقة المفاتيح","de":"كلما ثقلت حزمة المفاتيح، ازداد غموض أي مفتاح لأي باب. اربطها بمشبك تصنيف فتعرف أطراف أصابعك وحدها زوجها الصحيح. مرشد صامت يمنح الأبواب التي تُفتح وتُغلق كل يوم نظامًا بهدوء."},"ICON-2740":{"nm":"مشبك حامل أوراق الملاحظات","de":"الملاحظة المدونة كانت غالبًا تنقلب على المكتب. حين يُمسك المشبك الورقة منتصبة، تنظر الحروف مباشرة في عينيك. طريقة لجعل السطر الذي يجب ألا تنساه يعيش في مكان مرئي دائمًا."},"ICON-2741":{"nm":"حامل رأس القلم","de":"كم مرة انحنى ظهرك لالتقاط قلم تدحرج بعيدًا؟ اغرس طرفه في الحامل منتصبًا فتقصر المسافة إلى السطر التالي شبرًا واحدًا. محطة انتظار صغيرة، مستيقظة دائمًا بجانب من يكتب."},"ICON-2742":{"nm":"قاعدة قلب الساعة الرملية","de":"حين تنفد الساعة الرملية تمامًا، لا بد لأحد أن يقلبها كي تحيا من جديد. تلتقط القاعدة تلك اللحظة لآخر حبة وتديرها بسلاسة منتصبة مجددًا. اللمسة التي تعيد الزمن إلى بدايته تسكن هنا، فوق قطعة خشب صغيرة."},"ICON-2743":{"nm":"بطاطا مشوية بالزبدة","de":"تذوب الزبدة ببطء فوق بطاطا مشوية بقشرها. حين تتسرب حبيباتها الذهبية مع البخار، يحتضن اللب الطري النكهة الغنية بهدوء. تلك اللحظة بالذات التي يبلغ فيها خضار جذري يفوح برائحة التراب أعلى درجات الدفء."},"ICON-2744":{"nm":"ذرة مشوية بالزبدة","de":"الحبات الصفراء المصطفة تُصدر صوت طقطقة فوق الشواية. قطعة زبدة تنزلق فوقها فتفوح رائحة حلوة فجأة. حلاوة حقل صيفي تُنقل مباشرة إلى قضمة واحدة."},"ICON-2745":{"nm":"وافل","de":"في كل مربع صغير من الشبكة، ينتظر الشراب بهدوء أن يتجمع. مقرمش من الخارج، طري من الداخل، قضمة واحدة يتسرب منها بخار دافئ. المربعات الصغيرة أشبه بوعاء يوزّع لُقيمات صغيرة من السعادة."},"ICON-2746":{"nm":"بان كيك","de":"أتذكر رائحة العجين وهو ينتفخ ذهبيًا فوق المقلاة. فوق أقراص مكدسة طبقة فوق طبقة، تنهار الزبدة وتذوب برفق. طبق ناعم لا يُسمح به إلا في صباح هادئ."},"ICON-2747":{"nm":"شوكولاتة","de":"أمسك قطعة في فمك فتذوب ببطء عند ملامسة حرارة الجسد. الحلاوة المنتشرة في نهاية المرارة تُرخي توتر القلب قليلًا. في يوم مُتعب، قطعة بنية صغيرة من العزاء تُخرجها من الجيب."},"ICON-2748":{"nm":"كيك الفراولة","de":"فراولة حمراء تجلس فوق كريمة بيضاء مخفوقة، تُبشّر بالربيع أولًا. حين تشق الشوكة المقطع الطري، تتفتح رائحة حامضة برفق. في يوم فيه ما يستحق الاحتفال، بطلة حانية توضع في وسط المائدة."},"ICON-2749":{"nm":"تشيز كيك","de":"قطعة ثقيلة تنهار بغنى فوق اللسان. النكهة المالحة الأخيرة تمسك بيد الحلاوة وتستدعي قضمة أخرى تلو الأخرى. حلوى يتذوقها بهدوء محبو الكثافة الدسمة."},"ICON-2750":{"nm":"كوكيز الموز","de":"رائحة الموز المهروس تنضج ذهبية داخل الفرن. قضمة واحدة تنشر حلاوة طرية في الفم كله. لحظة تحوّل دافئة، حين تُولد فاكهة ناضجة جيدًا من جديد على هيئة كوكيز."},"ICON-2751":{"nm":"كوكيز رقائق الشوكولاتة","de":"حبات الشوكولاتة داخل العجين تذوب بغنى أثناء الخبز. اكسرها وهي دافئة فيلطخ لون بني عميق أطراف أصابعك. مع كوب من الحليب، قطعة تجعل بعد الظهر أكثر لطفًا."},"ICON-2752":{"nm":"كوكيز حبيبات الكاكاو","de":"قطع كاكاو مطحونة ناعمًا تُقرمش بين العجين. مرارة عميقة غير محلاة تُهدئ ذوق الكبار بهدوء. كوكيز جادة قليلًا، تحمل عبق الكاكاو الأصيل كما كان قبل أي معالجة."},"ICON-2753":{"nm":"توست بالجبن","de":"يتمدد الجبن كخيط طويل فوق خبز محمص ذهبي. قرمشة السطح ونكهة الداخل الغنية تتلاقيان في قضمة واحدة. أبسط وجبة وأكثرها حنانًا، تملأ صباحًا متأخرًا بالشبع والدفء."},"ICON-2754":{"nm":"ساندويتش","de":"بين شريحتي خبز، تتكدس عناية يوم كامل طبقة فوق طبقة. قضمة واحدة تجعل كل النكهات المتراصة تُلقي التحية معًا. مائدة صغيرة على راحة اليد، جاهزة لتُحمل إلى أي مكان."},"ICON-2755":{"nm":"فرنش توست","de":"خبز منقوع جيدًا في خليط البيض ينضج ذهبيًا فوق المقلاة. الحواف المنتفخة برائحة الزبدة تقرمش أولًا. أضف خطًا من الشراب فيصبح خبز عادي رفاهية يوم عطلة."},"ICON-2756":{"nm":"رامن الفطر","de":"رائحة الفطر العميقة تتصاعد مع البخار فوق المرق الساخن. ارفع قبعة فطر طرية فتنتشر حلاوة ترابية في الفم. وعاء مميز قليلًا، يملأ البطن بالعبق قبل النودلز."},"ICON-2757":{"nm":"رامن مقلي","de":"على نودلز مقلية بلا مرق، تلتف توابل حارة بلمعان براق. ارفعها بعيدان الأكل فتنتشر رائحة دخانية شهية بين البخار. حين تشتاق لوجبة سريعة وغنية، أوثق صديق."},"ICON-2758":{"nm":"رامن الجبن","de":"ضع شريحة جبن فوق نودلز ساخنة فتنهار وتذوب ببطء فيها. يلتقي المرق الحار بالغنى الطري فتستدير الحواف. وعاء يناسب تمامًا ليلة تريد فيها تهدئة النكهة الحادة قليلًا."},"ICON-2759":{"nm":"رامن الكاري","de":"رائحة كاري غنية تلتف حول النودلز وتُصعد بخارًا أصفر. رشفة واحدة تُدفئ الداخل بحرارة لذيذة. نودلز بتنويع ممتع، يضيف عبقًا غريبًا قليلًا إلى مرق مألوف."},"ICON-2760":{"nm":"رامن المأكولات البحرية","de":"فوق مرق فائح برائحة البحر، يطفو الجمبري والمحار ممتلئين. نكهة عميقة ومنعشة تتسرب بين خيوط النودلز. سحر صغير يحمل عبق الساحل إلى وعاء واحد دون سفر بعيد."},"ICON-2761":{"nm":"كيمباب الفجل المخلل","de":"حين يجلس الفجل المخلل الأصفر في المنتصف وحبات الأرز محيطة به مستديرة، تربطها ورقة عشب بحري واحدة بحنان في لفافة واحدة. في فجر يوم النزهة، ألذّ وجبة صادقة تُولد فوق لوح التقطيع."},"ICON-2762":{"nm":"كيمباب التونة","de":"لحظة تتسرب ملعقة من تونة ممزوجة بالمايونيز بين حبات الأرز، تصبح وجبة دافئة بما يكفي حتى تحت أضواء متجر مفتوح ليلًا. العزاء الذي تلجأ إليه الأيدي المشغولة أكثر من غيره."},"ICON-2763":{"nm":"سلطة فواكه","de":"ألوان جُمعت من موسمها تلتقي للمرة الأولى في وعاء واحد. كيف يتآلف الأحمر والأخضر والأصفر دون خصام، لا تُظهره الفاكهة إلا بعد أن تُقطّع وتُجمع معًا."},"ICON-2764":{"nm":"سلطة الدجاج","de":"صدر دجاج مشوي بسيط يوضع بترتيب فوق خضار ورقية خضراء. على مائدة من يستعد لمسرح الغد، يوجد دائمًا طبق أنيق كهذا."},"ICON-2765":{"nm":"سلطة الطماطم والخيار","de":"طماطم ناضجة وخيار مقرمش تُتبّلان بنكهة حامضة منعشة. في نهار كثيف بصوت الزيز، قضمة واحدة تجعل الصيف يبرد إيقاعًا بداخلها."},"ICON-2766":{"nm":"سلطة الخس","de":"اغسل أوراقًا قُطفت للتو من الحديقة بماء بارد فتستيقظ أطراف أصابعك منعشة. لحظة يحتل فيها أكثر خضار شيوعًا أكثر الأماكن اخضرارًا ونضارة على المائدة."},"ICON-2767":{"nm":"سلطة الذرة","de":"كلما انفجرت حبة حلوة برفق، ينفتح أمام عينيك حقل صيف مغمور بأشعة الشمس. حتى في وعاء السلطة، لا تنسى الذرة الصفراء شمسها أبدًا."},"ICON-2768":{"nm":"كول سلو","de":"حين يمتص الملفوف المبشور صلصة حلوة حامضة، تلين قرمشته قليلًا برفق. فضيلة طبق جانبي: مهما جاور من طبق رئيسي، لا ينافس على الأضواء ويؤدي دوره."},"ICON-2769":{"nm":"سلطة الجمبري بالليمون الحامض","de":"اعصر قليلًا من الليمون الحامض فتستيقظ حلاوة الجمبري أكثر وضوحًا. قطرة حامضة واحدة تبعث الحياة في الطبق كله، لمسة أخيرة صغيرة لكنها حاسمة."},"ICON-2770":{"nm":"هامبورغ ستيك","de":"قرص لحم سميك يُطهى ذهبيًا فوق صفيحة حديدية ساخنة. العصارة التي تتسرب لحظة ملامسة السكين له، وجبة الأطول محبوبة بين الطبخ المنزلي والمطبخ الغربي."},"ICON-2771":{"nm":"بيتزا","de":"تلك القضمة التي يتمدد فيها الجبن طويلًا، تُتناقل من يد إلى يد بين جالسين كُثر. حين تُقسّم قطعة مستديرة معًا إلى شرائح، يصبح اللقاء لقاءً حقيقيًا أخيرًا."},"ICON-2772":{"nm":"باستا الفطر بالكريمة","de":"رائحة الفطر الترابية العميقة ونعومة الكريمة تحتضنان كل خيط نودلز. في مساء يهطل فيه المطر بهدوء، يتسرب العبق الغني ببطء حتى قاع الطبق."},"ICON-2773":{"nm":"باستا الجمبري","de":"جمبري ممتلئ يُقلى قليلًا في زيت الزيتون ويُمزج مع النودلز. حين تلتقي ملوحة البحر بعذوبة النودلز البسيطة، يصبح مساء عادي مميزًا قليلًا."},"ICON-2774":{"nm":"باستا بالزيت","de":"ثوم وزيت ونودلز، ثلاثة أشياء فقط. هناك نكهة تزداد وضوحًا كلما نقصت المكونات، وباستا آليو أوليو تُثبت ذلك بهدوء دون أي زيادة."},"ICON-2775":{"nm":"باستا المحار","de":"المرق الذي يُطلقه المحار وهو يفتح صدفته يتسرب عميقًا في كل خيط. عبق رشفة من النبيذ الأبيض يبقى طويلًا فوق الطبق، كيوم ربيعي لا يذبل."},"ICON-2776":{"nm":"باستا بالكريمة","de":"حين تحتضن الكريمة الغنية النودلز بهدوء، تدفأ زاوية من القلب منذ القضمة الأولى. عزاء تمنحه النعومة، يزداد عمقًا في يوم عاصف."},"ICON-2777":{"nm":"باستا الطماطم","de":"صلصة طماطم طُهيت طويلًا تنتشر حمراء فوق النودلز. حين تتقلص الحلاوة والحموضة ببطء وتجدان توازنهما أخيرًا، يصبح أبسط طبق أكثرها اعتمادًا."},"ICON-2778":{"nm":"أومورايس","de":"بيض طري يغطي الأرز الدافئ كبطانية، يُدسّ برفق. اكتب حتى حرفًا واحدًا من اسم بالكاتشب، فتصبح مائدة ذلك اليوم رسالة صغيرة أهداها أحدهم."},"ICON-2779":{"nm":"سلمون مشوي","de":"يُشوى ببطء أمام النار حتى تصبح القشرة مقرمشة. خيط بخار يتصاعد بينما يتفتت اللحم الوردي على طول ألياف، الصبر يُكافأ دائمًا بصدق مع السلمون."},"ICON-2780":{"nm":"بروسكيتا","de":"كوّم طماطم مفرومة وريحانًا بسخاء فوق خبز محمص مقرمش. تلك الخفة في التقاطها بالأصابع وأخذ قضمة منها تفتح بحنان أول تحية في أي لقاء."},"ICON-2781":{"nm":"سموذي المانجو","de":"اخلط مانجو ناضجة ناعمة وامزجها باردة مع الثلج. حين تتكاثف قطرات الماء فوق الكوب الأصفر، ينسكب بعد ظهر صيفي كسول حتى طرف الماصة."},"ICON-2782":{"nm":"ليموناضة","de":"أضف عصير ليمون طازجًا وسكرًا وماءً باردًا، ورجّه في الكوب. حين تنزلق الحموضة الصفراء منعشة في حلقك، يستسلم حتى الحر الشديد للحظة."},"ICON-2783":{"nm":"حليب الفراولة","de":"امزج فراولة مهروسة بالحليب فتترسب سحابة وردية ببطء داخل الكوب. إثارة أطراف الأصابع وهي تفتح باب الثلاجة في الطفولة، تسكن كاملة في كوب واحد."},"ICON-2784":{"nm":"حليب الموز","de":"مشروب أصبح بشكل جرته المستدير وحده ذكرى لحقبة كاملة. الذكرى الصفراء لغرس ماصة وأنت جالس على مصطبة الحمام العام، تحيا بحنان مع كل رشفة."},"ICON-2785":{"nm":"حليب التوت الأزرق","de":"افرك حبات أرجوانية وأضفها فيصطبغ الحليب الأبيض بلون سماوي رقيق. تلك الحفنة الصغيرة من الفاكهة تُحوّل كوبًا كاملًا إلى لون جديد تمامًا."},"ICON-2786":{"nm":"عصير فواكه","de":"اعصر عدة فواكه معًا فتصبح نكهة لا يمكن تسميتها باسم واحد. جوقة صغيرة من الحلاوات، تختلط وتنتفخ أغنى وأغنى."},"ICON-2787":{"nm":"كاكاو","de":"بجانب نافذة تتساقط عليها الثلوج، احتضن كوبًا دافئًا بهدوء بكلتا يديك. كوب بني يتصاعد منه البخار يُدفئك ببطء، من أطراف الأصابع إلى القلب."},"ICON-2788":{"nm":"قهوة","de":"هذا الكوب هو دائمًا من يُضيء أنوار غرفة التمرين عند الفجر. حين يدفع عبقها المر النعاس بهدوء جانبًا، يبدأ مسرح يوم آخر هكذا، بهدوء."},"ICON-2789":{"nm":"سوشي السلمون","de":"اضغط الأرز في يدك، مقدرًا ذلك الخط الدقيق بين الصلابة والنعومة. لحظة ترقد فيها شريحة سلمون رقيقة برفق فوقه، تصبح قضمة واحدة اكتمال عناية صغيرة."},"ICON-2790":{"nm":"عصيدة اليقطين الحلو","de":"اسلق اليقطين الأصفر جيدًا واهرسه ناعمًا. مع كل ملعقة تُغرف، تذوب شمس الخريف دافئة في الفم. العصيدة التي تخطر بالبال أولًا عند المرض."},"ICON-2791":{"nm":"كاري السمك","de":"لحم سمك مطهو قليلًا بالتوابل يتفتت طريًا داخل الكاري. أضف نكهة البحر إلى وعاء مألوف، فينطلق مساء عادي في رحلة أبعد بشبر."},"ICON-2792":{"nm":"جمبري مقلي","de":"اللحظة القصيرة من الإمساك بالذيل وتغطيته بالعجين وإسقاطه في الزيت الغالي هي مربط الفرس. جمبري يرتدي ثوبًا ذهبيًا، يلمع أكثر إذا أُكل قبل أن تبرد قرمشته."},"ICON-2793":{"nm":"كاليماري مقلي","de":"حلقات مستديرة تنتفخ ممتلئة داخل الزيت الساخن. تلك القضمة التي تلف فيها القرمشة الليونة، تليق أكثر تحت أضواء صفراء لعربة طعام في الشارع."},"ICON-2794":{"nm":"دجاج مشوي","de":"ادهن التتبيلة واشوِ ببطء أمام النار حتى يلمع الجلد بلمعان. طبق تتحدد نكهته بضبط النار وحدها، أبسط طبق، فيصبح بذلك الأكثر صدقًا."},"ICON-2795":{"nm":"لحم خنزير مقلي بالكيمتشي","de":"اقلِ كيمتشي ناضجًا جيدًا مع لحم الخنزير معًا فتنضج الحموضة إلى حلاوة. طبق يستدعي وعاء أرز أبيض من تلقاء نفسه، الرفيق الأكثر اعتمادًا على مائدة كورية."},"ICON-2796":{"nm":"لحم خنزير مقلي","de":"اقلِ بسرعة على نار قوية حتى يُطهى السطح مقرمشًا. حين تملأ رائحة الزيت الشهية المطبخ، يُحسم قائمة عشاء الليلة دون سؤال آخر."},"ICON-2797":{"nm":"لحم بقري مقلي بالفطر","de":"اقلِ فطرًا عطرًا مع لحم بقري معًا فتزداد نكهة كل منهما عمقًا. وجبة خريفية أنيقة، يتصافح فيها التراب والحقل بهدوء فوق طبق واحد."},"ICON-2798":{"nm":"تشيز داك غالبي","de":"أذب جبنًا بسخاء فوق داك غالبي الحار ومدّه طويلًا. اجلس كثيرون حول صفيحة حديدية ساخنة في الوسط، فتذوب حتى الحرارة اللاذعة في الضحك."},"ICON-2799":{"nm":"يخنة الكيمتشي","de":"كلما قدُم الكيمتشي أكثر، منح مرقًا أعمق وأغنى. اجلسا وجهًا لوجه أمام قدر فخاري يغلي بهدوء، فتُدفأ كلمة \"العائلة\" من جديد."},"ICON-2800":{"nm":"يخنة الدوينجانغ","de":"أذب معجون الصويا الشهي، وأضف التوفو والكوسا، واتركه يغلي ببطء وثبات. ذلك الصوت الذي يغلي حتى النهاية في القدر الفخاري هو أوضح إشارة على أنك عدت إلى البيت."},"ICON-2801":{"nm":"شوربة لحم البقر بالفجل","de":"نصف نهار من الانتظار الهادئ أمام نار هادئة حتى يصبح الفجل شفافاً. حين تلامس ملعقة من المرق الصافي الشفتين، تعود إلى الذهن مائدة تلك الأيام البسيطة الخالية من الزخرفة. فالطعم الهادئ هو الأبقى على الدوام."},"ICON-2802":{"nm":"شوربة المحار","de":"في اللحظة التي يفتح فيها المحار صدفته، يتعمّق الربيع داخل القدر. حين تتصاعد مع البخار حفنة من رائحة البحر، تتراءى مطابخ فجرٍ في قرية ساحلية. وفي كل صدفة مفتوحة يتجمّع رشيقٌ من ملوحة البحر."},"ICON-2803":{"nm":"البطاطا الحلوة المسكّرة","de":"في طريق العودة من المدرسة، كتلٌ صفراء توضع في كوب ورقي وتُقبض عليها كأنها كيس تدفئة لليدين. عندما تُعضّ القشرة الذهبية يتصاعد البخار فجأة من الداخل. القشرة الحلوة المطهوة والداخل الساخن — طعم الشتاء في أرقّ حالاته."},"ICON-2804":{"nm":"الباذنجان المقلي","de":"اللحظة التي يلتقي فيها اللون الأرجواني بالزيت فيذوب ببطء. الخضار الذي يُلام على ليونته هو في الحقيقة أفضل من يحتضن التوابل. عضّة واحدة تنقل إليك أولاً لمسة يد الطاهي الناعمة المتشرّبة."},"ICON-2805":{"nm":"بطاطا مطهوة بصلصة الصويا","de":"مساء كانت فيه رائحة حلوة تفوح في أنحاء المطبخ كله بينما يتبخّر صلصة الصويا. يدٌ كانت تملأ حجيرة صندوق الغداء بقطعة بنية لامعة واحدة. عناية لا تُكتب في أي وصفة تتغلغل في كل قطعة صغيرة."},"ICON-2806":{"nm":"أوراق البريلا المخللة","de":"عمل تخليل رائحة الصيف كاملة ونقلها حتى مائدة الشتاء. انزع ورقة واحدة وضعها على الأرز، فيتفتّح الفصل الماضي من جديد في الفم. بين الأوراق المتراصة طبقةً فوق طبقة ينام شمس ذلك العام."},"ICON-2807":{"nm":"كيمتشي الملفوف الطازج","de":"يدان لم تستطيعا الانتظار حتى موسم الكيمتشي الكبير فعجنتا الملفوف في اليوم نفسه. نضارة لا يمكن الاستمتاع بها إلا في اللحظة التي بدأت فيها التوابل تتغلغل في الأوراق المقرمشة. تلك الخضرة النيّئة قبل التخمّر رفاهية ليوم واحد فقط."},"ICON-2808":{"nm":"الفطر المقلي","de":"أشياء نبتت بهدوء في ظل الغابة بعد توقف المطر. وبينما تُقلى بزيت البريلا، تتحول رائحة التراب إلى نكهة شهية. فكلما نما الشيء بصمت في الظلام، ازدادت رائحته عمقاً وغنى."},"ICON-2809":{"nm":"سبانخ متبّلة","de":"خضار ورقي يتقلّص إلى حفنة صغيرة عند السلق، تُعجن بأطراف الأصابع. ذلك الحجم المتواضع هو فضيلة خضار الربيع. طبق أخضر واحد يُدخل إلى المائدة شبراً إضافياً من شمس الربيع."},"ICON-2810":{"nm":"الأعشاب البحرية المتبّلة","de":"خيوط زلقة انتُشلت للتو من البحر تمتزج مع صلصة حامضة حارة. طقطقة مالحة تنفجر مع كل مضغة. طبق ينقل مباشرة إلى الوعاء ملمس الموج المتموّج."},"ICON-2811":{"nm":"الكوسا المقلية","de":"هناك خضروات تزداد حلاوة كلما تقدّمت في العمر. قطّعها رقيقة وقلّبها مع الروبيان المملّح، فتُفصح الكوسا الهادئة عن حلاوتها خلسة. صفرة تذوب بنعومة في الفم حتى النهاية."},"ICON-2812":{"nm":"أرز مقلي بالكيمتشي","de":"حين يعتّق الكيمتشي القديم، يلتقي بالأرز البارد في مقلاة واحدة. طبق يزداد إشباعاً حين يجتمع ما تبقّى مع ما تبقّى. أرقّ خلاص تحت ضوء غرفة سكن صغيرة في ليل متأخر."},"ICON-2813":{"nm":"كاري الدجاج","de":"حين يغطي المرق الأصفر الأرز الأبيض، تضيء المائدة فجأة. في زمن كانت فيه التوابل غريبة، كان أول طعم للعالم الخارجي أصبحنا مقرّبين منه. ظهيرة أحد كان فيها لحم الدجاج يتفكك طرياً وناعماً."},"ICON-2814":{"nm":"الأرز المقلي","de":"بقايا متناثرة في أقصى الثلاجة تجتمع بوئام في مقلاة واحدة. سعة صدر تستقبل أي شيء بكرم. جمع المتناثر في مكان واحد — من هنا تبدأ إدارة البيت."},"ICON-2815":{"nm":"طبق البولجوجي على الأرز","de":"لحمٌ منقوع في صلصة حلوة ينزلق بسلاسة فوق أرزٍ يتصاعد منه البخار. حين يستقر بطل مائدة الضيوف في وعاء واحد ليوم عادي، يصبح ما هو مميز أكثر حناناً."},"ICON-2816":{"nm":"بيبيمباب","de":"فوق الأرز الطري تجلس خضروات بخمسة ألوان في دائرة. في أطراف الأصابع التي ترتّب الألوان يسري ذوقٌ قديم للعناية الرقيقة. نكهة الانسجام لا تكتمل إلا حين يُخلط كل شيء معاً."},"ICON-2817":{"nm":"أرز مقلي بالروبيان","de":"روبيان ممتلئ يبرز بلونه الوردي بين حبات الأرز. حين تُقلى حفنة من البحر وتُضاف إليه، تتقمّص وجبة عادية مظهر مأدبة. الحلاوة التي تنتشر لحظة طقطقتها بين الأسنان أمر مُرحَّب به."},"ICON-2818":{"nm":"لحم الخنزير الحار مع الأرز","de":"لحم خنزير تغلغلت فيه توابل حارة بعمق يلتقي بأرزٍ يتصاعد منه البخار. الوعاء الذي كان أول من يظهر قاعه وقت الغداء. مواساة وجبة تربّت على يوم مزدحم وتهدّئه."},"ICON-2819":{"nm":"أرز التونة بالمايونيز","de":"علبة واحدة، خط من المايونيز، ووعاء أرز دافئ. المكونات قليلة لكن المواساة وافرة. طعم تلك الليلة، الذي كان يُخلط خلسة على مكتب الصف بعد ساعات الدراسة الذاتية."},"ICON-2820":{"nm":"أرز الكاري","de":"لونٌ ذهبي كثيف يملأ الطبق بالكامل. عناية التحريك الطويل حتى تلين البطاطا والجزر تماماً. يُذكّر بدفء تلك الليلة حين كانت العائلة بأكملها تحدّق في القدر نفسه."},"ICON-2821":{"nm":"بيبيمباب الأعشاب البحرية","de":"خيوط برائحة البحر تلتقي بمعجون الفلفل الأحمر وتُخلط جيداً. حين يلفّ الملمس الزلق الحامض حبات الأرز، ينبسط داخل وعاء واحد بحرٌ انتشلته غوّاصة حابسة أنفاسها."},"ICON-2822":{"nm":"الماكريل المشوي","de":"ظهر فضي ينضج ذهبياً فوق الشواية. يدٌ كانت تنزع العظام وتضع اللحم على الأرز. في قطعة واحدة من سمك الظهر الأزرق يتشرّب حبٌ صامت أطعم وربّى."},"ICON-2823":{"nm":"فطيرة البطاطا","de":"في الأيام الممطرة، ذاك الذي كان يُبشر ويُقلى في مطبخ قرية جبلية في مقاطعة غانغوون. الحواف الطرية والأطراف المقرمشة تعيشان جنباً إلى جنب في قطعة واحدة. العجينة الأنسب لصوت المطر يقرع النافذة."},"ICON-2824":{"nm":"فطيرة الكيمتشي","de":"في اللحظة التي يلامس فيها الكيمتشي الحامض المقلاة المزيّتة، يمتلئ البيت كله بصوت القلي المتفرقع. قرص ذهبي يستدعي وعاء ماكولي من تلقاء نفسه. طبق مألوف يرافق صوت المطر تحت الشرفة."},"ICON-2825":{"nm":"فطيرة البصل الأخضر","de":"تُرصّ خيوط البصل الأخضر بعناية، تُصبّ فوقها العجينة، وتُقلى ببطء. قرصٌ يتأرجح بين المقرمش والطري. تماماً مثل ذلك المشهد الودود لبخار يتصاعد من كشك في يوم السوق."},"ICON-2826":{"nm":"فطيرة الكوسا","de":"تُغطى شرائح الكوسا الرفيعة بعجينة وتُقلى حتى تذهب. دائرة خضراء فاتحة كانت تحرس بأناقة ركناً من مائدة الطقوس. ذلك الشكل الرسمي المتقن الذي لا يكتمل إلا بعناء يدوي كبير."},"ICON-2827":{"nm":"الحبار المقلي الحار","de":"أرجل ملفوفة بتوابل حمراء تلمع وتتلألأ ببريق زيتي. حتى مع تصبّب حبات العرق من الحرارة على الجبين، لا تتوقف عيدان الطعام. ذلك الطبق الواحد الذي يمتزج فيه العرق بالمتعة."},"ICON-2828":{"nm":"تيوكبوكي","de":"تغرق كعكات الأرز وكعكات السمك عميقاً في مرق أحمر من معجون الفلفل المُركّز. فيه يُختزن بأكمله عصر متجر وجبات خفيفة كان يُقتسم بين اثنين بعملات معدنية مجمّعة. طعم ذكرى يُسيل اللعاب لمجرد سماع اسمه."},"ICON-2829":{"nm":"شوربة كعك السمك","de":"عربة طعام يتمايل فيها كعك السمك في المرق، والبخار يُغبّش زجاجها بالبياض. أمسك بسيخ واحد، اجمع القليل من المرق في كوب ورقي، ورشفه، فتصبح ليلة الشتاء القارسة أكثر دفئاً."},"ICON-2830":{"nm":"التوفو مع الكيمتشي","de":"بجانب التوفو الطري، يجلس كيمتشي مقلي حار جنباً إلى جنب. البرودة والحرارة، اللين والقوة، تمتزج في طبق واحد. رفيقٌ حرس ليالي الكبار طويلاً."},"ICON-2831":{"nm":"النقانق مع الخضار المقلية","de":"نقانق حمراء وخضروات تتقلّب معاً بلون الكاتشب المتفرقع. الحجيرة التي كانت تُفرَغ أولاً عند فتح غطاء صندوق غداء يوم الرياضة المدرسية. لون ذلك اليوم يبقى زاهياً مهما مرّ الزمن."},"ICON-2832":{"nm":"لاتيه البطاطا الحلوة","de":"بطاطا حلوة مهروسة بنعومة تذوب برفق في حليب دافئ. حلاوة أصيلة مكتوبة بالكورية على قائمة الطعام. في يومٍ تكون فيه أطراف أصابعك باردة، احتضنه بكلتا يديك فينتشر الدفء ببطء عبر الكوب."},"ICON-2833":{"nm":"مايونيز","de":"صلصة لم تصل بعد إلى مطبخ الجزيرة اللامعة. ستُرسم قريباً كأيقونة بلون كريمي. (قيد الإعداد)"}};